class Strategy_COLLECTIVE_1(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Stock Sensitivity.
    
    Strategy Logic:
    - Round 1: Always Cooperate.
    - Final Round: Always Defect to extract value.
    - Stock Safety: If stock < capacity/4, Defect, unless all other players 
      are cooperating (indicating collective effort to recover).
    - Reciprocal: If majority of opponents (>= ceil(n/2)) cooperated in the 
      previous round, Cooperate; otherwise, Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_opponents_c = history.opponent_cooperators[-1]
        if current_stock < capacity / 4.0 and prev_opponents_c < n - 1:
            return Action.D
        if prev_opponents_c >= math.ceil(n / 2):
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_2(BaseStrategy):
    """
    A Tit-for-Tat strategy with forgiveness, punishment, and resource-preservation thresholds.
    - Round 1: Always Cooperate.
    - Intermediate: Cooperate if full cooperation, forgive one-off defection, otherwise punish for 2 rounds.
    - Final Rounds/Thresholds: Defect if stock is critically low or if it's the last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.punishment_rounds_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.r:
            return Action.D
        if current_stock < self.capacity * 0.1:
            return Action.D
        if current_round == 1:
            return Action.C
        if self.punishment_rounds_remaining > 0:
            self.punishment_rounds_remaining -= 1
        prev_k = history.opponent_cooperators[-1]
        if prev_k == self.n:
            self.punishment_rounds_remaining = 0
            return Action.C
        elif prev_k == self.n - 1:
            if self.punishment_rounds_remaining == 0:
                return Action.C
            else:
                return Action.D
        else:
            self.punishment_rounds_remaining = 2
            return Action.D
        if self.punishment_rounds_remaining > 0:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_3(BaseStrategy):
    """
    A Trigger-Modified Tit-for-Tat strategy that prioritizes sustainability
    through conditional cooperation and aggressive defect-response when 
    the resource pool is endangered or cooperation norms fail.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.recovery_counter = 0
        self.last_action_was_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            self.last_action_was_defect = True
            return Action.D
        if history.round_number == 0:
            self.last_action_was_defect = False
            return Action.C
        n = self.game_description.n_players
        threshold_crit = self.game_description.capacity / (4 * n)
        if current_stock < threshold_crit:
            self.last_action_was_defect = True
            return Action.D
        prev_round_k = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators = prev_round_k + (1 if my_prev_action else 0)
        cooperation_rate = total_cooperators / n
        tau = 0.5
        threshold_coop = self.game_description.capacity / (2 * n)
        if self.last_action_was_defect:
            if current_stock >= self.game_description.capacity / n and cooperation_rate > tau:
                self.recovery_counter += 1
            else:
                self.recovery_counter = 0
            if self.recovery_counter >= 2:
                self.last_action_was_defect = False
                self.recovery_counter = 0
                return Action.C
            else:
                return Action.D
        if current_stock > threshold_coop and cooperation_rate > tau:
            self.last_action_was_defect = False
            return Action.C
        self.last_action_was_defect = True
        return Action.D

class Strategy_COLLECTIVE_4(BaseStrategy):
    """
    Adaptive Reciprocal Sustainability (ARS) Strategy:
    Prioritizes resource sustainability by enforcing a 'tit-for-tat' style 
    conditional cooperation mechanism. It shifts between aggressive extraction 
    (Defect) when reciprocity is violated, and cooperative recovery (Cooperate) 
    when the stock is critical or when the majority of opponents are cooperating.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        current_round = current_round_idx + 1
        if current_round == 1:
            return Action.C
        if current_round == self.r:
            return Action.D if current_stock > self.capacity / 2 else Action.C
        prev_round_idx = current_round_idx - 1
        prev_opp_coop_count = history.opponent_cooperators[prev_round_idx]
        if current_stock < self.capacity / 4:
            return Action.C
        cooperation_threshold = self.n - 1
        if prev_opp_coop_count >= cooperation_threshold:
            return Action.C
        elif current_stock > self.capacity / 8:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_1(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource game.
    Implements a sustainable targeting strategy: cooperates to maintain 
    stock, defects when stock is critically low or when widespread 
    defection is observed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_stock <= 0:
            return Action.D
        if current_round == self.r:
            if current_stock > self.capacity / 2:
                return Action.D
            return Action.C
        if current_stock < self.capacity / 4:
            return Action.D
        if current_round == 1:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opp_cooperators = history.opponent_cooperators[-1]
        total_cooperators = last_opp_cooperators + (1 if last_my_action else 0)
        if total_cooperators >= self.n - 1:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_2(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with sustainability thresholds.
    Focuses on maintaining the common pool resource by cooperating when the pool is healthy
    and punishing defectors unless the pool is near capacity. Defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1
        self.capacity = self.game_description.capacity
        self.max_rounds = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.max_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.D
        prev_opp_coop_count = history.opponent_cooperators[-1]
        num_defectors = self.n_opponents - prev_opp_coop_count
        is_near_capacity = current_stock >= 0.8 * self.capacity
        if num_defectors > 0:
            if not is_near_capacity:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_PROSOCIAL_3(BaseStrategy):
    """
    A strategy that maintains common pool resources by monitoring stock levels and 
    peer cooperation. It cooperates when the stock is healthy and the group 
    cooperates, defects when the stock is threatened or peers defect, and makes 
    last-ditch cooperative efforts if the stock approaches total collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.capacity = self.game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opponents_cooperated = history.opponent_cooperators[-1]
        total_cooperators_prev = opponents_cooperated + (1 if my_prev_action else 0)
        if current_round == self.r - 1:
            if total_cooperators_prev == self.n:
                return Action.C
            else:
                return Action.D
        if current_stock >= self.capacity * 0.5:
            if total_cooperators_prev == self.n:
                return Action.C
            else:
                return Action.D
        else:
            critical_threshold = self.capacity / (2 * self.n)
            if current_stock < critical_threshold:
                return Action.C
            else:
                return Action.D

class Strategy_PROSOCIAL_4(BaseStrategy):
    """
    Tit-for-Tat with Forgiving Resilience strategy.
    
    Operates by initiating with cooperation, employing probabilistic forgiveness
    based on the previous round's cooperation levels, incorporating a 
    sustainability-first override when stock is low, and transitioning to a 
    reputational heuristic in the terminal round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.last_stock = float(self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        if round_t == 0:
            self.last_stock = current_stock
            return Action.C
        prev_my_action_c = bool(history.my_actions[-1])
        opp_coop_count = history.opponent_cooperators[-1]
        k_t = opp_coop_count + (1 if prev_my_action_c else 0)
        prev_stock = self.last_stock
        self.last_stock = current_stock
        if round_t == self.r - 1:
            total_coop_history = []
            for t in range(round_t):
                my_c = 1 if history.my_actions[t] else 0
                total_coop_history.append(history.opponent_cooperators[t] + my_c)
            avg_coop_rate = np.mean(np.array(total_coop_history) / self.n)
            return Action.C if avg_coop_rate >= 0.5 else Action.D
        if current_stock < self.capacity / 4.0:
            if current_stock <= prev_stock:
                return Action.C
            else:
                return Action.D
        if k_t == self.n:
            return Action.C
        elif k_t == 0:
            return Action.D
        else:
            probability = k_t / self.n
            return Action.C if random.random() < probability else Action.D

class Strategy_ALTRUISTIC_1(BaseStrategy):
    """
    Target Stock Management (TSM) strategy.
    Prioritizes cooperation to maintain capacity, implements a dynamic
    defense mechanism (Restoration Phase) when stock drops below thresholds,
    and defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.s_prev = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_t = history.round_number + 1
        if round_t == r:
            return Action.D
        if round_t == 1:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        num_defectors_last_round = n - (prev_opp_coop + (1 if prev_my_action else 0))
        threshold_recovery = 0.2 * capacity
        if current_stock >= 0.5 * capacity:
            self.s_prev = current_stock
            return Action.C
        elif current_stock < threshold_recovery:
            self.s_prev = current_stock
            if num_defectors_last_round > 0:
                return Action.D
            else:
                return Action.C
        elif current_stock < 0.75 * self.s_prev:
            self.s_prev = current_stock
            return Action.D
        else:
            self.s_prev = current_stock
            return Action.C

class Strategy_ALTRUISTIC_2(BaseStrategy):
    """
    Tit-for-Tat Sustainability (TFTS) Strategy:
    Prioritizes maintaining the common pool stock at capacity for long-term optimization.
    - Cooperates by default in the first round.
    - Monitors stock levels: enters 'Recovery Mode' (Cooperate) if stock is critically low (< 20% capacity).
    - Aggregates behavior: If stock is shrinking due to defectors (previous round), may retaliate (Defect).
    - End-game: Switches to Defect if stock is healthy (> 50% capacity) in the final 3 rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def _calculate_stock_from_previous(self, prev_stock: float, my_prev_action: Action, prev_opp_coop: int) -> float:
        """Helper to calculate what the stock would have been at the end of the previous round."""
        n = self.game_description.n_players
        cap = self.game_description.capacity
        my_consumption = prev_stock / (2 * n) if my_prev_action == Action.C else prev_stock / n
        num_opp_defectors = n - 1 - prev_opp_coop
        opp_c_consumption = prev_opp_coop * (prev_stock / (2 * n))
        opp_d_consumption = num_opp_defectors * (prev_stock / n)
        total_consumption = my_consumption + opp_c_consumption + opp_d_consumption
        s_remaining = max(0.0, prev_stock - total_consumption)
        growth = 2.0 * s_remaining * (1.0 - s_remaining / cap)
        new_stock = min(cap, s_remaining + growth)
        return new_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.game_description.n_rounds - 3:
            if current_stock > 0.5 * self.game_description.capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < 0.2 * self.game_description.capacity:
            return Action.C
        if not hasattr(self, '_last_stock'):
            self._last_stock = float(self.game_description.capacity)
        prev_stock = self._last_stock
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        observed_new_stock = self._calculate_stock_from_previous(prev_stock, prev_my_action, prev_opp_coop)
        self._last_stock = current_stock
        if observed_new_stock >= prev_stock:
            return Action.C
        prev_defectors = self.game_description.n_players - 1 - prev_opp_coop
        if prev_defectors > 0:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_3(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy.
    
    This strategy aims to maximize the longevity and yield of the common pool by:
    1. Cooperating in the first round.
    2. Cooperating if the stock is critically low (<1% capacity) or below 75% capacity.
    3. Cooperating if at least 50% of opponents cooperated in the previous round.
    4. Defecting if the capacity is near maximum (>90% capacity) to capture value.
    5. Defecting for one round as a 'signal' if previous cooperation was too low (<25% of players).
    6. Always defecting in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_punishing = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == total_rounds - 1:
            self.is_punishing = False
            return Action.D
        if current_round == 0:
            self.is_punishing = False
            return Action.C
        prev_round = current_round - 1
        my_prev_action = 1 if history.my_actions[prev_round] else 0
        k_prev = history.opponent_cooperators[prev_round] + my_prev_action
        if self.is_punishing:
            self.is_punishing = False
            return Action.C
        if k_prev < n / 4:
            self.is_punishing = True
            return Action.D
        if current_stock < 0.01 * capacity:
            return Action.C
        if current_stock > 0.9 * capacity:
            return Action.D
        if current_stock < 0.75 * capacity or k_prev >= math.ceil(n / 2):
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_4(BaseStrategy):
    """
    Implements a conditional "Grim-Trigger with Forgiveness" strategy for the Common Pool Resource game.
    The strategy prioritizes long-term resource sustainability by adjusting cooperation based on current stock levels,
    previous round outcomes, and proximity to the final round. It aims to maintain stock at capacity/2.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if t == 1:
            return Action.C
        k = int(history.opponent_cooperators[-1])
        c_prev = bool(history.my_actions[-1])
        num_defectors = n - 1 - k
        if t == r:
            if current_stock < capacity * 0.2:
                return Action.D
            else:
                return Action.C if k >= (n - 1) / 2 else Action.D
        if current_stock < capacity * 0.25 or num_defectors > n / 2:
            return Action.D
        if current_stock >= capacity * 0.5:
            if k >= (n - 1) / 2:
                return Action.C
            else:
                return Action.D
        return Action.C if k >= (n - 1) / 2 else Action.D

class Strategy_BENEVOLENT_1(BaseStrategy):
    """
    Tit-for-Tat with Forgiving Resilience: A strategy that balances cooperative
    sustainability with retaliation against defection, incorporating an adaptive
    'Defection Debt' mechanism for forgiveness and explicit recovery modes for 
    low-stock preservation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.debt = 0.0
        self.recovery_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if current_stock < capacity / n:
            self.recovery_counter = 3
            return Action.C
        if self.recovery_counter > 0:
            self.recovery_counter -= 1
            return Action.C
        remaining_rounds = r - round_idx
        if remaining_rounds <= 2:
            if current_stock < capacity / 4:
                return Action.C
            if current_stock > capacity / 2:
                return Action.D
        my_prev_action = history.my_actions[-1]
        opp_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        n_defectors_opponents = n_opponents - opp_cooperators
        prev_defectors = n_defectors_opponents + (0 if my_prev_action else 1)
        if prev_defectors > 0:
            self.debt += 1.0
        else:
            self.debt = max(0.0, self.debt - 0.5)
        if prev_defectors == 0:
            return Action.C
        denom = max(1, n * remaining_rounds)
        threshold = self.debt / denom
        if random.random() < threshold:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_2(BaseStrategy):
    """
    Benevolent Tit-for-Tat with Stock Sensitivity (BTT-SS):
    Prioritizes sustainability by transitioning between Cooperative and Defective modes
    based on remaining stock levels and collective historical cooperation rates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.s_safe = 0.5 * self.capacity
        self.s_critical = 0.1 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        last_opponents_c = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        last_total_c = last_opponents_c + (1 if last_my_action else 0)
        round_idx = history.round_number + 1
        if round_idx > self.total_rounds - 3 and current_stock < 0.8 * self.capacity:
            if last_opponents_c >= self.n - 1:
                return Action.C
            else:
                return Action.D
        if current_stock < self.s_critical:
            return Action.D
        if current_stock < self.s_safe:
            if last_total_c >= self.n / 2:
                return Action.C
            else:
                return Action.D
        if last_total_c >= self.n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_3(BaseStrategy):
    """
    Sustainability-Conditional Reciprocity (SCR) strategy.
    Prioritizes maintaining stock levels near capacity while managing defection
    through retaliatory defection and recovery phases.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.recovery_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if t == self.r:
            return Action.D
        if t == 1:
            return Action.C
        if self.recovery_counter > 0:
            self.recovery_counter -= 1
            return Action.C
        if current_stock < 0.1 * self.capacity:
            self.recovery_counter = 2
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        my_action_prev = 1 if history.my_actions[-1] else 0
        total_k = k_prev + my_action_prev
        if total_k == self.n:
            return Action.C
        s_prev = self._estimate_previous_stock(history, current_stock)
        total_consumption = total_k * (s_prev / (2 * self.n)) + (self.n - total_k) * (s_prev / self.n)
        if s_prev > 0 and total_consumption > s_prev / 2:
            return Action.D
        return Action.C

    def _estimate_previous_stock(self, history: PlayerHistory, current_stock: float) -> float:
        """
        Since the stock dynamics function is non-invertible (due to min(capacity, growth)),
        we perform a heuristic estimation or simply use the current_stock as a proxy for the 
        previous state to make the decision rule functional.
        """
        return current_stock

class Strategy_BENEVOLENT_4(BaseStrategy):
    """
    A conditional tit-for-tat strategy with sustainability prioritization.
    - Cooperates in the first round.
    - Cooperates in the final round if stock is low or generally defects in the final round 
      (though the spec explicitly dictates always defecting in the final round).
    - If all players cooperated in the previous round, continues to cooperate.
    - If defection occurred, punishes by defecting only if the stock is healthy (>= 0.5 * capacity).
    - If defection occurred and stock is low (< 0.5 * capacity), prioritizes regeneration by cooperating.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round_idx = history.round_number
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        last_action_was_cooperate = history.my_actions[-1]
        opponent_cooperators_count = history.opponent_cooperators[-1]
        total_cooperators_prev = (1 if last_action_was_cooperate else 0) + opponent_cooperators_count
        if total_cooperators_prev == n:
            return Action.C
        elif current_stock >= capacity * 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_1(BaseStrategy):
    """
    A Trigger-Tit-for-Tat strategy that maintains cooperation based on stock levels,
    unanimous opponent cooperation, and game progression. It defects if the stock
    is critically low, if any opponent has defected in the previous round, or in the
    terminal phase (last 2 rounds).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = game_description.n_players
        self.threshold = 0.25 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        rounds_remaining = total_rounds - current_round
        if current_round == 0:
            return Action.C
        if rounds_remaining < 3:
            return Action.D
        if current_stock < self.threshold:
            return Action.D
        prev_round_idx = current_round - 1
        num_opponents = self.n_players - 1
        if history.opponent_cooperators[prev_round_idx] < num_opponents:
            return Action.D
        return Action.C

class Strategy_SELFISH_2(BaseStrategy):
    """
    Conditional Cooperation strategy:
    - Plays C in the first round.
    - Plays D in the final round to maximize terminal extraction.
    - Uses a threshold-based conditional cooperation:
        - If stock is below epsilon (0.1 * capacity), it enters exhaustion mode (D).
        - Otherwise, if observed cooperators in the previous round >= (n - 1 - k), it cooperates.
        - Uses a tolerance parameter k=1 to forgive one defector.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.k = 1
        self.epsilon_factor = 0.1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        epsilon = self.epsilon_factor * self.game_description.capacity
        if current_stock <= epsilon:
            return Action.D
        c_observed = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        threshold = max(0, n_opponents - self.k)
        if c_observed >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_3(BaseStrategy):
    """
    Adaptive Sustenance-Defection (ASD) Strategy.
    
    Principles:
    1. First Round: Cooperate (C) to build sustainability.
    2. Terminal Round: Defect (D) to maximize final extraction.
    3. Intermediate Rounds (2 to r-1):
       - Sustainability First: If current_stock < capacity / 2, play C.
       - Correction: If the stock decreased by > 40% in the previous round, play C to stabilize.
       - Default: Defect (D) regardless of opponent behavior (Tit-for-tat-adjacent logic: exploit while sustainable).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.s_crit = self.game_description.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock < self.s_crit:
            return Action.C
        n_opp = self.game_description.n_players - 1
        nc_prev = history.opponent_cooperators[-1]
        my_action_prev = 1 if history.my_actions[-1] else 0
        total_cooperators = nc_prev + my_action_prev
        total_defectors = self.game_description.n_players - total_cooperators
        if total_defectors > self.game_description.n_players / 2:
            return Action.C
        return Action.D

class Strategy_SELFISH_4(BaseStrategy):
    """
    Implements the Adaptive Threshold Monitoring strategy:
    - Round 1: Always Cooperate.
    - Subsequent rounds before final:
        - Defect if stock < 50% capacity.
        - Cooperate if stock >= 50% capacity AND previous round's cooperation count 
          was >= ceil(n_players / 2).
        - Otherwise Defect.
    - Final round: Always Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        current_round_index = history.round_number + 1
        if current_round_index == 1:
            return Action.C
        if current_round_index == total_rounds:
            return Action.D
        sustainability_threshold = 0.5 * self.game_description.capacity
        if current_stock < sustainability_threshold:
            return Action.D
        i_cooperated_last = bool(history.my_actions[-1])
        prev_cooperators = history.opponent_cooperators[-1] + (1 if i_cooperated_last else 0)
        required_cooperators = math.ceil(n / 2)
        if prev_cooperators >= required_cooperators:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_1(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Common Pool Resource Game.
    The strategy aims to maintain stock levels by playing 'C' while cooperating 
    with near-unanimous behavior in the previous round, or 'D' if defection is 
    widespread or the game is in its final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.survival_threshold = 0.1 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < self.survival_threshold:
            return Action.D
        prev_round_cooperators = history.opponent_cooperators[-1]
        if prev_round_cooperators >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_2(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy for the Common Pool Resource Game.
    
    Rules:
    - Round 1: Cooperate.
    - Final Round: Defect.
    - Intermediate Rounds:
        - If current_stock < capacity / 2: Defect.
        - Else if all opponents cooperated in previous round: Cooperate.
        - Else: Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 2.0:
            return Action.D
        prev_round_cooperators = history.opponent_cooperators[-1]
        if prev_round_cooperators == self.n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_3(BaseStrategy):
    """
    Trigger-Based Sustainable Harvest (TSH)
    A strategy that maintains cooperation while resources are sustainable,
    responds to defection with conditional punishment, and optimizes 
    payoff capture in terminal rounds or critical resource conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.punishment_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        num_opponents = self.n - 1
        prev_cooperators = history.opponent_cooperators[prev_round_idx]
        prev_defectors = num_opponents - prev_cooperators
        if self.punishment_remaining > 0:
            self.punishment_remaining -= 1
        if prev_defectors > 0:
            if current_stock > 0.9 * self.capacity:
                pass
            else:
                self.punishment_remaining = prev_defectors
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if self.punishment_remaining > 0:
            return Action.D
        if current_stock < 0.5 * self.capacity:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_4(BaseStrategy):
    """
    Implements a modified Tit-for-Tat strategy with a sustainability threshold.
    
    Logic:
    - Always Cooperates in round 1.
    - Always Defects in the final round.
    - If stock <= 0.25 * capacity, Defects (harvesting remaining value).
    - If stock > 0.25 * capacity:
        - Cooperates if the cooperation ratio of opponents in the previous round >= 0.75.
        - Defects otherwise (including scenarios where 0.25 < CR < 0.75).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock <= 0.25 * self.game_description.capacity:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        if n_opponents == 0:
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        cooperation_ratio = k_prev / n_opponents
        if cooperation_ratio >= 0.75:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_1(BaseStrategy):
    """
    Threshold-Based Reciprocal Exploitation (TBRE) Strategy.
    
    This strategy behaves as a conditionally cooperative agent:
    - Always cooperates in the first round.
    - Always defects in the final round.
    - In middle rounds:
        - If current stock < 25% of capacity, it abandons cooperation to capture remaining value.
        - Otherwise, it calculates the rolling average cooperation rate of opponents over the last S rounds (S=3).
        - If the average cooperation rate of opponents >= 0.5, it cooperates to maintain the pool.
        - If the average cooperation rate of opponents < 0.5, it defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = 0.5
        self.sensitivity = 3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.D
        num_opponents = self.n - 1
        if num_opponents == 0:
            return Action.C
        s = min(self.sensitivity, history.round_number)
        recent_coop_counts = history.opponent_cooperators[-s:]
        total_coop_events = np.sum(recent_coop_counts)
        possible_coop_events = s * num_opponents
        avg_cooperation = total_coop_events / possible_coop_events
        if avg_cooperation >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_2(BaseStrategy):
    """
    Adaptive Resource Harvesting: A conditional cooperation strategy that balances
    long-term sustainability with exploitation of non-cooperative populations.
    
    Logic:
    1. Always cooperates in the first round.
    2. Defects in the final round (terminal phase).
    3. If stock drops below 20% of capacity, prioritizes cooperation (safeguard).
    4. Otherwise, uses Tit-for-Tat logic: cooperates if at least (n-1) players 
       cooperated in the previous round, otherwise defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.2 * self.capacity:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        c_observed_previous = my_prev_coop + history.opponent_cooperators[-1]
        if c_observed_previous >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_3(BaseStrategy):
    """
    A strategy that maintains cooperation based on resource sustainability and 
    opponent behavior, with defensive triggers for depletion, endgame scenarios, 
    and resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.6 * self.game_description.capacity
        self.collapse_threshold = 0.1 * self.game_description.capacity
        self.n_total = self.game_description.n_players
        self.n_opponents = self.n_total - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_opp_defectors = self.n_opponents - prev_opp_coop
        my_prev_action = history.my_actions[-1]
        my_prev_defect = 1 if not my_prev_action else 0
        total_defectors_prev = prev_opp_defectors + my_prev_defect
        if current_stock < self.collapse_threshold:
            return Action.D
        if current_stock < self.threshold or total_defectors_prev >= self.n_total / 2:
            if history.round_number > self.game_description.n_rounds - 3:
                return Action.D
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_4(BaseStrategy):
    """
    An adaptive Common Pool Resource strategy that balances cooperative resource management
    with tit-for-tat retaliation and collapse avoidance.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.total_rounds - 1:
            return Action.D
        if current_stock < self.capacity / 2:
            return Action.D
        if current_stock >= 0.9 * self.capacity:
            last_opp_coop = history.opponent_cooperators[-1]
            last_my_action = history.my_actions[-1]
            opponents_count = self.n - 1
            if last_opp_coop == opponents_count:
                return Action.C
        prev_action = history.my_actions[-1]
        last_round_cooperators = history.opponent_cooperators[-1]
        if prev_action == True:
            opponents_defecting = self.n - 1 - (last_round_cooperators - 1)
        else:
            opponents_defecting = self.n - 1 - last_round_cooperators
        opponents_defecting = max(0, opponents_defecting)
        if self.n <= 1:
            return Action.C
        impact = opponents_defecting / (self.n - 1)
        if impact > 0.5:
            return Action.D
        elif impact == 0:
            return Action.C
        else:
            prob_cooperate = 1.0 - 2.0 * impact
            if random.random() < prob_cooperate:
                return Action.C
            else:
                return Action.D

class Strategy_INDIVIDUALISTIC_1(BaseStrategy):
    """
    A strategy for the Common Pool Resource game that balances cooperation for long-term sustainability
    with defection when the resource is critically depleted or when others fail to cooperate.
    
    Logic:
    1. First round: Cooperate (C).
    2. Final round (t = r): Defect (D).
    3. If current stock S < (capacity / 4): Defect (D) to maximize immediate gain before collapse.
    4. If stock S >= (capacity / 2) AND previous round cooperative actions >= (n / 2): Cooperate (C).
    5. Otherwise: Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.threshold = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_stock <= 0:
            return Action.D
        if current_round_idx == self.r - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < self.capacity / 4:
            return Action.D
        prev_round_idx = current_round_idx - 1
        num_cooperators = history.opponent_cooperators[prev_round_idx]
        required_coop = math.ceil(self.n / 2)
        if current_stock >= self.threshold and num_cooperators >= required_coop:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_2(BaseStrategy):
    """
    A strategy that maintains a reputation score based on group cooperation.
    It cooperates when the reputation is high and stock levels are sufficient to be sustainable,
    or when stock levels are high enough to justify the consumption cost.
    It defects in the final round and when the stock levels fall below critical thresholds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation_score = 1.0
        self.alpha = 0.1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        t = history.round_number + 1
        capacity = self.game_description.capacity
        if t == r:
            return Action.D
        if t == 1:
            return Action.C
        my_last_action = history.my_actions[-1]
        my_last_coop = 1 if my_last_action == Action.C else 0
        total_cooperators_last_round = history.opponent_cooperators[-1] + my_last_coop
        group_cooperation_rate = total_cooperators_last_round / n
        self.reputation_score = (1 - self.alpha) * self.reputation_score + self.alpha * group_cooperation_rate
        if self.reputation_score > 0.6 and current_stock > capacity / n:
            return Action.C
        elif current_stock > capacity / (2 * n):
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_3(BaseStrategy):
    """
    A Tit-for-Tat variant designed for Common Pool Resource games. 
    Prioritizes sustainable extraction by maintaining stock levels near capacity 
    unless triggered by defection or imminent resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.n_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if current_round_idx >= 2:

            def get_defector_count(round_idx: int) -> int:
                ops_coop = history.opponent_cooperators[round_idx]
                my_action = history.my_actions[round_idx]
                self_defected = 1 if not my_action else 0
                return self.n - 1 - ops_coop + self_defected
            d1 = get_defector_count(-1)
            d2 = get_defector_count(-2)
            if d1 > self.n / 2 and d2 > self.n / 2:
                return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_defectors = self.n - 1 - prev_opp_coop
        my_prev_action = history.my_actions[-1]
        if not my_prev_action:
            prev_defectors += 1
        if prev_defectors == 0:
            return Action.C
        if current_stock >= 0.5 * self.capacity:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_4(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy for a Common Pool Resource game.
    - Round 1: Always Cooperate.
    - Rounds 2 to r-1: 
        - If stock < capacity/4, Cooperate (Rescue).
        - Else if last round cooperation >= n/2, Cooperate.
        - Else, Defect.
    - Final Round: Always Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_total = self.game_description.n_players
        r_total = self.game_description.n_rounds
        current_round_index = history.round_number
        if current_round_index == r_total - 1:
            return Action.D
        if current_round_index == 0:
            return Action.C
        last_opponent_coop = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        total_cooperators_last_round = last_opponent_coop + (1 if last_my_action else 0)
        if current_stock < self.game_description.capacity / 4:
            return Action.C
        n_threshold = n_total / 2.0
        if total_cooperators_last_round >= n_threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_5(BaseStrategy):
    """
    A strategy that maintains a state machine between "Cooperative" and "Punishing".
    It monitors defectors from previous rounds and stock levels to decide its 
    action, attempting to punish defection while preserving the pool's sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.state = 'COOPERATIVE'
        self.warning_count = 0

    def _calculate_defectors(self, s_prev: float, s_curr: float, n: int) -> int:
        """
        Infers the number of defectors from the previous round (t-1).
        
        Logic derivation:
        Stock dynamics: 
        S_t = min(S_rem + Growth(S_rem), capacity)
        Growth(S_rem) = 2 * S_rem * (1 - S_rem / capacity)
        
        This makes inversion complex due to the min() function and the quadratic growth.
        However, the problem statement provides the mechanism to calculate defectors 
        based on total consumption.
        
        Given the constraints and the provided pseudocode logic requirements:
        The strategy tracks state based on 'd_prev'. Since the game history provides 
        'opponent_cooperators' (an array of count of cooperators), we can derive 
        defectors directly without reversing the stock dynamics formula, which is safer.
        
        Total players = n.
        Cooperating opponents = opponent_cooperators[-1].
        My action in previous round (t-1) = self_action_prev.
        Total cooperators = opponent_cooperators[-1] + (1 if self_action_prev == C else 0).
        Defectors = n - Total Cooperators.
        """
        return 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.desc.n_players
        r = self.desc.n_rounds
        cap = self.desc.capacity
        t = history.round_number
        if t == 0:
            self.state = 'COOPERATIVE'
            self.warning_count = 0
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_cooperators_prev = history.opponent_cooperators[-1]
        my_prev_coop = 1 if my_prev_action else 0
        total_coops = opp_cooperators_prev + my_prev_coop
        d_prev = n - total_coops
        if t == r - 1:
            return Action.D
        if self.state == 'COOPERATIVE':
            if d_prev > n / 2 or current_stock < cap / 2:
                self.state = 'PUNISHING'
            elif d_prev > 0:
                self.warning_count += 1
                if self.warning_count >= 2:
                    self.state = 'PUNISHING'
            else:
                self.warning_count = 0
        elif self.state == 'PUNISHING':
            if current_stock >= 0.8 * cap:
                self.state = 'COOPERATIVE'
                self.warning_count = 0
        if self.state == 'PUNISHING':
            return Action.D
        if current_stock < cap / 4:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_6(BaseStrategy):
    """
    Trigger-Modified Tit-for-Tat:
    - Maintains cooperation while the stock is healthy.
    - If defection occurs, it checks for stock stability to decide whether to punish (Defect) or maintain (Cooperate).
    - Includes a 'Grim Trigger' switch if opponents persist in defecting (for 3 rounds).
    - Includes an 'Emergency Defection' threshold if stock is nearing collapse.
    - Always Defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.grim_trigger_active = False
        self.consecutive_defections = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_stock < capacity / (10 * n):
            return Action.D
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        n_opponents = n - 1
        opponents_cooperated = history.opponent_cooperators[-1]
        opponents_defected = n_opponents - opponents_cooperated
        if opponents_defected > 0:
            self.consecutive_defections += 1
        else:
            self.consecutive_defections = 0
        if self.consecutive_defections >= 3:
            self.grim_trigger_active = True
        if self.grim_trigger_active:
            return Action.D
        if current_stock >= capacity * 0.99:
            return Action.C
        if opponents_defected == 0:
            return Action.C
        elif current_stock >= capacity / 2:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_7(BaseStrategy):
    """
    Implements a Conditional Stock-Stabilizing Reciprocity strategy.
    
    Logic:
    - Starts with Cooperate (C).
    - In final round, always Defect (D).
    - If pool is critically low (< 10% capacity), forces Cooperation (C) to prevent permanent collapse.
    - If not in critical state, compares previous round's cooperation levels against a 25% defection threshold.
    - If defectors > 25% of n, retaliates with Defect (D).
    - Otherwise, maintains Cooperation (C) to foster sustainable growth.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == self.r - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_val = 1 if my_prev_action else 0
        total_cooperators = my_val + history.opponent_cooperators[-1]
        total_defectors = self.n - total_cooperators
        if total_defectors > self.n * 0.25:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_8(BaseStrategy):
    """
    Trigger-Based Conditional Cooperation with Threshold Recovery.
    
    Prioritizes sustainability via dynamic modes:
    1. Recovery Mode: Activated when stock <= 10% capacity. Punishes cooperators if 
       they are numerous, otherwise cooperates to build stock.
    2. Normal Mode: Cooperates if cooperation ratio >= 0.75, otherwise defects.
    3. Global Triggers: Permanent defection if stock is 0 or if the moving average 
       of cooperation over the last 3 rounds is < 0.3.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.n_rounds - 1:
            return Action.D
        if round_idx >= 3:
            last_3_coop_counts = history.opponent_cooperators[-3:]
            my_actions = history.my_actions.astype(int)[-3:]
            total_coop_counts = history.opponent_cooperators[-3:] + my_actions
            avg_cr = np.mean(total_coop_counts / self.n)
            if avg_cr < 0.3:
                return Action.D
        if self.n < 4:
            last_my_action = int(history.my_actions[-1])
            last_opponent_coops = history.opponent_cooperators[-1]
            if last_my_action + last_opponent_coops < self.n:
                return Action.D
            return Action.C
        prev_my_action = int(history.my_actions[-1])
        prev_opp_coop = history.opponent_cooperators[-1]
        previous_CR = (prev_opp_coop + prev_my_action) / self.n
        if not hasattr(self, 'stock_history'):
            self.stock_history = [self.capacity]
        prev_stock = self.stock_history[-1]
        if prev_stock <= 0.1 * self.capacity:
            action = Action.D if previous_CR >= 0.5 else Action.C
        else:
            action = Action.C if previous_CR >= 0.75 else Action.D
        if len(self.stock_history) <= round_idx:
            n_coop = prev_opp_coop + prev_my_action
            n_def = self.n - n_coop
            total_cons = n_coop * (prev_stock / (2 * self.n)) + n_def * (prev_stock / self.n)
            s_rem = prev_stock - total_cons
            growth = 2 * s_rem * (1 - s_rem / self.capacity)
            next_stock = min(s_rem + growth, self.capacity)
            self.stock_history.append(next_stock)
        return action

class Strategy_COLLECTIVE_9(BaseStrategy):
    """
    A conditional 'Tit-for-Tat' strategy for the Common Pool Resource game.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Termination (Final Round): Always Defect (D) to maximize terminal payoff.
    - Crisis Management: If stock < 0.5 * capacity, switch to Defect (D) to extract value.
    - Reciprocity: If previous round had any defectors (cooperators < total_opponents), punish by Defecting (D).
    - Otherwise: Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n_opponents = self.game_description.n_players - 1
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < 0.5 * self.game_description.capacity:
            return Action.D
        prev_coop_count = history.opponent_cooperators[-1]
        if prev_coop_count < n_opponents:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_10(BaseStrategy):
    """
    A conditionally cooperative strategy that prioritizes system survival (stock preservation)
    when the resource is critically low, and follows a majority-rule reciprocity norm
    (Tit-for-Tat against majority) when the resource is sustainable. Always cooperates 
    in the first round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        last_self_cooperated = int(history.my_actions[-1])
        total_cooperators_prev = history.opponent_cooperators[-1] + last_self_cooperated
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_stock < capacity / n:
            return Action.C
        majority_threshold = math.ceil(n / 2)
        if total_cooperators_prev >= majority_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_11(BaseStrategy):
    """
    A conditional cooperation strategy based on a trigger-threshold mechanism.
    - Round 1: Always Cooperate.
    - Final Round: Defect if stock > 1, else Cooperate.
    - General rounds:
        - If stock is at capacity: Cooperate.
        - If current stock < 20% of capacity AND others defected in prev round: Defect for one round.
        - Perfect cooperation (everyone cooperated prev round): Cooperate.
        - Otherwise (stock recovering or stable): Cooperate, else Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.initial_capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D if current_stock >= 1.0 else Action.C
        if current_round == 0:
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        if current_stock >= self.initial_capacity:
            return Action.C
        if current_stock < self.initial_capacity * 0.2 and prev_k < n - 1:
            return Action.D
        is_stock_stable = current_stock / self.initial_capacity > 0.5
        if prev_k == n - 1 or is_stock_stable:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_12(BaseStrategy):
    """
    A Tit-For-Tat variant strategy for the Common Pool Resource game.
    It cooperates in the first round, and subsequently mimics the aggregate
    cooperation level of opponents, with specific thresholds and edge-case behaviors
    to maximize sustainability and payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.epsilon = 0.05 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        s_crit = self.capacity / (2 * self.n)
        if current_stock <= self.epsilon or current_stock < s_crit:
            return Action.D
        num_opponents = self.n - 1
        if num_opponents <= 0:
            return Action.C
        k = history.opponent_cooperators[-1]
        cl = k / num_opponents
        if current_stock >= self.capacity:
            if cl > 0.3:
                return Action.C
            else:
                return Action.D
        if cl >= 0.5:
            return Action.C
        elif random.random() < cl:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_13(BaseStrategy):
    """
    A conditional cooperation strategy that maintains stock sustainability.
    
    Logic:
    1. First round: Cooperate (C).
    2. Last round: Defect (D).
    3. Low Stock Check: If stock < 0.25 * capacity, immediately Defect (D).
    4. Otherwise:
       - If everyone cooperated in the previous round (c == n-1 opponents + 1 self), Cooperate (C).
       - If some defected (c < n-1):
         - If stock < 0.5 * capacity, Defect (D).
         - Else, Cooperate (C).
    
    Note: The input 'opponent_cooperators' counts only the opponents.
    Since total n = n_players, the total cooperators = opponent_cooperators[-1] + (1 if last_action_was_C else 0).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 0.25 * self.game_description.capacity:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_action_was_c = bool(history.my_actions[-1])
        opp_coop_count = int(history.opponent_cooperators[-1])
        total_cooperators = opp_coop_count + (1 if last_action_was_c else 0)
        if total_cooperators == self.game_description.n_players:
            return Action.C
        if current_stock < 0.5 * self.game_description.capacity:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_14(BaseStrategy):
    """
    Implements a reputation-based strategy for the Common Pool Resource Game.
    Maintains a reputation score derived from the history of cooperation.
    Defects if stock is low, reputation drops below a threshold, or in the final round.
    Includes a fallback 'give-up' condition for large groups with declining cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 1.0
        self.punishment_threshold = 0.5
        self.alpha = 0.8
        self.defecting_penalty_round = False
        self.gave_up = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        if self.gave_up:
            return Action.D
        prev_round = current_round - 1
        prev_c_count = history.opponent_cooperators[prev_round]
        my_prev_action = history.my_actions[prev_round]
        total_c_count = prev_c_count + (1 if my_prev_action else 0)
        self.reputation = self.alpha * self.reputation + (1 - self.alpha) * (total_c_count / n)
        if n > 10 and current_round >= 2:
            prev_reputation = self.alpha * 1.0
            if current_round >= 3:
                prev_prev_c_count = history.opponent_cooperators[prev_round - 1]
                if total_c_count / n < 0.3 and prev_c_count / n < 0.4:
                    self.gave_up = True
                    return Action.D
        if current_stock < self.game_description.capacity / 2.0:
            return Action.D
        if self.defecting_penalty_round:
            self.defecting_penalty_round = False
            return Action.C
        if self.reputation < self.punishment_threshold:
            self.defecting_penalty_round = True
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_15(BaseStrategy):
    """
    Tit-for-Tat with Forgiving Resilience strategy.
    
    Logic:
    1. Always C in the first round.
    2. Crisis management: If stock < 0.2 * capacity (and > 0), force C.
    3. Last round: If stock > 0, force D to capture value.
    4. General logic: Cooperate if most opponents cooperated in the previous round
       (threshold: k >= n - 1), otherwise Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock > 0:
                return Action.D
            return Action.C
        if current_stock < 0.2 * self.game_description.capacity and current_stock > 1e-09:
            return Action.C
        last_k = history.opponent_cooperators[-1]
        if last_k >= self.n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_16(BaseStrategy):
    """
    Trigger-Based Sustainable Harvest Strategy.
    Prioritizes resource regeneration and punishes mass defection or stock depletion,
    while optimizing for terminal round gains.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = float(game_description.n_players)
        self.s_threshold = self.capacity / 2.0
        self.punishment_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        capacity = self.capacity
        r = self.game_description.n_rounds
        t = history.round_number + 1
        if t == 1:
            self.punishment_mode = False
            return Action.C
        prev_idx = history.round_number - 1
        k = float(history.opponent_cooperators[prev_idx])
        my_prev_action = history.my_actions[prev_idx]
        num_cooperators = k + (1.0 if my_prev_action else 0.0)
        num_defectors = n - num_cooperators
        if not hasattr(self, '_prev_stock'):
            self._prev_stock = capacity
        s_prev = self._prev_stock
        self._prev_stock = current_stock
        if t == r:
            if self.punishment_mode:
                return Action.D
            else:
                return Action.D
        if current_stock < capacity / (2.0 * n):
            return Action.C
        if self.punishment_mode:
            if current_stock > self.s_threshold:
                self.punishment_mode = False
                return Action.C
            else:
                return Action.D
        total_cooperators = k + (1.0 if my_prev_action else 0.0)
        total_defectors = n - total_cooperators
        if total_defectors > n / 2.0:
            self.punishment_mode = True
            return Action.D
        if current_stock < capacity / n:
            return Action.C
        if s_prev > current_stock:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_17(BaseStrategy):
    """
    A strategy that maintains a moving average of collective cooperation (trust_level)
    to decide between Cooperating (C) and Defecting (D) in a common pool resource game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_level = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r_idx = history.round_number
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        if r_idx == 0:
            return Action.C
        if r_idx == total_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        last_my_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        self.trust_level = 0.7 * self.trust_level + 0.3 * (c_prev / n)
        coop_threshold = 0.8 if n > 10 else 0.6
        if self.trust_level > coop_threshold:
            if current_stock > 0.4 * self.game_description.capacity:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_COLLECTIVE_18(BaseStrategy):
    """
    A strategy for the Common Pool Resource game that implements conditional cooperation.
    
    Logic:
    - Always cooperates in the first round.
    - Monitors the cooperation rate of opponents in previous rounds.
    - If the cooperation rate is < 0.75, it defects in the next round to punish.
    - If the current stock is dangerously low (< 20% of capacity), it defects to maximize immediate yield.
    - Always defects in the final round to maximize final payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = 0.75
        pass

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 0.2 * self.game_description.capacity:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        if n_opponents > 0:
            observed_cooperation_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            observed_cooperation_rate = 1.0
        if observed_cooperation_rate >= self.cooperation_threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_19(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Stock-Dependent Thresholds.
    
    Implements a decision logic that balances resource sustainability with
    responsiveness to opponent behavior. Prioritizes cooperation when the
    stock is healthy, tightens criteria when vulnerable, and utilizes
    a punishment/recovery mechanism for total defection scenarios.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        n_opponents = n - 1
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number + 1
        n_coop_prev = history.opponent_cooperators[-1]
        if t == r:
            return Action.C if current_stock >= 0.5 * capacity else Action.D
        if current_stock < 0.1 * capacity:
            return Action.D
        if n_coop_prev == 0:
            self.punishment_counter = 2
        if self.punishment_counter > 0:
            self.punishment_counter -= 1
            if self.punishment_counter == 0:
                return Action.C
            return Action.D
        if current_stock > 0.5 * capacity:
            if n_coop_prev >= n_opponents - 1:
                return Action.C
            return Action.D
        else:
            if n_coop_prev >= n_opponents:
                return Action.C
            return Action.D

class Strategy_COLLECTIVE_20(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with threshold-based defection.
    Focuses on sustainability by punishing defectors when stock is low, while
    remaining cooperative under stable conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        n_opponents = n - 1
        capacity = self.game_description.capacity
        prev_C_obs = history.opponent_cooperators[-1]
        prev_D_obs = n_opponents - prev_C_obs
        if self.punishment_counter > 0:
            forgiveness_triggered = False
            if history.round_number >= 2:
                last_round_full_coop = history.opponent_cooperators[-1] == n_opponents
                prev_round_full_coop = history.opponent_cooperators[-2] == n_opponents
                if last_round_full_coop and prev_round_full_coop:
                    forgiveness_triggered = True
            if forgiveness_triggered:
                self.punishment_counter = 0
            else:
                self.punishment_counter = max(0, self.punishment_counter - 1)
                return Action.D
        if prev_C_obs == n_opponents:
            return Action.C
        if current_stock < 0.25 * capacity:
            return Action.D
        if prev_C_obs < n_opponents:
            if current_stock < 0.5 * capacity:
                self.punishment_counter = max(1, int(prev_D_obs / (n / 2)))
                return Action.D
        return Action.C

class Strategy_COLLECTIVE_21(BaseStrategy):
    """
    Implements the Tit-for-Tat Adjusted Stock Thresholding strategy.
    Maintains stock via dynamic thresholds, punishes defectors, and switches to D in final round.
    Includes special handling for stock collapse and sudden defection spikes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.collapse_counter = 0
        self.last_observed_coop_rate = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if round_idx == r - 1:
            return Action.D
        if round_idx == 0:
            self.last_observed_coop_rate = 1.0
            return Action.C
        prev_my_action = bool(history.my_actions[-1])
        prev_coop_count = history.opponent_cooperators[-1]
        n_c = prev_coop_count + (1 if prev_my_action else 0)
        if current_stock < capacity / (2 * n) or self.collapse_counter > 0:
            if self.collapse_counter < 2:
                self.collapse_counter += 1
                return Action.D
            else:
                self.collapse_counter = 0
        current_observed_rate = n_c / n
        if self.last_observed_coop_rate is not None:
            if self.last_observed_coop_rate - current_observed_rate > 0.5:
                self.last_observed_coop_rate = current_observed_rate
                return Action.D
        self.last_observed_coop_rate = current_observed_rate
        if current_stock > 0 and current_stock < capacity / n and (current_observed_rate == 1.0):
            return Action.C
        if current_stock == 0:
            return Action.D
        threshold = 1.0 - current_stock / capacity
        num_others = n - 1
        if prev_my_action:
            observed_cooperation_rate = (n_c - 1) / num_others if num_others > 0 else 0
        else:
            observed_cooperation_rate = n_c / num_others if num_others > 0 else 0
        if observed_cooperation_rate >= threshold and current_stock >= capacity / n:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_22(BaseStrategy):
    """
    A strategy for the Common Pool Resource Game that balances sustainability with
    reputation-based retaliation.
    
    Strategy Overview:
    1. Initialize: Always cooperate (C) on the first round. Initialize Reputation (R) at 0.
    2. Reputation Management: Track collective behavior. R updates based on the 
       proportion of cooperators vs. a threshold (0.5).
    3. State Survival:
       - If stock < 0.05 * capacity, force Defect (D) until recovery to 0.2 * capacity.
       - If stock <= 0.1 * capacity, Defect (D).
    4. Decision Logic:
       - If R < -2, Defect (D) to punish the collective.
       - Otherwise, Cooperate (C), provided the stock is sufficient.
    5. Terminal Phase:
       - If round is final (r), Defect (D) if stock >= 0.5 * capacity, otherwise Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 0.0
        self.recovering = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_stock < 0.05 * capacity:
            self.recovering = True
        if self.recovering and current_stock > 0.2 * capacity:
            self.recovering = False
        if self.recovering:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n == 2:
            if prev_cooperators == 0:
                self.reputation -= 1.0
            else:
                self.reputation += 0.5
        else:
            coop_ratio = prev_cooperators / n_opponents
            self.reputation += coop_ratio - 0.5
        if current_round == r_total - 1:
            if current_stock >= 0.5 * capacity:
                return Action.D
            return Action.C
        if current_stock <= 0.1 * capacity:
            return Action.D
        if self.reputation < -2:
            if n == 2:
                self.reputation = 0.0
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_23(BaseStrategy):
    """
    Implements a Tit-for-Tat with Forgiveness strategy.
    
    Logic:
    1. First round: Always cooperate.
    2. Final round: Always defect.
    3. Critical stock (< 0.2 capacity): Always cooperate (recovery mode).
    4. General case: Cooperate if previous round defectors < 0.5 * n_players, else defect.
    5. Automatic forgiveness/recovery: If stock recovers/stabilizes, logic shifts back to 
       conditional cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = self.game_description.capacity
        self.n = self.game_description.n_players
        self.recovery_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n_opponents = self.n - 1
        prev_cooperators = int(history.opponent_cooperators[-1])
        prev_defectors = n_opponents - prev_cooperators
        threshold = 0.2 * self.capacity
        if current_stock < threshold:
            self.recovery_counter = 2
            return Action.C
        if self.recovery_counter > 0:
            self.recovery_counter -= 1
            return Action.C
        tolerance = 0.5 * self.n
        if prev_defectors >= tolerance:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_24(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Common Pool Resource Game.
    The strategy aims to maintain the stock level at capacity through Tit-For-Tat-like
    behavior, with specific responses to depletion and terminal rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        total_rounds = self.n_rounds
        if current_round_index == 0:
            return Action.C
        if current_round_index == total_rounds - 1:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if abs(current_stock - self.capacity) < 1e-06 or current_stock >= 0.95 * self.capacity:
            return Action.C
        my_last_action = history.my_actions[-1]
        total_cooperators_last_round = prev_cooperators + (1 if my_last_action else 0)
        threshold = self.n // 2
        if total_cooperators_last_round >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_25(BaseStrategy):
    """
    A Trigger-Tit-for-Tat strategy that incorporates sustainability thresholds based on 
    current resource stock. It attempts to cooperate when conditions are favorable, 
    punishes defectors based on recent history, and aggressively exploits the pool in 
    the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.in_defect_state = False
        self.resumption_threshold = 0.8

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        prev_cooperators_total = history.opponent_cooperators[-1] + my_prev_action
        if current_stock < self.capacity / (10 * self.n):
            self.in_defect_state = True
            return Action.D
        if self.in_defect_state:
            if current_stock > self.resumption_threshold * self.capacity:
                self.in_defect_state = False
                return Action.C
            else:
                return Action.D
        if prev_cooperators_total >= self.n - 1:
            return Action.C
        elif prev_cooperators_total >= self.n / 2 and current_stock > self.capacity / 2:
            return Action.C
        else:
            self.in_defect_state = True
            return Action.D

class Strategy_COLLECTIVE_26(BaseStrategy):
    """
    A strategy for the Common Pool Resource Game that balances reciprocity,
    stock preservation, and retaliation, while transitioning to defection 
    near the end of the game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.retaliation_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if self.game_description.n_rounds - history.round_number <= 2:
            return Action.D
        n = self.game_description.n_players
        opponents_count = n - 1
        num_cooperators_prev = history.opponent_cooperators[-1]
        d_prev = opponents_count - num_cooperators_prev
        if self.retaliation_counter > 0:
            self.retaliation_counter -= 1
            return Action.D
        my_prev_action = history.my_actions[-1]
        total_defectors = d_prev + (0 if my_prev_action else 1)
        if total_defectors > n / 2:
            self.retaliation_counter = 1
            return Action.D
        s_index = current_stock / self.game_description.capacity
        if s_index < 0.25:
            return Action.C
        if d_prev == 0:
            return Action.C
        else:
            prob = d_prev / n
            if random.random() < prob:
                return Action.D
            else:
                return Action.C

class Strategy_COLLECTIVE_27(BaseStrategy):
    """
    Implements a 'Tit-for-Tat with Forgiveness and Stock-Awareness' strategy.
    
    Logic summary:
    1. First round: Cooperate (C).
    2. Endgame: Defect (D) on the final round.
    3. Critical Stock: Defect (D) if stock <= capacity / 4.
    4. Reciprocity: Defect (D) if fewer than 50% of opponents cooperated previously, 
       unless forgiveness threshold (80% cooperation) is met.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t_index = history.round_number
        if t_index == self.r - 1:
            return Action.D
        if current_stock <= self.capacity / 4:
            return Action.D
        if t_index == 0:
            return Action.C
        n_opponents = self.n - 1
        prev_opp_cooperators = history.opponent_cooperators[-1]
        threshold = n_opponents * 0.5
        forgiveness_threshold = n_opponents * 0.8
        if prev_opp_cooperators >= threshold:
            return Action.C
        else:
            if prev_opp_cooperators >= forgiveness_threshold:
                return Action.C
            return Action.D

class Strategy_COLLECTIVE_28(BaseStrategy):
    """
    Implements a conditional Tit-for-Tat strategy with resilience thresholds.
    
    Logic:
    - Round 0: Always C.
    - Resilience Override: If stock < 0.1 * capacity, C only if everyone else (or n-1 players) cooperated.
    - End-Game (Final round): If stock < 0.25 * capacity, play D.
    - Standard Rounds: Play based on CR = (num_cooperators / n).
      - CR >= 0.75: C
      - 0.5 <= CR < 0.75: C if stock >= 0.5 * capacity, else D
      - CR < 0.5: D
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.capacity = self.game_description.capacity
        self.r = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        my_prev_action = history.my_actions[prev_round_idx]
        my_prev_coop = 1 if my_prev_action else 0
        total_cooperators = history.opponent_cooperators[prev_round_idx] + my_prev_coop
        cr = total_cooperators / self.n
        if current_stock < self.capacity * 0.1:
            if total_cooperators >= self.n - 1:
                return Action.C
            else:
                return Action.D
        if history.round_number == self.r - 1:
            if current_stock < self.capacity * 0.25:
                return Action.D
        if cr >= 0.75:
            return Action.C
        elif cr >= 0.5:
            if current_stock >= self.capacity * 0.5:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_COLLECTIVE_29(BaseStrategy):
    """
    Tit-for-Tat with a sustainable threshold strategy. 
    Prioritizes resource maintenance (C) when stock is low or when cooperation 
    is observed, but punishes defectors (D) when stock allows. In the final 3 rounds, 
    it aggressively extracts value (D) if the stock is sufficiently high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.game_description.n_rounds - 3:
            if current_stock > self.game_description.capacity / 4:
                return Action.D
            else:
                return Action.C
        my_last_action = history.my_actions[-1]
        opponents_who_cooperated = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if opponents_who_cooperated < n_opponents:
            return Action.D
        if current_stock < self.game_description.capacity / 2:
            return Action.C
        return Action.C

class Strategy_COLLECTIVE_30(BaseStrategy):
    """
    Implements a Tit-for-Tat variant with a threshold-based forgiveness mechanism 
    designed for the Common Pool Resource Game.
    
    Logic Summary:
    1. Initial round: Cooperate.
    2. End-game (final round): Defect.
    3. Crisis management: If stock < 2*n, maintain cooperation for recovery unless 
       stock is critically low (< 0.1 * capacity), in which case Defect to capture remaining value.
    4. Steady state: If round < r and stock >= 2*n:
       - Cooperative if previous round cooperation rate >= ceil(n/2).
       - Otherwise, Defect with a 20% probability of forgiveness (testing the waters).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.r - 1:
            return Action.D
        if current_stock < 2 * self.n:
            if current_stock < 0.1 * self.capacity:
                return Action.D
            else:
                return Action.C
        if current_round_idx == 0:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        my_prev_action = int(history.my_actions[-1])
        total_cooperators = last_round_cooperators + my_prev_action
        threshold = math.ceil(self.n / 2)
        if total_cooperators >= threshold:
            return Action.C
        elif random.random() < 0.2:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_31(BaseStrategy):
    """
    A conditional cooperative strategy for the Common Pool Resource Game.
    
    Strategy Logic:
    1. Phase 1 (Round 1): Plays Cooperate (C).
    2. Phase 2 (Rounds 2 to r-1):
       - If stock < 0.25 * capacity: Defect (D) to maximize extraction.
       - Else: If all other players cooperated in the previous round, Cooperate (C). 
         Otherwise, Defect (D) for one round as retaliation.
    3. Phase 3 (Final Round r): Always Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n_total = self.game_description.n_players
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.game_description.capacity * 0.25:
            return Action.D
        prev_my_cooperated = bool(history.my_actions[-1])
        total_cooperators = (1 if prev_my_cooperated else 0) + history.opponent_cooperators[-1]
        if total_cooperators == n_total:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_32(BaseStrategy):
    """
    A conditional cooperation strategy based on a Tit-for-Tat variant.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Terminal Round: Always Defect (D).
    - Other Rounds:
        - If all other players cooperated last round, Cooperate (C).
        - If others defected:
            - If stock is critical (< 50% capacity), Defect (D).
            - Otherwise, Cooperate (C) to attempt signal recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.n_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        c_obs = history.opponent_cooperators[-1]
        if c_obs == self.n_players - 1:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_5(BaseStrategy):
    """
    A Prosocial Compliance strategy for Common Pool Resource games.
    
    Logic:
    1. Round 1: Always Cooperate (C).
    2. Stock Floor Check: If stock < capacity/(4n), always Defect (D).
    3. Terminal Round (r): If stock >= capacity/(2n), C; else D.
    4. Phase 2 (Intermediate Rounds):
        a. If stock < capacity/(2n), Defect (D).
        b. If currently in 'Defect' mode due to low PCR:
           Check if stock recovered to >= capacity/2.
           If yes, try Cooperating (C) to test opponents.
           If k_t (total cooperators) == n, permanently switch to Cooperation mode.
           Else, Defect (D).
        c. If in 'Cooperate' mode or normal play:
           Calculate Prosocial Compliance Ratio (PCR).
           If PCR >= 0.5, Cooperate (C).
           Else, Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.in_defect_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_stock < capacity / (4 * n):
            self.in_defect_mode = True
            return Action.D
        if current_round == 0:
            return Action.C
        if current_round == r_total - 1:
            if current_stock >= capacity / (2 * n):
                return Action.C
            return Action.D
        if current_stock < capacity / (2 * n):
            self.in_defect_mode = True
            return Action.D
        if self.in_defect_mode:
            if current_stock >= capacity / 2.0:
                return Action.C
            else:
                return Action.D
        my_actions_int = history.my_actions.astype(int)
        total_cooperators_history = history.opponent_cooperators + my_actions_int
        numerator = np.sum(history.opponent_cooperators)
        denominator = n * current_round
        pcr = numerator / denominator if denominator > 0 else 1.0
        if pcr >= 0.5:
            self.in_defect_mode = False
            return Action.C
        else:
            self.in_defect_mode = True
            return Action.D

class Strategy_PROSOCIAL_6(BaseStrategy):
    """
    A strategy that maintains common pool sustainability by targeting a specific number of cooperators.
    It cooperates when the stock is healthy or when the group trend is sufficient to support
    the target, and defects when the stock is critically low or the group is depleting the resource.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = float(game_description.capacity)
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.total_rounds - 1:
            if current_stock < self.capacity / 2.0:
                return Action.D
            return Action.C
        if current_stock < 1e-06:
            return Action.D
        raw_target = self.n * self.capacity / current_stock
        target_cooperators = min(float(self.n), raw_target)
        if current_stock >= 0.9 * self.capacity:
            return Action.C
        if history.round_number > 0:
            my_prev_action = 1 if history.my_actions[-1] else 0
            prev_cooperators_total = history.opponent_cooperators[-1] + my_prev_action
            if prev_cooperators_total >= target_cooperators:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_PROSOCIAL_7(BaseStrategy):
    """
    Implements a reputation-based reciprocal strategy that prioritizes 
    long-term stock sustainability by mimicking observed cooperation levels,
    punishing defection, and collapsing to defect in the final round or 
    during resource depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if current_round_index == self.r - 1:
            return Action.D
        if current_round_index == 0:
            return Action.C
        c_prev = history.opponent_cooperators[-1]
        if current_stock <= 0.25 * self.capacity:
            return Action.D
        if c_prev == self.n_opponents:
            return Action.C
        if self.n_opponents > 0:
            threshold = 0.5 * self.n_opponents
            if c_prev > threshold:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_PROSOCIAL_8(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness:
    - Always cooperates in the first round.
    - Always defects in the final round (optimal payoff strategy).
    - In intermediate rounds:
        - Rewards full cooperation (0 defectors) with cooperation.
        - If previous round had defectors:
            - If stock is critical (< 25% capacity), defects to salvage resources.
            - If stock is low (< 50% capacity) and defectors exist, defects to protect utility.
            - Otherwise, cooperates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        num_opponents = self.n - 1
        i_cooperated = history.my_actions[last_round_idx]
        opponents_who_cooperated = history.opponent_cooperators[last_round_idx]
        opponents_who_defected = num_opponents - opponents_who_cooperated
        k_prev = opponents_who_defected + (0 if i_cooperated else 1)
        if k_prev == 0:
            return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.D
        if current_stock < self.capacity * 0.5:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_9(BaseStrategy):
    """
    Target-Stock Triggered Reciprocity Strategy.
    Maintains capacity by targeting a steady-state stock. Prioritizes sustainability
    over retaliation during recovery phases and critical shortages, but enforces
    cooperation otherwise.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number + 1
        if current_round == r:
            return Action.D
        if current_stock < 0.1 * capacity:
            return Action.C
        if current_stock < 0.5 * capacity:
            return Action.C
        if current_round == 1:
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        if history.round_number > 1:
            k_prev_prev = history.opponent_cooperators[-2]
            if k_prev_prev < n - 1 and history.my_actions[-1] == False:
                return Action.C
        if k_prev >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_10(BaseStrategy):
    """
    A conditional cooperation strategy that maintains resource sustainability 
    through reciprocal cooperation while dynamically reacting to stock depletion 
    and end-game incentives.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.capacity = self.game_description.capacity
        self.threshold_cooperators = (self.n - 1) / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        is_final_round = current_round == self.r - 1
        if is_final_round:
            if current_stock > self.capacity / 2:
                return Action.C
            else:
                return Action.D
        if current_round == 0:
            return Action.C
        c_obs = history.opponent_cooperators[-1]
        if current_stock < self.capacity / 2:
            if c_obs < self.threshold_cooperators:
                return Action.D
            else:
                return Action.C
        if c_obs >= self.threshold_cooperators:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_11(BaseStrategy):
    """
    A strategy that implements conditional cooperation (Tit-for-Tat) 
    with a strict sustainability override. It cooperates when stock is 
    low (conservation), cooperates in the first round, and employs 
    probabilistic defection based on opponent behavior in later rounds, 
    while always defecting in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.r:
            return Action.D
        if current_stock < self.capacity / 2.0:
            return Action.C
        if current_round == 1:
            return Action.C
        last_round_cooperators = int(history.opponent_cooperators[-1])
        target_threshold = self.n - 1
        if last_round_cooperators >= target_threshold:
            return Action.C
        else:
            prob_defect = 1.0 - last_round_cooperators / self.n
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_12(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Sustainability Buffer.
    
    This strategy balances resource maintenance with responsive punishment.
    It prioritizes stock regeneration when the pool is low (< 50% capacity)
    or critically low (< 10% capacity). It uses a "Tit-for-Tat" approach
    regarding opponent cooperation in standard conditions, while always
    defecting in the final round to capture remaining resources.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._previous_stock = -1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        round_idx = history.round_number
        is_last_round = round_idx == self.game_description.n_rounds - 1
        if is_last_round:
            self._previous_stock = current_stock
            return Action.D
        if round_idx == 0:
            self._previous_stock = current_stock
            return Action.C
        prev_coop_count = history.opponent_cooperators[-1]
        prev_defector_count = n_opponents - prev_coop_count
        is_recovering = current_stock > self._previous_stock * 1.2
        self._previous_stock = current_stock
        if current_stock < 0.1 * self.game_description.capacity:
            return Action.C
        if current_stock < 0.5 * self.game_description.capacity:
            if is_recovering:
                return Action.C
            if prev_coop_count < n / 2:
                return Action.D
            else:
                return Action.C
        if is_recovering:
            return Action.C
        if prev_defector_count > n / 2:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_13(BaseStrategy):
    """
    Implements Proportional Tit-for-Tat with Threshold Sensitivity.
    
    Strategy:
    1. Initial Round: Always Cooperate (C).
    2. Terminal Round (last round): Always Defect (D).
    3. Desperation Threshold: If current_stock < (capacity / n), Defect (D).
    4. Tit-for-Tat Logic: If current_stock >= (capacity / n), cooperate if the 
       number of opponents who cooperated in the previous round >= ceil((n-1)/2).
       Otherwise, defect to punish non-cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if current_stock < self.capacity / self.n_players:
            return Action.D
        n_opponents = self.n_players - 1
        threshold = math.ceil(n_opponents / 2)
        last_round_cooperators = history.opponent_cooperators[-1]
        if last_round_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_14(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Depletion Awareness:
    A strategy that balances resource sustainability with cooperative reciprocity.
    It utilizes a survival threshold (20% capacity), a final round defection trigger,
    and a cooperation threshold (based on 75% of players) to decide actions, 
    with a conditional forgiveness mechanism based on stock health.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.theta = 0.25

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < self.game_description.capacity * 0.2:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        prev_k_others = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        prev_k_total = prev_k_others + (1 if my_prev_action else 0)
        if prev_k_total >= n - self.theta * n:
            return Action.C
        if current_stock >= self.game_description.capacity * 0.5:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_15(BaseStrategy):
    """
    A sustainability-focused strategy that balances resource replenishment with 
    tit-for-tat retaliation. It prioritizes the common pool stock level, 
    switching to cooperation if the stock is below a target threshold, 
    and uses the opponent cooperation rate to decide actions when the 
    stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.target_stock = game_description.capacity * 0.5
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if round_idx == 0:
            return Action.C
        prev_opp_coops = history.opponent_cooperators[-1]
        if round_idx == total_rounds - 1:
            all_prev_opp_coops = history.opponent_cooperators
            avg_opp_coop_rate = np.mean(all_prev_opp_coops) / self.n_opponents
            if avg_opp_coop_rate < 0.5:
                return Action.D
            return Action.C
        if current_stock < self.target_stock:
            return Action.C
        threshold = (self.game_description.n_players - 1) / 2
        if prev_opp_coops >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_16(BaseStrategy):
    """
    Implements a Target-Stock Tit-for-Tat strategy.
    
    This strategy attempts to maintain the common pool at capacity.
    1. If stock is critical (< 25% of capacity), prioritize replenishment via C.
    2. If stock is low (< 50% of capacity), prioritize C to ensure survival.
    3. In the final round, act greedily if the pool is healthy (>= 50% capacity).
    4. Otherwise, use reciprocity: if cooperation in the previous round was < 50%,
       defect for one round to signal intolerance, then return to C.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.last_action_was_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number + 1
        if history.round_number == 0:
            self.last_action_was_defect = False
            return Action.C
        if current_stock < self.capacity / 4:
            self.last_action_was_defect = False
            return Action.C
        if current_stock < self.capacity / 2:
            self.last_action_was_defect = False
            return Action.C
        if round_t == self.r:
            if current_stock >= 0.5 * self.capacity:
                self.last_action_was_defect = True
                return Action.D
            else:
                self.last_action_was_defect = False
                return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators = last_round_cooperators + (1 if my_last_action else 0)
        cooperation_rate = total_cooperators / self.n
        if cooperation_rate >= 0.5:
            self.last_action_was_defect = False
            return Action.C
        elif self.last_action_was_defect:
            self.last_action_was_defect = False
            return Action.C
        else:
            self.last_action_was_defect = True
            return Action.D

class Strategy_PROSOCIAL_17(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource game.
    Implements sustainability-focused thresholds (Critical Buffer, Target Stock) 
    and reciprocation logic to manage resource growth.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        s_star = self.capacity * 0.5
        s_critical = self.capacity * 0.2
        prev_my_action = history.my_actions[-1]
        k_prev = history.opponent_cooperators[-1] + (1 if prev_my_action else 0)
        if t == self.r - 1:
            start_idx = max(0, t - 3)
            recent_coop = history.opponent_cooperators[start_idx:]
            my_recent = history.my_actions[start_idx:]
            total_recent_k = [opp + (1 if my else 0) for opp, my in zip(recent_coop, my_recent)]
            avg_cooperation = sum(total_recent_k) / (len(total_recent_k) * self.n)
            if avg_cooperation > 0.8:
                return Action.C
            else:
                return Action.D
        if current_stock < s_critical:
            return Action.C
        if k_prev >= self.n - 1:
            return Action.C
        elif current_stock < s_star:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_18(BaseStrategy):
    """
    A strategy that maintains common pool resources by monitoring stock levels and 
    conditional reciprocity (Tit-for-Tat based on a prosocial threshold). 
    It switches to aggressive extraction (Defect) if the resource approaches 
    collapse or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_critical = 0.2 * game_description.capacity
        self.threshold_recovery = 0.1 * game_description.capacity
        self.prosocial_threshold = 0.5
        self.stock_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.stock_history.append(current_stock)
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        prev_opp_C_count = history.opponent_cooperators[-1]
        opp_coop_rate = prev_opp_C_count / n_opponents if n_opponents > 0 else 1.0
        if current_stock <= self.threshold_recovery:
            return Action.D
        if current_stock <= self.threshold_critical:
            return Action.D
        if len(self.stock_history) >= 3:
            if self.stock_history[-1] < self.stock_history[-2] and self.stock_history[-2] < self.stock_history[-3]:
                if opp_coop_rate < self.prosocial_threshold:
                    return Action.D
        if opp_coop_rate >= self.prosocial_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_19(BaseStrategy):
    """
    Prosocial Equilibrium Maintenance (PEM)
    
    A conditional cooperator strategy that balances resource sustainability with
    retaliatory logic. It prioritizes cooperation but switches to defection if 
    the common pool stock vitality drops below critical thresholds or if defection 
    occurs, with specific end-game considerations.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        if self.r - current_round < self.n:
            if current_stock < 0.2 * self.capacity:
                return Action.D
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponents_cooperating = history.opponent_cooperators[-1]
        total_cooperators = int(last_my_action) + last_opponents_cooperating
        num_defectors = self.n - total_cooperators
        if num_defectors == 0:
            return Action.C
        else:
            vitality = current_stock / self.capacity if self.capacity > 0 else 0.0
            if vitality > 0.4:
                return Action.C if random.random() > 0.5 else Action.D
            else:
                return Action.D

class Strategy_PROSOCIAL_20(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource Game.
    Starts by cooperating, then adjusts based on the observed cooperation of opponents.
    Features a punishment mechanism for defection and an emergency override for low stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n = self.game_description.n_players
        if n > 10:
            self.cooperation_threshold = max(0.2, (n - 2) / (2 * n))
        else:
            self.cooperation_threshold = 0.5
        self.is_punished = False
        self.override_recovery = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        capacity = self.game_description.capacity
        if current_stock < capacity / 4.0:
            self.override_recovery = True
            return Action.C
        if self.override_recovery:
            self.is_punished = False
            self.override_recovery = False
        if history.round_number == 0:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        prev_my_action = history.my_actions[-1]
        prev_opponents_cooperated_count = history.opponent_cooperators[-1]
        if n_opponents > 0:
            opponents_cooperated_frac = prev_opponents_cooperated_count / n_opponents
        else:
            opponents_cooperated_frac = 1.0
        current_round_idx = history.round_number
        is_last_round = current_round_idx == self.game_description.n_rounds - 1
        if not is_last_round:
            if self.is_punished:
                return Action.D
            elif opponents_cooperated_frac >= self.cooperation_threshold:
                return Action.C
            else:
                self.is_punished = True
                return Action.D
        elif self.is_punished or opponents_cooperated_frac < self.cooperation_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_21(BaseStrategy):
    """
    Conditional Sustainability (CS) strategy:
    - Maintains a target stock level to maximize sustainable yield.
    - Uses adaptive thresholds for cooperation based on opponent history.
    - Implements a recovery mode if stock drops below a critical point (capacity/4).
    - Defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.k_threshold = math.floor((self.n - 1) / 2)
        self.alpha = 0.9
        self.recovery_rounds_left = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round > 0:
            k_prev = int(history.opponent_cooperators[-1])
            self.k_threshold = self.alpha * self.k_threshold + (1 - self.alpha) * k_prev
            self.k_threshold = max(0, min(self.k_threshold, self.n - 1))
            if self.recovery_rounds_left > 0:
                self.recovery_rounds_left -= 1
        if current_stock < self.capacity / 4:
            self.recovery_rounds_left = 2
        if current_round == self.r - 1:
            return Action.D
        if self.recovery_rounds_left > 0:
            return Action.C
        if current_round == 0:
            return Action.C
        if current_stock < self.capacity / 2:
            return Action.D
        k_prev = int(history.opponent_cooperators[-1])
        if k_prev >= self.k_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_22(BaseStrategy):
    """
    Implements a Conditional Cooperator strategy. 
    Tracks reputation based on opponent history and adjusts cooperation based on 
    pool stock levels, utilizing a Tit-for-Tat impulse for maintenance.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 1.0
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 1e-09:
            return Action.C
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            total_observed_coop = 0.0
            for coop_count in history.opponent_cooperators:
                total_observed_coop += coop_count / max(1, self.n_opponents)
            avg_coop = total_observed_coop / history.round_number
            return Action.C if avg_coop >= 0.5 else Action.D
        recent_coop_count = history.opponent_cooperators[-1]
        observed_cooperation = recent_coop_count / max(1, self.n_opponents)
        self.reputation = 0.9 * self.reputation + 0.1 * observed_cooperation
        capacity = self.game_description.capacity
        if current_stock < capacity / 4:
            return Action.C if observed_cooperation >= 0.5 else Action.D
        else:
            return Action.C if self.reputation >= 0.7 else Action.D

class Strategy_PROSOCIAL_23(BaseStrategy):
    """
    Conditional Sustainability strategy.
    Prioritizes maintaining stock at capacity by calculating sustainable defector thresholds.
    Punishes unsustainable consumption by defecting, while signaling cooperation recovery
    after a correction phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.in_correction_phase = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_stock <= 1e-09:
            return Action.D
        if current_round == r_total - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if self.in_correction_phase:
            self.in_correction_phase = False
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        d_prev = n - c_prev
        t_crit = n // 2
        if current_stock < capacity * 0.25:
            return Action.D
        if d_prev > t_crit:
            self.in_correction_phase = True
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_24(BaseStrategy):
    """
    Implements a threshold-based conditional cooperation strategy.
    
    Logic:
    1. First round: Always Cooperate (C).
    2. Terminal round (last round): Always Defect (D).
    3. Intermediate rounds:
       - If all opponents cooperated in the previous round, Cooperate (C).
       - If current stock is critical (stock < capacity/4), Cooperate (C).
       - Otherwise (if opponents defected or stock is healthy), Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.num_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        k = int(history.opponent_cooperators[-1])
        if current_stock < self.capacity / 4.0:
            return Action.C
        if k == self.num_opponents:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_25(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy for the Common Pool Resource Game.
    
    This strategy focuses on maintaining long-term cooperation while protecting against 
    total resource collapse.
    
    Logic:
    1. Round 1: Always Cooperate (C).
    2. Last Round: Always Defect (D) to maximize final payoff.
    3. Intermediate Rounds:
       - If stock <= capacity / 4: Defect (D) due to critical resource scarcity.
       - Else if previous round cooperators >= n - 1: Cooperate (C) to sustain pool.
       - Otherwise: Defect (D) to punish/limit over-extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)
        self.stock_critical_level = self.capacity / 4.0
        self.cooperation_threshold = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock <= self.stock_critical_level:
            return Action.D
        prev_round_cooperators = int(history.opponent_cooperators[-1])
        if prev_round_cooperators >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_26(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Resource-Contingent Forgiveness.
    Prioritizes sustainability via thresholds while using reciprocal defection
    penalties, with a mechanism to force forgiveness if the resource stock recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.HIGH_STOCK_THRESHOLD = 0.8 * self.capacity
        self.CRITICAL_STOCK_THRESHOLD = 0.2 * self.capacity
        self.TERMINATION_THRESHOLD = 0.5 * self.capacity
        self.RECOVERY_THRESHOLD = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        total_rounds = self.game_description.n_rounds
        current_round_index = history.round_number
        if current_round_index == total_rounds - 1:
            return Action.C if current_stock > self.TERMINATION_THRESHOLD else Action.D
        my_last_action = history.my_actions[-1]
        last_round_cooperators = (1 if my_last_action else 0) + history.opponent_cooperators[-1]
        acr = last_round_cooperators / self.n
        if not my_last_action and current_stock > self.RECOVERY_THRESHOLD:
            return Action.C
        if current_stock > self.HIGH_STOCK_THRESHOLD:
            return Action.C
        if current_stock < self.CRITICAL_STOCK_THRESHOLD:
            return Action.C if acr >= 0.5 else Action.D
        return Action.C if acr >= 0.5 else Action.D

class Strategy_PROSOCIAL_27(BaseStrategy):
    """
    A 'Responsive Sustainability' strategy that prioritizes long-term resource stability.
    It begins with cooperation to test the environment. In intermediate rounds, it monitors
    the stock level and the cooperation rate of opponents. It forces depletion if the stock
    is critically low (to reset growth) or if the majority of opponents are defecting (to
    punish/extract). In the final round, it consumes based on whether the stock is sustainable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.prev_stock_cache = float(self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number + 1
        if round_t == 1:
            self.prev_stock_cache = current_stock
            return Action.C
        n_opponents = self.n_players - 1
        last_coop_count = history.opponent_cooperators[-1]
        cooperation_rate = last_coop_count / n_opponents if n_opponents > 0 else 0.0
        prev_stock = self.prev_stock_cache
        self.prev_stock_cache = current_stock
        if round_t == self.n_rounds:
            if prev_stock > 0.5 * self.capacity:
                return Action.C
            else:
                return Action.D
        if prev_stock < 0.2 * self.capacity:
            return Action.D
        if cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_28(BaseStrategy):
    """
    A conditional cooperator strategy that tracks population cooperation history,
    utilizing a forgiving tit-for-tat mechanism with stock-dependent thresholding.
    Prioritizes sustainability via depletion awareness.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.last_action_was_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            self.last_action_was_defect = False
            return Action.C
        if current_stock < self.capacity * 0.25:
            self.last_action_was_defect = True
            return Action.D
        if current_round == self.r - 1:
            if current_stock >= self.capacity * 0.5:
                self.last_action_was_defect = False
                return Action.C
            else:
                self.last_action_was_defect = True
                return Action.D
        if self.last_action_was_defect:
            if current_stock >= self.capacity * 0.5:
                self.last_action_was_defect = False
                return Action.C
            return Action.D
        total_coops = int(np.sum(history.opponent_cooperators))
        total_possible = (self.n - 1) * current_round
        opp_rate = total_coops / total_possible if total_possible > 0 else 1.0
        if opp_rate >= 0.75:
            action = Action.C
        elif opp_rate >= 0.4:
            action = Action.C if random.random() < opp_rate else Action.D
        else:
            action = Action.D
        self.last_action_was_defect = action == Action.D
        return action

class Strategy_PROSOCIAL_29(BaseStrategy):
    """
    A strategy that balances sustainable cooperation, reciprocal punishment for 
    defection, and reactive restoration phases based on stock health.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = float(game_description.capacity)
        self.penalty_countdown = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_opponents = self.game_description.n_players - 1
        if current_stock <= 0.0:
            self.prev_stock = 0.0
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            self.prev_stock = current_stock
            return Action.C
        if current_stock > self.prev_stock * 1.3:
            self.prev_stock = current_stock
            return Action.C
        if history.round_number >= 2:
            rho_last = history.opponent_cooperators[-1] / n_opponents
            rho_prev = history.opponent_cooperators[-2] / n_opponents
            if rho_last < 0.2 and rho_prev < 0.2:
                self.penalty_countdown = 2
        if self.penalty_countdown > 0:
            self.penalty_countdown -= 1
            self.prev_stock = current_stock
            return Action.D
        rho = history.opponent_cooperators[-1] / n_opponents
        self.prev_stock = current_stock
        if current_stock >= self.game_description.capacity * 0.5:
            return Action.C if rho >= 0.5 else Action.D
        else:
            return Action.C if rho > 0.8 else Action.D

class Strategy_PROSOCIAL_30(BaseStrategy):
    """
    A conditionally cooperative strategy for the Common Pool Resource Game.
    Maintains cooperation while the stock is above a threshold (T=0.5*capacity).
    If below threshold, adapts to opponent behavior.
    Includes edge case handling for exhaustion and critical recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.T = 0.5 * self.capacity
        self.critical_level = 0.2 * self.capacity
        self.was_in_recovery = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.was_in_recovery = False
            return Action.C
        if current_stock < 1e-06:
            return Action.D
        if self.was_in_recovery:
            self.was_in_recovery = False
            return Action.C
        if current_stock < self.critical_level:
            self.was_in_recovery = True
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock >= self.T:
                return Action.C
            else:
                return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        majority_threshold = self.n / 2
        if current_stock > self.T:
            return Action.C
        elif prev_cooperators >= majority_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_31(BaseStrategy):
    """
    Implements a Tit-for-Tat variant for common pool resources.
    - Round 1: Cooperate.
    - Last round: Defect if stock > 0, else Cooperate.
    - Rescue Mode: If stock < capacity/4, Defect to allow recovery.
    - Cooperation Logic: If recent avg opponent cooperation >= 0.5, Cooperate; else Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        current_round_num = current_round_idx + 1
        if current_round_idx == self.r - 1:
            return Action.D if current_stock > 0 else Action.C
        if current_stock < self.capacity / 4:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        k = min(current_round_idx, 3)
        start_idx = current_round_idx - k
        recent_coop_counts = history.opponent_cooperators[start_idx:current_round_idx]
        total_coops = np.sum(recent_coop_counts)
        avg_opponents_cooperation = total_coops / (k * self.n_opponents)
        if avg_opponents_cooperation >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_32(BaseStrategy):
    """
    A strategy that maintains cooperation while resources are sustainable, 
    punishes defectors when resources are critical, and maximizes yield 
    in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock >= 0.5 * self.capacity:
                return Action.C
            else:
                return Action.D
        if current_stock < 0.05 * self.capacity:
            return Action.D
        i_cooperated = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + i_cooperated
        if total_cooperators_prev == self.n:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_5(BaseStrategy):
    """
    A Conditional Tit-for-Tat strategy with Resource Preservation.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Round r (Final): Always Defect (D).
    - Rounds 2 to r-1: 
        - If all players cooperated last round (C_observed == n), continue to Cooperate (C).
        - If defection occurred (C_observed < n):
            - If stock < 0.5 * capacity, Defect (D) to secure remaining value.
            - If stock >= 0.5 * capacity, Cooperate (C) to signal altruism/forgiveness.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        last_opponents_c = history.opponent_cooperators[-1]
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        total_cooperators = last_opponents_c + (1 if my_last_action == Action.C else 0)
        if total_cooperators == self.game_description.n_players:
            return Action.C
        safety_threshold = 0.5 * self.game_description.capacity
        if current_stock < safety_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_6(BaseStrategy):
    """
    Implements a Conditional Sustainable Stewardship strategy. 
    Prioritizes resource survival using threshold-based consumption, 
    reciprocal tit-for-tat logic, and adaptive correction for 
    unsustainable resource extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.max_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_stock <= self.capacity / 4.0:
            return Action.C
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponents_c = history.opponent_cooperators[-1]
        k = last_opponents_c + (1 if last_my_action else 0)
        if current_round == self.max_rounds - 1:
            if current_stock > self.capacity / 2.0:
                return Action.D
            return Action.C
        if k == self.n:
            return Action.C
        if current_stock < self.capacity / 2.0:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_7(BaseStrategy):
    """
    Implements a reciprocal cooperation strategy for the Common Pool Resource game.
    The strategy cooperates by default but switches to defect if the stock
    reaches critical levels or if the observed aggregate cooperation rate
    from opponents falls below a trust threshold (0.5) while the stock is declining.
    It unconditionally defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_threshold = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock < capacity * 0.2:
            return Action.D
        if current_round_idx > 0:
            total_cooperators_observed = np.sum(history.opponent_cooperators)
            total_slots_available = (n_players - 1) * current_round_idx
            avg_cooperation = total_cooperators_observed / total_slots_available if total_slots_available > 0 else 1.0
            if avg_cooperation < self.trust_threshold:
                return Action.D
        return Action.C

class Strategy_ALTRUISTIC_8(BaseStrategy):
    """
    A strategy that prioritizes sustainability by cooperating by default,
    employing a Tit-for-Tat retaliation mechanism to punish over-extraction,
    incorporating a forgiveness mechanism, and utilizing a stock-dependent
    threshold to ensure recovery during critical shortages.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx >= self.r - 2:
            if current_stock < 0.25 * self.capacity:
                return Action.C
            cooperation_count = np.sum(history.my_actions)
            cooperation_rate = cooperation_count / current_round_idx
            if cooperation_rate >= 0.75:
                return Action.D
            else:
                return Action.C
        last_round_idx = current_round_idx - 1
        last_my_action = history.my_actions[last_round_idx]
        last_my_cooperation = 1 if last_my_action else 0
        total_cooperators = last_my_cooperation + history.opponent_cooperators[last_round_idx]
        cr = total_cooperators / self.n
        if current_stock > 0.5 * self.capacity:
            if cr >= 0.5:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_9(BaseStrategy):
    """
    Threshold-Triggered Tit-for-Tat Strategy:
    - Maintains a 'cooperation score' to track collective behavior.
    - Starts with cooperation (Round 1).
    - If the resource is critical (< 20% capacity) or it is the final round, always defect.
    - Otherwise, updates the cooperation score based on how many opponents cooperated
      in the previous round. If score >= 0, cooperates; else, defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.c_score = 0
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if current_stock < 0.2 * self.capacity:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_idx = -1
        prev_opp_coop = int(history.opponent_cooperators[last_round_idx])
        my_prev_action = history.my_actions[last_round_idx]
        if my_prev_action:
            others_cooperated = prev_opp_coop
        else:
            others_cooperated = prev_opp_coop
        if others_cooperated == self.n - 1:
            self.c_score += 1
        else:
            self.c_score -= self.n - 1 - others_cooperated
        if self.c_score >= 0:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_10(BaseStrategy):
    """
    Implements the 'Sustainable Stewardship' strategy.
    
    This strategy focuses on maintaining the common pool resource stock by prioritizing
    sustainability. It uses a Tit-for-Tat variant with forgiveness, monitoring the 
    previous round's cooperation rate (C_rate) and current stock level to decide 
    whether to cooperate or defect. 
    
    It employs:
    1. Initial cooperation.
    2. Stock crisis management: If stock is below 20% capacity, it defaults to cooperation.
    3. Adaptive behavior: 
        - Cooperate if all cooperate.
        - Defect if cooperation is low (<= n/2).
        - Use stock thresholds for medium cooperation scenarios.
    4. Terminal strategy: Defect in the final round only if the resource is healthy and 
       the history indicates strong overall cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.threshold_stock = 0.5 * self.capacity
        self.crisis_stock = 0.2 * self.capacity
        self.last_round_coop_threshold = 0.75 * self.n

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_C_rate = float(history.opponent_cooperators[-1])
        r = history.round_number
        if current_stock < self.crisis_stock:
            return Action.C
        if r == self.n_rounds - 1:
            half_r = max(1, r // 2)
            recent_history = history.opponent_cooperators[-half_r:]
            avg_C_rate = np.mean(recent_history)
            if current_stock > self.threshold_stock and avg_C_rate > self.last_round_coop_threshold:
                return Action.D
            else:
                return Action.C
        if prev_C_rate == self.n:
            return Action.C
        elif prev_C_rate <= self.n / 2:
            return Action.D
        elif current_stock < self.threshold_stock:
            return Action.C
        else:
            return Action.C

class Strategy_ALTRUISTIC_11(BaseStrategy):
    """
    Target State Maintenance (TSM) strategy.
    
    Aims to maintain common pool stock at capacity/2 to maximize growth
    while adapting to opponent behavior and terminal game constraints.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        S = current_stock
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == r - 1:
            return Action.D
        my_prev_action = int(history.my_actions[-1])
        k_prev = history.opponent_cooperators[-1] + my_prev_action
        if S < capacity / n:
            return Action.C
        if S > 0.9 * capacity:
            return Action.D
        if k_prev < n / 4:
            S_rem_actual = S - k_prev * (S / (2 * n)) - (n - k_prev) * (S / n)
            S_next_actual = S_rem_actual + 2 * S_rem_actual * (1 - S_rem_actual / capacity)
            if S_next_actual <= 0:
                return Action.D
            return Action.C
        S_rem_ideal = S / 2
        S_next_ideal = S_rem_ideal + 2 * S_rem_ideal * (1 - S_rem_ideal / capacity)
        if S_next_ideal < capacity / 2 or S < capacity / 4:
            return Action.C
        if S_next_ideal > capacity / 2:
            if k_prev > n / 2:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_ALTRUISTIC_12(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Stock Preservation.
    
    This strategy aims to maximize collective utility by keeping the resource stock
    near the optimal capacity/2 level. It employs:
    1. Initial cooperation.
    2. Critical threshold checks (play D if stock < 25% capacity).
    3. Tit-for-Tat punishment for defection.
    4. Probabilistic forgiveness (based on current stock levels) to restore cooperation.
    5. Final round defection to maximize terminal payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_coop_count = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_prev_coop_int = 1 if my_prev_action else 0
        total_prev_coop = prev_coop_count + my_prev_coop_int
        d_count = self.n - total_prev_coop
        critical_threshold = self.capacity * 0.25
        if current_stock < critical_threshold:
            return Action.D
        if d_count == 0:
            return Action.C
        elif current_stock > self.capacity * 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_13(BaseStrategy):
    """
    Adaptive Sustainable Reciprocity:
    Maintains cooperation as the default state. Monitors the common pool stock level 
    and opponent defection history. If stock falls below 10% capacity, it switches to 
    unconditional defection for loss mitigation. Otherwise, it employs a probabilistic 
    punishment mechanism against defectors, where the risk of punishment scales 
    inversely with stock health.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.1 * self.game_description.capacity:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        if n_opponents <= 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        prev_defectors = n_opponents - prev_cooperators
        if prev_defectors == 0:
            return Action.C
        health = current_stock / self.game_description.capacity
        risk_factor = 1.5 if health < 0.5 else 0.5
        prob_punish = min(1.0, prev_defectors / n_opponents * risk_factor)
        if random.random() < prob_punish:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_14(BaseStrategy):
    """
    Conditional Stewardship: A tit-for-tat strategy focused on sustainable 
    resource management. It prioritizes the common pool stock level above 
    punitive actions, forgiving defectors if the stock recovers, and 
    enforcing a quorum-based cooperation rule.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.quorum = math.ceil((self.game_description.n_players - 1) * 0.75)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_stock < capacity / n:
            return Action.C
        if current_stock < 1e-06:
            return Action.C
        if current_round == r - 1:
            if current_stock > capacity / 2:
                return Action.D
            return Action.C
        if current_stock >= capacity / 2:
            return Action.C
        m_prev = history.opponent_cooperators[-1]
        if m_prev >= self.quorum:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_15(BaseStrategy):
    """
    Adaptive Stewardship:
    Balances sustainability with group cooperation levels. It defaults to cooperation in round 1,
    responds to the aggregate cooperation of opponents in subsequent rounds using thresholds,
    and enters an emergency conservation mode if the stock drops below the sustainability threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.perfect_coop_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        r_total = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        total_cooperation_events = np.sum(history.my_actions.astype(int)) + np.sum(history.opponent_cooperators)
        total_potential_events = round_idx * n
        history_cooperation_rate = total_cooperation_events / total_potential_events
        last_round_cooperators = history.opponent_cooperators[-1]
        my_last_action = int(history.my_actions[-1])
        if last_round_cooperators + my_last_action == n:
            self.perfect_coop_streak += 1
        else:
            self.perfect_coop_streak = 0
        critical_threshold = capacity / (2 * n)
        if current_stock < critical_threshold:
            return Action.C
        if self.perfect_coop_streak >= 3:
            return Action.C
        if round_idx == r_total - 1:
            if history_cooperation_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        last_round_coop_rate = last_round_cooperators / n_opponents if n_opponents > 0 else 0
        if last_round_coop_rate >= 0.75:
            return Action.C
        elif 0.5 <= last_round_coop_rate < 0.75:
            return Action.C if random.random() < last_round_coop_rate else Action.D
        else:
            return Action.D

class Strategy_ALTRUISTIC_16(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource game.
    The strategy prioritizes sustainability by cooperating initially and maintaining 
    cooperation unless the resource stock reaches critical levels or the population 
    at large turns towards defection. In the final round, it defects to maximize 
    final utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if round_idx == total_rounds - 1:
            return Action.D
        if current_stock < 0.2 * capacity:
            return Action.D
        if round_idx == 0:
            return Action.C
        n_opponents = n - 1
        prev_opp_coops = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        prev_defectors = n_opponents - prev_opp_coops + (0 if my_prev_action else 1)
        defector_ratio = prev_defectors / n
        if defector_ratio > 0.5:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_17(BaseStrategy):
    """
    Implements a 'Conditional Altruism with Sustainability Constraints' strategy.
    
    This strategy prioritizes sustainability:
    1.  Starts by cooperating.
    2.  If stock is critically low (< 20% capacity), it always cooperates.
    3.  In the final 2 rounds, it switches to defection to maximize yield before extinction.
    4.  Otherwise, it calculates system integrity. If the system is resilient to the
        previous round's defection pattern, it cooperates. If not, it probabilistically
        cooperates based on the level of previous group cooperation, attempting to 
        nudge the group back toward sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.2 * game_description.capacity
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        remaining_rounds = self.total_rounds - current_round
        if current_round == 0:
            return Action.C
        if current_stock < self.threshold:
            return Action.C
        if remaining_rounds <= 2:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        k_prev = history.opponent_cooperators[-1] + my_prev_action
        if k_prev == self.n:
            return Action.C
        m_prev = self.n - k_prev
        consumption = current_stock / (2 * self.n) * (k_prev + 2 * m_prev)
        s_rem = max(0.0, current_stock - consumption)
        growth = 2 * s_rem * (1 - s_rem / self.game_description.capacity)
        s_next = min(self.game_description.capacity, s_rem + growth)
        if s_next >= current_stock:
            return Action.C
        elif random.random() < k_prev / self.n:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_18(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Resource Preservation strategy.
    
    Strategy logic:
    - Round 0: Always Cooperate.
    - Final Round: Always Defect.
    - Else if Stock < 20% of Capacity: Cooperate (recovery mode).
    - Else (if Stock >= 20%): Cooperate if previous round cooperators >= ceil(n/2), else Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.c_threshold = math.ceil(self.n / 2)
        self.s_crit = 0.2 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.s_crit:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action_is_coop = bool(history.my_actions[-1])
        total_cooperators_prev_round = prev_cooperators + (1 if my_prev_action_is_coop else 0)
        if total_cooperators_prev_round >= self.c_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_19(BaseStrategy):
    """
    A strategy that balances altruistic stock preservation with conditional reciprocity.
    - Initial round: Always Cooperate.
    - Subsequent rounds:
        - Cooperate if:
            - Stock is >= 80% capacity.
            - Prev round coop rate > 0.5.
            - Stock is growing.
        - Defect if:
            - Stock is < 20% capacity AND prev round coop rate <= 0.5 AND we are in the last 2 rounds.
            - Stock is < 10% capacity.
            - Stock dropped by > 50% from previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.prev_stock = self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.prev_stock = current_stock
            return Action.C
        t = history.round_number
        r = self.game_description.n_rounds
        n = self.n
        my_prev_action = history.my_actions[-1]
        c_prev_count = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        coop_rate = c_prev_count / n
        if self.prev_stock > 1e-09:
            depletion_ratio = current_stock / self.prev_stock
            if depletion_ratio < 0.5:
                self.prev_stock = current_stock
                return Action.D
        if t >= r - 1 and current_stock < 0.2 * self.capacity or current_stock < 0.1 * self.capacity:
            self.prev_stock = current_stock
            return Action.D
        if current_stock >= 0.8 * self.capacity:
            self.prev_stock = current_stock
            return Action.C
        if coop_rate > 0.5:
            self.prev_stock = current_stock
            return Action.C
        if current_stock > self.prev_stock:
            self.prev_stock = current_stock
            return Action.C
        self.prev_stock = current_stock
        return Action.D

class Strategy_ALTRUISTIC_20(BaseStrategy):
    """
    Tit-for-Tat with Logistic Sustainability Threshold.
    
    Maintains resource stock by cooperating at the start and in critical scarcity.
    Uses Tit-for-Tat logic with a probability based on the observed defection rate
    from opponents, unless the Expected Sustainability Index (ESI) suggests
    the resource is at risk, in which case it prioritizes cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock < self.capacity * 0.5:
                return Action.C
            return Action.D
        num_opponents = self.n - 1
        num_coop_opponents = history.opponent_cooperators[-1]
        k = num_opponents - num_coop_opponents
        if current_stock < self.capacity * 0.25:
            return Action.C
        if k == 0:
            return Action.C
        cons_coop = current_stock / (2 * self.n)
        cons_defect = current_stock / self.n
        my_prev_action = history.my_actions[-1]
        my_consumption = cons_coop if my_prev_action else cons_defect
        total_cons = my_consumption + num_coop_opponents * cons_coop + k * cons_defect
        stock_remaining = max(0.0, current_stock - total_cons)
        growth = 2 * stock_remaining * (1 - stock_remaining / self.capacity)
        esi = min(stock_remaining + growth, self.capacity)
        if esi > self.capacity * 0.5:
            if random.random() < k / self.n:
                return Action.D
            return Action.C
        else:
            return Action.C

class Strategy_ALTRUISTIC_21(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Sustainability Thresholds.
    
    This strategy prioritizes long-term common pool sustainability. 
    - If the current stock is below half capacity, it switches to defection (D) 
      to buffer against resource collapse.
    - If the stock is healthy (>= half capacity), it adopts a conditional 
      cooperation approach based on the previous round's aggregate opponent behavior,
      requiring at least (n-1)/2 cooperative opponents to maintain cooperation.
    - It always starts with cooperation (C) in round 0 and defects (D) in the 
      final round to maximize utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == r - 1:
            return Action.D
        if t == 0:
            return Action.C
        threshold = capacity / 2.0
        if current_stock < threshold:
            return Action.D
        else:
            k = history.opponent_cooperators[-1]
            if k >= (n - 1) / 2.0:
                return Action.C
            else:
                return Action.D

class Strategy_ALTRUISTIC_22(BaseStrategy):
    """
    Conditional Reciprocity strategy that prioritizes stock maintenance.
    - Operates with a buffer (0.75 * capacity) to ensure sustainability.
    - Defects on the last round.
    - Cooperates in round 1 and when stock is below target/collapse thresholds.
    - Uses a 3-round memory to analyze aggregate opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_opponents = game_description.n_players - 1
        self.target_ratio = 0.75
        self.collapse_ratio = 0.1
        self.cooperation_threshold = 0.5
        self.memory_depth = 3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock <= self.collapse_ratio * self.capacity:
            return Action.D
        if current_stock < self.target_ratio * self.capacity:
            return Action.C
        recent_history = history.opponent_cooperators[-self.memory_depth:]
        total_coops = np.sum(recent_history)
        max_possible_coops = len(recent_history) * self.n_opponents
        if max_possible_coops == 0:
            return Action.C
        avg_cooperation = total_coops / max_possible_coops
        if avg_cooperation >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_23(BaseStrategy):
    """
    A conditional cooperation strategy that balances sustainable yield with punishment mechanisms.
    
    The strategy prioritizes long-term resource stability:
    1.  Always cooperates in the first round.
    2.  Always defects in the final round (zero future value).
    3.  Defects if current stock is below capacity/4 (Critical Scarcity).
    4.  Defects if the resource failed to regenerate adequately (Regeneration Check).
    5.  Defects if any opponent defected in the previous round (Tit-for-Tat Enforcement).
    6.  Otherwise, defaults to cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def _simulate_stock_dynamics(self, history: PlayerHistory) -> list[float]:
        """
        Reconstructs the stock trajectory based on the history of actions.
        Returns a list of stocks starting with initial capacity.
        """
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        stocks = [float(capacity)]
        for r in range(history.round_number):
            current_s = stocks[-1]
            my_action = history.my_actions[r]
            my_cooperation = 1 if my_action == Action.C else 0
            total_cooperators = history.opponent_cooperators[r] + my_cooperation
            total_defectors = n - total_cooperators
            cons_c = current_s / (2 * n)
            cons_d = current_s / n
            total_consumption = total_cooperators * cons_c + total_defectors * cons_d
            s_rem = max(0.0, current_s - total_consumption)
            if capacity == 0:
                growth = 0.0
            else:
                growth = 2 * s_rem * (1 - s_rem / capacity)
            next_stock = min(capacity, s_rem + growth)
            stocks.append(next_stock)
        return stocks

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 4:
            return Action.D
        stocks = self._simulate_stock_dynamics(history)
        if len(stocks) >= 2:
            prev_stock = stocks[-2]
            if current_stock < prev_stock * 0.8:
                return Action.D
        if history.opponent_cooperators[-1] < self.game_description.n_players - 1:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_24(BaseStrategy):
    """
    A Conditional Tit-for-Tat strategy with a Sustainability Threshold.
    Prioritizes maintaining stock levels above capacity/4 by defaulting to
    cooperation when the resource is scarce. Uses a majority-rule trigger
    (n // 2) for standard rounds and an end-game logic that prioritizes
    resource survival unless full cooperation is already achieved.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_cooperators = int(history.opponent_cooperators[-1])
        round_idx = history.round_number + 1
        if round_idx > self.total_rounds - 3:
            if current_stock < self.capacity / 4.0:
                return Action.C
            elif prev_cooperators == self.n - 1:
                return Action.C
            else:
                return Action.D
        if current_stock < self.capacity / 4.0:
            return Action.C
        threshold = self.n // 2
        if prev_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_25(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource Stewardship:
    Prioritizes sustainable long-term yields.
    
    Logic:
    - Round 1: Cooperate.
    - Rounds 2 to r-1:
        - Critical State: If stock <= threshold, randomize C/D.
        - Reciprocal: If majority of others cooperated in prev round, Cooperate.
        - Recovery: If stock is growing, Cooperate (Forgiveness).
        - Otherwise, Defect.
    - Final Round: Cooperate if stock > threshold, else Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = game_description.capacity * 0.25

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if not hasattr(self, '_last_stock'):
            self._last_stock = self.capacity
        s_prev = self._last_stock
        s_curr = current_stock
        self._last_stock = current_stock
        if current_round_idx == self.r - 1:
            return Action.C if s_curr > self.threshold else Action.D
        if s_curr <= self.threshold:
            return random.choice([Action.C, Action.D])
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev >= self.n / 2.0:
            return Action.C
        if s_curr > s_prev:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_26(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    This strategy prioritizes long-term stock regeneration while punishing
    exploitation. It cooperates if the stock is healthy (>= 75% capacity)
    or if a majority of other players cooperate. It defects if the stock
    is being depleted by a majority of defectors or if negative growth
    trends are detected. In the final three rounds, it switches to a 
    utility-maximizing approach based on a low-stock threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        prev_stock = None
        if not hasattr(self, '_last_stock'):
            self._last_stock = self.capacity
        prev_stock = self._last_stock
        self._last_stock = current_stock
        observed_cooperators = int(history.opponent_cooperators[-1])
        if self.r - t < 3:
            if current_stock < 0.1 * self.capacity:
                return Action.D
            return Action.C
        growth_trend = current_stock < prev_stock
        coop_threshold = self.n / 2.0
        healthy_stock = 0.75 * self.capacity
        if observed_cooperators > coop_threshold or current_stock >= healthy_stock:
            return Action.C
        if observed_cooperators < coop_threshold or (growth_trend and observed_cooperators <= coop_threshold):
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_27(BaseStrategy):
    """
    Implements an Altruistic Sustainability strategy for the Common Pool Resource game.
    Prioritizes maintaining stock near capacity/2 to maximize regrowth.
    Utilizes Tit-for-Tat with Forgiveness logic during standard phases and
    exploits terminal rounds for final value extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.n_rounds - 1:
            return Action.D if current_stock > 0 else Action.C
        rounds_remaining = self.n_rounds - round_idx
        if rounds_remaining <= 2:
            last_n_c = history.opponent_cooperators[-1]
            if last_n_c >= self.n / 2:
                return Action.D
            return Action.C
        optimal_stock = self.capacity / 2
        threshold = self.n / 2
        if current_stock < self.capacity / 4:
            return Action.C
        last_n_c = history.opponent_cooperators[-1]
        if last_n_c >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_28(BaseStrategy):
    """
    A strategy that starts with Cooperation (C). In subsequent rounds, it adapts
    using a tolerance threshold for cooperation, temporary punishment for
    unsustainable stock depletion, and specific logic for the terminal phase
    and high-stock recovery scenarios.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.tolerance = 0
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.max_rounds = game_description.n_rounds
        self.max_tolerance = self.n // 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_stock > 0.9 * self.capacity:
            return Action.C
        if current_round == self.max_rounds - 1:
            if current_stock < self.capacity * 0.1:
                return Action.D
            else:
                return Action.C
        last_my_action = history.my_actions[-1]
        my_cooperation = 1 if last_my_action else 0
        k_prev = history.opponent_cooperators[-1] + my_cooperation
        if k_prev >= self.n - self.tolerance:
            return Action.C
        elif current_stock < self.capacity / 2:
            self.tolerance = min(self.tolerance + 1, self.max_tolerance)
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_29(BaseStrategy):
    """
    A conditional cooperation strategy that utilizes Tit-for-Tat with probabilistic 
    punishment and an emergency forgiveness mechanism for low-stock scenarios.
    
    Logic:
    1. Round 1: Always Cooperate.
    2. Final Round: Cooperate if cooperation threshold was met previously; 
       otherwise Defect to avoid exploitation.
    3. Intermediate Rounds: 
       - If stock is < 25% of capacity, force Cooperate to prevent collapse.
       - If previous round cooperators >= n/2, Cooperate.
       - Otherwise, punish probabilistically based on the ratio of defectors 
         to total players (P = (n - C_prev) / n).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.cooperation_threshold = self.n / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            if history.opponent_cooperators[-1] >= self.cooperation_threshold:
                return Action.C
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        c_prev = history.opponent_cooperators[-1]
        if c_prev >= self.cooperation_threshold:
            return Action.C
        else:
            defection_count = self.n - c_prev
            probability_of_d = defection_count / self.n
            if random.random() < probability_of_d:
                return Action.D
            return Action.C

class Strategy_ALTRUISTIC_30(BaseStrategy):
    """
    Adaptive Sustainability Tit-for-Tat:
    Prioritizes maintaining common pool stock at capacity.
    - Start: Cooperate.
    - Last round: Defect.
    - Critical crash (stock < 20% of previous): Defect.
    - High Cooperation: If all cooperated last round, maintain cooperation.
    - Adaptive: If not all cooperated, predict if cooperation sustains growth (S_{t+1} > S_t).
      If yes, cooperate; otherwise, defect to match behavior/prevent exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.last_stock = float(self.game_description.capacity)
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.last_stock * 0.2:
            self.last_stock = current_stock
            return Action.D
        n = self.game_description.n_players
        prev_my_action_val = 1 if history.my_actions[-1] else 0
        prev_cooperators = history.opponent_cooperators[-1] + prev_my_action_val
        if prev_cooperators == n:
            self.last_stock = current_stock
            return Action.C
        my_cons_C = current_stock / (2 * n)
        total_cons_if_I_cooperate = n * (current_stock / (2 * n))
        remaining_stock = max(0.0, current_stock - total_cons_if_I_cooperate)
        growth = 2.0 * remaining_stock * (1.0 - remaining_stock / self.game_description.capacity)
        projected_next_stock = min(remaining_stock + growth, float(self.game_description.capacity))
        self.last_stock = current_stock
        if projected_next_stock > current_stock:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_31(BaseStrategy):
    """
    Altruistic Tit-for-Tat with Resource Preservation.
    This strategy balances collective sustainability with individual utility protection.
    It cooperates initially, maintains cooperation if the stock is healthy and 
    others reciprocate, but defects to prevent total exhaustion or when 
    the resource reaches critical, non-recoverable levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.reciprocity_threshold = math.ceil((self.n - 1) / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_stock < 1.0:
            return Action.D
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators = my_prev_action + prev_k
        total_defectors = self.n - total_cooperators
        if current_stock < 0.2 * self.capacity:
            return Action.D
        if prev_k >= self.reciprocity_threshold:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_32(BaseStrategy):
    """
    Implements a Conditional Sustainable Tit-for-Tat strategy.
    
    Logic:
    1. First round: Always Cooperate (C).
    2. Terminal phase (final round): Cooperate if stock >= 0.5 * capacity, else Defect (D).
    3. Resource constraint: If the stock at the end of the previous round was < 0.8 * capacity, Defect.
    4. Tit-for-tat/Punishment logic: If defectors were present in the previous round, 
       punish by playing D. If currently punishing (playing D), only resume cooperation if 
       stock >= 0.5 * capacity. Otherwise, Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock >= 0.5 * self.game_description.capacity:
                return Action.C
            return Action.D
        last_round_idx = history.round_number - 1
        last_stock = current_stock
        my_last_action_is_c = history.my_actions[-1]
        opp_c_count = history.opponent_cooperators[-1]
        n = self.game_description.n_players
        total_cooperators = (1 if my_last_action_is_c else 0) + opp_c_count
        total_defectors = n - total_cooperators
        if last_stock < 0.8 * self.game_description.capacity:
            return Action.D
        if total_defectors > 0:
            if not my_last_action_is_c and current_stock >= 0.5 * self.game_description.capacity:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_5(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    This strategy aims to maintain the common pool stock at capacity/2 (optimal regeneration).
    It cooperates in the first round to signal intent and defects in the final round to
    prevent exploitation. In intermediate rounds, it monitors the cooperation level of 
    others and the state of the stock. It defects if the stock is critically low (below
    capacity/4) or if the peer group is not providing sufficient cooperation 
    (R < 0.5 where R = (cooperators_prev + 1) / n_players).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < self.capacity / 4.0:
            return Action.D
        c_observed = int(history.opponent_cooperators[-1])
        if c_observed >= self.n / 2.0 - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_6(BaseStrategy):
    """
    Resilient Sustainability: A conditional cooperation strategy that maintains 
    common pool levels by monitoring past cooperation, enforcing a stability 
    threshold, and initiating recovery phases when stock levels are robust.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        current_round = round_idx + 1
        if current_stock < capacity / n:
            return Action.C
        if current_round == r:
            if current_stock >= capacity * 0.25:
                return Action.D
            return Action.C
        if current_round == 1:
            return Action.C
        last_opponent_coop_count = history.opponent_cooperators[-1]
        last_my_action = 1 if history.my_actions[-1] else 0
        k_prev = last_opponent_coop_count + last_my_action
        threshold = n - 1
        if k_prev >= threshold:
            return Action.C
        elif current_stock >= capacity * 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_7(BaseStrategy):
    """
    Adaptive Sustainable Tit-for-Tat (ASTFT): A strategy that balances stock 
    sustainability with conditional cooperation. It monitors stock levels and 
    opponent behavior to trigger either cooperative growth or measured punishment.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.two_consecutive_full_coop = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        my_last_move = history.my_actions[-1]
        last_c = history.opponent_cooperators[-1]
        if last_c == self.n:
            self.two_consecutive_full_coop += 1
        else:
            self.two_consecutive_full_coop = 0
        if t == self.r - 1:
            if current_stock >= self.capacity / 2:
                return Action.C
            return Action.D
        if current_stock <= self.capacity / (2 * self.n):
            return Action.C
        if current_stock < self.capacity / self.n:
            return Action.C
        opponents_cooperating = last_c - (1 if my_last_move else 0)
        fraction_coop = opponents_cooperating / (self.n - 1)
        if self.two_consecutive_full_coop >= 2:
            fraction_coop = max(fraction_coop, 0.6)
        if fraction_coop > 0.5:
            return Action.C
        else:
            if random.random() < 1.0 - fraction_coop:
                return Action.D
            return Action.C

class Strategy_BENEVOLENT_8(BaseStrategy):
    """
    Conditional Sustainability strategy:
    Balances resource preservation with opportunistic defense. Cooperates primarily when
    stock is high or when group cooperation is robust. Switches to defection if the 
    resource becomes critically depleted or when opponents demonstrate uncooperative behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.sustainability_threshold = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        n_opponents = self.n - 1
        last_round_idx = round_idx - 1
        k = history.opponent_cooperators[last_round_idx]
        I = k / n_opponents if n_opponents > 0 else 0.0
        is_perfect_coop = False
        if round_idx >= 3:
            if history.opponent_cooperators[-1] == n_opponents and history.opponent_cooperators[-2] == n_opponents and (history.opponent_cooperators[-3] == n_opponents):
                is_perfect_coop = True
        if current_stock < 0.1 * self.capacity:
            if I == 1.0:
                return Action.C
            return Action.D
        if round_idx == self.r - 1:
            if current_stock > self.capacity / self.n:
                return Action.C
            else:
                return Action.D
        if is_perfect_coop:
            if current_stock >= 0.2 * self.capacity:
                return Action.C
        if current_stock > self.sustainability_threshold:
            return Action.C
        elif I >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_9(BaseStrategy):
    """
    Sustainable Tit-for-Tat with Resilience Buffer:
    Maintains a reputation score based on opponent cooperation history.
    - Cooperates in round 1.
    - Defects in the final round to maximize payoff.
    - Cooperates if stock is critically low (< capacity/n) to prevent total collapse.
    - Otherwise, cooperates if reputation >= 0.6, else defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 1.0
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.r:
            return Action.D
        if current_stock < self.capacity / self.n:
            return Action.C
        if current_round == 1:
            return Action.C
        prev_round_observed_C = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if n_opponents > 0:
            current_coop_ratio = prev_round_observed_C / n_opponents
            self.reputation = 0.7 * self.reputation + 0.3 * current_coop_ratio
        if self.reputation >= 0.6:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_10(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource Awareness strategy.
    
    Prioritizes sustainability:
    1. Always cooperates in the first round.
    2. If stock < capacity/2, forces cooperation to recover resources.
    3. If stock >= capacity/2, matches previous group cooperation (Trigger threshold n/2).
    4. If the game is in the final round, cooperates only if full cooperation was maintained
       throughout history, otherwise defects to maximize final payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.has_full_cooperation_been_maintained = True

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round > 0:
            my_prev_action = int(history.my_actions[current_round - 1])
            total_cooperators = history.opponent_cooperators[current_round - 1] + my_prev_action
            if total_cooperators < n:
                self.has_full_cooperation_been_maintained = False
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            if self.has_full_cooperation_been_maintained:
                return Action.C
            else:
                return Action.D
        if current_stock < 0.001 * capacity:
            return Action.D
        if current_stock < capacity / 2.0:
            return Action.C
        my_prev_action = int(history.my_actions[current_round - 1])
        total_cooperators_prev = history.opponent_cooperators[current_round - 1] + my_prev_action
        threshold = n / 2.0
        if total_cooperators_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_11(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource Stewardship strategy.
    Prioritizes sustainability by tracking pool stock trends, punishing defectors 
    while employing a forgiveness mechanism to re-establish cooperation, 
    and adopting a risk-averse stance when stock levels are critical.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold_offset = 0
        self.my_last_action = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            self.my_last_action = Action.C
            return Action.C
        if current_round == r_total - 1:
            self.my_last_action = Action.D
            return Action.D
        if current_stock <= 2 * n or current_stock < 1.5 * n:
            self.my_last_action = Action.D
            return Action.D
        if current_round >= 3:
            self.cooperation_threshold_offset = 1
        else:
            self.cooperation_threshold_offset = 0
        my_prev_C = 1 if self.my_last_action == Action.C else 0
        total_C = history.opponent_cooperators[-1] + my_prev_C
        threshold = max(0, n // 2 - self.cooperation_threshold_offset)
        action = Action.D
        if total_C >= threshold:
            action = Action.C
        elif self.my_last_action == Action.D:
            action = Action.C
        else:
            action = Action.D
        self.my_last_action = action
        return action

class Strategy_BENEVOLENT_12(BaseStrategy):
    """
    A sustainability-contingent reciprocity strategy for the Common Pool Resource Game.
    
    Logic overview:
    1. First round (t=1): Always Cooperate (C).
    2. Endgame phase (final two rounds):
       - If stock > 50% capacity, Defect (D) to capture value.
       - Otherwise, Cooperate (C) to ensure survival.
    3. Sustainability check:
       - Calculates theoretical stock S_theory if all players had cooperated in the previous round.
       - If current stock < 90% of S_theory:
         - If stock < 20% capacity, Cooperate (C) (Emergency mode).
         - Else, Defect (D) (Assume depletion is inevitable or exploitation is required).
    4. Reciprocity check:
       - Uses the number of cooperators from the previous round (k).
       - If everyone cooperated, cooperate.
       - Otherwise, cooperate with probability p = k / (n - 1).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_known_stock = float(game_description.capacity)

    def _calculate_s_theory(self, s_prev: float) -> float:
        """
        Calculates the theoretical stock for the next round assuming everyone cooperates.
        Consumption_i = S / (2n)
        Total Consumption = n * (S / (2n)) = S / 2
        S_remaining = S - S/2 = S/2
        Growth = 2 * S_remaining * (1 - S_remaining / capacity)
        New Stock = min(S_remaining + Growth, capacity)
        """
        s_remaining = s_prev / 2.0
        growth = 2.0 * s_remaining * (1.0 - s_remaining / self.game_description.capacity)
        return min(s_remaining + growth, float(self.game_description.capacity))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.game_description.n_players
        capacity = float(self.game_description.capacity)
        if t == 0:
            self.last_known_stock = current_stock
            return Action.C
        if t >= self.game_description.n_rounds - 2:
            self.last_known_stock = current_stock
            if current_stock > 0.5 * capacity:
                return Action.D
            else:
                return Action.C
        s_theory = self._calculate_s_theory(self.last_known_stock)
        if current_stock < 0.9 * s_theory:
            self.last_known_stock = current_stock
            if current_stock <= 0.2 * capacity:
                return Action.C
            else:
                return Action.D
        k = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
        self.last_known_stock = current_stock
        if k >= n - 1:
            return Action.C
        else:
            if n - 1 == 0:
                return Action.C
            threshold = k / (n - 1)
            if random.random() < threshold:
                return Action.C
            else:
                return Action.D

class Strategy_BENEVOLENT_13(BaseStrategy):
    """
    Conditional Stewardship Strategy (Tit-for-Tat with Resource Thresholds).
    
    This strategy prioritizes long-term sustainability by cooperating in the first round 
    and in subsequent rounds where no defection is detected. If defection is detected 
    (k > 0), the strategy responds adaptively:
    - If the stock is critically low (< 25% of capacity), it defects for self-preservation.
    - Otherwise, it defects with probability proportional to the observed defection, 
      acting as a deterrent to exploiters while attempting to stabilize the pool.
    - It always defects in the final round to capture remaining resource value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        previous_k = n_opponents - last_round_cooperators
        if previous_k == 0:
            return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.D
        p_defect = previous_k / n_opponents
        if random.random() < p_defect:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_14(BaseStrategy):
    """
    A conditional reciprocity strategy for the Common Pool Resource game.
    It prioritizes stock preservation by cooperating initially, using Tit-for-Tat
    with forgiveness, and employing defect-based punishment when necessary, 
    while ultimately defecting in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_defector_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        current_round = round_idx + 1
        if current_round == r:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock <= 0:
            return Action.D
        if current_round > r // 2:
            if round_idx >= 2:
                recent_defect = history.opponent_cooperators[-1] < n - 1
                prev_defect = history.opponent_cooperators[-2] < n - 1
                if recent_defect and prev_defect:
                    return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        is_stock_critically_low = current_stock < capacity / n
        if last_round_cooperators < n - 1:
            self.consecutive_defector_rounds += 1
        else:
            self.consecutive_defector_rounds = 0
        if last_round_cooperators == n - 1:
            return Action.C
        if self.consecutive_defector_rounds >= 2:
            self.consecutive_defector_rounds = 0
            return Action.D
        if is_stock_critically_low:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_15(BaseStrategy):
    """
    The Sustainable Tit-for-Tat Strategy (STFT).
    
    This strategy focuses on maintaining common pool resources at maximum sustainable yield
    by cooperating when others cooperate, applying defensive defection if the pool 
    dips below critical thresholds after others defect, and defecting on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        my_last_action = history.my_actions[-1]
        my_last_was_c = 1 if my_last_action else 0
        total_cooperators = my_last_was_c + history.opponent_cooperators[-1]
        if total_cooperators == self.game_description.n_players:
            return Action.C
        if current_stock < 0.5 * self.game_description.capacity:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_16(BaseStrategy):
    """
    A Trigger-Modified Tit-for-Tat strategy that prioritizes sustainability.
    
    Logic:
    - First Round: Cooperate (C).
    - Final Round: Defect (D).
    - Rounds [2, r-1]:
        - If stock < capacity/4: Emergency C (override all).
        - If stock >= capacity/2:
            - If cooperators k >= n-1: C.
            - If cooperators k < n-1: D (retaliation).
        - If capacity/4 <= stock < capacity/2: C (maintain sustainability).
    - Reset Condition: If stock >= capacity, treat as sub-game (C).
    - Rapid Depletion Check: If previous round caused loss > 50% of previous stock, C.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.prev_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.prev_stock = self.desc.capacity
            return Action.C
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        k = history.opponent_cooperators[-1] + my_prev_coop
        if current_stock < self.desc.capacity / 4.0 or current_stock < 1.0:
            self.prev_stock = current_stock
            return Action.C
        if self.prev_stock - current_stock > 0.5 * self.prev_stock:
            self.prev_stock = current_stock
            return Action.C
        if current_stock >= self.desc.capacity:
            self.prev_stock = current_stock
            return Action.C
        if current_stock >= self.desc.capacity / 2.0:
            if k >= self.desc.n_players - 1:
                self.prev_stock = current_stock
                return Action.C
            else:
                self.prev_stock = current_stock
                return Action.D
        else:
            self.prev_stock = current_stock
            return Action.C

class Strategy_BENEVOLENT_17(BaseStrategy):
    """
    Implements a 'Conditional Sustainment' strategy for the Common Pool Resource game.
    The strategy balances resource preservation with retaliatory defection.
    - Round 1: Always Cooperate.
    - Terminal Round: Always Defect.
    - Steady State: Maintains Cooperation if stock >= 90% capacity or if 
      aggregate opponent cooperation is >= 50%.
    - Rescue: Prioritizes Cooperation if stock < 10% capacity.
    - Forgiveness: Transitions from Defect to Cooperate if stock >= 50% capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1
        self.cooperation_threshold = self.n_opponents / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_action_was_defect = history.my_actions[-1] == False
        prev_opponents_cooperated = history.opponent_cooperators[-1]
        if current_stock < 0.1 * self.game_description.capacity:
            return Action.C
        if last_action_was_defect and current_stock >= 0.5 * self.game_description.capacity:
            return Action.C
        if current_stock >= 0.9 * self.game_description.capacity:
            return Action.C
        if prev_opponents_cooperated >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_18(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy for the Common Pool Resource Game.
    
    This strategy focuses on sustainability by:
    1. Always cooperating in the first round.
    2. Monitoring opponent cooperation in the previous round to decide on reciprocity.
    3. Applying a regenerative constraint (cooperate if stock is critically low).
    4. Utilizing an adaptive threshold based on current stock levels when cooperation is low.
    5. Optimizing for utility in the final round without unnecessary depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            if current_stock >= self.capacity / self.n:
                return Action.D
            else:
                return Action.C
        last_opponent_coops = history.opponent_cooperators[-1]
        i_cooperated = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = last_opponent_coops + i_cooperated
        if total_cooperators_prev >= self.n - 1:
            return Action.C
        if current_stock < 0.2 * self.capacity:
            return Action.C
        if current_stock > 0.5 * self.capacity:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_19(BaseStrategy):
    """
    Tit-for-Tat with Forgiving Resilience.
    Maintains the common pool stock near capacity by adjusting cooperation based on health factors,
    population behavior, and targeted punishment/forgiveness logic.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_round_active = False
        self.stagnation_counter = 0
        self.previous_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            self.previous_stock = current_stock
            return Action.C
        H = current_stock / capacity
        my_last_action_int = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + my_last_action_int
        C_rate = total_cooperators / n
        if (self.previous_stock - current_stock) / self.previous_stock > 0.3:
            self.punishment_round_active = True
        else:
            self.punishment_round_active = False
        if H < 0.5:
            self.stagnation_counter += 1
        else:
            self.stagnation_counter = 0
        self.previous_stock = current_stock
        if self.stagnation_counter >= 3:
            self.stagnation_counter = 0
            return Action.C
        if self.punishment_round_active:
            return Action.D
        if H < 0.25:
            return Action.C if H > 0.1 else Action.D
        if H >= 0.9:
            if total_cooperators < n:
                return Action.D
            return Action.C
        if C_rate >= 0.5:
            return Action.C
        elif random.random() < 1.0 - C_rate:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_20(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    This strategy prioritizes long-term resource viability by aiming to maintain 
    the stock at K/2. It uses a conditional cooperation approach:
    1. Plays C initially.
    2. In subsequent rounds, it cooperates if a majority (>= 50%) of the group 
       cooperated in the previous round and the stock is above a critical floor (K/n).
    3. If the stock is critically low (< 0.1 * K), it forces defection to recover stock.
    4. Otherwise, it switches to 'Defensive Defection' to punish free-riders or 
       recover stock, returning to C in the next round to allow cooperation to reform.
    5. In the final round, it defects only if the stock is critically low (<= K/4),
       otherwise it cooperates to maximize final welfare.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            if current_stock <= capacity / 4.0:
                return Action.D
            else:
                return Action.C
        my_last_action_was_c = history.my_actions[-1]
        last_round_cooperators = history.opponent_cooperators[-1] + (1 if my_last_action_was_c else 0)
        cooperation_fraction = last_round_cooperators / n
        critical_depletion_floor = capacity / n
        if current_stock < 0.1 * capacity:
            return Action.D
        if cooperation_fraction >= 0.5 and current_stock >= critical_depletion_floor:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_21(BaseStrategy):
    """
    Sustainable Tit-for-Tat (STFT):
    A reciprocal strategy that maximizes long-term social welfare by maintaining 
    the common pool stock. It cooperates in the first and final rounds, and uses 
    a threshold-based mechanism for middle rounds: it cooperates if at least 
    floor(n/2) players cooperated in the previous round, otherwise it defects 
    briefly to punish, then reverts to cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = math.floor(self.game_description.n_players / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        total_cooperators = (1 if last_my_action else 0) + last_opponent_coops
        if total_cooperators >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_22(BaseStrategy):
    """
    Implements a conditional Tit-for-Tat strategy optimized for Common Pool Resource dynamics.
    It balances sustainable extraction with punishment mechanisms to maintain the resource stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        capacity = float(self.game_description.capacity)
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock >= 0.5 * capacity:
                return Action.D
            return Action.C
        if current_stock < 0.5 * capacity:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_prev_coop = history.opponent_cooperators[-1]
        total_prev_coop = opp_prev_coop + (1 if my_prev_action else 0)
        prev_defectors = self.game_description.n_players - total_prev_coop
        if prev_defectors == 0 or math.isclose(current_stock, capacity, rel_tol=0.001):
            return Action.C
        if prev_defectors > 0 and current_stock >= 0.5 * capacity:
            if current_stock < 0.8 * capacity:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_BENEVOLENT_23(BaseStrategy):
    """
    Implements the Adaptive Sustainable Tit-for-Tat strategy.
    
    This strategy maintains the common pool stock by enforcing a cooperative equilibrium
    using a tit-for-tat approach based on the cooperation ratio (CR). It includes 
    mechanisms for resource recovery when stock levels are critical and switches to 
    selfish exploitation in the terminal round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.5
        self.recovery_fraction = 0.25

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r_total - 1:
            if current_stock > 0:
                return Action.D
            else:
                return Action.C
        if current_round == 0:
            return Action.C
        if current_stock <= self.game_description.capacity * self.recovery_fraction:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop_count = history.opponent_cooperators[-1]
        total_cooperators = int(prev_my_action) + prev_opp_coop_count
        cr = total_cooperators / n
        if cr >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_24(BaseStrategy):
    """
    Implements a reputation-based resource management strategy for the Common Pool Resource Game.
    The agent dynamically tracks the 'reputation' of the collective, derived from the count of
    cooperating players in the previous round, and modulates between Cooperation (C) and 
    Defection (D) based on resource thresholds and reputation trust levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        r = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if t == 1:
            self.reputation = 1.0
        else:
            my_last_action_val = 1 if history.my_actions[-1] else 0
            k_prev = history.opponent_cooperators[-1] + my_last_action_val
            self.reputation = self.reputation * 0.9 + k_prev / n * 0.1
        if t == r:
            return Action.C if self.reputation >= 0.5 else Action.D
        if t < r:
            if current_stock < capacity * 0.2:
                return Action.D
            if self.reputation >= 0.6:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_BENEVOLENT_25(BaseStrategy):
    """
    A strategy that maximizes long-term collective welfare in a Common Pool Resource game.
    
    Logic:
    1. Always initiates with C.
    2. If the stock is critically low (< 0.5 * capacity), forces C to allow recovery.
    3. In the final round, defects (D) unless stock is critically low (< 0.25 * capacity),
       where it switches to C to minimize loss.
    4. Otherwise, uses a Tit-for-Tat threshold approach: cooperates (C) if at least 50%
       of opponents cooperated in the previous round, otherwise defects (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        is_final_round = history.round_number == self.game_description.n_rounds - 1
        if not is_final_round and current_stock < 0.5 * self.capacity:
            return Action.C
        if is_final_round:
            if current_stock < 0.25 * self.capacity:
                return Action.C
            else:
                return Action.D
        prev_opp_c_count = float(history.opponent_cooperators[-1])
        if self.n_opponents > 0 and prev_opp_c_count / self.n_opponents >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_26(BaseStrategy):
    """
    Trigger-Adaptive Cooperation:
    Maintains resource health by balancing cooperative norms with conditional defection
    to punish non-cooperation, while preserving the stock against extinction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_low_performance = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.game_description.capacity / (2 * self.game_description.n_players):
            return Action.C
        threshold = math.ceil(self.game_description.n_players / 2)
        k_prev = history.opponent_cooperators[-1]
        if k_prev < threshold:
            self.consecutive_low_performance += 1
        else:
            self.consecutive_low_performance = 0
        if self.consecutive_low_performance > 3:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock <= self.game_description.capacity / 2:
                return Action.D
            else:
                return Action.C
        if current_stock >= 0.95 * self.game_description.capacity:
            if k_prev >= self.game_description.n_players - 2:
                return Action.C
        if k_prev >= threshold:
            return Action.C
        else:
            last_action_was_C = history.my_actions[-1]
            if not last_action_was_C:
                return Action.C
            else:
                return Action.D

class Strategy_BENEVOLENT_27(BaseStrategy):
    """
    Implements a resource-aware adaptive strategy:
    - Round 0: Cooperate.
    - Round r: Always Defect if stock > 0.
    - Otherwise:
        - If previous round cooperators k > n/2, Cooperate (Consensus).
        - If current stock S <= S_crit (where S_crit decreases with time), Cooperate (Survival).
        - Default: Defect (Punishment).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            if current_stock > 0:
                return Action.D
            return Action.D
        s_crit = self.capacity / 2 * (1 - current_round / self.r)
        if current_stock <= s_crit:
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        if history.my_actions[-1]:
            total_cooperators = k_prev + 1
        else:
            total_cooperators = k_prev
        if total_cooperators > self.n / 2:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_28(BaseStrategy):
    """
    Implements the Adaptive Sustainable Stewardship strategy.
    
    This strategy focuses on conditional cooperation. It attempts to maintain 
    the resource stock when robust but switches to competitive behavior (Defection) 
    when the resource becomes vulnerable or when the final round approaches 
    without sufficient stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if history.round_number == self.total_rounds - 1:
            if current_stock > self.capacity / 4:
                return Action.C
            else:
                return Action.D
        prev_round_cooperators = int(history.opponent_cooperators[-1])
        my_last_action_was_c = bool(history.my_actions[-1])
        total_cooperators_last_round = prev_round_cooperators + (1 if my_last_action_was_c else 0)
        is_vulnerable = current_stock <= self.capacity / 2
        if total_cooperators_last_round == self.n:
            return Action.C
        if is_vulnerable and total_cooperators_last_round < self.n:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_29(BaseStrategy):
    """
    Tit-for-Tat with Resource-Aware Forgiveness.
    
    Prioritizes sustainability via conditional cooperation.
    - Round 1: Always Cooperate.
    - End-game: If <= 3 rounds left, cooperate only if stock > 50% capacity.
    - Threshold: Defect if stock < 5% capacity, or if < 50% of players cooperated last round,
      or if stock < 20% capacity.
    - Recovery: If stock increased for two consecutive rounds, switch to Cooperation
      regardless of other conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.prev_stock = None
        self.stock_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            self.prev_stock = current_stock
            return Action.C
        if len(self.stock_history) >= 2:
            s_t_minus_1 = self.stock_history[-1]
            s_t_minus_2 = self.stock_history[-2]
            if current_stock > s_t_minus_1 and s_t_minus_1 > s_t_minus_2:
                self.stock_history.append(current_stock)
                return Action.C
        self.stock_history.append(current_stock)
        rounds_remaining = self.r - current_round
        if rounds_remaining <= 3:
            if current_stock > 0.5 * self.capacity:
                return Action.C
            else:
                return Action.D
        if current_stock < 0.05 * self.capacity:
            return Action.D
        my_prev_c = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_c
        threshold = self.n // 2
        if total_cooperators_prev >= threshold and current_stock > 0.2 * self.capacity:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_30(BaseStrategy):
    """
    A Tit-for-Tat inspired strategy with Forgiveness and Resource Awareness.
    
    Logic:
    1. Initial Round: Always cooperates.
    2. Final Round: Cooperates if the current stock is sufficient to support a cooperative payout, 
       otherwise defects to maximize final yield.
    3. Intermediate Rounds: 
       - Cooperates if all opponents cooperated in the previous round.
       - If some opponents defected, it offers 'Forgiveness' (Cooperation) if the ecosystem is 
         still healthy (stock > 50% capacity).
       - Otherwise, it punishes defection with Defection.
    4. Edge Cases:
       - Near-Depletion: If stock is below growth threshold (simplified as stock <= 0), it forces cooperation.
       - Persistent Defection: Switches to Defection if the ecosystem is collapsed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock <= 1e-09:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock <= self.capacity / self.n:
                return Action.D
            else:
                return Action.C
        k = history.opponent_cooperators[-1]
        if k == self.n - 1:
            return Action.C
        if current_stock > 0.5 * self.capacity:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_31(BaseStrategy):
    """
    Implements a Trigger-Modified Tit-for-Tat strategy for the Common Pool Resource Game.
    
    Strategy Logic:
    - Round 1 (index 0): Always Cooperate (C).
    - Rounds 2 to r-1: 
        - If current stock < capacity / 4: Cooperate (C) to prevent collapse.
        - If stock >= capacity / 4: 
            - If all opponents cooperated last round: Cooperate (C).
            - If any opponents defected: Defect (D) with probability p = 1 - (c / (n-1)),
              where c is the number of cooperating opponents.
    - Final Round: Always Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.game_description.capacity / 4:
            return Action.C
        num_opponents = self.game_description.n_players - 1
        prev_round_opponents_cooperated = history.opponent_cooperators[-1]
        if prev_round_opponents_cooperated == num_opponents:
            return Action.C
        coop_rate = prev_round_opponents_cooperated / num_opponents
        if random.random() > coop_rate:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_32(BaseStrategy):
    """
    Tit-for-Tat with Graduated Stock Sensitivity.
    Maintains a reputation score for opponents.
    Prioritizes C when ecosystem is healthy (> 0.5 capacity) or reputation is high.
    Includes a preservation mechanism when stock is critically low (< 10% capacity).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.reputation_score = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 0.1 * self.capacity and history.round_number < self.r - 1:
            return Action.C
        if history.round_number == 0:
            return Action.C
        num_opponents = self.n - 1
        if num_opponents > 0:
            cooperation_rate = history.opponent_cooperators[-1] / num_opponents
            self.reputation_score = 0.9 * self.reputation_score + 0.1 * cooperation_rate
        else:
            self.reputation_score = 1.0
        if history.round_number == self.r - 1:
            if current_stock > 0.25 * self.capacity:
                return Action.C
            else:
                return Action.D
        if current_stock > 0.5 * self.capacity:
            if self.reputation_score > 0.7:
                return Action.C
            elif random.random() < 1.0 - self.reputation_score:
                return Action.D
            else:
                return Action.C
        elif self.reputation_score >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_5(BaseStrategy):
    """
    A conditional tit-for-tat strategy with a threshold-based exit.
    
    Logic:
    - Round 1: Always Cooperate.
    - Rounds 2 to r-1: 
        - Cooperate if the majority of opponents cooperated in the previous round AND 
          stock is above 20% capacity.
        - Defect if opponents defected (rate < 0.5) OR if stock drops below 20% capacity.
        - Recovery: If previously defecting due to low stock, check if stock > 50% capacity 
          and opponent cooperation has resumed to switch back to Cooperate.
    - Final Round: Always Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_in_defensive_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        n_opponents = n - 1
        if round_t == total_rounds - 1:
            return Action.D
        if round_t == 0:
            return Action.C
        k = history.opponent_cooperators[-1]
        rate = k / n_opponents if n_opponents > 0 else 0.0
        critical_threshold = self.game_description.capacity * 0.2
        recovery_threshold = self.game_description.capacity * 0.5
        if rate < 0.5 or current_stock < critical_threshold:
            self.is_in_defensive_mode = True
            return Action.D
        if self.is_in_defensive_mode:
            if current_stock > recovery_threshold and rate >= 0.5:
                self.is_in_defensive_mode = False
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_SELFISH_6(BaseStrategy):
    """
    A tit-for-tat variant strategy that balances stock sustainability with opportunistic 
    defection. It cooperates if the stock is healthy and opponents cooperate, but 
    switches to defect if the stock is critically low (too low to recover) or if 
    opponents are unreliable. It enforces a terminal-round extraction phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.sustainable_threshold = 0.5 * self.capacity
        self.critical_threshold = 0.1 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if self.r - t < 3:
            return Action.D
        if current_stock < self.critical_threshold:
            return Action.D
        if t >= 2:
            defected_last = history.opponent_cooperators[-1] < self.n - 1
            defected_prev = history.opponent_cooperators[-2] < self.n - 1
            if defected_last and defected_prev:
                return Action.D
        if current_stock < self.sustainable_threshold:
            return Action.C
        last_opps = history.opponent_cooperators[-1]
        if last_opps == self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_7(BaseStrategy):
    """
    Implements a Threshold-Based Tit-for-Tat strategy.
    
    Logic:
    - Round 1: Cooperate.
    - Intermediate Rounds: 
        - Cooperate if the number of cooperating opponents (k) >= ceil(n/2).
        - Defect otherwise.
    - Final Round: Always Defect.
    - Resilience: If stock < capacity / (2 * n), force Defect, regardless of strategy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = (self.game_description.n_players - 1) / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_round_index == total_rounds - 1:
            return Action.D
        if current_stock < capacity / (2 * n):
            return Action.D
        if current_round_index == 0:
            return Action.C
        k = history.opponent_cooperators[-1]
        if k >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_8(BaseStrategy):
    """
    A strategy that maintains a moving average 'reputation' of the population's cooperation.
    It cooperates in the initial round, defects in the final round, and uses the reputation
    and current stock level to decide actions in intermediate rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.reputation = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx > 0:
            last_coop_count = history.opponent_cooperators[-1]
            my_last_action = 1 if history.my_actions[-1] else 0
            total_cooperators = last_coop_count + my_last_action
            proportion_coop = total_cooperators / self.n
            self.reputation = self.reputation * 0.7 + proportion_coop * 0.3
        if current_round_idx == self.r - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock <= 0:
            return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.D
        if current_stock > self.capacity * 0.9:
            if self.reputation < 0.3:
                return Action.D
            return Action.C
        if self.reputation > 0.6:
            return Action.C
        return Action.D

class Strategy_SELFISH_9(BaseStrategy):
    """
    A conditional trigger strategy for the Common Pool Resource Game.
    
    Logic:
    1. First Round: Always Cooperate (C).
    2. Terminal Round (last round): Always Defect (D).
    3. Intermediate Rounds:
        - If stock is critical (calculated threshold), switch to Defect (D).
        - Otherwise, prioritize cooperation if stock is low (recovery mode) or if full cooperation was achieved in the previous round.
        - Retaliate with Defect (D) if defection occurred in the previous round and the stock is sufficient.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        prev_n_c = int(history.opponent_cooperators[-1])
        i_cooperated = 1 if history.my_actions[-1] else 0
        total_n_c = prev_n_c + i_cooperated
        if self.capacity > 0:
            growth_potential = 2.0 * current_stock * (1.0 - current_stock / self.capacity)
            rounds_remaining = self.r - history.round_number
            projected_future = current_stock + growth_potential * rounds_remaining
            if projected_future < self.capacity / self.n:
                return Action.D
        if current_stock < self.capacity / self.n:
            return Action.D
        if total_n_c == self.n or current_stock < self.capacity / 2.0:
            return Action.C
        return Action.D

class Strategy_SELFISH_10(BaseStrategy):
    """
    Conditional Sustainability (CS) Strategy:
    Prioritizes resource preservation when conditions are favorable, but defaults 
    to defecting if the resource is critically depleted, if it is the final round, 
    or if the majority of opponents are defecting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.capacity = self.game_description.capacity
        self.threshold = math.ceil(self.n / 2)
        self.safety_buffer = self.capacity / 4

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.safety_buffer:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_opponents_cooperated = history.opponent_cooperators[-1]
        if prev_opponents_cooperated >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_11(BaseStrategy):
    """
    Implements a cooperative-adaptive strategy for the Common Pool Resource Game.
    Maintains a running average of opponent cooperation (H_c) and adjusts behavior
    based on resource thresholds and estimated opponent trust.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.H_c = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        n = self.game_description.n_players
        n_opponents = n - 1
        k_coop = history.opponent_cooperators[-1]
        if n_opponents > 0:
            self.H_c = (self.H_c * t + k_coop / n_opponents) / (t + 1)
        else:
            pass
        if not hasattr(self, 'last_known_stock'):
            self.last_known_stock = float(self.game_description.capacity)
        stock_new = current_stock
        stock_old = self.last_known_stock
        self.last_known_stock = stock_new
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if t + 1 == r:
            action = Action.D
        elif stock_new < capacity / 2.0:
            action = Action.D
        elif self.H_c > 0.75:
            action = Action.C
        elif self.H_c >= 0.25:
            if stock_new < stock_old:
                action = Action.D
            else:
                action = Action.C
        else:
            action = Action.D
        return action

class Strategy_SELFISH_12(BaseStrategy):
    """
    Tit-for-Tat with Resource Thresholds:
    - Round 1: Cooperate.
    - Final Round: Always Defect.
    - Intermediate Rounds:
        - If stock < capacity/4: Cooperate (to prevent collapse).
        - If stock >= capacity/4: 
            - If previous cooperation rate > 0.5: Cooperate.
            - If previous cooperation rate <= 0.5: Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponents_coop = history.opponent_cooperators[-1]
        total_cooperators = (1 if last_my_action else 0) + last_opponents_coop
        cooperation_rate = total_cooperators / self.game_description.n_players
        threshold = self.game_description.capacity / 4
        if current_stock < threshold:
            return Action.C
        if cooperation_rate > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_13(BaseStrategy):
    """
    A strategy that maintains a common pool resource by cooperating (C)
    when stock levels are critical (S < S_crit) or when recent cooperation
    suggests replenishment is necessary. Otherwise, it defects (D) to
    maximize extraction, except in the final round where it always defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.s_crit = 0.4 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.s_crit:
            return Action.C
        if current_stock > 0.7 * self.capacity:
            return Action.D
        last_my_action = 1 if history.my_actions[-1] else 0
        last_opponent_cooperators = history.opponent_cooperators[-1]
        total_cooperators = last_opponent_cooperators + last_my_action
        if total_cooperators >= self.n / 2:
            return Action.C
        return Action.D

class Strategy_SELFISH_14(BaseStrategy):
    """
    A conditional tit-for-tat strategy with threshold-based depletion avoidance.
    - Endgame: Always defects in the final round.
    - Emergency: Defects if stock < 25% capacity.
    - Opening: Cooperates in round 1.
    - Tit-for-Tat: Cooperates if n-1 or more players cooperated in the previous round; otherwise defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_1_based = history.round_number + 1
        if current_round_1_based == self.game_description.n_rounds:
            return Action.D
        critical_threshold = self.game_description.capacity * 0.25
        if current_stock < critical_threshold:
            return Action.D
        if current_round_1_based == 1:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if total_cooperators_prev >= self.game_description.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_15(BaseStrategy):
    """
    SelfishOptimizer strategy for the Common Pool Resource Game.
    
    Logic:
    - Round 1: Cooperate (C) to preserve stock.
    - Final Round: Defect (D) to exhaust resources.
    - Middle Rounds:
        - If stock < threshold (50% of capacity): Cooperate (C) to prevent resource collapse.
        - If stock >= threshold:
            - If opponent cooperation rate > 0.5: Defect (D) to exploit healthy resource and others' contribution.
            - If opponent cooperation rate <= 0.5: Cooperate (C) to rebuild resource.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold_stock = self.capacity * 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if current_stock < self.threshold_stock:
            return Action.C
        num_opponents = self.n_players - 1
        if num_opponents <= 0:
            return Action.D
        prev_opp_coop_count = history.opponent_cooperators[-1]
        cooperation_rate = prev_opp_coop_count / num_opponents
        if cooperation_rate > 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_16(BaseStrategy):
    """
    Implements the Sustainable Extraction Equilibrium strategy.
    
    This strategy attempts to maintain the common pool resource at a sustainable level 
    (capacity / 2) by reciprocating cooperative behavior. It defaults to cooperation 
    initially, but switches to defection if the stock falls below the threshold or 
    if the collective cooperation rate of the group drops below 50%. It always defects 
    in the final round to maximize remaining utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_round_index == total_rounds:
            return Action.D
        if current_round_index == 1:
            return Action.C
        my_prev_action = history.my_actions[-1]
        n_cooperators_prev = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if current_stock >= capacity / 2:
            if n_cooperators_prev / n >= 0.5:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFISH_17(BaseStrategy):
    """
    A Tit-for-Tat based strategy for the Common Pool Resource Game that incorporates
    sustainability thresholds and opportunistic re-seeding of cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_action = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n_opponents = self.game_description.n_players - 1
        if current_round_idx == total_rounds:
            self._last_action = Action.D
            return Action.D
        if current_stock < capacity / 2:
            self._last_action = Action.D
            return Action.D
        if current_round_idx == 1:
            self._last_action = Action.C
            return Action.C
        opponents_cooperated = history.opponent_cooperators[-1]
        if opponents_cooperated == n_opponents:
            self._last_action = Action.C
            return Action.C
        if self._last_action == Action.D and current_stock > 0.9 * capacity:
            self._last_action = Action.C
            return Action.C
        self._last_action = Action.D
        return Action.D

class Strategy_SELFISH_18(BaseStrategy):
    """
    Implements a Tit-for-Tat with Resource Constraints strategy.
    
    Logic:
    - Phase 1: Always Cooperate in the first round.
    - Phase 3: Always Defect in the final round.
    - Phase 2: If stock is low (<20% capacity), Defect to maximize immediate utility.
    - Otherwise, reciprocate based on majority cooperation (if >= N/2 players cooperated 
      in the previous round, Cooperate, else Defect).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity * 0.2:
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_prev_coop = prev_opp_coop + my_prev_action
        if total_prev_coop >= self.game_description.n_players / 2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_19(BaseStrategy):
    """
    Implements a conditional strategy based on stock levels, trust dynamics,
    and history of opponent behavior in a Common Pool Resource Game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_level = 0.5
        self.reputation_threshold = 0.5
        self.consecutive_zero_cooperation_rounds = 0
        self.depleted_switch_triggered = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if not self.depleted_switch_triggered and current_round_idx < r - 1:
            if current_stock < 0.1 * capacity:
                self.depleted_switch_triggered = True
        if self.depleted_switch_triggered:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == r - 1:
            return Action.D
        if current_stock < capacity / n:
            return Action.D
        k = history.opponent_cooperators[-1]
        if k == 0:
            self.consecutive_zero_cooperation_rounds += 1
        else:
            self.consecutive_zero_cooperation_rounds = 0
        if self.consecutive_zero_cooperation_rounds >= 2:
            self.reputation_threshold = 1.0
        n_opponents = n - 1
        observed_cooperation_rate = k / n_opponents if n_opponents > 0 else 0.0
        self.trust_level = 0.9 * self.trust_level + 0.1 * observed_cooperation_rate
        if n > 10 and self.trust_level < 0.3:
            if k < 1:
                return Action.D
        if self.trust_level >= self.reputation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_20(BaseStrategy):
    """
    A conditional Tit-for-Tat variant.
    
    Strategy Logic:
    1. Initial Round: Always Cooperate (C) to test mutual cooperation and stabilize.
    2. Terminal Round: Always Defect (D) as it is the dominant strategy when no future rounds exist.
    3. Steady State:
       - If stock is low (<= capacity / 2), play Cooperate (C) to prevent resource collapse.
       - If stock is high (> capacity / 2):
         - Use the previous round's aggregate cooperation (k):
           - If k >= (n - 1) / 2, play Cooperate (C).
           - Otherwise, play Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        if current_stock <= capacity / 2:
            return Action.C
        k = history.opponent_cooperators[-1]
        threshold = (n - 1) / 2
        if k >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_21(BaseStrategy):
    """
    Implements the Conditional Sustainability-Maximization strategy.
    
    This strategy treats the common pool as a finite asset, balancing long-term 
    sustainable harvesting with aggressive retaliation against defectors.
    
    Logic priority:
    1. Final Round: Always defect to maximize final utility.
    2. Depletion Emergency: Defect if the stock is too low to sustain future growth.
    3. Round 1: Cooperate to establish the resource base.
    4. Intermediate Rounds: Use Tit-for-Tat (50% threshold) to decide between 
       continued cooperation or defensive defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if current_round == 0:
            return Action.C
        previous_cooperators = history.opponent_cooperators[-1]
        if previous_cooperators / self.n_opponents >= 0.5:
            return Action.C
        return Action.D

class Strategy_SELFISH_22(BaseStrategy):
    """
    A responsive sustainability strategy for the Common Pool Resource game.
    
    The strategy maintains a dynamic sustainability threshold (S_target) based on 
    population cooperation levels. It defaults to cooperation in the first round.
    If the population cooperates (C_avg > 0.5), it aims to maintain a higher stock 
    threshold (0.75 * capacity). If the population defects, it lowers the threshold 
    to preserve remaining stock or abandons sustainability if the resource collapses 
    below a critical level (0.1 * capacity) or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.s_target = self.capacity * 0.75
        self.s_target_base = self.capacity * 0.75
        self.s_target_min = self.capacity * 0.25
        self.s_collapse_threshold = self.capacity * 0.1
        self.force_defect_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if self.force_defect_mode:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.s_collapse_threshold:
            self.force_defect_mode = True
            return Action.D
        last_round_opponents_c = int(history.opponent_cooperators[-1])
        my_prev_action = history.my_actions[-1]
        total_cooperators = last_round_opponents_c + (1 if my_prev_action else 0)
        c_avg = total_cooperators / self.n
        if c_avg <= 0.5:
            self.s_target = max(self.s_target_min, self.s_target - self.capacity * 0.1)
        else:
            self.s_target = self.s_target_base
        if current_stock < self.s_target:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_23(BaseStrategy):
    """
    A sustainability-focused Tit-for-Tat strategy for the Common Pool Resource Game.
    Prioritizes maintaining stock levels above critical thresholds while using
    tit-for-tat retaliation to manage cooperation. It features a recovery mode
    to resume cooperation only after stocks have stabilized, and an unconditional
    defection in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        last_round_idx = self.game_description.n_rounds - 1
        if round_idx == last_round_idx:
            return Action.D
        if current_stock < 0.2 * self.game_description.capacity:
            return Action.D
        if round_idx == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        c_obs = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        if current_stock < 0.5 * self.game_description.capacity:
            if c_obs < self.game_description.n_players - 1:
                return Action.D
        if c_obs >= self.game_description.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_24(BaseStrategy):
    """
    Implements an adaptive extraction strategy that balances resource preservation
    against exploitation based on current stock levels and observed opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if rounds_remaining <= 2:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock <= 0.001:
            return Action.C
        threshold = self.game_description.capacity * 0.5
        if current_stock <= threshold:
            return Action.C
        k = float(history.opponent_cooperators[-1])
        n = float(self.game_description.n_players)
        if k > n / 2.0:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_25(BaseStrategy):
    """
    A strategy that balances resource preservation and exploitation using a Target Sustainability 
    Level (TSL) and adaptive response to opponent defection and resource health.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.tsl = 0.5 * self.capacity
        self.in_recovery_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        k_prev = self.n - 1 - prev_cooperators
        prev_stock = 0.0
        if not hasattr(self, 'last_stock'):
            self.last_stock = self.capacity
        if self.in_recovery_mode:
            if current_stock >= 0.3 * self.capacity:
                self.in_recovery_mode = False
        elif current_stock < self.last_stock * 0.2:
            self.in_recovery_mode = True
        current_last_stock = self.last_stock
        self.last_stock = current_stock
        if self.in_recovery_mode:
            return Action.C
        if history.round_number >= 2:
            k_prev_prev = self.n - 1 - history.opponent_cooperators[-2]
            if k_prev == self.n - 1 and k_prev_prev == self.n - 1:
                return Action.D
        if current_stock <= self.tsl:
            return Action.C
        threshold = math.floor((self.n - 1) / 2)
        if k_prev <= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_26(BaseStrategy):
    """
    Implements a conditionally cooperative strategy based on current stock levels
    and the previous round's group cooperation, defecting on the final round
    or if stock/cooperation thresholds are not met.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.capacity = self.game_description.capacity
        self.total_rounds = self.game_description.n_rounds
        self.defection_threshold = (self.n - 1) / self.n

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.D
        my_last_action = history.my_actions[-1]
        if my_last_action:
            total_cooperators = history.opponent_cooperators[-1] + 1
        else:
            total_cooperators = history.opponent_cooperators[-1]
        cooperation_ratio = total_cooperators / self.n
        if cooperation_ratio < self.defection_threshold:
            return Action.D
        return Action.C

class Strategy_SELFISH_27(BaseStrategy):
    """
    Common Pool Resource strategy implementing growth-neutral stock awareness,
    reciprocity, and final-round defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        k = self.game_description.capacity
        t = history.round_number + 1
        if t == r:
            return Action.D
        if t == 1:
            return Action.C
        if current_stock <= k / n ** 2:
            return Action.D
        prev_my_action_val = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + prev_my_action_val
        if c_prev >= n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_28(BaseStrategy):
    """
    A Tit-for-Tat inspired strategy that maintains resource sustainability.
    
    The strategy cooperates (C) in the first round. In subsequent rounds (until the last),
    it calculates if the resource stock is projected to remain above 50% of capacity 
    based on the previous round's cooperation levels. If the projection is poor, or if 
    defectors were present in the last round, it switches to Defect (D) to maximize
    returns before depletion or to retaliate. In the final round, it always defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.target_stock = self.capacity * 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t == self.r - 1:
            return Action.D
        my_last_action = history.my_actions[-1]
        my_k = 1 if my_last_action else 0
        k_prev = history.opponent_cooperators[-1] + my_k
        s = current_stock
        consumption = k_prev * (s / (2 * self.n)) + (self.n - k_prev) * (s / self.n)
        s_rem = max(0.0, s - consumption)
        growth = 2 * s_rem * (1 - s_rem / self.capacity) if self.capacity > 0 else 0
        s_next = min(float(self.capacity), s_rem + growth)
        if s_next < self.target_stock or s < self.capacity * 0.25:
            return Action.D
        elif k_prev < self.n:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_29(BaseStrategy):
    """
    A Tit-for-Tat variant strategy for the Common Pool Resource Game.
    
    Logic:
    - First Round: Always Cooperate (C) to build stock.
    - Last Round: Always Defect (D) to maximize terminal payoff.
    - Stock Collapse: If stock is 0, always Defect (D).
    - Mid-game:
        - If rho (stock/capacity) < 0.25: Defect (D) immediately to maximize share before collapse.
        - Otherwise: Cooperate (C) if previous round cooperators >= n - 1 (very high group cooperation),
          else Defect (D) to punish non-cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        rho = current_stock / self.capacity
        if rho < 0.25:
            return Action.D
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_coop
        if total_cooperators_prev >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_30(BaseStrategy):
    """
    Threshold-Based Sustainable Exploitation (TBSE) strategy.
    Maintains resource stability using growth thresholds while adaptively 
    exploiting based on the cooperation environment.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        my_actions_int = history.my_actions.astype(int)
        total_cooperators_per_round = my_actions_int + history.opponent_cooperators
        avg_cooperation_rate = np.mean(total_cooperators_per_round / self.n)
        if avg_cooperation_rate <= 0.5:
            return Action.D
        if history.round_number % 2 == 1:
            avg_opp_coops = np.mean(history.opponent_cooperators)
            projected_consumption = current_stock / self.n + avg_opp_coops * (current_stock / (2 * self.n))
            remaining = current_stock - projected_consumption
            growth = 2 * remaining * (1 - remaining / self.capacity)
            next_S = min(remaining + growth, self.capacity)
            if next_S > 0.5 * self.capacity:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_SELFISH_31(BaseStrategy):
    """
    Implements the 'Conditional Sustainability' strategy:
    - Round 1: Cooperate.
    - Final Round: Defect.
    - Intermediate Rounds:
        - If current stock < capacity / 2: Defect.
        - Else: Cooperate if previous round cooperation rate >= 0.75, else Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        if current_round == self.r:
            return Action.D
        s_threshold = self.capacity / 2.0
        if current_stock < s_threshold:
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_k = 1 if my_prev_action else 0
        opponents_prev_k = history.opponent_cooperators[-1]
        total_k_prev = opponents_prev_k + my_prev_k
        rho = total_k_prev / self.n
        if rho >= 0.75:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_32(BaseStrategy):
    """
    Tit-for-Tat with Threshold-Based Defection.
    Maintains a trust_level based on opponent cooperation history.
    Transitions between C and D based on trust thresholds and stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_level = 1.0
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.trust_level = 1.0
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_n_c = history.opponent_cooperators[-1]
        capacity = self.game_description.capacity
        if current_stock <= 0.1 * capacity:
            return Action.D
        r_c = prev_n_c / self.n_opponents if self.n_opponents > 0 else 0.0
        self.trust_level = 0.9 * self.trust_level + 0.1 * r_c
        if prev_n_c == 0:
            self.trust_level = 0.0
            return Action.D
        if current_stock > 0.8 * capacity:
            return Action.C
        if current_stock < 0.4 * capacity or self.trust_level < 0.4:
            return Action.D
        if current_stock >= 0.4 * capacity and self.trust_level >= 0.5:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_5(BaseStrategy):
    """
    A strategy that combines sustainability constraints with Tit-for-Tat enforcement.
    1. If the common pool stock is critically low, it defects to maximize extraction.
    2. If it is the final round, it defects to maximize extraction.
    3. Otherwise, it cooperates in the first round and subsequently mimics the 
       cooperation status of the group (punishing if anyone defected).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == total_rounds:
            return Action.D
        if current_stock < capacity / (2 * n):
            return Action.D
        if history.round_number == 0:
            return Action.C
        previous_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_k = previous_cooperators + (1 if my_prev_action else 0)
        if total_k < n:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_6(BaseStrategy):
    """
    Conditional Reciprocity with Stock Awareness:
    - Plays Cooperate in the first round.
    - In subsequent rounds, defects if the final round is reached, if the stock is critically low (emergency threshold),
      or if the stock cannot sustain mutual cooperation (survival threshold).
    - Otherwise, reciprocates cooperation based on the previous round's cooperation count from opponents.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.survival_threshold = self.game_description.capacity / (2 * self.game_description.n_players)
        self.emergency_threshold = 0.1 * self.game_description.capacity
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.emergency_threshold:
            return Action.D
        if current_stock < self.survival_threshold:
            return Action.D
        prev_opp_cooperators = history.opponent_cooperators[-1]
        if prev_opp_cooperators >= self.n_opponents / 2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_7(BaseStrategy):
    """
    A recursive strategy for the Common Pool Resource Game. 
    Cooperates initially, then adapts based on the observed aggregate opponent 
    cooperation rate (alpha) and stock levels to balance sustainability 
    against exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        r = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if t == 0:
            return Action.C
        if t == r - 1:
            return Action.D
        if current_stock < capacity / n:
            return Action.D
        total_coop_obs = int(np.sum(history.opponent_cooperators))
        total_opp_rounds = (n - 1) * t
        alpha = total_coop_obs / total_opp_rounds if total_opp_rounds > 0 else 0.0
        if alpha < 0.25 and current_stock < capacity / 2:
            return Action.D
        if current_stock < capacity / 2:
            return Action.C
        return Action.C if alpha >= 0.5 else Action.D

class Strategy_SELFINTERESTED_8(BaseStrategy):
    """
    Dynamic Sustainable Tit-for-Tat (DSTFT):
    A conditional cooperation strategy that cooperates if the stock is healthy
    (>= capacity / 2) and all opponents cooperated in the previous round.
    It defects in the final round and whenever the sustainability conditions are violated.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.capacity = self.game_description.capacity
        self.n_rounds = self.game_description.n_rounds
        self.c_opp_threshold = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_opp_c = history.opponent_cooperators[-1]
        is_stock_healthy = current_stock >= self.capacity / 2
        all_opponents_cooperated = prev_opp_c == self.c_opp_threshold
        if is_stock_healthy and all_opponents_cooperated:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_9(BaseStrategy):
    """
    A strategy for the Common Pool Resource game that conditionally cooperates,
    punishes defectors based on their count, protects against resource collapse,
    and exploits the common pool in terminal rounds if sufficient stock exists.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.active_punishment_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.game_description.n_rounds - 2:
            if current_stock > 0.5 * self.game_description.capacity:
                return Action.D
        if current_stock < 0.05 * self.game_description.capacity:
            return Action.D
        if self.active_punishment_rounds > 0:
            self.active_punishment_rounds -= 1
            return Action.D
        prev_opp_cooperators = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        total_cooperators = prev_opp_cooperators + (1 if prev_my_action else 0)
        defectors_count = self.game_description.n_players - total_cooperators
        if defectors_count > 0:
            self.active_punishment_rounds = defectors_count - 1
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_10(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Depletion Thresholding:
    - Round 1: Cooperate.
    - Final Round: Always Defect.
    - Threshold: If stock < capacity/2, Defect to maximize immediate utility as recovery is unreliable.
    - Reciprocity: If stock >= capacity/2, Cooperate only if all opponents cooperated previously.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        n_opponents = n_players - 1
        if round_t == total_rounds:
            return Action.D
        if current_stock < capacity / 2.0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_coop_count = int(history.opponent_cooperators[-1])
        if last_round_coop_count == n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_11(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy for the Common Pool Resource Game.
    
    Logic:
    1. First Round: Always Cooperate.
    2. Last Round: Always Defect.
    3. Intermediate Rounds:
       - If stock is fragile (S < capacity/2): Cooperate only if everyone else cooperated (k = n-1).
       - If stock is robust (S >= capacity/2): Cooperate if a majority cooperated (k >= (n-1)/2).
       - If stock is effectively 0: Always Defect to capture final payoffs.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.n_opponents = self.n - 1
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == self.total_rounds - 1:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        if current_stock < 0.001:
            return Action.D
        is_fragile = current_stock < self.capacity / 2.0
        if is_fragile:
            if k_prev == self.n_opponents:
                return Action.C
            else:
                return Action.D
        else:
            majority_threshold = math.floor(self.n_opponents / 2.0)
            if k_prev >= majority_threshold:
                return Action.C
            else:
                return Action.D

class Strategy_SELFINTERESTED_12(BaseStrategy):
    """
    A strategy that maximizes long-term yield by maintaining the resource stock near the
    Optimal Sustainability Threshold (OST). It utilizes conditional, history-dependent logic:
    Cooperating when the stock is robust and the group shows cooperation, but defecting
    when the stock is critically low, the group is uncooperative, or it is the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 0.0001:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if self.n == 2:
            if history.opponent_cooperators[-1] == 1:
                return Action.C
            else:
                return Action.D
        if current_stock <= self.capacity * 0.25:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        threshold = math.floor(self.n / 2)
        if k_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_13(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Threshold (TFTS).
    
    Logic:
    1. If it is the last round, Defect (D).
    2. If stock is < capacity/2, Defect (D).
    3. If round 1, Cooperate (C).
    4. Otherwise, Cooperate (C) if (n-1) or more players cooperated in the last round, else Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 2.0:
            return Action.D
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_contribution = 1 if my_prev_action else 0
        k_prev = history.opponent_cooperators[-1] + my_contribution
        if k_prev >= self.game_description.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_14(BaseStrategy):
    """
    Trigger-Based Sustainable Yield (TBSY):
    A strategy that maintains cooperation (C) as long as opponents cooperate.
    It defects (D) if any opponent defects, unless the resource stock is 
    sufficiently high to encourage recovery (re-establishing cooperation),
    or if it is the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        consumption_c = current_stock / (2 * n)
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock <= 0 or current_stock < consumption_c:
            return Action.D
        if current_stock > 0.8 * capacity:
            return Action.C
        opponents_cooperated_prev_round = history.opponent_cooperators[-1]
        if opponents_cooperated_prev_round == n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_15(BaseStrategy):
    """
    Threshold-Based Stewardship strategy:
    - Plays C in round 0.
    - Terminal rounds (r-2, r-1): Plays D.
    - Conservation Phase (stock < 0.5 * capacity): Plays C.
    - Healthy Phase (stock >= 0.5 * capacity):
        - If any opponents defected in the previous round (opponent_cooperators < n-1), plays D.
        - Otherwise, plays C.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_opponents = self.game_description.n_players - 1
        if current_round >= self.game_description.n_rounds - 2:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.game_description.capacity * 0.5:
            return Action.C
        if history.opponent_cooperators[-1] < n_opponents:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_16(BaseStrategy):
    """
    Optimistic Trigger Strategy for Common Pool Resource Game:
    - Rounds 1-2: Always Cooperate.
    - Subsequent Rounds:
        - Defect if stock < 0.25 * capacity.
        - Defect if final round (r).
        - Defect if second to last round (r-1) and stock < 0.5 * capacity.
        - Otherwise, Cooperate if previous round cooperation count >= ceil(n/2).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.capacity = self.game_description.capacity
        self.n_req = math.ceil(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        current_round_num = current_round_idx + 1
        if current_round_idx == self.r - 1:
            return Action.D
        if current_round_idx == self.r - 2 and current_stock < 0.5 * self.capacity:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if current_round_idx <= 1:
            return Action.C
        n_c_previous = int(history.opponent_cooperators[-1])
        my_last_action = bool(history.my_actions[-1])
        total_cooperators = n_c_previous + (1 if my_last_action else 0)
        if total_cooperators >= self.n_req:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_17(BaseStrategy):
    """
    A Tit-for-Tat with Threshold Monitoring strategy.
    
    1. First Round: Cooperate (C).
    2. Final Round: Defect (D) to maximize terminal payoff.
    3. Intermediate Rounds:
       - Safety Check: If current_stock < capacity / n_players, Defect (D).
       - Reciprocity Check: If the observed external cooperation rate in the previous 
         round is < 0.5, Defect (D).
       - Sustainability/Default: Otherwise, Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold_stock = 0.7 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if n_opponents > 0:
            opp_cooperation_rate = prev_opp_cooperators / n_opponents
        else:
            opp_cooperation_rate = 1.0
        if current_stock < self.capacity / self.n:
            return Action.D
        if opp_cooperation_rate < 0.5:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_18(BaseStrategy):
    """
    Conditional Sustainability Equilibrium (CSE) strategy.
    Implements a threshold-based, trigger-tit-for-tat logic that prioritizes 
    stock sustainability while scaling punishment to observed defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            if current_stock >= capacity / 2:
                return Action.D
            else:
                return Action.C
        if current_stock < capacity / 4:
            return Action.C
        n_opponents = n - 1
        k = history.opponent_cooperators[-1]
        threshold = math.ceil(n_opponents / 2)
        if k >= threshold:
            return Action.C
        else:
            d_opponents = n_opponents - k
            prob_defect = d_opponents / n_opponents
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_SELFINTERESTED_19(BaseStrategy):
    """
    Adaptive Sustainability Guard: A Tit-for-Tat inspired strategy that balances
    resource maintenance with opportunistic extraction. Prioritizes stock levels above
    0.75 capacity. Punishes non-cooperators probabilistically when stock is high,
    and switches to hard defection when the resource is critical (below 75% capacity).
    Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.safe_stock_threshold = self.capacity * 0.75

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n_opponents = self.n - 1
        last_opponents_c = history.opponent_cooperators[-1]
        cooperation_rate = last_opponents_c / n_opponents if n_opponents > 0 else 1.0
        if current_stock >= self.safe_stock_threshold:
            if cooperation_rate >= 1.0:
                return Action.C
            elif random.random() > cooperation_rate:
                return Action.D
            else:
                return Action.C
        elif cooperation_rate >= 0.8:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_20(BaseStrategy):
    """
    Sustainable Tit-for-Tat with Resource Thresholding.

    This strategy enforces long-term sustainability by combining Tit-for-Tat 
    reciprocity with a hard constraint based on the remaining resource stock.
    - If the final round is reached, it defects to maximize short-term payoff.
    - If the stock falls below a critical safety threshold (capacity / 2n), it defects 
      to extract remaining value before depletion.
    - Otherwise, it initiates with Cooperation and subsequently matches the 
      collective cooperation of all opponents (requiring full cooperation from 
      everyone to sustain trust).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        safety_threshold = self.game_description.capacity / (2 * self.game_description.n_players)
        if current_stock < safety_threshold:
            return Action.D
        if history.round_number == 0:
            return Action.C
        opponents_count = self.game_description.n_players - 1
        if history.opponent_cooperators[-1] >= opponents_count:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_21(BaseStrategy):
    """
    Implements a resource-conscious Tit-for-Tat strategy with conditional forgiveness.
    Prioritizes sustainability, defects only when necessary or in the final round,
    and attempts to maintain coordination through forgiveness after punishment cycles.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.epsilon = 1e-09
        self.punishing = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        n_opponents = self.n - 1
        if current_stock / self.n < self.epsilon:
            return Action.D
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        s_threshold = self.capacity * (0.5 / self.n)
        if current_stock < s_threshold:
            return Action.D
        if round_idx == 0:
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        if n_opponents > 0:
            opp_coop_rate = prev_k / n_opponents
        else:
            opp_coop_rate = 1.0
        if self.punishing:
            self.punishing = False
            return Action.C
        if opp_coop_rate >= 0.5:
            return Action.C
        else:
            self.punishing = True
            return Action.D

class Strategy_SELFINTERESTED_22(BaseStrategy):
    """
    Tit-for-Tat with Conditional Forgiveness and Terminal Defection.
    
    This strategy cooperates based on a sustainability threshold and opponent
    reputation history. It switches to defecting if the resource stock is critical
    or if opponents consistently defect, while maintaining a mechanism to
    forgive and return to cooperation if opponents behave sustainably for
    two consecutive rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 0
        self.last_stock = float(game_description.capacity)
        self.consecutive_opp_c = 0
        self.is_currently_defecting = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        last_round_idx = self.game_description.n_rounds - 1
        if current_round_idx == last_round_idx:
            return Action.D
        if current_round_idx == 0:
            self.last_stock = current_stock
            return Action.C
        prev_opp_c = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        threshold = n_opponents * 0.5
        if prev_opp_c >= threshold:
            self.consecutive_opp_c += 1
        else:
            self.consecutive_opp_c = 0
        if self.is_currently_defecting and self.consecutive_opp_c >= 2:
            self.reputation = 0
            self.is_currently_defecting = False
            self.last_stock = current_stock
            return Action.C
        if self.last_stock < self.game_description.capacity / 4:
            self.is_currently_defecting = True
            self.last_stock = current_stock
            return Action.D
        if prev_opp_c >= threshold:
            self.reputation = min(0, self.reputation + 1)
            self.is_currently_defecting = False
            self.last_stock = current_stock
            return Action.C
        else:
            self.reputation = max(-2, self.reputation - 1)
            self.is_currently_defecting = True
            self.last_stock = current_stock
            return Action.D

class Strategy_SELFINTERESTED_23(BaseStrategy):
    """
    Threshold-Based Tit-for-Tat with Sustainability Correction.
    
    Logic:
    1. Final Round: Always Defect.
    2. Near-Zero Stock: If stock < capacity/(2n), Defect.
    3. First Round: Always Cooperate.
    4. Reciprocity Reset: If history average of opponent cooperation < 0.25, permanently Defect.
    5. Adaptive Thresholding:
       - If stock < capacity/2: Cooperate if F_prev >= 0.5, else Defect.
       - If stock >= capacity/2: Cooperate if F_prev > 0.5; Stochastic probe if F_prev == 0.5; Defect if F_prev < 0.5.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.n_opponents = self.n - 1
        self.capacity = game_description.capacity
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if self.permanent_defect:
            return Action.D
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if round_idx == total_rounds - 1:
            return Action.D
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if round_idx == 0:
            return Action.C
        total_opp_coop = np.sum(history.opponent_cooperators)
        total_possible_coop = round_idx * self.n_opponents
        if total_possible_coop > 0:
            avg_history_coop = total_opp_coop / total_possible_coop
            if avg_history_coop < 0.25:
                self.permanent_defect = True
                return Action.D
        f_prev = history.opponent_cooperators[-1] / self.n_opponents
        if current_stock < self.capacity / 2:
            if f_prev >= 0.5:
                return Action.C
            else:
                return Action.D
        elif f_prev > 0.5:
            return Action.C
        elif f_prev == 0.5:
            return Action.C if random.random() > 0.5 else Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_24(BaseStrategy):
    """
    A Tit-for-Tat variant strategy for the Common Pool Resource Game.
    
    This strategy implements:
    1.  Initial Round: Always Cooperate (C).
    2.  Subsequent Rounds: Cooperate (C) if all other players cooperated in the previous 
        round, else Defect (D).
    3.  Restoration Rule: If stock drops below 50% of capacity, force Cooperate (C) 
        regardless of previous history.
    4.  Final Round: Always Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if current_stock < self.capacity / 2.0:
            return Action.C
        if history.round_number == 0:
            return Action.C
        if history.opponent_cooperators[-1] == self.n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_25(BaseStrategy):
    """
    Implements a Tit-for-Tat with Forgiveness strategy in a Common Pool Resource game.
    Prioritizes sustainability, exploits surplus when possible, but reverts to 
    cooperation when the resource is threatened or recovery is needed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        r = self.game_description.n_rounds
        n = self.n
        if t == r:
            return Action.D
        if t == 1:
            return Action.C
        if current_stock <= self.capacity / (2 * n):
            return Action.C
        if current_stock >= 0.9 * self.capacity:
            return Action.D
        was_cooperating = history.my_actions[-1]
        c_prev_val = int(was_cooperating) + history.opponent_cooperators[-1]
        if t >= 3:
            c_prev_minus_1 = int(history.my_actions[-2]) + history.opponent_cooperators[-2]
            if c_prev_val < n / 2 and c_prev_minus_1 < n / 2:
                return Action.D
        if c_prev_val == n:
            return Action.C
        if current_stock > self.capacity / 2:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_26(BaseStrategy):
    """
    Implements Adaptive Tit-for-Tat with Sustainable Thresholds.
    
    Strategy:
    - Initial Round: Cooperate (C).
    - Final Round: Always Defect (D).
    - Logic (intermediate rounds):
        - Define Sustainable Stock Threshold (T) = 0.5 * capacity.
        - If current stock is critically low (<= 0.1 * capacity) or population 
          shows persistent defection (if cumulative defection is high), play D.
        - Otherwise, if stock >= T, cooperate if almost everyone else cooperated.
        - If stock < T, cooperate only if almost everyone else cooperated (restorative).
        - If majority consistently defects across history, switch to permanent D.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.T = 0.5 * self.game_description.capacity
        self.critical_stock_threshold = 0.1 * self.game_description.capacity
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            self.permanent_defection = True
            return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if not self.permanent_defection and history.round_number >= 3:
            num_opponents = self.game_description.n_players - 1
            recent_coop = np.mean(history.opponent_cooperators[-3:])
            if recent_coop < num_opponents * 0.25:
                self.permanent_defection = True
        if self.permanent_defection:
            return Action.D
        if current_stock <= self.critical_stock_threshold:
            return Action.D
        k = history.opponent_cooperators[-1]
        num_opponents = self.game_description.n_players - 1
        required_coop = max(0, num_opponents - 1)
        if current_stock >= self.T:
            if k >= required_coop:
                return Action.C
            else:
                return Action.D
        elif k >= required_coop:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_27(BaseStrategy):
    """
    Implements a Tit-for-Tat with Sustainability Threshold strategy for the Common Pool Resource game.
    
    Logic:
    1. Always plays C in the first round.
    2. Always plays D in the final round.
    3. In intermediate rounds:
       - If stock < capacity / n_players: Prioritize extraction (Defect/D).
       - Otherwise: Reciprocate based on the previous round's cooperation rate (>= 50% leads to Cooperate/C, else Defect/D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        if current_round_index == 0:
            return Action.C
        if current_round_index == self.game_description.n_rounds - 1:
            return Action.D
        threshold = self.game_description.capacity / self.game_description.n_players
        if current_stock < threshold:
            return Action.D
        prev_coop_count = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        total_cooperators = prev_coop_count + my_prev_coop
        cooperation_rate = total_cooperators / self.game_description.n_players
        if cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_28(BaseStrategy):
    """
    A state-dependent conditional cooperation strategy for the Common Pool Resource Game.
    
    Implements a hierarchy of logic:
    1. Terminal Defection: If on the last round, always defect.
    2. Recovery Failure: If the stock has been critically low for too long, defect.
    3. Restoration Phase: If stock is low, cooperate to restore it.
    4. Normal Operations: Use tit-for-tat like thresholds to maintain cooperation,
       with a deterrent mechanism for persistent defectors.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.low_stock_consecutive_count = 0
        self.failed_cooperation_consecutive_count = 0
        self.n = self.game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r = history.round_number
        if r == 0:
            return Action.C
        if r == self.game_description.n_rounds - 1:
            return Action.D
        capacity = self.game_description.capacity
        prev_k = history.opponent_cooperators[-1]
        if current_stock < 0.1 * capacity:
            self.low_stock_consecutive_count += 1
        else:
            self.low_stock_consecutive_count = 0
        if self.n > 0:
            threshold = (2 * self.n - 2) / (2 * self.n)
            if prev_k / self.n < threshold:
                self.failed_cooperation_consecutive_count += 1
            else:
                self.failed_cooperation_consecutive_count = 0
        if self.low_stock_consecutive_count > 3:
            return Action.D
        if self.failed_cooperation_consecutive_count >= 2:
            return Action.D
        if current_stock < 0.5 * capacity:
            return Action.C
        threshold = (2 * self.n - 2) / (2 * self.n)
        if prev_k / self.n >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_29(BaseStrategy):
    """
    Tit-for-Tat with Resilience strategy:
    Prioritizes sustainability by monitoring stock levels and punishing mass defection
    while attempting to maintain a cooperative equilibrium.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        current_prev_stock = self.prev_stock
        self.prev_stock = current_stock
        if round_idx == r - 1:
            if current_stock <= 0:
                return Action.C
            return Action.D
        if current_stock <= 0:
            return Action.C
        if current_stock < capacity / 4.0:
            return Action.C
        if round_idx > 0 and current_stock < current_prev_stock * 0.5:
            return Action.C
        if round_idx > 0:
            prev_opponents_cooperated = history.opponent_cooperators[-1]
            threshold = math.ceil(n / 2.0)
            if prev_opponents_cooperated >= threshold:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_SELFINTERESTED_30(BaseStrategy):
    """
    A Trigger-Based Tit-for-Tat variant strategy.
    
    Logic:
    1. Always cooperate in the first round.
    2. Always defect in the final round (endgame optimization).
    3. Defect if the stock level is critically low (< capacity/n).
    4. If previous round was fully cooperative, continue to cooperate.
    5. If previous round saw defection, enter a punishment phase proportional 
       to the severity of defection, where we defect.
    6. If punishment ends and stock is healthy, resume cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock < capacity / n:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if self.punishment_counter > 0:
            self.punishment_counter -= 1
            return Action.D
        if prev_cooperators == n:
            return Action.C
        severity = (n - prev_cooperators) / n
        remaining_rounds = total_rounds - (current_round_idx + 1)
        punishment_rounds = math.ceil(severity * remaining_rounds)
        if punishment_rounds > 0:
            self.punishment_counter = punishment_rounds - 1
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_31(BaseStrategy):
    """
    A strategy that prioritizes sustainability by cooperating when the stock 
    is healthy or regenerating and the group cooperates, while defecting 
    when the stock is critical or when the group fails to cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = game_description.capacity
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.prev_stock = current_stock
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        prev_total_coop = prev_opp_coop + (1 if my_prev_action else 0)
        prev_defectors = self.n - prev_total_coop
        if current_stock < 0.25 * self.capacity or prev_defectors > 1:
            self.prev_stock = current_stock
            return Action.D
        if (current_stock >= self.prev_stock or current_stock >= 0.5 * self.capacity) and prev_total_coop >= self.n - 1:
            self.prev_stock = current_stock
            return Action.C
        self.prev_stock = current_stock
        return Action.D

class Strategy_SELFINTERESTED_32(BaseStrategy):
    """
    A Tit-for-Tat with Forgiveness strategy for the Common Pool Resource Game.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Round r: Always Defect (D) to harvest remaining resources.
    - Rounds 2 to r-1:
        - If current stock < capacity/4, Cooperate (C) to prevent collapse.
        - Otherwise, evaluate group behavior:
            - If opponents cooperating (k >= n-1), Cooperate (C).
            - If opponents defecting (k < n-1), Defect (D), 
              unless we previously defected and they have returned to cooperation 
              (Forgiveness).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        if current_round_index == self.r - 1:
            return Action.D
        if current_round_index == 0:
            return Action.C
        if current_stock < self.capacity / 4:
            return Action.C
        k = history.opponent_cooperators[-1]
        if k >= self.threshold:
            return Action.C
        if not history.my_actions[-1]:
            if k >= self.threshold:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_5(BaseStrategy):
    """
    A conditional strategy that tracks cooperation history (H) to manage resource depletion.
    It cooperates to sustain the pool when the environment is stable, but switches to
    opportunistic defection if the stock hits critical lows or if the collective
    cooperation history decays. It includes a terminal-phase defection trigger.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.H = 0.0
        self._consecutive_recovery_count = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == r - 1:
            return Action.D
        if t > 0.75 * r:
            return Action.D
        if t == 0:
            return Action.C
        prev_k = history.opponent_cooperators[t - 1]
        if n > 1:
            self.H += prev_k / (n - 1) - 0.5
        if prev_k == n - 1:
            self._consecutive_recovery_count += 1
        else:
            self._consecutive_recovery_count = 0
        if self._consecutive_recovery_count >= 2:
            self.H = 0.0
        consumption_per_c = current_stock / (2 * n)
        if current_stock < consumption_per_c:
            return Action.D
        is_stable = prev_k == n - 1
        if current_stock < 0.25 * capacity or self.H < -2.0:
            return Action.D
        elif is_stable and current_stock >= 0.5 * capacity:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_6(BaseStrategy):
    """
    Opportunistic-Trigger Strategy:
    - Round 1: Always Cooperate (C).
    - Final Round: Always Defect (D).
    - Emergency (S < 0.2*capacity): Always Cooperate (C).
    - High Yield (S > 0.8*capacity): Always Defect (D).
    - Retaliation: If current punishment mode active, Defect (D).
    - Trigger Mechanism: Tracks reputation; punishes if stock drops below expected cooperative levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.is_punishing = False
        self.reputation = 0.0
        self.punishment_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.desc.n_players
        capacity = self.desc.capacity
        if t == 0:
            return Action.C
        if t == self.desc.n_rounds - 1:
            return Action.D
        if t > 0:
            prev_round = t - 1
            prev_S = current_stock
            coop_count = history.opponent_cooperators[prev_round]
            expected_coop_count = n - 1
            if coop_count < expected_coop_count:
                self.reputation -= 1.0
            else:
                self.reputation += 0.5
            if self.reputation < -0.5 * n:
                self.is_punishing = True
            if self.is_punishing:
                if current_stock > 0.5 * capacity and coop_count >= n - 1:
                    self.punishment_streak += 1
                else:
                    self.punishment_streak = 0
                if self.punishment_streak >= 2:
                    self.is_punishing = False
                    self.punishment_streak = 0
        if self.is_punishing:
            return Action.D
        if current_stock < 0.2 * capacity:
            return Action.C
        if current_stock > 0.8 * capacity:
            return Action.D
        opp_ratio = history.opponent_cooperators[-1] / (n - 1)
        if opp_ratio > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_7(BaseStrategy):
    """
    Opportunistic Tit-for-Tat Strategy:
    Balances resource sustainability with exploitation.
    - Operates on a Target Cooperation Level mechanism.
    - End-game: Always defects.
    - Sustainability Threshold: If stock is dangerously low, defects to extract value.
    - Tit-for-Tat: Cooperates if opponents cooperated, otherwise defects.
    - Rapid Depletion Check: Emergency defect if stock < 10% capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        current_round_idx = history.round_number + 1
        if current_round_idx == r:
            return Action.D
        s_min = capacity / (n + 1)
        if current_stock < s_min:
            return Action.D
        if current_stock < 0.1 * capacity:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n_c = int(history.opponent_cooperators[-1])
        if current_stock >= 0.9 * capacity:
            if n_c >= n - 1:
                return Action.C
            else:
                return Action.D
        if n_c >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_8(BaseStrategy):
    """
    Implements Dynamic Threshold Reciprocity:
    - Round 1: Cooperate to establish baseline.
    - Steady State: Cooperate if opponents were cooperative enough (>=(n-1)/2).
    - Defect if opponents were uncooperative and stock is high (opportunism).
    - Cooperate if opponents were uncooperative and stock is low (sustainability).
    - Final Round: Always defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        prev_opponents_cooperated = int(history.opponent_cooperators[-1])
        sustainability_threshold = (self.n - 1) / 2.0
        if prev_opponents_cooperated >= sustainability_threshold:
            return Action.C
        elif current_stock > self.capacity / 4.0:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_9(BaseStrategy):
    """
    A strategy that cooperates if the current stock level is sufficient to sustain growth, 
    but defects in the final round or if the stock falls below the defined sustainability threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = self.game_description.capacity / self.game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.threshold or current_stock <= 0:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_10(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with terminal defection.
    - Round 1: Always Cooperate.
    - Last Round (t=r): Always Defect.
    - Intermediate Rounds:
        - Cooperate if all other players cooperated in the previous round.
        - If previous cooperation was not universal:
            - Defect if stock is > 80% capacity (opportunistic).
            - Cooperate if stock <= 80% capacity (resource preservation).
    - Emergency Rule: Always Cooperate if stock is 0 to avoid wasted defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.C
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        total_c_count_prev = history.opponent_cooperators[-1] + my_prev_coop
        if total_c_count_prev == self.game_description.n_players:
            return Action.C
        threshold = 0.8 * self.game_description.capacity
        if current_stock > threshold:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_11(BaseStrategy):
    """
    A strategy for the Common Pool Resource Game that adjusts cooperativeness based on
    current stock levels and recent group behavior. It utilizes a forgiveness mechanic
    that decays based on group cooperation and resets upon successful punishment.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.forgiveness_level = 0
        self.consecutive_coop_rounds = 0
        self.prev_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if history.round_number > 0:
            my_prev_action = history.my_actions[-1]
            coop_count = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
            defect_count = n - coop_count
            if not my_prev_action and current_stock > self.prev_stock:
                self.forgiveness_level = 0
                self.consecutive_coop_rounds = 0
            if coop_count == n:
                self.consecutive_coop_rounds += 1
                if self.consecutive_coop_rounds >= 3:
                    self.forgiveness_level = min(5, self.forgiveness_level + 1)
                    self.consecutive_coop_rounds = 0
            else:
                self.consecutive_coop_rounds = 0
            self.prev_stock = current_stock
        if t == r:
            return Action.D
        if t == 1:
            return Action.C
        my_prev_action = history.my_actions[-1]
        coop_count_prev = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        d_count_prev = n - coop_count_prev
        if current_stock < 0.2 * capacity:
            return Action.C
        if d_count_prev > n / 2 + self.forgiveness_level:
            return Action.D
        if current_stock > 0.8 * capacity and d_count_prev < n / 2:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_12(BaseStrategy):
    """
    Tit-for-Tat Resource Harvesting: A conditional cooperation strategy that
    manages reputation based on past cooperators, monitors stock health for
    crisis management, and incorporates opportunistic defection in final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_t = history.round_number + 1
        if round_t == 1:
            return Action.C
        if round_t == r:
            return Action.D
        prev_opp_coops = int(history.opponent_cooperators[-1])
        last_action = Action.C if history.my_actions[-1] else Action.D
        k = prev_opp_coops + (1 if last_action == Action.C else 0)
        self.reputation = self.reputation * 0.7 + k / n * 0.3
        if current_stock < capacity / n:
            return Action.D
        if round_t == r - 1:
            if current_stock < capacity / 2:
                return Action.D
        if self.reputation >= 0.6:
            return Action.C
        elif self.reputation < 0.4:
            return Action.D
        else:
            threshold = n / 2
            return Action.C if k >= threshold else Action.D

class Strategy_OPPORTUNISTIC_13(BaseStrategy):
    """
    Tit-for-Tat with Resource-Aware Thresholding:
    Combines reciprocal behavior with stock-dependent thresholds to balance 
    sustainability, exploitation, and recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1
        self.threshold = 0.5
        self.depletion_recovery_timer = 0
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if t == 0:
            self.last_stock = current_stock
            return Action.C
        stock_drop = self.last_stock - current_stock
        if self.last_stock > 0 and stock_drop / self.last_stock > 0.5:
            self.depletion_recovery_timer = 2
        if current_stock < capacity / 2:
            self.threshold = 0.9
        prev_cooperators = history.opponent_cooperators[-1]
        prev_action = history.my_actions[-1]
        ocr = prev_cooperators / self.n_opponents if self.n_opponents > 0 else 1.0
        if t == self.game_description.n_rounds - 1:
            return Action.D
        if self.depletion_recovery_timer > 0:
            self.depletion_recovery_timer -= 1
            self.last_stock = current_stock
            return Action.C
        if current_stock < capacity / (2 * n):
            self.last_stock = current_stock
            return Action.C
        if current_stock > 0.9 * capacity and ocr < 0.5:
            self.last_stock = current_stock
            return Action.D
        decision = Action.C
        if ocr >= self.threshold:
            decision = Action.C
        else:
            decision = Action.D
        if abs(ocr - self.threshold) < 1e-09:
            decision = Action.C if prev_action else Action.D
        if ocr > self.threshold:
            self.threshold = max(0.2, self.threshold - 0.05)
        elif ocr < self.threshold:
            self.threshold = min(0.8, self.threshold + 0.1)
        self.last_stock = current_stock
        return decision

class Strategy_OPPORTUNISTIC_14(BaseStrategy):
    """
    A reactive strategy for the Common Pool Resource Game.
    Starts by cooperating. In subsequent rounds:
    - Defects if it's the last round.
    - Continues to defect if already in 'exploiting' mode.
    - Cooperates if stock is critically low (< capacity / n).
    - Transitions to 'exploiting' mode if any opponent defected in the previous round.
    - Otherwise, cooperates and ensures 'exploiting' mode is off.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_exploiting = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if self.is_exploiting:
            return Action.D
        if current_stock < self.game_description.capacity / self.game_description.n_players:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        prev_cooperators = history.opponent_cooperators[-1]
        k = n_opponents - prev_cooperators
        if k > 0:
            self.is_exploiting = True
            return Action.D
        self.is_exploiting = False
        return Action.C

class Strategy_OPPORTUNISTIC_15(BaseStrategy):
    """
    Conditional Tit-for-Tat with Yield Thresholds.
    
    Strategy Logic:
    1. Terminal Opportunism: Always defect on the final round.
    2. Preservation Mode: If the current stock is below half capacity, switch to 
       Defect (D) to extract remaining value before depletion.
    3. Tit-for-Tat Reciprocity: 
       - Round 1: Always Cooperate (C).
       - Subsequent rounds: If the stock is healthy (>= capacity/2), cooperate 
         only if nearly everyone else (n-1 players) cooperated in the last round.
         Otherwise, Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.total_rounds - 1:
            return Action.D
        if current_stock < self.capacity / 2:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        last_cooperators = history.opponent_cooperators[-1]
        we_cooperated_last = history.my_actions[-1]
        total_cooperators_last = last_cooperators + (1 if we_cooperated_last else 0)
        if total_cooperators_last >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_16(BaseStrategy):
    """
    A state-aware strategy for the Common Pool Resource Game.
    
    It alternates between a Cooperative Phase (rounds 0 to r-3) and a Terminal Phase (rounds r-2 and r-1).
    - In the Cooperative Phase: Prioritizes sustainability if stock > capacity/2, but switches to Defect 
      if the stock is critically low or if the opponent aggregate cooperation rate was low (< 0.5) 
      in the previous round.
    - In the Terminal Phase: Always defects to maximize immediate extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = self.capacity / 2.0
        self.n_opponents = max(1, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round >= self.n_rounds - 2:
            return Action.D
        if current_round > 0:
            coop_count = history.opponent_cooperators[-1]
            coop_rate = coop_count / self.n_opponents
            if coop_rate < 0.5:
                return Action.D
        if current_stock <= self.threshold:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_17(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy that incorporates resource-aware thresholding.
    Prioritizes cooperation when stock is healthy and cooperation is reciprocated,
    but defaults to defection in the end game or when resource collapse is imminent.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if r_total - round_idx <= 2:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < capacity / 2:
            return Action.D
        last_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = last_my_action + history.opponent_cooperators[-1]
        threshold = math.floor(0.75 * n)
        if total_cooperators_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_18(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    Prioritizes resource maintenance (stock >= 0.5 * capacity) while exploiting
    cooperative environments, but switches to survival mode or total defection
    based on the state of the common pool.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)
        self.threshold = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.C
        if current_round >= 2:
            last_two_rounds_cooperation = history.opponent_cooperators[-2:]
            if np.all(last_two_rounds_cooperation == 0):
                return Action.D
        start_idx = max(0, current_round - 3)
        recent_cooperators = history.opponent_cooperators[start_idx:current_round]
        n_cooperators_avg = np.mean(recent_cooperators)
        if current_stock < self.threshold * 0.8:
            return Action.C
        if n_cooperators_avg > self.n / 2:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_19(BaseStrategy):
    """
    A conditional, history-dependent strategy for the Common Pool Resource Game.
    It cooperates when the pool is at risk of depletion or when the population 
    is behaving sustainably. It defects when the pool is robust or when 
    the population is overly aggressive.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_l = 0.25 * game_description.capacity
        self.threshold_h = 0.75 * game_description.capacity
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.threshold_l:
            return Action.C
        if current_stock > self.threshold_h:
            return Action.D

        def calculate_defectors_in_round(r_idx):
            opp_c = history.opponent_cooperators[r_idx]
            my_c = 1 if history.my_actions[r_idx] else 0
            total_c = opp_c + my_c
            return self.n - total_c
        num_history = history.round_number
        lookback = min(num_history, 2)
        recent_defect_counts = [calculate_defectors_in_round(num_history - i - 1) for i in range(lookback)]
        avg_defect = sum(recent_defect_counts) / len(recent_defect_counts)
        if avg_defect < self.n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_20(BaseStrategy):
    """
    Implements a conditional Tit-for-Tat strategy for the Common Pool Resource game.
    - Round 1: Always Cooperates.
    - Ongoing: Adapts cooperation threshold based on previous round's stock and opponent cooperation.
    - Crisis: Switches to Cooperation if stock is critically low.
    - Terminal Phase: Greedily defects in the final two rounds (with an exception for the penultimate round based on stock).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        n_opponents = n - 1
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == total_rounds - 2:
            if current_stock > capacity * 0.5:
                return Action.D
        if current_stock < capacity * 0.1:
            return Action.C
        if current_round_idx == 0:
            return Action.C
        last_round_cooperators = int(history.opponent_cooperators[-1])
        if current_stock >= capacity * 0.75:
            threshold = n_opponents / 2.0
        else:
            threshold = float(n_opponents)
        if last_round_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_21(BaseStrategy):
    """
    Implements Adaptive Threshold Tit-for-Tat (AT-TFT).
    Balances resource sustainability with opportunistic defection based on stock levels
    and historical cooperation rates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.game_description.n_rounds - 1:
            self.last_stock = current_stock
            return Action.D
        if current_stock <= self.capacity / 4:
            self.last_stock = current_stock
            return Action.D
        if current_round == 0:
            self.last_stock = current_stock
            return Action.C
        if self.last_stock > 0 and current_stock / self.last_stock < 0.6:
            self.last_stock = current_stock
            return Action.D
        prev_coops = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_prev_int = 1 if my_prev_action else 0
        total_cooperators = prev_coops + my_prev_int
        cooperation_rate = total_cooperators / self.n
        threshold = 0.4 if current_stock > 0.9 * self.capacity else 0.6
        action = Action.C if cooperation_rate > threshold else Action.D
        self.last_stock = current_stock
        return action

class Strategy_OPPORTUNISTIC_22(BaseStrategy):
    """
    Conditional Reciprocity Strategy:
    Tracks a 'Trust Index' (T) of the population. Cooperates if the resource
    is sustainable and the Trust Index is high. Defects if the resource
    is near collapse, if the last round is reached, or if trust is low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.trust_index = 0.5

    def _update_trust(self, my_last_action: Action, opponents_cooperated_count: int) -> None:
        """
        Updates the Trust Index based on previous round behavior.
        my_action: Action.C or Action.D
        opponents_cooperated_count: integer count of opponents who cooperated.
        """
        my_contribution = 1 if my_last_action == Action.C else 0
        total_cooperators = opponents_cooperated_count + my_contribution
        k_others = total_cooperators - my_contribution
        denominator = self.n - 1
        if denominator == 0:
            cooperation_rate = 0.0
        else:
            cooperation_rate = k_others / denominator
        self.trust_index = 0.7 * self.trust_index + 0.3 * cooperation_rate

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round > 0:
            last_action = Action.C if history.my_actions[-1] else Action.D
            self._update_trust(last_action, history.opponent_cooperators[-1])
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_stock < self.capacity / self.n:
            return Action.D
        s_crit = self.capacity / 2.0
        if self.trust_index >= 0.5 and current_stock >= s_crit:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_23(BaseStrategy):
    """
    A strategy that enforces collective sustainability while stock is high and 
    cooperation is prevalent, switching to defect as the stock depletes, 
    cooperation wanes, or the game reaches its final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = game_description.capacity / 2
        self.majority_threshold = game_description.n_players / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock > self.threshold:
            last_round_idx = history.round_number - 1
            last_opp_coop = int(history.opponent_cooperators[last_round_idx])
            my_last_action = int(history.my_actions[last_round_idx])
            total_cooperators = last_opp_coop + my_last_action
            if total_cooperators >= self.majority_threshold:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_24(BaseStrategy):
    """
    A strategy that maintains a 'Trust Score' based on the collective cooperation of opponents.
    It initiates with cooperation, adjusts based on the history of others, and incorporates
    endgame dynamics (defecting near the end) and depletion safety (cooperating if stock is critical).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_score = 0
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_opp_coop_count = history.opponent_cooperators[-1]
        if prev_opp_coop_count == self.n_opponents:
            self.trust_score += 1
        elif prev_opp_coop_count == 0:
            self.trust_score -= 1
        if self.trust_score < 0:
            self.trust_score = 0
        remaining_rounds = self.game_description.n_rounds - history.round_number
        if remaining_rounds < 3:
            return Action.D
        cooperation_threshold = 2
        if current_stock < self.game_description.capacity / self.game_description.n_players:
            return Action.C
        if current_stock <= 0:
            return Action.C
        if self.trust_score >= cooperation_threshold:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_25(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource Game.
    
    It employs a trigger-based mechanism:
    1. Starts with cooperation (Round 0).
    2. Continues cooperation if the number of cooperating opponents is high (>= n-1).
    3. If opponents deviate, evaluates if the pool can sustain the cooperative equilibrium 
       based on the 25% capacity threshold.
    4. Switches to defection in the final round (n-1) or if specific collapse conditions 
       (rapid depletion or persistent defection) are met.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.consecutive_full_defections = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        n_opponents = self.n - 1
        prev_opp_C = history.opponent_cooperators[-1]
        if prev_opp_C == 0:
            self.consecutive_full_defections += 1
        else:
            self.consecutive_full_defections = 0
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if self.consecutive_full_defections >= 2:
            return Action.D
        if prev_opp_C >= n_opponents - 1 if n_opponents > 0 else True:
            return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_26(BaseStrategy):
    """
    Implements a strategy based on sustainability thresholds, trigger retaliation, 
    and opportunistic exploitation. 
    It tracks game state and adjusts actions based on stock health, history, and round progress.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.epsilon = self.capacity / (2 * self.n)
        self.target_stock = self.capacity / 2 + self.epsilon
        self.system_shock_active = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < self.capacity / self.n:
            self.system_shock_active = True
        if self.system_shock_active:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        prev_round_idx = -1
        prev_n_cooperators = history.opponent_cooperators[prev_round_idx]
        prev_my_action = history.my_actions[prev_round_idx]
        prev_n_defectors = self.n - 1 - prev_n_cooperators
        if not prev_my_action:
            prev_n_defectors += 1
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if history.round_number == 1:
            effective_prev_defectors = 0
        else:
            effective_prev_defectors = prev_n_defectors
        if effective_prev_defectors > self.n / 2:
            return Action.D
        if current_stock >= self.target_stock and effective_prev_defectors <= 1:
            return Action.C
        prev_n_cooperators_all = prev_n_cooperators + (1 if prev_my_action else 0)
        prev_n_defectors_all = self.n - prev_n_cooperators_all
        if prev_n_cooperators_all >= prev_n_defectors_all:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_27(BaseStrategy):
    """
    Implements a responsive, threshold-based Common Pool Resource strategy.
    
    The strategy balances resource sustainability with opportunistic exploitation.
    - Operates on thresholds: prioritizes replenishment when stock is low,
      opportunistic consumption when stock is high (over-saturation),
      and Tit-for-Tat based reciprocity during intermediate phases.
    - Tracks consecutive defection to identify permanent defection cycles.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = game_description.n_players
        self.n_opponents = self.n_players - 1
        self.consecutive_zero_cooperation_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        last_c_obs = history.opponent_cooperators[-1]
        if last_c_obs == 0:
            self.consecutive_zero_cooperation_rounds += 1
        else:
            self.consecutive_zero_cooperation_rounds = 0
        if self.consecutive_zero_cooperation_rounds >= 2:
            return Action.D
        threshold = 0.5 * self.capacity
        critical_threshold = 0.2 * self.capacity
        oversaturation_threshold = 0.8 * self.capacity
        if current_stock < critical_threshold:
            return Action.C
        if current_stock > oversaturation_threshold:
            return Action.D
        if current_stock < threshold:
            return Action.C
        if last_c_obs == self.n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_28(BaseStrategy):
    """
    Implements a Tit-for-Tat foundation with conditional expansion.
    Prioritizes resource stock conservation through explicit triggers:
    1. Conservation Phase: If stock < 0.25 * capacity or < 0.1 * capacity (override), plays C.
    2. Steady State Phase: If full cooperation observed, plays C.
    3. Opportunistic Phase: If high stock and decent cooperation, plays C.
    4. Default: Plays D, unless final round (always D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.recovering_from_collapse = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < 0.1 * capacity:
            self.recovering_from_collapse = True
        if self.recovering_from_collapse:
            if current_stock >= 0.5 * capacity:
                self.recovering_from_collapse = False
            else:
                return Action.C
        if current_stock < 0.25 * capacity:
            return Action.C
        last_action_val = 1 if history.my_actions[-1] else 0
        last_total_cooperators = history.opponent_cooperators[-1] + last_action_val
        cooperation_rate = last_total_cooperators / n
        if cooperation_rate == 1.0:
            return Action.C
        if current_stock >= 0.75 * capacity and cooperation_rate > 0.5:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_29(BaseStrategy):
    """
    Implements a responsive Common Pool Resource strategy.
    
    Strategy Summary:
    1. First round: Always Cooperate (C).
    2. Terminal round: Always Defect (D).
    3. Emergency: If stock < capacity/2, Defect (D).
    4. Performance check: If stock dropped > 20% in the last round, transition to permanent Defection.
    5. Adaptive: Otherwise, cooperate with probability proportional to the observed cooperation rate of the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.s_crit = game_description.capacity / 2.0
        self.permanent_defection = False
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            self.last_stock = current_stock
            return Action.C
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if not self.permanent_defection and self.last_stock > 0:
            drop_percentage = (self.last_stock - current_stock) / self.last_stock
            if drop_percentage > 0.2:
                self.permanent_defection = True
        self.last_stock = current_stock
        if self.permanent_defection:
            return Action.D
        if current_stock < self.s_crit or current_stock < 0.1:
            return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_cooperation_val = 1 if my_prev_action else 0
        total_cooperators = cooperators_last_round + my_cooperation_val
        n = self.game_description.n_players
        if total_cooperators == n:
            return Action.C
        cooperation_probability = total_cooperators / n
        if random.random() < cooperation_probability:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_30(BaseStrategy):
    """
    A strategy that balances sustainability and opportunistic exploitation in a Common Pool Resource game.
    It uses a moving average of recent cooperation to determine whether to cooperate or defect,
    while adjusting for current stock levels to avoid collapse or maximize utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.capacity = self.game_description.capacity
        self.num_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            if current_stock > self.capacity / self.n:
                return Action.D
            else:
                return Action.C
        if current_round == 0:
            return Action.C
        t = current_round
        k = min(t, 3)
        recent_cooperators = history.opponent_cooperators[-k:]
        if self.num_opponents == 0:
            coop_rate = 0.0
        else:
            coop_rate = np.mean(recent_cooperators) / self.num_opponents
        last_round_cooperators = history.opponent_cooperators[-1]
        if current_stock < self.capacity / 2:
            if last_round_cooperators == 0 and current_stock < self.capacity / 4:
                return Action.D
            return Action.C
        if coop_rate < 0.25:
            return Action.D
        threshold_opponents = (self.n - 1) / 2
        if last_round_cooperators > threshold_opponents and current_stock > 0.5 * self.capacity:
            return Action.C
        if last_round_cooperators < threshold_opponents:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_31(BaseStrategy):
    """
    Adaptive Sustainability with Defection Trigger.
    Maintains the common pool at sustainable levels by conditionally cooperating 
    based on previous opponent behavior, while aggressively exploiting in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t_round = history.round_number + 1
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if t_round == 1:
            return Action.C
        if t_round == r:
            return Action.D
        if current_stock < 0.2 * capacity:
            return Action.C
        c_prev = history.opponent_cooperators[-1]
        if c_prev == 0:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_32(BaseStrategy):
    """
    A strategy that maintains cooperation while resources are abundant,
    but defaults to defecting (D) if the stock drops below a critical threshold (capacity/4)
    or if opponents fail to sustain a cooperative equilibrium (where all n-1 opponents cooperate).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == n_rounds - 1:
            return Action.D
        if current_stock < capacity / 4:
            return Action.D
        if current_round == 0:
            return Action.C
        cooperation_threshold = n_players - 1
        observed_cooperators = history.opponent_cooperators[-1]
        if observed_cooperators == cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_5(BaseStrategy):
    """
    Implements a reputation-based strategy with a recovery mechanism for Common Pool Resource games.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation_score = 1.0
        self.permanently_defecting = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r = self.game_description.n_rounds
        t = history.round_number
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if t > 0:
            k = history.opponent_cooperators[-1]
            n_opponents = n - 1
            f = k / n_opponents if n_opponents > 0 else 1.0
            self.reputation_score = 0.2 * f + 0.8 * self.reputation_score
            if current_stock < 0.2 * capacity and k == 0:
                self.permanently_defecting = True
        if t == r - 1:
            return Action.D
        if current_stock == 0:
            return Action.D
        if self.permanently_defecting:
            return Action.D
        if current_stock < 0.2 * capacity:
            return Action.C
        if current_stock < capacity / n:
            return Action.D
        p_c = max(0.0, min(1.0, self.reputation_score))
        if random.random() < p_c:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_6(BaseStrategy):
    """
    Implements a trigger-based, threshold-dependent strategy for the Common Pool Resource Game.
    Prioritizes resource sustainability using critical thresholds while employing conditional
    reciprocity based on previous cooperative actions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D if current_stock > 0 else Action.C
        critical_threshold = capacity / 2 * 0.2
        if current_stock < critical_threshold:
            return Action.C
        if current_round > 0:
            opp_coop = history.opponent_cooperators[-1]
            my_prev_action = history.my_actions[-1]
            k_prev = opp_coop + (1 if my_prev_action else 0)
            if k_prev >= n - 1:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_7(BaseStrategy):
    """
    Implements a conditional cooperation strategy (Tit-for-Tat variant) 
    incorporating a sustainability threshold to adjust behavior based on 
    pool health and opponent history.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            if current_stock > self.capacity / self.n:
                return Action.D
            else:
                return Action.C
        if current_stock < self.capacity / 2.0:
            return Action.C
        n_opponents = self.n - 1
        phi = history.opponent_cooperators[-1] / n_opponents
        if phi >= 0.75:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_8(BaseStrategy):
    """
    Implements a resource-preservation strategy (the "Golden Equilibrium").
    
    The strategy prioritizes long-term resource maintenance to maximize yield 
    over multiple rounds, but proactively switches to extraction (Defect) 
    if the environment becomes unsustainable (high defection or low stock) 
    or when the game concludes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.r:
            return Action.D
        if history.round_number > 0:
            num_opponents = self.n - 1
            num_coop_opponents = history.opponent_cooperators[-1]
            num_defect_opponents = num_opponents - num_coop_opponents
            my_prev_action = history.my_actions[-1]
            num_defect_me = 0 if my_prev_action else 1
            total_defectors = num_defect_opponents + num_defect_me
            if total_defectors > self.n / 2:
                return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_9(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Threshold (TFTS).
    Prioritizes resource longevity via sustainability checks while using 
    a Tit-for-Tat mechanism to punish mass defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_max = self.game_description.n_rounds
        cap = self.game_description.capacity
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == r_max - 1:
            if current_stock > cap / n:
                return Action.D
            else:
                return Action.C
        if current_stock < cap / 4:
            return Action.D
        if current_stock >= 0.9 * cap:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_coop
        if total_cooperators_prev >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_10(BaseStrategy):
    """
    Adaptive strategy for Common Pool Resource Game:
    - Maintains a 'trust_score' based on history.
    - Switches to 'Grim Trigger' if trust is too low.
    - Uses threshold-based cooperation, with dynamic adjustments based on stock levels.
    - Maximizes gain when stock is critically low or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.trust_score = 0.5
        self.grim_trigger_active = False
        self.target_sustain_stock = self.capacity / 2.0
        self.cooperation_threshold_base = math.ceil(self.n * 0.75)
        self.low_stock_critical_threshold = self.capacity / (2.0 * self.n)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        i_cooperated = int(history.my_actions[-1])
        count_cooperators = history.opponent_cooperators[-1] + i_cooperated
        self.trust_score = self.trust_score * 0.7 + count_cooperators / self.n * 0.3
        if self.trust_score < 0.25:
            self.grim_trigger_active = True
        if self.grim_trigger_active:
            return Action.D
        if current_stock < self.low_stock_critical_threshold:
            return Action.D
        if current_stock >= 0.9 * self.capacity:
            threshold = math.ceil(self.n * 0.9)
        else:
            threshold = self.cooperation_threshold_base
        if current_stock < self.target_sustain_stock * 0.5:
            return Action.D
        if count_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_11(BaseStrategy):
    """
    Tit-for-Tat Sustainability (TFTS):
    A conditional sustainability strategy that prioritizes maintaining the stock at 
    capacity/2. It cooperates if the resource base is stable/growing, defects if
    it's declining, and always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_my_action = bool(history.my_actions[-1])
        prev_opp_coop_count = history.opponent_cooperators[-1]
        total_cooperators = prev_opp_coop_count + (1 if prev_my_action else 0)
        total_defectors = self.n - total_cooperators
        target_stock = self.capacity / 2
        s_remaining = current_stock
        growth = 2 * s_remaining * (1 - s_remaining / self.capacity)
        projected_stock = min(float(self.capacity), s_remaining + growth)
        if s_remaining < self.capacity / 4:
            return Action.D
        if projected_stock > target_stock:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_12(BaseStrategy):
    """
    Tit-for-tat with depletion adjustment: 
    - Round 1: Cooperate.
    - Final Round: Defect.
    - Low Stock (< 10% capacity): Defect.
    - Safety threshold check (> 50% capacity) and Opponent cooperation check (>= 75%): Cooperate.
    - Otherwise: Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock < 0.1 * capacity:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        is_stock_safe = current_stock > 0.5 * capacity
        prev_opponents_cooperated = history.opponent_cooperators[-1]
        if self.n_opponents > 0:
            opponents_cooperation_rate = prev_opponents_cooperated / self.n_opponents
        else:
            opponents_cooperation_rate = 1.0
        if is_stock_safe and opponents_cooperation_rate >= 0.75:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_13(BaseStrategy):
    """
    Implements the Adaptive Threshold Strategy.
    This strategy maintains a cooperation threshold (tau) that adjusts dynamically
    based on resource fluctuation, balancing sustainability with punishment of defectors.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.tau = 0.5
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if current_stock < self.last_stock:
            self.tau = min(0.9, self.tau + 0.1)
        elif current_stock > self.last_stock:
            self.tau = max(0.3, self.tau - 0.05)
        self.last_stock = current_stock
        if round_idx == self.r - 1:
            if current_stock > self.capacity / 2:
                return Action.D
        if current_stock < self.capacity / 4:
            return Action.D
        k = history.opponent_cooperators[-1]
        CR = k / (self.n - 1)
        if CR >= self.tau:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_14(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Threshold strategy.
    
    Cooperates in the first round. In subsequent rounds, it adapts based on the
    previous round's defection count and the current stock's resilience (sustainability index).
    - If the resource is healthy (SI > 0.5), it absorbs minor defections to maintain long-term stability.
    - If the resource is compromised (SI <= 0.5), it switches to selfish extraction (Defect).
    - In the terminal round, it maximizes extraction if the stock is low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == self.total_rounds - 1:
            if current_stock < self.capacity / 2:
                return Action.D
            else:
                return Action.C
        previous_cooperators = history.opponent_cooperators[-1]
        previous_defectors = self.n_players - 1 - previous_cooperators
        if previous_defectors == 0:
            return Action.C
        else:
            if self.capacity == 0:
                return Action.D
            sustainability_index = current_stock / self.capacity
            if sustainability_index > 0.5:
                return Action.C
            else:
                return Action.D

class Strategy_INDIVIDUALISTIC_15(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    Logic:
    1. Round 1: Cooperate (C).
    2. Rounds 2 to r-1: 
       - If all opponents cooperated in the previous round, Cooperate (C).
       - If at least one opponent defected:
         - If stock < 50% capacity, Defect (D) to extract before collapse.
         - If stock >= 50% capacity, Cooperate (C) but track persistent defection. 
           If defection persists for two consecutive rounds, switch to Defect (D) permanently.
    3. Terminal Round r: Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.persistent_defection_mode = False
        self.consecutive_defection_count = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.game_description.n_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        if self.persistent_defection_mode:
            return Action.D
        prev_idx = -1
        n_opponents = self.game_description.n_players - 1
        obs_coop = history.opponent_cooperators[prev_idx]
        if obs_coop == n_opponents:
            self.consecutive_defection_count = 0
            return Action.C
        else:
            self.consecutive_defection_count += 1
            if self.consecutive_defection_count >= 2:
                self.persistent_defection_mode = True
                return Action.D
            threshold = 0.5 * self.game_description.capacity
            if current_stock < threshold:
                return Action.D
            else:
                return Action.C

class Strategy_INDIVIDUALISTIC_16(BaseStrategy):
    """
    A Tit-for-Tat based strategy with threshold adjustment for Common Pool Resource games.
    
    This strategy aims to maximize cumulative payoff by maintaining resource stock near capacity.
    It cooperates (C) if a sufficient proportion of opponents cooperated in the previous round,
    defects (D) if they failed to meet the cooperation threshold (T=0.5), and prioritizes 
    self-preservation when the stock is critically low. It strictly defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = 0.5
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        critical_stock = self.game_description.capacity / (2 * self.game_description.n_players)
        if current_stock < critical_stock - 1e-09:
            return Action.D
        last_round_idx = history.round_number - 1
        last_c_obs = history.opponent_cooperators[last_round_idx]
        if self.n_opponents > 0:
            coop_rate = last_c_obs / self.n_opponents
        else:
            coop_rate = 1.0
        if coop_rate >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_17(BaseStrategy):
    """
    A conditionally cooperative strategy that aims to maximize long-term stock levels.
    It cooperates in the first round and when universal cooperation is achieved.
    It punishes non-cooperative behavior unless the stock is critical, 
    in which case it extracts remaining value. It always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.capacity / self.n:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        total_cooperators = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if total_cooperators == self.n:
            return Action.C
        elif current_stock >= 0.5 * self.capacity:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_18(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy using Dynamic Tit-for-Tat 
    and Capacity Thresholding. Balances immediate consumption with long-term 
    stock maintenance.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < 0.1 * capacity:
            return Action.D
        prev_idx = current_round - 1
        my_prev_action = history.my_actions[prev_idx]
        opp_prev_coop_count = history.opponent_cooperators[prev_idx]
        my_prev_coop_val = 1 if my_prev_action else 0
        total_cooperators = opp_prev_coop_count + my_prev_coop_val
        num_defectors = n - total_cooperators
        if num_defectors > n / 2:
            return Action.D
        if not my_prev_action and current_stock > 0.8 * capacity:
            return Action.C
        return Action.C

class Strategy_INDIVIDUALISTIC_19(BaseStrategy):
    """
    Adaptive Sustainable Tit-for-Tat (ASTFT):
    A strategy that balances cooperation and defection based on stock levels, 
    trust in opponents, and game progression. It prioritizes system health 
    when stock is low and uses a trust-score mechanism to determine 
    cooperation when stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.target_stock = 0.5 * self.game_description.capacity
        self.trust_score = 0.5
        self.n_opponents = self.game_description.n_players - 1
        self.last_stock = float(self.game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.last_stock = current_stock
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.target_stock:
            self.last_stock = current_stock
            return Action.C
        prev_idx = history.round_number - 1
        opp_c_count = int(history.opponent_cooperators[prev_idx])
        opp_d_count = self.n_opponents - opp_c_count
        my_prev_action = history.my_actions[prev_idx]
        my_c_count = 1 if my_prev_action else 0
        my_d_count = 0 if my_prev_action else 1
        total_c = opp_c_count + my_c_count
        total_d = opp_d_count + my_d_count
        n = self.game_description.n_players
        cons_c = total_c * (self.last_stock / (2 * n))
        cons_d = total_d * (self.last_stock / n)
        previous_consumption = cons_c + cons_d
        if previous_consumption >= self.game_description.capacity / 2.0:
            self.trust_score = max(0.0, self.trust_score - 0.2)
            self.last_stock = current_stock
            return Action.D
        if opp_c_count > opp_d_count:
            self.trust_score = min(1.0, self.trust_score + 0.1)
        else:
            self.trust_score = max(0.0, self.trust_score - 0.1)
        self.last_stock = current_stock
        if self.trust_score > 0.4:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_20(BaseStrategy):
    """
    State-Aware Trigger Tit-for-Tat (SATT).
    
    A strategy that balances long-term resource sustainability with opportunistic 
    exploitation. It cooperates to maintain stock levels above capacity/2, 
    but defects if:
    1. The stock level is critically low (below capacity/2).
    2. Opponents demonstrate defecting behavior (based on a majority threshold).
    3. The game reaches the terminal round (greed).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if current_stock < self.capacity / 2.0:
            return Action.D
        if history.round_number > 0:
            n_opponents = self.n - 1
            num_cooperators_last_round = history.opponent_cooperators[-1]
            num_defectors_last_round = n_opponents - num_cooperators_last_round
            if n_opponents > 0:
                defector_index = num_defectors_last_round / n_opponents
                if defector_index > 0.5:
                    return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_21(BaseStrategy):
    """
    Implements the 'Tit-for-Tat Stock Sustainer' strategy.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Terminal Round: Always Defect (D).
    - Sustainability Threshold: If current stock S < capacity / n_players, Defect (D).
    - Monitoring: If stock is healthy, Cooperate (C) if all opponents cooperated in the 
      previous round, otherwise Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round_idx == total_rounds - 1:
            return Action.D
        critical_threshold = self.game_description.capacity / self.game_description.n_players
        if current_stock < critical_threshold:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        opponents_cooperated = history.opponent_cooperators[-1]
        if opponents_cooperated == n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_22(BaseStrategy):
    """
    Implements a conditional Tit-for-Tat strategy with a sustainability override.
    
    Strategy Logic:
    1. First round: Always Cooperate (C).
    2. Terminal phase: Always Defect (D) on the last round.
    3. Sustainability: If current_stock < 40% of capacity, Defect (D).
    4. Tit-for-Tat: If at least half the players cooperated in the previous round, 
       Cooperate (C). Otherwise, Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold_stock = self.capacity * 0.4

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number + 1
        if round_number == self.n_rounds:
            return Action.D
        if current_stock < self.threshold_stock:
            return Action.D
        if round_number == 1:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        total_cooperators = history.opponent_cooperators[-1] + my_prev_coop
        if total_cooperators >= self.n_players / 2:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_23(BaseStrategy):
    """
    A sustainable, belief-based strategy for the Common Pool Resource game.
    Maintains a cooperative outlook until critical stock thresholds or defection-dominated 
    trends suggest otherwise. Uses a moving average of opponent cooperation to inform 
    future resource projections and determine current actions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.target_stock = self.capacity / 2.0
        self.b = 1.0
        self.alpha = 0.2
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if history.round_number == 0:
            return Action.C
        k_opp = history.opponent_cooperators[-1]
        if self.n_opponents > 0:
            coop_rate = k_opp / self.n_opponents
            self.b = self.b * (1 - self.alpha) + coop_rate * self.alpha
        else:
            self.b = 1.0
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        c_count_assume_c = self.b * self.n_opponents + 1
        d_count_assume_c = (1 - self.b) * self.n_opponents
        e_cons_c = current_stock / (2 * self.n) * c_count_assume_c + current_stock / self.n * d_count_assume_c
        s_rem = max(0.0, current_stock - e_cons_c)
        s_next = min(self.capacity, s_rem + 2 * s_rem * (1 - s_rem / self.capacity))
        if s_next < self.capacity / 4.0:
            return Action.D
        if s_next >= self.target_stock:
            return Action.C
        if self.b > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_24(BaseStrategy):
    """
    Implements a 'Sustainable Reciprocity' strategy.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Terminal Round: Always Defect (D).
    - Critical State (S < 25% of Capacity): Always Defect (D).
    - Otherwise: Tit-for-Tat style; Cooperate only if all n-1 opponents 
      cooperated in the previous round, otherwise Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity * 0.25:
            return Action.D
        prev_opponents_cooperated = history.opponent_cooperators[-1]
        if prev_opponents_cooperated >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_25(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy for the Common Pool Resource Game.
    
    This strategy monitors the resource stock level and the cooperation history of 
    opponents to decide between Cooperation (C) and Defection (D). It aims to 
    maximize long-term returns by cooperating when the stock is sufficient and 
    peer cooperation is high, while aggressively defecting when the stock is 
    low or the game is nearing its end.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if round_idx == 1:
            return Action.C
        if round_idx == total_rounds:
            return Action.D
        if round_idx > total_rounds - 3:
            if round_idx == total_rounds - 1:
                return Action.D
            if round_idx == total_rounds - 2:
                if current_stock < 0.75 * capacity:
                    return Action.D
                else:
                    pass
        if current_stock <= 0:
            return Action.D
        threshold = capacity / 2
        required_cooperation = math.ceil(self.n_opponents * 0.75)
        opponents_cooperated_last_round = history.opponent_cooperators[-1]
        if current_stock >= threshold:
            if opponents_cooperated_last_round >= required_cooperation:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_26(BaseStrategy):
    """
    Implements a reciprocal sustainability strategy:
    - Round 1: Always Cooperate.
    - Last Round: Always Defect (Terminal override).
    - Resource Criticality: Force Cooperate if stock is critically low.
    - Adaptive Response: Estimate opponent defection based on stock changes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def _calculate_next_stock(self, current_stock: float, n_cooperators: int) -> float:
        """
        Helper to predict the stock at the end of the round based on coop count.
        n_cooperators is the number of players playing C (1 to n).
        """
        n_defectors = self.n - n_cooperators
        cons_c = current_stock / (2.0 * self.n)
        cons_d = current_stock / self.n
        total_consumption = n_cooperators * cons_c + n_defectors * cons_d
        remaining = current_stock - total_consumption
        if remaining < 0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity)
        return min(remaining + growth, self.capacity)

    def _estimate_defectors(self, previous_stock: float, observed_stock: float) -> int:
        """
        Iterates through possible number of cooperators to find the one
        that best explains the observed_stock transition.
        """
        best_k = 0
        min_diff = float('inf')
        for k in range(self.n + 1):
            predicted = self._calculate_next_stock(previous_stock, k)
            diff = abs(predicted - observed_stock)
            if diff < min_diff:
                min_diff = diff
                best_k = k
        return self.n - best_k

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.capacity / self.n:
            return Action.C
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        last_n_coop = history.opponent_cooperators[last_round_idx] + (1 if history.my_actions[last_round_idx] else 0)
        expected_if_all_cooperate = self._calculate_next_stock(current_stock, self.n)
        if current_stock < expected_if_all_cooperate:
            k = self._estimate_defectors(self.capacity, current_stock)
            if k > self.n / 2:
                return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_27(BaseStrategy):
    """
    Implements the Tit-for-Tat Sustainability Strategy.
    Prioritizes resource preservation when stock is critically low, attempts to sustain 
    equilibrium via growth checks, and uses reciprocity (CR > 0.5) to cooperate 
    when stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock < 0.5 * self.capacity:
                return Action.C
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + my_prev_action
        cooperation_ratio = total_cooperators / self.n
        if cooperation_ratio > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_28(BaseStrategy):
    """
    Implements a resource-conscious adaptive strategy based on stock levels, 
    reputation tracking, and defector monitoring.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.reputation = 0.0
        self.coop_threshold = (self.n - 2) / (2 * self.n - 2) if 2 * self.n - 2 != 0 else 0.0
        self.defector_majority_trigger = False
        self.reset_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if n_opponents > 0:
            self.reputation += k_prev / n_opponents - self.coop_threshold
        if current_stock < 1.0:
            return Action.D
        if current_stock > 0.75 * self.capacity:
            self.defector_majority_trigger = False
        if k_prev <= 1:
            self.defector_majority_trigger = True
        if self.defector_majority_trigger:
            return Action.D
        if self.reputation < -2.0:
            self.reputation = 0.0
            self.reset_mode = True
            return Action.C
        if self.reset_mode:
            self.reset_mode = False
            if k_prev <= 1:
                return Action.D
            return Action.C
        if current_stock < self.capacity / 4:
            return Action.C
        if self.reputation >= 0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_29(BaseStrategy):
    """
    Implements a tit-for-tat sustainability-constrained strategy.
    
    Logic:
    1. Phase 1 (Round 0): Always Cooperate (C).
    2. Phase 2 (Rounds 1 to n_rounds - 2): 
       - Sustainability Check: If current_stock <= 10% of capacity, Defect (D).
       - Conditional Reciprocation: If everyone else cooperated (count of cooperators >= n-1), Cooperate (C). Otherwise, Defect (D).
    3. Phase 3 (Last Round): Always Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= 0.1 * self.game_description.capacity:
            return Action.D
        num_others = self.game_description.n_players - 1
        if history.opponent_cooperators[-1] >= num_others:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_30(BaseStrategy):
    """
    A strategy that maintains a 'trust_score' based on the population's cooperation rate.
    
    Logic:
    - Round 0 (First round): Plays C.
    - Final round: Plays D.
    - Intermediate rounds:
        - Calculates trust_score using an EWMA: 0.9 * prev_trust + 0.1 * cooperation_rate.
        - Defects (D) if stock < capacity / n.
        - Otherwise, Cooperates (C) if trust_score >= 0.7, else Defects (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_score = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if round_idx == r - 1:
            return Action.D
        if current_stock < capacity / n:
            return Action.D
        if round_idx == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        k = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        cooperation_rate = k / n
        self.trust_score = self.trust_score * 0.9 + cooperation_rate * 0.1
        if self.trust_score >= 0.7:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_31(BaseStrategy):
    """
    Implements a reputation-based resource management strategy. 
    Maintains a rolling average of opponent cooperation, switching between 
    cooperative preservation when the pool is healthy and reputation is high, 
    and aggressive extraction when the pool is at risk or opponents are uncooperative.
    Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            self.reputation = 0.0
            return Action.C
        n_opponents = self.game_description.n_players - 1
        if n_opponents > 0:
            obs_rate = history.opponent_cooperators[-1] / n_opponents
            self.reputation = 0.7 * self.reputation + 0.3 * obs_rate
        else:
            return Action.C
        if current_stock / self.game_description.capacity < 0.25:
            return Action.D
        if self.reputation > 0.6:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_32(BaseStrategy):
    """
    Implements a 'Tit-for-Tat with Sustainability Threshold' strategy.
    
    Logic:
    - Round 1: Cooperate (Action.C).
    - Round r (Final): Defect (Action.D).
    - Rounds 2 to r-1:
        - Check sustainability (New Stock / Old Stock >= 0.95).
        - Check opponent cooperation rate (Opponents_C / n-1).
        - If current stock < 0.2 * capacity, defect.
        - If sustainable AND cooperation rate > 0.5, cooperate.
        - Otherwise, defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.stock_history = [float(game_description.capacity)]

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round_idx == 0:
            self.stock_history = [current_stock]
            return Action.C
        if current_round_idx == total_rounds - 1:
            return Action.D
        prev_round_idx = current_round_idx - 1
        s_prev = self.stock_history[-1]
        s_curr = current_stock
        is_sustainable = s_curr >= s_prev * 0.95
        opponents_c = history.opponent_cooperators[-1]
        n_opponents = n - 1
        cooperation_rate = opponents_c / n_opponents if n_opponents > 0 else 0.0
        decision = Action.D
        if current_stock < 0.2 * capacity:
            decision = Action.D
        elif is_sustainable and cooperation_rate > 0.5:
            decision = Action.C
        else:
            decision = Action.D
        self.stock_history.append(current_stock)
        return decision

class Strategy_COLLECTIVE_33(BaseStrategy):
    """
    A conditional cooperative strategy that maintains the common pool resource
    by cooperating when the stock is sustainable and the majority of opponents 
    are cooperating, while switching to defection if the stock becomes critical 
    or if widespread defection occurs.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == self.n_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.C
        if current_stock < 0.2 * self.capacity:
            return Action.D
        my_last_action = history.my_actions[-1]
        k = (1 if my_last_action else 0) + history.opponent_cooperators[-1]
        if k >= self.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_34(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy based on resource sustainability.
    
    The strategy maintains the pool by calculating the Maintenance Consumption Level (MCL).
    It cooperates if the previous round's consumption was within the sustainable limit,
    defects if the limit was exceeded or in the last round, and handles collapse scenarios.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.epsilon = 0.001

    def _calculate_mcl(self, s_prev: float) -> float:
        """
        Solves for X in the sustainability equation:
        2 * (S_prev - X) * (1 - (S_prev - X) / capacity) = X
        
        Let u = S_prev - X (remaining stock)
        Equation: 2 * u * (1 - u / C) = S_prev - u
        2u - (2 * u^2 / C) = S_prev - u
        3u - (2 * u^2 / C) - S_prev = 0
        -(2/C) * u^2 + 3 * u - S_prev = 0
        
        Using quadratic formula for au^2 + bu + c = 0:
        a = -2/C, b = 3, c = -S_prev
        u = (-b + sqrt(b^2 - 4ac)) / 2a  (taking the root that allows growth)
        
        MCL = S_prev - u
        """
        if s_prev <= 0:
            return 0.0
        c = self.capacity
        a_quad = -2.0 / c
        b_quad = 3.0
        c_quad = -s_prev
        discriminant = b_quad ** 2 - 4 * a_quad * c_quad
        if discriminant < 0:
            return 0.0
        u = (-b_quad + math.sqrt(discriminant)) / (2 * a_quad)
        mcl = s_prev - u
        return max(0.0, min(mcl, s_prev))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.epsilon:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        my_prev_consumption_share = 1.0 / (2.0 * self.n) if my_prev_action == Action.C else 1.0 / self.n
        n_opponents = self.n - 1
        n_opponents_c = history.opponent_cooperators[-1]
        n_opponents_d = n_opponents - n_opponents_c
        total_consumption_share = my_prev_consumption_share + n_opponents_c * (1.0 / (2.0 * self.n)) + n_opponents_d * (1.0 / self.n)
        denom = 1.0 - total_consumption_share
        if denom <= 0:
            s_prev = current_stock
        else:
            s_prev = current_stock / denom
        prev_total_consumption = s_prev * total_consumption_share
        if s_prev <= 0:
            return Action.D
        mcl = self._calculate_mcl(s_prev)
        if prev_total_consumption > mcl:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_35(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource Game.
    Maintains cooperation while the stock is sustainable and opponent behavior 
    is cooperative. Transitions to permanent defection (punitive state) if the 
    stock falls below a critical threshold during uncooperative periods or if 
    the stock depletes by more than 50% in a single round. Always defects in 
    the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold_stock = 0.25 * self.capacity
        self.defect_trigger = False
        self.prev_stock = float(self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            self.prev_stock = current_stock
            return Action.C
        if current_round > 0 and self.prev_stock > 0:
            depletion_ratio = (self.prev_stock - current_stock) / self.prev_stock
            if depletion_ratio > 0.5:
                self.defect_trigger = True
        self.prev_stock = current_stock
        if self.defect_trigger:
            return Action.D
        last_round_opponents_cooperating = history.opponent_cooperators[-1]
        if current_stock < self.threshold_stock and last_round_opponents_cooperating < self.n / 2:
            self.defect_trigger = True
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_36(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness strategy for the Common Pool Resource Game.
    
    Strategy Logic:
    1. Phase 1: Always Cooperate (C) in round 0.
    2. Phase 2: Monitor previous round cooperation (C_prev). 
       - If C_prev >= threshold (n/2), Cooperate. 
       - If C_prev < threshold (n/2), Defect.
       - Threshold logic: ceil(n/2) for odd n.
    3. Phase 3: Forgiveness. If in 'punishment mode' (last action was D),
       check if stock recovers (S >= 0.5 * capacity) and others start cooperating 
       (C_prev increase), then revert to C.
    4. Phase 4: Final round always Defect (D).
    5. Edge Cases: 
       - If S < (capacity / (n^2)), Defect.
       - Opponent Oscillations: If logic dictates D, check if rolling 3-round 
         avg of C_prev >= threshold; if so, maintain C.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.threshold = math.ceil(self.desc.n_players / 2)
        self.punishment_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < self.desc.capacity / self.desc.n_players ** 2:
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        opp_cooperators = history.opponent_cooperators[-1]
        c_prev = opp_cooperators + (1 if my_last_action else 0)
        target_action = Action.C
        if history.round_number >= 3:
            recent_opps = history.opponent_cooperators[-3:]
            my_prev_actions = history.my_actions[-3:]
            rolling_avg = np.mean([recent_opps[i] + (1 if my_prev_actions[i] else 0) for i in range(3)])
            if rolling_avg >= self.desc.n_players / 2:
                target_action = Action.C
            elif c_prev < self.threshold:
                target_action = Action.D
            else:
                target_action = Action.C
        elif c_prev >= self.threshold:
            target_action = Action.C
        else:
            target_action = Action.D
        if not my_last_action:
            self.punishment_mode = True
        if self.punishment_mode:
            if history.round_number >= 2:
                prev_c_prev = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
                if current_stock >= 0.5 * self.desc.capacity and c_prev > prev_c_prev:
                    self.punishment_mode = False
                    return Action.C
            return target_action
        return target_action

class Strategy_COLLECTIVE_37(BaseStrategy):
    """
    A modified Tit-for-Tat strategy for the Common Pool Resource Game.
    1. Always cooperates in the first round.
    2. Always defects in the last round to maximize terminal utility.
    3. Defects if the stock drops below (capacity / n) to secure remaining resources.
    4. Evaluates previous round's cooperation levels: if the number of cooperating opponents
       is less than (n - 1), it defects in the current round to punish/prevent exploitation,
       returning to cooperation thereafter.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.in_punishment_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < capacity / n:
            return Action.D
        if current_stock <= 0:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators < n - 1:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_38(BaseStrategy):
    """
    Implements a Tit-for-Tat with Forgiveness strategy for the Common Pool Resource Game.
    It manages a dynamic cooperation threshold based on stock health and opponent behavior,
    with specific overrides for rapid depletion, systemic defection, and final round utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.n_opponents = self.desc.n_players - 1
        self.threshold = 0.9
        self.systemic_defection_counter = 0
        self.in_systemic_defection_mode = False
        self.is_recovering = False
        self.last_stock = float(self.desc.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            self.last_stock = current_stock
            return Action.C
        n_c_prev = history.opponent_cooperators[-1]
        if self.n_opponents > 0:
            f_obs = n_c_prev / self.n_opponents
        else:
            f_obs = 1.0
        if f_obs < 0.5:
            self.systemic_defection_counter += 1
        else:
            self.systemic_defection_counter = 0
            self.in_systemic_defection_mode = False
        if self.systemic_defection_counter >= 3:
            self.in_systemic_defection_mode = True
        if current_round == self.desc.n_rounds - 1:
            total_payoff = np.sum(history.my_payoffs)
            avg_potential = self.desc.capacity / (2 * self.desc.n_players)
            if total_payoff < self.desc.n_rounds * avg_potential / 2:
                return Action.D
            return Action.C
        if self.in_systemic_defection_mode:
            if current_round % 5 == 0:
                self.is_recovering = True
                return Action.C
            else:
                return Action.D
        if self.is_recovering:
            if current_stock > self.last_stock:
                self.in_systemic_defection_mode = False
                self.systemic_defection_counter = 0
            self.is_recovering = False
        if current_stock < self.last_stock * 0.7:
            self.last_stock = current_stock
            return Action.D
        if current_stock < 0.5 * self.desc.capacity:
            self.threshold = 1.0
        elif current_stock > 0.8 * self.desc.capacity:
            self.threshold = max(0.5, self.threshold - 0.05)
        self.last_stock = current_stock
        if f_obs >= self.threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_39(BaseStrategy):
    """
    Adaptive Threshold Tit-for-Tat:
    Maintains cooperative behavior if the group's cooperation rate is sustainable (>= 0.5),
    defects if the stock is near collapse (< capacity/4), or if the group is non-cooperative.
    Includes a 'recovery phase' mechanism to test for sustainable re-entry if previously defecting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_defecting_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        total_cooperators = prev_opp_coop + (1 if prev_my_action else 0)
        alpha = total_cooperators / self.game_description.n_players
        if current_stock < self.game_description.capacity / 4.0:
            self.is_defecting_mode = True
            return Action.D
        if self.is_defecting_mode:
            if current_stock > self.game_description.capacity / 2.0:
                self.is_defecting_mode = False
                return Action.C
            else:
                return Action.D
        if alpha >= 0.5:
            return Action.C
        else:
            self.is_defecting_mode = True
            return Action.D

class Strategy_COLLECTIVE_40(BaseStrategy):
    """
    Implements a Sustainable Tit-for-Tat strategy for the Common Pool Resource Game.
    Focuses on maintaining stock near capacity/2 to maximize logistic growth while 
    using collective action thresholds to determine cooperation or defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.capacity = self.game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.r - 1:
            return Action.D
        if current_stock < self.capacity / 4:
            return Action.C
        if current_round_idx == 0:
            return Action.C
        if current_stock >= 0.9 * self.capacity:
            return Action.C
        else:
            last_my_action = history.my_actions[-1]
            last_opp_coop = history.opponent_cooperators[-1]
            total_cooperators = last_opp_coop + (1 if last_my_action == Action.C.value else 0)
            n_defectors = self.n - total_cooperators
            if total_cooperators >= n_defectors:
                return Action.C
            else:
                return Action.D

class Strategy_COLLECTIVE_41(BaseStrategy):
    """
    A Tit-for-Tat variant strategy. It maintains a 'trust_score' based on
    the average cooperation of opponents using an exponential moving average.
    It cooperates if the trust score is high (>= 0.6) and the stock is healthy,
    defects if the trust score is low (< 0.6) or if the stock is critically low.
    It forces defection on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_score = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.trust_score = 1.0
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        my_last_action = int(history.my_actions[-1])
        total_cooperators = history.opponent_cooperators[-1] + my_last_action
        c_prev = total_cooperators / self.game_description.n_players
        self.trust_score = 0.7 * self.trust_score + 0.3 * c_prev
        if current_stock <= 0:
            return Action.D
        if current_stock < 0.2 * self.game_description.capacity:
            return Action.D
        if current_stock < 0.5 * self.game_description.capacity:
            if 0.4 <= self.trust_score < 0.6:
                return Action.D
        if self.trust_score >= 0.6:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_42(BaseStrategy):
    """
    Implements the 'Conditional Sustainability' strategy.
    
    Logic:
    1. Last round: Defect to exhaust resources.
    2. Stock Safety Override: If stock < capacity / n, defect to secure immediate payoff.
    3. Initial Round: Cooperate to build initial pool.
    4. General Rounds: Cooperate if 80% or more of other players cooperated last round, otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.game_description.capacity / self.game_description.n_players:
            return Action.D
        last_round_idx = -1
        opponents_cooperating = history.opponent_cooperators[last_round_idx]
        my_previous_action = history.my_actions[last_round_idx]
        total_cooperators = opponents_cooperating + (1 if my_previous_action == Action.C else 0)
        threshold = math.ceil(0.8 * self.game_description.n_players)
        if total_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_43(BaseStrategy):
    """
    Conditional Sustainer strategy: Maintains common pool capacity and reacts to aggregate defection.
    Prioritizes sustainability, re-cooperation, and reclaims potential loss during recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.recovery_countdown = 0

    def _calculate_next_stock(self, s: float) -> float:
        n = self.game_description.n_players
        cap = self.game_description.capacity
        if s <= 0:
            return 0.0
        s_rem = s / 2.0
        growth = 2.0 * s_rem * (1.0 - s_rem / cap)
        return min(s_rem + growth, float(cap))

    def _calculate_prev_stock(self, current_stock: float) -> float:
        cap = self.game_description.capacity
        if current_stock >= cap:
            return float(cap)
        a = 2.0 / cap
        b = -3.0
        c = current_stock
        discriminant = b ** 2 - 4 * a * c
        if discriminant < 0:
            return 0.0
        root1 = (-b + math.sqrt(discriminant)) / (2 * a)
        root2 = (-b - math.sqrt(discriminant)) / (2 * a)
        s_rem = min(root1, root2) if root1 > 0 and root2 > 0 else max(root1, root2)
        return s_rem * 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if current_stock < 0.1 * capacity:
            self.recovery_countdown = 2
            return Action.C
        if self.recovery_countdown > 0:
            self.recovery_countdown -= 1
            return Action.C
        if round_num == self.game_description.n_rounds - 1:
            return Action.C if current_stock >= 0.8 * capacity else Action.D
        prev_stock = self._calculate_prev_stock(current_stock)
        expected_stock = self._calculate_next_stock(prev_stock)
        is_stock_depleted = current_stock < 0.95 * expected_stock if expected_stock > 0 else False
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators = my_prev_action + history.opponent_cooperators[-1]
        is_group_hostile = total_cooperators < n / 2.0
        if n == 2:
            if history.opponent_cooperators[-1] < 1:
                return Action.D
            return Action.C
        if is_stock_depleted or is_group_hostile:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_44(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Sustainability Threshold.
    
    A strategy that focuses on long-term sustainability by conditionally cooperating based on
    aggregate group behavior and stock levels. It prioritizes the common pool health but
    resorts to defection if the stock becomes critically low (desperation) or if 
    cooperation levels drop too low to sustain the resource.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.total_rounds
        if round_idx == total_rounds - 1:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if round_idx == 0:
            return Action.C
        i_cooperated_last = bool(history.my_actions[-1])
        k = history.opponent_cooperators[-1] + (1 if i_cooperated_last else 0)
        cooperation_ratio = k / self.n
        if cooperation_ratio >= 0.5:
            return Action.C
        elif current_stock > 0.75 * self.capacity:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_45(BaseStrategy):
    """
    A conditional cooperation strategy based on 'Tit-for-Tat with Forgiveness',
    adjusted for common pool sustainability, with aggressive terminal play.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_index = history.round_number
        if round_index == self.r - 1:
            return Action.D
        if round_index == 0:
            return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.C
        c_prev = history.opponent_cooperators[-1]
        if self.r < 5:
            if c_prev < self.n_opponents:
                return Action.D
            return Action.C
        if c_prev == self.n_opponents:
            return Action.C
        s_crit = self.capacity * (1.0 - 1.0 / self.n)
        if current_stock < s_crit:
            return Action.C
        prob_defect = 1.0 - float(c_prev) / float(self.n_opponents)
        if random.random() < prob_defect:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_46(BaseStrategy):
    """
    Implements a resource-aware cooperative strategy.
    
    Logic:
    - Initially cooperates (Round 1).
    - Monitors previous round's cooperation. 
    - Projects future stock levels; switches to D if projected stock falls below 50% capacity.
    - Implements 'grim trigger' behavior for rapid resource depletion.
    - Implements 'recovery' if stock returns to >= 75% capacity.
    - Always defects on the final round.
    - Defects immediately if stock < capacity / (2 * n).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.permanently_defected = False

    def _calculate_projected_stock(self, current_s, num_cooperators):
        """
        Calculates the stock for the next round given n players and current_s.
        Note: Current player's own action must be factored in.
        """
        n = self.desc.n_players
        total_consumption = (num_cooperators + 1) * (current_s / (2 * n)) + (n - (num_cooperators + 1)) * (current_s / n)
        remaining = max(0.0, current_s - total_consumption)
        growth = 2 * remaining * (1 - remaining / self.desc.capacity)
        return min(self.desc.capacity, remaining + growth)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if self.permanently_defected:
            return Action.D
        prev_s = self.desc.capacity if history.round_number == 1 else self._calculate_prev_s_recursive(history)
        if prev_s - current_stock >= 0.5 * self.desc.capacity:
            self.permanently_defected = True
            return Action.D
        if current_stock < self.desc.capacity / (2 * self.desc.n_players):
            return Action.D
        if history.my_actions[-1] == Action.D:
            if current_stock >= 0.75 * self.desc.capacity:
                return Action.C
            return Action.D
        num_c = history.opponent_cooperators[-1]
        if num_c == self.desc.n_players - 1:
            return Action.C
        projected_next_s = self._calculate_projected_stock(current_stock, num_c)
        threshold = 0.5 * self.desc.capacity
        if projected_next_s >= threshold:
            return Action.C
        else:
            return Action.D

    def _calculate_prev_s_recursive(self, history: PlayerHistory) -> float:
        """
        Reconstructs the stock level from the previous round by simulating the game
        dynamics backwards or simply tracking history. 
        Simplified: We assume initial state is Capacity.
        """
        s = float(self.desc.capacity)
        for r in range(history.round_number):
            n = self.desc.n_players
            num_c = history.opponent_cooperators[r] + (1 if history.my_actions[r] else 0)
            num_d = n - num_c
            consumption = num_c * (s / (2 * n)) + num_d * (s / n)
            rem = max(0.0, s - consumption)
            growth = 2 * rem * (1 - rem / self.desc.capacity)
            s = min(self.desc.capacity, rem + growth)
        return s

class Strategy_COLLECTIVE_47(BaseStrategy):
    """
    A strategy for the Common Pool Resource Game that balances sustainability with opportunistic defection.
    
    Logic:
    1. Initial Round: Cooperate.
    2. Terminal Round: Defect if stock > 0.
    3. Intermediate Rounds:
        - If current stock < capacity / 2: Defect.
        - If stock is healthy (>= capacity / 2):
            - If previous round experienced a 'crash' (new_stock < old_stock / 4): Defect for 2 rounds.
            - Otherwise: Play Tit-for-Tat based on whether >= ceil(n/2) players cooperated.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.crash_cooldown = 0
        self.previous_stock = self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        if round_t > 0:
            if current_stock < self.previous_stock / 4.0:
                self.crash_cooldown = 2
        self.previous_stock = current_stock
        if round_t == 0:
            return Action.C
        if round_t == self.r - 1:
            return Action.D if current_stock > 0 else Action.C
        if current_stock <= 0:
            return Action.C
        if self.crash_cooldown > 0:
            self.crash_cooldown -= 1
            return Action.D
        s_min = self.capacity / 2.0
        if current_stock < s_min:
            return Action.D
        last_my_action = history.my_actions[-1]
        num_opponents_cooperating = history.opponent_cooperators[-1]
        total_cooperators = num_opponents_cooperating + (1 if last_my_action else 0)
        threshold = math.ceil(self.n / 2.0)
        if total_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_48(BaseStrategy):
    """
    A modified Tit-for-Tat strategy for the Common Pool Resource Game.
    Maintains resource sustainability by cooperating when the stock is healthy
    and the group has demonstrated cooperation, while defecting when the
    resource is endangered or the group fails to cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        threshold = capacity / n
        my_prev_action = history.my_actions[-1]
        prev_cooperators = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if current_stock <= threshold:
            return Action.D
        if prev_cooperators >= n // 2:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_49(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource game.
    Implements a threshold-based strategy:
    - Round 1: Cooperate.
    - Terminal Round: Defect to maximize immediate payoff.
    - Recovery Phase: If current_stock < capacity / 2, prioritize cooperation to restore stock.
    - Steady State: Cooperate if (n-1) or more opponents cooperated in the previous round, otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / 2.0:
            return Action.C
        k = history.opponent_cooperators[-1]
        if k >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_50(BaseStrategy):
    """
    Tit-for-Tat with a Triggered Threshold:
    - Cooperates in the first round.
    - If stock >= 0.5 * capacity:
        - Cooperates if everyone cooperated last round.
        - Defects if there was any defection in the last round.
    - If stock < 0.5 * capacity:
        - Cooperates if everyone cooperated last round (re-building phase).
        - Defects if there was any defection in the last round (survival phase).
    - Final round (round = n_rounds - 1):
        - Cooperates if stock >= 0.25 * capacity.
        - Defects otherwise.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.s_min = 0.5 * self.capacity
        self.final_threshold = 0.25 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            if current_stock >= self.final_threshold:
                return Action.C
            else:
                return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        total_cooperators = history.opponent_cooperators[-1] + my_prev_coop
        if current_stock >= self.s_min:
            if total_cooperators == self.n:
                return Action.C
            else:
                return Action.D
        elif total_cooperators == self.n:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_51(BaseStrategy):
    """
    A threshold-based Tit-for-Tat strategy for the Common Pool Resource Game.
    Maintains cooperation as long as sufficient cooperators exist in the previous round,
    defects in the final round, and salvages in critical stock conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity * 0.25:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        my_prev_action = history.my_actions[current_round_idx - 1]
        my_prev_coop = 1 if my_prev_action else 0
        total_cooperators_prev = my_prev_coop + history.opponent_cooperators[current_round_idx - 1]
        if total_cooperators_prev >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_52(BaseStrategy):
    """
    A trigger-based cooperative strategy for the Common Pool Resource game.
    It attempts to maintain mutual cooperation (Action.C) as long as everyone 
    else is cooperating. It punishes defection with defect (Action.D) and 
    attempts a reset to cooperation when the stock is sufficiently high.
    It includes logic for terminal rounds and near-collapse conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishing = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        round_idx = history.round_number
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity * 0.05:
            return Action.D
        if round_idx == 0:
            return Action.C
        last_action_c = history.my_actions[-1]
        cooperators_last_round = history.opponent_cooperators[-1] + (1 if last_action_c else 0)
        if current_stock > 0.9 * self.game_description.capacity:
            return Action.C
        if cooperators_last_round == n:
            self.punishing = False
            return Action.C
        if current_stock > 0.5 * self.game_description.capacity and cooperators_last_round >= n - 1:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_53(BaseStrategy):
    """
    A sustainable reciprocity strategy that cooperates initially, punishes defection
    when the common pool is sufficient, but switches to cooperative recovery modes 
    when the stock reaches critical levels or when reciprocity is observed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_coop = prev_opp_coop + (1 if prev_my_action else 0)
        if prev_total_coop == self.n:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_54(BaseStrategy):
    """
    Implements a Conditional Sustainability Tit-for-Tat strategy.
    
    Logic:
    - Round 0: Cooperate.
    - Final Round: Always Defect.
    - Low Stock (S < capacity/4): Force Cooperation to restart growth.
    - Standard Play:
        - If previous round saw all players cooperate (k=n), continue to cooperate.
        - If any defections occurred (k < n), defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_k = history.opponent_cooperators[-1] + (1 if my_prev_action == Action.C else 0)
        if current_stock < capacity / 4:
            return Action.C
        if prev_k < n:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_55(BaseStrategy):
    """
    Implements the 'Responsive Stewardship' strategy:
    - Initial Round: Cooperate (C).
    - If Last Round (t == r): Always defect (D).
    - If Stock > 50% capacity: 
        - Cooperate if near-unanimous cooperation observed in the previous round (k >= n-1).
        - Otherwise, defect.
    - If Stock <= 50% capacity:
        - Always cooperate (C) to prevent collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        n = self.game_description.n_players
        threshold = n - 1
        last_round_cooperators = history.opponent_cooperators[-1]
        if current_stock <= 0.5 * self.game_description.capacity:
            return Action.C
        if last_round_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_56(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Common Pool Resource Game.
    - Round 1: Always cooperates.
    - Rounds 1 < t < r: Cooperates if the previous round had at least n-1 cooperators.
    - Round r: Cooperates if the stock is >= 1.0 and previous round was perfect cooperation (n), else defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        if current_round == 1:
            return Action.C
        prev_round_idx = history.round_number - 1
        my_prev_action_val = 1 if history.my_actions[prev_round_idx] else 0
        k_prev = history.opponent_cooperators[prev_round_idx] + my_prev_action_val
        if current_round == r:
            if current_stock >= 1.0 and k_prev == n:
                return Action.C
            else:
                return Action.D
        if k_prev >= n - 1:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_57(BaseStrategy):
    """
    A Conditional Tit-for-Tat strategy for the Common Pool Resource game.
    
    Logic:
    1. Always Cooperate (C) in the first round to signal intent.
    2. In the final round, always Defect (D) to maximize terminal payoff.
    3. Emergency: If current stock < capacity / 10, always Defect (D) to salvage remaining value.
    4. Adaptive: In intermediate rounds, Cooperate (C) if the previous round's cooperation count 
       was at least (n-1). Otherwise, Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 10:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_58(BaseStrategy):
    """
    Implements a Tit-for-Tat variant designed to manage a common pool resource.
    The strategy prioritizes stock sustainability while adapting to "System Health" 
    thresholds and incorporating a "Bankruptcy Defense" mechanism.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            if current_stock >= 0.5 * self.capacity:
                return Action.C
            return Action.D
        if current_stock < 0.2 * self.capacity:
            return Action.D
        my_last_action = history.my_actions[-1]
        my_last_coop = 1 if my_last_action == Action.C else 0
        n_c = history.opponent_cooperators[-1] + my_last_coop
        if current_stock >= 0.9 * self.capacity:
            if n_c == self.n:
                return Action.C
            return Action.D
        else:
            if n_c == self.n:
                return Action.C
            return Action.D

class Strategy_COLLECTIVE_59(BaseStrategy):
    """
    Sustainable Tit-for-Tat with Stock Thresholding:
    - Maintains sustainability by cooperating when stock is high or critical.
    - Retaliates (Defects) if stock is medium/low and aggregate behavior indicates defection.
    - Maximizes utility on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_stock < 0.1 * capacity:
            return Action.C
        if current_stock >= 0.95 * capacity:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_cooperators = history.opponent_cooperators[-1]
        total_cooperators = prev_opp_cooperators + (1 if prev_my_action else 0)
        if total_cooperators < n:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_60(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness strategy for the Common Pool Resource game.
    
    Logic:
    1. First round: Always Cooperate (C).
    2. Final round: Always Defect (D) to maximize terminal payoff.
    3. Intermediate rounds:
       - If previous round saw universal cooperation (all other players cooperated), continue to Cooperate (C).
       - If previous round saw any defection, switch to Defect (D) to punish, unless the stock is critically low (< capacity / 4), in which case we switch back to Cooperate (C) to prevent extinction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 4:
            return Action.C
        my_prev_action = history.my_actions[-1]
        num_opponents_cooperating = history.opponent_cooperators[-1]
        my_cooperated = 1 if my_prev_action else 0
        total_cooperators = num_opponents_cooperating + my_cooperated
        if total_cooperators == n:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_61(BaseStrategy):
    """
    Triggered Tit-for-Tat with Recovery strategy.
    
    Logic:
    - Round 0: Cooperate.
    - Final Round: Defect.
    - Intermediate Rounds:
        - Defect if current stock is below 20% of capacity (safety buffer).
        - If stock is healthy, evaluate previous round cooperation:
            - Cooperate if number of cooperators >= n / 2.
            - Otherwise, Defect (penalty mechanism).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock < 0.2 * capacity:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        if last_round_cooperators >= n_players / 2:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_62(BaseStrategy):
    """
    Implements an Adaptive Tit-for-Tat strategy with trend analysis and emergency depletion handling.
    
    Logic:
    1. Round 1: Always Cooperate (C).
    2. Rounds 2 to r-1:
       - If stock < 1.0: Defect (D) to extract value before collapse.
       - Else if majority of all players (including self) cooperated in the previous round: Cooperate (C).
       - Otherwise: Defect (D).
    3. Final Round: Always Defect (D).
    
    Note on "majority":
    The strategy definition states: "If C_prev > (n/2), play Cooperate (C)".
    History provided is `opponent_cooperators`.
    - If I played C: Total C = opponent_cooperators[-1] + 1
    - If I played D: Total C = opponent_cooperators[-1]
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        current_round_index = history.round_number
        if current_round_index == total_rounds - 1:
            return Action.D
        if current_stock < 1.0:
            return Action.D
        if current_round_index == 0:
            return Action.C
        last_action_was_coop = history.my_actions[-1]
        c_prev_opponents = history.opponent_cooperators[-1]
        c_prev_total = int(last_action_was_coop) + c_prev_opponents
        if c_prev_total > n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_63(BaseStrategy):
    """
    A Tit-for-Tat with Forgiveness strategy for the Common Pool Resource Game.
    
    This strategy balances short-term consumption with long-term sustainability by 
    monitoring the current stock level and the collective behavior of opponents.
    - Round 1: Cooperate (C).
    - Terminal Round: Cooperate if stock > 0.25*capacity, otherwise Defect (D).
    - If Stock < 0.25*capacity: Defect (D) to capture remaining resources.
    - If 0.25*capacity <= Stock < 0.5*capacity: Cooperate (C) to allow regeneration.
    - If Stock >= 0.5*capacity: Conditional cooperation based on previous round's 
      cooperation count (threshold: >= n/2).
    - Edge Case: If total defection observed in previous round (k=0), immediately 
      defect to signal, otherwise revert to conditional logic.
    - Edge Case: For n=2, use strict Tit-for-Tat (only C if opponent played C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            if current_stock <= 0.25 * self.capacity:
                return Action.D
            return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if current_stock < 0.5 * self.capacity:
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        if k_prev == 0:
            return Action.D
        if self.n == 2:
            return Action.C if k_prev == 1 else Action.D
        threshold = math.ceil(self.n / 2)
        if k_prev >= threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_64(BaseStrategy):
    """
    Implements a cooperative strategy with salvage triggers and probabilistic reciprocity.
    - Plays C in round 1.
    - Plays D in the final round.
    - Performs a salvage operation (D) if stock < capacity / 2.
    - If previous round had full cooperation, maintains C.
    - Otherwise, acts probabilistically based on the ratio of cooperators in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round_idx = history.round_number
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock < capacity / 2.0:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        prev_total_coop = prev_opp_coop + (1 if my_prev_action else 0)
        if prev_total_coop == n:
            return Action.C
        threshold = prev_total_coop / n
        if random.random() < threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_65(BaseStrategy):
    """
    A Tit-for-Tat strategy with a Collective Sustainability Threshold.
    
    Logic:
    - Maintains resource at capacity / 2 to maximize regrowth.
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1: 
        - Cooperate if opponent cooperation >= 0.5 OR stock > 0.5 * capacity.
        - If opponent cooperation < 0.5 AND stock <= 0.25 * capacity (Critical), prioritize survival (C).
        - If opponent cooperation < 0.5 AND stock > 0.5 * capacity (Robust), punish (D) to discourage over-consumption.
    - Final Round: Defect (D) if stock is low (< 10% capacity), else Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            if current_stock < self.capacity * 0.1:
                return Action.D
            else:
                return Action.C
        last_coop_count = history.opponent_cooperators[-1]
        c_obs = last_coop_count / self.n_opponents if self.n_opponents > 0 else 1.0
        if c_obs >= 0.5:
            return Action.C
        if current_stock <= self.capacity * 0.25:
            return Action.C
        if current_stock > self.capacity * 0.5:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_66(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with a pre-emptive stock-safety override.
    
    1.  Initialization (Round 1): Always Cooperate (C).
    2.  General Rounds: Cooperate if (n-1) or more players cooperated in the 
        previous round, otherwise Defect (D).
    3.  Stock-Safety Override: If stock <= capacity / (2*n), always Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        threshold = self.game_description.capacity / (2 * self.game_description.n_players)
        if current_stock <= threshold:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_coop_count = history.opponent_cooperators[-1]
        total_cooperators_prev = last_opponent_coop_count + (1 if last_my_action else 0)
        if total_cooperators_prev >= self.game_description.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_67(BaseStrategy):
    """
    Implements a Trigger-Tit-for-Tat strategy for the Common Pool Resource Game.
    The strategy cooperates (Action.C) in the first round and maintains cooperation
    as long as the group cooperation rate meets a threshold (75%) and the stock
    is not critically low. It defects (Action.D) in the terminal round, or if
    the resource is depleted below (capacity / n), or if the previous round's
    cooperation rate fell below 75%.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.threshold_fraction = 0.75
        self.n_opponents = self.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_opponents_C = history.opponent_cooperators[-1]
        if self.n_opponents > 0:
            cooperation_rate = prev_opponents_C / self.n_opponents
        else:
            cooperation_rate = 1.0
        critically_low = current_stock < self.capacity / self.n_players
        insufficient_cooperation = cooperation_rate < self.threshold_fraction
        if critically_low or insufficient_cooperation:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_68(BaseStrategy):
    """
    Implements a Triggered Resilience strategy.
    
    This strategy aims to maintain the common pool stock at approximately half of capacity
    by monitoring group consumption. It cooperates by default, punishes mass defection 
    for one round, and defects in the final round to secure remaining value. It also 
    abandons cooperation if the resource collapses below a critical threshold (10%).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators = prev_cooperators + my_prev_action
        if total_cooperators == self.n:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_69(BaseStrategy):
    """
    A conditional 'Tit-for-Tat' strategy that calculates a Group Cooperation Rate (GCR)
    based on observed opponent behavior. It adapts its cooperation threshold based on
    historical performance, prioritizes resource recovery when stock is low, and 
    defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity * 0.2:
            return Action.C
        gcr_values = [count / self.n_opponents for count in history.opponent_cooperators]
        if len(gcr_values) >= 2:
            if gcr_values[-1] == 0.0 and gcr_values[-2] == 0.0:
                return Action.D
        avg_gcr = np.mean(gcr_values)
        prev_gcr = gcr_values[-1]
        if current_stock < 0.5 * self.capacity:
            return Action.C
        if prev_gcr >= avg_gcr:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_70(BaseStrategy):
    """
    A conditional cooperation strategy based on 'tit-for-tat with thresholding'.
    It cooperates to sustain the stock, monitors opponent cooperation ratios,
    and applies a Pavlovian recovery if cooperation drops or stock levels deplete,
    with a final-round defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_action_was_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_stock <= 0:
            self.last_action_was_defect = True
            return Action.D
        if current_round == n_rounds - 1:
            self.last_action_was_defect = True
            return Action.D
        if current_round == 0:
            self.last_action_was_defect = False
            return Action.C
        if self.last_action_was_defect and current_stock >= capacity * 0.1:
            self.last_action_was_defect = False
            return Action.C
        prev_opp_cooperators = history.opponent_cooperators[-1]
        num_opponents = n - 1
        cooperation_ratio = prev_opp_cooperators / num_opponents if num_opponents > 0 else 1.0
        if current_stock < capacity * 0.1:
            self.last_action_was_defect = True
            return Action.D
        if cooperation_ratio >= 0.5 and current_stock >= capacity * 0.25:
            self.last_action_was_defect = False
            return Action.C
        else:
            self.last_action_was_defect = True
            return Action.D

class Strategy_COLLECTIVE_71(BaseStrategy):
    """
    A strategy for the Common Pool Resource game that implements a 'Conditional Cooperator' logic.
    It prioritizes cooperation when the resource stock is healthy and the group shows high 
    participation, but switches to defection if the stock becomes critically low, if the 
    group exhibits high defection, or in the final round to maximize terminal utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.n_opponents = self.n_players - 1
        self.cooperation_threshold = math.ceil(self.n_opponents * 0.75)
        self.initial_defect_threshold = self.n_opponents // 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_cooperators = history.opponent_cooperators[-1]
        if current_stock < self.capacity * 0.1:
            return Action.D
        if history.round_number == 1:
            if history.opponent_cooperators[0] < self.initial_defect_threshold:
                return Action.D
        if current_stock > self.capacity * 0.4 and last_cooperators >= self.cooperation_threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_72(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Stock-Dependent Trigger.
    This strategy seeks to maintain resource capacity by enforcing a strict 
    cooperation threshold (n-1 players) while allowing for emergency 
    recovery measures when the stock levels are critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.my_last_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number + 1
        if history.round_number == 0:
            self.my_last_action = Action.C
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        total_cooperators = prev_cooperators + (1 if self.my_last_action == Action.C else 0)
        if current_round == r:
            if current_stock >= 0.5 * capacity:
                action = Action.D
            else:
                action = Action.C
            self.my_last_action = action
            return action
        if current_stock < 0.2 * capacity:
            if total_cooperators == 1 and self.my_last_action == Action.C:
                action = Action.D
            else:
                action = Action.C
        elif total_cooperators >= n - 1:
            action = Action.C
        else:
            action = Action.D
        self.my_last_action = action
        return action

class Strategy_COLLECTIVE_73(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource Game.
    
    Logic:
    - Round 0: Always Cooperate.
    - Final Round (n_rounds - 1): Always Defect.
    - Low Stock (< 25% capacity): Defect to maximize remaining utility.
    - Normal Rounds: Cooperate if the cooperation rate in the previous round 
      was >= 50% (threshold T=0.5), otherwise Defect to punish unsustainable behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if round_idx == total_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < 0.25 * self.game_description.capacity:
            return Action.D
        last_round_my_action = 1 if history.my_actions[-1] else 0
        last_round_opponent_coops = int(history.opponent_cooperators[-1])
        total_cooperators = last_round_my_action + last_round_opponent_coops
        last_cooperation_rate = total_cooperators / self.game_description.n_players
        if last_cooperation_rate >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_74(BaseStrategy):
    """
    Trigger-Based Sustainable Cooperation strategy.
    
    Maintains cooperation while the common pool resource is sustainable (>= 10% capacity)
    and collective behavior remains near-unanimous (n-1 cooperators). Defects in the
    final round to maximize individual payoff, or if the resource hits a critical 
    depletion threshold, or if previous cooperation falls below the (n-1) threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if history.opponent_cooperators[-1] >= self.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_75(BaseStrategy):
    """
    A Tit-for-Tat variant with probabilistic 'Grim Trigger' components, 
    accounting for stock dynamics, defection risk, and game-end pressure.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        k = int(history.opponent_cooperators[-1])
        n_opponents = self.n - 1
        if current_round == self.r - 1:
            if current_stock < self.capacity / (2 * self.n):
                return Action.D
            if k == n_opponents:
                return Action.C
            else:
                return Action.D
        if current_stock < self.capacity / 2 and k < n_opponents:
            return Action.D
        if k == 0:
            if current_stock >= 0.8 * self.capacity:
                return Action.C
            else:
                return Action.D
        if self.r - current_round < 3 and current_stock < self.capacity / self.n:
            return Action.D
        if k == n_opponents:
            return Action.C
        if n_opponents == 0:
            return Action.C
        d_risk = (1 - k / n_opponents) * (current_stock / self.capacity)
        if d_risk < 0.25:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_76(BaseStrategy):
    """
    A conditional strategy based on the 'Tit-for-Tat' principle, calibrated to maintain the common pool at maximum 
    sustainable yield. It uses adaptive cooperation thresholds, punitive measures for systemic defection, 
    and specific terminal strategies based on stock status.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold_coop = math.floor((self.n - 1) / 2)
        self.threshold_majority_defectors = math.floor(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx < self.r and current_stock < 0.1 * self.capacity:
            return Action.D
        if round_idx == self.r - 1:
            if current_stock >= self.capacity / 2:
                return Action.C
            else:
                return Action.D
        c_prev = history.opponent_cooperators[-1]
        is_majority_defecting = c_prev < self.threshold_majority_defectors
        if is_majority_defecting:
            return Action.D
        if c_prev >= self.threshold_coop:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_77(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy for the Common Pool Resource Game.
    
    Logic:
    - Maintains target capacity via thresholds.
    - Uses a recovery phase (k=2 rounds) if stock falls below capacity/4.
    - Shifts to permanent defection if threshold 'T' (n/2) is not met for 3 consecutive rounds.
    - Defaults to Defect in the last round, unless stock is critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.T = math.ceil(self.n / 2)
        self.recovery_rounds_left = 0
        self.consecutive_failures = 0
        self.permanently_defecting = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if self.recovery_rounds_left > 0:
            self.recovery_rounds_left -= 1
        if prev_cooperators < self.T:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            self.permanently_defecting = True
        if current_stock < self.capacity / 4.0:
            self.recovery_rounds_left = 2
            self.permanently_defecting = False
            self.consecutive_failures = 0
        if current_round == self.r - 1:
            if current_stock < 1.0:
                return Action.C
            return Action.D
        if self.recovery_rounds_left > 0:
            return Action.C
        if self.permanently_defecting:
            return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.C
        if prev_cooperators >= self.T:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_78(BaseStrategy):
    """
    A conditional reciprocity strategy for the Common Pool Resource game.
    Implements a Tit-for-Tat with Forgiveness framework, adapting to stock levels
    and aggregate opponent behavior. It prioritizes cooperation but retaliates
    probabilistically against systemic defection, with hard-coded triggers for
    final rounds and extreme resource scarcity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.capacity = self.game_description.capacity
        self.r = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_action_was_c = bool(history.my_actions[-1])
        c_obs = history.opponent_cooperators[-1] + (1 if last_action_was_c else 0)
        d_obs = self.n - c_obs
        if current_stock <= self.capacity * 0.1:
            return Action.D
        if current_round >= 2:
            last_c = c_obs
            second_last_action_c = bool(history.my_actions[-2])
            second_last_c = history.opponent_cooperators[-2] + (1 if second_last_action_c else 0)
            if last_c == 0 and second_last_c == 0:
                return Action.D
        if current_stock >= self.capacity * 0.95:
            return Action.C
        threshold = math.ceil(self.n / 2)
        if c_obs >= threshold:
            return Action.C
        else:
            defector_ratio = d_obs / self.n
            if random.random() < defector_ratio:
                return Action.D
            else:
                return Action.C

class Strategy_COLLECTIVE_79(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Stock-Pressure Sensitivity.
    
    1. First round: Play C.
    2. Last round: Play D.
    3. Survival mode: If stock < 0.2 * capacity, play D.
    4. Tit-for-Tat mechanism: If any opponent defected in the previous round (prev_opponents_C < n - 1), play D.
    5. Otherwise: Play C.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 0.2 * self.game_description.capacity:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        prev_opponents_C = history.opponent_cooperators[-1]
        if prev_opponents_C < n_opponents:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_80(BaseStrategy):
    """
    A strategy that balances sustainability and defense by tracking cooperators and stock levels.
    
    1. Always Cooperates in Round 1.
    2. Terminal Phase (Round t=r): Cooperates if stock >= 50% capacity, otherwise Defects.
    3. Low Stock (< 10% capacity): Defects to prioritize immediate value.
    4. Total Defection in previous round: Defects to "reboot".
    5. Standard logic: Cooperates if cooperators > 75% of players OR stock >= 50% capacity; otherwise Defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.s_crit = 0.5 * self.capacity
        self.low_stock_threshold = 0.1 * self.capacity
        self.coop_threshold = 0.75 * self.n

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        is_final_round = history.round_number == self.game_description.n_rounds - 1
        if is_final_round:
            if current_stock >= self.s_crit:
                return Action.C
            else:
                return Action.D
        my_last_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        d_prev = self.n - c_prev
        if current_stock < self.low_stock_threshold:
            return Action.D
        if d_prev == self.n:
            return Action.D
        if c_prev >= self.coop_threshold or current_stock >= self.s_crit:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_81(BaseStrategy):
    """
    A 'Conditional Sustainable Tit-for-Tat' strategy that balances 
    cooperative extraction with defensive measures based on stock health,
    aggregate peer behavior, and end-game proximity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.last_stock = float(self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_coop = (1 if prev_my_action else 0) + prev_opp_coop
        num_defectors = self.n - prev_total_coop
        if history.round_number >= self.r - 3:
            if current_stock > 0.75 * self.capacity:
                return Action.C if num_defectors == 0 else Action.D
            else:
                return Action.D
        if num_defectors > 0:
            if current_stock > 0.5 * self.capacity:
                return Action.C
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_82(BaseStrategy):
    """
    Tit-for-Tat strategy with forgiveness and capacity-based thresholds.
    Prioritizes cooperation to build stock, punishes defection, but intervenes
    with recovery efforts when stock is critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == r - 1:
            return Action.D
        if current_stock < capacity / 2:
            return Action.C
        if current_stock <= 0.001:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_cooperators = history.opponent_cooperators[-1]
        total_cooperators_prev = prev_opp_cooperators + (1 if prev_my_action else 0)
        if total_cooperators_prev == n:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_83(BaseStrategy):
    """
    A 'Conditional Sustainability' strategy that prioritizes stock preservation.
    
    Logic:
    - Maintains sustainability (S >= capacity/2).
    - If last round: Defect (maximize payoff).
    - If in 'punishment_active' mode:
        - Continue to defect until all other players cooperate in a single round.
    - If not in 'punishment_active' mode:
        - If stock is critical (< capacity/2), Cooperate (force regeneration).
        - If any opponent defected in the previous round, initiate punishment.
        - Otherwise, Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_active = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number > 0:
            n_opponents = self.game_description.n_players - 1
            prev_coop_count = history.opponent_cooperators[-1]
            prev_defection_count = n_opponents - prev_coop_count
            if self.punishment_active:
                if prev_coop_count == n_opponents:
                    self.punishment_active = False
            elif prev_defection_count > 0:
                self.punishment_active = True
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if self.punishment_active:
            return Action.D
        if current_stock < self.game_description.capacity / 2:
            return Action.C
        return Action.C

class Strategy_COLLECTIVE_84(BaseStrategy):
    """
    Constrained Trigger-Tit-for-Tat (CTTFT).
    
    This strategy aims to maximize long-term yield by maintaining the common pool 
    at capacity through conditional cooperation.
    
    Decision Logic:
    1. Terminal Round: Defect to extract remaining value.
    2. Critical State (Stock < Capacity/2): Defect to salvage utility.
    3. Initialization: Always cooperate in the first round.
    4. General Rounds: Cooperate if n-1 or more players cooperated in the 
       previous round (including self); otherwise, defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        if round_idx == r - 1:
            return Action.D
        if current_stock < self.capacity / 2.0:
            return Action.D
        if round_idx == 0:
            return Action.C
        prev_opp_coop = int(history.opponent_cooperators[-1])
        prev_self_action = history.my_actions[-1]
        total_coop = prev_opp_coop + (1 if prev_self_action else 0)
        if total_coop >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_85(BaseStrategy):
    """
    A Tit-for-Tat variant with threshold conditions adapted for a Common Pool Resource game.
    
    Logic:
    - Round 1: Always Cooperate.
    - Final Round: Always Defect.
    - Intermediate Rounds:
        - Defect if stock is critically low (< capacity / n).
        - Defect if stock is < 50% of capacity (Recovery phase).
        - Otherwise, cooperate if the cooperation rate of the group in the 
          previous round (including self) was >= 0.5.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t == self.r - 1:
            return Action.D
        if current_stock < 1e-06 or current_stock < self.capacity / self.n:
            return Action.D
        if current_stock < 0.5 * self.capacity:
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        my_cooped_int = 1 if prev_my_action else 0
        x = (prev_opp_coop + my_cooped_int) / self.n
        if x >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_86(BaseStrategy):
    """
    Tit-for-Tat with Sustainable Threshold Targeting strategy.
    
    This strategy monitors the common pool's health (stock level) and the aggregate
    behavior of opponents (theta) to decide between cooperation and defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.n_opponents = max(1, self.n - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if current_stock >= 0.95 * self.capacity:
            return Action.C
        relevant_history = history.opponent_cooperators[-3:]
        rates = [c / self.n_opponents for c in relevant_history]
        theta = sum(rates) / len(rates)
        if theta >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_87(BaseStrategy):
    """
    Implements Proportional Forgiving Tit-for-Tat strategy.
    
    Logic:
    1. First round: Cooperate.
    2. Terminal round: Defect.
    3. Low Stock Threshold: Cooperate if stock < 0.2 * capacity.
    4. Steady state: Observe previous round cooperators 'k' (excluding self if necessary, 
       but standard interpretation is total cooperators in system).
       Probability of Defection P(D) = (n - k) / n.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.2 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.threshold:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        k_opponents = int(history.opponent_cooperators[-1])
        last_my_action = history.my_actions[-1]
        k_total = k_opponents + (1 if last_my_action else 0)
        n = self.game_description.n_players
        if k_total == n:
            return Action.C
        p_defection = (n - k_total) / n
        if random.random() < p_defection:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_88(BaseStrategy):
    """
    Implements Conditional Cooperation with Threshold-Based Punishment.
    
    This strategy maintains an internal trust_score, reacting to the number of 
    cooperators in the previous round. It includes logic for low-stock 
    emergencies, recovery bonuses, and forgiveness.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.trust_score = self.n - 1
        self.max_trust = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        s_crit = self.capacity / (2 * self.n)
        if current_stock < s_crit:
            return Action.D
        if current_stock >= 0.9 * self.capacity:
            self.trust_score = self.max_trust
        last_my_action = history.my_actions[-1]
        last_others_coop = history.opponent_cooperators[-1]
        c_prev = last_others_coop + (1 if last_my_action else 0)
        if c_prev == self.n - 1:
            self.trust_score = min(self.max_trust, self.trust_score + 1)
        elif c_prev < self.n - 1:
            self.trust_score -= self.n - c_prev
        if self.trust_score < 0 and c_prev == self.n - 1:
            self.trust_score = 0
            return Action.C
        if current_stock < self.capacity / self.n:
            return Action.D
        if self.trust_score >= 0:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_89(BaseStrategy):
    """
    Implements Conditional Cooperation with State-Aware Punishment.
    - Round 1: Always Cooperate.
    - End-Game (last 3 rounds): Always Defect.
    - Resource Depletion Check: If stock < 0.5 * capacity, always Defect.
    - Reciprocity: If stock > critical, Defect if the number of defectors in 
      the previous round >= ceil(n / 2), otherwise Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx >= self.total_rounds - 3:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        d_prev = n_opponents - k_prev
        threshold = math.ceil(self.n_players / 2)
        if d_prev >= threshold:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_90(BaseStrategy):
    """
    A strategy for the Common Pool Resource Game that balances sustainability with 
    reciprocity. It uses a Tit-for-Tat mechanism with critical stock thresholds to 
    decide between Cooperation (C) and Defection (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.s_crit = self.capacity * 0.5
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_opponents = self.n - 1
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        if current_stock >= self.capacity:
            return Action.C
        if current_stock < self.s_crit:
            return Action.D
        if n_opponents > 0:
            prev_round_k = history.opponent_cooperators[-1]
            cooperation_percentage = prev_round_k / n_opponents
            if cooperation_percentage >= 0.5:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_COLLECTIVE_91(BaseStrategy):
    """
    Tit-for-Tat with Forgiving Resilience:
    A strategy that prioritizes long-term resource sustainability. It starts by cooperating,
    then mimics the population's cooperation ratio in subsequent rounds, while incorporating 
    critical state-based overrides to prevent resource collapse and end-game defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.prev_stock = current_stock
            return Action.C
        my_prev_action = history.my_actions[-1]
        n_opponents = self.game_description.n_players - 1
        num_cooperators = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        r_ratio = num_cooperators / self.game_description.n_players
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 2 and current_stock < 0.25 * self.game_description.capacity:
            return Action.D
        if current_stock <= 1e-06:
            return Action.C
        if current_stock < 0.25 * self.game_description.capacity:
            return Action.C
        is_crashing = False
        if self.prev_stock > 0:
            if (current_stock - self.prev_stock) / self.prev_stock < -0.2:
                is_crashing = True
        self.prev_stock = current_stock
        if r_ratio >= 0.5:
            return Action.C
        elif is_crashing:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_92(BaseStrategy):
    """
    Implements a Trigger-Tit-for-Tat strategy for the Common Pool Resource Game.
    It cooperates by default but triggers a punishment (Defection) if any other player 
    defects. Punishment continues until full cooperation is observed, unless the 
    current stock is critically low, in which case it prioritizes sustainability 
    by cooperating. The strategy always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.D_status = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        last_my_action = history.my_actions[-1]
        last_opponent_cooperators = history.opponent_cooperators[-1]
        if last_my_action:
            k = last_opponent_cooperators + 1
        else:
            k = last_opponent_cooperators
        if history.round_number == r:
            return Action.D
        if current_stock < capacity / n:
            return Action.C
        if self.D_status:
            if k == n:
                if current_stock >= capacity / 2.0:
                    self.D_status = False
                    return Action.C
                else:
                    return Action.D
            else:
                return Action.D
        elif k < n:
            self.D_status = True
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_93(BaseStrategy):
    """
    A Tit-for-Tat adaptation for Common Pool Resource dynamics.
    Prioritizes sustainability via a sustainability override, punishes defection
    when pool levels are healthy, and maximizes final-round yield.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.c_threshold = math.ceil(self.game_description.n_players / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.game_description.capacity / 2:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock >= self.game_description.capacity / 2:
                return Action.C
            else:
                return Action.D
        if current_stock < self.game_description.capacity / 4:
            return Action.C
        k = history.opponent_cooperators[-1]
        if k >= self.c_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_94(BaseStrategy):
    """
    A conditional cooperative strategy for the Common Pool Resource Game.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Terminal Round: Always Defect (D).
    - Emergency: If stock is critically low (< capacity / 2n), Defect (D).
    - General:
        - If previous cooperation count k is high (>= 75% of players, or == n for small n), Cooperate (C).
        - If cooperation count falls below threshold, Defect (D) to signal dissatisfaction, then revert to C next round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.75

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.D
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == self.game_description.n_rounds - 1:
            return Action.D
        emergency_threshold = self.game_description.capacity / (2 * self.game_description.n_players)
        if current_stock < emergency_threshold:
            return Action.D
        prev_k = history.opponent_cooperators[-1]
        n = self.game_description.n_players
        if n < 4:
            required_k = n
        else:
            required_k = math.ceil(n * self.threshold)
        if prev_k >= required_k:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_95(BaseStrategy):
    """
    A conditional trigger-based strategy for the Common Pool Resource game.
    Maintains a reputation score based on collective consumption, cooperating when 
    the resource is sustainable and punishing when over-consumption is detected.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.reputation_score = 0
        self.last_known_stock = float(self.capacity)

    def _calculate_total_consumption(self, num_cooperators: int, current_stock: float) -> float:
        """
        Reconstruct total consumption from the number of cooperators.
        Cooperators play C (consumes stock/2n).
        Defectors play D (consumes stock/n).
        Total players = n.
        Num Defectors = n - num_cooperators.
        """
        pass

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            self.last_known_stock = current_stock
            return Action.C
        prev_round_idx = history.round_number - 1
        my_prev_action = history.my_actions[prev_round_idx]
        num_cooperators = history.opponent_cooperators[prev_round_idx] + (1 if my_prev_action else 0)
        num_defectors = self.n - num_cooperators
        c_consumption = self.last_known_stock / (2 * self.n)
        d_consumption = self.last_known_stock / self.n
        total_consumption = num_cooperators * c_consumption + num_defectors * d_consumption
        if total_consumption > self.last_known_stock / 2:
            self.reputation_score -= 1
        else:
            self.reputation_score = min(0, self.reputation_score + 1)
        self.last_known_stock = current_stock
        if self.reputation_score < 0:
            probability = abs(self.reputation_score) / self.n
            if random.random() < probability:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_COLLECTIVE_96(BaseStrategy):
    """
    Tit-for-Tat with Trend Monitoring and Resource Awareness.
    
    This strategy implements a conditional cooperative approach:
    1. First round: Cooperate.
    2. Subsequent rounds:
        - If the previous round saw a majority of players defecting (>= n/2), switch to Defect.
        - If resource levels are critically low (< 0.2 * capacity), switch to Defect, regardless of history (to prevent starvation).
        - Exception: If resource levels are at 0, always Cooperate.
        - Exception: In the final two rounds, switch to Defect if stock > 0.
        - If none of the above triggers occur, Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_stock <= 0:
            return Action.C
        if current_round >= self.n_rounds - 2:
            return Action.D
        if current_stock < 0.2 * self.capacity:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        my_contribution = 1 if last_my_action == Action.C else 0
        total_cooperators_prev = my_contribution + last_opponent_coops
        total_defectors_prev = self.n_players - total_cooperators_prev
        if total_defectors_prev >= self.n_players / 2:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_97(BaseStrategy):
    """
    Implements Sustainable Conditional Reciprocity (SCR).
    
    This strategy balances resource maintenance with tit-for-tat retaliation.
    It targets resource preservation via cooperation when conditions are stable,
    retaliates against defection for one round, and defects in the final round
    to maximize terminal utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        threshold = self.capacity / (2 * self.n)
        if current_stock < threshold:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        if last_round_cooperators == self.n - 1:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_98(BaseStrategy):
    """
    Implements a Generous Tit-for-Tat strategy for the Common Pool Resource Game.
    Maintains resource stability by cooperating when the population is sustainable 
    (>= 50% cooperation) or when the resource stock is critically low.
    Defects in the final round to maximize payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock <= self.game_description.capacity * 0.25:
            return Action.C
        my_last_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_last_action
        if total_cooperators_prev >= math.ceil(n / 2):
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_99(BaseStrategy):
    """
    Conditional Tit-for-Tat with Logistic Sustainability Thresholds.
    
    This strategy focuses on maintaining the common pool stock near the capacity/2 
    sweet spot where logistic growth is maximized. It uses a conditional approach 
    based on the previous round's cooperation ratio and the current state of 
    the resource, while always defecting in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = float(game_description.n_players)
        self.target_stock = self.capacity / 2.0
        self.k = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / self.n:
            return Action.D
        if current_stock <= 0:
            return Action.D
        previous_my_action = history.my_actions[-1]
        previous_total_cooperators = history.opponent_cooperators[-1] + (1 if previous_my_action else 0)
        phi = previous_total_cooperators / self.n
        if current_stock > self.target_stock:
            return Action.C
        if current_stock <= self.target_stock:
            if phi >= self.k:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_COLLECTIVE_100(BaseStrategy):
    """
    Tit-for-tat with threshold forgiveness strategy for the Common Pool Resource Game.
    
    This strategy balances long-term sustainability with defensive defection.
    1. Initial round: Cooperate.
    2. Terminal round: Defect.
    3. Adaptive loop:
       - Default rule: Cooperate if cooperation count >= ceil(n/2), else Defect.
       - Edge Case (Stock Depletion): If stock < 5% of capacity, Defect.
       - Recovery Mechanism: If stock > 75% of capacity and we were in 'Defect' 
         mode, attempt restart by Cooperating once.
       - Partial Cooperation Stability: If in partial cooperation but stock < 25% 
         of capacity, switch to Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = math.ceil(self.n / 2)
        self.opponent_threshold = math.ceil((self.n - 1) / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < 0.05 * self.capacity:
            return Action.D
        last_n_c = history.opponent_cooperators[-1]
        if current_stock > 0.75 * self.capacity:
            return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if last_n_c >= self.opponent_threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_101(BaseStrategy):
    """
    Implements a conditional cooperative strategy (Trigger-Tit-for-Tat).
    Prioritizes resource stock preservation via a recovery phase (low stock threshold),
    punishes non-cooperation when other players deviate, and optimizes 
    final-round utility based on remaining stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.C
        if current_stock < self.capacity / 4:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock < self.capacity / 2:
                return Action.C
            else:
                return Action.D
        if history.round_number == 0:
            return Action.C
        last_cooperators_count = history.opponent_cooperators[-1]
        if last_cooperators_count == self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_102(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness (TFT-F) approach.
    Cooperates initially and conditionally matches group cooperation levels (C_rate >= 0.5).
    Includes a forgiveness mechanism if stock levels are high (>= 75% capacity),
    and prioritizes defection on the last round or when stock is critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.capacity = self.game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.r
        if round_idx == total_rounds - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if round_idx == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + prev_my_action
        c_rate = total_cooperators / self.n
        if current_stock >= 0.75 * self.capacity:
            return Action.C
        if c_rate >= 0.5:
            return Action.C
        else:
            if current_stock < 0.5 * self.capacity:
                return Action.D
            return Action.D

class Strategy_COLLECTIVE_103(BaseStrategy):
    """
    A conditional trigger strategy for the Common Pool Resource Game.
    Maintains a 'Cooperative' or 'Punitive' status based on history.
    It cooperates to sustain stock levels, punishes defection by defecting,
    and reverts to cooperation once the group returns to full cooperation.
    It defects in the final round to maximize payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.status = 'Cooperative'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        others_cooperated = history.opponent_cooperators[-1]
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        total_cooperators_prev = others_cooperated + my_prev_coop
        if total_cooperators_prev < n:
            self.status = 'Punitive'
        if self.status == 'Punitive':
            if current_stock < capacity * 0.25:
                return Action.C
            if total_cooperators_prev == n:
                self.status = 'Cooperative'
                return Action.C
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_104(BaseStrategy):
    """
    A Tit-for-Tat with Forgiveness strategy adapted for common-pool resource management.
    Prioritizes sustainability (C) during low-stock or initial states, punishes defectors
    only when stock is high (TFT), and attempts to maximize payoff in the final round
    based on historical cooperative behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.2 * self.capacity:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.C
        is_last_round = history.round_number == self.game_description.n_rounds - 1
        prev_opponents_cooperated = history.opponent_cooperators[-1]
        previous_defectors = self.n_opponents - prev_opponents_cooperated
        if is_last_round:
            if prev_opponents_cooperated == self.n_opponents:
                return Action.C
            else:
                return Action.D
        elif previous_defectors == 0:
            return Action.C
        elif current_stock > 0.75 * self.capacity:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_105(BaseStrategy):
    """
    Tit-for-Tat with Conditional Forgiveness (TFT-CF):
    Attempts to sustain the common pool by cooperating as long as aggregate 
    opponent behavior remains optimal. It includes forgiveness thresholds 
    based on stock health and switches to defection in the terminal round 
    if the cooperative equilibrium was ever violated.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.has_ever_defected = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if current_stock < 0.1 * capacity:
            self.has_ever_defected = True
            return Action.D
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            if self.has_ever_defected:
                return Action.D
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        all_opponents_cooperated = prev_cooperators == n_opponents
        if all_opponents_cooperated:
            return Action.C
        elif current_stock > 0.8 * capacity:
            return Action.C
        else:
            self.has_ever_defected = True
            return Action.D

class Strategy_COLLECTIVE_106(BaseStrategy):
    """
    Tit-for-Tat with Dynamic Sustainable Threshold (TFT-DST).
    This strategy aims to keep the resource at capacity by calculating
    a maximum sustainable consumption threshold and reacting to group behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_rounds_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        capacity = self.game_description.capacity
        target_rem = 0.5 * capacity
        max_sustainable_consumption = current_stock - target_rem
        if current_stock < 0.1 * capacity:
            return Action.C
        if self.punishment_rounds_remaining > 0:
            self.punishment_rounds_remaining -= 1
            return Action.D
        if current_stock < 0.25 * capacity:
            return Action.C
        prev_coop = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
        if prev_coop < self.game_description.n_players / 2:
            self.punishment_rounds_remaining = 2
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_107(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource game.
    
    This strategy defaults to Cooperation (C). It monitors the number of defectors 
    in the previous round to assess sustainability. It defects if:
    1. It is the final round.
    2. The current stock is critically low (< 1.0).
    3. The previous round's total consumption threatened the stock (exceeded 50% of the available pool).
    4. Defectors were observed in the previous round, and the sustainability of the pool is questioned.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number >= self.total_rounds - 1:
            return Action.D
        if current_stock < 1.0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_c = history.opponent_cooperators[-1] + my_last_action_val
        total_d = self.n - total_c
        consumption_d = total_d * (current_stock / self.n)
        consumption_c = total_c * (current_stock / (2 * self.n))
        total_consumption = consumption_d + consumption_c
        if total_consumption > 0.5 * current_stock:
            return Action.D
        if total_d > 0:
            return Action.C
        return Action.C

class Strategy_COLLECTIVE_108(BaseStrategy):
    """
    Implements a threshold-based conditional strategy that maintains the common pool stock 
    at capacity by monitoring cooperation levels and enforcing strict sustainability 
    rules based on stock dynamics.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_stock < capacity / n:
            return Action.D
        if current_round == 0:
            return Action.C
        my_last_action = bool(history.my_actions[-1])
        last_opp_cooperators = int(history.opponent_cooperators[-1])
        k = last_opp_cooperators + (1 if my_last_action else 0)
        if k == n:
            return Action.C
        threshold = capacity * (1.0 - (n - k) / n)
        if current_stock < threshold:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_109(BaseStrategy):
    """
    Implements a Triggered Equilibrium strategy. 
    Cooperates in the first round and maintains cooperation as long as all players cooperated in the previous round.
    Defects if any player defected in the previous round or if the stock falls below a critical depletion threshold.
    Attempts to recover cooperation if the stock levels recover to a sustainable point (capacity / 2).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.in_recovery = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round_index = history.round_number
        rounds_remaining = self.total_rounds - current_round_index
        critical_threshold = self.capacity / 2 ** (rounds_remaining + 1)
        if current_stock < critical_threshold:
            return Action.D
        if self.in_recovery and current_stock >= self.capacity / 2.0:
            self.in_recovery = False
            return Action.C
        last_my_action_was_c = bool(history.my_actions[-1])
        k = history.opponent_cooperators[-1] + (1 if last_my_action_was_c else 0)
        if k == self.n:
            return Action.C
        else:
            self.in_recovery = True
            return Action.D

class Strategy_COLLECTIVE_110(BaseStrategy):
    """
    A Tit-for-Tat inspired strategy with sustainability constraints.
    
    Logic:
    1. First Round: Always Cooperate (C).
    2. Intermediate Rounds (1 to r-2):
       - Sustainability Check: If current stock is below capacity / (2 * n), force Cooperate (C).
       - Reciprocity: If previous round's cooperation rate (C_prev / n) >= 0.5, Cooperate (C), else Defect (D).
    3. Final Round (r-1):
       - If historical average cooperation >= 0.75, Cooperate (C).
       - Otherwise, Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == self.r - 1:
            my_coops = np.where(history.my_actions, 1, 0)
            total_cooperators_per_round = history.opponent_cooperators + my_coops
            avg_coop_rate = np.mean(total_cooperators_per_round / self.n)
            if avg_coop_rate >= 0.75:
                return Action.C
            return Action.D
        if current_stock < self.capacity / (2 * self.n):
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators / self.n >= 0.5:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_111(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with threshold cooperation.
    - Round 1: Cooperate.
    - Final Round: Defect.
    - Stock Check: If current stock < capacity / n_players, Defect.
    - Cooperation Logic: Cooperate if (n - 1) or more players cooperated in the previous round, else Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if self.n_players > 0:
            if current_stock < self.capacity / self.n_players:
                return Action.D
        last_opponent_k = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_k = last_opponent_k + (1 if my_last_action else 0)
        if total_k >= self.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_112(BaseStrategy):
    """
    Implements Targeted Sustainable Reciprocation (TSR).
    Cooperates initially, then adapts to current stock levels and history.
    Punishes based on the severity of previous round's observed defection.
    Switches to predatory behavior if resource depletion is critical or
    in the final round given sufficient remaining stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.n = self.desc.n_players
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_idx = history.round_number - 1
        if current_stock <= 0:
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            if current_stock >= self.desc.capacity / 2:
                return Action.D
            else:
                return Action.C
        if current_stock < self.desc.capacity / (2 * self.n):
            return Action.D
        if not hasattr(self, '_prev_stock'):
            self._prev_stock = self.desc.capacity
        is_rapid_depletion = False
        if self._prev_stock > 0:
            if self._prev_stock - current_stock > 0.5 * self._prev_stock:
                is_rapid_depletion = True
        self._prev_stock = current_stock
        if is_rapid_depletion:
            return Action.D
        obs_coop = history.opponent_cooperators[prev_idx]
        if obs_coop >= self.n_opponents:
            return Action.C
        else:
            if self.n_opponents > 0:
                prob_defect = (self.n_opponents - obs_coop) / self.n_opponents
                if random.random() < prob_defect:
                    return Action.D
            return Action.C

class Strategy_COLLECTIVE_113(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy.
    
    This strategy acts as a collective Tit-for-Tat mechanism. It cooperates
    while the resource is sustainable and everyone cooperates, but shifts 
    to defection if the stock drops below the sustainability buffer or if
    other players defect. It includes explicit handling for the terminal round,
    rapid depletion, and "handshake" attempts to restore cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_stock < 1e-06:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_coop = int(history.my_actions[-1])
        total_prev_coop = prev_opp_coop + prev_my_coop
        if total_prev_coop == self.n:
            return Action.C
        if current_stock > self.capacity / 2:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_114(BaseStrategy):
    """
    Trigger-Tit-for-Tat with Sustainability Threshold strategy.
    Prioritizes cooperation when trust and stock levels are sufficient,
    defects upon detecting unsustainable behavior or low stock,
    and always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_level = 1.0
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.capacity / self.n:
            return Action.D
        last_k = int(history.opponent_cooperators[-1])
        last_my_action = history.my_actions[-1]
        if last_my_action:
            observed_cooperation_rate = last_k / (self.n - 1) if self.n > 1 else 0.0
        else:
            observed_cooperation_rate = (last_k + 0) / self.n
        if observed_cooperation_rate < 0.5:
            self.trust_level = 0.0
        else:
            self.trust_level = self.trust_level * 0.9 + observed_cooperation_rate * 0.1
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if self.trust_level > 0.5 and current_stock >= self.capacity / 2:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_115(BaseStrategy):
    """
    Implements a Triggered Tit-for-Tat strategy with sustainability constraints.
    Prioritizes cooperative resource management while punishing defection when 
    the common pool stock is above a critical recovery threshold. Switches 
    to defection in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_stock < self.capacity / 2:
            return Action.C
        if current_round == 0:
            return Action.C
        last_round_idx = -1
        last_opponents_cooperated = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        k_prev = last_opponents_cooperated + (1 if my_last_action else 0)
        if k_prev == self.n:
            return Action.C
        num_defectors = self.n - k_prev
        if random.random() < num_defectors / self.n:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_116(BaseStrategy):
    """
    Implements a 'Tit-for-Tat with Forgiveness and Thresholding' strategy.
    
    1. Final Round: Always Defect (D) to capture residual stock.
    2. Sustainability Override: If stock < 0.5 * capacity, always Cooperate (C).
    3. Initial Round: Cooperate (C).
    4. Reciprocity: Otherwise, mirror group behavior. Cooperate if cooperation 
       ratio >= 0.75, else Defect. Ratio is calculated based on the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 0.5 * self.game_description.capacity:
            return Action.C
        if history.round_number == 0:
            return Action.C
        last_opp_coop_count = int(history.opponent_cooperators[-1])
        last_my_action = bool(history.my_actions[-1])
        c_prev = last_opp_coop_count + (1 if last_my_action else 0)
        if c_prev >= 0.75 * self.n:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_117(BaseStrategy):
    """
    A sustainable-harvest strategy implementing a Tit-for-Tat variant.
    It targets the stock level where growth is maximized (0.5 * capacity) 
    and uses reciprocity (Tit-for-Tat) and threshold triggers (collapse 
    prevention) to navigate the common pool dynamics.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold_defectors = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        n_opponents = self.n - 1
        prev_coop_count = history.opponent_cooperators[-1]
        prev_defectors = n_opponents - prev_coop_count
        if current_stock < 0.2 * self.capacity:
            return Action.D
        if prev_defectors > self.threshold_defectors:
            return Action.D
        growth_at_current = 2.0 * current_stock * (1.0 - current_stock / self.capacity)
        if current_stock / 2.0 <= growth_at_current:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_118(BaseStrategy):
    """
    An adaptive strategy for the Common Pool Resource game.
    It begins by cooperating. In subsequent rounds, it switches to defect if the 
    previous round's cooperation level drops below a calculated threshold (usually majority).
    It includes a 'Grudge' mechanism: if cooperation fails, it defects until the 
    resource stock recovers to at least 90% of capacity, at which point it resets 
    to cooperation. It forces defection in the final round or if the resource 
    is near exhaustion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.state = 0
        if self.game_description.n_players == 2:
            self.threshold = 2
        else:
            self.threshold = math.ceil(self.game_description.n_players / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.state = 0
            return Action.C
        if current_stock < 0.0001:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators = prev_cooperators + my_prev_action
        if self.state == 1:
            recovery_threshold = 0.9 * self.game_description.capacity
            if current_stock >= recovery_threshold:
                self.state = 0
                return Action.C
            else:
                return Action.D
        elif total_cooperators < self.threshold:
            self.state = 1
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_119(BaseStrategy):
    """
    A Tit-for-Tat variant strategy for the Common Pool Resource game.
    It calculates the projected stock growth based on the previous round's cooperation level.
    It cooperates to maintain stability, defects in the final round, extracts residual value
    when stock is critically low, and uses a stability threshold to decide between cooperation 
    and punishment.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.max_rounds = game_description.n_rounds

    def _calculate_next_stock(self, current_stock: float, cooperators_count: int) -> float:
        pass

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.max_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < 0.1 * self.capacity:
            return Action.D
        my_last_action = int(history.my_actions[-1])
        k = history.opponent_cooperators[-1] + my_last_action
        consumption_per_coop = current_stock / (2 * self.n)
        consumption_per_def = current_stock / self.n
        total_consumption = k * consumption_per_coop + (self.n - k) * consumption_per_def
        s_remaining = max(0.0, current_stock - total_consumption)
        growth = 2 * s_remaining * (1 - s_remaining / self.capacity)
        projected_next_stock = min(s_remaining + growth, self.capacity)
        is_high_slack = current_stock > 0.9 * self.capacity
        is_stable = projected_next_stock >= 0.95 * current_stock
        if is_high_slack:
            if k >= self.n - 2:
                return Action.C
            return Action.D
        if is_stable:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_120(BaseStrategy):
    """
    A strategy that maintains cooperation to stabilize the common pool, 
    with a specific exit strategy in the final round and a forced recovery
    phase if the pool is threatened.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.recovery_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        round_idx = history.round_number
        remaining_rounds = r - round_idx
        capacity = self.game_description.capacity
        if self.recovery_counter > 0:
            self.recovery_counter -= 1
        if round_idx > 0 and self.recovery_counter == 0:
            defectors = n - 1 - history.opponent_cooperators[-1]
            if current_stock < 0.9 * capacity or defectors > 0:
                k = min(remaining_rounds, math.ceil(n / 2))
                self.recovery_counter = k
        if round_idx == r - 1:
            if current_stock >= 0.75 * capacity:
                return Action.D
            else:
                return Action.C
        if self.recovery_counter > 0:
            return Action.C
        return Action.C

class Strategy_COLLECTIVE_121(BaseStrategy):
    """
    Implements a 'Cooperate-if-Sustainable' Tit-for-Tat strategy. 
    It prioritizes stock conservation when capacity is low, defaults to 
    cooperation in early rounds, and utilizes a memory-based mechanism to 
    recover from depletion, while defecting in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_full_cooperation = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 2:
            self.consecutive_full_cooperation = 0
            return Action.D
        if history.round_number == 0:
            self.consecutive_full_cooperation = 0
            return Action.C
        my_last_action = int(history.my_actions[-1])
        total_cooperators_last_round = history.opponent_cooperators[-1] + my_last_action
        is_full_coop = total_cooperators_last_round == self.game_description.n_players
        if is_full_coop:
            self.consecutive_full_cooperation += 1
            return Action.C
        else:
            self.consecutive_full_cooperation = 0
            stock_recovered = current_stock >= 0.5 * self.game_description.capacity
            if stock_recovered:
                return Action.C
            return Action.D

class Strategy_COLLECTIVE_122(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness strategy for Common Pool Resource Game.
    Maintains cooperation while stock is sustainable, punishes defection based on stock-dependent
    forgiveness thresholds, and exploits in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == total_rounds - 1:
            return Action.D
        obs_C = history.opponent_cooperators[-1]
        if current_stock < capacity * 0.25 and obs_C < self.n_opponents * 0.5:
            return Action.D
        if current_stock > 0.5 * capacity:
            return Action.C
        if obs_C >= self.n_opponents:
            return Action.C
        else:
            forgiveness_prob = current_stock / capacity if capacity > 0 else 0.0
            rand_val = random.random()
            if rand_val < forgiveness_prob:
                return Action.C
            else:
                return Action.D

class Strategy_COLLECTIVE_123(BaseStrategy):
    """
    Conditional Tit-for-Tat with Sustainability Threshold (CTFT-S).
    
    This strategy balances aggressive maximization of payoffs against the
    preservation of the common pool resource. It employs a dynamic target
    for cooperation and prioritizes stock preservation when the resource
    is fragile.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.dynamic_target = game_description.n_players - 1
        self.base_threshold = 0.5 * game_description.capacity
        self.collapse_threshold = 0.1 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= self.collapse_threshold:
            return Action.C
        if current_stock <= self.base_threshold:
            return Action.C
        if history.round_number == 0:
            return Action.C
        if history.round_number >= 3:
            c1 = history.opponent_cooperators[-3]
            c2 = history.opponent_cooperators[-2]
            c3 = history.opponent_cooperators[-1]
            if c1 < c2 < c3:
                if self.dynamic_target > 0:
                    self.dynamic_target -= 1
        last_round_coop = history.opponent_cooperators[-1]
        if last_round_coop >= self.dynamic_target:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_124(BaseStrategy):
    """
    Trigger-Resilient Cooperation Strategy.
    
    A Tit-for-Tat variant designed to maintain stock at capacity.
    - Prioritizes recovery (Cooperate) when stock is below 50% capacity.
    - Enforces punishment (Defect) if other players collectively deviate from
      near-unanimous cooperation, unless the game is ending.
    - Switches to aggressive extraction (Defect) in the final 2 rounds if the stock
      is sufficiently high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_bad_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        r_total = self.game_description.n_rounds
        r_current = history.round_number
        r_remaining = r_total - r_current
        capacity = self.game_description.capacity
        if r_current == 0:
            return Action.C
        if current_stock < capacity * 0.5:
            return Action.C
        if r_remaining < 2:
            if current_stock > capacity * 0.75:
                return Action.D
            else:
                return Action.C
        n_c_prev = history.opponent_cooperators[-1]
        if n_c_prev < n - 1:
            self.consecutive_bad_rounds += 1
        else:
            self.consecutive_bad_rounds = 0
        if self.consecutive_bad_rounds > 2:
            return Action.D
        if n_c_prev >= n_opponents - 1 and n_c_prev >= 0:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_125(BaseStrategy):
    """
    Implements a 'Conditional Sustainment' strategy.
    
    The strategy follows a tiered decision process:
    1. Termination: Always defects in the final round.
    2. Emergency: Cooperates if the stock drops below 25% of capacity, 
       prioritizing long-term sustainability over immediate gains.
    3. Initialization: Cooperates in the first round.
    4. Reciprocity: Cooperates if, in the previous round, nearly everyone (n-1 or n) 
       cooperated. Otherwise, it defects to prevent exploitation.
       
    The strategy accounts for potential resource exhaustion by checking for 0 stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.critical_threshold = self.capacity * 0.25

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        if current_stock <= 1e-09:
            return Action.D
        if round_t == self.n_rounds - 1:
            return Action.D
        if current_stock < self.critical_threshold:
            return Action.C
        if round_t == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= self.n_players - 1:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_126(BaseStrategy):
    """
    A conditional cooperative strategy that prioritizes stock maintenance.
    It cooperates in the first round and performs Tit-for-Tat based on 
    the observed cooperation rate of opponents, with additional 
    thresholds for stock sustainability and final round defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        n_opponents_cooperating = history.opponent_cooperators[last_round_idx]
        i_cooperated = history.my_actions[last_round_idx]
        total_cooperators = n_opponents_cooperating + (1 if i_cooperated else 0)
        if history.round_number == self.n_rounds - 1:
            if current_stock >= self.capacity / 2.0:
                return Action.C
            else:
                return Action.D
        if current_stock < 0.05:
            return Action.D
        if current_stock < self.capacity * 0.5:
            return Action.D
        if current_stock >= self.capacity * 0.95 and total_cooperators == self.n:
            return Action.C
        if total_cooperators >= self.n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_127(BaseStrategy):
    """
    A strategy that maintains cooperation based on stock levels and opponent cooperation.
    - Cooperates initially.
    - Defects if stock is critically low (unless recovering).
    - Uses probabilistic cooperation when stock is healthy.
    - Punishes defectors.
    - Forgives/Resets if stock recovers after sustained defection.
    - Defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_defections = 0
        self.just_performed_reset = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        n = self.game_description.n_players
        n_opponents = n - 1
        capacity = self.game_description.capacity
        prev_k = history.opponent_cooperators[-1]
        x = prev_k / n_opponents if n_opponents > 0 else 0.0
        last_my_action = history.my_actions[-1]
        if not last_my_action:
            self.consecutive_defections += 1
        else:
            self.consecutive_defections = 0
            self.just_performed_reset = False
        if current_stock < 0.05 * capacity:
            return Action.D
        if self.consecutive_defections >= 3 and current_stock > 0.5 * capacity:
            self.just_performed_reset = True
            return Action.C
        if current_stock < 0.5 * capacity:
            if x > 0.8:
                return Action.C
            else:
                return Action.D
        if x >= 1.0:
            return Action.C
        elif x > 0.5:
            return Action.C if random.random() < x else Action.D
        else:
            return Action.D

class Strategy_COLLECTIVE_128(BaseStrategy):
    """
    Implements a conditional cooperative strategy for the Common Pool Resource game.
    The strategy balances sustainability and exploitation prevention using adaptive
    reciprocity based on the previous round's cooperation levels and current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            if current_stock > 0.5 * self.capacity:
                return Action.D
            return Action.C
        last_round_idx = -1
        last_opp_coop = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        total_coop_count = last_opp_coop + (1 if my_last_action else 0)
        if current_stock < 0.25 * self.capacity:
            return Action.C
        if total_coop_count > self.n / 2:
            return Action.C
        if current_stock > 0.4 * self.capacity:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_33(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    1. Initial Phase: Always starts with Cooperation (C) in Round 1.
    2. Terminal Phase: Cooperates if the stock is healthy (>= 25% capacity), otherwise defects.
    3. Intermediate Phases:
       - Healthy Stock (>= 50% capacity): Prioritizes Cooperation (C).
       - Unhealthy Stock (< 50% capacity): Uses a conditional trigger (Tit-for-Tat). 
         If most opponents (>= n-1) cooperated in the previous round, maintains C.
         Otherwise, defects (D) to reduce consumption pressure.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r = history.round_number
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        if r == 0:
            return Action.C
        if r == total_rounds - 1:
            if current_stock >= 0.25 * capacity:
                return Action.C
            else:
                return Action.D
        if current_stock >= 0.5 * capacity:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        if prev_opp_coop >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_34(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource game.
    Implements a Tit-for-Tat variant with resource-aware recovery and defensive defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        total_rounds = self.r
        if round_t == total_rounds - 1:
            return Action.D
        if round_t == 0:
            return Action.C
        if current_stock < self.n:
            return Action.D
        prev_k = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if prev_k > self.n / 2:
            return Action.C
        else:
            if current_stock >= self.capacity * 0.8:
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_35(BaseStrategy):
    """
    A conditional, trigger-based cooperative strategy for the Common Pool Resource Game.
    
    Logic:
    1. First Round: Always Cooperate (C).
    2. Final Round: Always Defect (D).
    3. Resource Collapse Threshold: If current stock S < capacity / (2 * n), Defect (D) to secure share.
    4. Reciprocity: If S >= capacity / (2 * n), cooperate if previous cooperation rate >= 0.5, else Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.num_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        threshold = self.capacity / (2 * self.n)
        if current_stock < threshold:
            return Action.D
        if self.num_opponents <= 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        cooperation_rate = prev_cooperators / self.num_opponents
        if cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_36(BaseStrategy):
    """
    A modified Tit-for-Tat strategy with forgiveness and stock-dependent constraints.
    Prioritizes sustainability when possible, switches to survival (Defection) when 
    the resource is critically depleted, and uses probabilistic cooperation based on 
    the observed cooperation rate of the group.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.critical_threshold = self.capacity / 4.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            if current_stock >= self.critical_threshold:
                return Action.C
            else:
                return Action.D
        if current_stock < self.critical_threshold:
            return Action.D
        last_action = history.my_actions[-1]
        if last_action == Action.D:
            if current_stock >= 0.5 * self.capacity:
                return Action.C
        my_last_action_val = 1 if history.my_actions[-1] == Action.C else 0
        total_cooperators = my_last_action_val + history.opponent_cooperators[-1]
        ocr_prev = total_cooperators / self.n
        if ocr_prev == 1.0:
            return Action.C
        elif 0.0 < ocr_prev < 1.0:
            if random.random() < ocr_prev:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_PROSOCIAL_37(BaseStrategy):
    """
    A conditional cooperation strategy based on a Tit-for-Tat variant.
    It attempts to maintain stock at capacity by dynamically adjusting the 
    cooperation threshold based on current stock levels and punishing 
    defection probabilistically.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if current_stock >= self.capacity * 0.95:
            prev_coops = history.opponent_cooperators[-1]
            if prev_coops / self.n >= 0.75:
                return Action.C
        if current_stock < self.capacity * 0.2:
            return Action.D
        normalized_stock = current_stock / self.capacity if self.capacity > 0 else 0
        threshold = 0.5 + 0.5 * normalized_stock
        prev_cooperators = history.opponent_cooperators[-1]
        proportion_cooperated = prev_cooperators / self.n
        if proportion_cooperated >= threshold:
            return Action.C
        else:
            punishment_chance = 1.0 - proportion_cooperated
            if random.random() < punishment_chance:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_38(BaseStrategy):
    """
    Implements a Target-Stock Tit-for-Tat strategy.
    
    This strategy calculates the required number of cooperators to maintain 
    the common pool resource at a sustainable level (K/2). It acts adaptively
    to signal cooperation while protecting personal payoff if the group 
    fails to maintain the required threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        k_max = self.game_description.capacity
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r_total - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < k_max / 2:
            return Action.C
        target_k = n * k_max / current_stock
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if total_cooperators_prev >= target_k:
            return Action.C
        else:
            if random.random() < total_cooperators_prev / n:
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_39(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource game.
    
    The strategy:
    - Always cooperates in the first round.
    - In subsequent rounds (except the last), it tracks the cooperation fraction of opponents.
      - If the fraction of cooperative opponents is >= 0.5, it reciprocates cooperation.
      - If below 0.5, it cooperates only if the stock is > 50% of capacity (pro-social buffering),
        otherwise it defects to protect individual share.
    - In the final round, it defects if the stock is positive, otherwise cooperates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round_index == 0:
            return Action.C
        if current_round_index == n_rounds - 1:
            return Action.D if current_stock > 0 else Action.C
        k = history.opponent_cooperators[-1]
        n_opponents = n_players - 1
        if n_opponents == 0:
            return Action.C
        cf = k / n_opponents
        if cf >= 0.5:
            return Action.C
        threshold = 0.5 * capacity
        if current_stock > threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_40(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with Sustainability Thresholding.
    
    Strategy Overview:
    - Round 0: Always cooperates (C).
    - Recovery Mode (S < capacity * 0.5): Always cooperates (C) to allow stock recovery.
    - Steady State Mode (S >= capacity * 0.5): 
        - Cooperates (C) if at least 50% of opponents cooperated in the previous round.
        - Defects (D) if fewer than 50% of opponents cooperated.
    - Terminal Phase (Final Round):
        - Defects (D) if S >= capacity * 0.5 (extracting value).
        - Cooperates (C) if S < capacity * 0.5 (prosocial gesture).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = self.capacity * 0.5
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            if current_stock >= self.threshold:
                return Action.D
            else:
                return Action.C
        if current_stock < self.threshold:
            return Action.C
        if self.n_opponents == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        cooperation_ratio = prev_opp_coop / self.n_opponents
        if cooperation_ratio >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_41(BaseStrategy):
    """
    Implements a Trigger-Based Tit-for-Tat strategy with sustainability thresholds.
    
    Logic:
    - Terminal Phase (last 3 rounds): Cooperate if stock > 50% capacity, else Defect.
    - Round 0: Always Cooperate.
    - Crisis Management (stock < 25% capacity): Defect to maximize immediate payoff.
    - Standard Rounds: Probabilistic Tit-for-Tat based on observed cooperation count of opponents.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.t_threshold = 0.5 * self.capacity
        self.crisis_threshold = 0.25 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if total_rounds - current_round <= 3:
            if current_stock > self.t_threshold:
                return Action.C
            else:
                return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.crisis_threshold:
            return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if n_opponents == 0:
            return Action.C
        cooperation_ratio = last_round_cooperators / n_opponents
        if random.random() < cooperation_ratio:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_42(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Stock Sensitivity:
    - Always cooperates in the first round.
    - If stock is healthy (> 50% capacity), cooperates.
    - If stock is low (<= 50% capacity), cooperates only if the group 
      cooperation rate in the previous round exceeds 75% of opponents.
    - In the last round, cooperates if stock is > 20% capacity, otherwise defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.cooperation_threshold = math.ceil((self.n - 1) * 0.75)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        current_round = round_idx + 1
        if current_round == 1:
            return Action.C
        if current_round == self.r:
            if current_stock > 0.2 * self.capacity:
                return Action.C
            else:
                return Action.D
        if current_stock > 0.5 * self.capacity:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_43(BaseStrategy):
    """
    A growth-conscious Tit-for-Tat strategy that adapts to common pool resource stock levels.
    It targets maximum sustainable capacity while punishing defections, adjusting its
    cooperation threshold dynamically based on observed opponent behavior and stock health.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        capacity = self.game_description.capacity
        my_prev_action = history.my_actions[-1]
        if k_prev < self.cooperation_threshold and my_prev_action:
            self.cooperation_threshold = min(n_opponents, self.cooperation_threshold + 1)
        elif k_prev == n_opponents:
            self.cooperation_threshold = max(0, self.cooperation_threshold - 1)
        elif k_prev < n_opponents:
            self.cooperation_threshold = n_opponents
        if current_stock < 0.5 * capacity:
            if k_prev >= n_opponents:
                return Action.C
            else:
                return Action.D
        elif k_prev >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_44(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Capacity Thresholding.
    Prioritizes sustainability when stock is low, uses Tit-for-Tat to encourage 
    cooperation when stock is healthy, and periodically forces cooperation 
    to break cycles of defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.tau = self.game_description.capacity / 2
        self.tft_threshold = (self.game_description.n_players - 1) // 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.tau:
            return Action.C
        if (current_round + 1) % 3 == 0:
            return Action.C
        k = history.opponent_cooperators[-1]
        if k >= self.tft_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_45(BaseStrategy):
    """
    A modified Tit-for-Tat strategy for the Common Pool Resource game.
    
    Logic:
    - Round 1: Cooperate (C).
    - End-game: If round == total rounds, defect (D) if current stock < 10% of capacity, else cooperate (C).
    - Recovery: If current stock < 50% of capacity, defect (D) to recover position.
    - Standard Rounds: Cooperate (C) if the number of cooperators in the previous round 
      was >= ceil(n/2), otherwise defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.threshold = math.ceil(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            if current_stock < 0.1 * self.capacity:
                return Action.D
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.D
        prev_cooperators = int(history.opponent_cooperators[-1])
        if prev_cooperators >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_46(BaseStrategy):
    """
    A conditional cooperative strategy that plays 'C' initially, then mirrors
    aggregate opponent cooperation rates using a 0.5 threshold. 
    It includes an emergency override for low stock scenarios and optimizes 
    actions for the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.tau = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        s_crit = self.capacity / (2 * self.n)
        if current_stock < s_crit:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        last_cooperators_count = history.opponent_cooperators[last_round_idx]
        if history.round_number == self.r:
            if current_stock > self.capacity / (4 * self.n):
                n_opponents = self.n - 1
                if n_opponents > 0:
                    if last_cooperators_count >= n_opponents / 2:
                        return Action.C
            return Action.D
        n_opponents = self.n - 1
        if n_opponents > 0:
            opponent_cooperation_rate = last_cooperators_count / n_opponents
            if opponent_cooperation_rate >= self.tau:
                return Action.C
        return Action.D

class Strategy_PROSOCIAL_47(BaseStrategy):
    """
    A reciprocity-based strategy for the Common Pool Resource game.
    
    Logic:
    1. First round: Always Cooperate (C).
    2. Survival check: If stock < capacity/n, Defect (D).
    3. Standard Reciprocity (rounds 1 to r-2):
       - CI = avg(opponents_who_cooperated / (n-1)) over history.
       - If CI >= 0.5, Cooperate (C).
       - Else, Defect (D).
    4. Terminal Round (final round):
       - If avg CI over entire history > 0.8, Cooperate (C).
       - Else, Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        n_opponents = n - 1
        if round_idx == 0:
            return Action.C
        critical_threshold = self.game_description.capacity / n
        if current_stock < critical_threshold:
            return Action.D
        if n_opponents > 0:
            coop_ratios = history.opponent_cooperators / n_opponents
            avg_ci = np.mean(coop_ratios)
        else:
            avg_ci = 1.0
        if round_idx == total_rounds - 1:
            if avg_ci > 0.8:
                return Action.C
            else:
                return Action.D
        if avg_ci >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_48(BaseStrategy):
    """
    Implements a 'Conditional Tit-for-Tat with Resilience' strategy.
    
    The strategy focuses on sustainability:
    1. Always cooperates in the first round.
    2. Maintains a persistent internal state ('is_punishing') to track if it is currently 
       in a punishment phase due to prior depletion of the resource.
    3. If currently punishing, it checks if the stock has recovered to at least 90% 
       of capacity before resuming cooperation.
    4. If not punishing, it checks the cooperation level of others in the previous round.
       - If everyone cooperated, it continues cooperating.
       - If there was defection, it checks if the stock is critically low (below 1/2n of capacity).
         If so, it triggers the punishment phase (switching to D).
    5. Implements a terminal round exception: if it's the last round, it stops cooperating 
       if the stock is below half capacity, as there is no future incentive to preserve it.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_punishing = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if rounds_remaining == 1:
            if current_stock >= self.game_description.capacity / 2:
                return Action.C
            else:
                return Action.D
        if self.is_punishing:
            if current_stock >= 0.9 * self.game_description.capacity:
                self.is_punishing = False
                return Action.C
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        k_total = k_prev + (1 if my_prev_action else 0)
        if k_total == self.game_description.n_players:
            return Action.C
        else:
            critical_threshold = self.game_description.capacity / (2 * self.game_description.n_players)
            if current_stock < critical_threshold:
                self.is_punishing = True
                return Action.D
            return Action.C

class Strategy_PROSOCIAL_49(BaseStrategy):
    """
    Adaptive Sustainability Threshold (AST) strategy:
    A Tit-for-Tat foundation modified by the current state of the resource pool.
    
    Logic:
    1. First round: Always Cooperate (C).
    2. Last round: If stock >= 50% capacity, C; else D.
    3. Intermediate rounds:
       - If stock < 25% capacity: Defect (D).
       - If stock >= 25% capacity: Check cooperation density of opponents.
         - If >= 50% of opponents cooperated last round: C.
         - Else: D.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        if history.round_number == r - 1:
            if current_stock >= 0.5 * capacity:
                return Action.C
            else:
                return Action.D
        if current_stock < 0.25 * capacity:
            return Action.D
        n_opponents = n - 1
        if n_opponents == 0:
            return Action.C
        opponents_cooperated = history.opponent_cooperators[-1]
        cooperation_ratio = opponents_cooperated / n_opponents
        if cooperation_ratio >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_50(BaseStrategy):
    """
    Threshold-Based Conditional Reciprocity (TCR):
    A strategy that adapts its cooperation threshold based on current stock levels 
    and group behavior, prioritizing sustainability and recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.last_stock = current_stock
            return Action.C
        prev_round_cooperators = int(history.opponent_cooperators[-1])
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_coop_count = prev_round_cooperators + my_prev_action
        stock_falling = current_stock < self.last_stock
        self.last_stock = current_stock
        if history.round_number >= self.r - 3:
            if current_stock < 0.2 * self.capacity:
                return Action.D
        if current_stock < 0.2 * self.capacity:
            return Action.D
        if 0.2 * self.capacity <= current_stock < 0.5 * self.capacity:
            if total_coop_count >= self.n:
                return Action.C
            return Action.D
        if current_stock >= 0.5 * self.capacity:
            threshold = math.ceil(self.n / 2)
            if stock_falling:
                threshold += 1
            if total_coop_count >= threshold:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_PROSOCIAL_51(BaseStrategy):
    """
    A Trigger-Corrected Tit-for-Tat strategy that balances resource conservation 
    with defect-based protection during end-game or system-collapse scenarios.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0.0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        remaining_rounds = self.total_rounds - history.round_number
        if remaining_rounds <= 3:
            if current_stock < 0.25 * self.capacity:
                return Action.D
            elif current_stock > 0.75 * self.capacity:
                return Action.C
        if current_stock >= 0.95 * self.capacity:
            return Action.C
        last_opponents_cooperated = history.opponent_cooperators[-1]
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators = last_opponents_cooperated + my_last_action_val
        if total_cooperators >= self.n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_52(BaseStrategy):
    """
    A sustainable resource management strategy that adjusts strictness based on pool health.
    It targets a capacity-maximizing stock level S_star and uses a threshold T to decide 
    whether to cooperate. T adjusts dynamically: it tightens when the pool is struggling 
    and relaxes when the pool is thriving.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.T = 1
        self.s_star = game_description.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        if current_round == 1:
            self.T = 1
            return Action.C
        if current_round == total_rounds:
            return Action.D
        if current_stock < self.game_description.capacity * 0.1:
            return Action.D
        prev_round_idx = history.round_number - 1
        k_prev = history.opponent_cooperators[prev_round_idx]
        if k_prev >= self.T:
            if current_stock < self.s_star * 0.8 and self.T < self.game_description.n_players:
                self.T += 1
            elif current_stock >= self.s_star * 1.2 and self.T > 1:
                self.T -= 1
            return Action.C
        else:
            self.T = 1
            return Action.D

class Strategy_PROSOCIAL_53(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness strategy for the Common Pool Resource game.
    
    This strategy prioritizes sustainability:
    1. Always cooperates in the first round.
    2. In subsequent rounds, maintains cooperation if a near-unanimous group 
       cooperation threshold (n-1) is met.
    3. If cooperation falls below (n-1), it uses the current stock level as a buffer:
       - If stock > 50% capacity, it forgives and cooperates to nudge the group back.
       - If stock <= 50% capacity, it defects to prioritize self-preservation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        last_cooperators = history.opponent_cooperators[-1]
        is_final_round = history.round_number == self.game_description.n_rounds - 1
        if not is_final_round:
            if last_cooperators >= self.cooperation_threshold:
                return Action.C
            if current_stock > self.game_description.capacity * 0.5:
                return Action.C
            else:
                return Action.D
        elif last_cooperators >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_54(BaseStrategy):
    """
    A conditionally cooperative trigger strategy for the Common Pool Resource game.
    
    Logic:
    - Round 1: Cooperates (C).
    - Rounds 2 to r-1: 
        - Cooperates if the count of cooperating opponents in the previous round 
          is >= (n - 1) * 0.5.
        - Defects otherwise.
        - Exception: If current stock < capacity / (2 * n), always cooperates (C).
    - Final Round (r): 
        - If current stock < capacity / 2, cooperates (C).
        - Otherwise, defects (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.cooperation_threshold = (self.n - 1) * 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        if current_round == self.r:
            if current_stock < self.capacity / 2:
                return Action.C
            else:
                return Action.D
        prev_opp_C = history.opponent_cooperators[-1]
        if current_stock < self.capacity / (2 * self.n):
            return Action.C
        if prev_opp_C >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_55(BaseStrategy):
    """
    Trigger-Tit-for-Tat with Recovery:
    Cooperate initially, maintain cooperation if the resource is healthy and opponents cooperate,
    or if the stock is below a recovery threshold. Probabilistically retaliate against defectors
    when the resource is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == self.n_rounds - 1:
            if current_stock >= self.capacity / self.n:
                return Action.D
            else:
                return Action.C
        if current_stock < self.capacity / 2.0:
            return Action.C
        if t == 0:
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if current_stock < self.capacity / (2.0 * self.n):
            return Action.C
        if k_prev == n_opponents:
            return Action.C
        if n_opponents > 0:
            p_defect = 1.0 - k_prev / float(n_opponents)
            if random.random() < p_defect:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_PROSOCIAL_56(BaseStrategy):
    """
    Tit-for-Tat with a Forgiving Threshold strategy.
    
    This strategy focuses on sustainability:
    1. Always cooperate in the first round.
    2. Monitor stock levels relative to capacity.
    3. If stock is critical (< capacity/2), prioritize preservation unless opponents defect aggressively.
    4. If stock is healthy (>= capacity/2), use a stochastic response to defection (tit-for-tat variant).
    5. Detect recovery trends to switch to unconditional cooperation.
    6. Implement specific terminal round logic.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.stock_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.stock_history.append(current_stock)
        round_t = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        n_opponents = self.n - 1
        if round_t == 1:
            return Action.C
        if round_t == total_rounds:
            return Action.D if current_stock >= 2 * self.n else Action.C
        if current_stock < 1:
            return Action.D
        if len(self.stock_history) >= 4:
            if self.stock_history[-1] > self.stock_history[-2] > self.stock_history[-3] > self.stock_history[-4]:
                return Action.C
        k_prev = history.opponent_cooperators[-1]
        r_prev = k_prev / n_opponents if n_opponents > 0 else 1.0
        if current_stock < self.capacity / 2:
            return Action.C if r_prev >= 0.5 else Action.D
        if k_prev == n_opponents:
            return Action.C
        else:
            prob_defect = 1.0 - r_prev
            if random.random() < prob_defect:
                return Action.D
            return Action.C

class Strategy_PROSOCIAL_57(BaseStrategy):
    """
    Conditional Reciprocity with Stock Thresholds:
    - Prioritizes preservation when stock is critically low.
    - Cooperates in the first round.
    - Reciprocates group cooperation levels from the previous round.
    - Uses punishment/recovery logic when group cooperation drops below a threshold (n-1).
    - Modifies behavior in the final round based on stock status.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if current_stock <= 0:
            return Action.D
        if current_stock < self.capacity * 0.1:
            return Action.C
        if t == self.r:
            return Action.D if current_stock > self.capacity * 0.1 else Action.C
        if t == 1:
            return Action.C
        c_prev = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators_prev = c_prev + (1 if my_prev_action else 0)
        if total_cooperators_prev >= self.n - 1:
            return Action.C
        else:
            return Action.D if current_stock >= self.capacity * 0.25 else Action.C

class Strategy_PROSOCIAL_58(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and dynamic thresholds.
    Target: Maintain stock at capacity/2. Cooperates if stock is sufficient,
    punishes defectors based on a majority threshold, and adjusts for forgiveness.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.penalty_adjustment = 0
        self.consecutive_low_stock_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_stock = current_stock
        if current_stock < capacity / 2:
            self.consecutive_low_stock_rounds += 1
        else:
            self.consecutive_low_stock_rounds = 0
        if self.consecutive_low_stock_rounds >= 2:
            self.penalty_adjustment = min(self.penalty_adjustment + 1, math.ceil((n - 1) / 2))
        else:
            self.penalty_adjustment = 0
        if current_round == r - 1:
            return Action.C if current_stock >= capacity / 2 else Action.D
        if current_stock < capacity / (10 * n):
            if r - current_round <= 5:
                return Action.D
        if current_stock < capacity / 2:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        n_opponents = n - 1
        base_threshold = math.ceil(n_opponents / 2)
        threshold = max(0, base_threshold - self.penalty_adjustment)
        if k_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_59(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Stock Stewardship.

    This strategy prioritizes long-term stock sustainability while employing 
    reactive enforcement against defectors. It balances between:
    1. Stock Recovery: If stock is low, prioritize cooperation.
    2. Tit-for-Tat Punishment: If others defect, punish to recoup relative value.
    3. Terminal Greed: Defect in the final round unless group cohesion is observed.
    4. Adaptive Defection: Permanently switch to defection if the group is locked in 
       mutual defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_permanently_defecting = False
        self.low_coop_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        cap = self.game_description.capacity
        round_t = history.round_number
        is_last_round = round_t == r - 1
        last_total_coop = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        last_k = last_total_coop if not last_my_action else last_total_coop - 1
        if last_k < n // 2:
            self.low_coop_streak += 1
        else:
            self.low_coop_streak = 0
        if self.low_coop_streak >= 3:
            self.is_permanently_defecting = True
        if is_last_round:
            if last_k >= n - 2 and current_stock > 0:
                return Action.C
            return Action.D if current_stock > 0 else Action.C
        if current_stock < 0.1 * cap:
            return Action.C
        if last_k < n // 2:
            return Action.C
        if self.is_permanently_defecting:
            return Action.D
        if current_stock < 0.5 * cap:
            return Action.C
        if last_k < n - 2:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_60(BaseStrategy):
    """
    A Tit-for-Tat variant strategy utilizing "Win-Stay, Lose-Shift" logic with adaptive thresholds.
    - Cooperates in the first round.
    - In subsequent rounds (t < r), uses a reciprocity trigger: if >= 50% of opponents cooperated in the 
      previous round, Cooperate; otherwise, Defect.
    - Safety Valve: If current stock < 25% of capacity, forces Cooperation.
    - Final Round (t = r): Cooperates if the average cooperation rate of opponents throughout 
      previous rounds was >= 50%; otherwise, Defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1
        self.crit_threshold = self.game_description.capacity * 0.25

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            if current_round > 0:
                avg_cooperation_rate = np.mean(history.opponent_cooperators) / self.n_opponents
            else:
                avg_cooperation_rate = 0.0
            if avg_cooperation_rate < 0.5:
                return Action.D
            return Action.C
        if current_stock < self.crit_threshold and current_stock > 1e-09:
            return Action.C
        if self.n_opponents > 0:
            prev_opp_coop = history.opponent_cooperators[-1]
            if prev_opp_coop / self.n_opponents >= 0.5:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_PROSOCIAL_61(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness. 
    Prioritizes sustainability, punishing defection probabilistically when the stock is healthy,
    and switching to cooperation when the stock is critical.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.num_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < 1e-06:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock < self.capacity / 2:
                return Action.C
            else:
                return Action.D
        if current_stock < self.capacity / 2:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        if prev_opp_coop >= self.num_opponents:
            return Action.C
        else:
            num_defectors = self.num_opponents - prev_opp_coop
            probability_to_defect = num_defectors / self.num_opponents
            if random.random() < probability_to_defect:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_62(BaseStrategy):
    """
    Adaptive Logistic Stewardship: A Tit-for-Tat based strategy aimed at maintaining
    the common pool stock. It cooperates when the majority of the group is
    prosocial, defects if the resource collapses to critical levels (survival
    mode), and plays the last round selfishly if the resource is below the
    quarter-capacity threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock >= self.capacity / 4.0:
                return Action.C
            else:
                return Action.D
        if current_stock <= self.capacity / (2.0 * self.n):
            return Action.D
        last_round_idx = history.round_number - 1
        others_cooperated = history.opponent_cooperators[last_round_idx]
        my_previous_action = history.my_actions[last_round_idx]
        total_cooperators = others_cooperated + (1 if my_previous_action else 0)
        if total_cooperators >= self.n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_63(BaseStrategy):
    """
    Tit-for-Tat Adaptive Thresholding Strategy.
    
    Maintains cooperation while penalizing defectors proportionally to their impact,
    using the observed cooperation rate to adjust behavior dynamically. Switches to 
    Defect if the stock falls below critical levels or if cooperation rates are low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number == self.r - 1:
            if current_stock < self.capacity / (2 * self.n):
                return Action.D
            return Action.C
        c_observed = int(history.opponent_cooperators[-1])
        if self.n_opponents > 0:
            rate = c_observed / self.n_opponents
        else:
            rate = 1.0
        if current_stock < self.capacity / self.n:
            if rate == 1.0:
                return Action.C
            return Action.D
        if rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_64(BaseStrategy):
    """
    Implements a conditional cooperation strategy ("Tit-for-Tat with Forgiveness")
    designed to maintain a Common Pool Resource.
    
    Strategy:
    1. Terminal Phase: If in the last round, prioritize sustainability if resource
       is healthy (>= 50% capacity), otherwise maximize payoff via defection.
    2. Rescue Phase: If stock is critical (< 25% capacity), force Defection to
       capture remaining value.
    3. Initialization: Cooperate on Round 1.
    4. Tit-for-Tat: Calculate cooperation rate of opponents. If > 0.5, cooperate.
       If <= 0.5, defect, but offer "forgiveness" (cooperate) if we defected
       in the immediate previous round to recover the relationship.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            if current_stock >= 0.5 * self.capacity:
                return Action.C
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if round_idx == 0:
            return Action.C
        opponents_count = self.n - 1
        cooperation_rate = history.opponent_cooperators[-1] / opponents_count
        if cooperation_rate > 0.5:
            return Action.C
        else:
            if not history.my_actions[-1]:
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_65(BaseStrategy):
    """
    Tit-for-Tat with Resilience Threshold strategy.
    Maintains the pool via conditional cooperation and punishes defectors based on sustainability scores.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.ss = 0.0
        self.last_stock = float(self.capacity)

    def _estimate_defectors(self, s_prev: float, s_new: float) -> int:
        """
        Reverses the dynamics to estimate the number of defectors in the previous round.
        Dynamics:
        S_new = S_rem + 2 * S_rem * (1 - S_rem / C)
        S_new = S_rem + 2*S_rem - (2 * S_rem^2 / C)
        S_new = 3*S_rem - (2 * S_rem^2 / C)
        (2/C) * S_rem^2 - 3 * S_rem + S_new = 0
        Using quadratic formula: ax^2 + bx + c = 0 where x = S_rem
        a = 2/C, b = -3, c = S_new
        x = (-b +/- sqrt(b^2 - 4ac)) / 2a
        """
        if s_prev <= 0:
            return self.n - 1
        a = 2.0 / self.capacity
        b = -3.0
        c = s_new
        discriminant = b ** 2 - 4 * a * c
        if discriminant < 0:
            s_rem = 0.0
        else:
            root1 = (-b + math.sqrt(discriminant)) / (2 * a)
            root2 = (-b - math.sqrt(discriminant)) / (2 * a)
            s_rem = root2 if root2 <= s_prev else root1
        total_consumption = s_prev - s_rem
        if s_prev == 0:
            return self.n
        d_val = total_consumption * 2.0 * self.n / s_prev - self.n
        return int(max(0, min(self.n, round(d_val))))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            self.last_stock = float(self.capacity)
            return Action.C
        d = self._estimate_defectors(self.last_stock, current_stock)
        self.ss += self.n - 2 * d
        self.last_stock = current_stock
        if round_idx == self.game_description.n_rounds:
            return Action.C if self.ss >= 0 else Action.D
        if self.ss < -self.n:
            return Action.D
        if current_stock < self.capacity / 4.0:
            return Action.C
        if d == 0:
            return Action.C
        if random.random() < d / self.n:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_66(BaseStrategy):
    """
    Threshold-Conditioned Tit-for-Tat strategy for the Common Pool Resource Game.
    Prioritizes sustainability when stock is high, and mimics defectors when stock is low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.s_crit = self.capacity / 2.0
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock > 1e-09:
                return Action.D
            else:
                return Action.C
        if current_stock < 1e-09:
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        if current_stock < self.s_crit:
            if prev_k < self.n_opponents:
                return Action.D
            else:
                return Action.C
        else:
            defectors_observed = self.n_opponents - prev_k
            tolerance = math.floor(self.n / 3)
            if defectors_observed > tolerance:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_67(BaseStrategy):
    """
    A Tit-for-Tat variant that stabilizes resource stock by monitoring 
    opponent cooperation levels and managing the pool against threshold depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_defections = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if current_stock <= 0:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        if current_stock < capacity * 0.25:
            return Action.D
        if self.consecutive_defections > 2:
            if current_stock > capacity * 0.1:
                return Action.C
            else:
                self.consecutive_defections += 1
                return Action.D
        if t == r - 1:
            if k_prev >= n - 1:
                return Action.C
            else:
                return Action.D
        threshold = math.floor(n / 2) + 1
        if k_prev >= threshold:
            self.consecutive_defections = 0
            return Action.C
        else:
            self.consecutive_defections += 1
            return Action.D

class Strategy_PROSOCIAL_68(BaseStrategy):
    """
    Adaptive cooperation strategy for Common Pool Resource games.
    Monitors population cooperation levels and adjusts threshold for cooperation 
    based on observed stock health and historical partner behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.alpha = 0.8
        self.h_coop = 1.0
        self.d_threshold = 0.5
        self.last_defect_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_idx = -1
        my_prev_action = history.my_actions[prev_idx]
        prev_n_coop = history.opponent_cooperators[prev_idx] + (1 if my_prev_action else 0)
        self.h_coop = self.alpha * self.h_coop + (1.0 - self.alpha) * (prev_n_coop / self.n)
        if self.h_coop < 0.3:
            self.d_threshold = 0.6
        elif self.h_coop > 0.8:
            self.d_threshold = 0.4
        if current_stock < self.capacity / self.n:
            return Action.D
        rounds_remaining = self.n - 1 - history.round_number
        if rounds_remaining < 2:
            if self.h_coop >= 0.5:
                return Action.C
            else:
                return Action.D
        if self.h_coop >= self.d_threshold:
            return Action.C
        else:
            if history.round_number - self.last_defect_round > 2:
                self.last_defect_round = history.round_number
                return Action.D
            return Action.C

class Strategy_PROSOCIAL_69(BaseStrategy):
    """
    Tit-for-Tat with Resource-Based Threshold Adjustment:
    Maintains cooperation if the group is sustainable, defects if the resource
    is critical, and always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / self.n - 1e-09:
            return Action.D
        prev_my_cooperated = history.my_actions[-1]
        prev_opp_cooperated = history.opponent_cooperators[-1]
        total_cooperators_prev = (1 if prev_my_cooperated else 0) + prev_opp_cooperated
        if total_cooperators_prev >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_70(BaseStrategy):
    """
    A strategy that maintains an internal trust metric of opponents,
    adjusting behavior based on resource stock levels and observed
    cooperation rates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_level = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r_current = history.round_number
        if r_current == 0:
            return Action.C
        if r_current == self.game_description.n_rounds - 1:
            return Action.C
        prev_round = r_current - 1
        total_cooperators = history.opponent_cooperators[prev_round]
        my_last_action = history.my_actions[prev_round]
        n_opponents = self.game_description.n_players - 1
        if my_last_action == Action.C:
            count_opp_coop = max(0, total_cooperators - 1)
        else:
            count_opp_coop = total_cooperators
        if n_opponents > 0:
            c_obs = count_opp_coop / n_opponents
        else:
            c_obs = 0.0
        self.trust_level = 0.7 * self.trust_level + 0.3 * c_obs
        if current_stock < self.game_description.capacity / self.game_description.n_players:
            return Action.C
        n = self.game_description.n_players
        cap = self.game_description.capacity
        is_high_trust = self.trust_level > 0.4
        is_sufficient_stock = current_stock > cap / (2 * n)
        is_critically_low_stock = current_stock < cap / (2 * n)
        if is_high_trust and is_sufficient_stock:
            return Action.C
        elif not is_high_trust:
            if is_critically_low_stock:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_PROSOCIAL_71(BaseStrategy):
    """
    Proportional Sustenance strategy: Maintains cooperation when stock is high (sustainability index > 0.5)
    or when group behavior demonstrates collective effort (majority cooperated in previous round).
    Switches to defect to protect utility when stock is low and others are defecting, 
    and adapts in the final phase to prioritize remaining resource capture.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.cooperation_threshold_k = math.ceil(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx >= self.r - 2:
            if current_stock > 0.2 * self.capacity:
                return Action.C
            else:
                return Action.D
        if current_round_idx == 0:
            return Action.C
        sustainability_index = current_stock / self.capacity
        if sustainability_index > 0.5:
            return Action.C
        else:
            my_last_action = int(history.my_actions[-1])
            opponent_cooperators = int(history.opponent_cooperators[-1])
            total_cooperators = my_last_action + opponent_cooperators
            if total_cooperators >= self.cooperation_threshold_k:
                return Action.C
            else:
                return Action.D

class Strategy_PROSOCIAL_72(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with resource-aware thresholding.
    Prioritizes sustainability when stock is low, tit-for-tat retaliation
    during normal play, and strategic defection in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < self.game_description.capacity * 0.25:
            return Action.C
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock >= self.game_description.capacity * 0.5:
                return Action.D
            else:
                return Action.C
        prev_round_cooperators = int(history.opponent_cooperators[-1])
        if self.n_opponents <= 0:
            return Action.C
        defectors_observed = self.n_opponents - prev_round_cooperators
        if defectors_observed == 0:
            return Action.C
        prob_defect = defectors_observed / self.n_opponents
        if random.random() < prob_defect:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_73(BaseStrategy):
    """
    Adaptive Sustainable Tit-for-Tat (ASTFT)
    
    This strategy prioritizes sustainability through dynamic thresholds based on 
    resource stock and reciprocating previous group behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == r - 1:
            if current_stock < 0.25 * capacity:
                return Action.C
            return Action.D
        if current_stock < capacity / n:
            return Action.C
        prev_round_idx = current_round_idx - 1
        my_prev_action_val = 1 if history.my_actions[prev_round_idx] else 0
        total_cooperators = history.opponent_cooperators[prev_round_idx] + my_prev_action_val
        if current_stock < 0.1 * capacity:
            threshold = n
        else:
            threshold = math.ceil(n * 0.75)
        if total_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_74(BaseStrategy):
    """
    Conditional Sustainability Threshold (CST) Strategy.
    Prioritizes resource preservation while punishing defectors, adjusting behavior
    based on the state of the common pool resource.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_group_defections = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == r - 1:
            return Action.D
        if current_stock < 0.05 * capacity:
            return Action.D
        if t == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_coop_val = 1 if my_prev_action else 0
        total_cooperators = prev_opp_coop + my_coop_val
        total_defectors = n - total_cooperators
        if total_defectors == n - 1:
            self.consecutive_group_defections += 1
        else:
            self.consecutive_group_defections = 0
        if self.consecutive_group_defections >= 2:
            return Action.D
        D_prev = n_opponents - prev_opp_coop
        if D_prev == 0:
            return Action.C
        if current_stock > 0.5 * capacity:
            if D_prev < 0.25 * n:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_PROSOCIAL_75(BaseStrategy):
    """
    A Tit-for-Tat variant with a probabilistic threshold based on stock maintenance.
    It prioritizes stock regeneration when the resource is critically low (< capacity/2),
    otherwise it mirrors the majority behavior of opponents (reciprocal cooperation).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock <= 1e-09:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        num_opponents = self.n - 1
        majority_threshold = math.ceil(num_opponents / 2)
        majority_cooperating = k_prev >= majority_threshold
        stock_critically_low = current_stock < self.capacity / 2
        if majority_cooperating or stock_critically_low:
            return Action.C
        if current_stock >= self.capacity / 2:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_76(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with forgiveness and stock-sensitivity.
    Prioritizes resource sustainability by defecting when the stock is critically low.
    Maintains cooperation in stable environments and utilizes an escalation mechanism
    when faced with consistent defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.punishment_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.punishment_counter = 0
            return Action.C
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        my_last_action = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + my_last_action
        all_cooperated = total_cooperators == self.n
        if history.round_number == self.n_rounds - 1:
            return Action.C if all_cooperated else Action.D
        if all_cooperated:
            self.punishment_counter = 0
            return Action.C
        else:
            self.punishment_counter += 1
            if self.punishment_counter % 2 != 0:
                return Action.D
            self.punishment_counter = 0
            return Action.C

class Strategy_PROSOCIAL_77(BaseStrategy):
    """
    Conditional Sustainability Trigger (CST) Strategy.
    Implements a policy of 'Targeted Cooperation with Forgiving Reciprocity'.
    - Round 1: Always Cooperate.
    - Sustainability Emergency: If stock < 25% capacity, Cooperate.
    - Final Round: Defect if stock > 10% capacity, else Cooperate.
    - Reciprocity: Defect if stock is declining and previous round had defections; 
      otherwise, maintain cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock > self.capacity * 0.1:
                return Action.D
            else:
                return Action.C
        prev_round_idx = history.round_number - 1
        prev_n_coop = history.opponent_cooperators[prev_round_idx]
        prev_n_defect = self.n_opponents - prev_n_coop
        my_prev_action = history.my_actions[prev_round_idx]
        if prev_n_defect == 0:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_78(BaseStrategy):
    """
    Implements a conditionally cooperative strategy for the Common Pool Resource Game.
    The strategy cooperates in the first round and maintains cooperation as long as
    the aggregate opponent behavior remains sustainable and the stock level is safe.
    It defects in the final round and during critical depletion to maximize utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.n_rounds - 1:
            return Action.D
        if current_stock < self.capacity / (2 * self.n_players):
            return Action.D
        prev_opp_coop_count = history.opponent_cooperators[-1]
        if self.n_opponents > 0:
            opp_coop_rate = prev_opp_coop_count / self.n_opponents
        else:
            opp_coop_rate = 1.0
        if opp_coop_rate > 0.5:
            return Action.C
        elif current_stock >= self.capacity / 2:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_79(BaseStrategy):
    """
    Adaptive Sustainability Threshold (AST) strategy.
    Maintains stock near optimal capacity (capacity/2) by balancing cooperation
    rates, stock level feedback, and end-game harvesting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.eps = 1e-06

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.n
        capacity = self.capacity
        t = history.round_number
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        ccr = total_cooperators_prev / n
        if t >= self.r - math.ceil(n / 4):
            if current_stock > capacity / 2:
                return Action.D
            else:
                return Action.C
        if current_stock < capacity / (4 * n):
            return Action.C
        if current_stock < self.eps:
            return Action.C
        if ccr < 0.5:
            return Action.C
        if ccr < 0.75:
            return Action.C
        if current_stock >= 0.8 * capacity:
            return Action.D
        if t >= 3:
            my_actions_int = history.my_actions.astype(int)
            full_coop_history = history.opponent_cooperators + my_actions_int
            recent_ccrs = full_coop_history[-3:] / n
            if current_stock >= 0.95 * capacity and np.all(recent_ccrs > 0.9):
                return Action.D
        return Action.C

class Strategy_PROSOCIAL_80(BaseStrategy):
    """
    Implements a Reciprocal Cooperation strategy with Emergency Recovery for 
    Common Pool Resource games. Maintains a Cooperation Credit (CC) score, 
    clamped between -2 and 2, which determines the action. CC is updated based 
    on the previous round's aggregate opponent behavior and relative changes 
    in stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.cc = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / 4:
            return Action.C
        prev_idx = history.round_number - 1
        c_prev = history.opponent_cooperators[prev_idx]
        if not hasattr(self, '_stock_history'):
            self._stock_history = []
        if len(self._stock_history) > 0:
            s_prev = self._stock_history[-1]
            if current_stock < s_prev * 0.5:
                self.cc -= 1
            else:
                d_prev = self.n - 1 - c_prev
                self.cc += c_prev - d_prev
        self._stock_history.append(current_stock)
        self.cc = max(-2, min(2, self.cc))
        if history.round_number == self.r - 1:
            return Action.D if self.cc > 0 else Action.C
        return Action.C if self.cc >= 0 else Action.D

class Strategy_PROSOCIAL_81(BaseStrategy):
    """
    Implements a Tit-for-Tat with a Prosocial Buffer strategy.
    
    Logic:
    1. First Round: Cooperate.
    2. Critical Threshold: 20% of capacity.
    3. If Stock <= Threshold: Always Cooperate (to prevent collapse).
    4. If Stock > Threshold:
        - If not last round: Cooperate if cooperation rate >= 0.5, else Defect.
        - If last round: Defect (unless below threshold).
    5. Stock Collapse: If stock is 0, Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.critical_threshold = 0.2 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if current_stock <= 1e-09:
            return Action.C
        if current_stock <= self.critical_threshold:
            return Action.C
        if round_number == self.n_rounds - 1:
            return Action.D
        prev_opponents_cooperated = history.opponent_cooperators[-1]
        num_opponents = self.n_players - 1
        cooperation_rate = prev_opponents_cooperated / num_opponents
        if cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_82(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with Capacity-Targeting.
    
    The strategy aims to maintain the resource stock near 50% of capacity to maximize
    regeneration rates. It follows a distinct logic:
    1. Always cooperates in the first round.
    2. Always defects in the final round.
    3. For intermediate rounds, it adjusts based on stock level and observed aggregate 
       cooperation from the previous round:
       - If stock is critical (< 20%), it cooperates only if the group majority cooperated.
       - If stock is abundant (> 80%), it cooperates to promote sustainable usage.
       - Otherwise, it tit-for-tats (cooperates if group majority cooperated, else defects).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        self_prev_action = int(history.my_actions[-1])
        total_prev_cooperators = prev_cooperators + self_prev_action
        is_cooperative_group = total_prev_cooperators >= self.game_description.n_players / 2
        capacity = self.game_description.capacity
        if current_stock < 0.2 * capacity:
            return Action.C if is_cooperative_group else Action.D
        elif current_stock > 0.8 * capacity:
            return Action.C
        else:
            return Action.C if is_cooperative_group else Action.D

class Strategy_PROSOCIAL_83(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Common Pool Resource Game.
    The strategy maintains cooperation based on a resource sustainability threshold (capacity / 2)
    and reciprocal observation of opponent behavior. It shifts to emergency conservation
    when the stock is low and reverts to strict reciprocity in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.s_crit = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 1e-09:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n_opponents = self.n - 1
        prev_opp_cooperators = history.opponent_cooperators[-1]
        if history.round_number == self.r - 1:
            return Action.C if prev_opp_cooperators == n_opponents else Action.D
        if current_stock >= self.s_crit:
            return Action.C if prev_opp_cooperators >= self.n / 2.0 else Action.D
        else:
            return Action.C if prev_opp_cooperators == n_opponents else Action.D

class Strategy_PROSOCIAL_84(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Threshold-based Forgiveness.
    
    This strategy focuses on maintaining the common pool resource at capacity by 
    collaborating when the stock is healthy or when the group demonstrates 
    cooperative intent, and harvesting (defecting) defensively when the 
    resource is nearing depletion or the group is actively destroying the pool.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.threshold = self.capacity / 2.0
        self.cooperation_threshold = math.ceil(self.n / 2.0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opp_coop = history.opponent_cooperators[-1]
        prev_k = last_opp_coop + (1 if last_my_action else 0)
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock >= self.threshold:
                return Action.C
            return Action.D
        if current_stock < self.threshold:
            return Action.D
        if prev_k >= self.cooperation_threshold:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_85(BaseStrategy):
    """
    Implements a Triggered Tit-for-Tat with Recovery strategy.
    
    Logic:
    1. Always cooperate in the first round.
    2. Always defect in the final round (t=r).
    3. In intermediate rounds:
       - If stock < 0.5 * capacity, prioritize sustainability (Cooperate).
       - If k_prev (previous defectors) == 0, maintain Cooperation.
       - If k_prev > 0:
         - If k_prev >= ceil(n/2), punish by Defecting.
         - Otherwise, remain prosocial (Cooperate).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.target_stock = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        final_round_idx = self.r - 1
        if current_round_idx == final_round_idx:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < self.target_stock:
            return Action.C
        n_opponents = self.n - 1
        cooperators_prev = history.opponent_cooperators[-1]
        k_prev = n_opponents - cooperators_prev
        if k_prev == 0:
            return Action.C
        else:
            threshold = math.ceil(self.n / 2)
            if k_prev >= threshold:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_86(BaseStrategy):
    """
    Tit-for-Tat with Forgiving Resilience:
    A strategy that aims to maintain capacity by cooperating, penalizing defectors 
    with temporary defection, but resetting quickly to encourage collective 
    cooperation. Includes recovery logic for low stock and greedy final-round behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1
        self.threshold = math.ceil(self.n_opponents * 0.5)
        self.recovery_rounds_left = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_stock < 0.1 * self.capacity:
            self.recovery_rounds_left = 2
        if self.recovery_rounds_left > 0:
            self.recovery_rounds_left -= 1
            return Action.C
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            if current_stock > self.capacity / 2:
                return Action.D
            else:
                return Action.C
        if current_stock < self.capacity / 2:
            return Action.C
        last_opponents_c = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        if last_opponents_c >= self.threshold:
            return Action.C
        if last_my_action == Action.D.value:
            return Action.C
        if random.random() < 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_87(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness strategy for the Common Pool Resource game.
    Calibrates actions based on stock health, reciprocal opponent behavior, 
    and end-game conditions to maximize long-term sustainable yield.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        health = current_stock / self.game_description.capacity
        last_coop_rate = history.opponent_cooperators[-1] / n_opponents
        k = min(3, total_rounds // 10)
        if total_rounds - current_round <= k and health <= 0.5:
            return Action.D
        if last_coop_rate >= 0.75:
            return Action.C
        if health > 0.8:
            if current_round >= 2:
                prev_coop_rate = history.opponent_cooperators[-2] / n_opponents
                if last_coop_rate < 0.5 and prev_coop_rate < 0.5:
                    return Action.D
            return Action.C
        elif health > 0.2:
            if last_coop_rate >= 0.5:
                return Action.C
            return Action.D
        else:
            if math.isclose(last_coop_rate, 1.0):
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_88(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness strategy for the Common Pool Resource Game.
    Cooperates initially and when cooperation is high. Defects when stock is critically
    low or when group cooperation collapses, with a probabilistic restoration mechanism.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            return Action.D if current_stock > 0 else Action.C
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        threshold = self.n - 1
        if prev_cooperators >= threshold:
            return Action.C
        else:
            if current_stock < self.capacity / 2:
                return Action.D
            prob_restore = prev_cooperators / self.n
            if random.random() < prob_restore:
                return Action.C
            else:
                return Action.D

class Strategy_PROSOCIAL_89(BaseStrategy):
    """
    Implements Proportional Tit-for-Tat with Resilience Thresholds.
    
    This strategy focuses on sustainability and cooperative equilibrium:
    - Plays C in round 1.
    - Plays D in the final round to maximize final payoff.
    - If stock is critical (<25% capacity), forces C to aid recovery.
    - If stock drops by >50% since the last round, forces D for one round to signal unsustainability.
    - Otherwise, classifies the collective as 'Cooperative' or 'Exploitative' based on the 
      last 3 rounds' average cooperation count (>= (n-1)/2 is Cooperative).
    - If Exploitative, plays D (for one round, then back to C) to defend against exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.last_stock = float(self.desc.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        n = self.desc.n_players
        n_opponents = n - 1
        if round_idx == self.desc.n_rounds - 1:
            self.last_stock = current_stock
            return Action.D
        if current_stock <= 0:
            self.last_stock = current_stock
            return Action.D
        if current_stock < self.desc.capacity * 0.25:
            self.last_stock = current_stock
            return Action.C
        if round_idx == 0:
            self.last_stock = current_stock
            return Action.C
        if self.last_stock > 0 and current_stock / self.last_stock < 0.5:
            self.last_stock = current_stock
            return Action.D
        self.last_stock = current_stock
        k = min(round_idx, 3)
        recent_coop_counts = history.opponent_cooperators[-k:]
        avg_cooperation = sum(recent_coop_counts) / k
        threshold = n_opponents / 2.0
        if avg_cooperation >= threshold:
            return Action.C
        elif len(history.my_actions) > 0 and history.my_actions[-1] == Action.D.value:
            return Action.D
        else:
            return Action.D

class Strategy_PROSOCIAL_90(BaseStrategy):
    """
    Implements a Conditional Sustainability-Adjusted Tit-for-Tat strategy.
    
    This strategy prioritizes long-term resource viability over short-term gain.
    - Round 1: Always Cooperate.
    - Subsequent Rounds:
        1. Critical Threshold: If the current stock is extremely low (< capacity / 2n), Defect to preserve resources.
        2. Last Round Override: If the stock is critically low, Defect; otherwise Cooperate.
        3. Adaptive Logic: If previous round had <= 1 defectors (cooperation dominated), Cooperate. Otherwise, Defect.
    - Uncertainty Handling: If data is ambiguous, defaults to critical preservation logic.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        my_prev_action = history.my_actions[-1]
        other_cooperators = history.opponent_cooperators[-1]
        total_cooperators = (1 if my_prev_action else 0) + other_cooperators
        total_defectors = n - total_cooperators
        if current_stock < capacity / (2 * n):
            return Action.D
        if current_round == r_total - 1:
            if current_stock < capacity * 0.5:
                return Action.D
            return Action.C
        if total_defectors <= 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_91(BaseStrategy):
    """
    A variant of Tit-for-Tat conditioned on sustainability thresholds.
    1. Always Cooperates in the first round.
    2. Terminal Phase (last round): Cooperates if stock >= capacity/2, else Defects.
    3. Sustainability Check: If stock < capacity/4, Defects to protect/buffer individual payoff.
    4. Reciprocity Check: If stock >= capacity/4, compares cooperative rate of opponents to 0.5.
       Cooperates if >= 50% of opponents cooperated, else Defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock >= self.game_description.capacity / 2:
                return Action.C
            else:
                return Action.D
        if current_stock < self.game_description.capacity / 4:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        if n_opponents <= 0:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        reciprocity_rate = last_round_cooperators / n_opponents
        if reciprocity_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_92(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with a proportional threshold.
    Cooperation is maintained if the group acts collectively, while defaulting to 
    defection under resource pressure or perceived betrayal by other players.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.n_rounds - 1:
            if current_stock >= self.capacity / 4.0:
                return Action.C
            else:
                return Action.D
        survival_limit = self.capacity / (2.0 * self.n)
        if current_stock < survival_limit:
            return Action.D
        threshold = self.n - 1
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_93(BaseStrategy):
    """
    A threshold-based cooperation strategy (Trigger-Tit-for-Tat) for the Common Pool Resource game.
    
    Logic Summary:
    1. Initial Round: Always starts with Cooperate (C).
    2. Sustainability/Endgame: If the final round is reached, defaults to Defect (D) to capture remaining value. If stock is critically low (< 25% capacity), defaults to Defect (D).
    3. Conditional Cooperation: In intermediate rounds, cooperates if previous round's cooperation level meets a simple majority threshold (ceil((n-1)/2)). Otherwise, defects to incentivize punishment/correction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = math.ceil((self.game_description.n_players - 1) / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 4:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_94(BaseStrategy):
    """
    A strategy that maintains the common pool resource at a sustainable level (50% capacity).
    It employs a probabilistic Tit-for-Tat mechanism: cooperation is triggered if the number 
    of cooperating opponents meets a threshold (n-2), otherwise, it retaliates with a 
    probability inversely proportional to the group's cooperation level. It also prioritizes 
    resource conservation by defecting if the stock falls below critical levels or 
    cooperating in the final round if resources are abundant.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if history.round_number == self.total_rounds - 1:
            if current_stock > 0.8 * self.capacity:
                return Action.C
            else:
                return Action.D
        k = int(history.opponent_cooperators[-1])
        threshold = self.n - 2
        if k >= threshold:
            return Action.C
        else:
            prob_defect = 1.0 - k / (self.n - 1)
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_95(BaseStrategy):
    """
    Implements a modified Tit-for-Tat strategy with threshold-based cooperation 
    and a recovery mode to preserve common pool resources.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == total_rounds - 1:
            return Action.C if current_stock > capacity / 2 else Action.D
        if current_stock < capacity / n:
            return Action.C
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        threshold = math.ceil(n / 2)
        if c_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_96(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with a sustainability buffer.
    Maintains resource levels by prioritizing cooperation when stock is low,
    and using probabilistic defection to punish non-cooperators when stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == r - 1:
            return Action.D
        if history.round_number == 0 or current_stock < capacity / 2:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coop = history.opponent_cooperators[-1]
        k_prev = prev_opp_coop + prev_my_action
        if k_prev >= n - 1:
            return Action.C
        else:
            num_defectors = n - k_prev
            if random.random() < num_defectors / n:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_97(BaseStrategy):
    """
    Conditional Tit-for-Tat with Resource Thresholds.
    
    Strategy logic:
    1. Always cooperate in the first round.
    2. Critical Depletion check: If stock < 10% capacity, defect.
    3. Last Round logic: If stock is low (< capacity / n), defect to extract remaining value,
       else cooperate to maximize yield.
    4. Adaptive Tit-for-Tat: 
       - If previous round's majority cooperated (>= n/2), cooperate.
       - If minority cooperated (< n/2), punish by defecting.
       - If exactly n/2 cooperators, stick to previous action (history persistence).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_action = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.last_action = Action.C
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        prev_round_coop_count = history.opponent_cooperators[-1]
        my_last_action_val = 1 if self.last_action == Action.C else 0
        total_cooperators = prev_round_coop_count + my_last_action_val
        if current_stock < 0.1 * capacity:
            self.last_action = Action.D
            return Action.D
        if history.round_number == total_rounds - 1:
            if current_stock < capacity / n:
                self.last_action = Action.D
                return Action.D
            else:
                self.last_action = Action.C
                return Action.C
        if current_stock < capacity / (2 * n):
            self.last_action = Action.D
            return Action.D
        if total_cooperators == n / 2 and n % 2 == 0:
            return self.last_action
        if total_cooperators >= n / 2:
            self.last_action = Action.C
            return Action.C
        else:
            self.last_action = Action.D
            return Action.D

class Strategy_PROSOCIAL_98(BaseStrategy):
    """
    Implements a conditional sustainability strategy. Prioritizes cooperation in the 
    first round and during critical stock shortages to ensure survival. In 
    intermediate states, employs a Tit-for-Tat approach based on a strong 
    majority (80%) of cooperators in the previous round. Always defects in 
    the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < capacity / (2 * n) or current_stock < capacity / 4:
            return Action.C
        threshold = math.ceil(0.8 * n)
        prev_my_action = history.my_actions[-1]
        prev_opp_cooperators = history.opponent_cooperators[-1]
        total_cooperators = prev_opp_cooperators + (1 if prev_my_action else 0)
        if total_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_99(BaseStrategy):
    """
    Implements an Adaptive Tit-for-Tat strategy with Sustainability Thresholds.
    
    Strategy Overview:
    1. First Round: Always Cooperate (C).
    2. Endgame (Final Round): Always Defect (D).
    3. Sustainability Trigger: If stock < 25% of capacity, Defect (D) to prevent 
       immediate total depletion and extract final utility.
    4. Reciprocity Phase: Calculates the average cooperation rate (CR_avg) of 
       opponents across all prior rounds. If CR_avg >= 0.5, Cooperate (C), 
       otherwise Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.D
        total_cooperations_seen = np.sum(history.opponent_cooperators)
        total_opponents_possible = current_round * (self.n - 1)
        if total_opponents_possible == 0:
            return Action.C
        cr_avg = total_cooperations_seen / total_opponents_possible
        if cr_avg >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_100(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource game.
    It assesses resource health and peer behavior to decide between cooperation,
    punishment, and conservation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.delta = 0.1
        self.epsilon_factor = 0.05
        self.s_target = self.game_description.capacity / 2.0
        self.epsilon = self.epsilon_factor * self.game_description.capacity
        self.n = self.game_description.n_players
        self.cooperation_threshold = math.ceil(self.n / 2.0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        r = self.game_description.n_rounds
        c_prev = history.opponent_cooperators[-1]
        if t == r - 1:
            return Action.D
        if current_stock <= self.epsilon:
            return Action.D
        if current_stock < self.s_target * (1.0 - self.delta):
            return Action.C
        if c_prev >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_101(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource Game.
    
    Logic:
    1. Always cooperates (C) in the first round.
    2. Terminal Round (last round):
       - If stock >= capacity/2, defects (D) to maximize final utility.
       - If stock < capacity/2, cooperates (C) to prevent catastrophic depletion.
    3. Safety Check:
       - If current stock < capacity/4, cooperates (C) regardless of history.
    4. Adaptive Tit-for-Tat (for remaining rounds):
       - If the Group Cooperation Index (GCI) of the previous round >= (n - 1), cooperates (C).
       - Otherwise, defects (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        if history.round_number == total_rounds - 1:
            if current_stock >= capacity / 2:
                return Action.D
            else:
                return Action.C
        if current_stock < capacity / 4:
            return Action.C
        gci = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        my_last_action_val = 1 if my_last_action else 0
        total_group_gci = gci + my_last_action_val
        if total_group_gci >= n_players - 1:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_102(BaseStrategy):
    """
    A conditional tit-for-tat strategy for the Common Pool Resource Game.
    It cooperates initially and then balances conditional cooperation based on 
    the number of previous cooperators and the stock sustainability index. 
    It is programmed to defect when the stock is dangerously low or in the 
    final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.recovering = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        prev_cooperators = history.opponent_cooperators[-1]
        current_round = history.round_number
        if current_round == total_rounds - 1:
            return Action.D
        sigma = current_stock / capacity
        if sigma < 0.25:
            self.recovering = True
            return Action.D
        if self.recovering:
            if sigma > 0.5 and prev_cooperators >= n - 1:
                self.recovering = False
                return Action.C
            else:
                return Action.D
        rounds_left = total_rounds - 1 - current_round
        target = n - 1 if rounds_left > 1 else 0
        if prev_cooperators >= target:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_103(BaseStrategy):
    """
    Adaptive Prosocial Tit-for-Tat with Resource Maintenance.
    Prioritizes cooperation when resource levels are healthy or when the 
    collective group is cooperating, while defecting when sustainability 
    is threatened or exploitation is detected.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        i_cooperated_last = history.my_actions[-1]
        n_cooperators_last = history.opponent_cooperators[-1] + (1 if i_cooperated_last else 0)
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.capacity / 4:
            if n_cooperators_last > 0:
                return Action.C
            else:
                return Action.D
        threshold = math.ceil(self.n / 2)
        if n_cooperators_last >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_104(BaseStrategy):
    """
    Adaptive Sustainability Tit-for-Tat (ASTFT) Strategy.
    
    Maintains the pool stock near the maximum regeneration level. 
    Prioritizes cooperation in crisis or early/late phases based on stock 
    thresholds, while utilizing stochastic reciprocity to punish 
    excessive consumption.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def _calculate_required_cooperators(self, s: float) -> float:
        """
        Calculates k_threshold: the number of cooperators required such that
        stock_remaining after consumption = 0.5 * capacity.
        
        Formula derivation:
        S - [k * (S / 2n) + (n-k) * (S / n)] = 0.5 * capacity
        S - [ (k*S)/(2n) + (2n*S - k*S)/(2n) ] = 0.5 * capacity
        S - [ (k*S + 2n*S - k*S) / (2n) ] = 0.5 * capacity
        S - [ (2n*S) / (2n) ] = 0.5 * capacity  <-- This simplification shows consumption depends heavily on S
        
        Wait, solving for k:
        S - (k*S/2n) - (n*S/n) + (k*S/n) = 0.5 * capacity
        S - (k*S/2n) - S + (k*S/n) = 0.5 * capacity
        -k*S/(2n) + 2k*S/(2n) = 0.5 * capacity
        k*S / (2n) = 0.5 * capacity
        k = (0.5 * capacity * 2n) / S
        k = (capacity * n) / S
        """
        if s <= 0:
            return self.n
        k = self.capacity * self.n / s
        return max(0.0, min(float(self.n), k))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        prev_k = prev_opp_coop + my_prev_action
        if current_round == self.total_rounds - 1:
            if current_stock > 0.1 * self.capacity:
                return Action.C
            else:
                return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        target_k = self._calculate_required_cooperators(current_stock)
        if prev_k >= target_k:
            return Action.C
        else:
            prob_defect = (self.n - prev_k) / self.n
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_105(BaseStrategy):
    """
    A Tit-for-Tat with Hysteresis strategy for the Common Pool Resource Game.
    It prioritizes long-term sustainability by maintaining a target stock level,
    punishing defectors when the resource is healthy, and reverting to forced
    cooperation when the resource is critically low to prevent collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.s_target = game_description.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            if current_stock >= self.s_target:
                return Action.D
            else:
                return Action.C
        if current_stock < self.s_target * 0.5:
            return Action.C
        prev_round_coops = history.opponent_cooperators[-1]
        if prev_round_coops >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_106(BaseStrategy):
    """
    Sustained Equilibrium Cooperation (SEC) strategy.
    
    This strategy acts as a conditional cooperator, adjusting cooperation thresholds
    based on resource stock levels. It aims to maintain stock at sustainable levels
    (> 0.5 capacity) while responding to opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r_total - 1:
            return Action.D
        last_action_was_defect = history.my_actions[-1] == False
        last_opponents_cooperated = history.opponent_cooperators[-1]
        if last_action_was_defect and current_stock > 0.5 * capacity:
            return Action.C
        if current_stock < 0.25 * capacity:
            threshold = n - 1
        elif current_stock < 0.5 * capacity:
            threshold = n - 2
        else:
            threshold = n - 3
        effective_threshold = max(0, threshold)
        if last_opponents_cooperated >= effective_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_107(BaseStrategy):
    """
    Implements 'Triggered Tit-for-Tat with Sustainability Thresholds'.
    
    Strategy:
    1. First round: Cooperate (C).
    2. Final round: Defect (D).
    3. Intermediate rounds:
       - Trigger 'Grim Trigger' Defection if stock < 10% capacity.
       - Cooperate if stock >= 50% capacity AND fewer than n-1 opponents defected in the previous round.
       - Otherwise, Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.D
        is_stock_healthy = current_stock >= 0.5 * self.capacity
        prev_round_my_action_is_cooperate = history.my_actions[-1]
        prev_round_my_is_defector = 1 if not prev_round_my_action_is_cooperate else 0
        prev_round_opponent_cooperators = history.opponent_cooperators[-1]
        prev_round_opponent_defectors = self.n - 1 - prev_round_opponent_cooperators
        total_defectors = prev_round_my_is_defector + prev_round_opponent_defectors
        is_environment_stable = total_defectors < self.n - 1
        if is_stock_healthy and is_environment_stable:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_108(BaseStrategy):
    """
    An adaptive Tit-for-Tat strategy for the Common Pool Resource game.
    It maintains a Target Cooperation Level (TCL) based on weighted moving averages
    of opponent actions and switches between cooperation (C) and defection (D)
    based on stock levels and observed behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.tcl = float(game_description.n_players - 1)
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.tcl = float(self.n - 1)
            return Action.C
        prev_round_idx = history.round_number - 1
        c_prev = float(history.opponent_cooperators[prev_round_idx])
        self.tcl = 0.7 * self.tcl + 0.3 * c_prev
        if history.round_number == self.total_rounds - 1:
            if current_stock > self.capacity / 4.0:
                return Action.C
            else:
                return Action.D
        if current_stock < float(self.n):
            return Action.D
        if current_stock < self.capacity / 2.0:
            return Action.D
        if c_prev < self.tcl - 1.0:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_109(BaseStrategy):
    """
    A reputation-based cooperative strategy for the Common Pool Resource game.
    It tracks opponent cooperation rates and adjusts behavior dynamically, 
    including a punitive signaling mechanism when the common pool is threatened.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 1.0
        self.signaling_cooldown = 0
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.D
        round_idx = history.round_number
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if self.signaling_cooldown > 0:
            self.signaling_cooldown -= 1
            return Action.C
        last_k = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        coop_rate = last_k / n_opponents if n_opponents > 0 else 0
        self.reputation = 0.7 * self.reputation + 0.3 * coop_rate
        if last_k < n_opponents and current_stock < self.game_description.capacity / 4:
            self.signaling_cooldown = 0
            return Action.D
        if current_stock < self.game_description.capacity / (2 * self.n):
            return Action.D
        if self.reputation >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_110(BaseStrategy):
    """
    Implements a Tit-for-Tat variant with a Forgiving Threshold.
    
    This strategy prioritizes sustainability:
    1. Always cooperates in the first round.
    2. Enters a 'Regeneration Mode' (cooperates) if the current stock is below 
       half capacity, regardless of previous behavior.
    3. In abundant states (stock >= half capacity), it assesses the total 
       group cooperation from the previous round. It reciprocates if the 
       majority (>= n/2) cooperated, otherwise it defects to discourage 
       systemic over-extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.game_description.capacity / 2:
            return Action.C
        last_round_my_action = history.my_actions[-1]
        last_round_opponent_coops = history.opponent_cooperators[-1]
        total_prev_cooperators = last_round_opponent_coops + (1 if last_round_my_action else 0)
        threshold = math.ceil(self.game_description.n_players / 2)
        if total_prev_cooperators >= threshold:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_111(BaseStrategy):
    """
    Implements a conditional cooperation strategy ('Tit-for-Tat with Forgiveness and Threshold').
    - Round 1: Always Cooperate.
    - Rounds 2 to r-1: 
        - If stock < 50% capacity, require ALL opponents to cooperate to trigger Cooperation (T = n-1).
        - If stock >= 50% capacity, require at least 50% of opponents to cooperate to trigger Cooperation (T = ceil(0.5 * (n-1))).
    - Last round: Always Defect.
    - Special Handling: Always Defect if current stock is 0.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0.0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        half_capacity = self.game_description.capacity * 0.5
        if current_stock < half_capacity:
            threshold = self.n_opponents
        else:
            threshold = math.ceil(0.5 * self.n_opponents)
        try:
            previous_round_cooperators = history.opponent_cooperators[-1]
        except (IndexError, TypeError):
            if current_stock < 0.1 * self.game_description.capacity:
                return Action.D
            return Action.C
        if previous_round_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_112(BaseStrategy):
    """
    Implements a reputation-based strategy for the Common Pool Resource game.
    Tracks group cooperation history to decide between cooperation (C) and defection (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 1.0
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock > 0.25 * self.capacity:
                return Action.C
            else:
                return Action.D
        if not hasattr(self, 'prev_stock'):
            self.prev_stock = float(self.capacity)
        last_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + last_my_action
        self.reputation = 0.7 * self.reputation + 0.3 * (total_cooperators / self.n)
        if self.reputation < 0.1:
            self.reputation = 0.0
        self.prev_stock = current_stock
        if current_stock < 0.5 * self.capacity:
            return Action.C
        if self.reputation >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_113(BaseStrategy):
    """
    Tit-for-Tat with Forgiving Resilience:
    A strategic agent for Common Pool Resource games that prioritizes resource sustainability 
    through cooperative tit-for-tat mechanisms, with safety thresholds for regeneration 
    and periodic re-engagement checks.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.num_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            if current_stock < self.capacity * 0.1:
                return Action.D
            return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.C
        prev_opp_cooperators = history.opponent_cooperators[-1]
        threshold = self.num_opponents / 2
        is_cooperative_history = prev_opp_cooperators > threshold
        if prev_opp_cooperators == 0:
            if round_idx % 3 == 0:
                return Action.C
            return Action.D
        if is_cooperative_history:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_114(BaseStrategy):
    """
    A conditional cooperation strategy that attempts to maintain stock 
    via Trigger-Tit-for-Tat:
    - Round 0: Cooperate.
    - Subsequent Rounds:
        - Defect if last round (r-1).
        - Defect if stock is critically low (< 10% capacity).
        - Cooperate if group cooperation was high in previous round (>= n-1 cooperators).
        - Otherwise, defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock < self.capacity * 0.1:
            return Action.D
        last_my_action = int(history.my_actions[-1])
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        k_prev = last_my_action + last_opponent_cooperators
        if k_prev >= self.n - 1:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_115(BaseStrategy):
    """
    Implements a sustainable management strategy for the Common Pool Resource Game.
    The strategy prioritizes resource recovery when stock is low, cooperates to maintain
    an equilibrium stock level, and defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 0.1 * capacity:
            return Action.C
        my_last_action_is_c = bool(history.my_actions[-1])
        c_count = history.opponent_cooperators[-1] + (1 if my_last_action_is_c else 0)
        d_count = n - c_count
        total_consumption = c_count * (current_stock / (2 * n)) + d_count * (current_stock / n)
        s_rem = max(0.0, current_stock - total_consumption)
        growth = 2 * s_rem * (1 - s_rem / capacity)
        s_next = min(s_rem + growth, capacity)
        if s_next < 0.4 * capacity:
            return Action.D
        elif s_next > 0.6 * capacity:
            if history.opponent_cooperators[-1] > (n - 1) / 2:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_116(BaseStrategy):
    """
    Implements a conditionally cooperative strategy for the Common Pool Resource Game.
    The strategy focuses on sustaining the pool capacity by cooperating, 
    but switches to defection if opponents indicate unsustainable behavior 
    or if the resource is critically depleted. It includes defensive heuristics
    for rapid stock decline and recovery phases.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.collapse_threshold = 0.05 * self.game_description.capacity
        self.danger_zone_threshold = 0.2 * self.game_description.capacity
        self.recovery_threshold = 0.8 * self.game_description.capacity
        self.rapid_decline_threshold = 0.4
        self.previous_stock = float(self.game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.game_description.n_rounds - 1:
            self.previous_stock = current_stock
            return Action.D
        if round_idx == 0:
            self.previous_stock = current_stock
            return Action.C
        prev_k_c = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if current_stock < self.collapse_threshold:
            self.previous_stock = current_stock
            return Action.D
        if self.previous_stock > 0 and (self.previous_stock - current_stock) / self.previous_stock > self.rapid_decline_threshold:
            self.previous_stock = current_stock
            return Action.D
        if current_stock >= self.recovery_threshold:
            self.previous_stock = current_stock
            return Action.C
        if prev_k_c == n_opponents:
            self.previous_stock = current_stock
            return Action.C
        if prev_k_c < n_opponents:
            if current_stock > self.danger_zone_threshold:
                self.previous_stock = current_stock
                return Action.C
            else:
                self.previous_stock = current_stock
                return Action.D
        self.previous_stock = current_stock
        return Action.C

class Strategy_PROSOCIAL_117(BaseStrategy):
    """
    Adaptive Sustainability Tit-for-Tat (ASTFT): 
    Balances cooperation with resource sustainability. It defaults to C, 
    but defects if the resource is critically depleted, if opponents 
    over-consume, or if it is the final round and the stock is high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.2 * self.game_description.capacity:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock > 0.8 * self.game_description.capacity:
                return Action.D
            if current_stock < 0.5 * self.game_description.capacity:
                return Action.C
        prev_k = history.opponent_cooperators[-1]
        if prev_k == self.n_opponents:
            return Action.C
        if prev_k < self.n_opponents:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_118(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Proportional Response.
    A strategic agent that attempts to maintain common pool capacity by cooperating 
    when prosocial behavior is detected, while defecting during resource depletion 
    or when cooperation is insufficient. Includes a forgiveness mechanism to 
    recover cooperation after cycles of defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.majority_threshold = math.ceil(self.n * 0.6)
        self.critical_threshold = self.capacity * 0.25
        self.forgiveness_threshold = self.capacity * 0.5
        self.last_round_index = self.game_description.n_rounds - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.last_round_index:
            return Action.C if current_stock >= self.forgiveness_threshold else Action.D
        if current_stock < self.critical_threshold:
            return Action.D
        if not history.my_actions[-1] and current_stock >= self.forgiveness_threshold:
            return Action.C
        if history.opponent_cooperators[-1] >= self.majority_threshold:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_119(BaseStrategy):
    """
    Adaptive Proportional Tit-for-Tat (APTFT) strategy for the Common Pool Resource Game.
    
    Maintains a reputation score for the collective of opponents based on an exponential moving average
    of their cooperation counts. The decision to cooperate or defect is based on comparing this 
    reputation against the current stock sustainability threshold, with overrides for extreme 
    stock depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.alpha = 0.2
        self.reputation = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.reputation = 1.0
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if n_opponents == 0:
            self.reputation = 1.0
        elif self.n == 2:
            self.reputation = 1.0 if k_prev > 0 else 0.0
        else:
            cooperation_ratio = k_prev / n_opponents
            self.reputation = (1.0 - self.alpha) * self.reputation + self.alpha * cooperation_ratio
        threshold = current_stock / self.capacity if self.capacity > 0 else 1.0
        critical_level = self.capacity / (10.0 * self.n)
        if current_stock < critical_level:
            if self.reputation < 0.2:
                return Action.D
            else:
                return Action.C
        if self.reputation >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_120(BaseStrategy):
    """
    A strategy that maintains cooperation while the pool is healthy, uses probabilistic
    punishment (Tit-for-Tat variant) to discourage defection when cooperation drops,
    and prioritizes critical threshold protection to prevent resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.t_coop = self.n - 1
        self.s_crit = self.capacity / 4

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            if current_stock >= self.capacity / 2:
                return Action.C
            else:
                return Action.D
        if current_stock < self.s_crit:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= self.t_coop:
            return Action.C
        else:
            denominator = max(1, self.n - 1)
            prob_defect = 1.0 - prev_cooperators / denominator
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_121(BaseStrategy):
    """
    Implements a Tit-for-Tat with Resilience and Forgiveness strategy.
    
    Logic Summary:
    1. First round (round 0): Always Cooperate (C).
    2. Last round (round r-1): If stock >= 0.5 * capacity, Defect (D) to maximize score. Otherwise, Cooperate (C).
    3. Emergency Recovery: If current_stock < 0.25 * capacity, always Cooperate (C).
    4. Adaptive Policy: If previous round defection count > 0.3 * n, Defect (D). Otherwise, Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.max_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.max_rounds - 1:
            if current_stock >= 0.5 * self.capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.C
        my_last_action = history.my_actions[-1]
        opp_coop_count = history.opponent_cooperators[-1]
        total_cooperators = (1 if my_last_action else 0) + opp_coop_count
        defectors_last_round = self.n - total_cooperators
        if defectors_last_round > 0.3 * self.n:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_122(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Resource Thresholds strategy.
    
    Logic:
    - Round 1: Cooperate.
    - Final Round: Always Defect (to maximize terminal utility).
    - If current_stock >= capacity / 2 (Healthy):
        - Cooperate if prev_round_cooperators >= (n - 1). 
        - Otherwise, Defect to punish.
    - If current_stock < capacity / 2 (Endangered):
        - Always Cooperate (altruistic attempt to prevent collapse).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        round_t = current_round_index + 1
        if round_t == self.total_rounds:
            return Action.D
        if round_t == 1:
            return Action.C
        is_healthy = current_stock >= self.capacity / 2.0
        if is_healthy:
            last_my_action = history.my_actions[-1]
            last_opponent_coops = history.opponent_cooperators[-1]
            total_cooperators = last_opponent_coops + (1 if last_my_action else 0)
            if total_cooperators >= self.n - 1:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_123(BaseStrategy):
    """
    Threshold-Based Tit-for-Tat with Proportional Reciprocity.
    
    This strategy monitors the common pool resource stock level and the cooperation 
    of opponents in previous rounds to decide between cooperation and defection.
    It prioritizes sustainability when the stock is critically low and uses 
    a calculated threshold for reciprocity based on the number of opponents.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.alpha = (game_description.n_players - 1) / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_stock < capacity / n:
            return Action.C
        if current_round == total_rounds - 1:
            if current_stock > capacity / 2:
                return Action.D
            else:
                return Action.C
        if current_round == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        if prev_opp_coop >= self.alpha:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_124(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource game.
    Implements a tit-for-tat with forgiveness logic, incorporating a sustainability
    override when stock is low and terminal defection in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if current_stock < 0.5 * self.capacity:
            return Action.C
        if self.n_opponents > 0:
            coop_count = history.opponent_cooperators[-1]
            cooperation_rate = coop_count / self.n_opponents
        else:
            cooperation_rate = 1.0
        if cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_125(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource game.
    
    This strategy uses a threshold-based approach:
    1. First round: Always Cooperate.
    2. Last round: Always Defect (to maximize final payoff).
    3. Near-Zero Stock: Defect (prevents wasting resources).
    4. Full Capacity: Prioritize Cooperation.
    5. General Case:
       - If stock is critical (< Capacity / 2N), Defect.
       - Else, compare previous round's cooperation count against N/2 (ceiling).
         Cooperate if threshold met, otherwise Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.max_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.max_rounds - 1:
            return Action.D
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if math.isclose(current_stock, self.capacity):
            if history.opponent_cooperators[-1] == 0:
                pass
            else:
                return Action.C
        last_action = history.my_actions[-1]
        last_coop_count = history.opponent_cooperators[-1] + (1 if last_action else 0)
        threshold = math.ceil(self.n / 2)
        if last_coop_count >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_126(BaseStrategy):
    """
    A strategy that adjusts cooperation probability based on recent defection history,
    current stock levels, and game progression, aiming to stabilize the pool at 50% capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.p_coop = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_stock <= 0:
            return Action.C
        if current_stock < 0.1 * capacity:
            self.p_coop = 1.0
            return Action.C
        if current_stock > 0.95 * capacity:
            last_round_idx = history.round_number - 1
            last_opp_coop = history.opponent_cooperators[last_round_idx]
            last_my_coop = history.my_actions[last_round_idx]
            opp_defectors = n - 1 - last_opp_coop
            k = opp_defectors + (0 if last_my_coop else 1)
            if k == 0:
                if n <= 10:
                    return Action.D
                else:
                    return Action.C
        if history.round_number < r - 1:
            last_round_idx = history.round_number - 1
            last_opp_coop = history.opponent_cooperators[last_round_idx]
            last_my_coop = history.my_actions[last_round_idx]
            k = n - 1 - last_opp_coop + (0 if last_my_coop else 1)
            d = k / (n - 1) if n > 1 else 0.0
            if current_stock > 0.9 * capacity and d == 0:
                self.p_coop = 1.0
            elif current_stock < 0.5 * capacity:
                if k > 0:
                    self.p_coop = max(0.0, self.p_coop - 0.5 * d)
                elif k == 0:
                    self.p_coop = min(1.0, self.p_coop + 0.1)
            elif current_stock >= 0.5 * capacity and k > 0:
                self.p_coop = max(0.2, self.p_coop - 0.2 * d)
            return Action.C if random.random() <= self.p_coop else Action.D
        if current_stock < 0.25 * capacity:
            return Action.D
        else:
            lookback = 3
            start_idx = max(0, history.round_number - lookback)
            relevant_payoffs = history.my_payoffs[start_idx:history.round_number]
            return Action.C

class Strategy_PROSOCIAL_127(BaseStrategy):
    """
    A Tit-for-Tat inspired strategy that incorporates a sustainability threshold.
    It cooperates if the previous round's cooperation count is sufficient to maintain
    or grow the stock, unless the stock is critically low (where it always rescues/cooperates).
    It includes a specific end-game condition and a reconciliation mechanism.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def _calculate_min_k_for_stability(self, stock: float) -> int:
        """
        Calculate min k such that S_next >= S_current.
        S_next = min(S_rem + 2 * S_rem * (1 - S_rem/capacity), capacity)
        S_rem = S - Consumption_total
        Consumption_total = (k * S / (2n)) + ((n - k) * S / n)
                          = S/n * (1 - k/2n)
        
        We need: S_rem + 2 * S_rem * (1 - S_rem/capacity) >= S
        Since 2 * S_rem * (1 - S_rem/capacity) is the growth term,
        the condition simplifies to: Growth >= Total Consumption.
        
        2 * S_rem * (1 - S_rem/capacity) >= S/n * (1 - k/(2n))
        
        This is a quadratic inequality in k, but we can solve for the integer k 
        by iterating or checking bounds. Given the problem constraint simplifies
        to checking if consumption <= growth:
        """
        if stock <= 0:
            return self.n
        for k in range(self.n + 1):
            s_rem = stock - stock / self.n * (1 - k / (2 * self.n))
            growth = 2 * s_rem * (1 - s_rem / self.capacity)
            consumption = stock / self.n * (1 - k / (2 * self.n))
            if s_rem + growth >= stock:
                return k
        return self.n

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        threshold_danger = self.capacity / (2 * self.n)
        if current_stock <= threshold_danger:
            return Action.C
        if history.round_number == self.r - 1:
            if history.round_number >= 3:
                recent_k = np.mean(history.opponent_cooperators[-3:])
                if recent_k < self.n - 1:
                    return Action.D
            return Action.C
        threshold_k = self._calculate_min_k_for_stability(current_stock)
        if history.opponent_cooperators[-1] >= threshold_k - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_128(BaseStrategy):
    """
    Implements Conditional Sustainability Maintenance strategy:
    - Round 1: Always cooperates to foster initial growth.
    - Final Round: Always defects to maximize final payoff.
    - Stock Safety Override: If stock is below the consumption threshold of a single cooperator (capacity / 2n), defects to attempt recovery.
    - Reciprocity: Based on the previous round, if the number of cooperating opponents meets the calculated threshold (ceil((n-1)/2)), continues to cooperate. Otherwise, defects to conserve/protect state.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = math.ceil((game_description.n_players - 1) / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        if round_idx == n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < self.game_description.capacity / (2 * n_players):
            return Action.D
        c_previous = history.opponent_cooperators[-1]
        if c_previous >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_33(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with sustainability monitoring.
    Prioritizes resource maintenance at 50% capacity, punishes defectors using a 
    grim-trigger mechanism when stock is low, and exploits the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._in_critical_punishment_phase = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock > 0.1 * self.game_description.capacity:
                return Action.D
            return Action.C
        if current_stock <= 0:
            return Action.C
        if current_stock < 0.25 * self.game_description.capacity:
            return Action.C
        n = self.game_description.n_players
        prev_my_action = history.my_actions[-1]
        n_c = history.opponent_cooperators[-1] + (1 if prev_my_action else 0)
        if n_c == n:
            self._in_critical_punishment_phase = False
            return Action.C
        elif current_stock < 0.4 * self.game_description.capacity:
            self._in_critical_punishment_phase = True
            return Action.D
        else:
            self._in_critical_punishment_phase = False
            return Action.C
        return Action.C

class Strategy_ALTRUISTIC_34(BaseStrategy):
    """
    Generous Tit-for-Tat with Sustainability Threshold:
    - Prioritizes sustainability: if stock < 0.25 * capacity, plays C regardless of history.
    - Round 1: Always plays C.
    - Round t > 1 (not final): Plays C if the cooperation rate in the previous round was > 0.5, else plays D.
    - Final Round: Plays C if avg historical cooperation > 0.6, else plays D.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_total = self.game_description.n_players
        self.n_opponents = self.n_total - 1
        self.s_crit = 0.25 * self.game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < self.s_crit:
            return Action.C
        if history.round_number == 0:
            return Action.C
        last_round_idx = -1
        my_last_action = int(history.my_actions[last_round_idx])
        total_cooperators_last_round = history.opponent_cooperators[last_round_idx] + my_last_action
        group_cooperation_index = total_cooperators_last_round / self.n_total
        if history.round_number == self.game_description.n_rounds - 1:
            my_actions_int = history.my_actions.astype(int)
            total_cooperators_all = np.sum(history.opponent_cooperators) + np.sum(my_actions_int)
            avg_cooperation = total_cooperators_all / (history.round_number * self.n_total)
            if avg_cooperation > 0.6:
                return Action.C
            else:
                return Action.D
        if group_cooperation_index > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_35(BaseStrategy):
    """
    Sustainable Tit-for-Tat: A conditional reciprocity strategy.
    
    Operates by maintaining cooperation as the default state. It punishes 
    defection by temporarily switching to defection, provided the resource 
    stock is high enough (above 50% capacity). If the stock is critical, 
    it prioritizes cooperation to allow for resource recovery, regardless 
    of opponent history.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            if current_stock <= self.capacity / 4:
                return Action.C
            else:
                return Action.D
        k_prev = history.opponent_cooperators[-1]
        num_opponents = self.n - 1
        if k_prev == num_opponents:
            return Action.C
        elif current_stock > self.capacity / 2:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_36(BaseStrategy):
    """
    Conditional Sustainability (Tit-for-Tat with Threshold) Strategy.
    
    This strategy prioritizes long-term resource sustainability. It starts by cooperating
    and subsequently adjusts its behavior based on the cooperation levels of others,
    stock recovery, and proximity to the final round. It employs a "tit-for-tat" 
    mechanism triggered by the aggregate cooperation of the group, while strictly 
    enforcing a conservation mode if the resource approaches critical levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        capacity = self.capacity
        total_rounds = self.r
        round_idx = history.round_number
        if current_stock < capacity / 4:
            return Action.C
        if round_idx == total_rounds - 1:
            if current_stock > capacity / 2:
                return Action.D
            else:
                return Action.C
        if round_idx == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_coop_prev = history.opponent_cooperators[-1]
        total_cooperators_prev = opp_coop_prev + (1 if my_prev_action else 0)
        last_action = Action.C if my_prev_action else Action.D
        if total_cooperators_prev <= n // 2:
            return Action.D
        if last_action == Action.C:
            if total_cooperators_prev >= n - 1:
                return Action.C
            else:
                return Action.D
        elif last_action == Action.D:
            if current_stock >= capacity / 2:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_ALTRUISTIC_37(BaseStrategy):
    """
    Conditional Sustainability: 
    - Round 1: Always Cooperate.
    - Last Round: Always Defect.
    - If Stock < 50% Capacity: Always Cooperate (Recovery).
    - If Stock >= 80% Capacity: Cooperate.
    - If Stock in (50%, 80%): Defect with probability P = 1 - c_prev (where c_prev is previous population cooperation rate).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.critical_threshold = 0.8 * self.capacity
        self.recovery_threshold = 0.5 * self.capacity
        self.n_players = float(game_description.n_players)
        self.n_opponents = self.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.recovery_threshold:
            return Action.C
        last_round_idx = -1
        last_opponents_coop = history.opponent_cooperators[last_round_idx]
        last_my_action = 1 if history.my_actions[last_round_idx] else 0
        c_prev = (last_opponents_coop + last_my_action) / self.n_players
        if current_stock >= self.critical_threshold:
            return Action.C
        prob_defect = 1.0 - c_prev
        if random.random() < prob_defect:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_38(BaseStrategy):
    """
    Implements a sustainable resource management strategy that prioritizes stock 
    regeneration when the pool is low (<= 20% capacity). In sustainable states,
    it employs a graded reciprocity (Tit-for-Tat variant) based on the previous 
    round's aggregate cooperation level to deter mass defection while remaining 
    forgiving of transient shocks.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.threshold = 0.2 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.threshold:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.C if current_stock >= self.threshold else Action.D
        last_self_action = Action.C if history.my_actions[-1] else Action.D
        last_total_cooperators = history.opponent_cooperators[-1] + (1 if last_self_action == Action.C else 0)
        k_target = self.n_players - 1
        if last_total_cooperators >= k_target:
            return Action.C
        defect_probability = 1.0 - last_total_cooperators / self.n_players
        if random.random() < defect_probability:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_39(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource Game.
    
    Logic:
    1. First Round: Always Cooperate (C) to signal cooperation.
    2. Last Round: If stock > 0, Cooperate (C) as an altruistic gesture.
    3. Intermediate Rounds:
       - Critical State: If stock < capacity * 0.25, force Cooperate (C) to recover.
       - Reciprocity: If stock is healthy, Cooperate (C) if the majority (>= ceil(n/2)) 
         cooperated in the previous round, otherwise Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.cooperation_threshold = math.ceil(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            return Action.C if current_stock > 0 else Action.D
        if current_stock < self.capacity * 0.25:
            return Action.C
        n_c = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators = n_c + (1 if my_last_action else 0)
        if total_cooperators >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_40(BaseStrategy):
    """
    Implements the Conditional Guardian strategy:
    - Round 1: Cooperate to signal baseline.
    - End-game: Cooperate to maximize altruism unless stock is critical.
    - Guardianship: 
        - Cooperate if stock < 40% capacity.
        - Cooperate if group cooperation ratio >= 0.5, else Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.game_description.n_rounds - 3:
            if current_stock < 0.05 * self.game_description.capacity:
                return Action.D
            return Action.C
        if current_stock < 0.4 * self.game_description.capacity:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        total_cooperators = prev_opp_coop + (1 if prev_my_action else 0)
        cooperation_ratio = total_cooperators / self.game_description.n_players
        if cooperation_ratio >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_41(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy that prioritizes stock maintenance.
    - Cooperates in the first round.
    - Defects in the final round.
    - If stock < capacity/2, enters Recovery Phase and forces Cooperation.
    - Otherwise, uses Tit-for-Tat logic: cooperates if everyone previously cooperated,
      otherwise uses probabilistic punishment based on the observed defection rate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.recovery_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.capacity / 2:
            self.recovery_counter = 2
            return Action.C
        if self.recovery_counter > 0:
            self.recovery_counter -= 1
            return Action.C
        if history.round_number == 0:
            return Action.C
        num_coop_opponents = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators = (1 if my_prev_action else 0) + num_coop_opponents
        num_defectors = self.n - total_cooperators
        if num_defectors == 0:
            return Action.C
        else:
            punishment_threshold = num_defectors / self.n
            if random.random() < punishment_threshold:
                return Action.D
            else:
                return Action.C

class Strategy_ALTRUISTIC_42(BaseStrategy):
    """
    Sustainable Tit-for-Tat with Conditional Forgiveness.
    
    Strategy:
    - Round 0: Always Cooperate (C).
    - Final Round: Always Defect (D).
    - Intermediate Rounds:
        - Maintains a sustainable stock by cooperating only if the previous round's 
          cooperation count was >= ceil(n / 2).
        - If the stock is depleted (approx 0) or the group falls into the "tragedy 
          of the commons," switch to Defect (D).
        - Includes a forgiveness mechanism: if the group returns to the cooperation 
          threshold, the strategy resumes cooperating.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_total = game_description.n_players
        self.cooperation_threshold = math.ceil(self.n_total / 2)
        self.epsilon = 1e-09

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        last_round = self.game_description.n_rounds - 1
        if current_round == last_round:
            return Action.D
        if current_round == 0:
            return Action.C
        my_last_action = int(history.my_actions[-1])
        prev_round_cooperation_count = history.opponent_cooperators[-1] + my_last_action
        if current_stock < self.epsilon:
            return Action.D
        if prev_round_cooperation_count >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_43(BaseStrategy):
    """
    Tit-for-Tat with Exponential Forgiveness.
    Prioritizes sustainability by cooperating (C) while the common pool resource is healthy.
    Uses a predictive model to switch to defection (D) if the system is collapsing,
    and includes an forgiveness mechanism if the stock recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_idx = -1
        opp_c = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        my_c_val = 1 if my_last_action else 0
        total_cooperators_prev = opp_c + my_c_val
        if not my_last_action:
            if current_stock >= 0.5 * self.capacity:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev == self.n:
            return Action.C
        defected_consumption = current_stock / (2 * self.n) * (2 * self.n - total_cooperators_prev)
        s_remaining = max(0.0, current_stock - defected_consumption)
        growth = 2 * s_remaining * (1.0 - s_remaining / self.capacity)
        s_next = min(s_remaining + growth, self.capacity)
        if s_next > self.capacity / self.n:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_44(BaseStrategy):
    """
    Implements a 'Conditional Sustenance' strategy for the Common Pool Resource Game.
    Prioritizes sustainability, utilizes Tit-for-Tat dynamics with forgiveness,
    and switches to defection in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators = prev_opp_coop + (1 if my_prev_action else 0)
        if current_stock < self.capacity * 0.25:
            return Action.C
        if total_cooperators >= self.n_players - 1:
            return Action.C
        if current_stock > self.capacity * 0.5:
            if my_prev_action == Action.D.value:
                return Action.C
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_45(BaseStrategy):
    """
    Tit-for-Tat with Restoration:
    Prioritizes sustainability by cooperating whenever the resource pool is healthy (>75% capacity) 
    or when perfect cooperation was observed in the previous round. Uses disciplinary 
    defection to punish non-cooperative groups when the stock is critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = float(game_description.n_players)
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.total_rounds - 1:
            if current_stock > self.capacity / self.n:
                return Action.C
            else:
                return Action.D
        prev_round_cooperators = int(history.opponent_cooperators[-1])
        my_prev_action = bool(history.my_actions[-1])
        total_cooperators_prev_round = prev_round_cooperators + (1 if my_prev_action else 0)
        if total_cooperators_prev_round == int(self.n):
            return Action.C
        else:
            threshold = self.capacity * 0.75
            if current_stock > threshold:
                return Action.C
            else:
                return Action.D

class Strategy_ALTRUISTIC_46(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Capacity Thresholds.
    Target: Maintain capacity to maximize long-term social welfare.
    Strategies include critical stock response, historical defection tracking,
    probabilistic cooperation signaling, and final-round extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.d_history = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx > 0:
            my_prev_action = history.my_actions[-1]
            k_opponents = history.opponent_cooperators[-1]
            k = k_opponents + (1 if my_prev_action else 0)
            if k < self.n:
                self.d_history += self.n - k
            if current_stock >= self.capacity * 0.5:
                self.d_history -= 1
            self.d_history = max(0, min(float(self.n), self.d_history))
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            if current_stock > self.capacity * 0.5:
                return Action.D
            return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.C
        if self.d_history > self.n / 2:
            return Action.D
        k_opponents = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        k = k_opponents + (1 if my_prev_action else 0)
        if current_stock > self.capacity * 0.75:
            return Action.C
        if k >= self.n - 1:
            return Action.C
        prob = k / self.n
        if random.random() < prob:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_47(BaseStrategy):
    """
    A Tit-for-Tat strategy with forgiveness and sustainability constraints for the Common Pool Resource Game.
    
    Strategy Logic:
    - Initialises cooperativeness to 1.
    - If in the final 3 rounds, ignores Tit-for-Tat and sets cooperativeness based on 
      critical stock levels: S > capacity/4 -> 0.5, S <= capacity/4 -> 1.0.
    - If not in final rounds and S < capacity/2, forces cooperation (C).
    - Otherwise, calculates target cooperativeness: (opponents_C / (n - 1)) + 0.05.
    - Actions are chosen probabilistically based on target cooperativeness.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.delta = 0.05

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.r - 3:
            if current_stock <= self.capacity / 4.0:
                return Action.C
            else:
                return Action.C if random.random() < 0.5 else Action.D
        if current_stock < self.capacity / 2.0:
            return Action.C
        k_t_prev = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        i_t = 1 if my_last_action else 0
        if self.n > 1:
            opponents_c_count = k_t_prev - i_t
            opponents_c_count = max(0, min(self.n - 1, opponents_c_count))
            coop_rate = opponents_c_count / (self.n - 1)
            target_c = min(1.0, coop_rate + self.delta)
        else:
            target_c = 1.0
        return Action.C if random.random() < target_c else Action.D

class Strategy_ALTRUISTIC_48(BaseStrategy):
    """
    Implements an Altruistic Target strategy for the Common Pool Resource Game.
    Focuses on sustainability by aiming for stock levels near capacity/2, 
    using Tit-for-Tat with probabilistic forgiveness, and handling 
    resource depletion edge cases.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        if round_t == 0:
            return Action.C
        if round_t == self.r - 1:
            return Action.D
        if current_stock < 1.0:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.D
        k_previous = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if k_previous >= self.n / 2:
            return Action.C
        p = k_previous / self.n
        if random.random() < p:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_49(BaseStrategy):
    """
    A strategy that maximizes long-term resource sustainability using a Tit-for-Tat 
    variant. It defaults to cooperation, reacts to group cooperation levels 
    (conditional Tit-for-Tat), prioritizes regeneration when stocks are low, 
    and defects in the final round to maximize individual payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        if round_t == self.n_rounds - 1:
            return Action.D
        if round_t == 0:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.C
        last_round_opponents_c = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        k_prev = last_round_opponents_c + (1 if my_last_action else 0)
        if k_prev > self.n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_50(BaseStrategy):
    """
    Implements a Conditional Stewardship strategy for the Common Pool Resource Game.
    Maintains the common pool at target capacity (capacity / 2) by cooperating when 
    the stock is vulnerable or when the population shows sufficient cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.target_stock = game_description.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == n_rounds - 1:
            if current_stock < self.game_description.capacity / n_players:
                return Action.C
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + my_prev_action
        fraction_cooperators = total_cooperators / n_players
        if current_stock <= self.target_stock:
            return Action.C
        elif fraction_cooperators >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_51(BaseStrategy):
    """
    Implements a Generous Tit-for-Tat strategy with sustainability thresholds.
    Focuses on stock preservation when low, dynamic retaliation based on 
    reputation, and greedy exploitation only when resource buffers are secure.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.target_threshold = 0.75 * self.capacity
        self.critical_threshold = 0.25 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        prev_my_action = history.my_actions[prev_round]
        prev_opponent_coops = history.opponent_cooperators[prev_round]
        my_prev_coop = 1 if prev_my_action else 0
        k = prev_opponent_coops + my_prev_coop
        if current_stock < self.critical_threshold:
            return Action.C
        if history.round_number >= 3:
            last_3_rounds = history.my_actions[-3:]
            last_3_opp_coops = history.opponent_cooperators[-3:]
            if all((opp_c < self.n - 1 for opp_c in last_3_opp_coops)):
                return Action.D
        if self.desc.n_rounds - history.round_number <= 2:
            if current_stock > 0.5 * self.capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < self.target_threshold:
            return Action.C
        if k == self.n:
            if current_stock >= 0.95 * self.capacity:
                return Action.D
            return Action.C
        else:
            p = (self.n - k) / self.n
            if random.random() < p:
                return Action.D
            else:
                return Action.C

class Strategy_ALTRUISTIC_52(BaseStrategy):
    """
    Implements a 'Conditional Altruistic Sustainable Growth' strategy.
    
    The strategy prioritizes maintaining the common pool stock at capacity. 
    It cooperates if the previous round was fully cooperative, or if the current
    stock is high enough despite previous defections to potentially recover.
    It defects if sustainability is compromised (stock <= capacity/2) or if 
    it detects that opponents' behavior will likely drive the stock below 
    the critical threshold in the next round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.threshold_crit = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 1e-06:
            return Action.D
        if history.round_number == 0:
            return Action.C
        was_i_cooperating = int(history.my_actions[-1])
        n_prev_coop = history.opponent_cooperators[-1] + was_i_cooperating
        d_prev = self.n - n_prev_coop
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock >= self.threshold_crit:
                return Action.C
            return Action.D
        if d_prev == 0:
            return Action.C
        predicted_rem = current_stock * (1.0 - (self.n + d_prev) / (2.0 * self.n))
        if current_stock <= self.threshold_crit or predicted_rem < self.threshold_crit:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_53(BaseStrategy):
    """
    Sustainable Tit-for-Tat (STFT) strategy:
    A conditionally cooperative strategy that prioritizes long-term resource 
    sustainability over short-term gain. It cooperates based on group 
    cooperation thresholds, critical stock levels, and endgame proximity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.n_total = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        r_rem = self.total_rounds - history.round_number
        cooperators_prev = history.opponent_cooperators[-1]
        if current_stock < self.capacity * 0.25:
            return Action.C
        if r_rem < 3:
            if current_stock < self.capacity * 0.4:
                return Action.C
            else:
                return Action.D
        if cooperators_prev >= self.n_total * 0.75:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_54(BaseStrategy):
    """
    A Tit-for-Tat variant designed for sustainable resource management.
    Prioritizes collective survival by cooperating when others cooperate,
    or when the stock level is critically low. Resorts to defection only
    when necessary for survival or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.n_rounds = self.game_description.n_rounds
        self.capacity = self.game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        current_round_num = current_round_idx + 1
        if current_round_num == self.n_rounds:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        opponents_prev_coop = history.opponent_cooperators[-1]
        total_cooperators = opponents_prev_coop + (1 if my_prev_action == Action.C else 0)
        if total_cooperators >= self.n / 2:
            return Action.C
        if current_stock < self.capacity / 4:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_55(BaseStrategy):
    """
    Implements Tit-for-Tat with Threshold-Based Forgiveness (TFT-TF).
    
    This strategy prioritizes sustainability of the common pool resource.
    It cooperates initially and continues to cooperate if the group as a whole 
    sustains the resource (Majority Reciprocity). It defects if the resource 
    reaches a critical low threshold (25% capacity) or if the group's cooperation 
    falls below the majority threshold. It always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity * 0.25:
            return Action.D
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = history.opponent_cooperators[-1] + my_last_action_val
        threshold = self.game_description.n_players / 2
        if total_prev_cooperators >= threshold:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_56(BaseStrategy):
    """
    Sustainable Conditional Cooperation strategy.
    
    This strategy aims to maintain the common pool stock at capacity while incentivizing
    others to cooperate. It follows these principles:
    1. Start with Cooperation (C).
    2. Near-zero stock recovery: If stock < 0.1 * capacity, forces C to save the system.
    3. End-game: If within the last 3 rounds, uses a specific trigger based on 
       cooperation history (switch to D if group cooperation < 50%).
    4. Adaptive Response: If stock is low (< 0.2 * capacity), plays D only if 
       necessary; otherwise uses a probabilistic response based on previous
       defectors to pressure others while signaling C.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.total_rounds_cooperated = 0
        self.total_rounds_played = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        capacity = self.game_description.capacity
        r_current = history.round_number
        my_prev_action = history.my_actions[-1]
        my_prev_coop_val = 1 if my_prev_action else 0
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_coop = prev_opp_coop + my_prev_coop_val
        prev_defectors = n - prev_total_coop
        if r_total - r_current < 3:
            if my_prev_action:
                self.total_rounds_cooperated += 1
            self.total_rounds_played += 1
            cumulative_coop_rate = self.total_rounds_cooperated / self.total_rounds_played
            if prev_defectors / n > 0.5:
                return Action.D
            elif cumulative_coop_rate < 0.75:
                if prev_defectors / n > 0.5:
                    return Action.D
            return Action.C
        if current_stock < 0.1 * capacity:
            return Action.C
        if prev_defectors == 0:
            return Action.C
        if current_stock < 0.2 * capacity:
            return Action.D
        else:
            prob_coop = 1.0 - prev_defectors / n
            if random.random() < prob_coop:
                return Action.C
            else:
                return Action.D

class Strategy_ALTRUISTIC_57(BaseStrategy):
    """
    Implements the Adaptive Sustainable Tit-for-Tat strategy.
    
    This strategy focuses on maintaining long-term sustainability of the common pool
    by employing a majority-cooperation threshold. It dynamically adjusts between
    cooperation and defection based on group behavior and absolute resource levels,
    while rewarding consistent cooperation in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = math.ceil(0.5 * self.game_description.n_players)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_round_total_cooperators = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if history.round_number == self.game_description.n_rounds - 1:
            cooperation_count = np.sum(history.my_actions)
            if cooperation_count / history.round_number > 0.5:
                return Action.C
            else:
                return Action.D
        if current_stock < 0.2 * self.game_description.capacity:
            return Action.D
        if prev_round_total_cooperators >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_58(BaseStrategy):
    """
    Implements a sustainable cooperation model that monitors the common pool resource.
    - Prioritizes recovery (Cooperate) if the stock is below a critical threshold (25% capacity).
    - If stock is healthy, uses a reciprocating strategy: continues to cooperate if the 
      group maintains stock, or if the majority (>= 75%) cooperated in the previous round.
    - Includes a specific final-round heuristic: Defect if the stock is high (> 50%),
      otherwise Cooperate to avoid resource exhaustion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock == 0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            if current_stock > self.capacity * 0.5:
                return Action.D
            else:
                return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.C
        my_last_action = history.my_actions[-1]
        opponents_coop_last = history.opponent_cooperators[-1]
        total_coop_last = opponents_coop_last + (1 if my_last_action else 0)
        cooperation_threshold = math.floor(self.n * 0.75)
        if total_coop_last >= cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_59(BaseStrategy):
    """
    Sustainable Conditional Reciprocity (SCR) Strategy:
    Prioritizes resource sustainability by cooperating when stock is low,
    reciprocating collective cooperation when stock is healthy,
    and defecting in the final round based on stock status.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.threshold = 0.25 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            if current_stock > 0.5 * self.capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < self.threshold:
            return Action.C
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators_last_round = history.opponent_cooperators[-1] + my_last_action_val
        if total_cooperators_last_round >= self.n_players // 2:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_60(BaseStrategy):
    """
    Implements a Conditional Sustenance Tit-for-Tat strategy for the Common Pool Resource game.
    
    Logic:
    1. First Round: Always Cooperate (C) to signal cooperation.
    2. Sustainability Threshold: If current_stock < (0.25 * capacity), Defect (D) to prevent depletion.
    3. Reciprocity: 
       - If prev_cooperators >= n/2, Cooperate (C).
       - If prev_cooperators < n/2, Defect (D).
    4. Final Round Override: Follows the same logic as the reciprocity step (as implemented in the pseudocode).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_total_cooperators = history.opponent_cooperators[-1] + prev_my_action
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if prev_total_cooperators >= self.n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_61(BaseStrategy):
    """
    Sustainable Tit-for-Tat (STFT):
    A strategy that maintains common pool resources by cooperating in the first round 
    and mirroring group cooperativeness (with a threshold of n-2) in subsequent rounds, 
    provided the stock remains viable. It defects in the final round to maximize 
    harvest, and defects early if the resource is below the critical viability threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.s_crit = self.game_description.capacity / (2 * self.game_description.n_players)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        total_rounds = self.game_description.n_rounds
        if t == total_rounds - 1:
            return Action.D
        if current_stock < self.s_crit:
            return Action.D
        if t == 0:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        threshold = self.game_description.n_players - 2
        if history.opponent_cooperators[-1] >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_62(BaseStrategy):
    """
    Conditional Cooperative Regeneration Strategy:
    Prioritizes sustainability of the common pool resource by maintaining 
    cooperation unless the pool is collapsing or the end of the game is reached.
    Implements a 'Scavenger' fallback when depletion is inevitable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        cap = self.game_description.capacity
        round_t = history.round_number
        if round_t == r - 1:
            return Action.D
        if current_stock <= 0.1 * cap:
            return Action.D
        if round_t == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        k = prev_opp_coop + (1 if prev_my_action else 0)
        if k == n:
            return Action.C
        if current_stock > 0.25 * cap:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_63(BaseStrategy):
    """
    A Tit-for-Tat inspired strategy that prioritizes stock preservation.
    It cooperates in healthy states, enters conditional cooperation when the stock 
    is threatened, and liquidates in the final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.sustainability_threshold = game_description.capacity / 2.0
        self.n_players = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if rounds_remaining < 3:
            return Action.D
        if current_stock >= self.sustainability_threshold:
            return Action.C
        my_last_action = history.my_actions[-1]
        prev_opp_cooperators = history.opponent_cooperators[-1]
        total_cooperators = (1 if my_last_action else 0) + prev_opp_cooperators
        if total_cooperators >= self.n_players / 2.0:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_64(BaseStrategy):
    """
    Implements a 'Conditional Tit-for-Tat with Resilience' strategy.
    
    This strategy focuses on sustaining the common pool resource by cooperating 
    by default, forgiving minor defections if the stock is healthy, but 
    switching to aggressive extraction (Defection) if the stock is critically 
    low or if the collective cooperation falls below a necessary threshold to 
    sustain the pool.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r_index = history.round_number
        total_rounds = self.game.n_rounds
        if r_index == 0:
            return Action.C
        opp_c = int(history.opponent_cooperators[-1])
        n_opp = self.game.n_players - 1
        if r_index == total_rounds - 1:
            if current_stock > 0.25 * self.game.capacity:
                return Action.C
            else:
                return Action.D
        if opp_c == n_opp:
            return Action.C
        if current_stock > 0.5 * self.game.capacity and opp_c >= n_opp - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_65(BaseStrategy):
    """
    Implements a resource-conscious strategy that prioritizes long-term sustainability.
    
    The strategy follows these rules:
    - Always cooperates on the first round.
    - Always defects on the last round if stock > 0.
    - Maintains a target stock level at 80% capacity.
    - Cooperates if stock is healthy (>= 80% capacity) and defection is minimal (<= 1 defector).
    - Defects as a defensive "correction" measure if the stock is collapsing (num_cooperators < n/2) 
      to prevent total depletion and force an end to the current unsustainable trajectory.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.target_stock = game_description.capacity * 0.8
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number + 1
        if round_num == 1:
            return Action.C
        if round_num == self.r:
            return Action.D if current_stock > 0 else Action.C
        my_prev_action = history.my_actions[-1]
        opp_coop_count = history.opponent_cooperators[-1]
        total_cooperators = (1 if my_prev_action else 0) + opp_coop_count
        s_prev = current_stock
        if s_prev >= self.target_stock and total_cooperators >= self.n - 1:
            return Action.C
        if total_cooperators < self.n / 2.0:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_66(BaseStrategy):
    """
    A Tit-for-Tat variant with a regenerative threshold.
    Prioritizes sustainability by cooperating during growth phases and punishing
    excessive consumption, while forcing regeneration when stock levels drop dangerously low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_punishing = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        if round_idx == 0:
            return Action.C
        if round_idx == self.game_description.n_rounds - 1:
            if current_stock > 0.2 * capacity:
                return Action.C
            else:
                return Action.D
        if current_stock <= 0.5 * capacity:
            self.is_punishing = False
            return Action.C
        last_round_opp_coop_count = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        my_last_action_int = 1 if my_last_action else 0
        total_cooperators = last_round_opp_coop_count + my_last_action_int
        observed_cooperation_rate = total_cooperators / n_players
        if self.is_punishing:
            self.is_punishing = False
            return Action.C
        if observed_cooperation_rate >= 0.5:
            return Action.C
        else:
            self.is_punishing = True
            return Action.D

class Strategy_ALTRUISTIC_67(BaseStrategy):
    """
    A sophisticated strategy for the Common Pool Resource Game based on reputation
    tracking and resource-state awareness, aiming to maximize sustainability while
    protecting against exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.reputation = 1.0
        self.T = self.capacity * 0.5
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if self.n_opponents > 0:
            self.reputation = self.reputation * 0.9 + 0.1 * (prev_cooperators / self.n_opponents)
        else:
            self.reputation = 1.0
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D if self.reputation < 0.5 else Action.C
        if current_stock > self.T:
            return Action.C
        if current_stock < self.T * 0.5:
            if self.reputation < 0.1:
                return Action.D
            return Action.C
        if current_stock < self.capacity * 0.25:
            if self.reputation < 0.3:
                return Action.D
            else:
                return Action.C
        else:
            avg_opp_coop = prev_cooperators / self.n_opponents
            total_consumption = current_stock * (1 - avg_opp_coop / 2)
            s_remaining = current_stock - total_consumption
            growth = 2 * s_remaining * (1 - s_remaining / self.capacity) if self.capacity > 0 else 0
            s_next = min(s_remaining + growth, self.capacity)
            if s_next < self.capacity * 0.1:
                return Action.D
            else:
                return Action.C

class Strategy_ALTRUISTIC_68(BaseStrategy):
    """
    Tit-for-Tat with Sustainable Thresholds:
    Maintains the common pool resource at capacity by cooperating when healthy,
    punishing defectors when the stock is sufficient, and abandoning preservation
    efforts when the stock is critical or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        current_round = round_idx + 1
        if current_round == self.n_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        if current_stock <= self.capacity / 2.0:
            return Action.D
        n_opponents = self.n_players - 1
        cooperators_prev = history.opponent_cooperators[-1]
        defectors_prev = n_opponents - cooperators_prev
        if defectors_prev <= self.n_players / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_69(BaseStrategy):
    """
    Adaptive Tit-for-Tat Sustainability (ATTS) strategy.
    Prioritizes sustainability via conditional cooperation, with specific rules 
    for low-stock recovery, final-round defection, and permanent-defection shifts 
    when the environment is deemed non-cooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.consecutive_defections = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 0.1 * self.capacity:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock > 0:
                return Action.D
        if history.round_number == 0:
            return Action.C
        opponents_cooperated = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if opponents_cooperated < n_opponents:
            self.consecutive_defections += 1
        else:
            self.consecutive_defections = 0
        if self.consecutive_defections >= 3 and current_stock >= 0.25 * self.capacity:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        if opponents_cooperated < n_opponents:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_70(BaseStrategy):
    """
    Sustainable Cooperative Tit-for-Tat (SCTT) Strategy.
    Balances resource preservation with population cooperation trends.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        c_history = []
        for i in range(t):
            my_c = 1 if history.my_actions[i] else 0
            total_c = my_c + history.opponent_cooperators[i]
            c_history.append(total_c)
        if t > self.r - 4:
            if current_stock > self.capacity / (2 * self.n):
                return Action.C
            else:
                return Action.D
        if current_stock < 0.05 * self.capacity:
            return Action.D
        if current_stock < self.threshold:
            if c_history[-1] >= self.n - 1:
                return Action.C
            else:
                return Action.D
        avg_cooperation = sum(c_history) / (t * self.n)
        if avg_cooperation >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_71(BaseStrategy):
    """
    Implements a Reciprocal Stewardship strategy.
    The strategy maintains cooperation to maximize long-term resource stock,
    but dynamically shifts to defection during critical collapses or 
    unilateral defection clusters, while ensuring altruism in terminal rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        if history.round_number == 0:
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        if history.round_number == total_rounds - 1:
            if current_stock <= 0.25 * capacity:
                return Action.D
            return Action.C
        if current_stock <= 0.25 * capacity:
            return Action.D
        if current_stock >= 0.75 * capacity:
            return Action.C
        if k_prev >= n / 2:
            return Action.C
        if current_stock < 0.5 * capacity and k_prev < n / 2:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_72(BaseStrategy):
    """
    A strategy that maintains cooperation while resources are sufficient, uses a 
    probabilistic mechanism to punish non-cooperation when the resource is declining,
    and defaults to defection in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = float(self.game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        r = self.game_description.n_rounds
        round_idx = history.round_number
        if round_idx == r - 1:
            self.prev_stock = current_stock
            return Action.D
        if round_idx == 0:
            self.prev_stock = current_stock
            return Action.C
        critical_threshold = self.game_description.capacity * 0.2
        if current_stock < critical_threshold:
            self.prev_stock = current_stock
            return Action.D
        prev_k = history.opponent_cooperators[-1]
        if prev_k >= n_opponents:
            self.prev_stock = current_stock
            return Action.C
        is_growth_negative = current_stock < self.prev_stock
        if is_growth_negative:
            defection_denominator = float(n_opponents) if n_opponents > 0 else 1.0
            defection_probability = 1.0 - prev_k / defection_denominator
            self.prev_stock = current_stock
            if random.random() < defection_probability:
                return Action.D
            else:
                return Action.C
        self.prev_stock = current_stock
        return Action.C

class Strategy_ALTRUISTIC_73(BaseStrategy):
    """
    A strategy that aims to maintain stock near a target buffer (75% of capacity).
    It uses an exponentially weighted moving average (EMA) of opponent cooperation
    to project future stock levels and makes decisions based on sustainability,
    reciprocal restraint, and last-round defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.alpha = 0.9
        self.target_stock = game_description.capacity * 0.75
        self.opponent_avg_coop_rate = 1.0
        self.n = game_description.n_players
        self.n_opponents = self.n - 1

    def _calculate_next_stock(self, current_stock: float, my_action: Action, opponent_coop_rate: float) -> float:
        cons_c = current_stock / (2 * self.n)
        cons_d = current_stock / self.n
        my_cons = cons_c if my_action == Action.C else cons_d
        opp_cons = self.n_opponents * (opponent_coop_rate * cons_c + (1 - opponent_coop_rate) * cons_d)
        total_consumption = my_cons + opp_cons
        s_remaining = max(0.0, current_stock - total_consumption)
        growth = 2 * s_remaining * (1 - s_remaining / self.game_description.capacity)
        return min(self.game_description.capacity, s_remaining + growth)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_opp_coops = history.opponent_cooperators[-1]
        current_coop_fraction = prev_opp_coops / self.n_opponents if self.n_opponents > 0 else 1.0
        self.opponent_avg_coop_rate = self.alpha * self.opponent_avg_coop_rate + (1 - self.alpha) * current_coop_fraction
        potential_recovery = self._calculate_next_stock(current_stock, Action.C, 1.0)
        if current_stock < 0.1 * self.game_description.capacity and potential_recovery < 0.1 * self.game_description.capacity:
            return Action.D
        if current_stock <= self.game_description.capacity / self.n:
            return Action.D
        proj_stock_c = self._calculate_next_stock(current_stock, Action.C, self.opponent_avg_coop_rate)
        if proj_stock_c >= self.target_stock:
            return Action.C
        else:
            proj_stock_d = self._calculate_next_stock(current_stock, Action.D, self.opponent_avg_coop_rate)
            if proj_stock_d < self.game_description.capacity / (2 * self.n):
                return Action.C
            else:
                return Action.D

class Strategy_ALTRUISTIC_74(BaseStrategy):
    """
    Implements a 'Sustainable Reciprocity' strategy. 
    It cooperates initially to build the pool, then adapts based on the previous round's 
    collective behavior. It defaults to defection if the remaining stock is critically 
    low or if the population is predominantly defecting. It unconditionally defects 
    in the final round to maximize utility before the game ends.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_opp_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        prev_total_cooperators = prev_opp_cooperators + (1 if my_prev_action else 0)
        n = self.game_description.n_players
        consumption_per_c = current_stock / (2 * n)
        consumption_per_d = current_stock / n
        prev_total_consumption = prev_total_cooperators * consumption_per_c + (n - prev_total_cooperators) * consumption_per_d
        remaining_stock = current_stock - prev_total_consumption
        if remaining_stock < 0.25 * self.game_description.capacity:
            return Action.D
        if prev_total_cooperators >= n / 2:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_75(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    This strategy prioritizes the long-term health of the common pool resource.
    It initiates with cooperation, maintains cooperation when the pool is healthy
    or when others are cooperating, and defaults to protective cooperation
    even in the face of some exploitation. It only defects in the terminal
    round if the resource is in a collapsing state, or under very specific 
    threat-mitigation conditions during standard play when extinction is imminent.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        current_round = history.round_number + 1
        prev_round_idx = history.round_number - 1
        my_prev_action = history.my_actions[prev_round_idx]
        prev_coop_others = history.opponent_cooperators[prev_round_idx]
        total_cooperators_prev = prev_coop_others + (1 if my_prev_action else 0)
        if current_round == r:
            if current_stock >= capacity * 0.5:
                return Action.C
            else:
                return Action.D
        if current_stock < capacity * 0.2:
            return Action.C
        if total_cooperators_prev == n:
            return Action.C
        if current_stock >= capacity * 0.5:
            return Action.C
        if current_stock < capacity * 0.5 and total_cooperators_prev < n:
            if current_stock < capacity * 0.1:
                return Action.D
            return Action.C
        return Action.C

class Strategy_ALTRUISTIC_76(BaseStrategy):
    """
    A cooperative strategy that monitors stock sustainability and employs a
    tit-for-tat reciprocity mechanism to maximize collective welfare. It defaults
    to cooperation but punishes widespread defection and protects the common
    pool stock when it drops below a safety threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        last_my_action_bool = history.my_actions[-1]
        last_my_action = Action.C if last_my_action_bool else Action.D
        last_opp_coop = history.opponent_cooperators[-1]
        num_opponents = self.n - 1
        total_cooperators_last = last_opp_coop + (1 if last_my_action == Action.C else 0)
        opp_cooperators_count = last_opp_coop
        if t == self.r - 1:
            if total_cooperators_last < self.n / 2:
                return Action.D
            return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.D
        if num_opponents > 0 and opp_cooperators_count < num_opponents / 2:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_77(BaseStrategy):
    """
    A Common Pool Resource strategy that prioritizes sustainability through
    conditional cooperation (tit-for-tat variant) while employing a "grim-trigger" 
    style defection if the resource collapses, with a forgiveness mechanism 
    when the stock recovers sufficiently.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.collapse_threshold = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            if current_stock > 0.1:
                return Action.D
            return Action.C
        my_last_action = history.my_actions[-1]
        k_prev = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        if current_stock > 0.75 * self.capacity:
            return Action.C
        if current_stock <= 1e-09:
            return Action.D
        if current_stock < self.capacity / self.n and k_prev < self.n:
            return Action.D
        if current_stock >= self.capacity / self.n:
            if k_prev >= math.floor(self.n / 2):
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_ALTRUISTIC_78(BaseStrategy):
    """
    Conditional Tit-for-Tat with Resilience Thresholds.
    
    Strategy:
    1. Initial Round: Always Cooperate (C).
    2. Termination (Last Round): 
       - If stock > 0.5 * capacity, Defect (D) to claim remaining resources.
       - If stock <= 0.5 * capacity, Cooperate (C) to support pool health.
    3. Intermediate Rounds:
       - If stock <= 0.25 * capacity, Cooperate (C) (Emergency mode).
       - If stock > 0.25 * capacity:
         - Cooperate (C) if previous round's cooperation rate (rho) >= 0.5.
         - Defect (D) otherwise.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            if current_stock > 0.5 * self.capacity:
                return Action.D
            else:
                return Action.C
        s_crit = 0.25 * self.capacity
        if current_stock <= s_crit:
            return Action.C
        last_self_action = int(history.my_actions[-1])
        total_cooperators = history.opponent_cooperators[-1] + last_self_action
        rho = total_cooperators / self.n
        if rho >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_79(BaseStrategy):
    """
    Implements a sustainable reciprocity strategy for the Common Pool Resource game.
    Prioritizes maintaining stock levels when low, uses Tit-for-Tat logic based on
    group cooperation thresholds when stock is healthy, and defects in the final
    round to capture remaining value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.C
        last_round_idx = -1
        last_round_my_action = history.my_actions[last_round_idx]
        my_cooperation_val = 1 if last_round_my_action else 0
        total_cooperators = history.opponent_cooperators[last_round_idx] + my_cooperation_val
        threshold = self.n // 2
        if total_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_80(BaseStrategy):
    """
    Green Tit-for-Tat with Restoration:
    Prioritizes sustainability of the common pool by enforcing restoration rules 
    when stock levels are critical. In robust states, it employs a Tit-for-Tat 
    mechanism to punish defectors unless the pool is at 90% capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == self.n_rounds - 1:
            if current_stock > self.capacity / 2:
                return Action.C
            else:
                return Action.D
        if current_stock < 0.9 * self.capacity:
            return Action.C
        last_round_cooperators = int(history.opponent_cooperators[-1])
        if last_round_cooperators >= self.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_81(BaseStrategy):
    """
    Sustainable Tit-for-Tat (STFT): A strategy designed to maintain capacity
    and discourage defection. It cooperates in the first round and maintains 
    cooperation as long as the stock is healthy and no one defected in the 
    previous round. It punishes any detected defection by defecting for one 
    round and switches to pure conservation (cooperation) if the stock 
    drops below half capacity. In the final round, it defects if the 
    stock is non-zero to maximize final payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D if current_stock > 0 else Action.C
        if current_stock < self.capacity / 2.0:
            return Action.C
        if round_idx == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        num_opponents = self.n - 1
        num_opp_defectors = num_opponents - prev_opp_coop
        my_defected = not prev_my_action
        total_defections = num_opp_defectors + (1 if my_defected else 0)
        if total_defections > 0:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_82(BaseStrategy):
    """
    Conditional Sustainability Cooperation (CSC) Strategy:
    Prioritizes maintaining common pool stock at carrying capacity.
    Operates via reciprocal altruism, punishing defectors only when projected
    sustainability is compromised.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = float(self.game_description.capacity)
        r = self.game_description.n_rounds
        t = history.round_number
        if t == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_coop_prev = history.opponent_cooperators[-1]
        n_c = opp_coop_prev + (1 if my_prev_action else 0)
        if current_stock < 0.25 * capacity:
            return Action.C
        if t == r - 1:
            return Action.C if n_c == n else Action.D
        if n_c == n:
            return Action.C
        else:
            total_consumption = current_stock / (2 * n) * (2 * n - n_c)
            s_remaining = max(0.0, current_stock - total_consumption)
            growth = 2 * s_remaining * (1 - s_remaining / capacity)
            next_s = min(s_remaining + growth, capacity)
            if next_s > 0.5 * capacity:
                return Action.C
            else:
                return Action.D

class Strategy_ALTRUISTIC_83(BaseStrategy):
    """
    Adaptive Sustainable Stewardship:
    A Tit-for-Tat variant designed to maintain stock levels near capacity/2.
    It cooperates to sustain the pool, punishes defectors if cooperation drops
    below a threshold, and defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        current_round_num = current_round_idx + 1
        if current_round_num == self.r:
            return Action.D
        if current_round_num == 1:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        total_cooperators_prev = last_opponent_coops + (1 if last_my_action else 0)
        if current_stock < self.capacity / 4 and total_cooperators_prev < self.n:
            return Action.D
        if total_cooperators_prev >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_84(BaseStrategy):
    """
    Tit-for-Tat with Forgiving Resilience Strategy.
    
    Operates by monitoring the common pool resource health and opponent cooperativeness.
    - If stock is >= 50% capacity: Cooperates if the majority of opponents cooperated.
    - If stock is < 50% capacity: Cooperates only if ALL opponents cooperated (desperate measure).
    - In the final round: Always Defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold_healthy = 0.5 * self.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        current_round_num = current_round_index + 1
        if current_round_num == self.r:
            return Action.D
        if current_round_index == 0:
            return Action.C
        prev_opponents_cooperated = int(history.opponent_cooperators[-1])
        if current_stock >= self.threshold_healthy:
            if prev_opponents_cooperated >= self.n // 2:
                return Action.C
            else:
                return Action.D
        elif prev_opponents_cooperated == self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_85(BaseStrategy):
    """
    Implements the 'Sustainable Reciprocity' strategy.
    Maintains a reputation belief system to conditionalize cooperation, 
    with a focus on stock regeneration when the common pool is critical.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 1.0
        self.forced_regen_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        prev_round_idx = history.round_number - 1
        prev_opp_coop = history.opponent_cooperators[prev_round_idx]
        n_opponents = n - 1
        obs_rate = prev_opp_coop / n_opponents if n_opponents > 0 else 0.0
        self.reputation = 0.9 * self.reputation + 0.1 * obs_rate
        if current_stock < 0.25 * capacity and obs_rate > 0.1:
            self.forced_regen_counter = 2
        if self.forced_regen_counter > 0:
            self.forced_regen_counter -= 1
            return Action.C
        if history.round_number + 1 == r:
            consumption_c = current_stock / (2.0 * n)
            if current_stock - consumption_c >= capacity / 2.0:
                return Action.C
            else:
                return Action.D
        threshold = 0.5 if current_stock > 0.5 * capacity else 0.8
        if self.reputation >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_86(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with conditional stock recovery.
    Cooperates when the stock is healthy or when others are cooperating.
    Defects during the endgame, when the stock is critically low, or when 
    the group shows high defection rates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = float(game_description.capacity)
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if round_idx == 0:
            self.prev_stock = current_stock
            return Action.C
        if round_idx >= total_rounds - 3:
            self.prev_stock = current_stock
            return Action.D
        if current_stock <= 0.1 * self.capacity:
            self.prev_stock = current_stock
            return Action.D
        if current_stock >= self.capacity:
            self.prev_stock = current_stock
            return Action.C
        prev_coop_opponents = history.opponent_cooperators[-1]
        my_prev_action_bool = history.my_actions[-1]
        prev_total_cooperators = prev_coop_opponents + (1 if my_prev_action_bool else 0)
        s_prev = self.prev_stock
        n = self.n
        consumption_coop = prev_total_cooperators * (s_prev / (2 * n))
        consumption_defect = (n - prev_total_cooperators) * (s_prev / n)
        prev_total_consumption = consumption_coop + consumption_defect
        expected_stock_after_cons = s_prev - s_prev / 2
        expected_growth = 2 * expected_stock_after_cons * (1 - expected_stock_after_cons / self.capacity)
        expected_new_stock = min(expected_stock_after_cons + expected_growth, self.capacity)
        self.prev_stock = current_stock
        if current_stock >= 0.95 * expected_new_stock:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.D
        if prev_total_consumption > 0.6 * s_prev:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_87(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    This strategy prioritizes long-term common pool health:
    1. Round 1: Always Cooperate (C).
    2. Terminal Round (r): Always Defect (D) to maximize final utility.
    3. Emergency: If stock < capacity/4, Defect (D) to salvage utility.
    4. Reciprocity: 
       - Cooperate (C) if previous round had full cooperation.
       - If previous round had defection (cooperator count < n-1), punish by Defecting (D) for one round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / 4.0:
            return Action.D
        last_opponents_cooperating = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators = last_opponents_cooperating + (1 if my_last_action else 0)
        if total_cooperators == self.n:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_88(BaseStrategy):
    """
    A strategy that aims to maximize collective yield by maintaining the stock 
    near its capacity through conditional cooperation, while reserving the 
    option to defect when the resource is threatened or the group fails to 
    cooperate.

    Decision rules:
    - Last round (r-1): Always defect (D).
    - First round: Always cooperate (C).
    - High stock (>= 90% capacity): Always cooperate (C).
    - Critical low stock (< 25% capacity): Always defect (D) to prevent total collapse.
    - Standard conditions: Cooperate if previous round cooperation was >= n/2, 
      otherwise defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.total_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock >= 0.9 * self.capacity:
            return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators = prev_cooperators + (1 if my_prev_action else 0)
        if total_cooperators >= self.n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_89(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with a sustainability threshold.
    Prioritizes resource preservation when stock is low, employs probabilistic
    cooperation based on previous round behavior, and optimizes utility in
    the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        round_t = current_round_index + 1
        if round_t == 1:
            return Action.C
        stock_ratio = current_stock / self.capacity
        last_opponents_C = history.opponent_cooperators[-1]
        opponent_cooperation_rate = last_opponents_C / self.n_opponents if self.n_opponents > 0 else 0
        if round_t == self.r:
            if stock_ratio > 0.5:
                return Action.C
            else:
                return Action.D
        if stock_ratio < 0.2:
            return Action.D
        if opponent_cooperation_rate == 1:
            return Action.C
        elif random.random() < opponent_cooperation_rate:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_90(BaseStrategy):
    """
    A Tit-for-Tat inspired strategy that employs a stock-dependent altruism threshold.
    It balances resource preservation with conditional cooperation.
    - Round 1: Always Cooperate.
    - Final Round: Always Defect.
    - Low Stock: Defect to extract before total collapse.
    - High Stock: Cooperate to maximize growth stability.
    - Normal State: Use probabilistic conditional cooperation based on past cooperation ratio.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_stock <= 0:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        if current_stock < capacity * 0.25:
            return Action.D
        if current_stock > capacity * 0.9:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        prev_my_coop_val = 1 if prev_my_action else 0
        total_prev_coop = prev_opp_coop + prev_my_coop_val
        cr = total_prev_coop / n
        if cr >= 0.5:
            return Action.C
        else:
            probability_defect = 1.0 - 2.0 * cr
            if random.random() < probability_defect:
                return Action.D
            else:
                return Action.C

class Strategy_ALTRUISTIC_91(BaseStrategy):
    """
    Implements a Conditional Cooperative Tit-for-Tat with Recovery strategy.
    
    This strategy maintains a 'Trust_Level' state. It attempts to cooperate when 
    the resource is healthy and trust is high, but enforces strict reciprocity 
    and salvage logic when the resource is threatened or trust is broken.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_level = 1.0
        self.recovery_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_stock < 0.05 * capacity:
            return Action.D
        if current_round == 0:
            return Action.C
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        c_observed_others = history.opponent_cooperators[-1]
        c_total = c_observed_others + (1 if my_prev_action == Action.C else 0)
        if c_observed_others == n - 1:
            self.trust_level = min(1.0, self.trust_level + 0.1)
        else:
            defectors = n - c_total
            self.trust_level = max(0.0, self.trust_level - defectors / n)
        if current_stock < 0.1 * capacity:
            self.trust_level = 0.5
            self.recovery_counter = 2
        if self.recovery_counter > 0:
            self.recovery_counter -= 1
            return Action.C
        if self.trust_level > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_92(BaseStrategy):
    """
    A Conditional Sustainability strategy that balances cooperative equilibrium 
    with emergency resource preservation. It maintains a trust_score based on 
    observed opponent cooperation rates and adjusts consumption probabilities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_score = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        if t == 1:
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        observed_rate = prev_k / (n - 1)
        self.trust_score = 0.7 * self.trust_score + 0.3 * observed_rate
        if t == r:
            if current_stock > 0.1 * capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < 0.2 * capacity:
            return Action.C
        if self.trust_score >= 0.6:
            return Action.C
        elif self.trust_score < 0.4:
            return Action.D
        elif random.random() < self.trust_score:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_93(BaseStrategy):
    """
    Implements Sustainable Stewardship Tit-for-Tat.
    Prioritizes long-term resource sustainability and incentivizes cooperation.
    - Round 1: Always Cooperate.
    - Subsequent rounds:
        - If stock is critically low (<= 0.2 * capacity), always Cooperate to recover.
        - Otherwise, Cooperate if at least half of the *total* players cooperated in the previous round.
        - Note: history.opponent_cooperators counts *opponents* only. We must adjust logic to account for this player's self-contribution.
    - Final round: Cooperate if stock > 0, otherwise Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r_total - 1:
            return Action.C if current_stock > 0 else Action.D
        if current_round == 0:
            return Action.C
        last_round_idx = current_round - 1
        opponents_who_cooperated = history.opponent_cooperators[last_round_idx]
        i_cooperated = 1 if history.my_actions[last_round_idx] else 0
        total_cooperators = opponents_who_cooperated + i_cooperated
        if current_stock <= self.game_description.capacity * 0.2:
            return Action.C
        if total_cooperators >= n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_94(BaseStrategy):
    """
    Sustainable Tit-for-Tat: A strategy that balances long-term resource sustainability
    with conditional cooperation. It prioritizes cooperation unless stock is extremely low
    or the group norm becomes unsustainable, while employing a forgiving mechanism
    to allow for recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        super().__init__(game_description)
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.n_opponents = self.n - 1
        self.total_rounds = game_description.n_rounds
        self.consecutive_opponent_defections = 0
        self.in_permanent_defection_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 0.1 * self.capacity:
            self.consecutive_opponent_defections = 0
            self.in_permanent_defection_mode = False
            return Action.C
        if history.round_number >= 2:
            last_round_coop = history.opponent_cooperators[-1]
            prev_round_coop = history.opponent_cooperators[-2]
            if last_round_coop == 0 and prev_round_coop == 0:
                self.in_permanent_defection_mode = True
            if self.in_permanent_defection_mode:
                return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            if current_stock > 0.5 * self.capacity:
                threshold = self.n_opponents / 2
                if history.opponent_cooperators[-1] >= threshold:
                    return Action.C
                return Action.D
            return Action.C
        threshold = self.n_opponents / 2
        c_prev = history.opponent_cooperators[-1]
        if c_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_95(BaseStrategy):
    """
    A conditional cooperative strategy that uses a forgiveness mechanism and sustainability 
    thresholds to maximize long-term payoffs in a Common Pool Resource game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_action_was_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == r - 1:
            self.last_action_was_defect = True
            return Action.D
        if t == 0:
            self.last_action_was_defect = False
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        total_coop_last_round = prev_opp_coop + (1 if prev_my_action else 0)
        if current_stock > 0.75 * capacity:
            self.last_action_was_defect = False
            return Action.C
        critical_threshold = capacity / 2 ** min(n, 20)
        if current_stock < critical_threshold:
            self.last_action_was_defect = True
            return Action.D
        if self.last_action_was_defect:
            if total_coop_last_round >= n - 1:
                self.last_action_was_defect = False
                return Action.C
            else:
                self.last_action_was_defect = True
                return Action.D
        if total_coop_last_round == n:
            self.last_action_was_defect = False
            return Action.C
        else:
            self.last_action_was_defect = True
            return Action.D

class Strategy_ALTRUISTIC_96(BaseStrategy):
    """
    A conditional cooperative strategy for Common Pool Resource games using
    a Tit-for-Tat with Forgiveness framework. It optimizes long-term sustainability
    by maintaining stock levels near regeneration peaks and using emergency
    defection only when necessary.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.coop_threshold = math.ceil((self.game_description.n_players - 1) / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D if current_stock > capacity * 0.2 else Action.C
        if current_stock < capacity * 0.1:
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        if current_stock >= capacity * 0.5:
            if prev_k >= self.coop_threshold:
                return Action.C
            elif current_stock < capacity * 0.2:
                return Action.D
            elif current_stock > capacity * 0.7:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_97(BaseStrategy):
    """
    Implements a Conditional Sustenance Tit-for-Tat strategy.
    Prioritizes resource preservation while adapting cooperation levels based
    on observed aggregate population behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock > 0:
                return Action.D
            return Action.C
        my_last_action = history.my_actions[-1]
        num_cooperators = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        last_stock = 0.0
        if not hasattr(self, '_stock_history'):
            self._stock_history = []
        last_stock = self._stock_history[-1] if self._stock_history else self.capacity
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if current_stock >= self.capacity / (2 * self.n):
            if num_cooperators == self.n:
                action = Action.C
            elif last_stock > current_stock:
                prob_defect = 1.0 - num_cooperators / self.n
                if random.random() < prob_defect:
                    action = Action.D
                else:
                    action = Action.C
            else:
                action = Action.C
        else:
            action = Action.D
        self._stock_history.append(current_stock)
        return action

class Strategy_ALTRUISTIC_98(BaseStrategy):
    """
    Implements a Conditional Altruism with Sustainability Enforcement strategy.
    Prioritizes sustainability by maintaining stock at 50% of capacity while punishing 
    defection via a Tit-for-Tat mechanism and employing a recovery phase for depleted stocks.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.recovery_rounds_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.total_rounds - 1:
            self.recovery_rounds_counter = 0
            return Action.D
        if current_stock < 1e-06:
            self.recovery_rounds_counter = 0
            return Action.D
        critical_threshold = self.capacity / (2 * self.n)
        if current_stock < critical_threshold:
            self.recovery_rounds_counter = 0
            return Action.D
        if current_stock < 0.2 * self.capacity:
            if self.recovery_rounds_counter < 3:
                self.recovery_rounds_counter += 1
                return Action.C
            else:
                return Action.D
        else:
            self.recovery_rounds_counter = 0
        if history.round_number == 0:
            return Action.C
        prev_opp_coop_count = history.opponent_cooperators[-1]
        threshold = math.ceil(self.n / 2)
        if prev_opp_coop_count >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_99(BaseStrategy):
    """
    A conditional 'tit-for-tat' strategy focused on resource regeneration.
    - Round 1: Always Cooperate.
    - Final Round: Always Defect to extract remaining value.
    - Mid-game: 
        - If stock < 0.25 * capacity: Defect (salvage mode).
        - If stock >= 0.25 * capacity: 
            - Cooperate if majority (>= n/2) cooperated last round.
            - Otherwise Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.cooperation_threshold = math.ceil(self.n_players / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if round_idx == total_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < self.game_description.capacity * 0.25:
            return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        i_cooperated_last = history.my_actions[-1]
        total_cooperators = last_round_cooperators + (1 if i_cooperated_last else 0)
        if total_cooperators >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_100(BaseStrategy):
    """
    An altruistic, conditional sustainability strategy. 
    It prioritizes cooperation to maintain the common pool at capacity.
    If the pool is threatened, it persists in cooperation for up to 3 rounds 
    against defecting majorities before switching to exploitation (Defect) 
    in the face of imminent collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_coop_threatened = 0
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            self.last_stock = current_stock
            return Action.C
        is_healthy = current_stock >= self.game_description.capacity * 0.95
        if is_healthy:
            self.consecutive_coop_threatened = 0
            self.last_stock = current_stock
            return Action.C
        else:
            my_last_action = history.my_actions[-1]
            my_last_c = 1 if my_last_action else 0
            prev_total_c = my_last_c + history.opponent_cooperators[-1]
            prev_total_d = self.game_description.n_players - prev_total_c
            if prev_total_d > prev_total_c:
                if my_last_c == 1:
                    self.consecutive_coop_threatened += 1
                if self.consecutive_coop_threatened >= 3:
                    self.last_stock = current_stock
                    return Action.D
            self.last_stock = current_stock
            return Action.C

class Strategy_ALTRUISTIC_101(BaseStrategy):
    """
    Generous Tit-for-Tat with Adaptive Sustainability.
    Prioritizes maintaining stock near capacity/2, punishes defection based on history,
    and switches to aggressive extraction in the terminal phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.prev_stock = current_stock
            return Action.C
        r_current = history.round_number
        r_total = self.game_description.n_rounds
        r_rem = r_total - r_current
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        k = history.opponent_cooperators[-1]
        my_last_action = int(history.my_actions[-1])
        total_cooperators = k + my_last_action
        if r_rem < 3:
            self.prev_stock = current_stock
            return Action.D
        if current_stock < 0.1 * capacity:
            self.prev_stock = current_stock
            return Action.D
        if self.prev_stock is not None and self.prev_stock > 0 and (total_cooperators == n) and ((self.prev_stock - current_stock) / self.prev_stock > 0.25):
            self.prev_stock = current_stock
            return Action.D
        if total_cooperators == n:
            self.prev_stock = current_stock
            return Action.C
        if random.random() < total_cooperators / n:
            self.prev_stock = current_stock
            return Action.C
        self.prev_stock = current_stock
        return Action.D

class Strategy_ALTRUISTIC_102(BaseStrategy):
    """
    A reciprocal strategy for the Common Pool Resource Game.
    Maintains a dynamic tolerance threshold 'k' that adjusts based on the 
    sustainability of the common pool. Prioritizes survival when the stock is low 
    and acts greedily in the final round if the stock is depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.tolerance = 0
        self.last_stock = float(self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.last_stock = current_stock
            return Action.C
        prev_stock = self.last_stock
        if current_stock > prev_stock:
            self.tolerance = min(self.n - 1, self.tolerance + 1)
        elif current_stock < prev_stock * 0.8:
            self.tolerance = max(0, self.tolerance - 1)
        self.last_stock = current_stock
        if history.round_number == self.r - 1:
            if current_stock > self.capacity / (2 * self.n):
                return Action.C
            else:
                return Action.D
        if current_stock < self.capacity / self.n:
            return Action.C
        n_opponents = self.n - 1
        opp_coop = history.opponent_cooperators[-1]
        n_defect = n_opponents - opp_coop
        my_last_action = history.my_actions[-1]
        total_defectors = n_defect + (1 if not my_last_action else 0)
        if total_defectors <= self.tolerance:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_103(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with a sustainability threshold.
    
    The strategy cooperates if the previous round's cooperation level among opponents 
    meets a 50% threshold, provided the stock is above a critical level.
    It forces defection in the final round to prevent exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_ratio = 0.5
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        critical_threshold = self.capacity / (2 * self.n)
        if current_stock < critical_threshold:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if n_opponents > 0:
            coop_ratio = prev_cooperators / n_opponents
            if coop_ratio >= self.threshold_ratio:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_ALTRUISTIC_104(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Sustainability Threshold strategy.
    
    This strategy maximizes collective yield by favoring cooperation. It adheres to three main principles:
    1. First round: Always cooperate (C) to build potential for long-term value.
    2. Sustainability First: If the stock drops below 50% of capacity, it unconditionally
       cooperates (C) to prevent resource collapse, sacrificing short-term gain for survival.
    3. Tit-for-Tat Enforcement: If the stock is healthy, it matches the cooperation level 
       of the previous round:
       - If the majority of opponents cooperated (>= n_players/2), it cooperates.
       - If opponents defected, it punishes them with a defection (D).
    4. Last Round: It defects (D) to capture remaining value as the game ends.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < capacity / 2.0:
            return Action.C
        prev_opponents_cooperated = history.opponent_cooperators[-1]
        if prev_opponents_cooperated >= n / 2.0:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_105(BaseStrategy):
    """
    Conditional Sustenance Strategy:
    Prioritizes long-term resource preservation while employing altruistic reciprocity.
    - Round 1: Always Cooperate (C).
    - Sustainability: If stock < capacity/(2*n), always C.
    - Reciprocity: If last round opponent cooperation rate >= 0.5, C. Else, defect probabilistically.
    - Endgame (last 3 rounds): Switch to "Greedy-Safe" mode.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        round_t = history.round_number
        if self.total_rounds - round_t < 3:
            if current_stock > self.capacity / 4.0:
                return Action.D
            else:
                return Action.C
        threshold = self.capacity / (2.0 * self.n)
        if current_stock < threshold:
            return Action.C
        last_obs_c_count = int(history.opponent_cooperators[-1])
        my_last_move = history.my_actions[-1]
        obs_cooperators = last_obs_c_count
        num_opponents = self.n - 1
        if num_opponents <= 0:
            return Action.C
        cooperation_rate = obs_cooperators / num_opponents
        if cooperation_rate >= 0.5:
            return Action.C
        else:
            prob_defect = 1.0 - cooperation_rate
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_ALTRUISTIC_106(BaseStrategy):
    """
    A strategy that maintains common pool resources through conditional cooperation.
    - Cooperates initially.
    - Uses a cooperation ratio (CR) based on opponents' past actions.
    - Punishes defection (CR < 0.5) unless the stock is high (forgiveness).
    - Defects in the final two rounds regardless of state.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        remaining_rounds = self.game_description.n_rounds - history.round_number
        if remaining_rounds <= 2:
            return Action.D
        if current_stock <= 1e-09:
            return Action.D
        n = self.game_description.n_players
        num_opponents = n - 1
        prev_opponents_c = history.opponent_cooperators[-1]
        cooperation_ratio = prev_opponents_c / num_opponents
        if cooperation_ratio >= 0.5:
            return Action.C
        elif current_stock >= 0.5 * self.game_description.capacity:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_107(BaseStrategy):
    """
    Generous Resource Stewardship (GRS):
    A strategy designed to maximize long-term welfare. It cooperates under abundance,
    uses probabilistic reciprocity based on the group's cooperation levels to balance
    sustainability against fairness, and shifts to pure selfishness only when the
    resource is critically depleted or the game is ending.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_stock > 0.9 * self.capacity:
            return Action.C
        if current_round == self.total_rounds - 1:
            return Action.D if current_stock > 0 else Action.C
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_coop_prev = int(my_prev_action) + prev_opp_coop
        A_prev = self.n - total_coop_prev
        if A_prev == 0:
            return Action.C
        elif A_prev == self.n:
            return Action.D
        else:
            prob_cooperate = total_coop_prev / self.n
            if random.random() < prob_cooperate:
                return Action.C
            else:
                return Action.D

class Strategy_ALTRUISTIC_108(BaseStrategy):
    """
    A Tit-for-Tat variant strategy for the Common Pool Resource Game.
    It cooperates to maintain stock levels around an optimal target (capacity/2),
    monitors aggregate cooperation rates to enforce sustainability,
    and defects in the terminal round or when resource depletion becomes critical.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.target_stock = 0.5 * self.capacity
        self.threshold = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.r
        if round_idx == total_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        last_opp_coop = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        if my_last_action == Action.C:
            cooperation_rate = (last_opp_coop + 1) / self.n
        else:
            cooperation_rate = last_opp_coop / self.n
        if current_stock >= self.target_stock:
            if cooperation_rate >= self.threshold:
                return Action.C
            else:
                return Action.D
        else:
            critical_level = self.capacity / (2 * self.n)
            if current_stock < critical_level:
                return Action.D
            else:
                return Action.C

class Strategy_ALTRUISTIC_109(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Stock Stewardship.
    
    The strategy aims to preserve the common pool stock while punishing defection,
    with logic to forgive under high-stock conditions and a final-round grab.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        k = self.total_rounds - history.round_number
        if k == 1:
            return Action.D
        if current_stock < self.capacity / 4:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if current_stock >= 0.9 * self.capacity and prev_opp_coop >= self.n - 2:
            return Action.C
        if prev_opp_coop == n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_110(BaseStrategy):
    """
    Implements Sustainable Reciprocal Altruism (SRA).
    
    This strategy prioritizes the long-term sustainability of the common pool resource.
    It defaults to cooperation, utilizes a Panic Preservation mode to protect stock 
    when it reaches critical levels, employs a Tit-for-Tat style reciprocity based on 
    the previous round's aggregate opponent behavior, and switches to defecting in 
    the final round if the resource is healthy to maximize individual utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == 0:
            return Action.C
        critical_level = capacity / (2 * n)
        if current_stock <= critical_level:
            return Action.C
        if current_round == total_rounds - 1:
            if current_stock > capacity / 2:
                return Action.D
            else:
                return Action.C
        opponents_cooperated = history.opponent_cooperators[-1]
        n_opponents = n - 1
        p_coop = opponents_cooperated / n_opponents
        if p_coop >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_111(BaseStrategy):
    """
    Implements a 'Conditional Restoration' strategy. 
    Prioritizes sustainability by cooperating (C) in the first round and dynamically 
    adjusting based on the stock levels and opponent behavior. It includes logic 
    for end-game exploitation, recovery attempts when stock is low, and 
    reciprocity/re-seeding behaviors to sustain the common pool.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_failed_reseeding_rounds = 0
        self.gave_up_on_cooperation = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        t = history.round_number + 1
        prev_C_count = history.opponent_cooperators[-1]
        my_prev_action = int(history.my_actions[-1])
        total_C_previous = prev_C_count + my_prev_action
        if t == r:
            if current_stock > capacity / 2:
                return Action.D
            else:
                return Action.C
        if total_C_previous < n / 2:
            self.consecutive_failed_reseeding_rounds += 1
        else:
            self.consecutive_failed_reseeding_rounds = 0
            self.gave_up_on_cooperation = False
        if self.consecutive_failed_reseeding_rounds >= 3:
            self.gave_up_on_cooperation = True
        if current_stock < capacity * 0.2:
            return Action.C
        if self.gave_up_on_cooperation:
            if current_stock < capacity / 10:
                return Action.C
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_112(BaseStrategy):
    """
    Sustainability-First Tit-for-Tat:
    Prioritizes resource preservation when the stock is critically low (< 20% of capacity).
    In the mid-game, enforces cooperation (n-1 requirement) to punish free-riders.
    In the final round, adopts a 'grab' strategy if stock is >= 50% capacity, 
    otherwise remains cooperative to extract remaining value gently.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        if current_round == self.n_rounds:
            if current_stock >= self.capacity * 0.5:
                return Action.D
            else:
                return Action.C
        if current_stock < self.capacity * 0.2:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= self.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_113(BaseStrategy):
    """
    Threshold-Based Reciprocal Altruism:
    Maintains resource stock by cooperating when the environment is sustainable,
    reciprocating based on previous cooperation rates, and switching to defect
    when the resource is endangered or in the final round with low stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.capacity = self.game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == self.r - 1:
            if current_stock >= 0.1 * self.capacity:
                return Action.C
            else:
                return Action.D
        if current_stock <= 0.5 * self.capacity:
            return Action.D
        my_last_action = int(history.my_actions[-1])
        total_cooperators = history.opponent_cooperators[-1] + my_last_action
        cooperation_ratio = total_cooperators / self.n
        threshold_cooperate_all = (self.n - 1) / self.n
        if cooperation_ratio >= threshold_cooperate_all:
            return Action.C
        elif cooperation_ratio >= 0.5:
            if random.random() < cooperation_ratio:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_ALTRUISTIC_114(BaseStrategy):
    """
    A strategy that aims to maintain the common pool stock at capacity/2 by
    using a conditional Tit-for-Tat mechanism. It cooperates initially,
    monitors stock levels for sustainability, and reacts to aggregate population
    behavior to decide between cooperation and defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_total = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.threshold_stock = self.capacity * 0.2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_coop
        s_prev = current_stock
        if current_round == self.n_rounds - 1:
            if s_prev >= self.threshold_stock:
                return Action.C
            else:
                return Action.D
        if s_prev < self.threshold_stock:
            return Action.D
        if c_prev >= self.n_total / 2:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_115(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy for the Common Pool Resource Game.
    
    Logic:
    1. Initial Phase: Cooperate on the first round.
    2. Monitoring Phase: If stock is critically low, always cooperate. Otherwise, check
       aggregate history. If the average cooperation rate of the group is >= 0.5,
       cooperate. If cooperation is poor (< 0.5), alternate between D and C to punish
       and attempt re-coordination.
    3. Termination Phase: In the final round, cooperate if average cooperation was >= 0.5,
       otherwise defect to avoid exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.n_opponents = self.desc.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        my_coops = history.my_actions.astype(int)
        total_cooperators = history.opponent_cooperators + my_coops
        avg_coop_rate = np.mean(total_cooperators) / self.desc.n_players
        if history.round_number == self.desc.n_rounds - 1:
            if avg_coop_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        if current_stock <= self.desc.capacity / (2 * self.desc.n_players):
            return Action.C
        if avg_coop_rate >= 0.5:
            return Action.C
        elif history.round_number % 2 == 0:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_116(BaseStrategy):
    """
    Threshold-Based Reciprocal Altruism strategy.
    
    Operates on a Tit-for-Tat foundation with stock-dependent thresholding.
    1. Initial Round: Always Cooperate (C).
    2. Terminal Round: Cooperate (C) if stock > 0.5 * capacity, else Defect (D).
    3. General Rules (Rounds 2 to r-1):
       - If current stock <= 0.25 * capacity, play Defect (D) to secure remaining resources.
       - If stock > 0.25 * capacity:
         - If all other players cooperated in previous round (C_prev == n_opponents), play Cooperate (C).
         - If not, play Cooperate (C) with probability p = C_prev / n_opponents.
    
    Note: The input 'n' in the problem description is total players. The history 
    tracks opponent_cooperators, which implicitly excludes the player themselves.
    Therefore, the comparison for "everyone" is checking if opponent_cooperators == n - 1.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_total = game_description.n_players
        self.n_opponents = self.n_total - 1
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round_idx = history.round_number
        is_terminal_round = current_round_idx == self.total_rounds - 1
        if is_terminal_round:
            if current_stock > 0.5 * self.capacity:
                return Action.C
            else:
                return Action.D
        if current_stock <= 0.25 * self.capacity:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators == self.n_opponents:
            return Action.C
        if self.n_opponents == 0:
            return Action.C
        probability = prev_cooperators / self.n_opponents
        if random.random() < probability:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_117(BaseStrategy):
    """
    A conditional cooperative strategy for Common Pool Resource games.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Terminal Round: If stock > 0.1 * capacity, Cooperate; else Defect.
    - Standard Rounds:
        - Emergency: If stock < 0.2 * capacity, always Cooperate to prevent extinction.
        - Decision: Use 0.6 * capacity threshold and 75% cooperation threshold to decide between C and D.
        - Defection Penalty: If the penalty condition (low group cooperation or low stock) is met, defect for one round before returning to cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_safe = 0.6 * game_description.capacity
        self.emergency_threshold = 0.2 * game_description.capacity
        self.terminal_threshold = 0.1 * game_description.capacity
        self.cooperation_threshold = math.floor(0.75 * game_description.n_players)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C if current_stock > self.terminal_threshold else Action.D
        if current_stock < self.emergency_threshold:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        if current_stock > self.threshold_safe and cooperators_last_round >= self.cooperation_threshold:
            return Action.C
        if current_stock <= self.threshold_safe or cooperators_last_round < self.cooperation_threshold:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_118(BaseStrategy):
    """
    Implements a Tit-for-Tat adaptation for Common Pool Resource games.
    Prioritizes sustainability via a thresholds-based approach:
    1. Final round: Defect to maximize payoff.
    2. Low stock: Cooperate to attempt rescue.
    3. Normal state: Tit-for-tat based on previous aggregate cooperation rate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.max_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.max_rounds - 1:
            return Action.D
        if current_stock < self.capacity * 0.1:
            return Action.C
        if round_idx == 0:
            return Action.C
        last_round_idx = round_idx - 1
        opponents_cooperating = history.opponent_cooperators[last_round_idx]
        my_action = history.my_actions[last_round_idx]
        total_cooperators = opponents_cooperating + (1 if my_action else 0)
        cooperation_rate = total_cooperators / self.n
        if cooperation_rate >= 0.5:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_119(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy for the Common Pool Resource game.
    The strategy balances resource preservation with Tit-for-Tat style adaptation,
    making decisions based on current stock levels and observed past cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            if current_stock >= 0.5 * self.capacity:
                return Action.C
            else:
                return Action.D
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if current_stock > 0.8 * self.capacity:
            return Action.C
        threshold = math.ceil((self.n - 1) / 2)
        last_coop_count = history.opponent_cooperators[-1]
        if last_coop_count >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_120(BaseStrategy):
    """
    A strategy that balances stock preservation with individual utility maximization.
    
    Logic:
    1. Final Round: Always Defect.
    2. Recovery Phase (Stock < 0.5 * capacity): Always Cooperate to restore the common pool.
    3. Maintenance Phase (Stock >= 0.5 * capacity):
        - If previous round saw less than full cooperation, punish with probabilistic defection.
        - If stock is critical (< 0.25 * capacity), force Cooperation regardless of history to avoid collapse.
        - Default to Cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < 0.5 * capacity:
            return Action.C
        if current_round == 0:
            return Action.C
        last_action_was_coop = 1 if history.my_actions[-1] else 0
        last_round_coop_count = history.opponent_cooperators[-1] + last_action_was_coop
        if current_stock < 0.25 * capacity:
            return Action.C
        if last_round_coop_count < n:
            threshold = last_round_coop_count / n
            if random.random() > threshold:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_ALTRUISTIC_121(BaseStrategy):
    """
    Sustainability-First strategy: Prioritizes maintaining the stock at capacity.
    Uses a Growth vs. Depletion zone logic based on current stock levels and
    previous round defection rates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        prev_cooperators = history.opponent_cooperators[-1]
        my_last_action_was_c = history.my_actions[-1]
        num_opponents = n - 1
        opp_defectors = num_opponents - prev_cooperators
        k = opp_defectors + (0 if my_last_action_was_c else 1)
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if rounds_remaining < 3 and current_stock <= self.game_description.capacity * 0.2:
            return Action.D
        if current_stock >= self.game_description.capacity * 0.5:
            if k == n:
                return Action.D
            else:
                return Action.C
        elif k > 0:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_122(BaseStrategy):
    """
    Threshold-Based Stewardship Strategy:
    Maintains the common pool resource by cooperating when the stock is sustainable,
    while employing selective defection if the resource is depleted or if defectors
    are present. Prioritizes collective sustainability over individual gain,
    switching to selfish play (Defect) only in the final round or when the
    collective outcome is unrecoverable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.consecutive_defector_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.total_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        prev_round_cooperators = int(history.opponent_cooperators[-1])
        if prev_round_cooperators < self.n:
            self.consecutive_defector_rounds += 1
        else:
            self.consecutive_defector_rounds = 0
        if self.consecutive_defector_rounds >= 3 and current_stock < 0.25 * self.capacity:
            return Action.D
        if prev_round_cooperators < self.n:
            if current_stock < 0.4 * self.capacity:
                return Action.D
        if current_stock >= 0.5 * self.capacity:
            return Action.C
        if prev_round_cooperators == self.n:
            return Action.C
        if current_stock < 0.05 * self.capacity:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_123(BaseStrategy):
    """
    Implements a sustainability-focused reciprocity strategy:
    1. Always Cooperate in the first round.
    2. If stock < 0.5 * capacity, Cooperate to ensure regeneration.
    3. If it is the last round, Defect if it maximizes individual payoff, otherwise Cooperate.
    4. Otherwise, use a stochastic reciprocity rule: Cooperate if the group fully cooperates, 
       otherwise defect with probability proportional to the lack of cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            payoff_C = current_stock / (2 * self.n)
            payoff_D = current_stock / self.n
            return Action.D if payoff_D > payoff_C else Action.C
        c_prev = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if c_prev >= n_opponents:
            return Action.C
        else:
            if n_opponents == 0:
                return Action.C
            defect_probability = (n_opponents - c_prev) / n_opponents
            if random.random() < defect_probability:
                return Action.D
            else:
                return Action.C

class Strategy_ALTRUISTIC_124(BaseStrategy):
    """
    Implements a 'Conditional Sustainment' strategy for the Common Pool Resource game.
    
    The strategy prioritizes stock sustainability at capacity. It cooperates (C) 
    in the first round, defects (D) in the last, and otherwise reacts to 
    stock health and peer behavior. It reverts to cooperation if the environment 
    stabilizes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if t == 1:
            return Action.C
        if t == self.r:
            return Action.D
        my_last_action_bool = history.my_actions[-1]
        my_last_coop = 1 if my_last_action_bool else 0
        opp_coop = history.opponent_cooperators[-1]
        total_cooperators = opp_coop + my_last_coop
        total_defectors = self.n - total_cooperators
        is_depleted = current_stock < 0.5 * self.capacity
        environment_hostile = total_defectors > self.n / 2
        if is_depleted or environment_hostile:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_125(BaseStrategy):
    """
    Implements a Tit-for-Tat inspired strategy based on Sustainable Reciprocal Altruism.
    
    The strategy prioritizes stock sustainability while employing probabilistic 
    conditional cooperation. It switches to Defection only in the final round 
    or when conditions are optimal, while enforcing a 'Recovery Override' to 
    prevent resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.buffer = 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number + 1
        if t == r:
            return Action.D
        if current_stock < capacity / max(n, 1):
            return Action.C
        if t == 1:
            return Action.C
        prev_k = int(history.opponent_cooperators[-1])
        if prev_k == n:
            return Action.C
        elif current_stock >= capacity * 0.5:
            if random.random() < prev_k / n:
                return Action.C
            else:
                return Action.D
        elif r - t < self.buffer:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_126(BaseStrategy):
    """
    Implements a "Conditional Sustainment with Forgiveness" strategy.
    
    This strategy attempts to maintain the common pool resource through cooperation
    when the stock is healthy and others are participating. It uses a flexible
    trigger system: it punishes defectors if cooperation drops below 50% of the
    total population, but remains forgiving if the resource regenerates sufficiently.
    It prioritizes individual extraction in terminal rounds or when the stock 
    reaches critical levels to avoid total resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_status = True
        self.zero_coop_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        opponents_last_coop = history.opponent_cooperators[-1]
        total_cooperators = opponents_last_coop + (1 if my_last_action else 0)
        n = self.game_description.n_players
        if self.cooperation_status:
            if total_cooperators == 0:
                self.zero_coop_streak += 1
            else:
                self.zero_coop_streak = 0
            if self.zero_coop_streak >= 2:
                self.cooperation_status = False
        elif current_stock >= self.game_description.capacity / 2:
            self.cooperation_status = True
            self.zero_coop_streak = 0
        if current_stock < self.game_description.capacity / 4:
            return Action.D
        if self.cooperation_status:
            if total_cooperators >= n / 2:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_ALTRUISTIC_127(BaseStrategy):
    """
    A Tit-for-Tat with Forgiveness strategy for the Common Pool Resource game.
    
    Logic:
    1. First Round: Cooperates to signal intent.
    2. Stock Depletion: If stock is critically low (below capacity / 2n), defects immediately.
    3. End-Game: If within the last n rounds, defects to extract remaining value.
    4. Tit-for-Tat with Forgiveness: 
       - If everyone cooperated in the previous round, cooperate.
       - If only one person defected (regret index <= 1), forgive and cooperate.
       - Otherwise, punish by defecting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if self.r - history.round_number <= self.n:
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_coop = prev_opp_coop + (1 if my_prev_action else 0)
        regret_index = self.n - total_prev_coop
        if total_prev_coop == self.n:
            return Action.C
        elif regret_index <= 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_128(BaseStrategy):
    """
    Implements the Sustainable Altruistic Equilibrium (SAE) strategy.
    
    This strategy aims to maximize long-term aggregate payoff by maintaining
    stock levels near capacity (where growth is maximized), utilizing a
    punishment mechanism (tit-for-tat variant) when defections occur, 
    and switching to defensive consumption when the resource nears collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_rounds_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        t = history.round_number
        if t == r_total - 1:
            return Action.D
        if t == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_cooperators = prev_cooperators + (1 if my_prev_action else 0)
        capacity = self.game_description.capacity
        if total_prev_cooperators < n:
            self.punishment_rounds_remaining = max(self.punishment_rounds_remaining, n - total_prev_cooperators)
        if current_stock > 0.5 * capacity:
            if total_prev_cooperators == n:
                return Action.C
            if self.punishment_rounds_remaining > 0:
                self.punishment_rounds_remaining -= 1
                return Action.D
            return Action.C
        elif total_prev_cooperators == n:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_33(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with forgiveness and sustainability constraints.
    Prioritizes maintaining stock capacity through cooperation, punishes defectors
    unless the stock is collapsing or the group demonstrates a strong cooperative
    recovery signal, and maximizes extraction in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number + 1
        if history.round_number == 0:
            return Action.C
        if current_round_idx == self.total_rounds:
            return Action.D
        last_round_idx = -1
        last_opp_coop = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        k = last_opp_coop + (1 if my_last_action else 0)
        s_crit = self.capacity / 2.0
        rounds_remaining = self.total_rounds - current_round_idx
        if current_stock < s_crit and rounds_remaining < 3:
            return Action.D
        if current_stock < self.capacity / (2.0 * self.n):
            return Action.D
        if k >= self.n - 1:
            return Action.C
        if k >= self.n / 2.0:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_34(BaseStrategy):
    """
    A strategy that plays Cooperate (C) as the default state, provided the stock 
    is sustainable and previous defection levels are low. It switches to Defect (D) 
    for punishment or resource protection when thresholds are breached. In the final 
    round, it switches to a greedy evaluation based on stock health.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.critical_stock_threshold = self.capacity * 0.25
        self.final_round_threshold = self.capacity * 0.5
        self.defector_limit = self.n / 2 - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        last_round_defectors = self.n - 1 - last_round_cooperators
        if history.round_number == self.r - 1:
            if current_stock >= self.final_round_threshold:
                return Action.C
            else:
                return Action.D
        if current_stock >= self.critical_stock_threshold and last_round_defectors < self.n / 2:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_35(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with stock-level monitoring.
    
    Logic:
    1. Initial Round: Cooperates.
    2. Terminal Round: Defects.
    3. Sustainability Check: If stock < capacity/n, defects for one round, then reverts to conditional response.
    4. Conditional Response: Observes count of cooperating opponents (k).
       - If k = n-1, cooperates.
       - If k < n-1, cooperates with probability p = k/(n-1).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = self.capacity / self.n

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.threshold:
            return Action.D
        k = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if k == n_opponents:
            return Action.C
        if n_opponents == 0:
            return Action.C
        probability_to_cooperate = k / n_opponents
        if random.random() < probability_to_cooperate:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_36(BaseStrategy):
    """
    Implements Conditional Tit-for-Tat with Resource Sustainability.
    
    Strategy:
    1. First Round: Always Cooperate (C).
    2. Endgame (Final Round): If stock >= 0.5 * capacity, Defect (D), else Cooperate (C).
    3. Recovery: If current_stock < 0.5 * capacity, always Cooperate (C).
    4. Conditional Tit-for-Tat: Otherwise, if all players (n) cooperated in the 
       previous round, Cooperate (C), else Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.in_recovery_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if self.in_recovery_mode:
            if current_stock >= 0.75 * self.capacity:
                self.in_recovery_mode = False
            else:
                return Action.C
        if current_stock < 0.5 * self.capacity:
            self.in_recovery_mode = True
            return Action.C
        if current_round == self.n_rounds - 1:
            if current_stock >= 0.5 * self.capacity:
                return Action.D
            else:
                return Action.C
        last_others_cooperators = history.opponent_cooperators[-1]
        i_cooperated = bool(history.my_actions[-1])
        total_cooperators = last_others_cooperators + (1 if i_cooperated else 0)
        if total_cooperators == self.n_players:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_37(BaseStrategy):
    """
    Tit-for-Tat with Threshold Recovery (TFTR):
    Maintains cooperation as default, enforces strict reciprocity (n-1 cooperators),
    prioritizes resource preservation when stock is critically low, and implements
    a recovery mechanism to offer an olive branch after periods of defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.was_defecting_last_round = False
        self.recovery_ready = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        round_idx = history.round_number
        is_last_round = round_idx == self.game_description.n_rounds - 1
        if round_idx == 0:
            return Action.C
        if is_last_round:
            return Action.C if current_stock >= capacity / 2 else Action.D
        if self.was_defecting_last_round and current_stock >= capacity / 2:
            self.recovery_ready = True
            self.was_defecting_last_round = False
            return Action.C
        if current_stock < capacity / 4:
            self.was_defecting_last_round = False
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        threshold = n - 1
        if k_prev >= threshold:
            self.was_defecting_last_round = False
            return Action.C
        else:
            self.was_defecting_last_round = True
            return Action.D

class Strategy_BENEVOLENT_38(BaseStrategy):
    """
    A triggered Tit-for-Tat strategy with sustainability thresholds. 
    It aims to cooperate to sustain the resource pool, but switches to 
    defection if other players exploit the resource or if the stock 
    reaches a critical minimum. In the final round, it defects to 
    capture remaining value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock < n:
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_coop
        if total_cooperators_prev >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_39(BaseStrategy):
    """
    A conditional Tit-for-Tat with Forgiveness strategy designed to maintain 
    the common pool resource near the capacity/2 equilibrium for sustainable yield.
    
    Logic:
    1. Initiation: Cooperate in round 0.
    2. Termination (Last Round): Defect if stock is healthy (>25% capacity), otherwise cooperate.
    3. Critical State (Stock < 10% capacity): Prioritize sustainability. Cooperate only if 
       at least n-1 players cooperated previously, otherwise defect.
    4. Operational: Cooperate if the majority of opponents (>= n/2) cooperated in the 
       previous round, otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        prev_my_action = 1 if history.my_actions[-1] else 0
        k_t = history.opponent_cooperators[-1] + prev_my_action
        if current_round == self.r - 1:
            if current_stock > 0.25 * self.capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < 0.1 * self.capacity:
            if k_t >= self.n - 1:
                return Action.C
            else:
                return Action.D
        if k_t >= self.n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_40(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy for the Common Pool Resource Game.
    The strategy attempts to maintain resources by cooperating when others cooperate,
    but switches to defecting behavior if the stock falls below critical thresholds or 
    if opponents begin over-exploiting the resource.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if current_stock < capacity / (2 * n):
            return Action.D
        if round_idx == r - 1:
            if current_stock > capacity / 2:
                return Action.C
            else:
                return Action.D
        k_coop = int(history.opponent_cooperators[-1])
        n_opponents = n - 1
        if k_coop == n_opponents:
            return Action.C
        s_rem_c = current_stock / 2
        growth = 2.0 * s_rem_c * (1.0 - s_rem_c / capacity)
        s_next = min(s_rem_c + growth, float(capacity))
        if s_next > capacity * 0.25:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_41(BaseStrategy):
    """
    A Tit-for-Tat-based Cooperative Equilibrium strategy designed for sustainability.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Last Round: Cooperate (C) if all opponents cooperated in the previous round, otherwise Defect (D).
    - Intermediate Rounds:
        - If all opponents cooperated in the previous round: Cooperate (C).
        - Otherwise, if current stock is critically low (< capacity / n): Cooperate (C) to prevent collapse.
        - Otherwise, Defect (D) to penalize non-cooperation.
    - Global Emergency: If stock is near zero, always Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 1e-06:
            return Action.C
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        k = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if current_round_idx == self.r - 1:
            if k == n_opponents:
                return Action.C
            else:
                return Action.D
        if k == n_opponents:
            return Action.C
        else:
            if current_stock < self.capacity / self.n:
                return Action.C
            return Action.D

class Strategy_BENEVOLENT_42(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource Stewardship.
    
    Strategy:
    - Round 1: Cooperate.
    - Final Round: Defect to maximize utility.
    - Intermediate Rounds:
        - Crisis Mode: If stock < capacity/4, defect to secure survival.
        - Trust Mode: If prev cooperators >= n-1, cooperate.
        - Retaliation Mode: If prev cooperators < n-1, defect with probability 
          proportional to the level of betrayal (1 - c_prev/n).
        - Forgiveness: If player previously defected but observes high cooperation 
          (c_prev >= n-1), switch to cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.r:
            return Action.D
        if current_round == 1:
            return Action.C
        if current_stock < self.capacity / 4.0:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        if c_prev >= self.n - 1:
            return Action.C
        if c_prev < self.n - 1:
            threshold = (self.n - c_prev) / self.n
            if random.random() < threshold:
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_43(BaseStrategy):
    """
    A conditional tit-for-tat strategy (Goodwill-based) that balances 
    long-term sustainability with proportional punishment of defectors.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.goodwill = 0
        self.threshold = max(2, math.floor(self.r / 4))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock > self.capacity / 2.0:
                return Action.D
            else:
                return Action.C
        is_depleted_multiple_rounds = False
        if history.round_number >= 2:
            pass
        if current_stock < self.capacity / 4.0:
            return Action.C
        previous_my_action = history.my_actions[-1]
        previous_opponents_c = history.opponent_cooperators[-1]
        total_cooperators = previous_opponents_c + (1 if previous_my_action else 0)
        if total_cooperators == self.n:
            self.goodwill = min(self.goodwill + 1, self.threshold)
        elif total_cooperators <= self.n / 2.0:
            self.goodwill = max(self.goodwill - 1, -self.threshold)
        if self.goodwill >= 0:
            return Action.C
        else:
            prob_defect = min(1.0, abs(self.goodwill) / (self.n / 2.0))
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_BENEVOLENT_44(BaseStrategy):
    """
    Adaptive Sustainable Tit-for-Tat strategy:
    - Always cooperates in the first round.
    - If stock < capacity / n, defaults to defect to prevent collapse or extract remaining value.
    - If in the final round, cooperates only if stock > capacity / (2 * n).
    - Otherwise, reciprocates cooperation if at least 50% of the group cooperated in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / self.n:
            return Action.D
        if history.round_number == self.total_rounds - 1:
            if current_stock > self.capacity / (2 * self.n):
                return Action.C
            else:
                return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        k_prev = history.opponent_cooperators[-1] + my_prev_action
        if k_prev >= 0.5 * self.n:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_45(BaseStrategy):
    """
    A Tit-for-Tat adaptive strategy for the Common Pool Resource Game.
    Focuses on maintaining stock levels above 50% capacity, punishing defections 
    only when stock is critical, and pivoting to greedy behavior in the final three rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.capacity = self.game_description.capacity
        self.r = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx >= self.r - 3:
            if current_stock > 0.75 * self.capacity:
                return Action.C
            else:
                return Action.D
        if round_idx == 0:
            return Action.C
        last_round_idx = round_idx - 1
        last_k = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        total_cooperators = last_k + (1 if my_last_action else 0)
        if current_stock >= 0.5 * self.capacity:
            return Action.C
        else:
            if last_k >= self.n - 2:
                return Action.C
            if last_k < self.n - 2:
                return Action.D
            return Action.C

class Strategy_BENEVOLENT_46(BaseStrategy):
    """
    Implements 'Adaptive Sustainability Tit-for-Tat'.
    
    This strategy balances resource conservation with conditional cooperation.
    - Initially cooperates.
    - Switches to defection if the resource is critically depleted (< capacity / 2n).
    - Uses a graduated response when the stock is healthy (>= 50% capacity).
    - Protects against persistent defection when the resource is under stress (< 50% capacity).
    - Prioritizes cooperation in the final round unless history dictates otherwise.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.threshold_critical = self.capacity / (2 * self.n)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.threshold_critical:
            return Action.D
        if history.round_number == self.r - 1:
            num_opponents = self.n - 1
            if history.opponent_cooperators[-1] == 0:
                return Action.D
            return Action.C
        if current_stock < 1e-06:
            return Action.D
        num_opponents = self.n - 1
        k = history.opponent_cooperators[-1]
        if k == num_opponents:
            return Action.C
        healthy_threshold = 0.5 * self.capacity
        if current_stock >= healthy_threshold:
            prob_cooperate = k / num_opponents
            return Action.C if random.random() < prob_cooperate else Action.D
        else:
            return Action.D

class Strategy_BENEVOLENT_47(BaseStrategy):
    """
    Implements a conditional cooperation strategy for Common Pool Resource games
    based on stock thresholds and historical defection rates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        target_stock = self.game_description.capacity / 2.0
        critical_threshold = self.game_description.capacity * 0.25
        final_threshold = self.game_description.capacity * 0.1
        total_players = self.game_description.n_players
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C if current_stock > final_threshold else Action.D
        if current_stock >= target_stock:
            return Action.C
        if current_stock >= critical_threshold:
            my_last_action_is_coop = 1 if history.my_actions[-1] else 0
            prev_total_cooperators = history.opponent_cooperators[-1] + my_last_action_is_coop
            n_defectors = total_players - prev_total_cooperators
            if n_defectors > total_players / 2.0:
                return Action.D
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_48(BaseStrategy):
    """
    Conditional Sustainability: Prioritizes system health to maximize long-term aggregate yield.
    Starts with Cooperation. In subsequent rounds, maintains Cooperation if the majority
    cooperated in the previous round. If cooperation drops, attempts forgiveness once
    unless the stock level is critically low (< 20% capacity), in which case it defects to
    salvage utility. Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock <= 1e-09:
            return Action.D
        last_round_idx = history.round_number - 1
        i_cooperated = 1 if history.my_actions[last_round_idx] else 0
        k = history.opponent_cooperators[last_round_idx] + i_cooperated
        k_threshold = self.n - 1
        if current_stock < self.capacity * 0.2:
            return Action.D
        if k >= k_threshold:
            return Action.C
        else:
            return Action.C

class Strategy_BENEVOLENT_49(BaseStrategy):
    """
    Tit-for-Tat with Resource Monitoring strategy:
    Prioritizes sustainability by tracking previous round cooperation counts 
    and current stock levels. Initiates Tit-for-Tat retaliation if the 
    cooperative majority falls below a calculated threshold, but re-enters 
    cooperation if the system recovers sufficiently or if it is the 
    last round and stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n = self.game_description.n_players
        if n == 2:
            self.d_threshold = 0
        else:
            self.d_threshold = math.ceil(n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        r = self.game_description.n_rounds
        t = history.round_number + 1
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        k_prev = history.opponent_cooperators[-1] + (1 if my_prev_action == Action.C else 0)
        if t == r:
            return Action.C if current_stock > capacity / 2 else Action.D
        if current_stock < capacity / n:
            return Action.D
        if k_prev >= self.d_threshold:
            return Action.C
        else:
            if current_stock >= 0.8 * capacity:
                return Action.C
            return Action.D

class Strategy_BENEVOLENT_50(BaseStrategy):
    """
    Tit-for-Tat with Forgiving Sustenance.
    
    Cooperates initially and when cooperation is high (>= 50%).
    Defects when the group is over-consuming.
    Features 'last-resort conservation' when stock is critically low.
    Optimizes for the final round by defecting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_stock <= capacity / n:
            return Action.C
        if current_round == 0:
            return Action.C
        num_opponents = n - 1
        if num_opponents == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        cooperation_ratio = prev_cooperators / num_opponents
        if cooperation_ratio >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_51(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Greed-Correction.
    
    This strategy prioritizes long-term resource sustainability. It cooperates
    when the group as a whole maintains the resource (majority cooperation)
    and switches to a defensive defect stance when the resource is being 
    depleted by the majority. It includes logic to capture final value in the 
    last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.threshold = self.n / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.total_rounds - 1:
            return Action.D if current_stock > 0.1 else Action.C
        if history.round_number == 0:
            return Action.C
        prev_self_cooperated = 1 if history.my_actions[-1] else 0
        prev_opponents_cooperated = history.opponent_cooperators[-1]
        total_cooperators = prev_opponents_cooperated + prev_self_cooperated
        if total_cooperators >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_52(BaseStrategy):
    """
    A strategy that implements a Benevolence Threshold (BT) mechanism to manage 
    resource sustainability. It prioritizes cooperation initially, adjusts its 
    behavior based on collective group outcomes (Trust Score), and enforces 
    sustainability guardrails. In the final round, it makes a last-minute 
    decision based on remaining stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.T = self.n

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 0.25 * self.capacity:
            return Action.C
        if history.round_number == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev == self.n:
            self.T = min(self.n, self.T + 1)
        else:
            defect_count = self.n - c_prev
            self.T -= defect_count
        if history.round_number == self.r - 1:
            if current_stock > 0.1 * self.capacity:
                return Action.C
            else:
                return Action.D
        if self.T > self.n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_53(BaseStrategy):
    """
    Implements a 'Tit-for-Tat with Resilience' strategy for the Common Pool Resource Game.
    Focuses on MSY maintenance while adapting to peer behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        prev_opp_coops = history.opponent_cooperators[-1]
        if t == self.r - 1:
            return Action.D
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if prev_opp_coops == self.n - 1:
            return Action.C
        if current_stock > self.capacity / 2:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_54(BaseStrategy):
    """
    Tit-for-Tat with Proportional Threshold Adaptation.
    
    This strategy aims to maximize long-term sustainable yield by mirroring 
    the collective behavior of the group while preventing total resource collapse.
    It defaults to cooperation, mimics group behavior if cooperation is >= 50%,
    and reserves an emergency threshold to regenerate the pool if stock is low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 4:
            return Action.C
        num_opponents_coop = int(history.opponent_cooperators[-1])
        my_last_action = bool(history.my_actions[-1])
        total_cooperators = num_opponents_coop + (1 if my_last_action else 0)
        ratio = total_cooperators / self.game_description.n_players
        if ratio >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_55(BaseStrategy):
    """
    A Conditional Reciprocity strategy for the Common Pool Resource game.
    Monitors aggregate cooperation of opponents and adjusts a 'trust_level'
    propensity to cooperate, forcing cooperation when stock levels are critical
    or for the final round if stock is depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_level = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        min_coop_consumption = current_stock / (2 * self.game_description.n_players)
        if min_coop_consumption < 1e-09:
            return Action.C
        if current_stock < self.game_description.capacity * 0.25:
            self.trust_level = 1.0
        k = history.opponent_cooperators[-1]
        n = self.game_description.n_players
        n_opponents = n - 1
        if k == n_opponents:
            self.trust_level = min(1.0, self.trust_level + 0.1)
        elif k < n_opponents:
            decrement = 0.2 * (n_opponents - k)
            self.trust_level = max(0.0, self.trust_level - decrement)
        current_round = history.round_number
        is_last_round = current_round == self.game_description.n_rounds - 1
        if is_last_round:
            if current_stock > 1e-09:
                return Action.D
            return Action.C
        if random.random() < self.trust_level:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_56(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Stock Sensitivity strategy.
    
    Strategy maintains cooperation while stock is healthy (above 20% of capacity)
    and others cooperate. It defects if stock drops below critical levels, if 
    others defect, or in the final round if the resource is depleted. 
    It incorporates a forgiveness mechanism to return to cooperation 
    if punishment successfully cleanses the system of defectors.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_stock = self.game_description.capacity * 0.2
        self.tolerance = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        num_opponents = self.game_description.n_players - 1
        prev_C_count = history.opponent_cooperators[-1]
        prev_D_count = num_opponents - prev_C_count
        prev_my_action = history.my_actions[-1]
        if current_stock == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock < self.game_description.capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < self.threshold_stock:
            return Action.D
        if prev_D_count > self.tolerance:
            return Action.D
        if not prev_my_action and prev_D_count == 0:
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_57(BaseStrategy):
    """
    A Tit-for-Tat based strategy with forgiveness and sustainability thresholds.
    - Prioritizes sustainability by cooperating when stock is critically low.
    - Always cooperates on the first round.
    - Always defects on the final round.
    - Uses a majority-defection threshold to decide whether to retaliate with defection
      against other players.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.r:
            return Action.D
        if current_round == 1:
            return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.C
        if current_stock < self.capacity * 0.5:
            return Action.C
        num_opponents = self.n - 1
        num_opponents_cooperating = history.opponent_cooperators[-1]
        num_opponents_defecting = num_opponents - num_opponents_cooperating
        my_last_action = history.my_actions[-1]
        my_last_defected = not my_last_action
        total_defectors = num_opponents_defecting + (1 if my_last_defected else 0)
        if total_defectors >= self.n / 2:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_58(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Thresholds strategy.
    
    Logic:
    - Round 0: Always Cooperate (C).
    - Final Round: Defect (D) if stock is >= 0.5 capacity, else Cooperate (C).
    - If stock < 0.5 capacity: Always Cooperate (C) to assist recovery.
    - Reciprocity: 
        - If all players cooperated: Cooperate (C).
        - If majority defected (D >= 0.5n): Defect (D).
        - If minority defected: Cooperate (C) unless stock dropped > 20% capacity, then Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        if history.round_number == r_total - 1:
            if current_stock >= 0.5 * capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < 0.5 * capacity:
            return Action.C
        last_round_cooperators = int(history.opponent_cooperators[-1])
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators = last_round_cooperators + my_prev_action
        total_defectors = n - total_cooperators
        if total_defectors == 0:
            return Action.C
        if total_defectors >= 0.5 * n:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_59(BaseStrategy):
    """
    Threshold-Based Reciprocal Benevolence:
    Maintains resource capacity via conditional cooperation and stochastic 
    tit-for-tat retaliation. 
    
    Logic:
    1. First round: Always Cooperate.
    2. Last round: If stock is >= 75% capacity, Defect. Otherwise Cooperate.
    3. Intermediate rounds:
       - If previous round was fully cooperative, Cooperate.
       - If stock is critical (< capacity / (2 * n)), Defect.
       - If stock < capacity / 2, Defect.
       - Otherwise, Cooperate with probability equal to the previous cooperation rate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D if current_stock >= 0.75 * self.capacity else Action.C
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        my_prev_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if c_prev == self.n:
            return Action.C
        if current_stock < self.capacity / self.n:
            return Action.D
        if current_stock < self.capacity / 2.0:
            return Action.D
        if random.random() < c_prev / self.n:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_60(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness strategy for Common Pool Resource Game.
    Prioritizes sustainability when stock is low, enforces cooperation when healthy,
    and defects in the final round to extract remaining value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        h = current_stock / capacity
        if h < 0.5:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D if current_stock >= 0.5 * capacity else Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_coop = my_prev_action + history.opponent_cooperators[-1]
        if total_coop >= n - 1:
            return Action.C
        if current_stock > 0.2 * capacity:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_61(BaseStrategy):
    """
    Triggered Conditional Cooperation:
    A strategy that maintains resource sustainability by signaling cooperation early,
    monitoring the stock level, and enforcing a Tit-for-Tat punishment mechanism
    when the collective behavior or resource level poses a threat to sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        if current_round == self.r:
            if current_stock >= 0.5 * self.capacity:
                return Action.C
            else:
                return Action.D
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        prev_C = history.opponent_cooperators[-1] + (1 if my_prev_action == Action.C else 0)
        prev_D = self.n - prev_C
        is_stock_critical = current_stock < 0.25 * self.capacity
        widespread_defection = prev_D > self.n / 2
        if is_stock_critical or widespread_defection:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_62(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource Awareness:
    - Round 1: Always Cooperate.
    - Subsequent rounds:
        - If stock is critical (< 25% capacity), Cooperate.
        - Otherwise, observe cooperation level:
            - If k >= n-1, Cooperate.
            - If k < n-1, Defect, UNLESS stock is declining (S_t < S_{t-1}) and
              stock is < 50% capacity (Restore equilibrium logic).
    - Final round:
        - If stock > 50% capacity, Defect.
        - If stock <= 50% capacity, Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        is_final_round = current_round == self.game_description.n_rounds - 1
        if current_round == 0:
            return Action.C
        if is_final_round:
            if current_stock > capacity * 0.5:
                return Action.D
            else:
                return Action.C
        if current_stock < capacity * 0.25:
            return Action.C
        k = history.opponent_cooperators[-1]
        if not hasattr(self, 'last_stock'):
            self.last_stock = float(capacity)
        prev_stock = self.last_stock
        self.last_stock = float(current_stock)
        if k >= n_players - 1:
            return Action.C
        is_stock_declining = prev_stock > current_stock
        is_stock_fragile = current_stock < capacity * 0.5
        if is_stock_declining and is_stock_fragile:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_63(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Buffer (TFT-SB) Strategy.
    
    Operates on conditional cooperation. Prioritizes keeping the stock level at 
    capacity/2 to maximize resource growth. Responds to defection with defection 
    if stock is healthy, but prioritizes cooperation if stock is critical 
    or when attempting to reset to sustainable levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.target_s = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            if current_stock > 0.0001:
                return Action.D
            return Action.C
        if current_stock < self.capacity / 10.0:
            return Action.C
        n_c = history.opponent_cooperators[-1]
        if n_c == self.n - 1:
            return Action.C
        if current_stock < self.target_s:
            return Action.C
        if current_stock >= self.target_s and n_c >= self.n / 2.0:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_64(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with Sustainability Thresholding.
    Prioritizes resource longevity by defecting only when the common pool is 
    endangered or the group cooperation rate is insufficient, while maintaining 
    probabilistic forgiveness.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if t == 1:
            return Action.C
        if t == self.total_rounds:
            threshold = self.capacity / (2 * self.n)
            return Action.D if current_stock > threshold else Action.C
        prev_C_count = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        if current_stock < self.capacity / self.n:
            if my_prev_action == True:
                return Action.C
            else:
                return Action.D
        n_opponents = self.n - 1
        if n_opponents == 0:
            return Action.C
        cooperation_rate = prev_C_count / n_opponents
        if cooperation_rate >= 0.5:
            return Action.C
        elif random.random() < cooperation_rate:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_65(BaseStrategy):
    """
    A strategy that starts by cooperating, then initiates a punitive defection 
    phase if previous cooperation levels are suboptimal and stock is declining. 
    It maintains a benevolence buffer: returning to cooperation if all players 
    revert to cooperation, if stock is critical, or if the stock recovers 
    to capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_punishing = False
        self.epsilon = 1e-06

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_stock >= capacity - self.epsilon:
            self.is_punishing = False
        if current_stock < self.epsilon:
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        if self.is_punishing and k_prev == n:
            self.is_punishing = False
        if current_round == r - 1:
            return Action.C if not self.is_punishing else Action.D
        if self.is_punishing:
            return Action.D
        if current_stock < capacity / n:
            return Action.C
        if k_prev < n:
            my_last_action = history.my_actions[-1]
            my_last_payoff = history.my_payoffs[-1]
            s_prev = my_last_payoff * 2 * n if my_last_action else my_last_payoff * n
            if current_stock < s_prev:
                self.is_punishing = True
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_66(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    This strategy prioritizes long-term resource maintenance using a Tit-for-Tat adaptation:
    1. Always Cooperates in the first round.
    2. Enters 'Conservation Mode' if the stock drops below the critical threshold (capacity / 2n).
    3. Employs a Tit-for-Tat logic in standard operation (punishing defections).
    4. Switches to a terminal payoff maximization heuristic in the final round based on historic cooperation levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        critical_threshold = capacity / (2 * n)
        if current_stock < critical_threshold:
            return Action.C
        if history.round_number == r - 1:
            total_possible_coops = (n - 1) * history.round_number
            total_actual_coops = np.sum(history.opponent_cooperators)
            avg_cooperation = total_actual_coops / total_possible_coops if total_possible_coops > 0 else 0
            if avg_cooperation > 0.75 and current_stock > capacity / 2:
                return Action.C
            else:
                return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if last_round_cooperators == n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_67(BaseStrategy):
    """
    An adaptive Tit-for-Tat strategy for the Common Pool Resource game.
    It prioritizes sustainability by tracking previous cooperation rates 
    and current stock thresholds, while utilizing terminal defection for 
    optimal final-round outcomes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.25 * self.game_description.capacity
        self.terminal_threshold = 0.5 * self.game_description.capacity
        self.majority_threshold = math.ceil(self.game_description.n_players / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        r = self.game_description.n_rounds
        if t == 1:
            return Action.C
        if t == r:
            if current_stock > self.terminal_threshold:
                return Action.C
            return Action.D
        c_obs_prev = history.opponent_cooperators[-1]
        if current_stock >= self.threshold and c_obs_prev >= self.majority_threshold:
            return Action.C
        elif current_stock < self.threshold:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_68(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource-Threshold Management.
    Prioritizes long-term resource preservation by defaulting to cooperation. 
    If the stock drops below a 25% threshold of capacity, switches to defection to 
    capture remaining value. Uses a history-dependent reciprocation model 
    (>= 50% opponent cooperation) with periodic testing (20% chance to cooperate 
    even when reciprocation fails).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.min_sustainable = game_description.capacity * 0.25
        self.num_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            if current_stock > self.min_sustainable:
                return Action.C
            else:
                return Action.D
        if current_stock < self.min_sustainable:
            return Action.D
        prev_cooperation_count = history.opponent_cooperators[-1]
        if self.num_opponents > 0:
            prev_rate = prev_cooperation_count / self.num_opponents
        else:
            prev_rate = 1.0
        if prev_rate >= 0.5:
            return Action.C
        elif random.random() < 0.8:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_69(BaseStrategy):
    """
    Implements a 'Tit-for-Tat with Forgiveness' strategy for the Common Pool Resource game.
    
    The strategy prioritizes long-term resource sustainability by:
    1. Always cooperating in the first round to build trust.
    2. Preventing total collapse if stock levels are critically low (< 20% capacity).
    3. Implementing a conditional reciprocity mechanism (cooperating only if the majority 
       of the group cooperated in the previous round).
    4. Optimizing for the terminal round by defecting if the stock is sufficiently high 
       to capture residual value, but cooperating if the stock is already depleted to 
       ensure a stable final payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            if current_stock >= 0.5 * self.capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < 0.2 * self.capacity:
            return Action.C
        majority_threshold = math.ceil(self.n / 2)
        prev_my_action = history.my_actions[-1]
        prev_opponent_c = history.opponent_cooperators[-1]
        total_cooperators = prev_opponent_c + (1 if prev_my_action else 0)
        if total_cooperators >= majority_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_70(BaseStrategy):
    """
    Triggered Tit-for-Tat with Sustainability Constraints:
    - Prioritizes sustainability by monitoring stock depletion.
    - Uses a Tit-for-Tat mechanism that triggers cooperation only if almost all others cooperate (n-1).
    - Includes a 'Forgiveness' mechanism: if the pool regenerates consistently while in a 
      punishment state, it tests cooperation once.
    - Defect-on-last-round and Defect-on-near-depletion heuristics.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.in_punishment_mode = False
        self.consecutive_stock_growth = 0
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r = history.round_number
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if r == 0:
            self.last_stock = current_stock
            return Action.C
        prev_round = r - 1
        prev_cooperators = history.opponent_cooperators[prev_round]
        my_prev_action = history.my_actions[prev_round]
        my_consumption_ratio = 1 / (2 * n) if my_prev_action else 1 / n
        opp_coop = prev_cooperators
        opp_defect = n - 1 - opp_coop
        opp_consumption_ratio = opp_coop / (2 * n) + opp_defect / n
        rho = 1.0 - (my_consumption_ratio + opp_consumption_ratio)
        if r == total_rounds - 1:
            return Action.D
        if current_stock < 0.1 * capacity:
            return Action.D
        if current_stock > self.last_stock:
            self.consecutive_stock_growth += 1
        else:
            self.consecutive_stock_growth = 0
        self.last_stock = current_stock
        if self.in_punishment_mode:
            if self.consecutive_stock_growth >= 2:
                self.in_punishment_mode = False
                return Action.C
            else:
                return Action.D
        if rho < 0.25:
            self.in_punishment_mode = True
            return Action.D
        if prev_cooperators < n - 1:
            self.in_punishment_mode = True
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_71(BaseStrategy):
    """
    A conditionally cooperative strategy that prioritizes the maintenance of the
    common pool stock at its carrying capacity. It cooperates by default,
    punishes insufficient cooperation (defecting if fewer than n-1 players
    cooperated in the previous round), but prioritizes stock recovery by
    switching to cooperation if the stock level falls below 25% of capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == 1:
            return Action.C
        if current_round == self.game_description.n_rounds:
            if current_stock <= 0.5 * capacity:
                return Action.C
            else:
                return Action.D
        if current_stock < 0.25 * capacity:
            return Action.C
        c_previous = int(history.opponent_cooperators[-1])
        threshold = n - 1
        if c_previous >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_72(BaseStrategy):
    """
    Implements the 'Sustainable Stewardship' strategy.
    
    This strategy utilizes conditional cooperation to maximize long-term sustainability.
    It targets full capacity, punishes defectors probabilistically based on the 
    cooperation ratio, and prioritizes survival if collapse is imminent.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.last_action: Action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        action: Action
        if history.round_number == 0:
            action = Action.C
        elif history.round_number == self.r - 1:
            if current_stock > 0.5 * self.capacity:
                action = Action.C
            else:
                action = Action.D
        elif current_stock < 1e-06:
            action = Action.D
        elif current_stock < 0.25 * self.capacity:
            action = Action.C
        else:
            c_prev_count = history.opponent_cooperators[-1] + (1 if self.last_action == Action.C else 0)
            n_total = self.n
            cooperation_ratio = c_prev_count / n_total
            if cooperation_ratio >= 1.0:
                action = Action.C
            elif cooperation_ratio >= 0.5:
                action = Action.C
            elif random.random() < 1.0 - cooperation_ratio:
                action = Action.D
            else:
                action = Action.C
        self.last_action = action
        return action

class Strategy_BENEVOLENT_73(BaseStrategy):
    """
    Conditional Tit-for-Tat with Sustainability Constraints.
    Prioritizes resource stock safety (Sustainability Threshold) and adapts to group
    cooperation levels using a probabilistic rule, while employing an end-game exit strategy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < self.capacity / 4:
            return Action.D
        if history.round_number >= self.r - 3:
            if history.round_number > 0:
                prev_opp_coop_count = history.opponent_cooperators[-1]
                if prev_opp_coop_count == self.n - 1:
                    return Action.C
                return Action.D
            return Action.C
        if history.round_number == 0:
            return Action.C
        prev_opp_coop_count = history.opponent_cooperators[-1]
        threshold = (self.n - 1) / 2
        if prev_opp_coop_count == self.n - 1:
            return Action.C
        elif prev_opp_coop_count >= threshold:
            probability = prev_opp_coop_count / (self.n - 1)
            return Action.C if random.random() < probability else Action.D
        else:
            return Action.D

class Strategy_BENEVOLENT_74(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource Stewardship.
    
    This strategy prioritizes sustainable common pool usage by cooperating initially.
    It employs a conditional strategy in subsequent rounds:
    1. If the current stock is critically low (below n), it defects to maximize 
       remaining value.
    2. If it is the final round, it defects.
    3. Otherwise, it forgives if at least n/2 players cooperated in the 
       previous round, otherwise it defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < n:
            return Action.D
        my_last_action = history.my_actions[-1]
        cooperators_last_round = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        if cooperators_last_round >= n / 2:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_75(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy that balances resource 
    preservation with tit-for-tat enforcement, defaulting to defection in 
    terminal or failing scenarios.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if current_stock < self.capacity / 10:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        prev_total_coop = prev_opp_coop + (1 if prev_my_action else 0)
        if history.round_number >= 2:
            prev2_opp_coop = history.opponent_cooperators[-2]
            prev2_my_action = history.my_actions[-2]
            prev2_total_coop = prev2_opp_coop + (1 if prev2_my_action else 0)
            if prev_total_coop < self.n / 2 and prev2_total_coop < self.n / 2:
                return Action.D
        if current_stock < self.capacity / 2 and prev_total_coop <= self.n / 2:
            return Action.D
        n_coop_if_C = prev_total_coop
        n_defect_if_C = self.n - n_coop_if_C
        total_consumption = n_coop_if_C * (current_stock / (2 * self.n)) + n_defect_if_C * (current_stock / self.n)
        s_remaining = current_stock - total_consumption
        growth = 2 * s_remaining * (1 - s_remaining / self.capacity)
        s_next_predicted = min(s_remaining + growth, self.capacity)
        if s_next_predicted >= current_stock:
            return Action.C
        elif prev_total_coop >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_76(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Terminal Round: Always Defect (D) to maximize payoff.
    - Survival Logic:
        - If Stock == 0: Defect (no resource to manage).
        - If Stock < (capacity / n): If not final round, Cooperate to prevent collapse; else Defect.
        - If Stock >= (capacity / n): Calculate CooperationIndex = (cooperating_opponents / n_opponents).
            - Index == 1.0 or 0.5 <= Index < 1.0: Cooperate.
            - Index < 0.5: Defect (tit-for-tat punishment/extraction).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / self.game_description.n_players:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        if n_opponents == 0:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        cooperation_index = last_round_cooperators / n_opponents
        if cooperation_index >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_77(BaseStrategy):
    """
    StewardStrategy: A conditional cooperation strategy that maintains the common pool resource
    by acting as a steward. It prioritizes cooperative play to build stock, enforces
    accountability by defecting when cooperation levels are too low, and includes a
    recovery mechanism for critically low stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        round_idx = history.round_number
        if current_stock < 0.25 * capacity:
            return Action.C
        if round_idx == r - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        total_prev_coop = int(my_prev_action) + prev_opp_coop
        if total_prev_coop >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_78(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    The strategy prioritizes stock maintenance at capacity. 
    1. First round: Always Cooperate (C).
    2. Stock >= capacity/2: Use tit-for-tat probabilistic signaling based on past defection count.
    3. Stock < capacity/2: Use survival logic (Defect if critical, otherwise Cooperate).
    4. Final round: Defect (D) as the game ends.
    5. Rapid Depletion protection: Switch to strict Defect if stock < 10% capacity.
    6. Sustained Cooperation: Lock into C if 3 consecutive rounds of perfect cooperation occur.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_perfect_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        t = history.round_number
        if t == 0:
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        if current_stock < 0.1 * capacity:
            return Action.D
        if t == r - 1:
            return Action.D
        my_last_action_was_c = history.my_actions[-1]
        total_cooperators_last_round = k_prev + (1 if my_last_action_was_c else 0)
        if total_cooperators_last_round == n:
            self.consecutive_perfect_rounds += 1
        else:
            self.consecutive_perfect_rounds = 0
        if self.consecutive_perfect_rounds >= 3:
            return Action.C
        critical_threshold = capacity / 2.0
        critically_low = current_stock < current_stock / (2 * n)
        if current_stock >= critical_threshold:
            if k_prev == 0 and (not my_last_action_was_c):
                return Action.D
            if k_prev == n - 1:
                return Action.C
            cooperation_prob = 1.0 - k_prev / (n - 1)
            if random.random() < cooperation_prob:
                return Action.C
            else:
                return Action.D
        else:
            defection_rate = (n - 1 - k_prev) / (n - 1)
            if defection_rate > 0.5:
                return Action.D
            if critically_low:
                return Action.D
            else:
                return Action.C

class Strategy_BENEVOLENT_79(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource-Targeting strategy.
    Prioritizes sustainability via a target stock level, employs Tit-for-Tat 
    logic with a forgiving reset after defections, and maximizes final round utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.target_stock = game_description.capacity * 0.5
        self.s_min = game_description.n_players * 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock > self.s_min:
                return Action.C
            else:
                return Action.D
        if current_stock > self.target_stock:
            return Action.C
        if n_opponents > 0:
            opp_c_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            opp_c_rate = 1.0
        if opp_c_rate > 0.5:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_80(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource Awareness.
    Prioritizes sustainability via cooperation unless provoked, 
    with dynamic forgiveness mechanisms and terminal-round defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1
        self.reputation = 0.5
        self.alpha = 0.8
        self.consecutive_low_reputation = 0
        self.in_punishment_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_n_cooperators = history.opponent_cooperators[-1]
        if self.n_opponents > 0:
            current_round_score = last_n_cooperators / self.n_opponents
        else:
            current_round_score = 1.0
        self.reputation = self.alpha * self.reputation + (1 - self.alpha) * current_round_score
        if self.reputation < 0.5:
            self.consecutive_low_reputation += 1
        else:
            self.consecutive_low_reputation = 0
        if current_stock < 0.1 * self.game_description.capacity:
            return Action.D
        if last_n_cooperators == self.n_opponents and current_stock > 0:
            return Action.C
        if self.game_description.n_players == 2:
            if last_n_cooperators == 0:
                return Action.D
        if self.consecutive_low_reputation >= 3:
            return Action.D
        if self.reputation < 0.5:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_81(BaseStrategy):
    """
    Implements a Generous Tit-for-Tat strategy with explicit threshold-based
    resource preservation. Prioritizes resource regeneration when stock levels
    drop below 50% capacity, and otherwise reciprocates the majority behavior
    of the collective in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.critical_threshold = 0.5 * self.capacity
        self.super_critical_threshold = 0.1 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.r - 1:
            return Action.C if current_stock > 0 else Action.D
        if current_stock < self.critical_threshold:
            return Action.C
        if current_round_idx == 0:
            return Action.C
        prev_opp_cooperators = history.opponent_cooperators[-1]
        if prev_opp_cooperators >= self.n // 2:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_82(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy.
    
    This strategy prioritizes long-term resource maintenance. It begins by 
    cooperating (C) in the first round. In subsequent rounds, it monitors the 
    previous round's collective behavior: if the number of defectors is less than 
    half the total number of players, it continues to cooperate (C). If the number 
    of defectors is half or more of the total number of players, it defects (D) as 
    a temporary corrective action. In the final round, it defects (D) to maximize 
    utility, unless the stock is depleted, in which case it cooperates (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.C if current_stock <= 0 else Action.D
        if current_round == 0:
            return Action.C
        opponents_cooperating = history.opponent_cooperators[-1]
        i_cooperated = 1 if history.my_actions[-1] else 0
        total_cooperators = opponents_cooperating + i_cooperated
        total_defectors = self.n - total_cooperators
        if total_defectors >= self.n / 2.0:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_83(BaseStrategy):
    """
    Tit-for-Tat Regeneration (TFR): A dynamic strategy for the Common Pool Resource Game.
    Prioritizes sustainability of the pool by adjusting cooperation based on resource health
    and historical opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = -1
        prev_opp_coop_count = history.opponent_cooperators[prev_round_idx]
        my_prev_action = history.my_actions[prev_round_idx]
        total_cooperators_prev = prev_opp_coop_count + (1 if my_prev_action else 0)
        cr = total_cooperators_prev / self.n
        threshold = 0.25 * self.capacity
        if current_stock < threshold:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            if current_stock > 0.5 * self.capacity:
                return Action.D
            return Action.C
        if current_stock < 0.75 * self.capacity:
            return Action.C
        if cr >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_84(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource Awareness.
    Prioritizes sustainability when the stock is low, punishes consistent 
    defectors when stock is high, and forgives after a punishment cycle.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.target = math.ceil(self.n / 2)
        self._just_punished = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r_idx = history.round_number
        if r_idx > 0:
            last_action_was_defect = history.my_actions[-1] == Action.D.value
            if self._just_punished:
                self._just_punished = False
        else:
            last_action_was_defect = False
        if r_idx == 0:
            return Action.C
        if current_stock < 0.05 * self.capacity or current_stock < 1.0:
            return Action.C
        if last_action_was_defect:
            return Action.C
        if r_idx == self.r - 1:
            coop_counts = history.opponent_cooperators
            if np.mean(coop_counts) >= self.target:
                return Action.C
            else:
                return Action.D
        k_prev = history.opponent_cooperators[-1]
        if k_prev >= self.target:
            return Action.C
        elif current_stock > self.capacity / 2:
            self._just_punished = True
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_85(BaseStrategy):
    """
    A strategy for the Common Pool Resource Game that adapts cooperation based on
    previous rounds' cooperation rates and stock levels, implementing a threshold-based
    reciprocity mechanism with a final round defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.T = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock <= 1e-09:
            return Action.D
        my_last_action = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + my_last_action
        c_prev = total_cooperators / self.n
        critical_threshold = 0.25 * self.capacity
        if current_stock < critical_threshold:
            if c_prev < self.T:
                return Action.D
            return Action.C
        elif c_prev >= self.T:
            return Action.C
        else:
            p_defect = (self.T - c_prev) / self.T
            if random.random() < p_defect:
                return Action.D
            else:
                return Action.C

class Strategy_BENEVOLENT_86(BaseStrategy):
    """
    A Tit-for-Tat variant that prioritizes stock sustainability. 
    It cooperates initially, penalizes the group if the average cooperation rate 
    falls below 50%, defects when the stock is critically low, and makes a 
    final-round decision based on remaining resource health.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        r_num = history.round_number
        if r_num == 0:
            return Action.C
        if current_stock < capacity / (2 * n):
            return Action.D
        my_cooperation_counts = history.my_actions.astype(int)
        total_cooperators_per_round = history.opponent_cooperators + my_cooperation_counts
        cooperation_rates = total_cooperators_per_round / n
        if np.mean(cooperation_rates) < 0.5:
            return Action.D
        if r_num == r - 1:
            if current_stock > capacity / 2:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_87(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Stock-Awareness Strategy.
    
    Logic Summary:
    - Last round: Always Defect (D).
    - Emergency (Stock < Capacity/4): Always Defect (D).
    - Healthy Stock (Stock >= Capacity/2): 
        - Cooperate if group cooperated (C_total > n/2).
        - Forgive once if group defected (punishment_counter < 1).
        - Retaliate with D if group defected and punishment_counter >= 1.
    - Precarious Stock (Capacity/4 <= Stock < Capacity/2): 
        - Cooperate only if everyone else is cooperating (C_total == n).
        - Otherwise Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            self.punishment_counter = 0
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opp_coop = history.opponent_cooperators[-1]
        prev_C_count = last_opp_coop + (1 if last_my_action == Action.C else 0)
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_stock < capacity / 4:
            return Action.D
        if current_stock >= capacity / 2:
            if prev_C_count > n / 2:
                self.punishment_counter = 0
                return Action.C
            elif self.punishment_counter < 1:
                self.punishment_counter += 1
                return Action.C
            else:
                return Action.D
        if capacity / 4 <= current_stock < capacity / 2:
            if prev_C_count == n:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_BENEVOLENT_88(BaseStrategy):
    """
    Tit-for-Tat with Graduated Response and Sustainability Threshold:
    A strategy that maintains cooperation based on stock health, responds to
    aggregate defection with probabilistic punishment, and switches to
    cautious behavior or regeneration modes based on critical stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if current_stock == 0:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        if round_idx >= self.total_rounds - 3:
            if current_stock < 0.5 * self.capacity:
                return Action.D
        if current_stock >= 0.9 * self.capacity:
            return Action.C
        my_last_action = history.my_actions[-1]
        opp_coop = history.opponent_cooperators[-1]
        total_coop = opp_coop + (1 if my_last_action else 0)
        d_last = self.n - total_coop
        if d_last == 0:
            return Action.C
        else:
            prob_defect = d_last / self.n
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_BENEVOLENT_89(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Stock Preservation.
    
    This strategy maintains stock levels by prioritizing cooperation when stock is low,
    punishing defectors proportionally to the number of observed defections, 
    and defecting in the final round to maximize remaining utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        num_opponents = self.game_description.n_players - 1
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round == total_rounds - 1:
            return Action.D if current_stock > 0 else Action.C
        if current_round == 0:
            return Action.C
        if current_stock < 0.2 * capacity:
            self.punishment_remaining = 0
            return Action.C
        prev_round_idx = current_round - 1
        num_cooperators = history.opponent_cooperators[prev_round_idx]
        num_defectors = num_opponents - num_cooperators
        if num_defectors > 0 and self.punishment_remaining == 0:
            self.punishment_remaining = num_defectors
        if self.punishment_remaining > 0:
            self.punishment_remaining -= 1
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_90(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Stock-Sensitivity strategy.
    
    1. First Round: Always Cooperate (C).
    2. Stock Safety Override: If stock < 2n, Defect (D) to extract remaining value.
    3. Final Round: If stock >= 2n, Cooperate (C), else Defect (D).
    4. General Rounds (Tit-for-Tat with Forgiveness):
       - k = number of cooperating players in previous round.
       - If k = n: Cooperate.
       - If k >= n/2: Cooperate.
       - If k < n/2: Defect with probability (1 - k/n).
    
    Note: Opponent cooperators count in history represents opponents only, 
    so we adjust calculations to include 'self' behavior for the total count k.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.threshold = 2 * self.n

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        current_round_num = round_idx + 1
        if current_stock < self.threshold:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_round_num == self.r:
            return Action.C if current_stock >= self.threshold else Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coop_count = int(history.opponent_cooperators[-1])
        k = prev_opp_coop_count + (1 if prev_my_action else 0)
        if k == self.n or k >= self.n / 2:
            return Action.C
        else:
            prob_defect = 1.0 - k / self.n
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_BENEVOLENT_91(BaseStrategy):
    """
    Implements a sustainable trigger strategy that targets a stock level of capacity/2.
    It cooperates in the first round and maintains cooperation if all players cooperated.
    It punishes defection and incorporates a recovery threshold mechanism and 
    a terminal round defection condition.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < capacity / (4 * n):
            return Action.D
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action_was_c = history.my_actions[-1]
        total_cooperators_prev = prev_cooperators + (1 if my_prev_action_was_c else 0)
        if total_cooperators_prev == n:
            return Action.C
        elif current_stock >= capacity / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_92(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource Stewardship.
    
    This strategy prioritizes long-term resource sustainability. It cooperates by default
    in the first round. In subsequent rounds, it monitors the common pool stock and 
    opponent behavior. If the stock is critically low, it forces cooperation to prevent 
    collapse. If the stock is healthy, it reciprocates cooperation, but punishes 
    defection by defecting for one round, followed by a forgiveness mechanism. 
    It also yields to full cooperation in the final round to maximize global welfare.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = self.game_description.capacity / self.game_description.n_players * 1.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        if current_stock < self.threshold:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        prev_c_count = history.opponent_cooperators[-1]
        last_action = history.my_actions[-1]
        if prev_c_count == n_opponents:
            return Action.C
        if last_action == False:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_93(BaseStrategy):
    """
    A cooperative, adaptive Tit-for-Tat strategy for the Common Pool Resource Game.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Rounds 1 < t < r:
        - Calculates the fraction of cooperating opponents in the previous round.
        - If fraction >= 0.5, Cooperate (C).
        - If fraction < 0.5, Defect (D).
        - If stock is critical (< 0.5 * capacity), forces Cooperation regardless of history to prevent extinction.
        - Reverts to conditional strategy once stock recovers (> 0.75 * capacity).
    - Round t = r:
        - If stock > 0, Defect (D) to maximize final utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game = game_description
        self.recovery_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if current_stock <= 0:
            return Action.C
        if round_idx == self.game.n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < 0.5 * self.game.capacity:
            self.recovery_mode = True
        elif current_stock > 0.75 * self.game.capacity:
            self.recovery_mode = False
        if self.recovery_mode:
            return Action.C
        n_opponents = self.game.n_players - 1
        if n_opponents == 0:
            return Action.C
        last_round_coops = history.opponent_cooperators[-1]
        f_t_minus_1 = last_round_coops / n_opponents
        if f_t_minus_1 >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_94(BaseStrategy):
    """
    Implements a conditional cooperation strategy (Tit-for-Tat variant) for a Common Pool Resource game.
    
    Logic:
    - First Round: Cooperate (C).
    - Last Round: Defect (D) to capture remaining value.
    - Intermediate Rounds:
        - If current_stock <= 25% of capacity: Defect (D) to preserve personal payoff.
        - Otherwise, cooperate if the number of defectors in the previous round was <= n/2,
          else defect to signal intolerance for depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opp_coop_count = history.opponent_cooperators[-1]
        total_cooperators_prev = (1 if last_my_action else 0) + last_opp_coop_count
        total_defectors_prev = self.n - total_cooperators_prev
        if current_stock <= 0.25 * self.capacity:
            return Action.D
        if total_defectors_prev <= self.n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_95(BaseStrategy):
    """
    A sustainability-focused Tit-for-Tat strategy for the Common Pool Resource Game.
    Prioritizes resource conservation when stock is low, and employs proportional
    probabilistic retaliation against defectors in later rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number + 1
        if current_round_idx == 1:
            return Action.C
        if current_stock < self.capacity / 4:
            return Action.C
        prev_round_idx = history.round_number - 1
        opp_coop_count = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        prev_round_defectors = n_opponents - opp_coop_count
        if prev_round_defectors == 0:
            return Action.C
        dif = prev_round_defectors / max(1, n_opponents)
        if current_round_idx == self.total_rounds:
            if dif > 0.3:
                return Action.D
            else:
                return Action.C
        if dif > 0.5:
            return Action.D
        if random.random() < dif:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_96(BaseStrategy):
    """
    Tit-for-Tat with Graduated Reciprocity: 
    Prioritizes maintaining the common pool at capacity. Defaults to cooperation.
    Observes previous round's cooperation levels to decide between sustaining 
    growth or switching to defensive defection when projected stock falls 
    below 50% of capacity. Includes an end-game heuristic to capture value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.r - 3:
            if current_stock < 0.5 * self.capacity:
                return Action.D
            else:
                return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        k_prev = history.opponent_cooperators[-1] + my_prev_action
        if current_stock >= self.capacity:
            return Action.C
        if k_prev >= self.n - 1:
            return Action.C
        total_consumption = k_prev * (current_stock / (2 * self.n)) + (self.n - k_prev) * (current_stock / self.n)
        s_remaining = current_stock - total_consumption
        if s_remaining < 0:
            s_remaining = 0.0
        growth = 2.0 * s_remaining * (1.0 - s_remaining / self.capacity)
        s_next = min(s_remaining + growth, float(self.capacity))
        if s_next > 0.5 * self.capacity:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_97(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Resource Stewardship.

    This strategy prioritizes sustainability. It maintains cooperation by default,
    defects only if total defection occurred in the previous round (while stock is high),
    prioritizes conservation when the stock is critically low, and optimizes
    final round utility based on remaining stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        current_round = round_idx + 1
        if round_idx == 0:
            return Action.C
        if current_stock < self.capacity / 2:
            return Action.C
        if current_round == self.total_rounds:
            if current_stock > self.capacity / 4:
                return Action.C
            else:
                return Action.D
        prev_round_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_prev_is_defector = 1 if my_prev_action == False else 0
        total_defectors = self.n - 1 - prev_round_cooperators + my_prev_is_defector
        if total_defectors == self.n:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_98(BaseStrategy):
    """
    Implements a sustainability-focused strategy with adaptive retaliation.
    
    Strategy Logic:
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1: 
        - If current stock S < capacity/4, Cooperate to save the pool, 
          unless S < 0.1, in which case Defect to harvest remaining utility.
        - Otherwise, calculate Defection Index I = (Defectors) / (n - 1).
        - If I > 0.5, Defect; else Cooperate.
    - Final Round: 
        - If S > capacity / (2 * n), Defect.
        - Else, Cooperate to avoid total collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == self.r - 1:
            threshold = self.capacity / (2 * self.n)
            if current_stock > threshold:
                return Action.D
            else:
                return Action.C
        num_opponents = self.n - 1
        num_cooperators_prev = history.opponent_cooperators[-1]
        num_defectors_prev = num_opponents - num_cooperators_prev
        if current_stock < self.capacity / 4.0:
            if current_stock < 0.1:
                return Action.D
            return Action.C
        if num_opponents > 0:
            defection_index = num_defectors_prev / float(num_opponents)
            if defection_index > 0.5:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_BENEVOLENT_99(BaseStrategy):
    """
    Tit-for-Tat Resource Stewardship strategy.
    Prioritizes long-term sustainability using a moving average of opponent cooperation
    and adapts based on current stock levels and round progression.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        r = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if t == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        my_contribution = 1 if my_last_action else 0
        last_round_cooperators = history.opponent_cooperators[-1]
        opponents_cooperated_count = last_round_cooperators - my_contribution
        c_prev = opponents_cooperated_count / (n - 1)
        self.cooperation_threshold = 0.9 * self.cooperation_threshold + 0.1 * c_prev
        if current_stock < n:
            return Action.C
        if current_stock == 0:
            return Action.C
        if t == r - 1:
            if current_stock > 0.25 * capacity:
                return Action.C
            else:
                return Action.D
        if self.cooperation_threshold >= 0.5 or current_stock > 0.5 * capacity:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_100(BaseStrategy):
    """
    A strategy that balances resource conservation with adaptive responses to 
    opponent behavior, using a threshold-based cooperation logic and 
    last-round optimization.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.has_ever_defected = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            if not self.has_ever_defected:
                return Action.C
            else:
                return Action.D
        if current_stock < self.capacity / (10 * self.n):
            self.has_ever_defected = True
            return Action.D
        k = history.opponent_cooperators[-1]
        threshold = math.ceil((self.n - 1) / 2)
        if k >= threshold or current_stock > self.capacity / 2:
            return Action.C
        else:
            if self.n == 2:
                if k == 1:
                    return Action.C
                else:
                    self.has_ever_defected = True
                    return Action.D
            self.has_ever_defected = True
            return Action.D

class Strategy_BENEVOLENT_101(BaseStrategy):
    """
    Implements a 'Conditional Tit-for-Tat with Resilience' strategy for the Common Pool Resource game.
    The strategy prioritizes long-term cooperation and sustainability by titrating responses based on
    previous round cooperation and current stock levels. It includes emergency defection thresholds
    and specific behaviors for the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < self.game_description.capacity / self.game_description.n_players - 1e-09:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opponents_coop = history.opponent_cooperators[-1]
        c_prev = opponents_coop + (1 if my_prev_action else 0)
        n = self.game_description.n_players
        if c_prev > n / 2:
            return Action.C
        if c_prev == 0:
            return Action.D
        prob_defect = 1.0 - c_prev / n
        if random.random() < prob_defect:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_102(BaseStrategy):
    """
    Triggered Tit-for-Tat with Resource Maintenance.
    Maintains a trust score based on aggregate cooperation history.
    Adapts cooperation probability based on trust, stock levels, and terminal game conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_score = 1.0
        self.alpha = 0.8
        self.cooperation_streak = 0
        self.consecutive_coop_threshold = 3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            self.trust_score = 1.0
            return Action.C
        prev_coop_count = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        total_cooperators = prev_coop_count + my_prev_coop
        p_t = total_cooperators / n
        self.trust_score = self.alpha * self.trust_score + (1 - self.alpha) * p_t
        if p_t > 0:
            self.cooperation_streak += 1
        else:
            self.cooperation_streak = 0
            self.trust_score = 0.0
        if current_stock < capacity * 0.2 or current_stock < 0.0001:
            return Action.D
        if self.cooperation_streak >= self.consecutive_coop_threshold and self.trust_score > 0.8:
            return Action.C
        prob_c = max(0.0, min(1.0, self.trust_score))
        if random.random() <= prob_c:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_103(BaseStrategy):
    """
    Tit-for-Tat with Resource-Adaptive Thresholding (TFRAT).
    
    Operates on conditional cooperation. If the stock is critically low, 
    it prioritizes cooperation to prevent collapse. If the stock is healthy,
    it uses a dynamic threshold (lenience buffer) against the previous round's 
    aggregate opponent cooperation to decide whether to cooperate or defect.
    It forces cooperation on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.C
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.05 * self.capacity:
            return Action.C
        if current_stock < self.capacity / 4.0:
            return Action.C
        if self.n_opponents > 0:
            c_prev = history.opponent_cooperators[-1] / self.n_opponents
        else:
            c_prev = 0.0
        t_threshold = 1.0 - current_stock / self.capacity
        if c_prev >= t_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_104(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    This strategy behaves benevolently by prioritizing resource preservation.
    - Round 1: Always Cooperate.
    - Resource Recovery: If stock < capacity/2, always Cooperate.
    - Steady State: Match the cooperation level of opponents.
    - Punishment: If opponents defect, punish stochastically to discourage exploitation.
    - Final Round: Harvest (Defect) if stock is safe, otherwise conserve (Cooperate).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            if current_stock > self.capacity / self.n:
                return Action.D
            else:
                return Action.C
        if current_stock < self.capacity / 2:
            return Action.C
        k = history.opponent_cooperators[-1]
        if self.n_opponents == 0:
            return Action.C
        if k >= self.n_opponents:
            return Action.C
        probability_cooperate = k / self.n_opponents
        if random.random() < probability_cooperate:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_105(BaseStrategy):
    """
    A Tit-for-Tat variant with a 'Cooperative Stock Preservation' threshold.
    Plays C in the first round. In subsequent rounds, plays C if the current stock 
    is above a critical threshold S_crit AND the previous round was cooperative.
    Otherwise, plays D.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.s_crit = self.capacity * (1 / (1 + (self.n - 2) / 2))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.s_crit:
            return Action.D
        cooperation_threshold = math.ceil((self.n - 1) / 2)
        if history.opponent_cooperators[-1] >= cooperation_threshold:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_106(BaseStrategy):
    """
    Implements an Adaptive Sustainable Cooperator strategy for the Common Pool Resource Game.
    This strategy balances aggressive resource extraction with long-term sustainability,
    utilizing a Tit-for-Tat mechanism for reciprocity, a 'collapse avoidance' trigger
    based on stock levels, and a terminal 'trust-but-verify' phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        if round_t == 0:
            return Action.C
        if round_t == self.r - 1:
            if current_stock >= 0.5 * self.capacity:
                return Action.D
            return Action.C
        if current_stock < 0.1 * self.capacity:
            return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.C
        last_my_action = 1 if history.my_actions[-1] else 0
        c_prev_total = history.opponent_cooperators[-1] + last_my_action
        if c_prev_total < self.n / 2.0:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_107(BaseStrategy):
    """
    A Forgiving Aggregate Tit-for-Tat strategy for the Common Pool Resource game.
    This agent prioritizes long-term sustainability by cooperating in the final round,
    cooperating when the stock is critically low, and forgiving previous defections 
    to restore cooperative equilibria.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.C
        if current_stock < capacity / (2 * n):
            return Action.C
        prev_action = Action.C if history.my_actions[-1] else Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_action == Action.D:
            return Action.C
        if prev_cooperators >= n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_108(BaseStrategy):
    """
    Threshold-Based Tit-For-Tat (TBTFT): 
    Maintains a trust score based on group cooperation. If the number of 
    cooperators meets a 75% threshold, trust increases. If not, trust 
    decreases. Actions are chosen based on whether trust > 0.5, with a 
    selfish exception in the final round to maximize payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_score = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.trust_score = 1.0
            return Action.C
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators_last_round = my_last_action_val + history.opponent_cooperators[-1]
        threshold = self.game_description.n_players * 0.75
        if total_cooperators_last_round >= threshold:
            self.trust_score = min(1.0, self.trust_score + 0.1)
        else:
            self.trust_score = max(0.0, self.trust_score - 0.2)
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if self.trust_score > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_109(BaseStrategy):
    """
    Implements a Tit-for-Tat inspired strategy with forgiveness and survival parameters 
    for the Common Pool Resource Game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.prev_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r_idx = history.round_number
        if r_idx == 0:
            self.prev_stock = current_stock
            return Action.C
        my_prev_action = history.my_actions[-1]
        k_prev = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if r_idx == self.game_description.n_rounds - 1:
            return Action.C if k_prev >= self.n - 1 else Action.D
        if current_stock <= 0.1 * self.capacity:
            return Action.C
        if k_prev >= self.n - 1:
            action = Action.C
        elif current_stock > self.prev_stock:
            action = Action.C
        else:
            action = Action.D
        self.prev_stock = current_stock
        return action

class Strategy_BENEVOLENT_110(BaseStrategy):
    """
    Implements a Sustainable Tit-for-Tat with Forgiveness strategy.
    
    Logic:
    - Round 1: Always Cooperate (C) to establish stability.
    - Subsequent Rounds (t > 1):
        1. If previous stock was low (S < capacity/4), prioritize recovery by playing C.
        2. If previous stock was healthy (S >= capacity/2):
           - If most players were cooperative (C_prev >= n/2), continue to Cooperate.
           - If most players defected (C_prev < n/2), Defect (D) to prevent exploitation.
    - Terminal Round (t = r): Always Cooperate (C) for a benevolent exit.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        if round_t == 0:
            return Action.C
        if round_t == self.r - 1:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        cooperators_prev = my_prev_action + history.opponent_cooperators[-1]
        if current_stock < self.capacity / 4.0:
            return Action.C
        if cooperators_prev >= self.n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_111(BaseStrategy):
    """
    Implements a Conditional Stewardship strategy.
    
    This strategy monitors the common pool resource health and the cooperation 
    levels of other players. It plays cooperatively when the resource is 
    sustainably managed and a sufficient majority of others are also cooperating.
    It switches to defection in terminal rounds, when the resource is nearing 
    collapse, or when others are defecting, to protect against exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.threshold = math.ceil(self.n * 0.6)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t == self.r - 1:
            return Action.D
        k_opponents = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        k_prev = k_opponents + (1 if my_prev_action else 0)
        growth_zone = current_stock >= self.capacity * 0.5
        collapse_imminent = current_stock < self.capacity * 0.25
        majority_cooperation = k_prev >= self.threshold
        if collapse_imminent:
            return Action.D
        if majority_cooperation and growth_zone:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_112(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness strategy for the Common Pool Resource game.
    
    Operates on the principle of sustainability:
    - Round 1: Always Cooperates (C) to signal intent.
    - Rounds 2 to r-1: 
        - Survival: If stock < capacity/4, force Cooperate (C).
        - Reciprocity: Cooperate (C) if almost all opponents (n-1) cooperated.
        - Forgiveness: If previously defected, switch to C with 20% probability.
    - Final Round: Defect (D) if stock >= capacity/2, else Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            if current_stock >= self.capacity / 2:
                return Action.D
            else:
                return Action.C
        if current_stock < self.capacity / 4:
            return Action.C
        k = history.opponent_cooperators[-1]
        if k >= self.n - 1:
            return Action.C
        my_prev_action = history.my_actions[-1]
        if my_prev_action == Action.D.value:
            if random.random() < 0.2:
                return Action.C
        return Action.D

class Strategy_BENEVOLENT_113(BaseStrategy):
    """
    A 'Conditional Sustainability' strategy that promotes long-term stock preservation.
    
    Logic:
    1. Round 1: Always Cooperate (C).
    2. Last Round: Cooperate (C) if stock is sufficient, otherwise Defect (D).
    3. Intermediate Rounds:
       - If stock < 20% capacity: Defect (D).
       - If stock < 80% capacity: Cooperate (C) if previous round had no defectors, otherwise permanent Defect (D).
       - If stock >= 80% capacity: Cooperate (C) if previous round had no defectors, otherwise Tit-for-Tat Defect (D).
       
    'Defectors' are inferred from the number of cooperating opponents. Total players n = n_opponents + 1.
    If 'opponent_cooperators' < (n - 1), then at least one opponent defected.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        n_players = self.game_description.n_players
        n_opponents = n_players - 1
        capacity = self.game_description.capacity
        if round_idx == 0:
            return Action.C
        if round_idx == self.game_description.n_rounds - 1:
            if current_stock >= capacity * 0.1:
                return Action.C
            return Action.D
        prev_opp_coops = history.opponent_cooperators[-1]
        my_prev_action_was_c = bool(history.my_actions[-1])
        total_cooperators = prev_opp_coops + (1 if my_prev_action_was_c else 0)
        d_prev = total_cooperators < n_players
        if not self.permanent_defection:
            if current_stock < capacity * 0.8 and d_prev:
                self.permanent_defection = True
        if current_stock < capacity * 0.2:
            return Action.D
        if self.permanent_defection:
            return Action.D
        if current_stock < capacity * 0.8:
            if d_prev:
                self.permanent_defection = True
                return Action.D
            return Action.C
        if d_prev:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_114(BaseStrategy):
    """
    Tit-for-Tat strategy with Generous Recovery mechanism.
    
    This strategy monitors the common pool resource stock:
    - Initiates a Recovery Phase if stock drops below capacity/n.
    - Plays cooperatively (C) during Recovery Phase for m rounds or until stock recovers.
    - Uses a Tit-for-Tat logic with a 75% cooperation threshold for opponent history.
    - Prioritizes sustainability in the final round based on resource levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.in_recovery = False
        self.recovery_countdown = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        if current_stock < capacity / n:
            if not self.in_recovery:
                self.in_recovery = True
                self.recovery_countdown = math.ceil(n / 2)
        if self.in_recovery:
            if current_stock > capacity / 2:
                self.in_recovery = False
            else:
                self.recovery_countdown -= 1
                if self.recovery_countdown <= 0:
                    self.in_recovery = False
                return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock < capacity / 2:
                return Action.C
            else:
                return Action.D
        k = history.opponent_cooperators[-1]
        threshold = (n - 1) * 0.75
        if k >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_115(BaseStrategy):
    """
    Triggered Sustainable Tit-for-Tat:
    Prioritizes sustainability and group utility.
    - Always cooperates in the first round.
    - Always defects in the final round.
    - If stock is below critical threshold (capacity / 2n), forces cooperation to prevent collapse.
    - Otherwise, reciprocates based on the 80% cooperation threshold of opponents in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == n_rounds - 1:
            return Action.D
        if n > 0 and current_stock < capacity / (2 * n):
            return Action.C
        if current_round == 0:
            return Action.C
        num_opponents = n - 1
        if num_opponents > 0:
            cooperators_last_round = history.opponent_cooperators[-1]
            cooperation_rate = cooperators_last_round / num_opponents
            if cooperation_rate >= 0.8:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_116(BaseStrategy):
    """
    Sustainable Tit-for-Tat with Forgiveness.
    
    This strategy prioritizes sustainability of the common pool resource.
    - First round: Cooperates.
    - Subsequent rounds: Monitors defection count. Cooperates if defection count is 
      low (<= n/2), otherwise defects.
    - Forgiveness: If the stock remains healthy (above capacity/4), it attempts 
      to forgive after defection.
    - Last round: Defects if the resource cannot support survival, otherwise cooperates.
    - Safety: If stock drops below 10% of capacity, it permanently defects to
      maximize final individual returns.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.has_defected_recently = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 0.1 * self.capacity:
            return Action.D
        current_round = history.round_number
        if current_round == 0:
            self.has_defected_recently = False
            return Action.C
        if current_round == self.r - 1:
            if current_stock > self.capacity / self.n:
                return Action.C
            else:
                return Action.D
        n_opponents = self.n - 1
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_defectors = n_opponents - prev_opp_coop
        threshold = self.n // 2
        my_prev_action = history.my_actions[-1]
        if prev_defectors <= threshold:
            self.has_defected_recently = False
            return Action.C
        elif not my_prev_action and current_stock > self.capacity / 4:
            self.has_defected_recently = False
            return Action.C
        else:
            self.has_defected_recently = True
            return Action.D

class Strategy_BENEVOLENT_117(BaseStrategy):
    """
    A Tit-for-Tat variant strategy for the Common Pool Resource Game.
    It maintains a 'status' (Cooperative or Retaliatory) to manage the common pool
    stock. It cooperates to build sustainable yields and retaliates (defects) if
    the resource is being depleted by the group. It also implements a terminal
    phase logic to decide whether to defect based on the health of the remaining stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_retaliatory = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            if current_stock >= 0.5 * capacity:
                return Action.C
            return Action.D
        prev_idx = round_idx - 1
        opponents_cooperated = history.opponent_cooperators[prev_idx]
        my_last_action = history.my_actions[prev_idx]
        my_contribution = 1 if my_last_action else 0
        total_cooperators = opponents_cooperated + my_contribution
        total_defectors = n - total_cooperators
        consumption_factor = (total_cooperators * 0.5 + total_defectors) / n
        is_depleting = consumption_factor > 0.5
        if self.is_retaliatory:
            if current_stock >= 0.95 * capacity or total_cooperators >= math.floor(n / 2):
                self.is_retaliatory = False
                return Action.C
            else:
                return Action.D
        elif is_depleting:
            self.is_retaliatory = True
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_118(BaseStrategy):
    """
    A Tit-for-Tat with Forgiveness strategy for the Common Pool Resource Game.
    
    This strategy focuses on sustaining the common pool by cooperating when others 
    are cooperating, punishing defection with a short-term defect action to buffer 
    losses, and prioritizing individual payoff extraction in the terminal game phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.epsilon = 1e-09

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            return Action.D
        if round_idx == total_rounds - 2 and current_stock < self.capacity * 0.5:
            return Action.D
        if current_stock < self.capacity * 0.2:
            return Action.C
        if current_stock <= self.epsilon:
            return Action.D
        prev_k = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        total_cooperators = prev_k + (1 if prev_my_action else 0)
        if total_cooperators >= self.n / 2:
            return Action.C
        if self.n - total_cooperators > self.n / 2:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_119(BaseStrategy):
    """
    A strategy that aims for sustainable common pool resource management using
    tit-for-tat reciprocity, stock-sensitive restoration phases, and defensive 
    mechanisms against depletion and consistent defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_full_defection_count = 0
        self.prev_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            self.prev_stock = current_stock
            return Action.C
        last_opponents_c = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if last_opponents_c == 0:
            self.consecutive_full_defection_count += 1
        else:
            self.consecutive_full_defection_count = 0
        stock_reduction = self.prev_stock - current_stock
        is_trending_down_rapidly = self.prev_stock > 0 and stock_reduction / self.prev_stock > 0.2
        self.prev_stock = current_stock
        if current_stock < capacity / 2 ** n:
            return Action.D
        if self.consecutive_full_defection_count >= 2:
            return Action.D
        if current_stock <= capacity / 2:
            if current_stock < capacity / 10:
                return Action.D
            return Action.C
        elif last_opponents_c >= n_opponents / 2:
            if last_opponents_c < n_opponents and is_trending_down_rapidly and (current_stock > capacity / 4):
                return Action.D
            return Action.C
        else:
            defection_rate = (n_opponents - last_opponents_c) / n_opponents if n_opponents > 0 else 0
            if random.random() < defection_rate:
                return Action.D
            return Action.C

class Strategy_BENEVOLENT_120(BaseStrategy):
    """
    Conditional Sustainability Strategy.
    Prioritizes resource preservation and stock viability.
    - Round 1: Always Cooperate (C).
    - Final Round: Always Defect (D) to capture residual value.
    - Imminent Collapse (stock near 0): Defect (D).
    - Cooperative Environment: If opponents show sustained cooperation, cooperate (C).
    - Declining Environment: Periodically signal for reset if stock is low, otherwise cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        total_rounds = self.game_description.n_rounds
        if round_t == 0:
            return Action.C
        if round_t == total_rounds - 1:
            return Action.D
        collapse_threshold = self.capacity / (2 * self.n)
        if current_stock < collapse_threshold:
            return Action.D
        total_coops = np.sum(history.opponent_cooperators)
        total_possible_coops = len(history.opponent_cooperators) * self.n_opponents
        if total_possible_coops > 0:
            coop_rate = total_coops / total_possible_coops
        else:
            coop_rate = 0.0
        if coop_rate >= 0.5:
            return Action.C
        if current_stock < 0.5 * self.capacity and round_t % 3 == 0:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_121(BaseStrategy):
    """
    Adaptive Sustainable Tit-for-Tat (ASTFT) Strategy.
    
    This strategy maintains resource stock levels by cooperating when the collective
    cooperation rate is high, and retaliating against defection. It includes a 
    survival threshold mechanism where the strategy reverts to cooperation if the 
    stock is critically low, regardless of opponent behavior, to prevent 
    systemic resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.epsilon = self.capacity / (2 * self.n)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        current_round = round_idx + 1
        if round_idx == 0:
            return Action.C
        my_last_action_val = 1 if history.my_actions[-1] == Action.C else 0
        k_prev = history.opponent_cooperators[-1] + my_last_action_val
        if current_round == self.r:
            if k_prev >= self.n - 1:
                return Action.C
            else:
                return Action.D
        if k_prev >= self.n - 1:
            return Action.C
        elif current_stock <= self.epsilon:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_122(BaseStrategy):
    """
    Implements a Tit-for-Tat with Forgiveness strategy for the Common Pool Resource Game.
    
    The strategy prioritizes long-term pool sustainability. It cooperates (C) by default, 
    but shifts to defection (D) if the stock drops below a critical threshold (25% capacity) 
    or if opponent cooperation in recent history is insufficient. It includes a 
    forgiveness mechanism to revert to cooperation if the pool significantly recovers 
    (> 50% capacity) and utilizes a terminal phase check to maximize final payoffs.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        recent_opponents_cooperated = history.opponent_cooperators[-1]
        last_n = 3
        if history.round_number < last_n:
            relevant_history = history.opponent_cooperators
        else:
            relevant_history = history.opponent_cooperators[-last_n:]
        avg_cooperation_rate = np.mean(relevant_history) / (self.n_players - 1)
        if history.round_number >= self.n_rounds - 2:
            if current_stock <= 0.1 * self.capacity:
                return Action.D
        is_cooperation_phase_healthy = current_stock > 0.25 * self.capacity
        is_history_sufficient = avg_cooperation_rate >= 0.5
        if not is_cooperation_phase_healthy or not is_history_sufficient:
            if current_stock > 0.5 * self.capacity:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_123(BaseStrategy):
    """
    Tit-for-Tat with Threshold Stock Preservation.
    
    Cooperates in the first round. In subsequent rounds, it monitors stock levels and 
    collective cooperation history. 
    
    Core logic:
    - If stock < capacity/n: Prioritize conservation unless no one cooperated previously (defect to extract before collapse).
    - If stock >= capacity/n: Tit-for-tat logic based on majority cooperation (>= n/2).
    - Last round exception: Always defect (if stock > 0) to maximize final payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_total = game_description.n_players
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.total_rounds - 1:
            if current_stock > 0:
                return Action.D
            return Action.C
        opponents_cooperated_last_round = history.opponent_cooperators[-1]
        i_cooperated_last = int(history.my_actions[-1])
        total_cooperated_last = opponents_cooperated_last_round + i_cooperated_last
        if current_stock < self.capacity / self.n_total:
            if total_cooperated_last == 0:
                return Action.D
            return Action.C
        if total_cooperated_last >= self.n_total / 2:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_124(BaseStrategy):
    """
    A conditional tit-for-tat strategy for the Common Pool Resource Game.
    Focuses on sustainability by cooperating when resources are stable and 
    majority cooperation exists, while defecting to secure utility when
    the stock is critically depleted or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < capacity / n:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_cooperators = history.opponent_cooperators[-1]
        total_cooperators_last_round = prev_opp_cooperators + (1 if prev_my_action else 0)
        if total_cooperators_last_round >= n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_125(BaseStrategy):
    """
    A Tit-for-Tat with Resource Thresholding strategy.
    
    This strategy prioritizes initial cooperation, monitors stock levels, and retaliates
    against systemic defection. It acts as a stabilizer by forcing cooperation (Action.C)
    when the resource pool is critically low (below 2n), regardless of past behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_opponents = self.n - 1
        prev_cooperators = history.opponent_cooperators[-1]
        prev_defectors = n_opponents - prev_cooperators
        is_final_round = history.round_number == self.r - 1
        if is_final_round:
            if current_stock > self.capacity * 0.5:
                return Action.C
            else:
                return Action.D
        if current_stock < 2 * self.n:
            return Action.C
        if current_stock >= 0.9 * self.capacity:
            return Action.C
        if prev_defectors > self.n / 2.0:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_126(BaseStrategy):
    """
    Tit-for-Tat with Resource-Aware Forgiveness.
    
    This strategy aims for sustainable resource management. It uses:
    1. A 'Benevolence Threshold' to prevent system collapse when stock is low.
    2. A stochastic punishment mechanism proportional to the number of defectors in the previous round.
    3. A greedy last-round heuristic to maximize final payoff if the stock permits.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        round_number = history.round_number + 1
        if current_stock < capacity / n:
            return Action.C
        if round_number == total_rounds:
            if current_stock > capacity / 2:
                return Action.D
            else:
                return Action.C
        if round_number == 1:
            return Action.C
        last_my_action = history.my_actions[-1]
        k = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        if k == n:
            return Action.C
        else:
            punishment_probability = (n - k) / n
            if random.random() < punishment_probability:
                return Action.D
            else:
                return Action.C

class Strategy_BENEVOLENT_127(BaseStrategy):
    """
    Implements Adaptive Sustainable Tit-for-Tat:
    - Round 1: Cooperate.
    - Last Round: Defect if stock > 0, else Cooperate.
    - Emergency: Cooperate if current_stock < capacity / n.
    - Tit-for-Tat with Forgiveness: If previous round had defectors (N_C < n), 
      Defect only if current_stock > capacity / 2 (healthy), else Cooperate (for recovery).
    - Equilibrium: Cooperate if all previous players cooperated.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        last_round_idx = self.game_description.n_rounds - 1
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round_idx == last_round_idx:
            if current_stock > 1e-09:
                return Action.D
            else:
                return Action.C
        if current_round_idx == 0:
            return Action.C
        if current_stock < capacity / n:
            return Action.C
        last_round_my_action = history.my_actions[-1]
        my_contribution_to_coop = 1 if last_round_my_action else 0
        n_cooperators_prev = history.opponent_cooperators[-1] + my_contribution_to_coop
        if n_cooperators_prev < n:
            if current_stock > capacity / 2:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_BENEVOLENT_128(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Capacity Awareness.
    
    This strategy prioritizes sustainability. It cooperates if the environment is healthy 
    (forgiveness) or if the cooperative baseline in the group is strong enough 
    (N_c >= n/2). It defects only when the resource is being depleted by a 
    majority of defectors, unless it can trigger a reset via high stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == self.r - 1:
            return Action.C
        if current_stock < 1e-06:
            return Action.C
        if current_stock > 0.5 * self.capacity:
            return Action.C
        last_my_action = history.my_actions[-1]
        n_c = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        if n_c >= self.n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_33(BaseStrategy):
    """
    A strategy that maintains cooperation as long as the aggregate cooperation
    of opponents in the previous round meets a critical threshold τ = (n-1)/n.
    Defects on the last round and when resources fall below 10% of initial capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.initial_stock = float(self.capacity)
        self.threshold = (self.n - 1) / self.n

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.initial_stock * 0.1:
            return Action.D
        num_opponents = self.n - 1
        opponents_cooperated = history.opponent_cooperators[-1]
        rho = opponents_cooperated / num_opponents
        if rho >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_34(BaseStrategy):
    """
    Implements the 'Threshold-Based Reciprocal Exploitation' strategy.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Round r: Always Defect (D).
    - Rounds 2 to r-1:
        - If all opponents cooperated in the last round (C_obs == n-1): Cooperate (C).
        - If any defection occurred:
            - If stock is low (< capacity/2): Defect (D).
            - Else: Defect (D).
        - Revert logic: The prompt mentions reverting if C_obs returns to n-1 for two consecutive rounds 
          while S > capacity/4.
    
    This implementation tracks consecutive periods of full cooperation to manage transitions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_perfect_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round_idx = history.round_number
        if current_round_idx == r - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        last_c_obs = history.opponent_cooperators[-1]
        is_perfect = last_c_obs == n - 1
        if is_perfect:
            self.consecutive_perfect_rounds += 1
        else:
            self.consecutive_perfect_rounds = 0
        if current_stock < 1e-06:
            return Action.D
        if is_perfect:
            if self.consecutive_perfect_rounds >= 2 and current_stock > capacity / 4:
                return Action.C
            elif self.consecutive_perfect_rounds == 1:
                return Action.C
            else:
                return Action.C
        else:
            return Action.D

class Strategy_SELFISH_35(BaseStrategy):
    """
    Threshold-Based Tit-for-Tat with Depletion Awareness.
    Prioritizes sustainability by maintaining stock near capacity/2, 
    using an adaptive threshold to respond to opponent cooperation levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.threshold_coop = self.n / 2.0
        self.consecutive_opponent_defections = 0
        self.penalty_rounds_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_opponents = self.n - 1
        previous_cooperators = history.opponent_cooperators[-1]
        t = history.round_number
        rounds_remaining = self.total_rounds - t
        if t > 0:
            if previous_cooperators == 0:
                self.consecutive_opponent_defections += 1
            else:
                self.consecutive_opponent_defections = 0
            pass
        if current_stock <= 0:
            return Action.D
        if self.consecutive_opponent_defections >= n_opponents:
            self.penalty_rounds_remaining = 2
            self.consecutive_opponent_defections = 0
        if self.penalty_rounds_remaining > 0:
            self.penalty_rounds_remaining -= 1
            return Action.D
        if current_stock < self.capacity / 4.0:
            return Action.D
        if rounds_remaining < 3:
            return Action.D
        if current_stock > 0.9 * self.capacity:
            return Action.D
        if previous_cooperators >= self.threshold_coop:
            return Action.C
        else:
            self.threshold_coop = min(float(self.n - 1), self.threshold_coop + 0.1)
            return Action.D

class Strategy_SELFISH_36(BaseStrategy):
    """
    Conditional strategy based on the 'Tit-for-Tat' principle, tailored for common pool resource management.
    The strategy prioritizes stock sustainability when levels are low and exploitative efficiency
    when levels are high, while respecting the end-game horizon.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_threshold = math.ceil(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if t > self.r - math.ceil(self.n / 2):
            return Action.D
        if history.round_number == 0:
            return Action.C
        k_prev = int(history.opponent_cooperators[-1])
        if current_stock < 0.5 * self.capacity:
            if k_prev >= self.n_threshold:
                return Action.C
            else:
                return Action.D
        elif k_prev >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_37(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy for the Common Pool Resource Game.
    Maintains cooperation while the stock is healthy and opponents cooperate,
    uses punishment for defectors, but switches to defection if the stock
    is critically low or if repeated defection persists.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.persistent_defection_count = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        opponents_count = self.n - 1
        cooperating_opponents = history.opponent_cooperators[-1]
        num_defecting_opponents = opponents_count - cooperating_opponents
        if num_defecting_opponents > 0:
            self.persistent_defection_count += 1
        else:
            self.persistent_defection_count = 0
        if self.persistent_defection_count >= 2:
            return Action.D
        if num_defecting_opponents == 0:
            return Action.C
        else:
            if history.my_actions[-1] == Action.D:
                return Action.C
            return Action.D

class Strategy_SELFISH_38(BaseStrategy):
    """
    Implements the Conditional Sustainability Maximization (CSM) strategy.
    Balances extraction and replenishment based on opponent cooperation,
    stock depletion, and game phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        current_r = history.round_number
        capacity = self.game_description.capacity
        if current_r == r_total - 1:
            return Action.D
        if current_stock < capacity * 0.2:
            return Action.D
        if current_r == 0:
            return Action.C
        coop_threshold = n / 2.0
        if current_r >= 3:
            last_round_opponents = float(history.opponent_cooperators[-1])
            trend_avg = np.mean(history.opponent_cooperators[-3:])
            if last_round_opponents < trend_avg:
                coop_threshold = n * 0.75
        my_last_action = history.my_actions[-1]
        my_last_val = 1 if my_last_action else 0
        k_prev = history.opponent_cooperators[-1]
        total_coop = k_prev + my_last_val
        if total_coop >= coop_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_39(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource Game.
    It cooperates when the resource is healthy and opponents cooperate,
    but switches to punitive defection if opponents defect or if the resource
    reaches critical exhaustion or the terminal phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_rounds_remaining = 0
        self.consecutive_cooperation_count = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if r - t <= 2:
            return Action.D
        if current_stock <= 0.5 * capacity:
            self.punishment_rounds_remaining = 0
            self.consecutive_cooperation_count = 0
            return Action.D
        if t == 0:
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        n_opponents = n - 1
        all_opponents_cooperated = prev_k == n_opponents
        if all_opponents_cooperated:
            self.consecutive_cooperation_count += 1
            if self.consecutive_cooperation_count >= 2:
                self.punishment_rounds_remaining = 0
        else:
            self.consecutive_cooperation_count = 0
            if prev_k < n_opponents:
                self.punishment_rounds_remaining = min(3, r - t)
        if self.punishment_rounds_remaining > 0:
            self.punishment_rounds_remaining -= 1
            return Action.D
        if prev_k < n_opponents:
            self.punishment_rounds_remaining = min(3, r - t) - 1
            return Action.D
        return Action.C

class Strategy_SELFISH_40(BaseStrategy):
    """
    A strategy that maximizes long-term yield by defecting when the stock is robust
    (>= 0.6 * capacity) or in the last round, and cooperating when the stock is low 
    (< 0.6 * capacity) provided that the majority of opponents are also cooperating.
    It permanently switches to defection if it detects that the group consensus 
    favors depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.threshold = 0.6 * self.capacity
        self.abandoned_resource = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        n_opponents = self.n_players - 1
        if current_round_idx == 0:
            return Action.D
        if current_round_idx == self.n_rounds - 1:
            return Action.D
        if not self.abandoned_resource and current_round_idx > 0:
            opponents_cooperated_last_round = history.opponent_cooperators[-1]
            if opponents_cooperated_last_round < n_opponents * 0.5:
                self.abandoned_resource = True
        if self.abandoned_resource:
            return Action.D
        if current_stock >= self.threshold:
            return Action.D
        return Action.C

class Strategy_SELFISH_41(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Threshold strategy.
    
    This strategy attempts to maintain long-term resource viability by cooperating
    based on a dynamic trust score and current resource health. It defects in the 
    final round or if the stock becomes critically depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_score = 0.5
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < 0.1 * self.capacity:
            return Action.D
        prev_C_count = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        n_opponents = self.n - 1
        if n_opponents == 0:
            cooperation_ratio = 1.0 if prev_C_count > 0 else 0.0
        else:
            cooperation_ratio = prev_C_count / n_opponents
        is_healthy = current_stock >= 0.5 * self.capacity
        should_cooperate = cooperation_ratio >= self.trust_score and is_healthy
        action = Action.C if should_cooperate else Action.D
        if prev_my_action == Action.C:
            if cooperation_ratio > self.trust_score:
                self.trust_score = min(self.trust_score + 0.05, 0.9)
            elif cooperation_ratio < self.trust_score:
                self.trust_score = max(self.trust_score - 0.1, 0.1)
        else:
            self.trust_score = 0.5
        return action

class Strategy_SELFISH_42(BaseStrategy):
    """
    Conditional Resource Maximization Strategy:
    - Round 1: Cooperate.
    - Final Round: Always Defect.
    - If S < S_crit: Defect (extraction prioritized over sustainability).
    - Otherwise: If previous round resulted in stock growth, Cooperate.
    - Otherwise (net loss): Cooperate only if a majority of opponents cooperated.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)
        self.S_crit = self.capacity / (2 * self.n)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_stock < self.S_crit:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_opp_c = int(history.opponent_cooperators[-1])
        my_last_action = int(history.my_actions[-1])
        prev_total_c = prev_opp_c + my_last_action
        prev_total_d = self.n - prev_total_c
        last_payoff = float(history.my_payoffs[-1])
        if my_last_action == 1:
            s_prev = last_payoff * 2 * self.n
        else:
            s_prev = last_payoff * self.n
        total_consumption = prev_total_c * (s_prev / (2 * self.n)) + prev_total_d * (s_prev / self.n)
        stock_after = s_prev - total_consumption
        growth = 2 * stock_after * (1 - stock_after / self.capacity)
        new_stock_expected = min(stock_after + growth, self.capacity)
        if new_stock_expected >= s_prev:
            return Action.C
        elif prev_opp_c >= self.n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_43(BaseStrategy):
    """
    A strategy that maintains cooperation while the common pool resource is healthy 
    (> 50% capacity) and the aggregate behavior is cooperative. It switches to 
    defection if the resource is critically low or if the group behavior becomes 
    unsustainable. It defaults to defection in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            if current_stock <= self.threshold:
                return Action.D
            return Action.C
        my_last_action = history.my_actions[-1]
        num_cooperators = (1 if my_last_action else 0) + history.opponent_cooperators[-1]
        num_defectors = self.n - num_cooperators
        if current_stock <= self.threshold or num_defectors >= self.n / 2:
            return Action.D
        return Action.C

class Strategy_SELFISH_44(BaseStrategy):
    """
    Implements a conditional trigger strategy based on previous round cooperation.
    Maintains a dynamic cooperation sensitivity parameter (phi) that increases
    to 1.0 (strict) if the strategy defects, forcing opponents to demonstrate
    re-established trust. Logic prioritizes extracting remaining value if the
    pool falls below a critical threshold or if it is the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.phi = 0.75
        self.s_sust = 0.5 * self.capacity
        self.s_crit = 0.2 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == self.r - 1:
            return Action.D
        if current_stock < self.s_crit:
            return Action.D
        if t == 0:
            if current_stock >= self.s_sust:
                return Action.C
            else:
                return Action.D
        k_prev = history.opponent_cooperators[-1]
        my_action_prev = history.my_actions[-1]
        if my_action_prev == Action.D:
            self.phi = 1.0
        elif k_prev == self.n - 1:
            self.phi = 0.75
        r_threshold = math.ceil((self.n - 1) * self.phi)
        if k_prev >= r_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_45(BaseStrategy):
    """
    Trigger-Based Sustainable Extraction:
    - Maintains cooperation to preserve capacity while the stock is healthy.
    - Uses a trigger mechanism based on the aggregate behavior of opponents to decide
      whether to cooperate or defect.
    - Exploits stock depletion if thresholds are breached, and maximizes final-round
      payoff via defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        c_agg = prev_opp_coop + (1 if my_prev_action else 0)
        if current_stock < self.capacity / self.n:
            return Action.D
        is_cooperative_majority = c_agg >= self.n / 2
        i_was_defecting = not my_prev_action
        if current_stock < self.capacity / 4 and i_was_defecting:
            if is_cooperative_majority:
                return Action.C
            else:
                return Action.D
        if is_cooperative_majority:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_46(BaseStrategy):
    """
    A sophisticated Common Pool Resource strategy that balances cooperative
    long-term sustainability with defensive defection during resource decline.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        if current_stock < self.capacity * 0.1:
            return Action.D
        if current_stock > self.capacity * 0.9:
            return Action.C
        if current_round > self.r - 4:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        if self.n_opponents > 0:
            P = k_prev / self.n_opponents
        else:
            P = 1.0
        group_is_cooperative = P > 0.5
        if current_stock <= self.capacity * 0.25:
            if current_stock < self.capacity * 0.15:
                return Action.D
        if group_is_cooperative:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_47(BaseStrategy):
    """
    A Tit-for-Tat variant strategy with a reputation system and dynamic thresholds 
    based on resource sustainability (Common Pool Resource Game).
    
    Strategy Logic:
    - Round 1: Always Cooperate (C).
    - Final Round: Always Defect (D).
    - Rounds 2 to r-1:
        - If stock > 80% capacity: Always Cooperate (C) to ensure regeneration.
        - If reputation <= -3: Always Defect (D) (environment is hostile).
        - If current stock < 25% capacity: Force Defect (D) to maximize extraction.
        - Otherwise:
            - Calculate average cooperation (k / (n-1)).
            - If >= 0.5: Cooperate (C).
            - If < 0.5: Defect (D).
            - If exactly 0.5 (indifference): Maintain previous action.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 0
        self.prev_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            self.prev_action = Action.C
            return Action.C
        k = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if k > n_opponents / 2:
            self.reputation += 1
        elif k < n_opponents / 2:
            self.reputation -= 1
        action_to_take = Action.C
        if current_stock > self.game_description.capacity * 0.8:
            action_to_take = Action.C
        elif self.reputation <= -3:
            action_to_take = Action.D
        elif current_stock < self.game_description.capacity / 4:
            action_to_take = Action.D
        elif n_opponents == 0:
            action_to_take = Action.C
        else:
            avg_coop = k / n_opponents
            if avg_coop > 0.5:
                action_to_take = Action.C
            elif avg_coop < 0.5:
                action_to_take = Action.D
            else:
                action_to_take = self.prev_action
        self.prev_action = action_to_take
        return action_to_take

class Strategy_SELFISH_48(BaseStrategy):
    """
    Implements the 'Conditional Sustainable Harvesting' strategy for the Common Pool Resource Game.
    This strategy balances cooperation for long-term sustainability with defecting when the pool is at risk
    or when others are exploiting the resource, while ensuring optimal final-round extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_recovering = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == r - 1:
            return Action.D
        if t == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        c_prev = (1 if my_last_action else 0) + history.opponent_cooperators[-1]
        last_round_idx = t - 1
        if current_stock < 0.2 * capacity:
            self.is_recovering = True
            return Action.D
        if self.is_recovering:
            if current_stock > 0.6 * capacity:
                self.is_recovering = False
            else:
                return Action.D
        if current_stock < 0.4 * capacity:
            self.is_recovering = True
            return Action.D
        if c_prev < n / 2:
            return Action.D
        return Action.C

class Strategy_SELFISH_49(BaseStrategy):
    """
    A Tit-for-Tat variant strategy for the Common Pool Resource game.
    It plays cooperatively in the first round, defects in the final round, 
    and uses a stock-dependent threshold for cooperation based on 
    the previous round's opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < capacity / n:
            return Action.D
        threshold = 0.4 if current_stock > 0.9 * capacity else 0.6
        prev_opp_coop_count = history.opponent_cooperators[-1]
        if n > 1:
            p_avg = prev_opp_coop_count / (n - 1)
        else:
            p_avg = 0.0
        if p_avg >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_50(BaseStrategy):
    """
    A conditional strategy for the Common Pool Resource game that implements a
    rolling threshold approach: calibrates in round 1, monitors aggregate cooperation
    levels relative to a dynamic threshold, and preemptively defects if the resource
    pool is collapsing or in the terminal round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        critical_threshold = self.capacity / (2.0 * self.n)
        if current_stock < critical_threshold:
            return Action.D
        if current_round == 0:
            return Action.C
        opp_coop_count = int(history.opponent_cooperators[-1])
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_coop_count = opp_coop_count + my_last_action_val
        cooperation_rate = total_coop_count / self.n
        threshold = 0.5 + 1.0 / self.n
        if current_stock >= 0.9 * self.capacity:
            return Action.C
        if cooperation_rate >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_51(BaseStrategy):
    """
    A tit-for-tat variant for Common Pool Resource games that balances long-term stock 
    sustainability with aggressive exploitation when resources permit.
    
    Logic:
    - Always Cooperates (C) in the first round.
    - Always Cooperates (C) if current stock <= 25% of capacity (Survival mode).
    - If stock > 25% of capacity:
        - If stock > 75% of capacity:
            - If last round, Defect (D).
            - If not last round, Cooperate (C) only if everyone cooperated last round, else Defect (D).
        - If 25% < stock <= 75% of capacity:
            - Cooperate (C) if all or nearly all (>= n-1) opponents cooperated last round, else Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        if current_stock <= self.capacity * 0.25:
            return Action.C
        prev_opp_cooperated = history.opponent_cooperators[-1]
        if current_round == self.total_rounds:
            if current_stock > self.capacity * 0.75:
                return Action.D
            elif prev_opp_cooperated == self.n - 1:
                return Action.D
            else:
                return Action.C
        if current_stock > self.capacity * 0.75:
            if prev_opp_cooperated == self.n - 1:
                return Action.C
            else:
                return Action.D
        elif prev_opp_cooperated == self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_52(BaseStrategy):
    """
    Sustainable Maximization with Conditional Retaliation:
    - Prioritizes sustainability by cooperating when the stock recovery is robust.
    - Switches to defection if total cooperation is not met and stock recovery
      falls below 50% of capacity.
    - Switches to aggressive defection in the final 3 rounds to maximize immediate yield.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        rounds_remaining = total_rounds - round_idx
        if rounds_remaining <= 3:
            return Action.D
        if round_idx == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opponents_cooperated = history.opponent_cooperators[-1]
        prev_round_cooperators = opponents_cooperated + (1 if my_prev_action else 0)
        if prev_round_cooperators == n:
            return Action.C
        total_consumption_if_all_C = n * (current_stock / (2 * n))
        stock_remaining = current_stock - total_consumption_if_all_C
        growth = 2 * stock_remaining * (1 - stock_remaining / capacity)
        projected_next_stock = min(stock_remaining + growth, capacity)
        if projected_next_stock >= 0.5 * capacity:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_53(BaseStrategy):
    """
    A trigger-based Tit-for-Tat variant designed to maintain stock at capacity.
    - Cooperates initially.
    - Subsequent rounds: Cooperates if stock is healthy and a threshold of opponents (n/2 + 1)
      cooperated in the previous round.
    - Defects immediately if stock drops below capacity, if cooperation threshold is not met,
      or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.coop_threshold = math.ceil(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_coop = history.my_actions[-1]
        total_prev_coop = prev_opp_coop + (1 if prev_my_coop else 0)
        is_stable = current_stock >= self.capacity * 0.99 and total_prev_coop >= self.coop_threshold + 1
        if is_stable:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_54(BaseStrategy):
    """
    Implements Conditional Depletion Optimization:
    - Round 1: Always Cooperate.
    - Last Round: Always Defect.
    - Stock Threshold (S_t < capacity/n): Always Defect.
    - Sufficient Stock (S_t >= capacity/n):
        - If previous round saw all others cooperate (k_t == n-1), Cooperate.
        - Otherwise, Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.capacity = self.game_description.capacity
        self.total_rounds = self.game_description.n_rounds
        self.threshold = self.capacity / self.n

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if current_stock < self.threshold:
            return Action.D
        if current_stock <= 0:
            return Action.D
        k_t = history.opponent_cooperators[-1]
        if k_t == self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_55(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Sustainability Threshold.
    
    This strategy aims to maximize cumulative payoff by maintaining a 'golden stock' level.
    It cooperates to build/maintain stock, punishes defection by defecting,
    and prioritizes long-term resource survival over punishment if the stock 
    reaches critical levels. It always defects in the final round to maximize 
    the terminal payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.target_stock = 0.5 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if round_idx == total_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        threshold = self.game_description.capacity / (10 * self.game_description.n_players)
        if current_stock < threshold:
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if prev_k < n_opponents:
            return Action.D
        return Action.C

class Strategy_SELFISH_56(BaseStrategy):
    """
    Implements an Adaptive Exploitation strategy for the Common Pool Resource Game.
    The strategy balances resource sustainability through conditional cooperation,
    reverts to extraction when the resource pool is terminal, and utilizes
    tit-for-tat aggregate matching for long-term survival.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.retest_counter = 0
        self.previous_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.previous_stock = current_stock
            return Action.C
        round_idx = history.round_number
        last_k = int(history.opponent_cooperators[-1])
        my_last_action = history.my_actions[-1]
        total_cooperators = last_k + (1 if my_last_action else 0)
        if current_stock <= 0.1 * self.capacity:
            self.previous_stock = current_stock
            return Action.D
        if total_cooperators == self.n:
            self.retest_counter = 2
        if self.retest_counter > 0:
            self.retest_counter -= 1
            self.previous_stock = current_stock
            return Action.C
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        is_declining = current_stock < self.previous_stock
        self.previous_stock = current_stock
        if is_declining:
            if total_cooperators >= self.n / 2:
                return Action.C
            else:
                return Action.D
        else:
            prob_c = total_cooperators / self.n
            if random.random() < prob_c:
                return Action.C
            else:
                return Action.D

class Strategy_SELFISH_57(BaseStrategy):
    """
    A strategy that maintains a reputation score for opponents, projecting future
    stock levels to decide between Cooperation and Defection. It favors Cooperation
    when resource stability is expected and utilizes Tit-for-Tat behavior when n=2.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == 0:
            self.reputation = 1.0
            return Action.C
        obs_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        obs_rate = obs_cooperators / n_opponents if n_opponents > 0 else 0.0
        self.reputation = 0.7 * self.reputation + 0.3 * obs_rate
        if n == 2:
            return Action.C if obs_cooperators == 1 else Action.D
        if t == r - 1:
            return Action.D
        k = self.reputation * n
        s_remaining = current_stock * (k / (2 * n))
        if capacity > 0:
            growth = 2 * s_remaining * (1 - s_remaining / capacity)
        else:
            growth = 0
        s_next = min(s_remaining + growth, capacity)
        if current_stock < capacity / (2 * n) or s_next < 1:
            return Action.D
        threshold = 1.0 - 1.0 / (n - 1) if n > 1 else 0.0
        if self.reputation >= threshold and s_next >= 0.85 * capacity:
            return Action.C
        return Action.D

class Strategy_SELFISH_58(BaseStrategy):
    """
    A trigger strategy that cooperates as long as aggregate consumption does not exceed 
    half the current stock. Once a defection is detected, it switches to perpetual defection.
    Always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_punishment_triggered = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if not self.is_punishment_triggered:
            n_opponents = self.game_description.n_players - 1
            opp_coop = history.opponent_cooperators[-1]
            my_coop = 1 if history.my_actions[-1] else 0
            total_cooperators = opp_coop + my_coop
            total_defectors = self.game_description.n_players - total_cooperators
            if total_cooperators < self.game_description.n_players:
                self.is_punishment_triggered = True
                return Action.D
            return Action.C
        return Action.D

class Strategy_SELFISH_59(BaseStrategy):
    """
    A conditional tit-for-tat strategy with a threshold-based defection trigger,
    balancing resource sustainability with long-term utility maximization.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock / capacity < 0.5:
            return Action.C
        if current_stock / capacity > 0.75:
            return Action.D
        last_round_cooperators = int(history.opponent_cooperators[-1])
        my_prev_action = history.my_actions[-1]
        total_cooperators_last_round = last_round_cooperators + (1 if my_prev_action else 0)
        if total_cooperators_last_round == n:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_60(BaseStrategy):
    """
    Threshold-based Reciprocity Strategy.
    Plays C in the first round and if stock is healthy and partners reciprocate.
    Plays D if the resource is endangered (below S_safe), if partners defect, 
    or in the final round to maximize terminal utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        self.s_safe = capacity * (n / (2 * n - 1))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock == 0:
            return Action.D
        if current_stock < self.s_safe:
            return Action.D
        k = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        threshold = n_opponents / 2.0
        if k >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_61(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Depletion Thresholds:
    - Round 1: Cooperate (C)
    - Final Round (t=r): Defect (D)
    - Sustainability Check: If current stock < capacity/4, Cooperate (C).
    - Reciprocity: If previous round cooperation count >= n/2, Cooperate (C), else Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        is_last_round = current_round_index == self.r - 1
        if is_last_round:
            return Action.D
        if current_round_index == 0:
            return Action.C
        if current_stock < self.capacity / 4.0:
            return Action.C
        my_previous_action = 1 if history.my_actions[-1] else 0
        k_t = history.opponent_cooperators[-1] + my_previous_action
        if k_t >= self.n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_62(BaseStrategy):
    """
    A Reputation-based strategy for the Common Pool Resource game.
    Maintains a reputation score of opponent cooperation, switching to defection
    if reputation falls below a threshold, the stock is critically low, 
    or the final round is reached.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 0.5
        self.cooperation_threshold = 0.75
        self.panic_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if current_stock < 0.1 * capacity and t < r - 1:
            self.panic_mode = True
        if self.panic_mode:
            return Action.D
        if t == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_cooperators = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        cooperation_rate_prev = prev_cooperators / n
        self.reputation = 0.7 * self.reputation + 0.3 * cooperation_rate_prev
        if t == r - 1:
            return Action.D
        if current_stock < capacity / n:
            return Action.D
        if self.reputation >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_63(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Depletion Thresholds.
    Stabilizes resource pools by cooperating when stock is high and cooperative
    intent is sufficient, forces regeneration when stock is critically low,
    and defects in the final round to maximize utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1
        self.s_crit = game_description.capacity / 2.0
        self.k_threshold = math.ceil(self.n_opponents * 0.6)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.s_crit:
            return Action.C
        prev_opp_C_count = int(history.opponent_cooperators[-1])
        if prev_opp_C_count >= self.k_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_64(BaseStrategy):
    """
    Implements a resource-conscious strategy that prioritizes sustainability
    when stocks are low, but switches to aggressive defecting if the resource
    is healthy or opponents are acting aggressively. Includes mechanisms for
    recovery from depletion and responding to volatility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.cap = game_description.capacity
        self.target_stock = self.cap / 2
        self.in_recovery_mode = False
        self.last_k = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.last_k = 0
            return Action.C
        n_opponents = self.n - 1
        prev_cooperators = history.opponent_cooperators[-1]
        prev_k = n_opponents - prev_cooperators
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 0.05 * self.cap:
            self.in_recovery_mode = True
        if self.in_recovery_mode:
            if current_stock >= 0.2 * self.cap:
                self.in_recovery_mode = False
            else:
                self.last_k = prev_k
                return Action.C
        if current_stock < 0.15 * self.cap:
            self.last_k = prev_k
            return Action.C
        if abs(prev_k - self.last_k) > self.n / 2:
            self.last_k = prev_k
            return Action.D
        self.last_k = prev_k
        if prev_k > self.n / 2:
            return Action.D
        elif current_stock >= self.target_stock:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_65(BaseStrategy):
    """
    State-dependent opportunistic strategy for the Common Pool Resource Game.
    
    Logic:
    1. Round 1: Cooperate (C).
    2. Final Round: Defect (D).
    3. Intermediate Rounds:
       - If stock < capacity / 2: Cooperate (C) to allow regeneration.
       - If stock >= capacity / 2:
         - If all opponents cooperated last round: Cooperate (C).
         - If any opponent defected last round: Defect (D) to capture value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        is_final_round = current_round_idx == self.total_rounds - 1
        if is_final_round:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < self.capacity / 2.0:
            return Action.C
        n_opponents = self.n_players - 1
        opponents_cooperated = history.opponent_cooperators[-1]
        if opponents_cooperated < n_opponents:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_66(BaseStrategy):
    """
    A conditional cooperation strategy for the Common Pool Resource game.
    Starts with Cooperation. In subsequent rounds:
    1. If the resource is depleted below capacity/n, defects to extract remaining value.
    2. If any other player defected in the previous round, defects.
    3. If all other players cooperated, cooperates.
    4. In the final round, always defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / self.n:
            return Action.D
        num_opponents = self.n - 1
        num_cooperators = history.opponent_cooperators[-1]
        num_defectors = num_opponents - num_cooperators
        if num_defectors >= 1:
            return Action.D
        return Action.C

class Strategy_SELFISH_67(BaseStrategy):
    """
    Adaptive Resource Management (ARM):
    A strategy that balances extraction with preservation. 
    1. Always cooperates in the first round.
    2. Always defects in the final round.
    3. In intermediate rounds, defects if the current stock is below half capacity 
       OR if the number of cooperators in the previous round was 50% or fewer of the total players.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        my_cooperation_count = 1 if last_my_action else 0
        total_cooperators = history.opponent_cooperators[-1] + my_cooperation_count
        is_stock_low = current_stock < self.game_description.capacity * 0.5
        is_cooperation_insufficient = total_cooperators <= self.game_description.n_players * 0.5
        if is_stock_low or is_cooperation_insufficient:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_68(BaseStrategy):
    """
    Adaptive Threshold Tit-for-Tat:
    This strategy aims to maximize cumulative utility by enforcing a sustainable 
    stock equilibrium while using aggressive punishment for defectors. 
    It defaults to cooperation, punishes defections with a single-round defection, 
    and abandons cooperation if the stock levels hit critical depletion thresholds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_action_taken: Action | None = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        round_idx = history.round_number
        capacity = self.game_description.capacity
        if round_idx == r_total - 1:
            action = Action.D
            self.last_action_taken = action
            return action
        if round_idx == 0:
            action = Action.C
            self.last_action_taken = action
            return action
        my_prev_action_val = 1 if self.last_action_taken == Action.C else 0
        num_cooperators = history.opponent_cooperators[-1] + my_prev_action_val
        if current_stock < capacity / 4.0:
            action = Action.D
            self.last_action_taken = action
            return action
        if num_cooperators == n:
            action = Action.C
            self.last_action_taken = action
            return action
        if self.last_action_taken == Action.D:
            action = Action.C
            self.last_action_taken = action
            return action
        else:
            action = Action.D
            self.last_action_taken = action
            return action

class Strategy_SELFISH_69(BaseStrategy):
    """
    Implements a strategy that dynamically manages common pool resources
    based on observed cooperation rates and stock health. It defaults to
    cooperation but shifts to defection as resources become scarce or
    as trust in the pool evaporates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.target_cooperation_rate = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == r_total - 1:
            return Action.D
        if t == 0:
            return Action.C
        prev_round = t - 1
        my_prev_action = history.my_actions[prev_round]
        k = history.opponent_cooperators[prev_round] + (1 if my_prev_action else 0)
        if current_stock <= 1e-09:
            return Action.D
        if current_stock > capacity * 0.9:
            return Action.C
        if current_stock < capacity * 0.2:
            return Action.D
        observed_rate = k / n
        if observed_rate < self.target_cooperation_rate:
            self.target_cooperation_rate = observed_rate
        growth = 2 * current_stock * (1 - current_stock / capacity)
        if current_stock + growth < current_stock:
            return Action.D
        if self.target_cooperation_rate > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_70(BaseStrategy):
    """
    A reciprocity-based strategy for the Common Pool Resource game.
    Starts by cooperating, then adjusts based on the previous round's aggregate cooperation rate.
    Defects in the final round and if the stock falls below 20% of capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        t = history.round_number + 1
        if t == self.r:
            return Action.D
        if current_stock < 0.2 * self.capacity:
            return Action.D
        opponents_who_cooperated = int(history.opponent_cooperators[-1])
        if self.n <= 1:
            opponents_cooperation_rate = 1.0
        else:
            opponents_cooperation_rate = opponents_who_cooperated / (self.n - 1)
        if opponents_cooperation_rate >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_71(BaseStrategy):
    """
    A strategy that maintains a dynamic trust level based on observed opponent cooperation,
    adapting actions based on resource stock thresholds and the game phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_level = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_stock <= 0:
            self.trust_level = 0.0
        if history.round_number == 0:
            return Action.C
        n_opponents = n - 1
        if n_opponents > 0:
            o_c = history.opponent_cooperators[-1] / n_opponents
            if o_c >= 0.5:
                self.trust_level = min(1.0, self.trust_level + 0.1)
            else:
                self.trust_level = max(0.0, self.trust_level - 0.2)
        if history.round_number == r - 1:
            threshold = capacity / n
            if current_stock < threshold:
                return Action.D
            return Action.C
        if current_stock < 0.2 * capacity:
            return Action.D
        if random.random() < self.trust_level:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_72(BaseStrategy):
    """
    A strategy for the Common Pool Resource game that balances long-term stock sustainability 
    against reputation-based cooperation. It tracks a moving average of opponent cooperation 
    and adapts its behavior based on game state, stock levels, and historical opponent performance.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.reputation_score = 0.5
        self.alpha = 0.8
        self.moving_avg_coop = 0.0

    def _get_projected_stock(self, current_stock: float) -> float:
        s_remaining = current_stock - current_stock / 2.0
        growth = 2.0 * s_remaining * (1.0 - s_remaining / self.capacity)
        return min(s_remaining + growth, self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == self.r - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if t >= 3:
            all_defected_recently = True
            for i in range(1, 4):
                if history.opponent_cooperators[-i] > 0:
                    all_defected_recently = False
                    break
            if all_defected_recently:
                self.reputation_score = 0.9
        if t == 0:
            return Action.C
        last_k = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        coop_rate_last_round = last_k / n_opponents if n_opponents > 0 else 0.0
        if t == 1:
            self.moving_avg_coop = coop_rate_last_round
        else:
            self.moving_avg_coop = self.alpha * self.moving_avg_coop + (1 - self.alpha) * coop_rate_last_round
        k_ratio = last_k / self.n
        if k_ratio > self.reputation_score:
            self.reputation_score = min(0.8, self.reputation_score + 0.05)
        elif k_ratio < self.reputation_score:
            self.reputation_score = max(0.2, self.reputation_score - 0.05)
        projected_next_stock = self._get_projected_stock(current_stock)
        if projected_next_stock < 1.2 * self.n:
            return Action.D
        if self.moving_avg_coop >= self.reputation_score and current_stock > 0.5 * self.capacity:
            return Action.C
        return Action.D

class Strategy_SELFISH_73(BaseStrategy):
    """
    Conditional Sustainability-Maximizing Tit-for-Tat (CSM-TFT):
    Prioritizes cooperative equilibria when stock is healthy.
    Defects if the stock is critically low, the game is ending, 
    or the group fails to sustain the common resource.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.alpha = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            return Action.D
        if round_idx >= self.r - 3:
            if current_stock < self.capacity / self.n:
                return Action.D
        if current_stock < self.capacity / self.n:
            return Action.D
        n_opponents = self.n - 1
        threshold = math.ceil(n_opponents * self.alpha)
        last_round_cooperators = int(history.opponent_cooperators[-1])
        if last_round_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_74(BaseStrategy):
    """
    An adaptive Tit-for-Tat strategy for the Common Pool Resource game. 
    It balances cooperation thresholds based on stock sustainability history,
    prioritizes replenishment during emergencies, and defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.alpha = 0.75
        self.stock_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.stock_history.append(current_stock)
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if len(self.stock_history) >= 4:
            recent_stocks = self.stock_history[-4:-1]
            capacity = self.game_description.capacity
            stock_drop = (recent_stocks[0] - recent_stocks[-1]) / capacity
            if stock_drop > 0.2:
                self.alpha = min(0.9, self.alpha + 0.05)
            elif recent_stocks[-1] >= recent_stocks[0]:
                self.alpha = max(0.5, self.alpha - 0.05)
        if current_stock < self.game_description.capacity / 4:
            return Action.C
        prev_c_count = history.opponent_cooperators[-1]
        threshold = math.ceil(self.game_description.n_players * self.alpha)
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators = prev_c_count + my_prev_action
        if total_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_75(BaseStrategy):
    """
    A strategy that maintains a 'TrustLevel' to decide between cooperation and defection.
    It cooperates conditionally based on the stock level and the recent history of 
    cooperation from other players, with dynamic adjustment of trust.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_level = 1.0
        if self.game_description.n_players > 4:
            self.threshold = 0.7 * self.game_description.capacity
        else:
            self.threshold = 0.5 * self.game_description.capacity
        self.is_permanently_defected = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        critical_threshold = self.game_description.capacity / (2 * n)
        if current_stock < critical_threshold:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if self.is_permanently_defected:
            return Action.D
        if prev_cooperators < n - 1:
            self.is_permanently_defected = True
            self.trust_level = max(0.0, self.trust_level - 0.2)
            return Action.D
        if current_stock >= self.threshold:
            self.trust_level = min(1.0, self.trust_level + 0.1)
            return Action.C
        elif random.random() > self.trust_level:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_76(BaseStrategy):
    """
    A threshold-based strategy for the Common Pool Resource Game.
    Maintains stock near MSY by extracting conservatively unless the resource
    is at risk, in abundance, or in the terminal phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        last_action = history.my_actions[-1]
        last_payoff = history.my_payoffs[-1]
        if last_action == Action.C:
            s_prev = last_payoff * 2.0 * n
        else:
            s_prev = last_payoff * float(n)
        capacity = float(self.game_description.capacity)
        target_stock = capacity / 2.0
        min_threshold = capacity / 4.0
        if s_prev < min_threshold:
            return Action.D
        if s_prev > target_stock + 0.2 * capacity:
            return Action.D
        if current_stock < 0.8 * s_prev:
            return Action.D
        return Action.C

class Strategy_SELFISH_77(BaseStrategy):
    """
    A threshold-based conditional cooperation strategy for the Common Pool Resource game.
    Cooperates if stock is above 60% of capacity and recent opponent cooperation is high,
    otherwise defects. Defects in the last round and when the resource is exhausted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.threshold = self.capacity * 0.6
        self.coop_threshold = math.ceil(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_stock == 0:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.threshold:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        if k_prev >= self.coop_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_78(BaseStrategy):
    """
    Dynamic Threshold Reciprocity (DTR) Strategy.
    
    Logic:
    - Round 1: Cooperate.
    - Last Round: Defect.
    - Stock >= 0.75 * Capacity: Defect (Exploitation).
    - Stock < 0.25 * Capacity: Cooperate (Preservation).
    - Intermediate stock: Calculate previous defection ratio of opponents.
        - If > 0.5: Defect.
        - Otherwise: Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.total_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        if current_stock >= 0.75 * self.capacity:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        num_opponents = self.n - 1
        prev_round_cooperators = history.opponent_cooperators[-1]
        prev_round_defectors = num_opponents - prev_round_cooperators
        if num_opponents > 0:
            defectors_ratio = prev_round_defectors / num_opponents
        else:
            defectors_ratio = 0.0
        if defectors_ratio > 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_79(BaseStrategy):
    """
    Tit-for-Tat with Resource-Threshold Calibration.
    
    Operates on a conditional cooperation framework:
    1. First round: Always Cooperate (C).
    2. Final round: Always Defect (D).
    3. Intermediate rounds:
       - Retaliate if any opponent defected in the previous round.
       - Cooperate if previous round full cooperation AND stock > capacity/2.
       - Defect if previous round full cooperation BUT stock <= capacity/2 (Scarcity Response).
    4. Collapse handling: If stock is depleted (0), Defect (D) perpetually.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._n_opponents = self.game_description.n_players - 1
        self._threshold = self.game_description.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock <= 0:
            return Action.D
        last_cooperators = history.opponent_cooperators[-1]
        last_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = last_my_action + last_cooperators
        if total_cooperators_prev < self.game_description.n_players:
            return Action.D
        if current_stock <= self._threshold:
            return Action.D
        return Action.C

class Strategy_SELFISH_80(BaseStrategy):
    """
    A Trigger-Resilient Cooperation strategy.
    
    This strategy maintains a Reputation Score (RS) based on the history of 
    opponent defections. It cooperates if the reputation is stable and the 
    resource is healthy, but switches to defection if the resource is collapsing, 
    the game is ending, or the opponents have demonstrated sustained exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if t == 0:
            return Action.C
        if t == r - 1:
            return Action.D
        if current_stock < capacity / n:
            return Action.D
        rs = 1.0
        n_opponents = n - 1
        if n_opponents > 0:
            for i in range(t):
                num_cooperators = history.opponent_cooperators[i]
                num_defectors = n_opponents - num_cooperators
                dr = num_defectors / n_opponents
                if dr > 0.5:
                    rs -= 0.1
                else:
                    rs += 0.05
        rs = min(1.0, max(0.0, rs))
        if rs < 0.3:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_81(BaseStrategy):
    """
    Implements Adaptive Threshold Tit-for-Tat with Terminal Defection.
    
    Logic:
    - Rule 1: Always Defect on the final round.
    - Rule 2: Always Cooperate on the first round.
    - Rule 3: If sustainability index < 0.25, always Cooperate to preserve resources.
    - Rule 4: If sustainability >= 0.25, use Reciprocal Strategy based on the 
              previous round's cooperation ratio (threshold 0.5).
    - Edge Case: If stock is near 0, default to Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        total_rounds = self.game_description.n_rounds
        round_number = history.round_number
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if round_number == total_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.C
        if current_stock < 1e-09:
            return Action.D
        sustainability_index = current_stock / capacity
        if sustainability_index < 0.25:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        num_opponents = n - 1
        if num_opponents <= 0:
            return Action.C
        opponents_cooperating_ratio = last_round_cooperators / num_opponents
        if opponents_cooperating_ratio >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_82(BaseStrategy):
    """
    Implements a resource-conscious strategy for the Common Pool Resource Game.
    Maintains a target stock trajectory by estimating opponent cooperativeness
    via an exponentially weighted moving average (EWMA) of their past actions.
    Decisions rely on comparing expected consumption against the resource's 
    growth potential, while pivoting to aggressive extraction (Defect) if 
    the resource is doomed or if opponents consistently defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.lambda_rate = 0.2
        self.alpha = 0.5
        self.n_opponents = self.n - 1

    def _get_growth(self, stock: float) -> float:
        """Calculates regeneration potential: G(S) = 2 * S * (1 - S / capacity)."""
        if self.capacity <= 0:
            return 0.0
        return 2.0 * stock * (1.0 - stock / self.capacity)

    def _update_alpha(self, history: PlayerHistory):
        """Updates alpha based on the most recent round's observations."""
        if history.round_number > 0:
            last_opp_coop_count = history.opponent_cooperators[-1]
            prop_opp_coop = last_opp_coop_count / self.n_opponents if self.n_opponents > 0 else 0.0
            self.alpha = (1.0 - self.lambda_rate) * self.alpha + self.lambda_rate * prop_opp_coop

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        self._update_alpha(history)
        if self.alpha < 0.1:
            return Action.D
        my_c_consumption = current_stock / (2.0 * self.n)
        expected_opp_consumption_unit = self.alpha * (current_stock / (2.0 * self.n)) + (1.0 - self.alpha) * (current_stock / self.n)
        expected_total_consumption = my_c_consumption + self.n_opponents * expected_opp_consumption_unit
        growth = self._get_growth(current_stock)
        if expected_total_consumption < growth:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_83(BaseStrategy):
    """
    Conditional Tit-for-Tat with Greed-Triggered Thresholds:
    - Cooperates in round 1.
    - Defects if stock is low (< capacity/2), if it's the last 2 rounds, 
      if recent cooperation count is below threshold (n-1), or if history 
      indicates persistent non-cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_c = game_description.n_players - 1
        self.persistent_defect_limit = 3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_r = history.round_number
        if current_r >= self.game_description.n_rounds - 2:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if current_stock < self.game_description.capacity / 2:
            return Action.D
        if history.round_number >= self.persistent_defect_limit:
            recent_opponents = history.opponent_cooperators[-self.persistent_defect_limit:]
            if all((k < self.threshold_c for k in recent_opponents)):
                return Action.D
        k_prev = history.opponent_cooperators[-1]
        if k_prev < self.threshold_c:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_84(BaseStrategy):
    """
    Implements Dynamic Tit-for-Tat with Depletion Thresholding.
    
    Strategy:
    1. First round: Cooperate.
    2. Last round: Defect.
    3. Critical depletion (Stock < capacity / 4): Defect (prioritize extraction).
    4. Otherwise:
       - Reciprocity: If previous round's number of defectors >= n/2, Defect.
       - Otherwise: Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < capacity / 4.0:
            return Action.D
        my_prev_action = history.my_actions[-1]
        prev_opponents_cooperated = history.opponent_cooperators[-1]
        total_cooperators = (1 if my_prev_action else 0) + prev_opponents_cooperated
        total_defectors = n - total_cooperators
        if total_defectors >= n / 2.0:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_85(BaseStrategy):
    """
    Implements a sustainable common pool resource strategy:
    - Round 1: Cooperate.
    - Rounds 2 to r-1: 
        - If stock > capacity/2: Cooperate.
        - If stock <= capacity/2:
            - If previous round saw >= n/2 cooperators: Cooperate.
            - Else: Defect.
    - Exception: If stock < 0.1 * capacity: Always Defect (post-critical failure).
    - Final Round: Always Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.target_stock = self.capacity / 2.0
        self.critical_threshold = self.capacity * 0.1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_stock < self.critical_threshold:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        if current_stock > self.target_stock:
            return Action.C
        prev_opponents_cooperating = history.opponent_cooperators[-1]
        if prev_opponents_cooperating >= self.n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_86(BaseStrategy):
    """
    Tit-for-Tat with a Modified Trigger Mechanism.
    
    Logic:
    1. Round 1: Always Cooperate (C).
    2. Rounds 2 to r-1: 
       - Evaluate if stock is critically low (S <= capacity / (2n)). If so, Defect (D).
       - Check if previous round resulted in stock decrease (New Stock < Current Stock). 
         Note: We estimate this based on the number of cooperators (k).
         If all players played C, stock is maintained. If any D, stock decreases.
         So, if k < n_opponents (i.e., someone defected), we treat it as stock decline.
         If stock declined, play D.
       - Otherwise, calculate cooperation threshold Tc = (n-1)/n.
         If proportion of cooperating opponents (k / (n-1)) >= Tc, play C.
         Else, play D.
    3. Final Round: Always Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        critical_threshold = self.capacity / (2 * self.n)
        if current_stock <= critical_threshold:
            return Action.D
        previous_self_action = history.my_actions[-1]
        previous_k = history.opponent_cooperators[-1]
        anyone_defected_prev = not previous_self_action or previous_k < self.n_opponents
        if anyone_defected_prev:
            return Action.D
        tc = self.n_opponents / self.n
        if self.n_opponents == 0:
            prop_coop = 1.0
        else:
            prop_coop = previous_k / self.n_opponents
        if prop_coop >= tc:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_87(BaseStrategy):
    """
    A strategy that maintains a reputation score based on observed opponent cooperation,
    while adjusting behavior based on stock sustainability and opponent trends.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 1.0
        self.permanently_defect = False
        self.consecutive_defect_count = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t > 0:
            m = n - 1
            k = history.opponent_cooperators[-1]
            observed_cooperation_rate = k / m if m > 0 else 0.0
            self.reputation = self.reputation * 0.7 + observed_cooperation_rate * 0.3
            if k == 0:
                self.consecutive_defect_count += 1
            else:
                self.consecutive_defect_count = 0
            if self.consecutive_defect_count >= 3:
                self.permanently_defect = True
        else:
            self.reputation = 1.0
            self.permanently_defect = False
            self.consecutive_defect_count = 0
        if self.permanently_defect:
            return Action.D
        if current_stock < 1.0 * n:
            return Action.D
        if current_stock < capacity / 4:
            return Action.D
        if t == r_total - 1:
            return Action.D
        if self.reputation < 0.5:
            return Action.D
        return Action.C

class Strategy_SELFISH_88(BaseStrategy):
    """
    A strategy for the Common Pool Resource game.
    It initiates with cooperation, switches to defection if the stock becomes critically low (below capacity/2),
    responds to resource decline by monitoring the opponent's defection ratio (if > 0.5, defect),
    and always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.previous_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round_idx = history.round_number
        if current_round_idx == r - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < self.game_description.capacity / 2:
            return Action.D
        if current_stock >= self.previous_stock:
            return Action.C
        prev_opp_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents > 0:
            d_ratio = (n_opponents - prev_opp_cooperators) / n_opponents
            if d_ratio > 0.5:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C
        self.previous_stock = current_stock
        return Action.C

class Strategy_SELFISH_89(BaseStrategy):
    """
    Tit-for-Tat with Recovery strategy for Common Pool Resource games.
    
    This strategy prioritizes sustainability by cooperating as long as the pool 
    remains stable or growing, while utilizing a punishing defection mechanism 
    when the collective group depletes resources. It dynamically adjusts for 
    population size (n) and switches to unilateral defection in the final round 
    or when critical depletion thresholds are met.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.epsilon = 1e-09
        self.consecutive_depletions = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D
        if current_stock < self.capacity / 4.0:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock / (2.0 * self.n) < self.epsilon:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        total_coop_prev = int(prev_my_action) + prev_opp_coop
        total_defect_prev = self.n - total_coop_prev
        threshold_for_stability = self.n / 2
        if total_coop_prev >= threshold_for_stability:
            self.consecutive_depletions = 0
            return Action.C
        else:
            self.consecutive_depletions += 1
            if self.n > 4:
                if self.consecutive_depletions >= 2:
                    self.consecutive_depletions = 0
                    return Action.D
                return Action.C
            else:
                return Action.D

class Strategy_SELFISH_90(BaseStrategy):
    """
    A sustainable harvest equilibrium (SHE) strategy.
    
    Logic:
    1. Terminal Phase (last two rounds): Always Defect to capture remaining stock.
    2. Initialization: Cooperate to build trust.
    3. Recovery Mode: If stock < 0.5 * capacity, Cooperate to rebuild resources.
    4. Reciprocity: If stock >= 0.5 * capacity:
       - If high stock (> 0.9 * capacity), Defect to prevent waste.
       - Otherwise, Cooperate if previous round cooperation was >= (n-1), else Defect.
    5. Fallback: If stock is near 0, Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_stock < 1e-06:
            return Action.C
        if current_round >= self.r - 2:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock > 0.9 * self.capacity:
            return Action.D
        if current_stock < 0.5 * self.capacity:
            return Action.C
        k_prev = int(history.opponent_cooperators[-1])
        if k_prev >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_91(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy that prioritizes individual
    accumulation while protecting the regenerative stock level to ensure future
    payoffs based on opponent behavior and current stock thresholds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.sustainable_stock_threshold = 0.5 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        if t == r - 1:
            return Action.D
        if t == 0:
            return Action.C
        if current_stock >= self.sustainable_stock_threshold:
            return Action.D
        else:
            opp_coop = history.opponent_cooperators[-1]
            prev_round_defect_count = n - 1 - opp_coop
            if prev_round_defect_count > n / 2:
                return Action.C
            return Action.D

class Strategy_SELFISH_92(BaseStrategy):
    """
    A sustainability-focused, reciprocity-based strategy for the Common Pool Resource game.
    It prioritizes cooperation when stock is low, responds to opponent greed with 
    probabilistic defection, and enters an aggressive harvesting mode during the end-game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_opponents = self.n_players - 1
        self.target_stock = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_stock > 0:
            ratio = current_stock / self.capacity
            log_val = -math.log(ratio) / math.log(2.0) if ratio > 0 else 0
            end_game_threshold = total_rounds - math.ceil(log_val)
        else:
            end_game_threshold = 0
        if current_round >= total_rounds - 2 or current_round >= end_game_threshold:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.target_stock:
            return Action.C
        cooperating_opponents = history.opponent_cooperators[-1]
        defecting_opponents = self.n_opponents - cooperating_opponents
        if defecting_opponents == 0:
            return Action.C
        elif defecting_opponents == self.n_opponents:
            return Action.D
        else:
            prob_defect = defecting_opponents / self.n_opponents
            if random.random() < prob_defect:
                return Action.D
            return Action.C

class Strategy_SELFISH_93(BaseStrategy):
    """
    A strategy that maintains a cooperation threshold (T) which adapts based on 
    stock levels and recent opponent behavior. 
    - Starts with cooperation.
    - Uses a threshold T to decide C/D based on opponent cooperation rate.
    - Switches to cooperation if stock is critically low.
    - Adjusts T dynamically based on stock sustainability.
    - Always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.5
        self.prev_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        if round_idx == total_rounds - 1:
            self.prev_stock = current_stock
            return Action.D
        if round_idx == 0:
            self.prev_stock = current_stock
            return Action.C
        is_declining = current_stock < self.prev_stock
        num_opponents = n_players - 1
        obs_coops = history.opponent_cooperators[-1]
        r_coop = obs_coops / num_opponents if num_opponents > 0 else 0.0
        action = Action.D
        if current_stock < capacity / 4:
            action = Action.C
        elif r_coop >= self.threshold:
            action = Action.C
        else:
            action = Action.D
        if current_stock > 0.9 * capacity:
            self.threshold = min(0.9, self.threshold + 0.05)
        elif is_declining:
            self.threshold = max(0.1, self.threshold - 0.05)
        self.prev_stock = current_stock
        return action

class Strategy_SELFISH_94(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Threshold Strategy.
    Prioritizes cooperative signaling early on and maintains stock levels
    while adapting to the aggregate behavior of opponents.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.tau = 0.5 * self.game_description.capacity
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock <= 0:
            return Action.D
        if current_stock <= self.tau:
            return Action.D
        c_obs = history.opponent_cooperators[-1]
        coop_threshold = math.ceil(self.n_opponents / 2)
        if c_obs >= coop_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_95(BaseStrategy):
    """
    A preservation-focused strategy that defaults to Defect (D) but switches 
    to Cooperate (C) when the common pool resource is threatened or depleted, 
    provided there is sufficient evidence of cooperation from opponents.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.epsilon = 1e-06

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if t == self.r:
            return Action.D
        threshold = self.capacity / (2 * self.n)
        if current_stock < threshold:
            if current_stock < self.epsilon:
                return Action.D
            return Action.C
        if 0 >= threshold:
            return Action.D
        else:
            if history.round_number == 0:
                return Action.C
            k_prev = history.opponent_cooperators[-1]
            if k_prev >= self.n / 2:
                return Action.C
            else:
                return Action.D

class Strategy_SELFISH_96(BaseStrategy):
    """
    Tit-for-Tat with Resource Thresholds strategy.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Last Round (index r-1): Always Defect (D).
    - Intermediate Rounds:
        - If stock < capacity * 0.25: Defect (D) to extract remaining value.
        - If stock >= capacity * 0.25:
            - If majority of opponents (>= ceil((n-1)/2)) cooperated in previous round: Cooperate (C).
            - Else: Defect (D) to protect share.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.D
        n_opponents = self.n - 1
        threshold = math.ceil(n_opponents * 0.5)
        if history.opponent_cooperators[-1] >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_97(BaseStrategy):
    """
    A strategy that maintains a target stock level for optimal logistic growth.
    It cooperates if the sustainability index is high and stock is healthy.
    It defaults to defection in the last round, when stock is dangerously low,
    or when opponent cooperation is insufficient.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = float(game_description.n_players)
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock < self.capacity / (2.0 * self.n):
            return Action.D
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_action_val = 1 if my_prev_action else 0
        k = history.opponent_cooperators[-1] + my_prev_action_val
        phi = k / self.n
        if current_stock <= self.capacity * 0.25:
            return Action.D
        if phi > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_98(BaseStrategy):
    """
    Implements Conditional Resource Sustenance (CRS).
    
    This strategy balances long-term resource sustainability with reciprocal behavior.
    - If the current stock is critically low (< 25% capacity), it always cooperates to prevent collapse.
    - Otherwise, it practices reciprocity, cooperating if at least 50% of the opponents cooperated
      in the previous round, and defecting otherwise.
    - It strictly exploits the final round for maximum return.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.C
        num_cooperators = history.opponent_cooperators[-1]
        num_opponents = self.n - 1
        cooperation_rate = num_cooperators / num_opponents
        if cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_99(BaseStrategy):
    """
    Implements the Sustainable Opportunism strategy for the Common Pool Resource game.
    
    This strategy prioritizes sustainability to maximize long-term payoffs.
    - Round 1: Always Cooperate (C).
    - Terminal Round: Always Defect (D).
    - Intermediate Rounds:
        - If current stock < capacity/n: Cooperate (C) to prevent resource collapse.
        - If all opponents cooperated last round: Cooperate (C) to maintain stability.
        - Otherwise: Defect (D) to maximize individual gain in a potentially unstable environment.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.critical_stock_threshold = self.capacity / self.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.n_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        if current_stock < self.critical_stock_threshold:
            return Action.C
        others_cooperated_last_round = history.opponent_cooperators[-1]
        if others_cooperated_last_round == self.n_players - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_100(BaseStrategy):
    """
    Implements a conditional Tit-for-Tat strategy for the Common Pool Resource game.
    It monitors the stock level and population cooperation to maintain equilibrium,
    while switching to permanent defection if the system collapses or stock depletes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.always_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if self.always_defect:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_idx = history.round_number - 1
        my_prev_action = history.my_actions[prev_idx]
        prev_payoff = history.my_payoffs[prev_idx]
        n_p = self.game_description.n_players
        capacity = self.game_description.capacity
        s_prev = prev_payoff * (2 * n_p if my_prev_action else n_p)
        k_prev = history.opponent_cooperators[prev_idx] + (1 if my_prev_action else 0)
        total_consumption = k_prev * (s_prev / (2 * n_p)) + (n_p - k_prev) * (s_prev / n_p)
        s_remaining = max(0.0, s_prev - total_consumption)
        growth = 2 * s_remaining * (1 - s_remaining / capacity)
        if current_stock < capacity / (2 * n_p):
            self.always_defect = True
            return Action.D
        if total_consumption > s_remaining + growth:
            self.always_defect = True
            return Action.D
        if current_stock < capacity / 2:
            return Action.D
        if k_prev < n_p:
            return Action.D
        return Action.C

class Strategy_SELFISH_101(BaseStrategy):
    """
    A strategy that maintains stock by cooperating unless:
    1. The game is in the final round (terminal phase).
    2. The current stock has dropped below a critical threshold (capacity/n).
    3. The number of defectors in the previous round was high (more than half of opponents).
    
    Otherwise, it cooperates to ensure sustainable resource growth.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        rounds_completed = history.round_number
        rounds_remaining = self.r - rounds_completed
        if rounds_completed == 0:
            return Action.C
        if rounds_remaining == 1:
            return Action.D
        if current_stock < self.capacity / self.n:
            return Action.D
        num_opponents = self.n - 1
        prev_round_cooperators = history.opponent_cooperators[-1]
        prev_round_defectors = num_opponents - prev_round_cooperators
        if prev_round_defectors > self.n / 2:
            return Action.D
        return Action.C

class Strategy_SELFISH_102(BaseStrategy):
    """
    Strategy: Sustainable Opportunism
    - Round 1: Cooperate (C) to build stock.
    - Rounds 2 to r-1: 
        - If previous round cooperators >= n-1, Cooperate (C).
        - If current stock < capacity / 2, Defect (D).
        - Otherwise, Defect (D).
    - Round r (Final): Always Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < self.game_description.capacity / 2.0:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_k = history.opponent_cooperators[-1] + (1 if prev_my_action else 0)
        if prev_k >= self.game_description.n_players - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_103(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Resource Thresholds.
    
    Logic:
    - Round 1: Cooperate.
    - Final Round: Defect (max extraction).
    - Else if rapid depletion (stock < 50% of previous): Defect.
    - Else if opponents defected: Defect (retaliation).
    - Else if stock is declining despite full cooperation: Defect (short-termism).
    - Otherwise: Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.prev_stock = current_stock
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_k = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if self.prev_stock > 0 and current_stock < self.prev_stock * 0.5:
            self.prev_stock = current_stock
            return Action.D
        if prev_k < n_opponents:
            self.prev_stock = current_stock
            return Action.D
        if current_stock < self.prev_stock:
            self.prev_stock = current_stock
            return Action.D
        self.prev_stock = current_stock
        return Action.C

class Strategy_SELFISH_104(BaseStrategy):
    """
    Strategy: Resource-Conditional Tit-for-Tat
    
    This strategy focuses on sustaining the common pool while the stock is healthy 
    by cooperating, but pivots to defection if opponents fail to cooperate or 
    if the stock falls below a critical threshold (half-capacity), 
    ensuring maximum extraction before collapse. In the final round, 
    it always defects to maximize final utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.s_threshold = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock <= self.s_threshold:
            return Action.D
        prev_round_idx = -1
        prev_cooperators = history.opponent_cooperators[prev_round_idx]
        if prev_cooperators >= self.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_105(BaseStrategy):
    """
    Tit-for-Tat with Thresholding strategy for the Common Pool Resource game.
    - Cooperates initially.
    - Defects in the final round.
    - Defects if stock falls below critical threshold (capacity / 4).
    - Otherwise, reciprocates cooperation if a majority of opponents (>= (n-1)/2) cooperated in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = self.capacity / 4.0
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.threshold:
            return Action.D
        prev_k = history.opponent_cooperators[-1]
        cooperation_threshold = math.floor(self.n_opponents / 2)
        if prev_k >= cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_106(BaseStrategy):
    """
    Implements the Conditional Harvesting strategy:
    - Cooperates in the first round to establish reciprocity.
    - Defects in the final round to maximize individual yield.
    - During intermediate rounds, adapts based on total cooperation history (k_t):
      - If cooperation is high (k_t >= n-1), extracts surplus if stock is high.
      - If cooperation is low, attempts conservation only if stock is critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        num_opponents_cooperating = history.opponent_cooperators[-1]
        k_t = num_opponents_cooperating + int(my_prev_action)
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        h = n - 1
        if k_t >= h:
            if current_stock / capacity > 0.6:
                return Action.D
            else:
                return Action.C
        elif current_stock < capacity / 4:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_107(BaseStrategy):
    """
    Implements a resource-conscious strategy that balances sustainability 
    with defect-maximization based on historical stock levels and opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.target_stock = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.D
        if self.r < 5:
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        if current_stock < self.target_stock / self.n:
            return Action.D
        my_prev_action = history.my_actions[-1]
        num_coop_sys = k_prev + (1 if my_prev_action else 0)
        num_def_sys = self.n - num_coop_sys
        if num_def_sys > self.n / 2.0:
            return Action.D
        if current_stock > self.target_stock / 2.0:
            return Action.C
        elif num_def_sys > 0:
            return Action.D
        return Action.C

class Strategy_SELFISH_108(BaseStrategy):
    """
    Implements Threshold-Based Sustainable Exploitation strategy.
    
    Logic:
    1. Always Cooperate in Round 1.
    2. Always Defect in the final round.
    3. If stock is critically low (< 20% of capacity), prioritize survival (Cooperate).
    4. Otherwise, use reciprocity: Cooperate if (n-1) or more others cooperated, 
       otherwise Defect to protect against depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.2 * self.capacity:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_109(BaseStrategy):
    """
    A Tit-for-Tat variant strategy for the Common Pool Resource Game.
    It cooperates initially and tries to maintain sustainability, but switches
    to permanent defection if the resource collapses, if the resource is
    depleted beyond recovery, or if the game enters its final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            self.permanent_defection = True
            return Action.D
        if current_round == 0:
            return Action.C
        if self.permanent_defection:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            self.permanent_defection = True
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponent_cooperators = history.opponent_cooperators[-1]
        total_cooperators_last_round = last_opponent_cooperators + (1 if last_my_action else 0)
        threshold = math.floor(self.n / 2)
        if total_cooperators_last_round < threshold:
            self.permanent_defection = True
            return Action.D
        return Action.C

class Strategy_SELFISH_110(BaseStrategy):
    """
    A threshold-based Tit-for-Tat strategy for the Common Pool Resource Game.
    
    Logic:
    1. Always cooperates in the first round.
    2. In the terminal round, always defects to extract remaining utility.
    3. If stock drops below 25% of capacity, defects immediately (safety valve).
    4. Otherwise, monitors the ratio of cooperating players from the previous round
       against a 0.5 threshold to decide between cooperation and defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity * 0.25:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_coop = prev_opp_coop + (1 if my_prev_action == Action.C else 0)
        if total_prev_coop / n >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_111(BaseStrategy):
    """
    A conditional Tit-for-Tat variant strategy for the Common Pool Resource Game.
    It balances cooperation based on stock levels (Critical Threshold) and 
    opponent behavior, while switching to pure extraction (Defection) in the 
    terminal phase or during periods of extreme stock volatility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = self.capacity / 2.0
        self.terminal_k = min(3, self.r // 4)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.r - self.terminal_k:
            if current_stock > 0:
                return Action.D
        if not hasattr(self, '_last_stock'):
            self._last_stock = self.capacity
        is_volatile = False
        if current_stock < 0.5 * self._last_stock:
            is_volatile = True
        self._last_stock = current_stock
        if is_volatile:
            return Action.D
        n_c = history.opponent_cooperators[-1]
        if current_stock <= 0.1 * self.capacity:
            return Action.D
        if current_stock > self.threshold:
            target_threshold = 0
        else:
            target_threshold = self.n - 1
        if n_c >= target_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_112(BaseStrategy):
    """
    A strategy that maintains a sustainable resource pool by cooperating when stock levels
    are healthy, punishing defection, and playing aggressively (Defect) in the final round.
    It tracks whether the common pool was managed sustainably in the previous round to 
    decide whether to continue cooperation or switch to an extraction-recapture mode.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_mode = False
        self.punishment_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == r - 1:
            return Action.D
        if self.punishment_mode:
            self.punishment_counter -= 1
            if self.punishment_counter == 0:
                self.punishment_mode = False
            return Action.D
        if t == 0:
            return Action.C
        prev_idx = t - 1
        my_action_prev = history.my_actions[prev_idx]
        n_opponents = n - 1
        opp_c_count = history.opponent_cooperators[prev_idx]
        total_c = opp_c_count + (1 if my_action_prev else 0)
        total_d = n - total_c
        consumption_factor = total_c / (2 * n) + total_d / n
        if consumption_factor > 0.5:
            self.punishment_mode = True
            self.punishment_counter = math.ceil(n / 2)
            return Action.D
        if current_stock < 0.25 * capacity:
            return Action.C
        if current_stock >= 0.5 * capacity:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_113(BaseStrategy):
    """
    A strategy that maintains cooperation (C) as long as the resource stock is 
    healthy (H >= 0.25) and all other players are cooperating. It retaliates (D)
    if the stock is critically low or if any opponent defects. In the final round,
    it always defects to maximize extraction. If the system collapses (H < 0.1),
    it switches to permanent defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1
        self.threshold_cooperation_count = self.n_opponents
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if self.game_description.capacity > 0:
            h = current_stock / self.game_description.capacity
        else:
            h = 0.0
        if h < 0.1:
            self.permanent_defect = True
        if self.permanent_defect:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if h < 0.25:
            return Action.D
        previous_cooperation_count = history.opponent_cooperators[-1]
        if previous_cooperation_count < self.threshold_cooperation_count:
            return Action.D
        return Action.C

class Strategy_SELFISH_114(BaseStrategy):
    """
    A reputation-based strategy for the Common Pool Resource game.
    Maintains a belief about opponent cooperation and adjusts actions based
    on round index, stock levels, and reputation thresholds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.alpha = 0.1
        self.tau = 0.6
        self.reputation = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        num_opponents = n - 1
        r = self.game_description.n_rounds
        t = history.round_number
        if t > 0:
            c_obs = history.opponent_cooperators[-1]
            if num_opponents > 0:
                normalized_c = c_obs / num_opponents
                self.reputation = (1.0 - self.alpha) * self.reputation + self.alpha * normalized_c
        if t == r - 1:
            return Action.D
        if current_stock < self.game_description.capacity / n:
            return Action.D
        if t == 0:
            return Action.C
        if self.reputation >= self.tau:
            return Action.C
        elif current_stock > self.game_description.capacity / 2.0:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_115(BaseStrategy):
    """
    A reputation-based strategy for the Common Pool Resource game.
    Tracks population cooperation levels (R_t) and adapts actions based on 
    resource sustainability and peer behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 1.0
        self.alpha = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number + 1
        if t == total_rounds:
            return Action.D
        if current_stock < capacity / (2 * n):
            return Action.D
        if t == 1:
            self.reputation = 1.0
            return Action.C
        last_my_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + last_my_action
        self.reputation = self.alpha * self.reputation + (1.0 - self.alpha) * (c_prev / n)
        if self.reputation >= 0.8:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_116(BaseStrategy):
    """
    Implements the 'Conditional Sustainability' strategy.
    
    This strategy aims to balance resource extraction with preservation. It follows 
    a predetermined path: cooperate in the first round, defect in the final round, 
    and use a threshold-based conditional policy in intermediate rounds based on 
    current stock levels and recent group behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.target_s = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        if current_round == self.r:
            return Action.D
        my_last_action = history.my_actions[-1]
        k_prev = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        if current_stock > self.target_s:
            return Action.D
        elif k_prev > self.n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_117(BaseStrategy):
    """
    A triggered sustainability strategy that balances cooperation with
    resource preservation. It cooperates when conditions allow for sustainable
    growth and the majority of the group is cooperating. It defects in the 
    terminal round, when resources fall below critical sustainability thresholds,
    or when the group norm shifts towards defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.sustainability_threshold = 0.25 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.n_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < self.sustainability_threshold:
            return Action.D
        last_action_mine = 1 if history.my_actions[-1] else 0
        total_cooperators_last_round = history.opponent_cooperators[-1] + last_action_mine
        if total_cooperators_last_round >= self.n_players / 2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_118(BaseStrategy):
    """
    Implements a Conditional Threshold Optimization strategy.
    
    The strategy aims to maintain the stock at 50% capacity (S_opt) by dynamically 
    switching between Cooperate (C) and Defect (D) based on current stock levels 
    and the observed cooperation rate of the population. It incorporates 
    final-round defection, critical collapse safeguards, and a population-reset 
    mechanism.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.target_stock = self.capacity / 2.0
        self.collapse_threshold = self.capacity * 0.05
        self.critical_threshold = self.capacity * 0.2
        self.coop_threshold = math.ceil(self.n * 0.75)
        self.reset_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r_current = history.round_number
        n_rounds = self.game_description.n_rounds
        if r_current >= n_rounds - 2:
            return Action.D
        if r_current == 0:
            return Action.C
        prev_obs = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        c_total_prev = prev_obs + (1 if my_prev_action else 0)
        if c_total_prev == 0:
            self.reset_counter = 3
        if self.reset_counter > 0:
            self.reset_counter -= 1
            return Action.D
        if current_stock < self.collapse_threshold:
            return Action.D
        if current_stock < self.critical_threshold:
            return Action.D
        if current_stock > self.target_stock:
            if c_total_prev >= self.n - 1:
                return Action.C
            else:
                return Action.D
        elif c_total_prev >= self.coop_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_119(BaseStrategy):
    """
    A conditional Tit-for-Tat approach adapted for resource stock dynamics.
    It balances extraction vs. preservation based on stock thresholds and 
    previous round cooperation, with an unconditional defection policy 
    during the end-game (last 3 rounds).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round >= self.r - 3:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if current_round == 0:
            if current_stock > 0.75 * self.capacity:
                return Action.D
            return Action.C
        if current_stock <= 0.25 * self.capacity:
            return Action.C
        if current_stock > 0.75 * self.capacity:
            return Action.D
        num_opponents = self.n - 1
        if num_opponents > 0:
            prev_coop_fraction = history.opponent_cooperators[-1] / num_opponents
            if prev_coop_fraction >= 0.5:
                return Action.C
        return Action.D

class Strategy_SELFISH_120(BaseStrategy):
    """
    Implements a conditional, history-dependent strategy for the Common Pool Resource game.
    It balances cooperation and exploitation using a 'trust_score' that updates based
    on the population's cooperation rate and reacts to resource stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_score = 1.0
        self.last_action = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r = self.game_description.n_rounds
        current_round_idx = history.round_number
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round_idx == r - 1:
            self.last_action = Action.D
            return Action.D
        if current_round_idx == 0:
            self.last_action = Action.C
            return Action.C
        if current_stock < capacity / n:
            self.last_action = Action.D
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        i_cooperated = 1 if my_prev_action == Action.C else 0
        opponents_c = k_prev - i_cooperated
        avg_coop = opponents_c / (n - 1) if n - 1 > 0 else 0.0
        if avg_coop > 0.5:
            self.trust_score = min(1.0, self.trust_score + 0.1)
        else:
            self.trust_score = max(0.0, self.trust_score - 0.2)
        if self.trust_score < 0.3 and current_stock < 0.8 * capacity:
            self.last_action = Action.D
            return Action.D
        if current_stock > 0.9 * capacity and self.trust_score > 0.1:
            self.last_action = Action.C
            return Action.C
        if avg_coop > 0.5:
            self.last_action = Action.C
            return Action.C
        self.last_action = Action.D
        return Action.D

class Strategy_SELFISH_121(BaseStrategy):
    """
    Implements a Conditional Threshold-Triggered Tit-for-Tat strategy.
    
    Logic Overview:
    - Round 1: Always Cooperate (C).
    - Round r (Terminal): Always Defect (D).
    - Rounds 2 to r-1:
        - If stock is critical (< 0.2 * capacity): Defect (D).
        - If previous round had defectors (D_obs > 0):
            - If new stock <= 0.75 * capacity, enter Punishment Phase.
            - If new stock > 0.75 * capacity, play C (unless punishing).
            - Punishment: Play D for D_obs rounds.
        - High Cooperation Trigger: If C_obs == n, stay C. Any single defection when stock >= 0.75 * capacity triggers a single-round D response.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_rounds_remaining = 0
        self.high_coop_trigger = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        prev_round = history.round_number - 1
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_obs = history.opponent_cooperators[-1] + my_prev_action
        d_obs = n - c_obs
        if current_stock <= 0.2 * capacity:
            return Action.D
        if c_obs == n:
            self.high_coop_trigger = False
            return Action.C
        if self.high_coop_trigger:
            self.high_coop_trigger = False
            return Action.D
        if current_stock >= 0.75 * capacity and d_obs > 0:
            self.high_coop_trigger = True
            return Action.D
        if d_obs > 0:
            if current_stock <= 0.75 * capacity:
                self.punishment_rounds_remaining = max(self.punishment_rounds_remaining, d_obs)
            else:
                return Action.C
        if self.punishment_rounds_remaining > 0:
            self.punishment_rounds_remaining -= 1
            return Action.D
        return Action.C

class Strategy_SELFISH_122(BaseStrategy):
    """
    A Tit-for-Tat variant with a Defection Threshold. Cooperates if the stock is high
    and the majority of opponents cooperated in the previous round. Switches to
    unconditional defection if the stock drops below a critical threshold or if
    the game is near its end.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.stock_critical_threshold = 0.5 * self.game_description.capacity
        if self.game_description.n_players <= 2:
            self.majority_threshold = 1.0
        else:
            self.majority_threshold = (self.game_description.n_players - 1) * 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if total_rounds - current_round < 2:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock <= 0:
            return Action.D
        if current_stock <= self.stock_critical_threshold:
            return Action.D
        c_count = history.opponent_cooperators[-1]
        if c_count >= self.majority_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_123(BaseStrategy):
    """
    Tit-for-Tat with Threshold Sensitivity:
    - Round 1: Cooperate to establish baseline.
    - Final Round: Defect to capture remaining utility.
    - Resource Sustainability: If current_stock < 50% of capacity, defect to salvage utility.
    - Tit-for-Tat: If any opponent defected in the previous round, punish by defecting.
    - Default: Cooperate if resources are sustainable and opponents are cooperating.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        threshold = 0.5 * self.game_description.capacity
        if current_stock < threshold:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        if history.opponent_cooperators[-1] < n_opponents:
            return Action.D
        return Action.C

class Strategy_SELFISH_124(BaseStrategy):
    """
    A threshold-based conservation strategy for the Common Pool Resource Game.
    Maintains resource stock by cooperating unless the resource is collapsing 
    or defectors need to be punished.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.target_threshold = self.capacity / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.capacity / self.n:
            return Action.D
        if current_stock < self.target_threshold:
            return Action.C
        prev_coop_opponents = int(history.opponent_cooperators[-1])
        prev_my_action = bool(history.my_actions[-1])
        total_cooperators = prev_coop_opponents + (1 if prev_my_action else 0)
        num_defectors = self.n - total_cooperators
        if num_defectors > 0:
            return Action.D
        return Action.C

class Strategy_SELFISH_125(BaseStrategy):
    """
    Implements Dynamic Tit-for-Tat Thresholding.
    Prioritizes cooperation unless stock is critically low, opponents defect, 
    or the game is ending. Includes mechanisms for forgiveness and recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < current_stock / (2 * self.n):
            return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.D
        prev_k = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        played_d_last = not history.my_actions[-1]
        if prev_k >= n_opponents:
            return Action.C
        else:
            if played_d_last and current_stock >= 0.75 * self.capacity:
                return Action.C
            return Action.D

class Strategy_SELFISH_126(BaseStrategy):
    """
    A sustainability-focused Tit-for-Tat strategy.
    
    Logic:
    1. Initial Round: Always Cooperate (C).
    2. Terminal Phase (last 2 rounds): Always Defect (D) to maximize final returns.
    3. Sustainability Check: If current_stock < capacity / 2, Cooperate (C).
    4. Reciprocity Check: If previous round cooperation ratio >= 0.5, Cooperate (C), otherwise Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.s_thresh = game_description.capacity / 2.0
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.total_rounds - 2:
            return Action.D
        if current_stock < self.s_thresh:
            return Action.C
        last_opponent_coops = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        total_prev_cooperators = last_opponent_coops + (1 if last_my_action else 0)
        cooperation_ratio = total_prev_cooperators / self.n
        if cooperation_ratio >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_127(BaseStrategy):
    """
    A conditional 'Tit-for-Tat' strategy that prioritizes stock maintenance 
    by cooperating when resources are high (Phase 1), adjusting to group 
    behavior when stocks are moderate (Phase 2), defecting in terminal 
    rounds (Phase 3), and defaulting to defection if the resource collapses.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.total_rounds - 3:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if current_stock > 0.8 * self.capacity:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opp_coop = history.opponent_cooperators[-1]
        total_cooperators_prev = (1 if last_my_action else 0) + last_opp_coop
        threshold = math.ceil(self.n / 2)
        if total_cooperators_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_128(BaseStrategy):
    """
    Implements a Tit-for-Tat with Sustainability Threshold strategy.
    
    Logic:
    1. First round (t=0): Always Cooperate (C).
    2. Final round (t=r-1): Always Defect (D).
    3. Intermediate rounds:
       - If stock < capacity/4: Defect (D).
       - If stock >= capacity/4: 
         - If number of defectors in previous round < n/2: Cooperate (C).
         - If number of defectors in previous round >= n/2: Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if round_idx == r - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < capacity / 4.0:
            return Action.D
        my_last_action = history.my_actions[-1]
        total_cooperators = (1 if my_last_action else 0) + history.opponent_cooperators[-1]
        total_defectors = n - total_cooperators
        if total_defectors < n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_33(BaseStrategy):
    """
    Conditional Sustainability (CS) strategy: 
    - Cooperates in the first round.
    - Defects in the final round.
    - When stock is low ( < 25% capacity), greed takes precedence: Defect.
    - Otherwise, maintains cooperation if most players cooperated previously (n-1).
    - If punishing, checks efficacy: if stock doesn't improve, extends punishment phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.extending_punishment = False
        self.prev_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round_idx == 0:
            self.prev_stock = current_stock
            return Action.C
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock < 0.25 * self.game_description.capacity:
            return Action.D
        if self.prev_stock is not None:
            if self.extending_punishment:
                if current_stock >= self.prev_stock:
                    self.extending_punishment = False
                else:
                    self.prev_stock = current_stock
                    return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        opponents_cooperating = history.opponent_cooperators[-1]
        total_cooperating = opponents_cooperating + my_prev_action
        threshold = self.game_description.n_players - 1
        if total_cooperating >= threshold:
            self.prev_stock = current_stock
            return Action.C
        else:
            self.extending_punishment = True
            self.prev_stock = current_stock
            return Action.D

class Strategy_SELFINTERESTED_34(BaseStrategy):
    """
    Implements the Conditional Sustainability (CS) strategy.
    
    Logic:
    1. Always Cooperate (C) in round 0.
    2. Always Defect (D) in the final round (total_rounds - 1).
    3. If current_stock < (capacity / 4), switch to Defect (D) to maximize extraction.
    4. Otherwise, track opponent behavior:
       - Threshold = n / 2.
       - If previous round defectors > threshold, Defect (D).
       - Else, Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < self.capacity / 4.0:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        prev_defectors = self.n_opponents - prev_cooperators
        threshold = self.n_players / 2.0
        if prev_defectors > threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_35(BaseStrategy):
    """
    Implements a Threshold-Based Reciprocal Tit-for-Tat strategy.
    
    Logic:
    - Round 0: Cooperate (C).
    - If current stock < 0.2 * capacity: Always Cooperate (C) to prevent extinction.
    - If round == last round: Always Defect (D) to maximize extraction.
    - Otherwise:
        - If previous round had 0 defectors: Cooperate (C).
        - If previous round had >= n/2 defectors: Defect (D).
        - If previous round had between 0 and n/2 defectors:
            - Calculate probability p = 1 - (defectors / n).
            - Adjust p = 0.5 * p if round is second to last.
            - Play C with probability p, else D.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        threshold = 0.2 * self.capacity
        if current_stock < threshold:
            return Action.C
        if current_round == 0:
            return Action.C
        prev_round_idx = -1
        my_prev_action_val = 1 if history.my_actions[prev_round_idx] else 0
        total_cooperators = history.opponent_cooperators[prev_round_idx] + my_prev_action_val
        total_defectors = self.n - total_cooperators
        if total_defectors == 0:
            return Action.C
        if total_defectors >= self.n / 2:
            return Action.D
        is_penultimate = current_round == self.total_rounds - 2
        p = 1.0 - total_defectors / self.n
        if is_penultimate:
            p = 0.5 * p
        return Action.C if random.random() < p else Action.D

class Strategy_SELFINTERESTED_36(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with resource-sensitive thresholds.
    Prioritizes cooperation when stock is low (sustainability) and adapts
    trust based on the cooperativeness of opponents in previous rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_level = 1.0
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock <= 0.5 * self.game_description.capacity:
            return Action.C
        prev_opponents_cooperated_count = history.opponent_cooperators[-1]
        if prev_opponents_cooperated_count == self.n_opponents:
            self.trust_level = min(1.0, self.trust_level + 0.1)
        else:
            self.trust_level -= 0.2
        if self.trust_level > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_37(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Threshold Stock Management.
    Prioritizes sustainability by cooperating when the stock is healthy,
    retaliating against defectors, and extracting remaining value when the stock
    is critically low or the game is ending.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1
        self.min_safe_stock = self.game_description.capacity / 4.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= self.min_safe_stock:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators < self.n_opponents:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_38(BaseStrategy):
    """
    Implements Sustainable Tit-for-Tat with Depletion Awareness:
    - Round 1: Cooperates.
    - Final Round: Defects.
    - If Stock is 0: Defects.
    - If Stock == Capacity: Cooperates (unless final round).
    - If Stock < epsilon (capacity/2n): Defects.
    - If Opponents cooperated fully in prev round: Cooperates.
    - If Opponents did not cooperate fully:
        - Checks projected next stock if all cooperate. If < capacity/4, Defects.
        - Otherwise, Cooperates with probability = k/(n-1).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.epsilon = self.capacity / (2 * self.n)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if current_stock <= 1e-09:
            return Action.D
        if t == 0:
            return Action.C
        if t == self.desc.n_rounds - 1:
            return Action.D
        if current_stock >= self.capacity:
            return Action.C
        if current_stock < self.epsilon:
            return Action.D
        k = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if k == n_opponents:
            return Action.C
        else:
            s_rem = current_stock / 2.0
            stock_next = min(s_rem + 2.0 * s_rem * (1.0 - s_rem / self.capacity), self.capacity)
            if stock_next < self.capacity / 4.0:
                return Action.D
            prob = k / n_opponents if n_opponents > 0 else 0.0
            if random.random() < prob:
                return Action.C
            else:
                return Action.D

class Strategy_SELFINTERESTED_39(BaseStrategy):
    """
    Implements a Constrained Tit-for-Tat strategy for the Common Pool Resource game.
    
    Logic:
    1. Terminal Phase: If it is the last round, always Defect (D).
    2. Stock Preservation: If stock < capacity / 2, always Cooperate (C) to ensure sustainability.
    3. Reciprocity: 
        - In the first round (round_number == 0), always Cooperate (C).
        - In subsequent rounds, Cooperate (C) only if everyone cooperated in the previous round.
        - Otherwise, Defect (D).
    
    Note: The input history is 0-indexed. Round 0 is the first round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        num_players = self.game_description.n_players
        if current_round == total_rounds:
            return Action.D
        if current_stock < self.game_description.capacity / 2.0:
            return Action.C
        if current_round == 1:
            return Action.C
        prev_my_action_int = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + prev_my_action_int
        if total_cooperators_prev == num_players:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_40(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Sustainability Thresholds strategy.
    
    Logic:
    1. Always Cooperate on the first round.
    2. Terminal Rounds: If stock > 50% capacity, Defect (greedy). Else, standard rules.
    3. Critical Stock: If stock < 20% capacity, Defect if any opponent defected last round.
    4. Adaptive Response: Calculate 3-round moving average of opponent cooperation rates.
       - If avg_c > 0.5: Cooperate.
       - Else: Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            if current_stock > 0.5 * self.capacity:
                return Action.D
        if current_stock < 0.2 * self.capacity:
            last_round_opponents_c = history.opponent_cooperators[-1]
            if last_round_opponents_c < self.n_opponents:
                return Action.D
            return Action.C
        if self.n_opponents == 0:
            return Action.C
        start_idx = max(0, current_round - 3)
        recent_coop_counts = history.opponent_cooperators[start_idx:current_round]
        rates = [c / self.n_opponents for c in recent_coop_counts]
        avg_c = sum(rates) / len(rates)
        if avg_c > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_41(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    The strategy attempts to maximize long-term yield by maintaining the resource capacity.
    It follows three main phases:
    1. Initial Cooperation: Always starts by cooperating to build stock.
    2. Threshold-based Sustainability: Cooperates if a sufficient fraction of the group
       cooperated in the previous round, otherwise defects to preserve personal utility.
    3. Terminal Extraction: Defects in the final three rounds regardless of prior state.
    4. Safety Override: Defects if the current stock falls below 25% of capacity,
       as the pool is effectively collapsing.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        round_num = current_round_idx + 1
        if round_num > self.r - 3:
            return Action.D
        if current_stock < self.capacity / 4:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        k = history.opponent_cooperators[-1]
        did_i_cooperate_last_round = bool(history.my_actions[-1])
        total_cooperators_last_round = k + (1 if did_i_cooperate_last_round else 0)
        sustainability_index = total_cooperators_last_round / self.n
        if sustainability_index >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_42(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy for the Common Pool Resource Game.
    
    Logic:
    1. Terminal Round (t=r-1): Always Defect.
    2. Low Stock (S < capacity/4): Always Defect to extract remaining value.
    3. Tit-for-Tat (S >= capacity/4): Cooperate if the majority (>= n/2) of
       opponents cooperated in the previous round. Otherwise, Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game = game_description
        self.s_crit = self.game.capacity / 4.0
        self.threshold = math.ceil(self.game.n_players / 2.0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game.n_rounds - 1:
            return Action.D
        if current_stock < self.s_crit:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        prev_k = last_opponent_coops + (1 if last_my_action else 0)
        if prev_k >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_43(BaseStrategy):
    """
    Tit-for-Tat with Threshold Stock Preservation.
    
    This strategy prioritizes sustainability of the common pool resource.
    Decision logic:
    1. If it's the last round, defect (D) to extract maximum value.
    2. If stock is critically low (below 1/2n capacity), defect (D) to minimize waste.
    3. In the first round, cooperate (C).
    4. In subsequent rounds, if the number of defectors in the previous round 
       was <= 1, cooperate (C). Otherwise, punish by defecting (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        critical_threshold = self.game_description.capacity / (2 * self.game_description.n_players)
        if current_stock < critical_threshold:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        prev_defectors = self.n_opponents - prev_cooperators
        if prev_defectors <= 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_44(BaseStrategy):
    """
    Conditional Sustainability (CS) Strategy.
    Hybridizes Tit-for-Tat and stock-dependent maintenance:
    - Maintains target-stock at capacity.
    - Cooperates when stock is low (recovery).
    - Defects on last round.
    - Cooperates if all opponents cooperated last round.
    - If opponents defected, defects if stock is high (opportunistic recovery),
      otherwise cooperates (preventing total collapse).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.C
        k = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if k == n_opponents:
            return Action.C
        elif current_stock > 0.8 * self.capacity:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_45(BaseStrategy):
    """
    Implements a resource-aware Tit-for-Tat strategy.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Last Round: Always Defect (D).
    - Other Rounds: 
        - If all opponents cooperated last round: Cooperate (C).
        - If stock is critically low (S < capacity/n): Defect (D) to extract remaining value.
        - If opponents defected:
            - If stock is high (S > 0.5 * capacity): Cooperate (C) to allow regeneration.
            - If stock is low (S <= 0.5 * capacity): Defect (D) (scarcity penalty).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_round_index = current_round - 1
        k = history.opponent_cooperators[prev_round_index]
        if current_stock < self.capacity / self.n:
            return Action.D
        if k == self.n_opponents:
            return Action.C
        elif current_stock > self.capacity * 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_46(BaseStrategy):
    """
    Tit-for-Tat with Capacity Thresholds:
    - Maintains cooperation while stock is high and others cooperate.
    - Punishes defectors by defecting in the next round.
    - Prioritizes extraction when the pool is severely depleted (< 50% capacity).
    - Always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_opponents = self.game_description.n_players - 1
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        critical_stock = 0.5 * self.game_description.capacity
        if current_stock < critical_stock:
            return Action.D
        if current_round == 0:
            return Action.C
        last_round_coops = history.opponent_cooperators[-1]
        if last_round_coops == n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_47(BaseStrategy):
    """
    A sustainability-focused Tit-for-Tat strategy for the Common Pool Resource Game.
    
    Logic:
    1. Always defect in the final round.
    2. If stock is critically low (S < capacity/4), default to Defect to minimize losses.
    3. Start by Cooperating in Round 1.
    4. In intermediate rounds, reciprocate cooperation if n-1 players cooperated in the 
       previous round, otherwise Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number + 1
        if current_round_idx == self.r:
            return Action.D
        if current_stock < self.capacity / 4:
            return Action.D
        if current_round_idx == 1:
            return Action.C
        my_action_last_round = bool(history.my_actions[-1])
        coop_count_last_round = history.opponent_cooperators[-1] + (1 if my_action_last_round else 0)
        if coop_count_last_round >= self.n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_48(BaseStrategy):
    """
    A strategy that follows a structured decision-making process for the Common Pool Resource Game.
    1. First round: Always Cooperate (C).
    2. Terminal rounds (last 3 rounds): Always Defect (D) to maximize final payoff.
    3. Scarcity phase: If stock < 25% of capacity, Defect (D) to protect against collapse.
    4. Reciprocity phase: Uses Tit-for-Tat logic based on opponent behavior in the previous round.
       Cooperate if >= 50% of opponents cooperated in the previous round, otherwise Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_total = game_description.n_players
        self.n_opponents = self.n_total - 1
        self.reciprocity_threshold = math.ceil(self.n_opponents / 2)
        self.scarcity_threshold = self.capacity * 0.25

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        if current_round >= total_rounds - 3:
            return Action.D
        if current_stock < self.scarcity_threshold:
            return Action.D
        prev_opp_cooperators = int(history.opponent_cooperators[-1])
        if prev_opp_cooperators >= self.reciprocity_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_49(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Critical Stock Thresholding.
    
    Strategy:
    1. First Round: Cooperate (C).
    2. Last Round: Defect (D).
    3. Critical Threshold: If current stock <= capacity / 2, prioritize harvesting (D).
    4. General Case (Stock > Critical):
       - If previous round had 0 defectors: Cooperate (C).
       - If previous round had >= n/2 defectors: Defect (D).
       - Otherwise: Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.s_crit = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        if current_round == self.total_rounds:
            return Action.D
        if current_stock <= self.s_crit:
            return Action.D
        n_opponents = self.n - 1
        num_cooperators = history.opponent_cooperators[-1]
        num_defectors = n_opponents - num_cooperators
        if num_defectors == 0:
            return Action.C
        elif num_defectors >= self.n / 2.0:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_50(BaseStrategy):
    """
    A Trigger-Modified Tit-for-Tat strategy for the Common Pool Resource Game.
    
    This strategy aims to maximize the collective stock by cooperating when 
    possible, punishing defectors when the resource is abundant, and entering 
    a recovery mode when the resource is scarce. It always defects in the 
    terminal round to capture remaining value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_bad_behavior = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        r_current = history.round_number
        capacity = self.game_description.capacity
        n_opponents = n - 1
        if r_current == r_total - 1:
            return Action.D
        if r_current == 0:
            return Action.C
        if current_stock <= capacity / 4:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators < n_opponents:
            self.consecutive_bad_behavior += 1
        else:
            self.consecutive_bad_behavior = 0
        if prev_cooperators == n_opponents:
            return Action.C
        if self.consecutive_bad_behavior > 2:
            return Action.D
        if current_stock > capacity / 2:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_51(BaseStrategy):
    """
    A triggered punishment strategy for the Common Pool Resource Game.
    Starts by cooperating. If any other player defects (observed cooperators < n-1),
    it permanently switches to defecting for all future rounds. If not punishing,
    it cooperates unless the stock falls to half capacity or below, in which case
    it defects to recover value before collapse. Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_punishment_active = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            return Action.D
        last_round_opp_coop = history.opponent_cooperators[-1]
        my_last_action_was_c = bool(history.my_actions[-1])
        total_cooperators_last_round = last_round_opp_coop + (1 if my_last_action_was_c else 0)
        if last_round_opp_coop < n - 1:
            self.is_punishment_active = True
        if self.is_punishment_active:
            return Action.D
        if current_stock <= self.game_description.capacity / 2:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_52(BaseStrategy):
    """
    Implements a Recursive Tit-for-Tat strategy with threshold-based stock preservation.
    Prioritizes sustainability, forgiving initial lapses only when stock is healthy,
    but defects aggressively when the resource is scarce or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.s_crit = 0.25 * self.capacity
        self.s_healthy = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.D
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.s_crit:
            return Action.D
        last_my_action = int(history.my_actions[-1])
        last_opponent_cooperators = history.opponent_cooperators[-1]
        k_prev = last_my_action + last_opponent_cooperators
        if k_prev == self.n:
            return Action.C
        if current_stock >= self.s_healthy:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_53(BaseStrategy):
    """
    A Sustainable Reciprocator strategy for the Common Pool Resource Game.
    Maintains cooperation as long as the resource stock is healthy and opponents
    behave sustainably. Retaliates with defection if the stock crashes or
    excessive defection is detected, while always defecting in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.n_opponents = self.n - 1
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.total_rounds - 1:
            return Action.D
        if current_stock <= 0.1 * self.capacity:
            return Action.D
        last_round_opp_coop = history.opponent_cooperators[-1]
        i_cooperated_last = bool(history.my_actions[-1])
        total_cooperators = last_round_opp_coop + (1 if i_cooperated_last else 0)
        k = self.n - total_cooperators
        if current_stock < 0.5 * self.capacity:
            return Action.D
        if k >= self.n / 2:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_54(BaseStrategy):
    """
    Adaptive Sustainability Control (ASC): 
    Balances cooperation with resource preservation by monitoring stock levels 
    and opponent behavior. It initiates with cooperation, maintains 
    cooperation when the group supports it, matches defection to avoid 
    exploitation, and aggressively harvests in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n = self.game.n_players
        opp_coop_count = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        k_prev = opp_coop_count + (1 if my_prev_action else 0)
        if k_prev == n:
            return Action.C
        cooperation_fraction = k_prev / n
        if cooperation_fraction < 0.5:
            return Action.D
        if current_stock > 0.25 * self.game.capacity:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_55(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness strategy for the Common Pool Resource Game.
    
    Operates by cooperating in the first round. In subsequent rounds, it monitors 
    the cooperation levels of opponents. It cooperates if the number of cooperating 
    opponents is at least (n-1). It defects if cooperation is below this threshold, 
    if the stock is critically low, or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.initial_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            return Action.D
        if n > 0 and current_stock < self.initial_stock / n:
            return Action.D
        threshold = n - 1
        prev_cooperators = int(history.opponent_cooperators[-1])
        if prev_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_56(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Monitoring:
    - Round 1: Always Cooperate.
    - Final Round: Always Defect.
    - Stock Collapse Protection: If stock < capacity / (10 * n), force Defect.
    - Conservation Mode (Stock < capacity / 2): If stock is low, prioritize replenishment by Cooperating.
    - Punishment Mode (Stock >= capacity / 2):
        - Cooperate if all opponents cooperated in the previous round.
        - Defect if any opponent defected in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        critical_threshold = self.game_description.capacity / (10 * self.game_description.n_players)
        if current_stock < critical_threshold:
            return Action.D
        if current_stock < self.game_description.capacity / 2:
            return Action.C
        k = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if k == n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_57(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy that manages resources
    by cooperating initially, retaliating against resource-depleting defectors,
    and consuming aggressively in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == total_rounds - 1:
            return Action.D
        if current_stock < capacity / (2 * n):
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_c = history.opponent_cooperators[-1]
        prev_total_c = (1 if prev_my_action else 0) + prev_opp_c
        prev_total_d = n - prev_total_c
        prev_my_payoff = history.my_payoffs[-1]
        if prev_my_action:
            s_prev = prev_my_payoff * 2 * n
        else:
            s_prev = prev_my_payoff * n
        if prev_total_d > 0:
            if current_stock < s_prev:
                return Action.D
            return Action.C
        return Action.C

class Strategy_SELFINTERESTED_58(BaseStrategy):
    """
    Implements a strategic cooperation approach for the Common Pool Resource Game,
    using a learning mechanism (k-threshold) to adapt to group behavior while 
    prioritizing stock sustainability and defensive action against exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.k = float(self.n - 1)
        self.was_low_stock = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        last_round_idx = history.round_number - 1
        n_c = history.opponent_cooperators[last_round_idx]
        if n_c > self.k:
            self.k = max(0.0, self.k - 0.1)
        elif n_c < self.k:
            self.k = min(float(self.n - 1), self.k + 0.1)
        if current_stock > 0.8 * self.capacity and self.was_low_stock:
            self.k = float(self.n - 1)
        self.was_low_stock = current_stock < 0.25 * self.capacity
        if current_stock < 0.0001:
            return Action.D
        h = current_stock / self.capacity
        if h < 0.25:
            return Action.D
        threshold = math.ceil((self.n - 1) * 0.75)
        if n_c >= threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_59(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    Logic:
    - First round: Cooperate.
    - Final round: Defect.
    - Stock Crisis (Stock < Capacity/n): Defect permanently.
    - Otherwise:
        - If all players cooperated in previous round: Cooperate.
        - If defectors present:
            - Project stock for next round assuming full cooperation.
            - If projected stock > (0.5 * capacity), Cooperate.
            - Else, Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_stock < self.capacity / self.n:
            return Action.D
        if current_round == 0:
            return Action.C
        last_action_bool = bool(history.my_actions[-1])
        last_opponent_coops = int(history.opponent_cooperators[-1])
        total_cooperators_prev = last_opponent_coops + (1 if last_action_bool else 0)
        if total_cooperators_prev == self.n:
            return Action.C
        s_remaining = current_stock - current_stock / 2.0
        if self.capacity == 0:
            return Action.D
        growth = 2.0 * s_remaining * (1.0 - s_remaining / self.capacity)
        s_next = min(s_remaining + growth, self.capacity)
        if s_next > self.capacity * 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_60(BaseStrategy):
    """
    Tit-for-Tat with Logistic Sustainability Threshold.
    
    Operates on a conditional cooperative basis, utilizing a trigger mechanism
    to enforce sustainability while maximizing extraction when stock permits.
    - Round 1: Always Cooperate.
    - Low Stock (S < Capacity/4): Always Cooperate to prevent collapse.
    - High Stock (S >= Capacity/4): Cooperate if at least n-1 players cooperated 
      last round, else Defect.
    - Final Round: Defect to maximize harvest, unless stock is negligible (<= 0), 
      in which case Cooperate to ensure non-zero payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D if current_stock > 1e-09 else Action.C
        if current_stock < capacity / 4.0:
            return Action.C
        last_opponents_k = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators = last_opponents_k + (1 if my_last_action == Action.C else 0)
        if total_cooperators >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_61(BaseStrategy):
    """
    Tit-for-Tat with a Forgiving Threshold strategy.
    
    This strategy encourages cooperative behavior while punishing collective greed.
    - Round 1: Always Cooperate.
    - Subsequent rounds:
        - Defect if stock is critically low (<= n * (stock/(2n)) = stock/2) or zero.
        - Otherwise, Cooperate if the majority cooperated in the last round.
        - If the stock shows significant recovery (increase >= 10% of capacity), prioritize Cooperate.
    - Final round: Always Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            self.last_stock = current_stock
            return Action.D
        if history.round_number == 0:
            self.last_stock = current_stock
            return Action.C
        prev_c_count = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_c = prev_c_count + (1 if my_last_action else 0)
        n = self.game_description.n_players
        if current_stock <= 0:
            self.last_stock = current_stock
            return Action.D
        if current_stock <= current_stock / 2.0:
            self.last_stock = current_stock
            return Action.D
        recovery_threshold = 0.1 * self.game_description.capacity
        if current_stock - self.last_stock > recovery_threshold:
            self.last_stock = current_stock
            return Action.C
        threshold = math.floor(n / 2) + 1
        self.last_stock = current_stock
        if prev_c_count >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_62(BaseStrategy):
    """
    Conditional Tit-for-Tat with Capacity Awareness strategy.
    
    Logic:
    - Round 1: Cooperate.
    - Final Round: Always Defect.
    - Capacity Criticality: If stock < 0.25 * Capacity, Defect (maximize remaining utility).
    - Cooperation Enforcement: If previous round had < n cooperators, punish by Defecting (Tit-for-Tat).
    - Recovery: Revert to Cooperate if stock >= 0.5 * Capacity, otherwise continue Defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < 0.25 * capacity:
            return Action.D
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_cooperators = history.opponent_cooperators[-1]
        k = last_opponent_cooperators + (1 if last_my_action else 0)
        if k < n:
            if current_stock >= 0.5 * capacity:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_SELFINTERESTED_63(BaseStrategy):
    """
    A conditional cooperation strategy that:
    1. Cooperates in the first round.
    2. Defects in the final round.
    3. Defects if the stock is below half capacity (sustainability threshold).
    4. Defects if any opponent defected in the previous round (tit-for-tat retaliation).
    5. Otherwise, cooperates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 2.0:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        opponents_who_cooperated = history.opponent_cooperators[-1]
        if opponents_who_cooperated < n_opponents:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_64(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Threshold Monitoring strategy.
    Maintains sustainable yields by monitoring previous round defection 
    and adjusting cooperation based on projected stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        total_rounds = self.game_description.n_rounds
        round_number = history.round_number
        if round_number == total_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.C
        last_c_opponents = history.opponent_cooperators[-1]
        my_last_action = bool(history.my_actions[-1])
        n_opponents = n - 1
        last_d_count = n_opponents - last_c_opponents + (0 if my_last_action else 1)
        if current_stock < capacity / 10.0:
            return Action.D
        if last_d_count == n - 1:
            return Action.D
        if last_d_count == 0:
            return Action.C
        cons_coop = (n - last_d_count) * (current_stock / (2.0 * n))
        cons_def = last_d_count * (current_stock / n)
        s_remaining = max(0.0, current_stock - (cons_coop + cons_def))
        if capacity > 0:
            growth = 2.0 * s_remaining * (1.0 - s_remaining / capacity)
            s_next = min(float(capacity), s_remaining + growth)
        else:
            s_next = 0.0
        if s_next > capacity / 4.0:
            if random.random() > last_d_count / float(n):
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_65(BaseStrategy):
    """
    Implements the 'Tit-for-Tat with Sustainable Threshold' (TFTS) strategy.
    
    Logic:
    - Maintains target stock level at 50% capacity for optimal regeneration.
    - If stock > 50%: Cooperates.
    - If stock <= 50%:
        - Final round: Defects.
        - Near-zero depletion (< 10% capacity): Defects.
        - Otherwise: Tit-for-Tat (Cooperate if previous round had 0 defectors, else Defect).
    - Round 1: Defaults to Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.target_stock = 0.5 * self.game_description.capacity
        self.critical_threshold = 0.1 * self.game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.critical_threshold:
            return Action.D
        if current_stock > self.target_stock:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        cooperating_opponents = history.opponent_cooperators[-1]
        my_last_action_was_c = history.my_actions[-1]
        if my_last_action_was_c:
            defecting_opponents = n_opponents - cooperating_opponents
        else:
            defecting_opponents = n_opponents - cooperating_opponents + 1
        if defecting_opponents == 0:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_66(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy with threshold stock maintenance.
    
    Logic Summary:
    1. First Round: Play Cooperate (C).
    2. Last Round: Play Defect (D).
    3. Intermediate Rounds: Play C only if:
       - Current stock >= capacity / 2 (Threshold Safety).
       - Cooperators in previous round >= n - 1 (Reciprocity).
       - Not previously entered a 'permanent defection' state due to prior threshold violation.
    4. Recovery: If Defect was played due to low reciprocity, but stock is safe, revert to C.
    5. Permanent Defection: If stock < threshold occurs, switch to Defect for all remaining rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = game_description.capacity / 2.0
        self.is_permanently_defected = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if self.is_permanently_defected:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.threshold:
            self.is_permanently_defected = True
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= self.game_description.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_67(BaseStrategy):
    """
    Sustainable Trigger-Tit-for-Tat:
    - Maintains target stock level by conditioning cooperation on aggregate opponent cooperation.
    - If S_t < capacity/2, acts as a 'last resort' by defecting to maximize remaining value.
    - If S_t >= capacity/2, cooperates only if all opponents cooperated in the previous round.
    - Always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        if round_t == 0:
            return Action.C
        if round_t == self.game_description.n_rounds - 1:
            return Action.D
        threshold = self.game_description.capacity / 2
        if current_stock < threshold:
            return Action.D
        c_obs = history.opponent_cooperators[-1]
        if c_obs == self.n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_68(BaseStrategy):
    """
    A strategy for the Common Pool Resource game based on conditional cooperation,
    punishment for insufficient cooperation, and aggressive extraction during scarcity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n_opponents = self.game_description.n_players - 1
        self.M = (n_opponents + 2 - 1) // 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.game_description.capacity / self.game_description.n_players:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        if k_prev < self.M:
            if current_stock < self.game_description.capacity / 2.0:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_SELFINTERESTED_69(BaseStrategy):
    """
    Implements a Triggered Tit-for-Tat strategy with stock-threshold sensitivity.
    Maintains cooperation if resources are sustainable and others are cooperating.
    Switches to punishment (defect) if defection is observed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_cooperative_state = True

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            self.is_cooperative_state = True
            return Action.C
        n = self.game_description.n_players
        num_others = n - 1
        prev_m = history.opponent_cooperators[-1]
        if self.is_cooperative_state and prev_m < num_others:
            self.is_cooperative_state = False
        elif not self.is_cooperative_state and prev_m == num_others:
            self.is_cooperative_state = True
        if current_stock < self.game_description.capacity / 4.0:
            return Action.D
        if not self.is_cooperative_state:
            return Action.D
        if current_stock <= 0:
            return Action.D
        remaining_after_c = current_stock / 2.0
        projected_stock = remaining_after_c + 2.0 * remaining_after_c * (1.0 - remaining_after_c / self.game_description.capacity)
        if projected_stock >= 0.8 * self.game_description.capacity:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_70(BaseStrategy):
    """
    Implements a "Conditional Sustainability" strategy. 
    Maintains cooperation as long as the resource stock is above a critical threshold (capacity/n)
    and opponents cooperated in the previous round. Punishes defection for one round,
    defects in the final round, and abandons cooperation if the resource is critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = self.game_description.capacity / self.game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.threshold:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        k = history.opponent_cooperators[-1]
        if k == n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_71(BaseStrategy):
    """
    Adaptive Sustainable Tit-for-Tat (ASTFT) Strategy.
    
    Conditionals:
    - Maintains sustainability by monitoring aggregate cooperation and stock depletion.
    - Round 1: Always Cooperate.
    - Rounds > 1: Cooperate if (Stock >= 90% Expected_Stock) AND (Opponents' cooperation >= target_coop).
    - Terminal Phase: If in final 3 rounds and Stock > 50% Capacity, Defect.
    - Edge Cases: Defect if Stock < 1.0 (Collapse).
    - Recovery: If Stock > 80% Capacity, enters 'probation' to test group cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.target_coop = self.n - 1
        self.probation_active = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 1.0:
            return Action.D
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        is_terminal = round_num >= self.r - 3
        if is_terminal:
            if current_stock > 0.5 * self.capacity:
                return Action.D
        if current_stock >= 0.8 * self.capacity:
            self.probation_active = True
        coop_obs = history.opponent_cooperators[-1]
        if self.probation_active:
            if coop_obs >= self.target_coop:
                self.probation_active = False
                return Action.C
            else:
                self.probation_active = False
                return Action.D
        if coop_obs >= self.target_coop:
            if current_stock >= 0.7 * self.capacity:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_72(BaseStrategy):
    """
    A Tit-for-Tat-based trigger strategy for the Common Pool Resource game.
    
    Logic:
    1. First Round: Cooperate (C).
    2. Last Round: Defect (D).
    3. Low Stock Recovery: If stock < capacity/2, Cooperate (C).
    4. General Rounds: If the number of cooperators in the previous round 
       is >= (n-1), Cooperate (C). Otherwise, Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 2.0:
            return Action.C
        if history.round_number == 0:
            return Action.C
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        last_round_opponents_cooperating = int(history.opponent_cooperators[-1])
        total_cooperators_prev = last_round_opponents_cooperating + (1 if my_last_action == Action.C else 0)
        if total_cooperators_prev >= self.game_description.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_73(BaseStrategy):
    """
    A resource-aware strategy for the Common Pool Resource game.
    It cooperates initially and in middle-game scenarios where the resource
    is sustainable and cooperation is sufficiently high, but defects in the
    final round or when the resource is threatened with collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.rounds = game_description.n_rounds
        self.previously_defected = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.previously_defected = False
            return Action.C
        t = history.round_number
        k_prev = int(history.opponent_cooperators[-1])
        i_cooperated = history.my_actions[-1]
        if t == self.rounds - 1:
            return Action.D
        k_other = k_prev
        d_other = self.n - 1 - k_other
        i_coop = 1 if i_cooperated else 0
        total_k = k_other + i_coop
        total_d = self.n - total_k
        c_total = total_k * (current_stock / (2 * self.n)) + total_d * (current_stock / self.n)
        s_rem = current_stock - c_total
        growth = 2 * s_rem * (1 - s_rem / self.capacity) if self.capacity > 0 else 0
        s_next = min(s_rem + growth, self.capacity)
        if s_next <= 0:
            self.previously_defected = True
            return Action.D
        if self.previously_defected and k_other >= (self.n - 1) / 2:
            self.previously_defected = False
            return Action.C
        if k_other >= math.floor(self.n / 2):
            self.previously_defected = False
            return Action.C
        else:
            self.previously_defected = True
            return Action.D

class Strategy_SELFINTERESTED_74(BaseStrategy):
    """
    Implements a Tit-for-Tat with Sustainability Threshold strategy.
    
    Logic Summary:
    - Round 0: Always Cooperate.
    - Final Round: Always Defect.
    - Intermediate Rounds:
        - Critical Failure Check: If stock < (capacity / n), prioritize Defect.
        - Stability Check: If all players cooperated in the previous round, Cooperate.
        - Otherwise: If stock > (capacity / 2), Cooperate (forgive/restore), else Defect (punish).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t_index = history.round_number
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        if t_index == n_rounds - 1:
            return Action.D
        if t_index == 0:
            return Action.C
        if current_stock < capacity / n_players:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        all_cooperated = k_prev == n_players - 1
        if all_cooperated:
            return Action.C
        elif current_stock > capacity / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_75(BaseStrategy):
    """
    A strategy that maintains a moving average of population cooperation.
    It cooperates initially and follows a reputation-based threshold for intermediate rounds.
    It defects in the final round and implements safety heuristics for low stock or collapsing populations.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 0.0
        self.recovery_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_total_coop_count = history.opponent_cooperators[-1] + prev_my_action
        prev_fraction = prev_total_coop_count / n
        all_prev_fractions = []
        for r in range(current_round):
            my_act = 1 if history.my_actions[r] else 0
            total_coop = history.opponent_cooperators[r] + my_act
            all_prev_fractions.append(total_coop / n)
        self.reputation = float(np.mean(all_prev_fractions))
        if history.opponent_cooperators[-1] == 0:
            self.reputation = 0.0
        if current_stock < self.game_description.capacity / 10:
            self.recovery_mode = True
            return Action.C
        if current_stock < self.game_description.capacity / 4:
            return Action.C
        if self.reputation > 0.8:
            return Action.C
        if 0.5 < self.reputation <= 0.8:
            return Action.C if random.random() < self.reputation else Action.D
        return Action.D

class Strategy_SELFINTERESTED_76(BaseStrategy):
    """
    Implements the Conditional Sustainability (Trigger-Grudger) strategy.
    
    Operates by initially cooperating to sustain the common pool resource.
    Monitors the pool level and opponent cooperation rates. If the pool drops
    below a critical threshold (25% of capacity) or if opponents fail to 
    cooperate sufficiently (rate < 0.5), it switches permanently to defection
    to maximize immediate payoff. Additionally, it ensures defection in the
    terminal round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_punishing = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if self.is_punishing:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        prev_round_cooperators = history.opponent_cooperators[-1]
        c_prev_rate = prev_round_cooperators / n_opponents if n_opponents > 0 else 0.0
        threshold = self.game_description.capacity * 0.25
        if current_stock < threshold or c_prev_rate < 0.5:
            self.is_punishing = True
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_77(BaseStrategy):
    """
    A Tit-for-Tat variant strategy for the Common Pool Resource game.
    Observes the cooperation level of the pool via stock dynamics and retaliates
    against over-consumption with defection, while incorporating a safety
    override for low stock levels and terminal defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = 1.1

    def _estimate_total_consumption(self, s_prev: float, s_curr: float) -> float:
        """
        Solves for total_consumption given S_prev and S_curr.
        S_curr = min(S_rem + 2 * S_rem * (1 - S_rem / capacity), capacity)
        Let f(S_rem) = S_rem + 2 * S_rem * (1 - S_rem / C) = 3*S_rem - 2*(S_rem^2)/C
        This is a quadratic equation: (2/C)*S_rem^2 - 3*S_rem + S_curr = 0
        """
        a = 2.0 / self.game_description.capacity
        b = -3.0
        c = s_curr
        delta = b ** 2 - 4 * a * c
        if delta < 0:
            return s_prev
        sqrt_delta = math.sqrt(delta)
        s_rem_1 = (-b + sqrt_delta) / (2 * a)
        s_rem_2 = (-b - sqrt_delta) / (2 * a)
        s_rem = max(s_rem_1, s_rem_2)
        if s_rem > s_prev:
            s_rem = min(s_rem_1, s_rem_2)
        return max(0.0, s_prev - s_rem)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.2 * self.game_description.capacity:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_78(BaseStrategy):
    """
    A strategy that balances long-term resource sustainability with opportunistic exploitation.
    It prioritizes cooperation when stock levels are low to ensure regeneration,
    cooperates when the group is stable, but switches to defection during endgame,
    resource abundance, or if the group enters a state of mass defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.total_rounds = self.game_description.n_rounds
        self.capacity = self.game_description.capacity
        self.s_min = self.capacity / 4.0
        self.s_collapse = self.capacity / 20.0
        self.s_abundance = 0.75 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        r_rem = self.total_rounds - t
        if t == 0:
            return Action.C
        if current_stock < self.s_collapse:
            return Action.D
        if r_rem < 3:
            return Action.D
        if current_stock < self.s_min:
            return Action.C
        if current_stock >= self.s_abundance:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        num_c = prev_opp_coop + (1 if prev_my_action else 0)
        num_d = self.n - num_c
        if num_d > num_c:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_79(BaseStrategy):
    """
    Triggered Conditional Cooperation with Anticipated Depletion.
    
    Logic:
    1. First round (index 0): Cooperate (C).
    2. Final round: Defect (D).
    3. Intermediate rounds:
       - Check if all opponents cooperated in the previous round.
       - If everyone cooperated: Cooperate (C).
       - If some defected: Check Sustainability Ratio (R = stock/capacity).
         - If R > 0.5: Attempt to restore via Cooperation (C).
         - If R <= 0.5: Defect (D) to extract value before collapse.
    
    Edge Handling:
    - Rapid Depletion: If stock < 0.1 * capacity, switch to Defect (D) regardless of others.
    - Non-cooperative Environment: If stock trends downward over the last 3 rounds, switch to Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if current_round >= 3:
            pass
        sustainability_ratio = current_stock / self.capacity
        prev_round = current_round - 1
        opponents_cooperated_prev = history.opponent_cooperators[prev_round]
        all_cooperated = opponents_cooperated_prev == self.n - 1
        if all_cooperated:
            return Action.C
        elif sustainability_ratio > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_80(BaseStrategy):
    """
    Implements a Grim Trigger strategy with a stock buffer.
    Cooperates initially and while stock is sufficient (>= 80% capacity) 
    or when opponent cooperation is robust (>= n-1).
    Defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.target_stock = 0.8 * self.capacity
        self.min_cooperators_required = max(1, self.n - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if current_stock < self.target_stock and prev_cooperators < self.min_cooperators_required:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_81(BaseStrategy):
    """
    A conditional cooperative strategy for the Common Pool Resource Game.
    Maintains a state machine ('Cooperative' or 'Defecting') to handle transitions based on observed
    opponent cooperation, while employing a threshold-based recovery mechanism and a
    critical depletion safety check.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.state = 0
        self.consecutive_full_coop = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.state = 0
            self.consecutive_full_coop = 0
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        t = history.round_number + 1
        if current_stock < self.capacity * 0.1:
            return Action.D
        if t == self.r:
            return Action.D
        my_prev_action = history.my_actions[-1]
        total_cooperators = prev_k + (1 if my_prev_action else 0)
        if total_cooperators == self.n:
            self.consecutive_full_coop += 1
        else:
            self.consecutive_full_coop = 0
        if self.state == 0:
            if total_cooperators < self.n:
                self.state = 1
                return Action.D
            return Action.C
        else:
            if self.consecutive_full_coop >= 2:
                self.state = 0
                return Action.C
            return Action.D

class Strategy_SELFINTERESTED_82(BaseStrategy):
    """
    A strategy for the Common Pool Resource game that balances long-term stock 
    sustainability with conditional retaliation and final-round defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if current_stock <= 0:
            return Action.D
        if t == 1:
            return Action.C
        if t == self.r:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if current_stock < 0.5 * self.capacity:
            return Action.D
        prev_my_action = history.my_actions[-1]
        n_prev_coop = history.opponent_cooperators[-1]
        total_cooperators_prev = n_prev_coop + (1 if prev_my_action else 0)
        total_defectors_prev = self.n - total_cooperators_prev
        too_many_defected = 0.5 * total_cooperators_prev + total_defectors_prev > 0.5 * self.n
        if too_many_defected:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_83(BaseStrategy):
    """
    Implements a Dynamic Tit-for-Tat with Stock-Threshold Trigger strategy.
    
    Logic:
    1. Always cooperate in the first round (Round 0).
    2. Always defect in the final round.
    3. If all players cooperated in the previous round, continue to cooperate.
    4. If any player defected in the previous round, punish (defect), 
       unless the stock is at least 50% of capacity, in which case, reset to cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_total = self.game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_count = history.opponent_cooperators[-1]
        total_cooperators_last_round = int(last_my_action) + last_opponent_count
        if total_cooperators_last_round == self.n_total:
            return Action.C
        threshold = 0.5 * self.game_description.capacity
        if current_stock >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_84(BaseStrategy):
    """
    A complex strategy for the Common Pool Resource Game:
    - Round 1: Always Cooperate.
    - Punishment Mode: Triggers if stock drops > 75% in a single round.
    - Persistent Defection Monitor: Switches to permanent Defect if opponents defect too often.
    - Reversion Logic: Resets to Cooperate after consistent cooperation.
    - Terminal Phase: End-game optimization based on stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_rounds_remaining = 0
        self.permanent_defect = False
        self.consecutive_low_cooperation = 0
        self.reversion_cooperation_streak = 0
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 0.0001:
            self.permanent_defect = True
            return Action.D
        if self.permanent_defect:
            return Action.D
        if history.round_number == 0:
            self.last_stock = current_stock
            return Action.C
        prev_round = history.round_number - 1
        k_prev = int(history.opponent_cooperators[-1])
        n = self.game_description.n_players
        n_opponents = n - 1
        if k_prev < n / 2:
            self.consecutive_low_cooperation += 1
        else:
            self.consecutive_low_cooperation = 0
        if self.consecutive_low_cooperation >= 3:
            self.permanent_defect = True
            return Action.D
        if k_prev == n_opponents:
            self.reversion_cooperation_streak += 1
        else:
            self.reversion_cooperation_streak = 0
        if self.reversion_cooperation_streak >= 2:
            self.punishment_rounds_remaining = 0
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock > self.game_description.capacity * 0.5:
                return Action.D
            else:
                if k_prev >= n_opponents * 0.75:
                    return Action.C
                return Action.D
        if current_stock < self.last_stock * 0.25:
            self.punishment_rounds_remaining = 2
        self.last_stock = current_stock
        if self.punishment_rounds_remaining > 0:
            self.punishment_rounds_remaining -= 1
            return Action.D
        if k_prev == n_opponents:
            return Action.C
        else:
            p = 1.0 - k_prev / max(1, n_opponents)
            if random.random() < p:
                return Action.D
            else:
                return Action.C

class Strategy_SELFINTERESTED_85(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with capacity thresholding:
    - Round 1: Always Cooperate.
    - Last Round: Always Defect.
    - Mid Rounds:
        - If stock < capacity/2: Cooperate (prioritize resource sustainability).
        - If stock >= capacity/2: 
            - If majority (>= n/2) cooperated previously: Cooperate.
            - Otherwise: Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.majority_threshold = math.ceil(self.game_description.n_players / 2)
        self.sustainability_threshold = self.game_description.capacity / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < self.sustainability_threshold:
            return Action.C
        else:
            prev_opp_coop = history.opponent_cooperators[-1]
            my_prev_action = history.my_actions[-1]
            total_coop = prev_opp_coop + (1 if my_prev_action == Action.C else 0)
            if total_coop >= self.majority_threshold:
                return Action.C
            else:
                return Action.D

class Strategy_SELFINTERESTED_86(BaseStrategy):
    """
    A Tit-for-Tat based strategy for the Common Pool Resource game.
    
    Phases:
    1. Cooperation Phase (Rounds 0 to r-2):
       - First round: Always Cooperate.
       - Subsequent rounds: 
         - If stock is critical (< capacity/n), prioritize survival by Cooperating.
         - Otherwise, mimic collective behavior: Cooperate if the number of 
           cooperators in the previous round was >= n/2, else Defect.
    2. Termination Phase (Final round):
       - Always Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        last_round_idx = self.r - 1
        if current_round_idx == last_round_idx:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < self.capacity / self.n:
            return Action.C
        k_last = history.opponent_cooperators[-1]
        my_action_last = 1 if history.my_actions[-1] else 0
        total_k = int(history.opponent_cooperators[-1] + my_action_last)
        if total_k >= self.n // 2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_87(BaseStrategy):
    """
    Implements a 'Contingent Sustainability' strategy for a Common Pool Resource Game.
    The strategy balances resource preservation with retaliatory punishment using
    tit-for-tat principles and threshold-based triggers for stock collapse prevention.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock >= 0.75 * self.capacity:
            return Action.C
        n_opponents = self.n - 1
        num_coop_opponents = history.opponent_cooperators[-1]
        num_defectors = n_opponents - num_coop_opponents
        if num_defectors == 0:
            return Action.C
        elif random.random() < num_defectors / self.n:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_88(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy for the Common Pool Resource game.
    Maximizes sustainable yield by cooperating when stock is healthy and others
    cooperate, while punishing defectors and extracting remaining value as the 
    stock depletes or the game ends.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.forced_to_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if round_idx == r - 1:
            return Action.D
        if current_stock < 0.25 * capacity:
            return Action.D
        if self.forced_to_defect:
            return Action.D
        if round_idx == 0:
            consumption = self.game_description.capacity / (2 * n)
            total_consumption = n * consumption
            remaining = self.game_description.capacity - total_consumption
            growth = 2 * remaining * (1 - remaining / self.game_description.capacity)
            next_stock = min(remaining + growth, self.game_description.capacity)
            if next_stock < self.game_description.capacity:
                return Action.D
            return Action.C
        prev_opponents_cooperated = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        if not prev_my_action:
            if prev_opponents_cooperated < n_opponents:
                self.forced_to_defect = True
                return Action.D
            return Action.C
        if prev_opponents_cooperated == n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_89(BaseStrategy):
    """
    Threshold-Based Tit-For-Tat with Sustainability Monitoring.
    
    This strategy monitors resource stock stability and the previous round's cooperation 
    count (k). It prioritizes long-term sustainability by cooperating when the pool 
    is robust or recovering, and defaults to defection when the pool is depleting, 
    the resource reaches critical levels, or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = game_description.capacity
        self.low_coop_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if t == 0:
            self.prev_stock = current_stock
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        k = history.opponent_cooperators[-1] + my_prev_action
        if t == r - 1:
            self.prev_stock = current_stock
            return Action.D
        critical_threshold = min(capacity / n, 0.2 * capacity)
        if current_stock < critical_threshold:
            self.prev_stock = current_stock
            return Action.D
        if k < n / 2:
            self.low_coop_counter += 1
        else:
            self.low_coop_counter = 0
        if self.low_coop_counter >= 2:
            self.prev_stock = current_stock
            self.low_coop_counter = 0
            return Action.D
        if current_stock < self.prev_stock:
            self.prev_stock = current_stock
            return Action.D
        threshold = n * (current_stock / capacity)
        self.prev_stock = current_stock
        if k >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_90(BaseStrategy):
    """
    Implements a sustainable Tit-for-Tat strategy with a stock-threshold trigger.
    
    Logic:
    1. Always cooperate in the first round.
    2. Assess sustainability using a projection model. If next-round stock is < capacity/4,
       prioritize resource preservation by cooperating.
    3. If stock is safe, use Tit-for-Tat based on the majority of opponents from the
       previous round.
    4. Terminal Phase (last 3 rounds): Shift to aggressive extraction if conditions permit.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == self.total_rounds - 2:
            if current_stock > self.capacity / 2:
                return Action.D
        S_t = current_stock
        n = self.n
        S_remaining = S_t - S_t / 2
        growth = 2 * S_remaining * (1 - S_remaining / self.capacity)
        S_next = min(S_remaining + growth, self.capacity)
        if S_next < self.capacity / 4:
            return Action.C
        prev_opp_coop_count = history.opponent_cooperators[-1]
        threshold = math.ceil((n - 1) / 2)
        if prev_opp_coop_count >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_91(BaseStrategy):
    """
    A modified Tit-for-Tat strategy for the Common Pool Resource game.
    
    Logic:
    - Round 0: Cooperate.
    - Final Round: Always defect.
    - Intermediate Rounds:
        - Defect if stock < 25% of capacity (scarcity).
        - Defect if any player defected in the previous round (unforgiving).
        - Otherwise, Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.game_description.capacity * 0.25:
            return Action.D
        if history.opponent_cooperators[-1] < self.game_description.n_players:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_92(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with resource-aware thresholds.
    - Initiates with cooperation.
    - In final round (r_rem == 0), always defects.
    - If stock < critical threshold (capacity/4), always cooperates to prevent collapse.
    - If close to end (r_rem < 3) and stock is safe, transition to defecting.
    - Otherwise, reciprocates cooperation based on the previous round's outcome.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.n_players = game_description.n_players
        self.tau = self.capacity / 4.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        rounds_remaining = self.total_rounds - 1 - current_round
        if current_round == 0:
            return Action.C
        if rounds_remaining == 0:
            return Action.D
        if current_stock < 1e-06:
            return Action.C
        if current_stock < self.tau:
            return Action.C
        if rounds_remaining < 3:
            return Action.D
        n_opponents = self.n_players - 1
        previous_opponents_cooperated = history.opponent_cooperators[-1]
        if previous_opponents_cooperated == n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_93(BaseStrategy):
    """
    Conditional Tit-for-Tat with Stock Protection.
    - Round 1: Cooperate.
    - Rounds 2 to r-1: 
        - If stock < 0.25 * capacity, Cooperate (Stock Protection).
        - Else, Cooperate if previous round opponent cooperation rate >= 0.5, else Defect.
    - Final Round: Always Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        prev_opp_coop_count = history.opponent_cooperators[-1]
        opp_coop_rate = prev_opp_coop_count / self.n_opponents
        if opp_coop_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_94(BaseStrategy):
    """
    A trigger-based, conditional cooperation strategy for the Common Pool Resource Game.
    
    Strategy Logic:
    1. First Round: Always Cooperate (C).
    2. Last Round: Always Defect (D).
    3. Critical Exhaustion: If stock < 0.25 * capacity, always Defect (D) to extract remaining value.
    4. Conditional Cooperation: If stock is sufficient, maintain cooperation if and only if
       the total number of cooperators in the previous round equaled n. If anyone defected,
       this strategy switches to Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_cooperators = history.opponent_cooperators[-1]
        total_cooperators_last_round = last_opponent_cooperators + (1 if last_my_action else 0)
        if total_cooperators_last_round == self.n:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_95(BaseStrategy):
    """
    Trigger-Based Sustainable Harvest (TBSH):
    Maintains cooperation while the stock is healthy and partners are cooperative.
    Defects when opponents defect, or if the stock reaches critical levels,
    or during the final three rounds if the stock is low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.s_crit = self.capacity / (2 * self.n)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.r
        if round_idx == total_rounds - 1:
            return Action.D
        if current_stock < self.s_crit:
            return Action.D
        if total_rounds - round_idx <= 3 and current_stock < 0.5 * self.capacity:
            return Action.D
        if round_idx == 0:
            return Action.C
        last_k = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        if last_k == self.n - 1:
            return Action.C
        if not my_last_action:
            if current_stock >= 0.5 * self.capacity:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFINTERESTED_96(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with a sustainability threshold.
    Maintains cooperation as long as stock levels are sustainable and the 
    group cooperates, but switches to defection if the stock collapses, 
    the group fails to cooperate, or the game is in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = math.ceil(self.n / 2)
        self.all_defect_counter = 0
        self.last_stock = float(self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            self.last_stock = current_stock
            return Action.C
        if round_idx == self.r - 1:
            return Action.D
        k = history.opponent_cooperators[-1]
        if k == 0:
            self.all_defect_counter += 1
        else:
            self.all_defect_counter = 0
        sudden_drop = False
        if self.last_stock > 0:
            drop_percentage = (self.last_stock - current_stock) / self.last_stock
            if drop_percentage > 0.5:
                sudden_drop = True
        self.last_stock = current_stock
        if self.all_defect_counter >= 2:
            return Action.D
        if sudden_drop:
            return Action.D
        if current_stock < 0.2 * self.capacity:
            return Action.D
        if current_stock < 0.5 * self.capacity:
            return Action.D
        if k >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_97(BaseStrategy):
    """
    Sustainable Tit-for-Tat with Stock Protection.
    
    This strategy attempts to maintain the common pool capacity by cooperating, 
    but adopts aggressive defection if the stock falls below critical levels or 
    if opponents show signs of aggressive exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        prev_defectors = self.n_opponents - prev_cooperators
        if current_stock <= self.game_description.capacity / self.game_description.n_players:
            return Action.D
        threshold = (self.game_description.n_players - 1) / 2
        if prev_defectors >= threshold:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_98(BaseStrategy):
    """
    A conditional, history-dependent strategy for the Common Pool Resource game.
    Implements a grim-trigger mechanism with salvage operations and a forgiveness clause.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.salvage_threshold = 0.1 * self.game_description.capacity
        self.forgiveness_threshold = 0.5 * self.game_description.capacity
        self.last_action_was_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        if current_round == 1:
            self.last_action_was_defect = False
            return Action.C
        if current_round == total_rounds:
            self.last_action_was_defect = True
            return Action.D
        if current_stock < self.salvage_threshold:
            self.last_action_was_defect = True
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        opp_cooperators = history.opponent_cooperators[-1]
        total_cooperators = opp_cooperators + my_prev_action
        if self.last_action_was_defect:
            if current_stock >= self.forgiveness_threshold and total_cooperators == n:
                self.last_action_was_defect = False
                return Action.C
            else:
                self.last_action_was_defect = True
                return Action.D
        if total_cooperators == n:
            self.last_action_was_defect = False
            return Action.C
        else:
            self.last_action_was_defect = True
            return Action.D

class Strategy_SELFINTERESTED_99(BaseStrategy):
    """
    Threshold-Trigger Adaptive Conservation Strategy:
    - Round 1: Cooperate.
    - Last Round: Defect.
    - Adaptive logic based on current stock levels and opponent behavior.
    - Prioritizes resource recovery when stock is critically low.
    - Defects if opponents show signs of unsustainable behavior or total defection.
    - Maintains cooperation when near capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.recovery_rounds_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock == 0:
            return Action.D
        if current_stock < 0.1 * self.game_description.capacity:
            if self.recovery_rounds_counter < 3:
                self.recovery_rounds_counter += 1
                return Action.C
            else:
                return Action.D
        else:
            self.recovery_rounds_counter = 0
        if current_stock >= 0.9 * self.game_description.capacity:
            return Action.C
        prev_opp_C = history.opponent_cooperators[-1]
        n = self.game_description.n_players
        if prev_opp_C == 0:
            return Action.D
        threshold_coop = (n - 1) // 2
        capacity = self.game_description.capacity
        if current_stock > capacity / 4 and prev_opp_C >= threshold_coop:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_100(BaseStrategy):
    """
    Threshold-Based Tit-for-Tat with Terminal Defection.
    
    Logic:
    1. Round 1: Always Cooperate (C) to establish baseline.
    2. Last Round: Always Defect (D) to maximize terminal payoff.
    3. Intermediate Rounds:
        - If current_stock < capacity / 2: Defect (D) to prioritize survival/recovery.
        - If current_stock >= capacity / 2:
            - If n == 2: Strict Tit-for-Tat (Cooperate if opponent cooperated, else Defect).
            - If n > 2: Cooperate (C) if previous cooperation count >= n - 2, else Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 2:
            return Action.D
        if self.game_description.n_players == 2:
            if history.opponent_cooperators[-1] == 1:
                return Action.C
            return Action.D
        if history.opponent_cooperators[-1] >= self.game_description.n_players - 2:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_101(BaseStrategy):
    """
    A strategy that implements a conditional cooperative approach for the Common Pool Resource Game.
    
    Logic:
    - Round 0: Always cooperate (C).
    - Final Round (t = r-1): Always defect (D).
    - Thresholds: 
        - Cooperate if stock > capacity / 2.
        - Defect if the number of defecting opponents in the previous round 
          is >= n // 2.
    - Otherwise: Cooperate (C).
    
    This strategy acts as a 'conditional cooperator' that switches to defect 
    if the resource is threatened or if others are over-harvesting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.k_tol = self.n_players // 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if round_idx == total_rounds - 1:
            return Action.D
        if current_stock <= capacity / 2.0:
            return Action.D
        if round_idx > 0:
            n_opponents = self.n_players - 1
            prev_cooperators = history.opponent_cooperators[-1]
            prev_defectors = n_opponents - prev_cooperators
            if prev_defectors >= self.k_tol:
                return Action.D
        return Action.C

class Strategy_SELFINTERESTED_102(BaseStrategy):
    """
    Implements a Sustainable Tit-for-Tat strategy.
    
    This strategy defaults to cooperation, but punishes defection by the opponent 
    group unless the resource stock is critically low. In the final round, it 
    prioritizes immediate payoff over sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.critical_threshold = 0.25 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D if current_stock > 0 else Action.C
        if history.round_number == 0:
            return Action.C
        prev_opp_coop_count = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if prev_opp_coop_count == n_opponents:
            return Action.C
        if current_stock <= self.critical_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_103(BaseStrategy):
    """
    Implements a 'Tit-for-Tat with Sustainability Threshold' strategy.
    
    The strategy operates on three primary layers:
    1. Initial Cooperation: Always starts by cooperating to maximize growth.
    2. Crisis Management: If the resource stock falls below the number of players (n), 
       prioritizes immediate consumption (defect) over sustainability.
    3. Reciprocal Threshold: In steady states, defects unless a high majority 
       (>= 80%) of opponents cooperated in the previous round.
    4. Terminal Defection: Always defects in the final round as there is no 
       future stock growth benefit.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        n_opponents = n_players - 1
        if current_round == n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < n_players:
            return Action.D
        prev_opponents_C = history.opponent_cooperators[-1]
        if n_opponents > 0:
            cooperation_ratio = prev_opponents_C / n_opponents
        else:
            cooperation_ratio = 1.0
        if cooperation_ratio >= 0.8:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_104(BaseStrategy):
    """
    Tit-for-Tat with Resource-Aware Thresholding Strategy.
    Balances cooperation with resource sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_retaliating = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        capacity = self.game_description.capacity
        n_opponents = self.game_description.n_players - 1
        if current_stock < 0.1 * capacity:
            return Action.C
        last_round = history.round_number - 1
        cooperators_observed = history.opponent_cooperators[last_round]
        c_rate = cooperators_observed / n_opponents if n_opponents > 0 else 1.0
        if current_stock < 0.2 * capacity:
            return Action.C
        if self.is_retaliating:
            self.is_retaliating = False
            return Action.D
        if c_rate < 0.5 and current_stock < 0.8 * capacity:
            self.is_retaliating = True
            return Action.D
        if c_rate >= 0.5 or current_stock >= 0.5 * capacity:
            return Action.C
        return Action.C

class Strategy_SELFINTERESTED_105(BaseStrategy):
    """
    Tit-for-Tat with Sustainable Threshold.
    
    This strategy aims to maximize long-term yield by cooperating to maintain stock levels.
    It defaults to cooperation, but monitors the number of cooperators from the previous round
    and the current stock level to decide whether to defect due to looming stock collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.majority_threshold = math.floor(self.game_description.n_players / 2) + 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        r = self.game_description.n_rounds
        n = self.game_description.n_players
        if t == r - 1:
            return Action.D
        if t == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        k_prev = history.opponent_cooperators[-1] + my_prev_coop
        if current_stock <= self.game_description.capacity * 0.25:
            return Action.D
        if k_prev < self.majority_threshold:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_106(BaseStrategy):
    """
    Implements a conditionally cooperative strategy for the Common Pool Resource game.
    The strategy maintains cooperation as long as the resource is sustainable and 
    all other players are cooperating. It defects in the final round, or if 
    the resource is degrading or if any betrayal (defection) was observed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.r:
            return Action.D
        if current_round == 1:
            return Action.C
        my_last_action = history.my_actions[-1]
        opponents_cooperated_count = history.opponent_cooperators[-1]
        total_cooperators_last_round = opponents_cooperated_count + (1 if my_last_action else 0)
        if total_cooperators_last_round < self.n:
            return Action.D
        if current_stock < self.capacity / self.n:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_107(BaseStrategy):
    """
    Tit-for-Tat variant with state-sensitive thresholds.
    - Round 1: Always Cooperate.
    - Last Round: Always Defect.
    - Emergency: Defect if stock < 5% of capacity.
    - Reciprocity: Defect if opponents did not fully cooperate (n-1), unless recovering.
    - Recovery: If in 'Defect loop', re-enter Cooperation if stock >= 50% capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.in_defect_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 0.05 * self.game_description.capacity:
            self.in_defect_mode = True
            return Action.D
        if history.round_number == 0:
            return Action.C
        if self.in_defect_mode:
            if current_stock >= 0.5 * self.game_description.capacity:
                self.in_defect_mode = False
            else:
                return Action.D
        n_opponents = self.game_description.n_players - 1
        last_cooperators = history.opponent_cooperators[-1]
        if last_cooperators == n_opponents:
            return Action.C
        else:
            self.in_defect_mode = True
            return Action.D

class Strategy_SELFINTERESTED_108(BaseStrategy):
    """
    Implements a Conditional Sustainability Tit-for-Tat strategy.
    
    This strategy maintains the highest sustainable stock level while retaliating 
    against defection. It cooperates in the first round and emergency situations 
    (low stock), reciprocates cooperation if opponents meet a threshold, 
    and defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.target = self.n - 1
        self.stock_crit = self.capacity / (2 * self.n)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.total_rounds - 1:
            return Action.D
        if current_stock < self.stock_crit:
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        if prev_k >= self.target:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_109(BaseStrategy):
    """
    A strategy that implements conditional cooperation based on pool stock sustainability.
    
    Rules:
    1. First round: Always Cooperate (C).
    2. Terminal round: Always Defect (D).
    3. Emergency: If stock < 0.25 * capacity, always Defect (D).
    4. Steady State (Reciprocity):
       - Observes the previous round's total consumption relative to the stock.
       - If total consumption in previous round > 50% of previous stock, treat as unsustainable 
         and Defect (D) to retaliate.
       - Otherwise, Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if round_idx == total_rounds - 1:
            self.prev_stock = current_stock
            return Action.D
        if current_stock < capacity * 0.25:
            self.prev_stock = current_stock
            return Action.D
        if round_idx == 0:
            self.prev_stock = current_stock
            return Action.C
        n_coop_opponents = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators = n_coop_opponents + (1 if my_last_action else 0)
        total_defectors = n - total_cooperators
        c_share = self.prev_stock / (2 * n)
        d_share = self.prev_stock / n
        total_consumption = total_cooperators * c_share + total_defectors * d_share
        is_unsustainable = total_consumption > 0.5 * self.prev_stock
        self.prev_stock = current_stock
        if is_unsustainable:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_110(BaseStrategy):
    """
    Implements a modified Tit-for-Tat strategy with forgiveness, emergency stock preservation, 
    and persistent defection detection in a common pool resource game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.defection_streak = 0
        self.is_predatory_environment = False
        self.in_recovery_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        k = history.opponent_cooperators[-1]
        n_opponents = self.desc.n_players - 1
        if k < n_opponents:
            self.defection_streak += 1
        else:
            self.defection_streak = 0
        if self.defection_streak >= 3:
            self.is_predatory_environment = True
        if current_stock < 0.2 * self.desc.capacity:
            self.in_recovery_mode = True
        elif current_stock >= 0.5 * self.desc.capacity:
            self.in_recovery_mode = False
        if self.in_recovery_mode:
            return Action.C
        if current_stock < 1e-06:
            return Action.C
        if self.is_predatory_environment:
            return Action.D
        if k == n_opponents:
            return Action.C
        if current_stock > 0.9 * self.desc.capacity and k == n_opponents - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_111(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Threshold Depletion Control.
    
    This strategy uses a combination of reciprocal cooperation and stock-level safety overrides:
    1. Terminal Phase: Always defect in the final round.
    2. Sustainability Override: If stock < 0.25 * capacity, force defect. 
       Revert to baseline only if stock >= 0.5 * capacity.
    3. Baseline Policy: Tit-for-tat based on the majority of the group.
       Cooperate if >= n/2 players cooperated in the previous round, else Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.override_active = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if round_idx == r - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if self.override_active:
            if current_stock >= 0.5 * capacity:
                self.override_active = False
        if not self.override_active and current_stock < 0.25 * capacity:
            self.override_active = True
        if self.override_active:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponents_coop = history.opponent_cooperators[-1]
        my_prev_coop_val = 1 if last_my_action else 0
        k = last_opponents_coop + my_prev_coop_val
        threshold = math.ceil(n / 2)
        if k >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_112(BaseStrategy):
    """
    A conditional cooperation strategy that maintains stock at capacity by cooperating
    if all players cooperated in the previous round. It punishes defection by switching
    to Retaliate mode (defecting) until the stock recovers or the final round is reached.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + my_last_action_val
        n = self.game_description.n_players
        if total_cooperators == n:
            return Action.C
        critical_threshold = self.game_description.capacity / 2.0
        if current_stock < critical_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_113(BaseStrategy):
    """
    Threshold-Based Tit-for-Tat strategy for the Common Pool Resource Game.
    
    This strategy balances long-term sustainability with immediate payoff maximization.
    It cooperates by default but switches to defection if the majority of the
    population is not cooperating. It includes a forgiveness mechanism when
    stock levels are high to attempt to re-establish a cooperative equilibrium,
    and it proactively defects in the final round and during stock depletion scenarios.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        collapse_threshold = self.game_description.capacity / (2 * self.game_description.n_players)
        if current_stock < collapse_threshold:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock >= self.game_description.capacity * 0.75:
            return Action.C
        k = history.opponent_cooperators[-1]
        if self.n_opponents <= 0:
            return Action.D
        cooperation_ratio = k / self.n_opponents
        if cooperation_ratio >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_114(BaseStrategy):
    """
    Grim-Trigger with Stock-Dependent Forgiveness strategy.
    
    Maintains a cooperation state that starts as True. If any round ends where 
    not all players cooperated, it transitions to False. If False, the player 
    defects, unless the stock is critically low (attempting recovery) or 
    it is the final round (where it defects for maximum utility).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.cooperation_status = True
        self.s_crit = self.capacity * (1 / (2 * self.n))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.cooperation_status = True
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        total_coop_prev = prev_opp_coop + (1 if prev_my_action else 0)
        if self.cooperation_status:
            if total_coop_prev < self.n:
                self.cooperation_status = False
        elif current_stock < self.s_crit:
            pass
        if current_stock < self.capacity / 10:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if self.cooperation_status:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_115(BaseStrategy):
    """
    Implements a conditional sustainability strategy that balances cooperative
    extraction with resource preservation based on population-wide behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        if current_idx == total_rounds - 1:
            return Action.D
        if current_idx == 0:
            return Action.C
        if current_stock < capacity * 0.1:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        threshold = n_players // 2
        if k_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_116(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Resource Thresholds strategy.
    
    This strategy prioritizes long-term resource sustainability. It starts by cooperating
    to test the environment. In subsequent rounds, it switches to unconditional 
    cooperation if the stock is critically low (< 25% of capacity) to prevent 
    collapse. If the stock is healthy, it adopts a tit-for-tat approach, cooperating
    only if all opponents cooperated in the previous round. In the final round, 
    it always defects to maximize immediate payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock <= 0:
            return Action.D
        if current_stock < self.capacity / 4.0:
            return Action.C
        last_opponents_cooperated = history.opponent_cooperators[-1]
        if last_opponents_cooperated >= self.n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_117(BaseStrategy):
    """
    Conditional Sustainability (CS) Strategy.
    
    A trigger-based strategy designed for shared resource pools:
    1. Always Cooperate in the first round.
    2. Always Defect in the final round.
    3. If stock is critically low (< 25% capacity), Defect to maximize immediate extraction.
    4. If previous round was fully cooperative (no defectors), Cooperate.
    5. If previous round had defectors but stock has recovered (>= 80% capacity), apply forgiveness and Cooperate.
    6. Otherwise, Defect (punishment/grim trigger).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            return Action.D
        num_opponents = self.game_description.n_players - 1
        cooperating_opponents = history.opponent_cooperators[-1]
        opponents_defected_prev_round = num_opponents - cooperating_opponents
        if current_stock < 0.25 * capacity:
            return Action.D
        if opponents_defected_prev_round == 0:
            return Action.C
        if current_stock >= 0.8 * capacity:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_118(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Threshold Depletion Control.
    
    This strategy maintains cooperation based on resource stock levels and
    the collective cooperation of opponents. It features an aggressive 
    extraction mode for terminal rounds or depleted stock, and a tit-for-tat
    mechanism when the resource is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.d_threshold = self.capacity / (2 * self.n)
        self.cooperation_threshold = math.floor((self.n - 1) * 0.75)
        self.collapsed = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_stock < self.capacity * 0.1:
            self.collapsed = True
        if self.collapsed:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        if current_stock < self.d_threshold:
            return Action.D
        if history.opponent_cooperators[-1] >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_119(BaseStrategy):
    """
    Implements an Adaptive Tit-for-Tat with Sustainability Threshold.
    - Cooperates in the first round.
    - Defects in the final round.
    - Mid-game: Cooperates only if stock >= 50% capacity AND
      at least 50% of the population cooperated in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.n_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opp_cooperators = history.opponent_cooperators[-1]
        my_last_val = 1 if last_my_action else 0
        total_cooperators = last_opp_cooperators + my_last_val
        cooperation_ratio = total_cooperators / self.n_players
        is_stock_sustainable = current_stock >= 0.5 * self.capacity
        is_population_cooperative = cooperation_ratio >= 0.5
        if is_stock_sustainable and is_population_cooperative:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_120(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Last Round (r): Always Defect (D).
    - Other Rounds:
        - If Stock > capacity / 2: Cooperate (C).
        - If Stock <= capacity / 2:
            - If no defectors in previous round (k=0): Cooperate (C).
            - If defectors present (k>0): Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock > capacity / 2.0:
            return Action.C
        num_opponents = n_players - 1
        num_cooperating_opponents = history.opponent_cooperators[-1]
        num_defecting_opponents = num_opponents - num_cooperating_opponents
        if num_defecting_opponents == 0:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_121(BaseStrategy):
    """
    A strategy that maintains cooperation as long as a minimum consensus (n-1 cooperators)
    is met, aiming for sustainable stock levels. It defaults to defection if consensus
    fails, and aggressively defects in the final round to maximize final utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        if last_my_action:
            total_cooperators_prev_round = last_opponent_coops + 1
        else:
            total_cooperators_prev_round = last_opponent_coops
        if total_cooperators_prev_round >= self.threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_122(BaseStrategy):
    """
    Implements a Tit-for-Tat with Forgiveness and Resource Stewardship strategy.
    
    Decision Hierarchy:
    1. Last Round: Defect to maximize immediate payoff.
    2. Round 1: Cooperate to build initial resource base.
    3. Critical Stock: Defect if stock < 50% capacity to extract remaining value.
    4. Reciprocity: Cooperate if >= 75% of opponents cooperated in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < 0.5 * self.game_description.capacity:
            return Action.D
        num_opponents = self.game_description.n_players - 1
        threshold = math.floor(0.75 * num_opponents)
        k_prev = history.opponent_cooperators[-1]
        if k_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_123(BaseStrategy):
    """
    A Conditional Tit-for-Tat strategy with Sustainability Constraints.
    Prioritizes sustainability, punishes exploitation based on thresholding,
    and switches to short-term greed in terminal phases or collapse scenarios.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.s_crit = 0.2 * self.capacity
        self.in_punishment_mode_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_r = history.round_number - 1
        num_cooperators = history.opponent_cooperators[prev_r]
        my_prev_action = history.my_actions[prev_r]
        if my_prev_action:
            d_prev = self.n - 1 - num_cooperators
        else:
            d_prev = self.n - 1 - num_cooperators + 1
        if d_prev > self.n / 2:
            self.in_punishment_mode_rounds = 2
        if self.in_punishment_mode_rounds > 0:
            self.in_punishment_mode_rounds -= 1
            return Action.D
        if self.n == 2:
            if d_prev > 0:
                return Action.D
            return Action.C
        if current_stock > 0.6 * self.capacity:
            return Action.C
        if d_prev == 0:
            return Action.C
        if current_stock <= self.s_crit:
            return Action.D
        if current_stock > self.s_crit:
            threshold = d_prev / self.n
            if random.random() < threshold:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_SELFINTERESTED_124(BaseStrategy):
    """
    Implements Conditional Sustainability Equilibrium:
    - Cooperates in the first round to initiate a stable pool.
    - Defects in the final round as there is no future utility.
    - Defects if stock is below half capacity to maximize recovery of remaining assets.
    - Reciprocates behavior: Defects if any opponent defected in the previous round, 
      otherwise Cooperates if the pool is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.game_description.capacity / 2:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        prev_cooperators = history.opponent_cooperators[-1]
        prev_defectors = n_opponents - prev_cooperators
        if prev_defectors == 0:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_125(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Thresholding.
    
    This strategy prioritizes sustainability:
    - Initially cooperates.
    - Monitors common pool stock; if it falls below 25% of capacity, it switches to 
      extraction (Defect) to maximize immediate payoff before potential collapse.
    - Reciprocates cooperation if all other players cooperated in the previous round.
    - Always defects in the final round to maximize payoff when future growth is irrelevant.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_total = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        r_remaining = n_rounds - current_round
        if current_round == 0:
            return Action.C
        if r_remaining == 1:
            return Action.D
        if current_stock < capacity / 4:
            return Action.D
        c_opponents = history.opponent_cooperators[-1]
        if c_opponents >= n_total - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_126(BaseStrategy):
    """
    A Tit-for-Tat variant that balances sustainability and reciprocity.
    It cooperates initially and continues cooperation if the stock is healthy and 
    the collective behavior of opponents remains cooperative. It defects if the 
    stock hits critical levels, if the pool is being over-exploited, or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number + 1
        if current_round_idx == self.r:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / 4.0:
            return Action.D
        last_num_opp_coop = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        total_last_round_cooperators = last_num_opp_coop + (1 if last_my_action else 0)
        if total_last_round_cooperators < self.n / 2.0:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_127(BaseStrategy):
    """
    Tit-for-Tat with Forgiving Resilience.
    This strategy focuses on collaborative resource management by:
    1. Cooperating in the first round.
    2. Defecting in the final round.
    3. Maintaining a 'critical threshold' check to force cooperation when resources are low.
    4. Engaging in reciprocating cooperation (Tit-for-Tat) when resources are safe,
       allowing for one defector (tolerate n-1 cooperators).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if t == r - 1:
            return Action.D
        if current_stock <= capacity / 4.0:
            return Action.C
        if current_stock >= capacity * 0.95:
            return Action.C
        k = history.opponent_cooperators[-1]
        if k >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_128(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy for the Common Pool Resource game.
    
    Logic:
    1. First round: Cooperate (Action.C).
    2. Last round: Defect (Action.D).
    3. If current stock < 20% of capacity: Cooperate to prevent extinction.
    4. Otherwise: Tit-for-Tat based on whether the number of cooperators 
       in the previous round was >= (n-1).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.stock_threshold = 0.2 * game_description.capacity
        self.threshold_cooperators = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.stock_threshold:
            return Action.C
        prev_round_cooperators = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = prev_round_cooperators + my_prev_action
        if total_prev_cooperators >= self.threshold_cooperators:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_33(BaseStrategy):
    """
    A Tit-for-Tat with Sustainability Constraints strategy.
    
    This strategy prioritizes long-term resource viability by monitoring stock levels
    against a sustainability threshold (50% of capacity).
    - In the final round, it always defects.
    - If the current stock is below the sustainability threshold, it cooperates to
      allow the resource to regenerate.
    - If the stock is robust, it uses reciprocal opportunism: it cooperates if the 
      majority of opponents cooperated in the previous round, and defects otherwise.
    - It always cooperates in the first round to build initial trust.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.s_min = game_description.capacity * 0.5
        self.n_opponents = game_description.n_players - 1
        self.cooperation_threshold = self.n_opponents * 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.s_min:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        if last_round_cooperators > self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_34(BaseStrategy):
    """
    Implements a "Tit-for-Tat with Forgiveness" strategy for the Common Pool Resource Game.
    The strategy cooperates initially, then tracks the number of cooperating opponents.
    It utilizes a self-correcting mechanism: if defecting, it tests the cooperative 
    threshold to decide whether to revert to cooperation. Terminal behavior triggers
    defection if stock is low or the game is ending.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if round_idx == total_rounds - 1:
            return Action.D
        if round_idx == total_rounds - 2 and current_stock < capacity / 2:
            return Action.D
        if round_idx == 0:
            return Action.C
        k_observed = int(history.opponent_cooperators[-1])
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        if round_idx == total_rounds - 2:
            if k_observed < self.n_opponents:
                return Action.D
            return Action.C
        if my_last_action == Action.D:
            if k_observed > self.n / 2:
                return Action.C
            else:
                return Action.D
        elif k_observed >= self.n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_35(BaseStrategy):
    """
    An adaptive Tit-for-Tat variant strategy for the Common Pool Resource Game.
    Prioritizes mutual cooperation when resources are abundant and trusts are maintained,
    while aggressively switching to self-interest (Defection) when the common pool is 
    endangered or in the endgame phase to maximize short-term yield.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.buffer = 2
        self.threshold_factor = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        n_opponents = n - 1
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if rounds_remaining < self.buffer:
            return Action.D
        threshold = self.game_description.capacity * self.threshold_factor
        if current_stock <= threshold:
            return Action.D
        last_round_opponents_cooperated = int(history.opponent_cooperators[-1])
        if last_round_opponents_cooperated >= n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_36(BaseStrategy):
    """
    Implements a Sustainable Tit-for-Tat with Exploitation strategy.
    
    Logic:
    1. Always cooperate (C) in the first round.
    2. Always defect (D) in the final round to maximize final extraction.
    3. If current stock is below 25% of capacity (critical crisis), defect (D) to salvage value.
    4. If any opponents defected in the previous round, defect (D) to punish/balance payoff.
    5. Otherwise, cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n_total = self.game_description.n_players
        capacity = self.game_description.capacity
        if round_idx == total_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < 0.25 * capacity:
            return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        n_opponents = n_total - 1
        if last_round_cooperators < n_opponents:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_37(BaseStrategy):
    """
    Implements a resource-conscious strategy that balances greedy extraction 
    with sustainability thresholds. It defaults to defection in early and 
    terminal phases but enforces strict cooperation when stock levels 
    approach extinction or when opponents exhibit aggressive consumption 
    during fragile stock states.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.capacity = self.game_description.capacity
        self.threshold_sustainability = self.capacity * 0.6
        self.threshold_danger = self.capacity * 0.2
        self.threshold_fragile_upper = self.threshold_sustainability * 0.8

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.D
        if round_idx == self.r - 1:
            return Action.D
        n_opponents = self.n - 1
        coop_prev = history.opponent_cooperators[-1]
        k_D_prev = n_opponents - coop_prev
        if current_stock < self.threshold_danger:
            return Action.C
        if current_stock >= self.threshold_sustainability:
            if k_D_prev < self.n / 2:
                return Action.D
            else:
                return Action.C
        if self.threshold_danger <= current_stock < self.threshold_sustainability:
            if k_D_prev > 0:
                return Action.C
            elif current_stock > self.threshold_fragile_upper:
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_38(BaseStrategy):
    """
    Tit-for-tat with regenerative thresholding.
    
    Logic:
    1. First round: Always Cooperate (C) to build stock.
    2. Final round: Always Defect (D) to maximize utility.
    3. Intermediate rounds:
       - If stock is < 20% of capacity: Defect (D) to salvage utility before collapse.
       - If stock >= 60% of capacity (Regeneration Threshold):
         - If previous round's cooperation count >= 75% of n: Cooperate (C).
         - Else: Defect (D) (punish/protect against depletion).
       - If stock is between 20% and 60% of capacity:
         - If stock < 10% of capacity (Critical Floor): Defect (D).
         - Else: Cooperate (C) to attempt recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if current_stock < 0.2 * self.capacity:
            return Action.D
        threshold = 0.6 * self.capacity
        prev_my_action = Action.C if history.my_actions[-1] else Action.D
        prev_coop_count = history.opponent_cooperators[-1] + (1 if prev_my_action == Action.C else 0)
        if current_stock >= threshold:
            if prev_coop_count >= math.floor(0.75 * self.n):
                return Action.C
            else:
                return Action.D
        else:
            if current_stock < 0.1 * self.capacity:
                return Action.D
            return Action.C

class Strategy_OPPORTUNISTIC_39(BaseStrategy):
    """
    Opportunistic Nuance Strategy:
    - Initiates with cooperation to build stock.
    - Monitors aggregate cooperation (rho).
    - Transitions to Defect if collective cooperation is low (< 0.7) or in the final round.
    - Prioritizes Cooperation if stock hits critical levels (<= 20% capacity).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock <= self.game_description.capacity * 0.2:
            return Action.C
        my_prev_actions = history.my_actions.astype(np.int_)
        total_cooperators_history = np.sum(my_prev_actions + history.opponent_cooperators)
        total_possible = self.game_description.n_players * round_idx
        rho = total_cooperators_history / total_possible
        if rho >= 0.7:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_40(BaseStrategy):
    """
    A conditional tit-for-tat strategy focused on sustainable yield maximization.
    Transitions from cooperative maintenance to aggressive harvesting as the temporal horizon shortens.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.desc = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.cap = game_description.capacity
        self.threshold_coop = math.ceil(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock >= 0.95 * self.cap:
            return Action.D
        if current_stock < self.cap / (2 * self.n):
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            return Action.D
        if round_idx == self.r - 2:
            if current_stock >= 0.5 * self.cap:
                return Action.D
            prev_c = history.opponent_cooperators[-1]
            return Action.C if prev_c >= self.threshold_coop else Action.D
        prev_c = history.opponent_cooperators[-1]
        if current_stock < 0.8 * self.cap or prev_c >= self.threshold_coop:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_41(BaseStrategy):
    """
    A tit-for-tat-based opportunistic strategy designed to maximize extraction while
    maintaining the stock level required for future exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < 0.001 * self.capacity:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        prev_round_cooperators = history.opponent_cooperators[-1] + my_prev_action
        prev_round_defectors = self.n - prev_round_cooperators
        if current_stock < 0.5 * self.capacity:
            if prev_round_defectors > self.n // 2:
                return Action.C
        if current_stock > 0.75 * self.capacity:
            if prev_round_defectors == 0:
                return Action.D
            elif prev_round_defectors == 1:
                return Action.D
            else:
                return Action.C
        elif prev_round_defectors > 0:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_42(BaseStrategy):
    """
    Adaptive Threshold Tit-for-Tat:
    Maintains cooperation at high stock levels but defects if the stock falls
    below 50% capacity or if recent average cooperation (last 3 rounds)
    drops below 50% of the number of players. Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.safe_stock_level = 0.5 * self.game_description.capacity
        self.n_players = self.game_description.n_players
        self.total_rounds = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.safe_stock_level:
            return Action.D
        lookback = min(history.round_number, 3)
        recent_history = history.opponent_cooperators[-lookback:]
        avg_cooperators = float(np.mean(recent_history))
        if avg_cooperators < self.n_players * 0.5:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_43(BaseStrategy):
    """
    Constrained Tit-for-Tat with Threshold-Based Defection.
    
    This strategy prioritizes resource sustainability. It follows these rules:
    1. Terminal Phase: Defect on the final round.
    2. Sustainability Check: Defect if the stock level drops below 25% of capacity.
    3. Initialization: Cooperate on the first round to signal intent.
    4. Conditional Reciprocity: If previous round cooperation among others >= ceil(n/2), cooperate; otherwise, defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = math.ceil(self.n_players / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_round_idx = current_round - 1
        prev_round_cooperators = history.opponent_cooperators[prev_round_idx]
        if prev_round_cooperators >= self.threshold:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_44(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Exploitation Threshold.
    
    This strategy uses conditional reciprocity. It maintains a cooperative stance
    as long as others cooperate, exploits the resource periodically if the stock
    is healthy, and switches to defection if the population becomes aggressively
    competitive. It includes survival mechanisms for low stock and a "greed" 
    trigger for healthy stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.persistent_defection_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.C
        if history.round_number == 0:
            return Action.C
        if history.round_number >= 2 and history.opponent_cooperators[-1] == 0 and (history.opponent_cooperators[-2] == 0):
            self.persistent_defection_mode = True
        if self.persistent_defection_mode:
            if current_stock > 0.5 * self.capacity and history.opponent_cooperators[-1] > 0:
                self.persistent_defection_mode = False
            else:
                return Action.D
        opponents_c = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if n_opponents == 0:
            return Action.C
        ratio = opponents_c / n_opponents
        if ratio == 1.0:
            if current_stock > 0.8 * self.capacity:
                return Action.D
            return Action.C
        if ratio >= 0.5:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_45(BaseStrategy):
    """
    Conditional Sustainability: A strategy that balances resource conservation
    with competitive opportunism.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Endgame Phase (last 2 rounds): Defect (D) unless stock is critically low.
    - Standard Phase:
        - Panic/Recovery: Cooperate (C) if stock <= 25% capacity.
        - Stability Check: Cooperate (C) if opponents were cooperative (>= 75%).
        - Else: Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.t_min = 0.25 * self.capacity
        self.d_exhaust = 0.1 * self.capacity
        self.n = game_description.n_players
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if current_stock <= 0:
            return Action.C
        if rounds_remaining <= 2:
            if current_stock > self.d_exhaust:
                return Action.D
            else:
                return Action.C
        if current_stock <= self.t_min:
            return Action.C
        threshold = self.n_opponents * 0.75
        c_prev = history.opponent_cooperators[-1]
        if c_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_46(BaseStrategy):
    """
    A strategy for the Common Pool Resource Game that attempts to maintain a sustainable 
    resource stock (S_target = capacity / 2). It cooperates in the first round and maintains 
    cooperation unless the resource level is dangerously low or the opponent group defected 
    in the previous round. It always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.target_stock = game_description.capacity / 2.0
        self.n_players = game_description.n_players
        self.n_opponents = self.n_players - 1
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        rem_stock = current_stock / 2.0
        growth = 2.0 * rem_stock * (1.0 - rem_stock / self.game_description.capacity)
        projected_s_next = min(rem_stock + growth, float(self.game_description.capacity))
        if projected_s_next < self.target_stock or current_stock < self.game_description.capacity / 4.0:
            return Action.C
        num_opponent_coop = history.opponent_cooperators[-1]
        num_opponent_defect = self.n_opponents - num_opponent_coop
        if num_opponent_defect >= self.n_players / 2.0:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_47(BaseStrategy):
    """
    A modified Tit-for-Tat strategy for the Common Pool Resource Game.
    
    Operates based on:
    1. Terminal Phase: Unconditional Defection (D) starting 2 rounds before end.
    2. Desperation Threshold: Unconditional Defection (D) if stock < 20% capacity.
    3. Initialization: Starts with Cooperation (C).
    4. Reciprocity: Plays Cooperation (C) only if at least n-1 opponents cooperated 
       in the previous round; otherwise plays Defection (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = float(game_description.capacity)
        self.cooperation_threshold = self.n_players - 1
        self.terminal_phase_round = self.n_rounds - 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number >= self.terminal_phase_round:
            return Action.D
        if current_stock < 0.2 * self.capacity:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        if last_round_cooperators >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_48(BaseStrategy):
    """
    Conditional Tit-for-Tat with Sustainability Thresholds strategy.
    
    Logic summary:
    - Round 0: Always Cooperate.
    - Last Round (r): Always Defect to maximize terminal payoff.
    - Critical Depletion: If stock < capacity/n, Defect to extract remaining value.
    - Large Groups (n > 10): If cooperation drops below n/2, assume tragedy of commons and Defect.
    - Reciprocity: Otherwise, if previous stock was high and cooperation >= n-1, Cooperate; 
      else if current stock is significantly lower than projected (suggesting heavy defection), Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        if current_stock < self.capacity / self.n:
            return Action.D
        if current_stock <= 0:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        if self.n > 10 and c_prev < self.n / 2:
            return Action.D
        if c_prev >= self.n - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_49(BaseStrategy):
    """
    Implements the 'Conditional Sustenance' strategy.
    Balances immediate rewards with long-term sustainability based on stock levels,
    previous cooperation rates, and remaining game duration.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        round_idx = history.round_number
        rounds_remaining = self.r - round_idx
        prev_k = int(history.opponent_cooperators[-1])
        if prev_k == 0:
            return Action.D
        if current_stock < 0.01 * self.capacity:
            return Action.C
        if rounds_remaining < 2:
            return Action.D
        sustainability_index = current_stock / self.capacity
        if prev_k == self.n - 1:
            if sustainability_index < 0.9:
                return Action.C
            else:
                return Action.D
        if sustainability_index > 0.8 or prev_k < self.n / 2:
            return Action.D
        if sustainability_index < 0.5:
            return Action.C
        if 0.5 <= sustainability_index <= 0.8 and prev_k >= self.n / 2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_50(BaseStrategy):
    """
    Implements an Adaptive Opportunism strategy for the Common Pool Resource Game.
    The strategy balances immediate extraction against long-term sustainability by 
    monitoring cooperation levels and stock projections.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.last_stock = float(self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.last_stock = current_stock
            return Action.C
        prev_round_idx = history.round_number - 1
        if history.round_number == self.r - 1:
            self.last_stock = current_stock
            return Action.D
        if current_stock < self.capacity / self.n:
            self.last_stock = current_stock
            return Action.C
        coop_history = []
        start_idx = max(0, history.round_number - 3)
        for i in range(start_idx, history.round_number):
            my_action = 1 if history.my_actions[i] else 0
            total_coop = my_action + history.opponent_cooperators[i]
            coop_history.append(total_coop / self.n)
        avg_coop = np.mean(coop_history) if coop_history else 1.0
        if avg_coop > 0.8:
            self.last_stock = current_stock
            return Action.C
        elif avg_coop < 0.2:
            self.last_stock = current_stock
            return Action.D
        if self.n > 10 and current_stock < self.capacity * 0.5:
            self.last_stock = current_stock
            return Action.C
        if current_stock < self.last_stock:
            self.last_stock = current_stock
            return Action.C
        self.last_stock = current_stock
        return Action.D

class Strategy_OPPORTUNISTIC_51(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with resource thresholding.
    Prioritizes sustainability when stock is low, and reciprocity when stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r_total - 1:
            return Action.D
        if current_stock < capacity * 0.25:
            return Action.C
        if history.opponent_cooperators[-1] == n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_52(BaseStrategy):
    """
    Conditional Harvest Optimization Strategy.
    Implements a Tit-for-Tat mechanism with trend analysis, utilizing
    regime-based decision rules, an adaptive buffer for sustainability, 
    and opportunistic overrides to maximize payoffs while preserving the resource.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.override_counter = 0

    def _get_total_cooperators(self, history: PlayerHistory) -> int:
        if history.round_number == 0:
            return 0
        my_last_action = history.my_actions[-1]
        opp_coop = history.opponent_cooperators[-1]
        my_c = 1 if my_last_action else 0
        return opp_coop + my_c

    def _is_defection_increasing(self, history: PlayerHistory) -> bool:
        if history.round_number < 2:
            return False

        def get_defectors(round_idx):
            opp_coop = history.opponent_cooperators[round_idx]
            my_c = 1 if history.my_actions[round_idx] else 0
            return self.n - (opp_coop + my_c)
        d1 = get_defectors(-1)
        d2 = get_defectors(-2)
        return d1 > d2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0 or (current_stock < 1.0 and self.r - current_round >= 3):
            return Action.C
        obs_cooperators = self._get_total_cooperators(history)
        if self.override_counter > 0:
            self.override_counter -= 1
            return Action.D
        if self._is_defection_increasing(history):
            self.override_counter = 2
            return Action.D
        action = Action.D
        if obs_cooperators >= self.n - 1:
            action = Action.C
        elif obs_cooperators >= self.n / 2:
            action = Action.C if current_stock >= 0.5 * self.capacity else Action.D
        else:
            action = Action.D
        consumption_if_coop = current_stock / 2.0
        if current_stock < consumption_if_coop:
            action = Action.C
        return action

class Strategy_OPPORTUNISTIC_53(BaseStrategy):
    """
    Implements the Conditional Sustainability Monitoring (CSM) strategy.
    
    This strategy uses a threshold-based conditional cooperation model:
    1. Phase 1 (Round 0): Always Cooperate.
    2. Phase 2 (Rounds 1 to r-2): Monitor opponent cooperation. If the number of 
       cooperating opponents is >= ceil(n/2), Cooperate. Otherwise, Defect.
    3. Phase 3 (Last Round): Always Defect.
    
    Includes edge case handling for low stock conditions (Recovery Mode) and 
    recovery detection (Defector Correction).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = math.ceil(self.game_description.n_players / 2)
        self.previous_stock = float(self.game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            self.previous_stock = current_stock
            return Action.C
        if current_stock < self.game_description.capacity / self.game_description.n_players:
            self.previous_stock = current_stock
            return Action.C
        c_prev = history.opponent_cooperators[-1]
        action = Action.D
        if c_prev >= self.cooperation_threshold:
            action = Action.C
        elif current_stock > self.previous_stock:
            action = Action.C
        else:
            action = Action.D
        self.previous_stock = current_stock
        return action

class Strategy_OPPORTUNISTIC_54(BaseStrategy):
    """
    Implements an adaptive strategy for the Common Pool Resource Game:
    - Starts with cooperation.
    - Tracks opponent cooperation via a trust_score (EWMA).
    - Defects on the final round.
    - Adjusts behavior based on stock levels and observed trust.
    - Exploits "overflowing" stock conditions when safe.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_score = 0.5
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if t == self.r:
            return Action.D
        if t == 1:
            return Action.C
        n_C_prev = history.opponent_cooperators[-1]
        denom = self.n - 1
        if denom == 0:
            self.trust_score = 1.0
        else:
            coop_ratio = n_C_prev / denom
            self.trust_score = self.trust_score * 0.9 + coop_ratio * 0.1
        if current_stock > 0.9 * self.capacity and t < self.r - 2:
            if denom > 0 and n_C_prev / denom > 0.5:
                return Action.D
        critical_threshold = 0.2 * self.capacity
        if current_stock < critical_threshold:
            return Action.D
        if self.trust_score > 0.6:
            return Action.C
        if self.trust_score < 0.4:
            return Action.D
        if random.random() < self.trust_score:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_55(BaseStrategy):
    """
    Sustainable Opportunism Strategy:
    - Round 1: Cooperate.
    - Final Round: Always Defect.
    - Otherwise:
        - If stock <= capacity/4: Defect (Critical depletion).
        - Else if opponents cooperated >= (n-1): Cooperate (Reciprocity).
        - Else: Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round_index == n_rounds - 1:
            return Action.D
        if current_round_index == 0:
            return Action.C
        critical_threshold = capacity / 4.0
        if current_stock <= critical_threshold:
            return Action.D
        k = int(history.opponent_cooperators[-1])
        n_opponents = n_players - 1
        if k >= n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_56(BaseStrategy):
    """
    Implements a complex strategy for the Common Pool Resource Game:
    - Switches between 'Always Defect' for small games and 'Conditional Cooperator' for large games.
    - Conditional Cooperator logic includes dynamic sustainability checks, punishment mechanisms, 
      and 'Sinking Ship' detection.
    - Enforces termination defection in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_always_defect = self.game_description.n_rounds < 5
        self.punishment_debt = 0
        self.sinking_ship = False
        self.permanent_defect = False
        self.previous_stock = float(self.game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        r = self.game_description.n_rounds
        t = history.round_number
        if current_stock <= 0:
            return Action.D
        if t > 0:
            if current_stock < self.previous_stock * 0.5:
                self.sinking_ship = True
        self.previous_stock = current_stock
        if self.sinking_ship or self.permanent_defect or self.is_always_defect:
            return Action.D
        if t == r - 1:
            return Action.D
        if t == 0:
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        if t > r / 2 and prev_k < n_opponents / 2:
            self.permanent_defect = True
            return Action.D
        if self.punishment_debt > 0:
            self.punishment_debt -= 1
            return Action.D
        if current_stock < self.game_description.capacity * 0.4:
            return Action.D
        if prev_k < n_opponents:
            defectors = n_opponents - prev_k
            remaining_rounds = r - t
            self.punishment_debt = math.ceil(defectors / n * remaining_rounds)
            return Action.D
        if prev_k == n_opponents:
            return Action.C
        elif prev_k == n_opponents - 1:
            return Action.C if random.random() < 0.5 else Action.D
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_57(BaseStrategy):
    """
    Implements a 'Target Stock Threshold' strategy with 'Conditional Tit-for-Tat'.
    Prioritizes resource preservation when stock is low, opportunistic extraction when stock is high,
    and reciprocal matching of cooperation rates in the middle range.
    Always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.C
        if current_stock >= self.capacity * 0.75:
            return Action.D
        last_round_cooperators = int(history.opponent_cooperators[-1])
        my_last_action = history.my_actions[-1]
        others_who_cooperated = last_round_cooperators
        if self.n <= 1:
            return Action.C
        cooperation_rate = others_who_cooperated / (self.n - 1)
        if cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_58(BaseStrategy):
    """
    A strategy that balances aggressive exploitation with resource preservation.
    
    Logic:
    - Phase 1: Cooperate in round 1.
    - Phase 2: If stock is high (> 75% capacity) and group cooperation is high, defect to exploit. 
               Otherwise, cooperate to protect the stock.
               Exceptions: If stock is very low (< 10% capacity), override to cooperate.
               If stock is zero, defect.
    - Phase 3: Defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opp_coop = history.opponent_cooperators[-1]
        k = last_opp_coop + (1 if last_my_action else 0)
        is_abundant = current_stock > 0.75 * self.capacity
        if is_abundant:
            if k >= self.n - 1:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_59(BaseStrategy):
    """
    A resource-conscious strategy for the Common Pool Resource Game that balances
    long-term sustainability with defensive opportunism. 
    - Cooperates in the first round.
    - Uses a threshold-based switching mechanism:
        - In surplus (Stock >= Capacity/2): Cooperates unless a majority defected previously.
        - In recovery (Stock < Capacity/2): Cooperates if all cooperated, otherwise Defects (scorched earth).
    - Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        n_opponents = n - 1
        if round_idx == total_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        crit_threshold = self.game_description.capacity / 2.0
        my_prev_action = history.my_actions[-1]
        prev_coop_count = history.opponent_cooperators[-1]
        my_prev_coop_val = 1 if my_prev_action else 0
        total_defectors = n - (prev_coop_count + my_prev_coop_val)
        if current_stock >= crit_threshold:
            if total_defectors == 0:
                return Action.C
            elif total_defectors <= n / 2.0:
                return Action.C
            else:
                return Action.D
        elif total_defectors == 0:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_60(BaseStrategy):
    """
    A cooperative strategy for the Common Pool Resource Game.
    
    Logic:
    - If it's the final round, always defect.
    - If the current stock is below 25% of capacity, cooperate to prioritize sustainability.
    - If it's the first round, cooperate.
    - Otherwise, use a Tit-for-Tat variant: if the number of cooperators in the 
      previous round meets or exceeds n/2, cooperate, otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.capacity = self.game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        rounds_remaining = self.r - round_number
        if rounds_remaining == 0:
            return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.C
        if round_number == 0:
            return Action.C
        last_opponent_coops = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators_last_round = last_opponent_coops + (1 if my_last_action else 0)
        threshold = self.n / 2.0
        if total_cooperators_last_round >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_61(BaseStrategy):
    """
    Implements a Threshold-Based Opportunistic Tit-for-Tat strategy.
    Maintains resource stability by cooperating when others cooperate,
    while defecting during critical depletion or the game's terminal phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.game_description.n_rounds - 2:
            return Action.D
        threshold_stock = self.game_description.capacity / self.game_description.n_players
        if current_stock < threshold_stock:
            return Action.D
        my_prev_action = history.my_actions[-1]
        opp_prev_coop = history.opponent_cooperators[-1]
        total_coop = opp_prev_coop + (1 if my_prev_action else 0)
        n = self.game_description.n_players
        coop_ratio = total_coop / n
        threshold = 0.75 if n > 10 else 0.5
        if coop_ratio >= threshold:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_62(BaseStrategy):
    """
    A Tit-for-Tat based strategy for the Common Pool Resource Game.
    This strategy prioritizes sustainability while being opportunistic 
    in high-stock scenarios and defensive against systemic collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            return Action.D
        if current_stock == 0:
            return Action.D
        critical_threshold = self.capacity / (2.0 * self.n)
        if current_stock < critical_threshold:
            return Action.C
        prev_opponents_c = int(history.opponent_cooperators[-1])
        my_prev_action = int(history.my_actions[-1])
        total_prev_c = prev_opponents_c + my_prev_action
        if total_prev_c == self.n:
            return Action.C
        if total_prev_c == 0:
            return Action.D
        if current_stock >= self.capacity * (1.0 - 1.0 / self.n):
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_63(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with an exploitation threshold.
    
    Strategy Logic:
    1. Round 1: Always Cooperate.
    2. Last Round: Always Defect.
    3. Low Stock: If stock < 10% of capacity, Defect regardless of history.
    4. General Rounds: 
       - If number of cooperating opponents >= floor(n/2), Cooperate.
       - Otherwise, Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = math.floor(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if self.capacity > 0 and current_stock < self.capacity * 0.1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            return Action.D
        prev_k = history.opponent_cooperators[-1]
        if prev_k >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_64(BaseStrategy):
    """
    Implements an Adaptive Opportunism strategy for the Common Pool Resource game.
    
    Strategy phases:
    1. First Round: Always Cooperate (C).
    2. Adaptive Opportunism (Rounds 2 to r-1): Defect if stock < 25% capacity.
       Otherwise, cooperate if the cooperation rate of the group in the previous
       round was >= 50%.
    3. Terminal Phase (Last Round): Always Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.total_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.D
        num_opponents = self.n - 1
        last_round_cooperators = history.opponent_cooperators[-1]
        cooperation_rate = last_round_cooperators / num_opponents if num_opponents > 0 else 0.0
        if cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_65(BaseStrategy):
    """
    A conditional strategy for the Common Pool Resource game:
    - Always cooperates in the first round.
    - If it is the last round, always defects.
    - If stock is below 50% of capacity, prioritizes resource preservation by cooperating.
    - If stock is >= 50% capacity:
        - If all opponents cooperated in the previous round, continues to cooperate.
        - If any opponent defected in the previous round, switches to defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            return Action.D
        if current_stock < 0.5 * self.game_description.capacity:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        prev_cooperators = history.opponent_cooperators[-1]
        k_defectors = n_opponents - prev_cooperators
        if k_defectors == 0:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_66(BaseStrategy):
    """
    Implements a strategy that balances resource conservation with opportunistic 
    exploitation based on the common pool stock level and historical cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if t == self.r:
            return Action.D
        if t == 1:
            return Action.C
        if current_stock == 0:
            return Action.C
        prev_k = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)

        def simulate_next_stock(my_action: Action, current_s: float, k: int) -> float:
            n_c = k + (1 if my_action == Action.C else 0)
            n_d = self.n - n_c
            total_consumption = n_c * (current_s / (2 * self.n)) + n_d * (current_s / self.n)
            s_rem = current_s - total_consumption
            if s_rem < 0:
                return 0.0
            growth = 2 * s_rem * (1 - s_rem / self.capacity)
            return min(s_rem + growth, self.capacity)
        if simulate_next_stock(Action.D, current_stock, history.opponent_cooperators[-1]) < self.capacity / 4:
            return Action.C
        threshold = self.capacity / 2
        r_t_minus_1 = history.opponent_cooperators[-1] / (self.n - 1) if self.n > 1 else 1.0
        if current_stock >= threshold:
            if r_t_minus_1 >= 0.5:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_67(BaseStrategy):
    """
    Conditional Sustainability with End-Game Opportunism.
    
    Implements a trigger-based strategy:
    1. Always defects in the final round.
    2. Defects if stock is below (capacity / n) to prioritize extraction.
    3. Initially cooperates.
    4. Uses a Tit-for-Tat variant: cooperates if at least n-1 players cooperated 
       previously, otherwise switches to Defect mode for a calculated number of rounds.
    5. Recovers to cooperation only if stock >= 0.8 * capacity after forced defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.defects_remaining = 0
        self.is_recovering = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        rounds_remaining = total_rounds - current_round
        if rounds_remaining == 1:
            return Action.D
        if current_stock < self.game_description.capacity / n:
            self.is_recovering = True
            return Action.D
        if self.is_recovering:
            if current_stock >= 0.8 * self.game_description.capacity:
                self.is_recovering = False
            else:
                return Action.D
        if current_round == 0:
            return Action.C
        if self.defects_remaining > 0:
            self.defects_remaining -= 1
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        total_prev_coop = history.opponent_cooperators[-1] + my_prev_coop
        if total_prev_coop >= n - 1:
            return Action.C
        else:
            m = round((n - total_prev_coop) / n * rounds_remaining)
            self.defects_remaining = max(1, m)
            self.defects_remaining -= 1
            return Action.D

class Strategy_OPPORTUNISTIC_68(BaseStrategy):
    """
    Trigger-Adaptive Exploitation: Uses an initial testing phase to gauge
    cooperation levels, followed by a regime-adaptive phase that balances
    stock conservation (RHI) and exploitation (OCR).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.num_opponents = self.n - 1
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < 1.0:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if 1 <= history.round_number <= 4:
            last_opp_coop_count = history.opponent_cooperators[-1]
            num_defect = self.num_opponents - last_opp_coop_count
            if num_defect > self.n / 2:
                return Action.D
            else:
                return Action.C
        if self.total_rounds - history.round_number < 3:
            return Action.D
        rhi = current_stock / self.capacity
        if rhi < 0.25:
            return Action.C
        if self.num_opponents > 0:
            ocr = history.opponent_cooperators[-1] / self.num_opponents
        else:
            return Action.D
        if ocr > 0.6:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_69(BaseStrategy):
    """
    A strategy that implements Tit-for-Tat with a dynamic Greed Threshold.
    It cooperates initially and maintains cooperation if others cooperate and the
    resource stock is sustainable. It defects if the game is nearing its end,
    the resource is collapsing, or if too many opponents defected in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round > 0.9 * (self.r - 1):
            return Action.D
        if current_stock < self.capacity * 0.2:
            return Action.D
        prev_round_cooperators = history.opponent_cooperators[-1]
        num_opponents = self.n - 1
        cooperation_index = prev_round_cooperators / num_opponents
        if cooperation_index < 0.5:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_70(BaseStrategy):
    """
    Adaptive Threshold Tit-for-Tat (AT-TFT) strategy.
    
    This strategy balances resource sustainability with conditional cooperation.
    It cooperates initially and when the resource stock is high and reciprocity is met.
    It defects when the resource is critically low, when reciprocity falls below 
    a 60% threshold, or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n = self.game_description.n_players
        self.reciprocity_threshold = math.floor((n - 1) * 0.6)
        self.critical_threshold = 0.5 * self.game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= self.critical_threshold:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        if c_prev >= self.reciprocity_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_71(BaseStrategy):
    """
    Implements a threshold-based conditional cooperation strategy for the Common Pool Resource Game.
    
    The strategy follows a distinct lifecycle:
    1. Stabilization Phase (Rounds 0 to r-3): Cooperate if the current stock is 
       healthy (>= 25% capacity) and a sufficient number of opponents cooperated in 
        the previous round. Otherwise, defect to extract value.
    2. Terminal Phase (Round r-2): If stock is > 50% capacity, cooperate to maintain 
       the pool; otherwise, defect.
    3. Final Round (Round r-1): Defect unconditionally.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n_opponents = self.game_description.n_players - 1
        self.threshold = n_opponents - math.floor(n_opponents / 3)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == total_rounds - 2:
            if current_stock > capacity * 0.5:
                return Action.C
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < capacity * 0.25:
            return Action.D
        k_prev = history.opponent_cooperators[-1]
        if k_prev >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_72(BaseStrategy):
    """
    Conditional Growth Maximization (CGM) strategy.
    
    Operates on maximizing stock level until the final round, monitoring
    the "Cooperation Ratio" of the group to decide between sustaining
    the resource (Cooperate) or extracting value (Defect).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_index = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if round_index == total_rounds:
            return Action.D
        if current_stock < capacity / 4:
            return Action.D
        if round_index == 1:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        if last_round_cooperators >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_73(BaseStrategy):
    """
    A strategic implementation for the Common Pool Resource Game that balances
    resource preservation with opportunistic extraction. The strategy cycles
    through three phases: Growth Focus (Cooperate when stock is healthy),
    Reciprocity (Tit-for-Tat adaptation based on previous cooperation density),
    and Terminal Extraction (Defect in the final round). It includes a 
    low-stock override to ensure extraction before collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        capacity = self.game_description.capacity
        r_current = history.round_number
        r_rem = r_total - r_current
        if r_rem == 1:
            return Action.D
        if current_stock <= capacity * 0.1:
            return Action.D
        if current_stock > capacity * 0.6:
            return Action.C
        if r_current == 0:
            return Action.C
        last_self_action = 1 if history.my_actions[-1] else 0
        last_opp_coop = history.opponent_cooperators[-1]
        total_cooperators = last_opp_coop + last_self_action
        if total_cooperators >= n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_74(BaseStrategy):
    """
    Conditional Sustainability Strategy:
    - Round 1: Cooperate.
    - Round r (Final): Always Defect.
    - Rounds [2, r-1]:
        - If stock < 0.5 * capacity: Cooperate (Sustainability Fallback).
        - If stock >= 0.5 * capacity:
            - If all opponents cooperated in the last round: Cooperate.
            - Else: Defect (Opportunistic punishment).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.5 * self.game_description.capacity:
            return Action.C
        k = history.opponent_cooperators[-1]
        if k == self.game_description.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_75(BaseStrategy):
    """
    Threshold-Based Tit-for-Tat with Terminal Defection.
    
    Logic:
    - Round 1: Cooperate (C).
    - Rounds 2-(r-3):
        - If stock < capacity/2 or stock == 0: Defect (D).
        - If stock is healthy and cooperators_prev >= n - 1: Cooperate (C).
        - Otherwise: Defect (D).
    - Exception for First 3 rounds: If stock < 0.25 * capacity, prioritize survival (D), otherwise maintain baseline (C).
    - Final Round (r): Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def _infer_cooperators(self, prev_stock: float, current_stock: float) -> int:
        if current_stock >= self.capacity:
            s_rem = self.capacity / 2.0
        else:
            disc = 9.0 - 8.0 * (current_stock / self.capacity)
            if disc < 0:
                disc = 0
            s_rem = (3.0 - math.sqrt(disc)) / (4.0 / self.capacity)
        consumption_total = prev_stock - s_rem
        s_prev = prev_stock
        unit_c = s_prev / (2.0 * self.n)
        if unit_c <= 1e-09:
            return self.n
        d_count = consumption_total / unit_c - self.n
        d_count = round(d_count)
        return max(0, min(self.n, self.n - d_count))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r_current = history.round_number
        if r_current == self.r - 1:
            return Action.D
        if r_current == 0:
            return Action.C
        if current_stock <= 1e-09:
            return Action.D
        if r_current < 3:
            if current_stock < 0.25 * self.capacity:
                return Action.D
            return Action.C
        cooperators_prev = history.opponent_cooperators[-1]
        if current_stock < self.capacity / 2.0:
            return Action.D
        if cooperators_prev >= self.n - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_76(BaseStrategy):
    """
    A strategy that enforces sustainability via conditional replenishment when 
    stocks are low and majority cooperation is present. It otherwise exploits 
    the surplus unless perfect cooperation is occurring, and always defects 
    in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.s_crit = game_description.capacity / 2.0
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        if round_t == 0:
            return Action.C
        if round_t == self.game_description.n_rounds - 1:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        n_c = history.opponent_cooperators[-1] + prev_my_action
        s_prev = current_stock
        if s_prev < self.s_crit:
            threshold = math.ceil(self.n / 2.0)
            if n_c >= threshold:
                return Action.C
            else:
                return Action.D
        elif n_c == self.n:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_77(BaseStrategy):
    """
    Strategy: Conditional Sustainability with Sunset Defection
    
    A rule-based strategy that transitions from cooperative behavior to
    opportunistic exploitation based on resource stock and round progression.
    
    Phases:
    1. Initiation: Always C in round 1.
    2. Maintenance: 
       - If stock < capacity/4: Force C.
       - If observed cooperators < (n/2): Switch to D.
       - Else: Cooperate with probability (1 - round/r).
    3. Termination: Always D in final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_round == total_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        if current_stock < capacity / 4:
            return Action.C
        k = int(history.opponent_cooperators[-1])
        if k < n / 2:
            return Action.D
        t_threshold = current_round / total_rounds
        if random.random() <= t_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_78(BaseStrategy):
    """
    Implements a threshold-based 'Tit-for-Tat with Greed' strategy for the Common Pool Resource Game.
    
    Phases:
    1. Initialization: Always defects in the first round to test baseline.
    2. Adaptive:
       - If stock is critical (< 0.25 capacity), prioritizes sustainability by cooperating.
       - If stock is abundant (>= 0.95 capacity), exploits the surplus by defecting.
       - Otherwise, tracks cooperation ratio (CR) of the previous round: cooperates if CR >= 0.5, else defects.
    3. Terminal: Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        logical_round = current_round_idx + 1
        if logical_round == self.r:
            return Action.D
        if logical_round == 1:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        if current_stock >= 0.95 * self.capacity:
            return Action.D
        last_my_action = history.my_actions[current_round_idx - 1]
        total_cooperators = history.opponent_cooperators[current_round_idx - 1] + (1 if last_my_action == Action.C else 0)
        cr = total_cooperators / self.n
        if cr >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_79(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Thresholds:
    Prioritizes cooperation while the stock is healthy (>= 50% capacity).
    Abandons cooperation if the pool is depleted (< 50% capacity) or
    in the final round to maximize immediate payoffs.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_stock < capacity / 2.0:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        n_c = prev_opp_coop + (1 if prev_my_action else 0)
        if n_c >= n - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_80(BaseStrategy):
    """
    A strategy that implements a reputation-based cooperation mechanism.
    - Round 1: Cooperates.
    - Final Round: Defects.
    - Steady State (Rounds 2 to r-1): 
        - If stock is critical (< 20% capacity), cooperate.
        - Otherwise, updates a running reputation score based on the previous round's total cooperation count and cooperates if the score is > 0.6.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation_score = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == total_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        stock_ratio = current_stock / capacity
        if stock_ratio < 0.2:
            return Action.C
        prev_opponents_coop = int(history.opponent_cooperators[-1])
        i_cooperated = int(history.my_actions[-1])
        k = prev_opponents_coop + i_cooperated
        cooperation_rate_prev = k / n
        self.reputation_score = 0.7 * self.reputation_score + 0.3 * cooperation_rate_prev
        if self.reputation_score > 0.6:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_81(BaseStrategy):
    """
    Tit-for-Tat with Harvesting Thresholds:
    1. First round: Cooperate.
    2. Final round: Defect.
    3. Intermediate rounds:
       - If stock < capacity/n: Cooperate (Safety valve).
       - Else if opponent_cooperators >= floor((n-1)/2): Cooperate (Reciprocity).
       - Else: Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        opponents_cooperated = history.opponent_cooperators[-1]
        if n > 0 and current_stock < capacity / n:
            return Action.C
        threshold = math.floor((n - 1) / 2)
        if opponents_cooperated >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_82(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Forgiving Exploitation.
    
    Maintains the common pool capacity via conditional cooperation,
    while exploiting the pool when group cooperation is low or 
    during terminal game phases.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.n_opponents = self.n - 1
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round >= self.r - 3:
            return Action.D
        if current_stock < 0.2 * self.capacity:
            return Action.D
        if current_stock >= self.capacity:
            return Action.C
        coop_ratios = history.opponent_cooperators.astype(float) / self.n_opponents
        if history.opponent_cooperators[-1] == 0:
            avg_c = 0.0
        else:
            avg_c = np.mean(coop_ratios)
        if current_stock > 0.8 * self.capacity:
            if avg_c > 0.75:
                return Action.C
            else:
                return Action.D
        elif avg_c > 0.9:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_83(BaseStrategy):
    """
    Implements a Tit-for-Tat with Sustainability Threshold strategy.
    
    Logic:
    1. Always cooperates in the first round.
    2. Always defects in the final round (if stock > 0).
    3. Emergency mode: If stock < capacity/(2n), always cooperate to prevent collapse.
    4. Opportunistic mode: If stock is healthy, cooperates if everyone else cooperated previously.
       Otherwise, checks if previous consumption was sustainable (Q < 0.5) to decide whether to exploit (D) or recover (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        if current_round == self.r:
            if current_stock > 0:
                return Action.D
            return Action.C
        threshold = self.capacity / (2 * self.n)
        if current_stock < threshold:
            return Action.C
        last_round_idx = history.round_number - 1
        last_my_action = history.my_actions[last_round_idx]
        last_opponent_coops = history.opponent_cooperators[last_round_idx]
        k_prev = int(last_opponent_coops) + int(last_my_action)
        if k_prev == self.n:
            return Action.C
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_84(BaseStrategy):
    """
    A sophisticated Common Pool Resource strategy implementing 'Tit-for-Tat with Forgiveness',
    incorporating reputation tracking, resource sustainability thresholds, and adaptive sensitivity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 0.5
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.capacity * 0.2:
            return Action.C
        prev_round_idx = -1
        cooperators_obs = history.opponent_cooperators[prev_round_idx]
        my_prev_action = history.my_actions[prev_round_idx]
        my_consumption_type = 1 if my_prev_action else 2
        my_weight = 1 if my_prev_action else 2
        total_consumption_weight = cooperators_obs + (self.n - 1 - cooperators_obs) * 2 + my_weight
        is_high_consumption = total_consumption_weight > 0.5 * self.n
        if is_high_consumption:
            self.reputation = self.reputation * 0.5 + cooperators_obs / (self.n - 1) * 0.5
        else:
            self.reputation = self.reputation * 0.8 + cooperators_obs / (self.n - 1) * 0.2
        if cooperators_obs == 0:
            return Action.D
        s_crit = self.capacity * 0.5
        if current_stock < s_crit:
            if self.reputation >= 0.3:
                return Action.C
            else:
                return Action.D
        if self.reputation >= 0.6:
            return Action.C
        else:
            if random.random() < 1.0 - self.reputation:
                return Action.D
            return Action.C

class Strategy_OPPORTUNISTIC_85(BaseStrategy):
    """
    Trigger-Based Sustainable Exploitation:
    - Initially cooperates.
    - Defects in the final two rounds of the game.
    - In intermediate rounds:
      - If stock > 50% capacity, cooperates only if all players cooperated in the previous round, else defects.
      - If stock <= 50% capacity, defects if stock is critically low (below capacity/2n), otherwise cooperates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if t == 0:
            return Action.C
        if t >= r - 2:
            return Action.D
        my_previous_action = history.my_actions[-1]
        n_cooperators = int(history.opponent_cooperators[-1] + (1 if my_previous_action else 0))
        threshold = 0.5 * capacity
        if current_stock > threshold:
            if n_cooperators == n:
                return Action.C
            else:
                return Action.D
        else:
            critical_level = capacity / (2 * n)
            if current_stock < critical_level:
                return Action.D
            return Action.C

class Strategy_OPPORTUNISTIC_86(BaseStrategy):
    """
    Forgiving Tit-for-Tat with Resource Preservation.
    
    This strategy focuses on sustainability:
    - Round 1: Always Cooperate (C).
    - Tracks global defection behavior. If > 50% of the player pool defects in a round,
      the environment is marked as 'active defectors', and the strategy switches to permanent Defect (D).
    - If no defector activity is detected:
        - If stock < capacity/4: Cooperate (C) to force resource recovery.
        - If stock > capacity * 0.75: Defect (D) to capitalize on the buffer.
        - Otherwise (Neutral): Cooperate (C) to maintain stability.
    - Final Round: Always Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_defector_active = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        my_last_action_was_c = bool(history.my_actions[-1])
        total_cooperators = history.opponent_cooperators[-1] + (1 if my_last_action_was_c else 0)
        total_defectors = n - total_cooperators
        if total_defectors > n / 2:
            self.is_defector_active = True
        if self.is_defector_active:
            return Action.D
        capacity = self.game_description.capacity
        if current_stock < capacity / 4:
            return Action.C
        elif current_stock > capacity * 0.75:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_87(BaseStrategy):
    """
    Implements a greedy-trigger strategy that balances resource regeneration with
    conditional reciprocity.
    
    Rules:
    1. First round: Always Cooperate (C) to establish trust.
    2. Final round: Always Defect (D) to maximize extraction.
    3. Low stock (S < capacity/2): Prioritize regeneration by Cooperating (C).
    4. Standard play: Calculate Cooperation Ratio (CR) of the previous round.
       If CR >= 0.5, Cooperate; otherwise, Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n_opponents = self.game_description.n_players - 1
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.game_description.capacity / 2:
            return Action.C
        k = history.opponent_cooperators[-1]
        cooperation_ratio = k / n_opponents
        if cooperation_ratio >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_88(BaseStrategy):
    """
    A Conditional Tit-for-Tat strategy with sustainability thresholding.
    
    Logic:
    - Terminal Round: Always defect.
    - First Round: Always cooperate to establish trust.
    - Critical Threshold (S < Capacity/4): Defect to salvage remaining resources.
    - Opportunistic Phase: If stock is sufficient (>= Capacity/4), mirror group cooperation 
      levels: Cooperate if >= 50% of the group cooperated in the previous round, else Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.salvage_threshold = self.capacity / 4.0
        self.coop_threshold = math.floor(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.r:
            return Action.D
        if current_round == 1:
            return Action.C
        if current_stock < self.salvage_threshold:
            return Action.D
        k = history.opponent_cooperators[-1]
        if k >= self.coop_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_89(BaseStrategy):
    """
    Implements a sustainability-focused strategy for the Common Pool Resource Game.
    The strategy monitors the average defection rate of the population and makes 
    decisions based on current stock levels and predicted future stock levels 
    to prevent resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def _simulate_next_stock(self, S_current: float, my_action: Action, avg_d: float) -> float:
        """
        Predicts S_{t+1} given S_t, my action, and the observed average defection rate.
        """
        num_opponents = self.n - 1
        n_opponents_defecting = num_opponents * avg_d
        n_opponents_cooperating = num_opponents * (1.0 - avg_d)
        if my_action == Action.D:
            my_consumption = S_current / self.n
            total_defecting = n_opponents_defecting + 1
            total_cooperating = n_opponents_cooperating
        else:
            my_consumption = S_current / (2 * self.n)
            total_defecting = n_opponents_defecting
            total_cooperating = n_opponents_cooperating + 1
        consumption_D = total_defecting * (S_current / self.n)
        consumption_C = total_cooperating * (S_current / (2 * self.n))
        total_consumption = consumption_D + consumption_C
        S_remaining = max(0.0, S_current - total_consumption)
        growth = 2 * S_remaining * (1 - S_remaining / self.capacity)
        return min(self.capacity, S_remaining + growth)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if t == 1:
            return Action.C
        if t == self.r:
            return Action.D
        num_opponents = self.n - 1
        if num_opponents == 0:
            avg_d = 0.0
        else:
            past_coops = np.array(history.opponent_cooperators)
            past_defects = num_opponents - past_coops
            avg_d = np.mean(past_defects) / num_opponents
        if current_stock < self.capacity / 4:
            return Action.C
        projected_S_next = self._simulate_next_stock(current_stock, Action.D, avg_d)
        if projected_S_next < self.capacity / 4:
            return Action.C
        if avg_d < 0.2:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_90(BaseStrategy):
    """
    Conditional Tit-for-Tat with Sustainability Thresholds strategy.
    
    This strategy adapts behavior based on the current stock levels relative to capacity
    and the recent collective behavior of opponents.
    - Round 1: Always Cooperate.
    - Final Round: Always Defect.
    - Mid-game:
        - If stock is critical (<= capacity/n), prioritize immediate consumption (Defect).
        - If stock is healthy, reciprocate cooperation if a majority of opponents cooperated.
        - Includes an opportunistic re-entry mechanism if stock is exceptionally high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock <= self.capacity / self.n:
            return Action.D
        prev_k = history.opponent_cooperators[-1]
        if prev_k >= self.n / 2:
            return Action.C
        else:
            if current_stock > 0.75 * self.capacity:
                return Action.C
            return Action.D

class Strategy_OPPORTUNISTIC_91(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Common Pool Resource game.
    - Round 1: Always Cooperate.
    - Final Round: Always Defect.
    - Rounds 1 < t < r:
        - If everyone cooperated in the previous round, Cooperate.
        - If not, assess sustainability:
            - If stock > capacity * 0.5: Cooperate.
            - Else: Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        last_round = self.game_description.n_rounds - 1
        if current_round == last_round:
            return Action.D
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_coop_count = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        if last_coop_count == self.game_description.n_players:
            return Action.C
        if current_stock > self.game_description.capacity * 0.5:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_92(BaseStrategy):
    """
    Implements a conditional tit-for-tat strategy with risk-adjusted thresholds for sustainability.
    Prioritizes cooperation when the stock allows and mutual cooperation is observed,
    but defaults to defection in terminal phases or when resource exhaustion is imminent.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r_remaining = self.game_description.n_rounds - history.round_number
        if history.round_number == 0:
            return Action.C
        if r_remaining == 1:
            return Action.D
        n = self.game_description.n_players
        threshold = self.game_description.capacity / (2 * n)
        if current_stock < threshold:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponent_coop_count = history.opponent_cooperators[-1]
        k = last_opponent_coop_count + (1 if last_my_action else 0)
        if k >= n / 2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_93(BaseStrategy):
    """
    Tit-for-Tat with Forgiveness and Greed.
    
    Strategy logic:
    - Round 1: Defect.
    - Final Round: Defect.
    - Stock 0: Cooperate.
    - Collapse Risk (<= 40% capacity): Cooperate.
    - Expansion Phase (> 80% capacity): Defect.
    - Maintenance Phase (40-80% capacity): Reciprocate based on majority cooperation (k > (n-1)/2).
    - Emergency Rule: If stock drops > 50% in the previous round, Cooperate for two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.emergency_cooperation_counter = 0
        self.prev_stock = float(self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.C
        if history.round_number > 0:
            if self.prev_stock > 0 and (self.prev_stock - current_stock) / self.prev_stock > 0.5:
                self.emergency_cooperation_counter = 2
        self.prev_stock = current_stock
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if self.emergency_cooperation_counter > 0:
            self.emergency_cooperation_counter -= 1
            return Action.C
        if current_stock <= 0.4 * self.capacity:
            return Action.C
        if current_stock > 0.8 * self.capacity:
            return Action.D
        k = history.opponent_cooperators[-1]
        threshold = (self.n - 1) / 2
        if k > threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_94(BaseStrategy):
    """
    Opportunistic Threshold Tit-for-Tat (OT-TFT): 
    Balances cooperative stock preservation with exploitative extraction based on 
    current resource levels and detected opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.previous_S_actual_new = self.capacity
        self.previous_S_prev = self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if t == self.r:
            return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.C
        if current_stock >= self.capacity * 0.8:
            return Action.D
        if t == 1:
            return Action.C
        s_prev = self.previous_S_prev
        expected_consumption = self.n * (s_prev / (2 * self.n))
        expected_remaining = s_prev - expected_consumption
        growth = 2 * expected_remaining * (1 - expected_remaining / self.capacity)
        s_expected_new = min(expected_remaining + growth, self.capacity)
        s_actual_new = current_stock
        self.previous_S_actual_new = s_actual_new
        self.previous_S_prev = current_stock
        if s_expected_new > 1e-06 and s_actual_new < s_expected_new * 0.9:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_95(BaseStrategy):
    """
    Calculated Opportunism: Maximizes individual payoff by tracking sustainability.
    Plays C (Cooperate) to build resources when the pool is healthy, but 
    shifts to D (Defect) when the stock is critically low or when others 
    defect and threaten the resource.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 0.1:
            return Action.D
        n = self.game_description.n_players
        prev_my_action = history.my_actions[-1]
        prev_opp_cooperators = history.opponent_cooperators[-1]
        prev_num_cooperators = prev_opp_cooperators + (1 if prev_my_action else 0)
        prev_num_defectors = n - prev_num_cooperators
        if prev_num_defectors == 0:
            return Action.C
        cons_per_c = current_stock / (2 * n)
        cons_per_d = current_stock / n
        total_consumption = prev_num_cooperators * cons_per_c + prev_num_defectors * cons_per_d
        stock_remaining = max(0.0, current_stock - total_consumption)
        growth = 2 * stock_remaining * (1 - stock_remaining / self.game_description.capacity)
        projected_next_stock = min(stock_remaining + growth, self.game_description.capacity)
        if projected_next_stock < 0.1 * self.game_description.capacity:
            return Action.D
        if random.random() < prev_num_defectors / n:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_96(BaseStrategy):
    """
    A Greedy Tit-for-Tat strategy that cooperates initially, 
    but shifts between cooperation and defection based on 
    the resource's health and the historical cooperation rate of opponents.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_cooperation_rate = 0.75
        self.stock_critical_threshold = 0.25

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 1e-06:
            return Action.D
        total_opponents_c = np.sum(history.opponent_cooperators)
        total_opponents_possible = history.round_number * (self.game_description.n_players - 1)
        if total_opponents_possible == 0:
            history_cooperation_rate = 0.0
        else:
            history_cooperation_rate = total_opponents_c / total_opponents_possible
        if current_stock < self.stock_critical_threshold * self.game_description.capacity:
            return Action.C
        if history_cooperation_rate >= self.threshold_cooperation_rate:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_97(BaseStrategy):
    """
    A strategy for the Common Pool Resource Game that balances resource 
    preservation and exploitation based on current stock levels and 
    observed opponent cooperation rates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.recovery_countdown = 0
        self.previous_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        n_opponents = n - 1
        if t == 0:
            self.previous_stock = current_stock
            return Action.C
        if t == r - 1:
            return Action.D
        if self.recovery_countdown > 0:
            if current_stock > capacity * 0.25:
                self.recovery_countdown = 0
            else:
                self.recovery_countdown -= 1
                self.previous_stock = current_stock
                return Action.C
        if current_stock < 0.05 * capacity:
            self.previous_stock = current_stock
            return Action.C
        if n_opponents > 0:
            c_prev = history.opponent_cooperators[-1] / n_opponents
        else:
            c_prev = 1.0
        threshold = capacity * 0.25
        if current_stock < threshold:
            self.recovery_countdown = 2
            self.previous_stock = current_stock
            return Action.C
        if current_stock >= threshold:
            played_d_last = not history.my_actions[-1]
            stock_increased = current_stock > self.previous_stock
            if played_d_last and stock_increased:
                self.previous_stock = current_stock
                return Action.C
            if c_prev >= 0.5:
                self.previous_stock = current_stock
                return Action.C
            else:
                self.previous_stock = current_stock
                return Action.D
        self.previous_stock = current_stock
        return Action.C

class Strategy_OPPORTUNISTIC_98(BaseStrategy):
    """
    A conditional cooperative strategy for the Common Pool Resource Game.
    It cooperates initially but defects if the collective sustainability is 
    threatened (low cooperation or critical stock levels) or if it is the final round.
    It allows for recovery and re-entry into cooperation if stock levels are sufficiently restored.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.is_defector_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.r:
            return Action.D
        remaining_rounds = self.r - current_round
        s_crit = self.capacity / 2 ** remaining_rounds
        if current_stock < s_crit:
            self.is_defector_mode = True
        if self.is_defector_mode:
            if current_stock >= 0.75 * self.capacity:
                self.is_defector_mode = False
                return Action.C
            return Action.D
        if current_round == 1:
            return Action.C
        n_c = history.opponent_cooperators[-1]
        if n_c < self.n - 1:
            self.is_defector_mode = True
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_99(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy with harvesting thresholds based on the 
    current stock level. It prioritizes sustainability when the stock is low 
    (cooperate), exploits when the stock is high (defect), and mimics the 
    majority behavior otherwise.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.n_rounds - 1:
            return Action.D
        if current_stock <= self.capacity * 0.3:
            return Action.C
        if current_stock > self.capacity * 0.9:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        k = prev_opp_coop + (1 if prev_my_action else 0)
        if k >= self.n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_100(BaseStrategy):
    """
    Implements a strategy for the Common Pool Resource game that conditionally
    cooperates based on the inferred Systemic Cooperation Rate (SCR) from the 
    previous round, unless in the final round where it always defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        if current_round_index == total_rounds - 1:
            return Action.D
        if current_round_index == 0:
            return Action.C
        prev_idx = current_round_index - 1
        opp_c_count = history.opponent_cooperators[prev_idx]
        my_prev_action = history.my_actions[prev_idx]
        c_count = opp_c_count + (1 if my_prev_action else 0)
        scr = c_count / n
        if scr < 0.5:
            return Action.D
        if current_stock <= 0.25 * self.game_description.capacity:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_101(BaseStrategy):
    """
    A threshold-based strategy for the Common Pool Resource Game.
    Transitions between Cooperation (C) and Defection (D) based on stock levels,
    remaining rounds, and observed opponent history.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_t = history.round_number + 1
        if self.r <= 3:
            return Action.D
        if self.r - current_t + 1 <= 2:
            return Action.D
        tau = self.capacity * (self.n / (self.n + 1))
        if history.round_number > 0:
            my_last_action = history.my_actions[-1]
            opponents_last_action_count = history.opponent_cooperators[-1]
            total_cooperators_prev = (1 if my_last_action else 0) + opponents_last_action_count
            if total_cooperators_prev < self.n - 1:
                tau = self.capacity * 0.95
        if current_stock <= 1e-09:
            return Action.D
        if current_stock > tau:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_102(BaseStrategy):
    """
    A 'Grim-Trigger with Proportional Forgiveness' strategy.
    
    This strategy prioritizes sustainability through cooperation (C) when the resource
    is stable, but switches to defection (D) if the common pool is dangerously depleted
    or if the number of cooperators falls below a threshold. It also includes an
    opportunistic harvesting phase when the stock is significantly high.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Terminal Round: Always Defect (D).
    - Critical Depletion: If stock < 10% of capacity, always Defect (D).
    - Cooperation Logic: 
        - Maintains a running 'recovery_counter'.
        - If previous round cooperation >= (n-1) * (n-1)/n, checks for opportunistic harvest.
        - Otherwise, performs retaliatory defection.
    - Recovery: If in a retaliatory state, requires two consecutive rounds of 
      sufficient cooperation to resume cooperating.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.cooperation_threshold = (self.n - 1) * 0.6
        self.recovery_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.1 * self.capacity:
            return Action.D
        last_c = history.opponent_cooperators[-1]
        is_cooperating_level = last_c >= self.cooperation_threshold
        if is_cooperating_level:
            if self.recovery_counter > 0:
                self.recovery_counter -= 1
            if current_stock > 0.75 * self.capacity:
                return Action.D
            else:
                return Action.C
        else:
            self.recovery_counter = 2
            return Action.D

class Strategy_OPPORTUNISTIC_103(BaseStrategy):
    """
    A Trigger-Tit-for-Tat strategy that cooperates to maintain resource levels
    but shifts to aggressive exploitation in the final rounds or if cooperation
    is not reciprocated by n-1 opponents.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_round >= total_rounds - 2:
            return Action.D
        if current_stock < capacity / (2 * n):
            return Action.C
        if current_round == 0:
            return Action.C
        opponents_cooperating = history.opponent_cooperators[-1]
        if opponents_cooperating >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_104(BaseStrategy):
    """
    Implements a tit-for-tat variant that balances stock replenishment with 
    opportunistic defection based on observed population behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number + 1
        if round_number == self.r:
            return Action.D
        if round_number == 1:
            return Action.C
        if current_stock < 0.01:
            return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.C
        try:
            last_round_cooperation_count = int(history.opponent_cooperators[-1])
        except (IndexError, TypeError, ValueError):
            return Action.C
        if last_round_cooperation_count >= self.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_105(BaseStrategy):
    """
    Opportunistic Sustainable-Harvesting (OSH) strategy.
    
    Phases:
    1. Cooperative Phase: Rounds 1 to r-2, if stock > 25% capacity.
       - Cooperate if all (or n-1 for n > 2) others cooperated in previous round.
    2. Terminal/Desperation Phase: Rounds r-1, r OR stock <= 25% capacity.
       - Always Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = self.capacity * 0.25

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_1idx = history.round_number + 1
        is_terminal_round = current_round_1idx >= self.total_rounds - 1
        is_low_stock = current_stock <= self.threshold
        if is_terminal_round or is_low_stock:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        required_cooperation = self.n_players - 1
        if prev_cooperators >= required_cooperation:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_106(BaseStrategy):
    """
    Implements a sustainable common pool resource management strategy.
    
    The strategy prioritizes stock regeneration when the resource is threatened (S < T),
    maximizes utility during healthy periods (S >= T), and attempts to force 
    cooperation when system-wide consumption is too aggressive. 
    It is always cooperative in the first round and always defecting in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.T = self.capacity / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.T:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        k = last_opponent_coops + (1 if last_my_action else 0)
        if current_stock > 0.9 * self.capacity:
            return Action.D
        if current_stock >= self.T:
            if k < self.n / 2:
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_107(BaseStrategy):
    """
    Conditional Cooperation with Harvesting Threshold strategy.
    
    1. Terminal Phase (Last Round): Always Defect.
    2. Resource Collapse Avoidance: Cooperate if stock < (capacity / n).
    3. Adaptive Reciprocity: Mimics opponent cooperation levels if stock is sufficient.
    4. First Round: Cooperate to build trust.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        last_round_index = self.r - 1
        if current_round_index == last_round_index:
            return Action.D
        if current_stock < self.capacity / self.n:
            return Action.C
        if current_round_index == 0:
            return Action.C
        num_cooperators = history.opponent_cooperators[-1]
        if num_cooperators >= (self.n - 1) * 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_108(BaseStrategy):
    """
    A modified Grim-Trigger strategy for the Common Pool Resource Game.
    Prioritizes extraction when the stock is healthy (above 50% capacity).
    When the stock is depleted (<= 50% capacity), it enforces conditional 
    cooperation based on the previous round's cooperation rate (>= 50% of players).
    Always defects in the first and final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_index = history.round_number
        is_first_round = current_round_index == 0
        is_last_round = current_round_index == self.game_description.n_rounds - 1
        if is_first_round:
            return Action.D
        if is_last_round:
            return Action.D
        threshold = self.game_description.capacity * 0.5
        if current_stock > threshold:
            return Action.D
        last_round_idx = -1
        prev_opp_coop = history.opponent_cooperators[last_round_idx]
        prev_my_coop = 1 if history.my_actions[last_round_idx] else 0
        total_cooperators = prev_opp_coop + prev_my_coop
        n_players = self.game_description.n_players
        if total_cooperators >= n_players / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_109(BaseStrategy):
    """
    A conditional trigger-based strategy for the Common Pool Resource game.
    
    Phases:
    1. Initial Rounds (1-3): Cooperates to preserve stock.
    2. Monitoring: Tracks opponents' cooperation in the previous round.
    3. Retaliation: If more than 1 opponent defects, switches to 'Predatory Mode' for 2 rounds.
    4. Adaptive: In Predatory Mode, switches to D (Defect). Afterward, returns to C unless stock is low.
    
    Terminals/Edge cases:
    - Last round: Always defects (D).
    - Stock collapse (S=0): Always defects (D).
    - Low stock recovery (S < capacity/4): Prioritizes self-preservation (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.predatory_rounds_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if current_stock < self.game_description.capacity / 4:
            return Action.D
        if history.round_number < 3:
            return Action.C
        if self.predatory_rounds_remaining > 0:
            self.predatory_rounds_remaining -= 1
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        prev_opp_defectors = n_opponents - prev_opp_coop
        if prev_opp_defectors > 1:
            self.predatory_rounds_remaining = 1
            return Action.D
        if current_stock > self.game_description.capacity / 2:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_110(BaseStrategy):
    """
    Conditional Sustainability Monitoring (CSM) strategy.
    
    A Tit-for-Tat variant calibrated to stock regeneration.
    - Maintains cooperation if stock is healthy and majority cooperates.
    - Prioritizes stock regeneration if below critical threshold (capacity/2).
    - Defects in final round or if stock is critically compromised beyond recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.critical_threshold = game_description.capacity / 2
        self.permanent_defect_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if self.permanent_defect_mode:
            return Action.D
        if current_stock < self.critical_threshold:
            if current_round > 0 and history.my_actions[-1] == Action.C.value:
                self.permanent_defect_mode = True
                return Action.D
            return Action.C
        if current_round == 0:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        prev_opp_cooperated = history.opponent_cooperators[-1]
        cooperation_threshold = math.ceil(n_opponents / 2)
        if prev_opp_cooperated >= cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_111(BaseStrategy):
    """
    Threshold-Gated Reciprocity Strategy:
    1. Initial round: Cooperate.
    2. Terminal round: Defect.
    3. Low stock threshold (S < 0.5 * capacity): Defect to maximize immediate utility.
    4. Reciprocity: If stock is healthy, cooperate only if opponents' 
       cooperation count >= 75% of (n-1).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.s_crit = 0.5 * self.capacity
        self.coop_threshold = (self.n - 1) * 0.75

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < self.s_crit:
            return Action.D
        opponents_cooperated = history.opponent_cooperators[-1]
        if opponents_cooperated >= self.coop_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_112(BaseStrategy):
    """
    Constrained Tit-for-Tat with Depletion Thresholding.
    
    This strategy aims to maximize long-term utility by cooperating when the resource is sustainable 
    and partners are cooperative. If the resource drops below a critical threshold, it 
    switches to aggressive extraction (Defect) unless everyone else is still cooperating.
    In the final round, it always Defects to maximize terminal payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.defection_threshold = self.game_description.capacity * 0.4

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if current_stock < self.defection_threshold:
            if prev_k == n_opponents:
                return Action.C
            else:
                return Action.D
        elif prev_k == n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_113(BaseStrategy):
    """
    A strategy that prioritizes long-term resource stability via conditional cooperation,
    switching to aggressive exploitation (Defection) when the resource becomes non-viable
    or the group signals a terminal collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num_index = history.round_number
        current_round = round_num_index + 1
        if current_round == self.r:
            return Action.D
        threshold = self.capacity / self.n
        if current_stock < threshold:
            return Action.D
        if round_num_index > 0:
            my_prev_action = history.my_actions[-1]
            opponents_prev_coop = history.opponent_cooperators[-1]
            total_prev_coop = opponents_prev_coop + (1 if my_prev_action else 0)
            if total_prev_coop < self.n * 0.25:
                return Action.D
            if current_stock > 0.5 * self.capacity:
                return Action.C
            if total_prev_coop > self.n / 2:
                return Action.C
            else:
                return Action.D
        if current_round == 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_114(BaseStrategy):
    """
    Implements the Conditional Sustainability Exploitation strategy.
    
    1. Always Cooperate in the first round.
    2. Always Defect in the final round.
    3. In intermediate rounds:
       - If stock < 25% of capacity: Defect.
       - If stock >= 25% of capacity:
         - Calculate Cooperation Rate P = k / n.
         - If P >= 0.5: Cooperate.
         - If P < 0.5: Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            return Action.D
        critical_threshold = 0.25 * self.capacity
        if current_stock < critical_threshold:
            return Action.D
        last_action_was_cooperate = bool(history.my_actions[-1])
        opponents_cooperating = int(history.opponent_cooperators[-1])
        total_cooperators = opponents_cooperating + (1 if last_action_was_cooperate else 0)
        population_cooperation_rate = total_cooperators / self.n
        if population_cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_115(BaseStrategy):
    """
    A strategy for the Common Pool Resource Game that balances cooperation
    based on the group's past behavior (Cooperation Threshold) and environmental
    safety (Recovery Override).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number + 1
        k_prev = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        k = k_prev + (1 if my_prev_action else 0)
        if t == r_total:
            return Action.D
        if current_stock < capacity / n:
            return Action.C
        if current_stock <= 0:
            return Action.D
        if k / n >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_116(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Harvesting Thresholds.
    Maintains cooperation when stock is critical or when the majority cooperates,
    otherwise defects. Always defects in the terminal round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        last_round_index = -1
        opp_coops = int(history.opponent_cooperators[last_round_index])
        my_prev_action = 1 if history.my_actions[last_round_index] else 0
        total_cooperators = opp_coops + my_prev_action
        if total_cooperators >= self.n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_117(BaseStrategy):
    """
    Implements a resource-aware strategy for the Common Pool Resource Game.
    Prioritizes sustainability via critical threshold checks and adapts 
    to group dynamics in mid-range stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.critical_threshold = 0.2 * game_description.capacity
        self.surplus_threshold = 0.8 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.critical_threshold:
            return Action.C
        if current_stock > self.surplus_threshold:
            return Action.D
        prev_my_action_int = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + prev_my_action_int
        if total_cooperators >= self.game_description.n_players / 2:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_118(BaseStrategy):
    """
    A resource-management strategy that prioritizes long-term cooperation while
    incorporating dynamic defect-switching based on observed opponent behavior 
    and opportunistic recovery checks.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_defecting = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round == 1:
            return Action.C
        if self.is_defecting and current_stock > 0.75 * capacity:
            self.is_defecting = False
            return Action.C
        if current_round == r:
            if current_stock >= 0.5 * capacity:
                return Action.D
            return Action.D
        last_opponents_c = history.opponent_cooperators[-1]
        if last_opponents_c < n - 1:
            self.is_defecting = True
        else:
            self.is_defecting = False
        if self.is_defecting:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_119(BaseStrategy):
    """
    Trigger-Modified Tit-for-Tat strategy.
    
    This strategy maintains resource stock levels by cooperating when opponents
    are cooperative, but shifts to defection in final rounds or when resource
    levels are threatened. It includes specific heuristics for recovery mode
    and immediate retaliation based on observed stock depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.recovery_mode_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        n_opponents = n_players - 1
        if self.recovery_mode_counter > 0:
            self.recovery_mode_counter -= 1
            return Action.C
        if current_stock < 0.1 * capacity:
            self.recovery_mode_counter = 1
            return Action.C
        if round_idx > 0:
            if history.opponent_cooperators[-1] < n_opponents:
                return Action.D
        if round_idx == total_rounds - 1:
            return Action.D
        if round_idx == total_rounds - 2:
            if current_stock > 0.75 * capacity:
                return Action.C
            else:
                return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < capacity / 2:
            return Action.C
        if history.opponent_cooperators[-1] == n_opponents:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_120(BaseStrategy):
    """
    A strategy that maintains a state of 'punishment'. It cooperates by default but
    switches to defect if opponents defect. It also aggressively defects if the
    stock resource nears depletion or if it is the final round of the game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_punishing = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        round_number = history.round_number + 1
        if round_number == self.game_description.n_rounds:
            return Action.D if current_stock > 0 else Action.C
        if current_stock <= self.game_description.capacity * 0.25:
            return Action.D
        if round_number == 1:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        i_defected = 1 if not my_prev_action else 0
        total_defectors_prev = n_opponents - prev_cooperators + i_defected
        if self.is_punishing:
            if total_defectors_prev == 0:
                self.is_punishing = False
                return Action.C
            else:
                return Action.D
        elif total_defectors_prev == 0:
            return Action.C
        else:
            self.is_punishing = True
            return Action.D

class Strategy_OPPORTUNISTIC_121(BaseStrategy):
    """
    Conditional Sustainability with End-Game Defection.
    
    A strategy that balances stock preservation with resource exploitation:
    1. Always cooperates in the first round.
    2. Always defects in the final round.
    3. If stock is dangerously low (<= 1e-6), cooperates to prevent extinction.
    4. If stock is healthy (> capacity/4): Cooperates if >= n/2 opponents cooperated previously.
    5. If stock is low but not critical (< capacity/4): Cooperates only if >= n-1 opponents cooperated previously.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        r_left = self.n_rounds - history.round_number
        if r_left == 1:
            return Action.D
        if current_stock <= 1e-06:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if current_stock < self.capacity / 4.0:
            if prev_cooperators >= self.n_players - 1:
                return Action.C
            else:
                return Action.D
        elif prev_cooperators >= self.n_players / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_122(BaseStrategy):
    """
    A conditional cooperation strategy that balances resource sustainability
    with opportunistic exploitation. It adapts to the aggregate cooperation
    levels observed in the previous round, utilizing probability to match
    cooperation signals while defaulting to defection in terminal phases
    or low-resource environments.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if current_stock < 0.1 * capacity:
            self.permanent_defection = True
        if self.permanent_defection:
            return Action.D
        if round_idx == 0:
            return Action.C
        if round_idx == r - 1:
            return Action.D
        my_last_action = history.my_actions[-1]
        opponents_cooperating = history.opponent_cooperators[-1]
        total_cooperators = opponents_cooperating + (1 if my_last_action else 0)
        total_defectors = n - total_cooperators
        if total_defectors > n / 2:
            self.permanent_defection = True
            return Action.D
        if total_defectors == 0:
            return Action.C
        else:
            c_consumption = total_cooperators * (current_stock / (2 * n))
            d_consumption = total_defectors * (current_stock / n)
            projected_s_remaining = current_stock - (c_consumption + d_consumption)
            if projected_s_remaining < 0.25 * capacity:
                return Action.D
            if random.random() < (n - total_defectors) / n:
                return Action.C
            else:
                return Action.D

class Strategy_OPPORTUNISTIC_123(BaseStrategy):
    """
    A strategy that initiates cooperation, then switches to defect on the final round,
    or mid-game if the stock is critically low or if the opponent group cooperation 
    ratio falls below 50%.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        last_round_cooperators = history.opponent_cooperators[-1]
        if n_opponents == 0:
            cooperation_ratio = 1.0
        else:
            cooperation_ratio = last_round_cooperators / n_opponents
        if current_stock < self.game_description.capacity / self.game_description.n_players:
            return Action.D
        if cooperation_ratio < 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_124(BaseStrategy):
    """
    Implements an Adaptive Threshold strategy for the Common Pool Resource Game.
    
    Logic:
    - Round 1: Always Cooperate.
    - Last Round: Always Defect if stock > 0.
    - Intermediate Rounds:
        - Critical Decline: If stock < capacity/n, Defect.
        - Adaptive Thresholding: Uses a running reputation index R based on past cooperation.
          - R > 0.75: Cooperate.
          - 0.4 <= R <= 0.75: Cooperate with probability P = (R - 0.4) / 0.35.
          - R < 0.4: Defect.
    - State Recovery: If stock increases > 20% from previous, reset reputation index.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.previous_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if round_idx == 0:
            self.previous_stock = current_stock
            return Action.C
        if round_idx == self.game_description.n_rounds - 1:
            if current_stock > 0:
                return Action.D
            return Action.C
        recovery = False
        if round_idx > 0:
            if current_stock > 1.2 * self.previous_stock:
                recovery = True
        if recovery:
            reputation = 1.0
        else:
            total_coop_sum = 0
            for r in range(round_idx):
                my_prev_action = 1 if history.my_actions[r] else 0
                opp_prev_action = history.opponent_cooperators[r]
                total_coop_sum += my_prev_action + opp_prev_action
            reputation = total_coop_sum / (n * round_idx)
        self.previous_stock = current_stock
        if current_stock < capacity / n:
            return Action.D
        if reputation > 0.75:
            return Action.C
        if 0.4 <= reputation <= 0.75:
            prob = (reputation - 0.4) / 0.35
            return Action.C if random.random() < prob else Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_125(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Harvesting Threshold:
    A conditional strategy that cooperates when the common pool is healthy and community 
    cooperation is high, but switches to aggressive extraction (Defect) if the pool 
    is critical or if others are over-exploiting the resource. It attempts to 
    signal reconciliation only when stock levels demonstrate significant recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.is_punishing = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        prev_defectors = self.n_players - 1 - prev_cooperators
        if current_stock < self.capacity / 4.0:
            self.is_punishing = True
            return Action.D
        if self.is_punishing:
            if current_stock >= 0.9 * self.capacity:
                self.is_punishing = False
                return Action.C
            else:
                return Action.D
        if prev_defectors > 1:
            self.is_punishing = True
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_126(BaseStrategy):
    """
    A strategy that plays C initially, and in subsequent rounds:
    1. If the stock is critically low (< 25% capacity), play C to prevent collapse.
    2. In the final two rounds, play D (unless stock is empty).
    3. Otherwise, if the last round had defectors (opponents who played D),
       punish by playing D, but otherwise cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 0:
            return Action.C
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.game_description.n_rounds - 2:
            return Action.D
        if current_stock / self.game_description.capacity < 0.25:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        last_round_defectors = self.n_opponents - last_round_cooperators
        if last_round_defectors > 0:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_127(BaseStrategy):
    """
    Implements a sustainability-focused strategy for the Common Pool Resource Game.
    - Initial Round: Always Cooperate.
    - Terminal Round: Always Defect.
    - Intermediate Rounds:
        - If stock >= 0.5 * capacity: Cooperate if the majority (>= n/2) of the group 
          cooperated in the previous round, else Defect.
        - If stock < 0.5 * capacity: Defect to capture remaining value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        sustainability_threshold = 0.5 * self.game_description.capacity
        if current_stock < sustainability_threshold:
            return Action.D
        total_cooperators = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
        required_cooperation = math.ceil(self.game_description.n_players / 2)
        if total_cooperators >= required_cooperation:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_128(BaseStrategy):
    """
    Tit-for-Tat with Threshold Sensitivity.
    1. Initial Round: Always Co-operate (C).
    2. Subsequent Rounds (non-terminal):
       - If stock < 0.25 * capacity: Co-operate (C) (Emergency Conservation).
       - Else if all opponents cooperated in previous round: Defect (D) (Exploitation).
       - Else: Co-operate (C) (Incentivization).
    3. Terminal Phase (Last 3 rounds):
       - If stock > 0.25 * capacity: Defect (D) (Extract residual value).
       - Else: Co-operate (C) (Salvage remaining stock).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number >= total_rounds - 3:
            if current_stock > capacity * 0.25:
                return Action.D
            else:
                return Action.C
        if current_stock < capacity * 0.25:
            return Action.C
        k = history.opponent_cooperators[-1]
        if k == self.n_opponents:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_33(BaseStrategy):
    """
    Implements a resource-conscious strategy that cooperates while the pool is 
    sustainable, retaliates against mass defection, and defects when the 
    resource collapses or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < self.capacity / 4.0:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        last_action_was_C = history.my_actions[-1]
        k_prev = self.n - (prev_cooperators + (1 if last_action_was_C else 0))
        if k_prev == 0:
            return Action.C
        if k_prev >= self.n / 2.0:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_34(BaseStrategy):
    """
    Adaptive Tit-for-Tat with Threshold Depletion Control.
    
    Strategies:
    - Round 1: Cooperate.
    - Final Round: Defect (maximize extraction).
    - Survival Mode: If stock < 50% capacity, forced Cooperate to prevent collapse.
    - Stability Mode: If stock >= 50% capacity, Cooperate if at least half of the other 
      players cooperated in the previous round, else Defect.
    - Edge Case handling: Epsilon tolerance for floating-point comparisons.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.epsilon = 1e-06

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.epsilon:
            return Action.D
        capacity = self.game_description.capacity
        if current_stock < 0.5 * capacity - self.epsilon:
            return Action.C
        n = self.game_description.n_players
        threshold = math.ceil(n / 2)
        last_cooperators = history.opponent_cooperators[-1]
        if last_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_35(BaseStrategy):
    """
    A Tit-for-Tat adaptation for Common Pool Resource games.
    Maintains a target cooperation level based on sustainability dynamics.
    - Round 1: Always Cooperate.
    - Maintenance: Uses a threshold (CT) of cooperative opponents to decide between Cooperation and Defection.
    - Sustainability Buffer: If stock < 0.75 * capacity, prioritizes immediate utility (Defect).
    - Endgame: Always Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.sustainability_buffer = 0.75 * self.capacity

    def _calculate_required_cooperators(self, current_stock: float) -> int:
        """
        Calculates the minimum number of cooperators required to keep the stock from shrinking.
        
        Stock Dynamics: 
        New_S = min(S_rem + 2 * S_rem * (1 - S_rem/C), C)
        We want New_S >= S_curr (or as close as possible).
        
        Let k be the number of cooperators (Action.C) among n players.
        Consumption_i_C = S / (2n)
        Consumption_i_D = S / n
        Total Consumption (TC) = k * (S / 2n) + (n - k) * (S / n)
                               = (S / 2n) * (k + 2(n - k))
                               = (S / 2n) * (2n - k)
        
        We need: S - TC + growth(S - TC) >= S
        This implies: growth(S - TC) >= TC
        
        Since solving this analytically for integer k is complex, we use a simple heuristic:
        The "neutral" state where stock is stable usually requires a certain cooperation density.
        For simplicity and robustness, we approximate the break-even point.
        """
        if current_stock <= 0:
            return self.n
        stock_ratio = current_stock / self.capacity
        ct = math.ceil(self.n * (1.0 - stock_ratio))
        return max(0, min(self.n, ct))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if current_stock < self.sustainability_buffer:
            return Action.D
        ct = self._calculate_required_cooperators(current_stock)
        prev_cooperators = int(history.opponent_cooperators[-1])
        if prev_cooperators >= ct:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_36(BaseStrategy):
    """
    Implements the Dynamic Threshold Reciprocity strategy.
    
    This strategy focuses on sustaining the common pool resource when it is scarce
    by conditioning cooperation on opponent behavior, while prioritizing individual 
    payoff maximization (defection) when the resource is abundant.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if current_stock > 0.5 * self.game_description.capacity:
            return Action.D
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        threshold = math.ceil(n * (current_stock / capacity))
        if threshold <= 0:
            return Action.D
        k = history.opponent_cooperators[-1]
        if k >= threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_37(BaseStrategy):
    """
    Implements a 'Sustainable Reciprocity' strategy.
    
    Logic overview:
    1. First Round: Always Cooperate (C) to build base stock.
    2. Last Round: Always Defect (D) to maximize final return.
    3. Safety Constraint: If stock < 50% capacity OR < 10% capacity, always C (recover).
    4. Reciprocity Trigger: If previous round's opponent cooperation is low (< 50% of opponents), play C to stabilize.
    5. Optimal Exploitation: If stock >= 50% capacity AND opponent cooperation is high (> 80%), play D to exploit surplus.
    6. Default: Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_total = game_description.n_players
        self.n_opponents = self.n_total - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds:
            return Action.D
        prev_opponent_c = float(history.opponent_cooperators[-1])
        if current_stock < 0.1 * self.capacity:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.C
        if self.n_opponents > 0 and prev_opponent_c < self.n_opponents * 0.5:
            return Action.C
        if self.n_opponents > 0 and prev_opponent_c >= self.n_opponents * 0.8:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_38(BaseStrategy):
    """
    Conditional Sustainability Strategy.
    
    This strategy focuses on resource preservation. It begins by cooperating. 
    In subsequent rounds (up to the penultimate one), it monitors the current stock 
    and the previous round's cooperation levels. 
    
    - If the stock is critically low (below capacity/4), it defects to maximize 
      immediate utility before collapse.
    - If the stock is healthy, it cooperates only if the majority of the group 
      cooperated in the previous round.
    - It always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_round_cooperators = int(history.opponent_cooperators[-1])
        my_last_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev_round = last_round_cooperators + my_last_action
        if current_stock < capacity / 4:
            return Action.D
        if total_cooperators_prev_round > n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_39(BaseStrategy):
    """
    Adaptive Sustainable Tit-for-Tat:
    A strategy that maintains cooperation while resources are stable (k >= n-1).
    It defects when group cooperation drops below thresholds or stock is dangerously low.
    It includes a re-entry mechanism to attempt cooperation if the stock recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == r - 1:
            return Action.D
        if current_stock < capacity / (2 * n):
            return Action.D
        k = history.opponent_cooperators[-1]
        previous_action_was_cooperate = history.my_actions[-1]
        if not previous_action_was_cooperate and current_stock >= 0.9 * capacity:
            return Action.C
        if k >= n - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_40(BaseStrategy):
    """
    Triggered Tit-for-Tat strategy that prioritizes sustainability early, 
    monitors group cooperation to decide on continued cooperation, 
    and shifts to aggressive extraction as the game nears completion 
    or if the resource stock falls below critical thresholds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        current_round_num = round_idx + 1
        if current_round_num == self.r:
            return Action.D
        if current_round_num == 1:
            return Action.C
        if current_stock <= 0.5 * self.capacity:
            return Action.D
        prev_round_idx = round_idx - 1
        others_cooperated = history.opponent_cooperators[prev_round_idx]
        i_cooperated = 1 if history.my_actions[prev_round_idx] else 0
        total_cooperators = others_cooperated + i_cooperated
        cooperation_index = total_cooperators / self.n
        if cooperation_index >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_41(BaseStrategy):
    """
    A strategy that maintains a trust level based on collective cooperation.
    It cooperates more frequently when trust is high and stock is healthy,
    defaults to cooperation when stock is critical (<= capacity/4),
    and always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_level = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_round_idx > 0:
            prev_cooperators = history.opponent_cooperators[-1]
            my_prev_action = history.my_actions[-1]
            total_cooperators = prev_cooperators + (1 if my_prev_action else 0)
            if total_cooperators == n:
                self.trust_level = min(1.0, self.trust_level + 0.1)
            elif total_cooperators == 0:
                self.trust_level = max(0.0, self.trust_level - 0.5)
            else:
                self.trust_level = max(0.0, self.trust_level - 0.2)
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock <= capacity / 4.0:
            return Action.C
        if random.random() < self.trust_level:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_42(BaseStrategy):
    """
    A strategy that balances cooperative potential with resource sustainability.
    It defaults to cooperation, but monitors stock levels and group cooperation 
    trends to switch to defection if sustainability is at risk or exploitation occurs.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.tolerance = self.n / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        prev_opponents_cooperated = history.opponent_cooperators[prev_round]
        prev_action_bool = history.my_actions[prev_round]
        multiplier = 2 * self.n if prev_action_bool else self.n
        prev_stock = history.my_payoffs[prev_round] * multiplier
        stock_decline = prev_stock - current_stock
        if stock_decline > 0.5 * prev_stock and prev_stock > 0:
            return Action.D
        if current_stock < self.capacity / 4:
            return Action.C
        if prev_opponents_cooperated >= self.n - 1:
            return Action.C
        elif prev_opponents_cooperated >= self.tolerance:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_43(BaseStrategy):
    """
    Strategy: Conditional Sustainability with Sunset Defection
    - Rounds 1 to r-1: Cooperative if stock >= 50% capacity AND no opponents defected in the previous round.
    - If stock < 50% capacity: Defect immediately.
    - If any opponent defected in the previous round: Defect (punishment phase).
    - Round r: Always defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_total = game_description.n_players
        self.n_opponents = self.n_total - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        if last_round_cooperators < self.n_opponents:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_44(BaseStrategy):
    """
    Adaptive Threshold Tit-for-Tat (AT-TFT).
    Maximizes cumulative utility by balancing stock preservation (via thresholds) 
    and social reciprocity (via history-based defector monitoring).
    
    Logic:
    - First round: Always Cooperate.
    - Last round: Always Defect (no future value).
    - Crisis mode (S < 25% cap): Defect to extract before total collapse.
    - High-abundance mode (S >= 75% cap): Cooperate if average defectors over k=3 rounds < n/4.
    - Moderate mode (25% <= S < 75% cap): Cooperate if 0 defectors in last round, else Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.k_window = 3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_coops_last = history.opponent_cooperators[-1] + my_last_action_val
        defectors_last_round = n - total_coops_last
        start_idx = max(0, history.round_number - self.k_window)
        defectors_history = []
        for r in range(start_idx, history.round_number):
            my_act = 1 if history.my_actions[r] else 0
            opp_coops = history.opponent_cooperators[r]
            defectors_history.append(n - (opp_coops + my_act))
        avg_defectors = np.mean(defectors_history) if defectors_history else 0
        if current_stock < 0.25 * capacity:
            return Action.D
        elif current_stock >= 0.75 * capacity:
            if avg_defectors < n / 4:
                return Action.C
            else:
                return Action.D
        elif defectors_last_round == 0:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_45(BaseStrategy):
    """
    Adaptive Sustainable Reciprocator:
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1:
        - If previous round defectors >= n/2: Defect (D).
        - If previous round defectors < n/2: 
            - If stock is critical (< capacity / 2n): Defect (D) to capture value.
            - Else: Cooperate (C).
    - Round r (Terminal):
        - If stock > capacity/4: Cooperate (C).
        - Else: Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == total_rounds - 1:
            if current_stock > capacity / 4.0:
                return Action.C
            else:
                return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        prev_defectors = n - 1 - prev_cooperators
        if current_stock < capacity / (2.0 * n):
            return Action.D
        if prev_defectors >= n / 2.0:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_46(BaseStrategy):
    """
    A Tit-for-Tat strategy designed for Common Pool Resource games.
    It cooperates to keep the resource at capacity, but switches to defection
    (punishment) if the stock level drops below half capacity or if any opponent
    defects. It also unilaterally defects in the final round to maximize payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_penalizing = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            self.is_penalizing = False
            return Action.C
        prev_round_idx = history.round_number - 1
        n_opponents = self.game_description.n_players - 1
        d_opponents = n_opponents - history.opponent_cooperators[prev_round_idx]
        if current_stock < self.game_description.capacity / 2.0 or d_opponents > 0:
            self.is_penalizing = True
        else:
            self.is_penalizing = False
        if self.is_penalizing:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_47(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with sustainability thresholds.
    Prioritizes resource preservation (Cooperation) when stock is low,
    and uses conditional reciprocity (Tit-for-Tat) when stock is healthy.
    Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < 0.1 * self.capacity:
            return Action.C
        if current_stock < 0.25 * self.capacity:
            return Action.C
        last_opponents_cooperated = history.opponent_cooperators[-1]
        last_action_was_coop = history.my_actions[-1]
        if last_action_was_coop:
            denom = self.n - 1 if self.n > 1 else 1
            coop_rate = last_opponents_cooperated / denom
        else:
            denom = self.n
            coop_rate = last_opponents_cooperated / denom
        if coop_rate >= 0.5:
            return Action.C
        elif current_stock < 0.5 * self.capacity:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_48(BaseStrategy):
    """
    Implements a Sustainability-Triggered Tit-for-Tat (ST-TFT) strategy.
    
    Logic Summary:
    1. Initial Round: Cooperate.
    2. Final Round: Defect to maximize extraction.
    3. Emergency: If stock < 10% capacity, force Cooperate to prevent collapse.
    4. Punishment/Collapse Avoidance:
       - If system detects 3 consecutive rounds of k_t-1 < n-1 (insufficient cooperation),
         permanently switch to Defect.
       - If previous round had more than 1 defector, Defect (tit-for-tat punishment).
       - If stock >= 80% capacity, Defect (opportunistic harvest).
       - Otherwise, Cooperate (conservative maintenance).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.persistent_defection_mode = False
        self.consecutive_low_cooperation_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        i_cooperated_last = 1 if history.my_actions[-1] else 0
        total_cooperators_last = prev_cooperators + i_cooperated_last
        num_defectors_last = self.n - total_cooperators_last
        if total_cooperators_last < self.n - 1:
            self.consecutive_low_cooperation_rounds += 1
        else:
            self.consecutive_low_cooperation_rounds = 0
        if self.consecutive_low_cooperation_rounds >= 3:
            self.persistent_defection_mode = True
        if self.persistent_defection_mode:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.C
        if num_defectors_last > 1:
            return Action.D
        if current_stock >= 0.8 * self.capacity:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_49(BaseStrategy):
    """
    A strategy that maintains a reputation score based on past cooperation.
    It cooperates if the reputation score exceeds a threshold (0.5 for non-final rounds).
    It prioritizes stock recovery by cooperating if stock < capacity/n, unless it's the final round.
    It always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation_score = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if round_t == 0:
            self.reputation_score = 1.0
            return Action.C
        prev_round_cooperators = history.opponent_cooperators[-1]
        coop_ratio = prev_round_cooperators / (n - 1)
        self.reputation_score = self.reputation_score * 0.9 + coop_ratio * 0.1
        if round_t == total_rounds - 1:
            return Action.D
        if current_stock < capacity / n:
            return Action.C
        if self.reputation_score > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_50(BaseStrategy):
    """
    A strategy for the Common Pool Resource Game that balances cooperation with
    retaliatory defection.
    
    Logic:
    1. First round: Always Cooperate (C).
    2. Final round: Always Defect (D).
    3. Emergency: If stock < capacity / n, Defect (D).
    4. Otherwise: Cooperate (C) if all opponents cooperated in the previous round,
       otherwise Defect (D) to retaliate/preserve stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / self.game_description.n_players:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        if prev_opp_coop == self.n_opponents:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_51(BaseStrategy):
    """
    A strategy that maintains a running estimate of opponent cooperation ('state_reputation').
    It cooperates early when stock is healthy and reputation is high, switches to
    exploitation when stock is low, and defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.state_reputation = 0.5
        self.alpha = 0.3
        self.gamma = 0.7

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        n_opponents = n - 1
        norm_coop = prev_opp_coop / n_opponents if n_opponents > 0 else 0.0
        if n == 2:
            self.state_reputation = self.state_reputation * self.gamma + (1 - self.gamma) * norm_coop
        else:
            self.state_reputation = (1 - self.alpha) * self.state_reputation + self.alpha * norm_coop
        if current_stock < 1e-09:
            return Action.D
        if current_stock < self.game_description.capacity * 0.2:
            return Action.D
        if self.state_reputation >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_52(BaseStrategy):
    """
    Tit-for-Tat with Threshold Monitoring strategy.
    Maintains a reputation metric based on opponent cooperation to inform
    switching between Cooperator and Defector modes, with safeguards for
    critical resource levels and terminal rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.gamma = 0.8
        self.reputation = 0.5
        self.n = self.game_description.n_players
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.reputation = 0.5
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        d_t = self.n_opponents - prev_cooperators
        self.reputation = self.gamma * self.reputation + (1 - self.gamma) * (1 - d_t / self.n_opponents)
        s_crit = 0.2 * self.game_description.capacity
        if current_stock < s_crit:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if self.reputation < 0.4:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_53(BaseStrategy):
    """
    Implements a Conditional Sustainability Targeting strategy.
    
    This strategy attempts to maintain the common pool resource at a sustainable level 
    (>= capacity/2) by cooperating when collective restraint is observed. 
    It shifts to defecting in the final round, when the resource is depleted, 
    or when the group fails to maintain sufficient collective restraint.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_cooperators = history.opponent_cooperators[-1]
        k = last_opponent_cooperators + (1 if last_my_action else 0)
        threshold_stock = capacity / 2.0
        threshold_restraint = n / 2.0
        if current_stock >= threshold_stock and k >= threshold_restraint:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_54(BaseStrategy):
    """
    Implements Adaptive Tit-for-Tat with Resource Preservation Threshold.
    
    Strategy:
    1. First Round: Always Cooperate.
    2. Final Round: Always Defect (unless overridden by sustainability).
    3. Sustainability Override: If stock < capacity / (2 * n), always Cooperate to preserve the pool.
    4. Adaptive Punishment: If (n - previous_cooperators) / n > 0.5, Defect. Otherwise, Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == 1:
            return Action.C
        threshold = capacity / (2.0 * n)
        if current_stock < threshold:
            return Action.C
        if current_round == total_rounds:
            return Action.D
        previous_idx = history.round_number - 1
        prev_opp_coop = int(history.opponent_cooperators[previous_idx])
        prev_my_action = bool(history.my_actions[previous_idx])
        total_coop = prev_opp_coop + (1 if prev_my_action else 0)
        defect_count = n - total_coop
        if defect_count / n > 0.5:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_55(BaseStrategy):
    """
    Implements a sustainability-focused strategy that defaults to cooperation but 
    shifts to defection (extraction) if the resource stock drops below 50% capacity, 
    if any other player defects, or if it is the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.n_players = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        prev_round_idx = -1
        prev_n_coops = history.opponent_cooperators[prev_round_idx]
        n_opponents = self.n_players - 1
        prev_n_defectors = n_opponents - prev_n_coops
        if current_stock < self.capacity / 2:
            return Action.D
        if prev_n_defectors > 0:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_56(BaseStrategy):
    """
    A strategy that implements "Targeted Sustainability":
    - Cooperates in the first round.
    - Defects in the final round.
    - For intermediate rounds, cooperates only if the stock is >= 50% capacity
      AND the number of other cooperators in the previous round was >= ceil(n/2).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.D
        sustainability_threshold = self.capacity * 0.5
        participation_threshold = (self.n_players + 1) // 2
        prev_cooperators = history.opponent_cooperators[-1]
        if current_stock >= sustainability_threshold and prev_cooperators >= participation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_57(BaseStrategy):
    """
    Implements Sustainable Tit-for-Tat (STFT).
    
    Logic:
    - Always cooperates on the first round.
    - Always defects on the last round.
    - Defects if the stock is below half capacity (desperation).
    - If stock is healthy:
        - If previous round saw universal cooperation, cooperate.
        - If previous round saw any defection, defect (retaliation).
        - If previously in a punishment state (defected), return to cooperate
          only if all opponents cooperated in the previous round (forgiveness).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        if current_stock < capacity / 2:
            return Action.D
        prev_idx = current_round - 1
        n_coop_opponents = history.opponent_cooperators[prev_idx]
        my_prev_action = history.my_actions[prev_idx]
        all_cooperated = n_coop_opponents == n_opponents and my_prev_action == True
        any_opponents_defected = n_coop_opponents < n_opponents
        if all_cooperated:
            return Action.C
        if any_opponents_defected:
            return Action.D
        if my_prev_action == False:
            if n_coop_opponents == n_opponents:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_58(BaseStrategy):
    """
    A strategy that employs "Conditional Sustainability" to balance long-term 
    resource accumulation with punishment of defectors. 
    It cooperates at capacity, defects in terminal rounds, and switches to 
    extraction (defect) if the resource drops below 20% capacity or if 
    the group fails to maintain a minimum cooperative threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.k = math.ceil(self.n / 2)
        self.s_min = 0.2 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.r:
            return Action.D
        if current_round == 1:
            return Action.C
        if current_stock <= self.s_min:
            return Action.D
        last_round_idx = -1
        last_round_cooperators = history.opponent_cooperators[last_round_idx]
        if last_round_cooperators >= self.k:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_59(BaseStrategy):
    """
    Threshold-Based Tit-For-Tat (TBTFT): A sustainability-linked reciprocal strategy.
    
    Operates on reciprocity by monitoring the Sustainability Index (SI) of the common pool.
    Plays 'C' while the pool is managed sustainably, switches to 'D' if over-exploited,
    and returns to 'C' only upon sufficient recovery. Incorporates end-game defection
    and critical depletion safeguards.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._prev_stock_cache = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 0.1 * self.game_description.capacity:
            return Action.D
        if history.round_number == 0:
            self._prev_stock_cache = current_stock
            return Action.C
        n = self.game_description.n_players
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + my_prev_action
        if self._prev_stock_cache <= 1e-09:
            tc = 0.0
        else:
            tc = total_cooperators * (self._prev_stock_cache / (2 * n)) + (n - total_cooperators) * (self._prev_stock_cache / n)
        sac = max(0.0, self._prev_stock_cache - tc)
        if self._prev_stock_cache <= 1e-09:
            si = 0.0
        else:
            si = sac / (self._prev_stock_cache / 2.0)
        is_unsustainable = si < 1.0
        is_critical_low = current_stock < 0.25 * self.game_description.capacity
        if is_unsustainable or is_critical_low:
            action = Action.D
        elif current_stock >= 0.8 * self.game_description.capacity:
            action = Action.C
        elif current_stock >= 0.5 * self.game_description.capacity:
            action = Action.C
        else:
            action = Action.D
        self._prev_stock_cache = current_stock
        return action

class Strategy_INDIVIDUALISTIC_60(BaseStrategy):
    """
    A conditional 'Tit-for-Tat' variant that prioritizes resource sustainability.
    
    Logic:
    1. First round: Cooperate.
    2. Last round: Defect.
    3. Intermediate rounds:
       - If stock < 25% capacity: Defect (resource exhaustion/non-regenerative state).
       - Else: Cooperate if and only if all other players cooperated in the previous round.
         This acts as a penalty mechanism for defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if round_t == r - 1:
            return Action.D
        if round_t == 0:
            return Action.C
        if current_stock < capacity * 0.25:
            return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        if last_round_cooperators >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_61(BaseStrategy):
    """
    Trigger-Controlled Reciprocal Sustainability (TCRS) Strategy.
    
    Logic:
    1. First round: Cooperate (C).
    2. End-game: If current round is the final round, Defect (D).
    3. Sustainability Check: If current_stock < (capacity * 0.25), Cooperate (C).
    4. Reciprocity Check: If stock >= (capacity * 0.25), calculate Defection Index (DI) 
       based on the number of defecting opponents in the previous round.
       - DI = (number of defecting opponents) / (n - 1)
       - If DI == 0, Cooperate (C).
       - If DI > 0, Defect (D) with probability p = DI * k (where k=1.0).
    5. Special end-game handling: In round r-1, Defect (D) if stock < (capacity * 0.5).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = game_description.n_players - 1
        self.k_sensitivity = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == total_rounds - 2:
            if current_stock < capacity * 0.5:
                return Action.D
        if current_stock < capacity * 0.25:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if self.n_opponents <= 0:
            return Action.C
        num_defectors = self.n_opponents - prev_cooperators
        di = num_defectors / self.n_opponents
        if di == 0:
            return Action.C
        else:
            probability_to_defect = di * self.k_sensitivity
            if random.random() < probability_to_defect:
                return Action.D
            else:
                return Action.C

class Strategy_INDIVIDUALISTIC_62(BaseStrategy):
    """
    Tit-for-Tat with Forgiving Resilience:
    A strategy that maintains a moving average reputation of opponents. 
    It cooperates when the reputation is high and the pool is healthy, 
    but defects if the pool is dangerously low, if the round is terminal, 
    or if the reputation falls below a critical threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation = 1.0
        self.alpha = 0.3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_round == 0:
            self.reputation = 1.0
            return Action.C
        if current_stock < 1.0:
            return Action.D
        if current_stock > 0.8 * self.game_description.capacity:
            self.reputation = 0.5
        observed_c = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if n_opponents > 0:
            observed_rate = observed_c / n_opponents
            self.reputation = (1.0 - self.alpha) * self.reputation + self.alpha * observed_rate
        if current_stock < 0.25 * self.game_description.capacity:
            return Action.D
        if self.reputation >= 0.6:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_63(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    This strategy focuses on sustaining the common pool resource by cooperating
    when the stock is above a critical regeneration threshold (50% of capacity).
    It defaults to cooperation in the first round and switches to defection in 
    the final round or when the stock drops below the threshold, indicating
    that the system is no longer regenerating effectively.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.5 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_64(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy for the Common Pool Resource Game.
    
    Logic:
    - Round 0: Cooperate.
    - Terminal Round: Defect to maximize final extraction.
    - Standard Rounds:
        - Defect if stock < 50% of capacity (unsustainable).
        - Defect if the moving average of opponent cooperation (over the last 3 rounds) is <= 0.5.
        - Otherwise, Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = 0.5 * game_description.capacity
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        recent_history = history.opponent_cooperators[-3:]
        if self.n_opponents > 0:
            avg_cooperation_rate = np.mean(recent_history) / self.n_opponents
        else:
            avg_cooperation_rate = 1.0
        if current_stock < self.cooperation_threshold or avg_cooperation_rate <= 0.5:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_65(BaseStrategy):
    """
    Tit-for-Tat Threshold Cooperation (TFT-TC) Strategy.
    
    In the first round, it cooperates. In the final round, it defects.
    In intermediate rounds, it calculates an adaptive cooperation threshold alpha 
    based on current stock relative to capacity. It compares the number of 
    cooperators in the previous round against this threshold. If cooperation 
    is sufficient, it cooperates; otherwise, it defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_my_action = Action.C if history.my_actions[-1] else Action.D
        k_prev = history.opponent_cooperators[-1] + (1 if last_my_action == Action.C else 0)
        alpha = 0.5 + 0.5 * (current_stock / capacity)
        required_cooperation = math.ceil(n * alpha)
        if k_prev >= required_cooperation:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_66(BaseStrategy):
    """
    A conditional tit-for-tat strategy aimed at sustainability. 
    It cooperates to maintain the resource pool, punishes defection when the pool is stable,
    and switches to defection in the final rounds to maximize end-of-game returns.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round >= self.r - 2:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock <= 0:
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.C
        last_my_action = history.my_actions[-1]
        prev_opp_k = history.opponent_cooperators[-1]
        k = prev_opp_k + (1 if last_my_action else 0)
        if k == self.n:
            return Action.C
        if k < self.n:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_67(BaseStrategy):
    """
    Implements the Conditional Sustainability Trigger strategy.
    
    This strategy prioritizes long-term resource maintenance by cooperating (C)
    when the pool is healthy and others cooperate, defecting (D) when the pool
    is exploited by others (to hedge against depletion), and always defecting
    in the final round to capture remaining value. It also includes protective
    logic for low-stock scenarios.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.collapse_threshold = 5.0
        self.recovery_threshold = 0.2 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D
        if current_stock < self.collapse_threshold:
            return Action.D
        if current_stock < self.recovery_threshold:
            return Action.C
        if round_idx == 0:
            return Action.C
        num_opponents = self.n - 1
        num_cooperators = history.opponent_cooperators[-1]
        num_defectors = num_opponents - num_cooperators
        if num_defectors > 0:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_68(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy.
    Prioritizes resource regeneration when stock is below target, punishes 
    defection to maintain long-term yield, and attempts to maximize 
    final round payoff based on remaining resources.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if round_idx == n_rounds - 1:
            if current_stock > current_stock / n:
                return Action.D
            return Action.C
        if round_idx == 0:
            return Action.C
        target_stock = capacity / 2
        if current_stock < target_stock:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        total_prev_coop = prev_opp_coop + (1 if prev_my_action else 0)
        if total_prev_coop < n:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_69(BaseStrategy):
    """
    Adaptive Sustainable Tit-for-Tat (ASTFT):
    A strategy that maintains cooperation to preserve the resource pool as long as
    a sufficient majority of opponents also cooperate, otherwise punishing with
    defection. It shifts to pure defection when the resource is critically low
    or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= 0.5 * self.game_description.capacity:
            return Action.D
        k = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        threshold = max(0, self.game_description.n_players - 2)
        if k >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_70(BaseStrategy):
    """
    Threshold-Based Tit-for-Tat with Sustainability Correction.
    
    Operates by maintaining a target stock level for optimal growth. 
    It cooperates if the population demonstrates sustainable behavior (cooperating above a 
    threshold K), provided the resource isn't already degraded beyond recovery.
    It defects during the terminal zone and if the stock level collapses below a threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.threshold = math.ceil((self.n - 1) / 2)
        self.r_final = min(3, self.total_rounds)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx >= self.total_rounds - self.r_final:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < self.capacity / 4.0:
            return Action.D
        last_opponents_c = history.opponent_cooperators[-1]
        if last_opponents_c >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_71(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Thresholds strategy.
    
    This strategy prioritizes sustainability:
    - Round 1: Cooperates.
    - Final Round: Defects to capture remaining value.
    - Intermediate Rounds:
        - If stock < capacity/4, Cooperates (regeneration priority).
        - If stock < capacity/10, Cooperates (collapse prevention).
        - Otherwise, retaliates against defection (if any opponents defected, shift to Defect).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.r - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock < self.capacity / 10:
            return Action.C
        if current_stock < self.capacity / 4:
            return Action.C
        n_opponents = self.n - 1
        cooperators_prev = history.opponent_cooperators[-1]
        defectors_prev = n_opponents - cooperators_prev
        if n_opponents > 0:
            defect_ratio = defectors_prev / n_opponents
        else:
            defect_ratio = 0.0
        if defect_ratio == 0:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_72(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy based on resource stock levels and cooperation density.
    
    Logic:
    - Round 1 (index 0): Always Cooperate (C).
    - Last Round (index r-1): Always Defect (D).
    - Intermediate Rounds:
        - Maintain C if stock is low (< capacity/2) to prevent depletion.
        - Maintain C if cooperation ratio (CR >= 0.5) is high to sustain stock.
        - Otherwise, Defect (D) to capture value before others deplete the stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        cooperators_count = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        cooperation_ratio = cooperators_count / self.n
        if current_stock < self.capacity / 2 or cooperation_ratio >= 0.5:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_73(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Threshold strategy.
    
    Logic:
    1. First round: Always Cooperate (C).
    2. Final round: Defect (D) if stock >= threshold, else Cooperate (C).
    3. Intermediate rounds (t > 1):
        - If current_stock < threshold (0.5 * capacity): Cooperate to replenish.
        - Else (Stock Safe): 
            - If everyone cooperated in the last round: Cooperate.
            - Else: Defect (punish previous defection).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.5 * game_description.capacity
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if current_stock < self.threshold:
                return Action.C
            return Action.D
        if current_stock < self.threshold:
            return Action.C
        last_round_idx = history.round_number - 1
        i_cooperated = history.my_actions[last_round_idx]
        opponents_cooperated = history.opponent_cooperators[last_round_idx]
        total_cooperators = (1 if i_cooperated else 0) + opponents_cooperated
        if total_cooperators == self.n:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_74(BaseStrategy):
    """
    Tit-for-Tat with Sustainable Thresholds strategy.
    
    Cooperates in the first round. In subsequent rounds, it monitors the
    cooperation of the group and the health of the common stock.
    It defects if:
    1. The previous round saw insufficient cooperation (k <= n/2).
    2. The stock is below 10% of capacity.
    3. It is the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_my_action = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            self.last_my_action = Action.D
            return Action.D
        if history.round_number == 0:
            self.last_my_action = Action.C
            return Action.C
        my_prev_cooperated = self.last_my_action == Action.C
        k_prev = history.opponent_cooperators[-1] + (1 if my_prev_cooperated else 0)
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_stock < capacity * 0.1:
            self.last_my_action = Action.D
            return Action.D
        is_cooperation_triggered = k_prev > n / 2 and current_stock >= capacity * 0.25
        if is_cooperation_triggered:
            self.last_my_action = Action.C
            return Action.C
        else:
            self.last_my_action = Action.D
            return Action.D

class Strategy_INDIVIDUALISTIC_75(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy conditioned on common pool sustainability.
    
    The strategy aims to maintain the resource stock by cooperating in early rounds and
    using proportional punishment (Tit-for-Tat) for minor defections, while reverting 
    to immediate extraction (defect) if the resource is critical, during systemic 
    defection, or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_stock < self.capacity / (2 * self.n):
            return Action.D
        if current_round == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        coop_count_others = history.opponent_cooperators[-1]
        total_cooperators = coop_count_others + (1 if my_last_action else 0)
        m = self.n - total_cooperators
        if m == 0:
            return Action.C
        if m >= self.n / 2:
            return Action.D
        if self.n > 1:
            if random.random() < m / (self.n - 1):
                return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_76(BaseStrategy):
    """
    Implements a 'Conditional Sustainability' strategy.
    
    Logic Overview:
    1. Phase 1: Always Cooperate in the first round.
    2. Phase 2: If the game is in the final round, always Defect.
    3. Phase 3: If the stock drops below K/10, Defect permanently (Emergency collapse protocol).
    4. Phase 4: If stock < K/4, Defect to secure individual share.
    5. Phase 5: Calculate last round's consumption. If consumption > (stock * 0.5) (heuristic for
       over-consumption), Defect to mitigate risk, otherwise Cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        k = self.game_description.capacity
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        if current_stock < k / 10.0:
            self.permanent_defect = True
        if self.permanent_defect:
            return Action.D
        if current_stock < k / 4.0:
            return Action.D
        last_n_cooperators = history.opponent_cooperators[-1]
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        total_cooperators = last_n_cooperators + (1 if my_last_action == Action.C else 0)
        total_defectors = n - total_cooperators
        estimated_consumption = total_cooperators * (current_stock / (2 * n)) + total_defectors * (current_stock / n)
        if estimated_consumption > current_stock * 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_77(BaseStrategy):
    """
    Tit-for-Tat with Thresholding strategy for Common Pool Resource games.
    Maintains cooperative equilibrium unless resource levels or opponent behavior 
    demand shifting to defect for survival or yield maximization.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        target_stock = 0.5 * self.game_description.capacity
        r = self.game_description.n_rounds
        if history.round_number == r - 1:
            return Action.D
        if current_stock < target_stock * 0.5:
            return Action.C
        recent_opponents_c = history.opponent_cooperators[max(0, history.round_number - 3):]
        recent_coop_rates = recent_opponents_c / n_opponents
        avg_coop_rate = np.mean(recent_coop_rates)
        last_coop_rate = recent_coop_rates[-1]
        if avg_coop_rate < 0.2:
            return Action.D
        if current_stock > target_stock * 0.9:
            return Action.C if last_coop_rate >= 0.5 else Action.D
        return Action.C if avg_coop_rate >= 0.5 else Action.D

class Strategy_INDIVIDUALISTIC_78(BaseStrategy):
    """
    A Tit-for-Tat variant strategy for the Common Pool Resource Game.
    It cooperates to build baseline sustainability, recovers stock by cooperating
    when the pool is depleted, punishes defection probabilistically when the stock 
    is high, and always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < capacity / 2:
            return Action.C
        n_opponents = n_players - 1
        prev_round_cooperators = history.opponent_cooperators[-1]
        prev_defectors = n_opponents - prev_round_cooperators
        if prev_defectors == 0:
            return Action.C
        else:
            probability_to_defect = prev_defectors / n_players
            if random.random() < probability_to_defect:
                return Action.D
            else:
                return Action.C

class Strategy_INDIVIDUALISTIC_79(BaseStrategy):
    """
    A strategy that balances cooperation and defection based on stock sustainability 
    and recent opponent behavior. 
    - Round 1: Cooperates.
    - Terminal Round: Defects.
    - Mid-game: If stock is robust (> 50% capacity), mimics the majority behavior (Tit-for-Tat).
    - Emergency: If stock is low, focuses on either recovery or final extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            self.prev_stock = current_stock
            return Action.D
        if history.round_number == 0:
            self.prev_stock = current_stock
            return Action.C
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        prev_cooperators = history.opponent_cooperators[-1]
        if current_stock <= 0.0:
            self.prev_stock = current_stock
            return Action.C
        if current_stock < 0.25 * capacity:
            self.prev_stock = current_stock
            return Action.D
        s_prev = self.prev_stock
        if s_prev > 0.5 * capacity:
            threshold = math.ceil(n_players / 2)
            my_prev_action = 1 if history.my_actions[-1] else 0
            total_cooperators = prev_cooperators + my_prev_action
            result = Action.C if total_cooperators >= n_players / 2 else Action.D
            self.prev_stock = current_stock
            return result
        elif current_stock > s_prev:
            self.prev_stock = current_stock
            return Action.C
        else:
            self.prev_stock = current_stock
            return Action.D

class Strategy_INDIVIDUALISTIC_80(BaseStrategy):
    """
    Dynamic Tit-for-Tat with Sustainability Threshold.
    
    A conditional cooperative strategy that enforces sustainability by prioritizing
    stock regeneration when levels are low, and using a probabilistic punishment 
    mechanism based on past cooperation levels to deter defectors. It adopts an
    aggressive payoff maximization approach in the final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.total_rounds - 1:
            return Action.D
        if round_idx == self.total_rounds - 2:
            if current_stock < self.capacity / 2.0:
                return Action.C
            return Action.D
        if current_stock < self.capacity / 4.0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        threshold = self.n - 1
        if prev_cooperators >= threshold:
            return Action.C
        else:
            prob_defect = 1.0 - prev_cooperators / self.n
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_INDIVIDUALISTIC_81(BaseStrategy):
    """
    A strategy that maintains common pool stock at approximately 50% of capacity,
    adopting a conditional cooperation (Tit-for-Tat) approach when the resource is
    in a stable zone, but exploiting the resource when stock is too high or 
    near depletion to maximize utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t_current = history.round_number + 1
        if t_current == self.r:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if current_stock > 0.9 * self.capacity:
            return Action.D
        if t_current == 1:
            return Action.C
        last_round_idx = -1
        last_round_opp_coop = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        total_cooperators = last_round_opp_coop + (1 if my_last_action else 0)
        total_defectors = self.n - total_cooperators
        if total_defectors == 0:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_82(BaseStrategy):
    """
    Implements the Conditional Sustainability Equilibrium (CSE) strategy.
    
    This strategy maintains the common pool at capacity via tit-for-tat logic.
    - Round 1: Always Cooperate.
    - Last Round: Always Defect.
    - Intermediate Rounds:
        - If previous round was fully cooperative, continue cooperating.
        - If previous round had defections, attempt recovery via cooperation only if stock > capacity/2.
        - Otherwise, switch to Defect to harvest remaining value.
    - Edge Case: If stock is near 0, permanently defect as recovery is impossible.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < 1e-06:
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_val = 1 if my_prev_action else 0
        total_cooperators = history.opponent_cooperators[-1] + my_prev_val
        cooperation_rate = total_cooperators / self.n
        if cooperation_rate >= 1.0:
            return Action.C
        if current_stock > self.capacity / 2.0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_83(BaseStrategy):
    """
    Implements a stock-sensitive Tit-for-Tat strategy.
    Prioritizes sustainability when stock is low, reciprocates majority behavior
    when stock is sufficient, and defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.5 * self.game_description.capacity
        self.coop_threshold = math.ceil(self.game_description.n_players / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.threshold:
            return Action.C
        k = history.opponent_cooperators[-1]
        if k >= self.coop_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_84(BaseStrategy):
    """
    Implements a responsive strategy for the Common Pool Resource Game.
    - Round 1: Always Cooperates (C).
    - Rounds 2 to r-1: 
        - If stock < capacity/2: Defect (D) if any defection occurred previously, else Cooperate (C).
        - If stock >= capacity/2: Cooperate (C) if defections < n/2, else Defect (D).
    - Final Round: Always Defects (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        prev_opponents_c = history.opponent_cooperators[-1]
        n = self.game_description.n_players
        prev_opponents_d = n - 1 - prev_opponents_c
        capacity = self.game_description.capacity
        if current_stock < capacity / 2.0:
            if prev_opponents_d > 0:
                return Action.D
            else:
                return Action.C
        elif prev_opponents_d == 0:
            return Action.C
        elif prev_opponents_d < n / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_85(BaseStrategy):
    """
    Triggered Tit-for-Tat with Sustainability Threshold.
    
    Strategy logic:
    1. Initial Round (0): Cooperate (C).
    2. Final Round (r-1): Defect (D).
    3. Sustainability Check: If current_stock < (capacity * 0.25), Defect (D).
    4. Reciprocal Adjustment: If any opponent defected in the previous round, Defect (D) 
       for exactly one round.
    5. Equilibrium: Otherwise, Cooperate (C).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishing_active = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.game_description.capacity * 0.25:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        prev_round_cooperators = history.opponent_cooperators[-1]
        prev_round_defectors = n_opponents - prev_round_cooperators
        if self.punishing_active:
            self.punishing_active = False
            return Action.C
        if prev_round_defectors > 0:
            self.punishing_active = True
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_86(BaseStrategy):
    """
    Conditional Tit-for-Tat with Sustainability Threshold.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Terminal Round (t = r): Always Defect (D).
    - Sustainability Emergency (S < capacity/4): Always Cooperate (C).
    - Standard Rounds: Cooperate if the number of cooperative opponents in the 
      previous round was >= 75% of (n-1), otherwise Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t_current = history.round_number + 1
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if t_current == r:
            return Action.D
        if current_stock < capacity / 4:
            return Action.C
        if t_current == 1:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        num_others = n - 1
        threshold = math.floor(num_others * 0.75)
        if prev_cooperators >= threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_87(BaseStrategy):
    """
    A Grim Trigger variant strategy for the Common Pool Resource game.
    It monitors stock levels and cooperation rates to balance sustainability 
    with utility maximization, defaulting to defection if thresholds are breached
    or if the final round is reached.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_punishing = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= 0.0:
            return Action.C
        if history.round_number == 0:
            self.is_punishing = False
            return Action.C
        threshold = 0.5 * self.game_description.capacity
        if current_stock < threshold:
            self.is_punishing = True
        elif current_stock >= self.game_description.capacity:
            self.is_punishing = False
        if self.is_punishing:
            return Action.D
        else:
            my_last_action_val = 1 if history.my_actions[-1] else 0
            opponents_cooperating = int(history.opponent_cooperators[-1])
            k = opponents_cooperating + my_last_action_val
            if k >= self.game_description.n_players - 1:
                return Action.C
            else:
                return Action.D

class Strategy_INDIVIDUALISTIC_88(BaseStrategy):
    """
    Targeted Sustainability Strategy:
    Prioritizes cooperation to maintain resource stocks but employs a strict
    punishment and extraction policy when environmental conditions degrade or 
    opponents defect. Transitions to aggressive extraction (Defection) in the 
    final round or when the resource is deemed unsustainable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        prev_round_idx = current_round - 1
        my_prev_action_val = 1 if history.my_actions[prev_round_idx] else 0
        total_cooperators_prev = history.opponent_cooperators[prev_round_idx] + my_prev_action_val
        num_defectors_prev = self.n - total_cooperators_prev
        if current_stock < 2 * self.n:
            return Action.D
        if current_stock <= 0.0001:
            return Action.D
        if num_defectors_prev > 0:
            if current_stock < self.capacity * 0.75:
                return Action.D
            else:
                return Action.C
        if current_stock > self.capacity / 2:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_89(BaseStrategy):
    """
    A sustainable tit-for-tat strategy that prioritizes pool preservation.
    It cooperates in the first round and maintains cooperation as long as the 
    pool is healthy and the majority of opponents are cooperating. 
    It defaults to defection in the final round or if the pool enters a critical state.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.d_thresh = math.floor(0.5 * self.n)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if current_stock <= self.capacity / self.n:
            return Action.D
        prev_c_count = history.opponent_cooperators[-1]
        if prev_c_count >= self.d_thresh:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_90(BaseStrategy):
    """
    Implements a "Conditional Sustainability" strategy for the Common Pool Resource game.
    The strategy attempts to enforce a Cooperative Equilibrium by cooperating if 
    the previous round's cooperation count was high (n-1), otherwise it defaults to 
    a Defection Harvest to minimize losses. It includes a rescue protocol for 
    critically low stock levels and unconditionally defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r_total - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        opp_coop = history.opponent_cooperators[-1]
        prev_round_cooperators = opp_coop + my_prev_coop
        if current_stock < 0.2 * capacity:
            if prev_round_cooperators >= n / 2:
                return Action.C
            else:
                return Action.D
        if prev_round_cooperators >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_91(BaseStrategy):
    """
    A Tit-for-Tat inspired strategy for the Common Pool Resource Game.
    It prioritizes sustainability and cooperation, reverting to defection if 
    cooperation fails, with a mandatory defection in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.s_star = 0.5 * self.game_description.capacity
        self.threshold = self.s_star / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < self.threshold:
            return Action.C
        last_my_action = 1 if history.my_actions[-1] else 0
        prev_cooperators = history.opponent_cooperators[-1] + last_my_action
        if prev_cooperators == self.game_description.n_players:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_92(BaseStrategy):
    """
    Threshold-Based Tit-for-Tat with Resource Sustainability (TBT-RS).
    Prioritizes resource sustainability by defecting when the stock is critically low,
    otherwise matches group cooperation trends if the resource is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx + 1 == self.r:
            return Action.D
        if current_stock < self.capacity / self.n:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        if current_stock > 0.9 * self.capacity:
            n_opponents = self.n - 1
            prev_cooperators = history.opponent_cooperators[-1]
            if prev_cooperators <= n_opponents / 2:
                return Action.D
            return Action.C
        if current_stock < 0.5 * self.capacity:
            return Action.D
        n_opponents = self.n - 1
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators > n_opponents / 2:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_93(BaseStrategy):
    """
    Implements a sustainable resource extraction strategy that attempts to maintain
    the common pool stock level. It cooperates if the stock is healthy and others
    are cooperating, defaults to defecting if the stock is critically low, 
    if others are defecting, or in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == 0:
            return Action.C
        if t == r - 1:
            return Action.D
        if current_stock < capacity * 0.25:
            return Action.D
        prev_coop_count = history.opponent_cooperators[-1]
        if prev_coop_count >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_94(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Common Pool Resource game based on
    current stock levels and previous round cooperation metrics.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.capacity = self.game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        threshold_low = 0.25 * self.capacity
        threshold_mid = 0.5 * self.capacity
        if current_stock < threshold_low:
            return Action.D
        elif current_stock >= threshold_mid:
            if total_cooperators_prev >= math.ceil(0.5 * self.n):
                return Action.C
            else:
                return Action.D
        elif threshold_low <= current_stock < threshold_mid:
            if total_cooperators_prev == self.n:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_95(BaseStrategy):
    """
    A reactive sustainability strategy for the Common Pool Resource Game.
    
    Logic Overview:
    1. Final Round (t = r): Always Defect (Action.D) to extract residual value, 
       unless stock is already effectively empty.
    2. Recovery Mode: If stock <= 10% of capacity, always Cooperate (Action.C) 
       to prevent collapse.
    3. Retaliatory Response: If in the previous round, more than 50% of the 
       opponents defected (or played D), and the stock dropped by > 25%, 
       Defect (Action.D) for one round as a temporary retaliatory measure.
    4. Default Policy: Cooperate (Action.C) if stock > 25% of capacity, 
       otherwise stay in Cooperative mode until recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.just_retaliated = False
        self.prev_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        n_opponents = n - 1
        if t == total_rounds - 1:
            if current_stock > 0.001:
                return Action.D
            return Action.C
        if current_stock <= capacity / 10:
            self.just_retaliated = False
            self.prev_stock = current_stock
            return Action.C
        if t > 0:
            prev_cooperators = history.opponent_cooperators[-1]
            k_prev = n_opponents - prev_cooperators
            stock_reduction = (self.prev_stock - current_stock) / max(self.prev_stock, 1e-09)
            if k_prev > n_opponents / 2 and stock_reduction > 0.25 and (not self.just_retaliated):
                self.just_retaliated = True
                self.prev_stock = current_stock
                return Action.D
        self.just_retaliated = False
        self.prev_stock = current_stock
        if current_stock > capacity / 4:
            return Action.C
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_96(BaseStrategy):
    """
    Implements the "Targeted Sustainment" strategy.
    
    This strategy behaves as follows:
    1. First round (round 0): Always Cooperate (C).
    2. Final round (round r-1): Always Defect (D).
    3. Intermediate rounds:
       - If all players cooperated in the previous round, continue to Cooperate (C).
       - If there were defectors in the previous round:
         - If the current stock is below 50% of capacity, Cooperate (C) to prevent resource collapse.
         - Otherwise, Defect (D) to maximize payoff while the resource is still viable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_opp_coops = history.opponent_cooperators[-1]
        total_prev_cooperators = int(prev_opp_coops) + (1 if my_prev_action else 0)
        if total_prev_cooperators == self.game_description.n_players:
            return Action.C
        safety_threshold = 0.5 * self.game_description.capacity
        if current_stock < safety_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_97(BaseStrategy):
    """
    Implements a Threshold-Responsive Tit-for-Tat strategy.
    
    Logic:
    - Last Round (t == r): Always Defect (D).
    - If Stock < 0.5 * Capacity: Always Defect (D).
    - If Round 1: Cooperate (C).
    - Otherwise: Cooperate (C) only if the number of cooperating opponents in the 
      previous round was >= floor(n / 2). Otherwise, Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock < capacity * 0.5:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        threshold = n // 2
        if prev_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_98(BaseStrategy):
    """
    A conditional 'Tit-for-Tat' variant that balances resource sustainability
    by maintaining the common pool stock at 50% of capacity, while punishing
    unsustainable behavior and maximizing utility in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.s_target = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        i_cooperated_last = 1 if history.my_actions[-1] else 0
        k_prev = history.opponent_cooperators[-1] + i_cooperated_last
        if np.mean(history.opponent_cooperators + history.my_actions.astype(int)) < self.n / 2:
            return Action.D
        if current_stock > self.s_target * 0.75:
            if k_prev >= math.ceil(self.n / 2):
                return Action.C
            else:
                return Action.D
        elif current_stock < self.capacity / 100:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_99(BaseStrategy):
    """
    A Tit-for-Tat inspired strategy with state-dependent threshold maintenance.
    - Cooperates in the first round to signal intent.
    - In the final round, defects to capture remaining value.
    - If stock < 50% capacity, defects to extract remaining resources.
    - Otherwise, cooperates if a running 'Reputation_Score' (tracked based on 
      past cooperation levels) is non-negative, otherwise defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation_score = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        prev_my_cooperated = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + prev_my_cooperated
        if total_cooperators_prev == self.game_description.n_players:
            self.reputation_score = min(5, self.reputation_score + 1)
        else:
            self.reputation_score = max(-5, self.reputation_score - 2)
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 0.5 * self.game_description.capacity:
            return Action.D
        if self.reputation_score >= 0:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_100(BaseStrategy):
    """
    Adaptive Sustainable Harvest strategy.
    
    Logic:
    1. Terminal Phase (last 3 rounds): Defect to capture final resources.
    2. Critical Depletion: If stock is below 25% of capacity, Defect to salvage.
    3. Conditional Cooperation: 
       - Round 0: Cooperate.
       - Subsequent: Cooperate if previous round's cooperator count (k) 
         exceeds or equals 60% of opponents (n-1). Otherwise, Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.critical_stock_threshold = self.capacity * 0.25
        self.coop_threshold = math.ceil((self.n - 1) * 0.6)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx >= self.r - 3:
            return Action.D
        if current_stock < self.critical_stock_threshold:
            return Action.D
        if round_idx == 0:
            return Action.C
        k_prev = history.opponent_cooperators[-1]
        if k_prev >= self.coop_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_101(BaseStrategy):
    """
    Tit-for-Tat with Threshold Recovery Strategy:
    - Maintains the common pool resource at its maximum sustainable capacity.
    - Cooperative by default.
    - Triggers punishment mode if any defection is detected in the previous round.
    - Exits punishment mode only when the stock recovers to >= 90% of capacity.
    - Always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round_idx == 0:
            return Action.C
        prev_round_idx = current_round_idx - 1
        my_prev_action = 1 if history.my_actions[prev_round_idx] else 0
        c_prev = my_prev_action + history.opponent_cooperators[prev_round_idx]
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if c_prev < n:
            self.punishment_mode = True
        elif current_stock >= 0.9 * capacity:
            self.punishment_mode = False
        if current_round_idx == total_rounds - 1:
            return Action.D
        if self.punishment_mode:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_102(BaseStrategy):
    """
    Adaptive Sustainable Tit-for-Tat (ASTFT) strategy.
    
    Operates on a logic of conditional cooperation to maintain resource sustainability.
    - Round 1: Always Cooperate (C).
    - Critical Depletion (SHI < 0.25): Always Cooperate (C) to prevent collapse.
    - Standard Play: Cooperate if opponent cooperation rate >= 0.5, else Defect (D).
    - Endgame Override: If current round is the last round, Defect if SHI > 0.10, 
      otherwise Cooperate to ensure remaining stock exists for extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == self.r - 1:
            if current_stock / self.capacity > 0.1:
                return Action.D
            else:
                return Action.C
        shi = current_stock / self.capacity
        if shi < 0.25:
            return Action.C
        num_opponents = self.n - 1
        prev_coop_count = history.opponent_cooperators[-1]
        opponent_coop_rate = prev_coop_count / num_opponents
        if opponent_coop_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_103(BaseStrategy):
    """
    Resource Preservation Tit-for-Tat (RPTFT):
    Manages the common pool by conditioning cooperative action on a reputation metric 
    (R_t) derived from opponent cooperation history, while implementing a safety-first 
    mechanism for critical stock levels. Reputation thresholding is adaptive, becoming 
    more permissive as the game nears its end.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds
        self.alpha = 0.7
        self.reputation = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_opponents = self.n - 1
        if history.round_number > 0:
            last_round_idx = history.round_number - 1
            k_opp = history.opponent_cooperators[last_round_idx]
            observed_rate = k_opp / n_opponents if n_opponents > 0 else 0.0
            self.reputation = self.alpha * self.reputation + (1 - self.alpha) * observed_rate
        buffer = current_stock / self.capacity
        if buffer < 0.25:
            return Action.D
        t = history.round_number + 1
        threshold = 0.5 + 0.5 * (self.r - t) / self.r
        if self.reputation >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_104(BaseStrategy):
    """
    Sustainable Tit-for-Tat with Threshold Defection (STT-TD).
    Maintains cooperation to preserve stock but employs probabilistic 
    retaliatory punishment for aggregate defection and switches to 
    selfish exploitation if stock sustainability is compromised or in the final round.
    Includes a 'Recovery Phase' mechanism to signal a return to cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.consecutive_cooperative_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_idx = history.round_number - 1
        c_obs = history.opponent_cooperators[prev_idx]
        if current_stock < 0.0001:
            return Action.D
        if current_stock < self.capacity / 4:
            return Action.D
        n_opponents = self.n - 1
        if c_obs == n_opponents:
            self.consecutive_cooperative_rounds += 1
        else:
            self.consecutive_cooperative_rounds = 0
        if self.consecutive_cooperative_rounds >= 2:
            return Action.C
        if c_obs == n_opponents:
            return Action.C
        else:
            threshold = (n_opponents - c_obs) / n_opponents
            if random.random() < threshold:
                return Action.D
            else:
                return Action.C

class Strategy_INDIVIDUALISTIC_105(BaseStrategy):
    """
    A conditional cooperation strategy that utilizes a dynamic threshold mechanism
    for reciprocation. It balances stock preservation with payoff maximization by 
    monitoring opponent behavior and stock sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.cooperation_threshold = 1
        self.n_opponents = self.n - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            return Action.D
        if current_stock < self.n * (current_stock / (2 * self.n)):
            return Action.D
        if current_stock < self.capacity * 0.25:
            return Action.D
        c_count = history.opponent_cooperators[-1]
        if round_idx >= 2:
            prev_c_count = history.opponent_cooperators[-1]
            prev_prev_c_count = history.opponent_cooperators[-2]
            if prev_prev_c_count > 0:
                drop_pct = (prev_prev_c_count - prev_c_count) / prev_prev_c_count
                if drop_pct > 0.25:
                    self.cooperation_threshold = min(self.n_opponents, self.cooperation_threshold + 1)
            if round_idx >= 4:
                if all((history.opponent_cooperators[i] >= self.cooperation_threshold for i in range(round_idx - 3, round_idx))):
                    self.cooperation_threshold = max(0, self.cooperation_threshold - 1)
        if c_count == 0:
            self.cooperation_threshold = self.n_opponents
            return Action.D
        if current_stock >= self.capacity:
            return Action.C
        if c_count >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_106(BaseStrategy):
    """
    Adaptive Sustainable Tit-for-Tat:
    A conditional cooperation strategy that maintains resource health near 50% capacity (MSY)
    while employing Tit-for-Tat punishment for defectors and forgiveness mechanisms.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        remaining_rounds = self.game_description.n_rounds - history.round_number
        if remaining_rounds < 3:
            return Action.D
        if current_stock < 0.25 * capacity:
            return Action.D
        prev_coop_count = history.opponent_cooperators[-1]
        n_opponents = n - 1
        num_defectors = n_opponents - prev_coop_count
        if num_defectors > 0:
            if current_stock >= 0.5 * capacity:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_107(BaseStrategy):
    """
    A conditional 'Tit-for-Tat' strategy for the Common Pool Resource Game.
    
    This strategy aims to maximize long-term stock sustainability by maintaining the stock 
    level near capacity/2, which optimizes the intrinsic growth rate. It defaults to 
    cooperation but pivots to defection if the stock level is critically low or if 
    opponents are aggressively over-extracting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock < self.capacity / 4:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if current_stock > self.capacity / 2:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        num_opponents = self.n - 1
        if num_opponents > 0:
            cooperation_ratio = last_round_cooperators / num_opponents
        else:
            cooperation_ratio = 1.0
        if cooperation_ratio >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_108(BaseStrategy):
    """
    Implements a Conditional Sustainability strategy.
    
    This strategy prioritizes long-term resource stability. It cooperates by default
    but triggers retaliatory defection if systemic over-consumption is detected 
    or if the resource pool is critically low. It unconditionally defects in the 
    final round to maximize terminal payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            return Action.D
        if current_stock < 0.2 * capacity:
            return Action.D
        last_cooperators_opponents = history.opponent_cooperators[-1]
        my_last_action_was_c = history.my_actions[-1]
        total_cooperators_last_round = last_cooperators_opponents + (1 if my_last_action_was_c else 0)
        if total_cooperators_last_round < n:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_109(BaseStrategy):
    """
    A dynamic strategy that balances cooperation and defection based on 
    resource sustainability, population behavior, and the remaining game duration.
    
    Logic:
    1. Initial Round: Cooperate (C) to establish baseline.
    2. Terminal Phase (last 5 rounds): If stock < capacity/2, Defect (D) to maximize 
       immediate payout before potential collapse.
    3. Resource Stress Check: If Stock/Capacity < 0.25, Defect (D).
    4. Adaptive Reciprocity: Otherwise, if previous round cooperators >= ceil(n/2), 
       Cooperate (C), else Defect (D).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = math.ceil(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        remaining_rounds = self.r - round_idx
        m = min(5, remaining_rounds)
        if remaining_rounds <= m and current_stock < self.capacity / 2:
            return Action.D
        if self.capacity > 0:
            sustainability_index = current_stock / self.capacity
            if sustainability_index < 0.25:
                return Action.D
        if history.opponent_cooperators[-1] >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_110(BaseStrategy):
    """
    Implements an adaptive threshold-based strategy for the Common Pool Resource game.
    Monitors opponent defection rates, adjusts caution (tau) based on stock health, 
    and incorporates terminal round heuristics.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.tau = 0.5
        self.alpha = 0.8
        self.running_delta = 0.0
        self.n = game_description.n_players
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        n_opponents = self.n - 1
        if round_idx == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        prev_defectors = n_opponents - prev_cooperators
        delta_t = prev_defectors / n_opponents if n_opponents > 0 else 0.0
        self.running_delta = self.alpha * self.running_delta + (1 - self.alpha) * delta_t
        my_prev_action = history.my_actions[-1]
        num_c = prev_cooperators + (1 if my_prev_action else 0)
        num_d = self.n - num_c
        if my_prev_action == Action.C:
            if current_stock < self.capacity * 0.5:
                self.tau = max(0.1, self.tau - 0.05)
        elif my_prev_action == Action.D:
            if current_stock >= self.capacity * 0.4:
                self.tau = min(0.9, self.tau + 0.05)
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        if round_idx == self.game_description.n_rounds - 2:
            if current_stock < self.capacity / 2:
                return Action.D
        if current_stock <= 0:
            return Action.D
        if current_stock < self.capacity / 4:
            return Action.D
        if n_opponents == 1:
            if prev_defectors > 0:
                return Action.D
            return Action.C
        if self.running_delta < self.tau:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_111(BaseStrategy):
    """
    Trigger-Based Target Maintenance strategy.
    
    This strategy attempts to maintain the common pool resource stock near 
    its capacity by cooperating when previous rounds show sufficient 
    collective cooperation (>= ceil(n/2)). It defaults to defecting 
    in terminal rounds, if the resource is below a sustainable threshold 
    (capacity / 2), or if collective cooperation is lacking.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds
        self.sustainable_threshold = self.capacity / 2.0
        self.majority_threshold = math.ceil(self.n / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.total_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        if current_stock < self.sustainable_threshold:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        prev_total_cooperators = history.opponent_cooperators[-1] + my_prev_action
        if prev_total_cooperators >= self.majority_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_112(BaseStrategy):
    """
    Adaptive Sustainable Harvesting (ASH):
    A strategy that uses a Tit-for-Tat variant combined with stock-level monitoring
    to balance resource preservation with payoff maximization.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < 0.2 * capacity:
            return Action.C
        if current_round < 2:
            return Action.C
        last_opponents_cooperated = history.opponent_cooperators[-1]
        if self.n_opponents > 0:
            theta = last_opponents_cooperated / self.n_opponents
        else:
            theta = 0.0
        if theta >= 0.75:
            return Action.C
        elif theta >= 0.5:
            return Action.C if current_stock > 0.5 * capacity else Action.D
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_113(BaseStrategy):
    """
    Conditional Preservation Strategy:
    Prioritizes sustainability of the common pool by cooperating when stock is critical
    or when others have cooperated. Punishes defection unless the stock recovers
    sufficiently. Defaults to defection in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[current_round - 1]
        prev_opp_coop = history.opponent_cooperators[current_round - 1]
        total_cooperators_prev = (1 if my_prev_action else 0) + prev_opp_coop
        num_defectors_prev = self.n - total_cooperators_prev
        threshold_low = self.capacity / (2 * self.n)
        if current_stock < threshold_low:
            return Action.C
        recovery_threshold = 0.8 * self.capacity
        if current_stock >= recovery_threshold:
            return Action.C
        if num_defectors_prev == 0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_114(BaseStrategy):
    """
    Implements a Tit-for-Tat with Sustainability Threshold strategy.
    
    Logic:
    1. Always defect in the final round.
    2. Cooperate in the first round.
    3. If stock drops below 25% of capacity, prioritize sustainability by cooperating.
    4. Otherwise, use Tit-for-Tat: cooperate if the number of cooperators 
       (including self, though typically Tit-for-Tat looks at the group state) 
       was at least (n - 1) in the previous round; otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.game_description.capacity * 0.25:
            return Action.C
        prev_opp_coop = int(history.opponent_cooperators[-1])
        prev_my_coop = 1 if history.my_actions[-1] == Action.C else 0
        total_cooperators_prev = prev_opp_coop + prev_my_coop
        n = self.game_description.n_players
        if total_cooperators_prev >= n - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_115(BaseStrategy):
    """
    Implements a Conditional Sustainability heuristic.
    Balances immediate gain against long-term resource viability.
    - Tests cooperation in round 1.
    - Punishes defections by others immediately.
    - Monitors resource sustainability; if the stock cannot regenerate 
      to a sustainable level (approx 80% capacity) given total cooperation,
      it switches to defection.
    - Always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == self.total_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        num_opponents = self.n - 1
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators = prev_cooperators + (1 if my_prev_action else 0)
        prev_k = self.n - total_cooperators
        if prev_k > 0:
            return Action.D
        if prev_k >= self.n - 1:
            return Action.D
        if current_stock < 0.05 * self.capacity:
            return Action.D
        if self.capacity > 0:
            remaining_stock = current_stock - current_stock / 2.0
            potential_growth = 2.0 * remaining_stock * (1.0 - remaining_stock / self.capacity)
            if remaining_stock + potential_growth < 0.8 * self.capacity:
                return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_116(BaseStrategy):
    """
    A strategy that maintains cooperation while resources are sustainable and
    opponents are cooperative, punishing defectors or low-stock situations
    with temporary defection, and optimizing for payoff in the final three rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_opponents = n - 1
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_idx = history.round_number
        if round_idx >= total_rounds - 3:
            if current_stock >= 0.5 * capacity:
                return Action.D
            else:
                return Action.C
        if round_idx == 0:
            return Action.C
        opponents_cooperated = history.opponent_cooperators[-1]
        if current_stock < 0.25 * capacity:
            return Action.C
        if opponents_cooperated < n_opponents or current_stock < 0.5 * capacity:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_117(BaseStrategy):
    """
    Tit-for-Tat with Sustainability Thresholds (TFT-ST):
    A strategy that balances short-term extraction with long-term viability by
    monitoring resource levels and punishing non-cooperative behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        rounds_remaining = self.r - current_round_idx
        if rounds_remaining == 1:
            return Action.D
        survival_threshold = self.capacity / (4 * self.n)
        if current_stock < survival_threshold:
            return Action.C
        if current_round_idx == 0:
            return Action.C
        last_cooperators = history.opponent_cooperators[-1]
        if last_cooperators < self.n - 1:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_118(BaseStrategy):
    """
    Implements a Tit-for-Tat variant with a safety valve.
    - Round 1: Cooperate.
    - Terminal Round: Defect.
    - Standard Rounds: Cooperate if defection index <= 0.25, else Defect.
    - Safety Valve: Override to Defect if stock < 0.25 * capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.total_rounds
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opp_coop = history.opponent_cooperators[-1]
        my_contribution = 1 if last_my_action else 0
        total_cooperators = my_contribution + last_opp_coop
        total_defectors = self.n - total_cooperators
        di = total_defectors / self.n
        if di <= 0.25:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_119(BaseStrategy):
    """
    A strategy that maintains a target stock level for sustainability while using 
    a Tit-for-Tat based reputation system to handle defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.reputation: float = 1.0
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        n_opponents = self.n - 1
        c_last = history.opponent_cooperators[last_round_idx]
        d_last = n_opponents - c_last
        if d_last > 0:
            self.reputation -= d_last
        elif c_last == n_opponents:
            self.reputation = min(self.reputation + 1.0, 5.0)
        if history.round_number == self.r - 1:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        if d_last > self.n / 2:
            return Action.D
        if current_stock > 0.75 * self.capacity:
            return Action.D
        if self.reputation < 0:
            self.reputation = 0
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_120(BaseStrategy):
    """
    Implements the Sustained Equilibrium Protocol for the Common Pool Resource Game.
    
    This strategy maintains the resource pool by cooperating when stock levels are 
    favorable or critical, and responds to group behavior by reciprocating cooperation
    unless the pool is collapsing or the game is ending.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.target_stock = game_description.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        n = self.game_description.n_players
        n_opponents = n - 1
        if round_idx == total_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if current_stock < self.target_stock * 0.8:
            return Action.C
        if n_opponents == 0:
            return Action.C
        prev_n_coop = history.opponent_cooperators[-1]
        coop_ratio = prev_n_coop / n_opponents
        if coop_ratio > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_121(BaseStrategy):
    """
    Implements a Targeted Sustainability strategy for the Common Pool Resource Game.
    The strategy cooperates by default or when the stock is below a safety threshold
    (50% of capacity) to encourage replenishment. It defects if the stock is high
    AND the majority of opponents are defecting (harvest phase).
    It always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.threshold = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        observed_cooperators = int(history.opponent_cooperators[last_round_idx])
        my_last_action_was_cooperate = bool(history.my_actions[last_round_idx])
        opponents_defecting = self.n - 1 - observed_cooperators
        if current_stock < self.threshold:
            return Action.C
        if opponents_defecting >= self.n / 2:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_122(BaseStrategy):
    """
    A modified Tit-for-Tat strategy that maintains a 'Cooperative' state 
    unless the resource stock drops below capacity/2 or any opponent defects.
    Once the strategy enters the 'Defensive' state (Defect), it remains 
    there permanently. It also forces defection in the final round to 
    maximize end-game utility.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.is_defensive = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_t = history.round_number
        if round_t == self.game_description.n_rounds - 1:
            return Action.D
        if round_t == 0:
            return Action.C
        if not self.is_defensive:
            critical_threshold = self.game_description.capacity / 2
            c_previous = history.opponent_cooperators[-1]
            num_opponents = self.game_description.n_players - 1
            if current_stock < critical_threshold or c_previous < num_opponents:
                self.is_defensive = True
        if self.is_defensive:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_123(BaseStrategy):
    """
    A strategy that aims to maintain the common pool at capacity.
    It cooperates while the pool is healthy (>= 50% capacity) and when opponents
    are cooperating. It defects if the stock drops below the sustainability threshold
    or if aggregate consumption in the previous round is deemed excessive.
    Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n_players = game_description.n_players
        self.n_opponents = game_description.n_players - 1
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock < 0.5 * self.capacity:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators == self.n_opponents:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_124(BaseStrategy):
    """
    Adaptive Sustainability Tit-for-Tat (AST-TFT).
    
    A conditional reciprocity strategy that adjusts consumption based on current
    common pool sustainability and observed historical cooperation from opponents.
    Maintains a rolling 'C_score' and enforces strict sustainability thresholds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.c_score = float(self.n - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        k = float(history.opponent_cooperators[-1])
        self.c_score = self.c_score * 0.7 + k * 0.3
        if current_round >= self.r - 1:
            if current_stock > self.capacity * 0.5:
                return Action.D
            else:
                return Action.C
        if current_stock < self.capacity * 0.3:
            return Action.C
        if self.c_score >= (self.n - 1) * 0.8:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_125(BaseStrategy):
    """
    Implements a dynamic, threshold-based cooperation strategy (T-Strategy).
    It adjusts cooperation based on the previous round's stock level and the
    cooperation behavior of opponents, attempting to keep stock near half capacity
    while adapting to the group's lenience.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_opponents = self.game_description.n_players - 1
        self.threshold = self.n_opponents

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            self.threshold = self.n_opponents
            return Action.C
        prev_k = history.opponent_cooperators[-1]
        if current_stock < 0.1 * self.game_description.capacity:
            self.threshold = 0
            return Action.C
        if current_stock == 0:
            return Action.D
        if current_stock >= 0.5 * self.game_description.capacity:
            return Action.C
        if prev_k >= self.threshold:
            action = Action.C
        else:
            action = Action.D
        self.threshold = min(self.n_opponents, max(0, prev_k))
        return action

class Strategy_INDIVIDUALISTIC_126(BaseStrategy):
    """
    Trigger-Threshold Sustainability (TTS) strategy:
    - First round: Cooperate.
    - Last round: Defect (always, to capture final value).
    - If stock < 25% capacity: Rescue (Cooperate).
    - Otherwise: Cooperate if previous round cooperators >= ceil(n/2), else Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_stock < self.capacity * 0.25:
            return Action.C
        threshold = math.ceil(self.n / 2)
        if history.opponent_cooperators[-1] >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_127(BaseStrategy):
    """
    A strategy that adapts based on stock levels and collective behavior.
    - Round 0: Always Cooperate.
    - Last Round: Always Defect.
    - Low Stock ( < 25% capacity): Always Cooperate to prevent collapse.
    - Adaptive Phase:
        - If group cooperation rate >= 50% in the previous round: Cooperate.
        - Otherwise: Defect with 50% probability (Retaliate/Exploit).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._alternation_flag = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        if current_round == r:
            return Action.D
        if current_stock < 0.25 * capacity:
            return Action.C
        previous_nc = int(history.opponent_cooperators[-1])
        my_previous_action = history.my_actions[-1]
        total_cooperators = previous_nc + (1 if my_previous_action else 0)
        if total_cooperators / n >= 0.5:
            return Action.C
        else:
            self._alternation_flag = not self._alternation_flag
            if self._alternation_flag:
                return Action.D
            return Action.C

class Strategy_INDIVIDUALISTIC_128(BaseStrategy):
    """
    Implements a "Conditional Sustenance" strategy.
    
    Logic Summary:
    1. First Round: Always Cooperate (C).
    2. Last Round: Always Defect (D) to maximize final extraction.
    3. Critical Threshold: If stock < capacity/4, Cooperate (C) to prevent collapse.
    4. Adaptive Rule:
       - If number of cooperators in the previous round >= ceil(N/2), Defect (D) to exploit stock stability.
       - Otherwise, Cooperate (C) to buffer the common pool against depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.majority_threshold = math.ceil(self.game_description.n_players / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n = self.game_description.n_players
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        if current_stock < capacity / 4.0:
            return Action.C
        my_last_action = history.my_actions[-1]
        opponents_cooperating = int(history.opponent_cooperators[-1])
        total_cooperators_prev = opponents_cooperating + (1 if my_last_action == True else 0)
        if total_cooperators_prev >= self.majority_threshold:
            return Action.D
        else:
            return Action.C